/* ============================================================
   Procedure: [dbo].[Adwords_EnableCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE Adwords_EnableCampaign         
as              
begin              
    
select   budget,user_id, CampAd_id,CampaignId into #tblCampStat      
from tblCampaign where 1=2     
    
select ROW_NUMBER() over (order by user_id) rowid,SUM(budget) budget,    
user_id into #tmptbl  from tblCampaign where minbal=1 
group by user_id       

      
declare @mxid as bigint, @minid as bigint      
select @mxid = MAX(rowid),@minid= MIN(rowid) from #tmptbl      
      
while @minid <= @mxid      
begin      
 declare @debitAmt int = 0, @BalAmt int = 0,      
 @uid bigint =0,  @Cost int =0      
 select @debitAmt=budget,@uid =USER_ID from #tmptbl where rowid= @minid      
     
 select top 1 @BalAmt=Balance from intcredit_Details where User_ID = @uid order by Credit_ID desc      
 if @BalAmt > @debitAmt      
 begin      
   update tblCampaign set minbal=0, Status = 1 where User_ID = @uid     
   insert into #tblCampStat (budget,user_id, CampAd_id)     
 select budget,user_id, CampAd_id from tblCampaign    
 where User_ID = @uid    
    
 insert into intcredit_Details (User_ID,Debits,Balance,M_ID)       
   select @uid,@debitAmt,@BalAmt-@debitAmt,M_ID from User_Detail     
  where User_ID = @uid    
 declare @Credit_ID int     
  set @Credit_ID = SCOPE_IDENTITY()      
  insert into Adword_DailyCampaignLock (User_ID,  Cost, Report_Date, Credit_ID)              
            select  @uid, @debitAmt,GETDATE(),@Credit_ID      
    
 end      
      
 set @minid = @minid+1      
end     
select * from #tblCampStat     
 drop table #tblCampStat     
 drop table #tmptbl    
end     


GO

