/* ============================================================
   Procedure: [dbo].[AdwordsDaily_Exp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[AdwordsDaily_Exp]         
(              
      
@Daterpt datetime                  
)              
as              
begin              
       
   declare @ParentID bigint
  
     
    
delete ad1 From Adword_DailyCampaignDt ad1 
   where Convert(date,ad1.Report_Date) = convert(Date,dbo.[fn_getISTtimefromusertime]( (select ISNULL(ud.ParentID,0) from user_detail ud where  ud.user_ID = ad1.user_id),@Daterpt))
    
    
      
insert into Adword_DailyCampaignDt (user_id, CampaignID, Report_Date, AdGroupId, KeyWordID,       
    Criteria, FinalUrls, Clicks,Impressions,Cost)              
            select cmp.user_id, tmp.CampaignID, Report_Date, AdGroupId, KeyWordID,       
    Criteria, FinalUrls, Clicks,Impressions,Cost from DailyRpttmp tmp      
   inner join tblCampaign cmp on cmp.CampAd_id =tmp.CampaignID order by      
   CampaignID,AdGroupId, KeyWordID      
      
      
--select * from Adword_DailyCampaignLock      
--update tmp  set tmp.user_id = cmp.user_id From  Adword_DailyCampaignLock tmp inner join tblCampaign       
-- cmp on cmp.CampAd_id =tmp.CampaignID       
--Declare @Daterpt datetime    
--set @Daterpt ='2018-10-15'      
select  ROW_NUMBER() over (order by user_id) rowid, Cost budget ,      
  USER_ID into #bdgTb from Adword_DailyCampaignLock adc where  CONVERT(date,Report_Date) =       
  CONVERT(date, dbo.[fn_getISTtimefromusertime]( (select ISNULL(ud.ParentID,0) from user_detail ud where  ud.user_ID = adc.user_id),@Daterpt))      
      
select  ROW_NUMBER() over (order by user_id) rowid, sum(Cost) Cost ,      
  USER_ID into #tbl from Adword_DailyCampaignDt adc where  CONVERT(date,adc.Report_Date) =       
  CONVERT(date,dbo.[fn_getISTtimefromusertime]( (select ISNULL(ud.ParentID,0) from user_detail ud where  ud.user_ID = adc.user_id),@Daterpt)) group by USER_ID      
      
declare @mxid as bigint, @minid as bigint      
select @mxid = MAX(rowid),@minid= MIN(rowid) from #bdgTb      
      
while @minid <= @mxid      
begin      
 declare @debitAmt int = 0, @BalAmt int = 0,      
 @uid bigint =0,  @Cost int =0      
 select @debitAmt=budget,@uid =USER_ID from #bdgTb where rowid= @minid      
       
 select top 1 @Cost=Cost from #tbl where USER_ID = @uid      
 select top 1 @BalAmt=Balance from intcredit_Details where User_ID = @uid order by Credit_ID desc      
 if @Cost < @debitAmt      
 begin      
  insert into intcredit_Details (User_ID,Credits,Balance,M_ID,Debits)       
  select @uid,@debitAmt-@Cost,(@debitAmt-@Cost)+@BalAmt,M_ID,0 from #bdgTb tb       
  inner join User_Detail ud on ud.User_ID = tb.User_ID      
       
 update Adword_DailyCampaignLock  set Cost = @Cost where User_ID = @uid and      
  CONVERT(date,Report_Date) = CONVERT(date, dbo.[fn_getISTtimefromusertime]( (select ISNULL(ud.ParentID,0) from user_detail ud where  ud.user_ID = @uid),@Daterpt))       
 end      
      
delete From DailyRpttmp       
 set @minid = @minid+1      
end      
 drop table #bdgTb     
 drop table #tbl    
end 



GO

