/* ============================================================
   Procedure: [dbo].[AdwordsDaily_ExpNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[AdwordsDaily_ExpNew] (@Daterpt DATETIME)  
AS  
BEGIN  
  
DELETE  FROM Adword_DailyCampaignDt WHERE Convert(DATE, Report_Date) = Convert(DATE, @Daterpt)  
  
INSERT INTO Adword_DailyCampaignDt (user_id, CampaignID, Report_Date, AdGroupId, KeyWordID, Criteria, FinalUrls, Clicks, Impressions, Cost)  
SELECT cmp.user_id, tmp.CampaignID, Report_Date, AdGroupId, KeyWordID, Criteria, FinalUrls, Clicks, Impressions, Cost  
FROM DailyRpttmp tmp INNER JOIN tblCampaign cmp   
ON cmp.CampAd_id = tmp.CampaignID and cmp.IsDeleted=0  
ORDER BY CampaignID, AdGroupId, KeyWordID  
  
SELECT  ROW_NUMBER() OVER (ORDER BY tblCampaign.User_ID) rowid, Report_Date, tblCampaign.User_ID, tblCampaign.CampAd_id, tblCampaign.Budget,   
    (tblCampaign.Budget - Adwordaily.Cost) AS Refund, tblCampaign.CampaignName  
INTO #bdgTb  
FROM tblCampaign INNER JOIN Adword_DailyCampaignDt AS Adwordaily   
ON tblCampaign.CampAd_id = Adwordaily.CampaignID  
WHERE tblCampaign.STATUS = 1  
 AND tblCampaign.InProcess = 1  
 AND tblCampaign.IsDeleted = 0  
 AND Convert(DATE, Report_Date) = Convert(DATE, @Daterpt)  
  
DECLARE @mxid AS BIGINT, @minid AS BIGINT  
  
SELECT @mxid = MAX(rowid), @minid = MIN(rowid)  
FROM #bdgTb  
  
WHILE @minid <= @mxid  
BEGIN  
 DECLARE @refundamt INT = 0, @BalAmt INT = 0, @campid INT = 0, @uid BIGINT = 0, @CampaignName varchar(250)  
  
 SELECT @refundamt = refund, @uid = USER_ID, @campid = CampAd_id, @CampaignName = CampaignName  
 FROM #bdgTb  
 WHERE rowid = @minid  
  
 SELECT TOP 1 @BalAmt = Balance  
 FROM intcredit_Details  
 WHERE User_ID = @uid  
 ORDER BY Credit_ID DESC  
  
 IF (@refundamt = 0)  
 BEGIN  
  --refund insert    
  INSERT INTO intcredit_Details (User_ID, Credits, Balance, M_ID, Debits,typecredit,Remarks,ICD_CreatedBy)  
  SELECT tb.User_ID, @refundamt, @BalAmt + @refundamt, ud.M_ID, 0, 9, 'Refund against Campaign - ' + tb.CampaignName, @uid  
  FROM #bdgTb tb INNER JOIN User_Detail ud   
  ON ud.User_ID = tb.User_ID   
  Where tb.User_ID = @uid and tb.CampAd_id = @campid  
 END  
  
 UPDATE Adword_DailyCampaignLock  
 SET refundamount = @refundamt, refundDate = GETDATE()  
 WHERE CampaignID = @campid  
  AND User_ID = @uid  
  AND CONVERT(DATE, Report_Date) = CONVERT(DATE, @Daterpt)  
  
 SET @minid = @minid + 1  
END  
  
DROP TABLE #bdgTb  
  
DELETE FROM DailyRpttmp  
  
END  


GO

