/* ============================================================
   Procedure: [dbo].[Block_DailyBudget]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROCEDURE  [dbo].[Block_DailyBudget]  --'2018-10-15'       
(    
  @dte datetime    
)        
As          
Begin
          
select USER_ID, CampAd_id into #tmptbl11 from tblCampaign        
where User_ID not in (select USER_ID from intcredit_Details)        
--drop table #bdgTb        
select ROW_NUMBER() over (order by user_id) rowid, sum(Budget) budget ,USER_ID into #bdgTbl       
from dbo.tblCampaign         
--where Status=1 and IsPublished =1         
group by user_id        
     
      
declare @mxid as bigint, @minid as bigint        
select @mxid = MAX(rowid),@minid= MIN(rowid) from #bdgTbl        
while @minid <= @mxid        
begin        
 declare @debitAmt int = 0, @BalAmt int = 0, @M_ID bigint =0,      
 @uid bigint =0,@dteConverted datetime = null        
       
  Declare @Credit_ID  bigint      
       
 select @debitAmt=budget,@uid =USER_ID from #bdgTbl where rowid= @minid        
 select top 1 @BalAmt=Balance from intcredit_Details where User_ID = @uid order by Credit_ID desc       
 --select top 1 @M_ID = M_ID User_Detail ud on ud.USER_ID = @uid   

 DECLARE @avilableBalance decimal(18,4) = dbo.GetAvailableBalanceForService(@uid, 16)

 if @avilableBalance > @debitAmt        
 begin 
  declare @ParentID Bigint = 0
  
  select @ParentID = isnull(ParentID,0) from user_detail where User_ID = @uid   
   
  select @dteConverted = dbo.[fn_getISTtimefromusertime](@ParentID,@dte)
        
  insert into intcredit_Details (User_ID,Debits,Balance,M_ID, FromDate    
      ,ToDate,DateCreated,DateUpdated)         
  select @uid,@debitAmt,@BalAmt-@debitAmt,M_ID,@dteConverted,@dteConverted,@dteConverted,@dteConverted from #bdgTbl tb         
  inner join User_Detail ud on ud.USER_ID = tb.User_ID       
      
  set @Credit_ID = SCOPE_IDENTITY()        
  exec usp_rf_UpdateReserveFundTransaction @CreditId = @Credit_ID

  insert into Adword_DailyCampaignLock (User_ID,  Cost, Report_Date, Credit_ID)                
            select  @uid, @debitAmt,@dteConverted,@Credit_ID         
  
                 
 end        
 else        
 begin        
  Insert into  #tmptbl11 (USER_ID, CampAd_id)        
  select USER_ID, CampAd_id from tblCampaign where  User_ID  =@uid        
         
          
 end        
 set @minid = @minid+1        
      
        
end       
       
 update tblCampaign set Status=0, minbal =1 where User_ID in (select USER_ID from #tmptbl11)        
 select * from #tmptbl11        
 drop table #bdgTbl      
 drop table #tmptbl11      
end



