/* ============================================================
   Procedure: [dbo].[Block_DailyBudget_Campaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Block_DailyBudget_Campaign]  
(          
@dte datetime,      
@campaignid bigint      
--@userid bigint          
)              
As                
Begin  
        
  
SELECT USER_ID, [CampAd_id]  
INTO [#tmptbl11]  
FROM tblCampaign  
WHERE User_ID NOT IN  
(  
    SELECT USER_ID  
    FROM [intcredit_Details] with(nolock)  
) and IsDeleted=0  
--drop table #bdgTb              
  
SELECT ROW_NUMBER() OVER(ORDER BY user_id) [rowid], [budget], USER_ID, [CampaignName]  
INTO [#bdgTbl]  
FROM dbo.tblCampaign  with(nolock) 
WHERE CONVERT(DATE, [CmpEndDate]) >= CONVERT(DATE, GETDATE())  
  AND CONVERT(DATE, [CmpStartDate]) <= CONVERT(DATE, GETDATE())  
  AND STATUS = 1  
  AND [IsPublished] = 1  
  AND [IsDeleted] = 0  
  AND [CampAd_id] = @campaignid;  
  
DECLARE @mxid AS BIGINT, @minid AS BIGINT;  
  
SELECT @mxid = MAX([rowid]), @minid = MIN([rowid])  
FROM #bdgTbl;  
  
WHILE @minid <= @mxid  
    BEGIN  
    DECLARE @debitAmt INT= 0, @BalAmt INT= 0, @M_ID BIGINT= 0, @uid BIGINT= 0;  
    DECLARE @Credit_ID BIGINT, @CampaignName varchar(250)  
  
    SELECT @debitAmt = [budget], @uid = USER_ID, @CampaignName = [CampaignName]  
    FROM #bdgTbl  
    WHERE [rowid] = @minid;  
  
    declare @PID bigint = (select top 1 ParentID from User_Detail with(nolock) where User_ID = @uid )  
	declare @MID bigint = (select top 1 M_ID from User_Detail with(nolock) where User_ID = @PID )  

    SELECT TOP 1 @BalAmt = [Balance]  
    FROM intcredit_Details with(nolock) 
    WHERE User_ID = @PID  
    ORDER BY [Credit_ID] DESC;  
  
    --select top 1 @M_ID = M_ID User_Detail ud on ud.USER_ID = @uid               
    IF @BalAmt > @debitAmt  
    BEGIN  
    INSERT INTO intcredit_Details(User_ID, [Debits], [Balance], [M_ID], [FromDate], [ToDate], [DateCreated], [DateUpdated], typecredit, Remarks,ICD_CreatedBy)  
    SELECT @PID, @debitAmt, @BalAmt - @debitAmt,@MID, @dte, @dte, @dte, @dte, 9, 'Cost debited against Campaign - ' + tb.CampaignName,@uid  
    FROM #bdgTbl tb INNER JOIN User_Detail ud  
    ON ud.USER_ID = tb.User_ID;  
  ----Add Reserve Fund----------------------
    SET @Credit_ID = SCOPE_IDENTITY();  
			if(@Credit_ID > 0)
			begin
				declare @Amount decimal(18,4)= @debitAmt;
				exec Mysms.dbo.usp_IntCredit_ManageReseveFund @UserId = @uid, 
				@ServiceName = 'Adword', @Mode = 'UP_REF_ID_CREDIT_ID', @Amount = @Amount
			end  
-----------------------------------------------
    INSERT INTO Adword_DailyCampaignLock(User_ID, CampaignID, [Cost], [Report_Date], [Credit_ID])  
    SELECT @uid, @campaignid, @debitAmt, @dte, @Credit_ID;  
    END;  
    ELSE  
    BEGIN  
    INSERT INTO #tmptbl11(USER_ID, [CampAd_id])  
    SELECT USER_ID, [CampAd_id]  
    FROM tblCampaign with(nolock) 
    WHERE User_ID = @uid;  
    END;  
    SET @minid = @minid + 1;  
    END;  
  
UPDATE tblCampaign  
  SET  
  STATUS = 0,  
  [minbal] = 1  
WHERE User_ID IN  
(  
    SELECT USER_ID  
    FROM [#tmptbl11]  
) and IsDeleted=0;  
  
SELECT *  
FROM #tmptbl11;  
  
DROP TABLE #bdgTbl;  
  
DROP TABLE #tmptbl11;  
  
end     



GO

