/* ============================================================
   Procedure: [dbo].[Block_DailyBudgetNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROC [dbo].[Block_DailyBudgetNew] --'2018-10-15'             
 (@dte DATETIME)  
AS  
BEGIN  
 SELECT USER_ID, CampAd_id  
 INTO #tmptbl11  
 FROM tblCampaign with(nolock)  
 WHERE User_ID NOT IN (SELECT USER_ID FROM intcredit_Details with(nolock)) and IsDeleted=0  
  
 --drop table #bdgTb              
 SELECT ROW_NUMBER() OVER (ORDER BY user_id) rowid, budget, USER_ID, tblCampaign.CampAd_id, tblCampaign.CampaignName  
 INTO #bdgTbl  
 FROM dbo.tblCampaign with(nolock) 
 WHERE CONVERT(DATE, CmpEndDate) >= CONVERT(DATE, GETDATE())  
  AND CONVERT(DATE, CmpStartDate) <= CONVERT(DATE, GETDATE())  
  AND STATUS = 1  
  AND IsPublished = 1  
  AND IsDeleted=0  
  
 --group by user_id              
 DECLARE @mxid AS BIGINT, @minid AS BIGINT  
  
 SELECT @mxid = MAX(rowid), @minid = MIN(rowid)  
 FROM #bdgTbl  
  
 WHILE @minid <= @mxid  
 BEGIN  
  DECLARE @debitAmt INT = 0, @BalAmt INT = 0, @M_ID BIGINT = 0, @uid BIGINT = 0, @campid INT = 0  
  DECLARE @Credit_ID BIGINT, @CampaignName varchar(250)  
  
  SELECT @debitAmt = budget, @uid = USER_ID, @campid = CampAd_id, @CampaignName = CampaignName  
  FROM #bdgTbl  
  WHERE rowid = @minid  
  
  Declare @PID bigint = ( select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @uid)
  Declare @MIDP bigint = ( select top 1 isnull(M_ID,0) from User_Detail with(nolock) where User_ID = @PID)

  SELECT TOP 1 @BalAmt = Balance  
  FROM intcredit_Details with(nolock)  
  WHERE User_ID = @PID  
  ORDER BY Credit_ID DESC  
  
  IF @BalAmt > @debitAmt  
  BEGIN  
   INSERT INTO intcredit_Details (User_ID, Debits, Balance, M_ID, FromDate, ToDate, DateCreated, DateUpdated, typecredit, Remarks, ICD_CreatedBy)  
   SELECT @PID, @debitAmt, @BalAmt - @debitAmt, @MIDP, @dte, @dte, @dte, @dte, 9, 'Cost debited against Campaign - ' + tb.CampaignName , @uid   
   FROM #bdgTbl tb INNER JOIN User_Detail ud with(nolock)   
   ON ud.USER_ID = tb.User_ID  
   Where tb.User_ID=@uid and tb.CampAd_id=@campid  
  
   SET @Credit_ID = SCOPE_IDENTITY()  
  
   INSERT INTO Adword_DailyCampaignLock (User_ID, CampaignID, Cost, Report_Date, Credit_ID)  
   SELECT @uid, @campid, @debitAmt, @dte, @Credit_ID  
  END  
  
  --else              
  --begin              
  -- Insert into  #tmptbl11 (USER_ID, CampAd_id)              
  -- select USER_ID, CampAd_id from tblCampaign where  User_ID  =@uid              
  --end              
  SET @minid = @minid + 1  
 END  
  
 --update tblCampaign set Status=0, minbal =1 where User_ID in (select USER_ID from #tmptbl11)              
 SELECT *  
 FROM #tmptbl11  
  
 DROP TABLE #bdgTbl  
  
 DROP TABLE #tmptbl11  
END  


