   Procedure: [dbo].[CheckMailBalanceSufficiency]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

------------------------------------------------------------------------

CREATE   PROCEDURE dbo.CheckMailBalanceSufficiency --34594,101,3
    @UserId BIGINT,
    @OriginCountryId INT,
    @EmailCount INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentIDAccount BIGINT;

    -- Get ParentID from User_Detail
    SELECT TOP 1 @ParentIDAccount = ParentID
    FROM User_Detail WITH (NOLOCK)
    WHERE User_ID = @UserId;

    DECLARE @PricePerSms DECIMAL(18, 4) = dbo.GetMailRatePriceByCountry(@OriginCountryId);
    DECLARE @TotalCost DECIMAL(18, 4) = @PricePerSms * @EmailCount;
    DECLARE @AvailableBalance DECIMAL(18, 4) = dbo.GetAvailableBalanceForService(@ParentIDAccount, 2); -- 2 = SMS CreditTypeId
    DECLARE @Status NVARCHAR(50);

    IF @TotalCost <= @AvailableBalance
        SET @Status = 'Sufficient Balance';
    ELSE
        SET @Status = 'Insufficient Balance';

    SELECT 
        @Status AS Status
        --@TotalCost AS TotalCost,
        --@AvailableBalance AS AvailableBalance;
END;


