AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentIDAccount BIGINT;

    -- Get ParentID from User_Detail
    SELECT TOP 1 @ParentIDAccount = ParentID
    FROM User_Detail WITH (NOLOCK)
    WHERE User_ID = @UserId;

    DECLARE @PricePerSms DECIMAL(18, 4) = dbo.GetSmsRatePriceByCountry(@OriginCountryId);
    DECLARE @TotalCost DECIMAL(18, 4) = @PricePerSms * @MobileCount;
    DECLARE @AvailableBalance DECIMAL(18, 4) = dbo.GetAvailableBalanceForService(@ParentIDAccount, 21); -- 2 = SMS CreditTypeId
    DECLARE @Status NVARCHAR(50);

    IF @TotalCost <= @AvailableBalance
        SET @Status = 'Sufficient Balance';
    ELSE
        SET @Status = 'Insufficient Balance';

    SELECT 
        @Status AS Status
        --@TotalCost AS TotalCost,
        --@AvailableBalance AS AvailableBalance;
END;




