/* ============================================================
   Procedure: [dbo].[Cloud_Balance_Notification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROCEDURE [dbo].[Cloud_Balance_Notification]    
    
as    
begin    
    
---- Update Avg Balance    
declare @Min int, @max int,@chargeable int    
declare @sms int, @email int, @user_id bigint    
declare @bal float, @Alert_Duration bigint    
declare @sub varchar(100), @body varchar(max),    
@user_login varchar(100)    
declare @mobile varchar(250),@emailid varchar(250)    
declare @Alladmin bit    
    
    
select cn.*,ud.user_login,ROW_NUMBER() over( order by cn.User_id) rno,    
 chargeable into #tmpbalance     
 from   Cloud_notificationsetting cn inner join user_detail ud     
 on ud.User_ID = cn.User_id inner join Cloud_NotificationMast nm    
 on nm.NotificationId = cn.NotificationId    
   where cn.NotificationId =9 and (cn.email =1 or cn.sms= 1)    
   and cn.Alert_Duration > 0    
    
select cn.*,ud.user_login,ROW_NUMBER() over( order by cn.User_id) rno,    
 chargeable into #tmpvalidaty     
 from   Cloud_notificationsetting cn inner join user_detail ud     
 on ud.User_ID = cn.User_id inner join Cloud_NotificationMast nm    
 on nm.NotificationId = cn.NotificationId    
   where cn.NotificationId =10 and (cn.email =1 or cn.sms= 1)    
   and cn.Alert_Duration > 0    
    
    
select  @Min = MIN(rno) , @max= MAX(rno) from #tmpbalance    
while @Min <= @max    
    
begin    
 select @sms= sms,@email= email,@user_id = user_id,    
 @Alert_Duration =Alert_Duration,@user_login = user_login,    
 @chargeable = chargeable, @mobile= mobileno ,@emailid= EmailId,    
 @Alladmin= Alladmin  from #tmpbalance    
  where rno = @Min    
    
if @Alladmin= 1    
begin    
     
     
 select @emailid=@emailid+','+Email,@mobile=@mobile+','+    
 CONVERT(varchar(100), Cast(Mobile as decimal(38, 0)))     
      from dbo.Cloud_user_Group ug inner join     
  user_detail ud on ud.User_ID = ug.userid    
   where Role = 'Admin' and ug.parentid = @user_id    
     
end     
   declare @debit as float    
       
select @debit =avg(debit) from dbo.Cloud_avg_consumption                               
   where USER_ID = @user_id     
 --  select @debit =avg(debits) from dbo.IntCredit_Details                               
 --  where USER_ID = @user_id and    
 --   convert(date,DateCreated) between    
 --  DATEADD(DAY,-(@Alert_Duration-1), CONVERT(date,getdate())) and     
 --  DATEADD(DAY,-1, CONVERT(date,getdate()))    
 --Group by user_id    
     
 select top 1 @bal= Balance from dbo.IntCredit_Details     
  where USER_ID = @user_id order by Credit_ID desc    
      
   if @bal =0    
   begin    
   set @sub = 'You have No account balance '    
    set @body = 'Dear '+ @user_login+' You have no account balance. Please Topup Your Account.'      
    
  if @sms=1       
   exec Cloud_smsNotification_new  @user_id,@body,@mobile,@chargeable     
     if @email=1                      
   exec Cloud_emailNotification_new  @user_id,@body,@sub,@emailid,@chargeable     
   end    
   else    
   begin    
   if @bal <= @debit*@Alert_Duration    
   begin    
    set @sub = 'account balance is going to Negative in '+ cast(@Alert_Duration as varchar)+' Days'    
    set @body = 'Dear '+ @user_login+' Your  your account balance is going to Negative in  '+    
  cast(@Alert_Duration as varchar)+' Days. Please Topup Your Account.'      
  if @sms=1       
   exec Cloud_smsNotification_new  @user_id,@body,@mobile,@chargeable     
     if @email=1                      
   exec Cloud_emailNotification_new  @user_id,@body,@sub,@emailid,@chargeable            
   end    
   end    
         
 set @Min = @Min+1    
end    
    
while @Min <= @max    
    
begin    
 select @sms= sms,@email= email,@user_id = user_id,    
 @Alert_Duration =Alert_Duration,@user_login = user_login,    
 @chargeable = chargeable, @mobile= mobileno ,@emailid= EmailId,    
 @Alladmin= Alladmin  from #tmpvalidaty    
  where rno = @Min    
    
if @Alladmin= 1    
begin    
 select @emailid=@emailid+','+Email,@mobile=@mobile+','+    
 CONVERT(varchar(100), Cast(Mobile as decimal(38, 0)))     
 from dbo.Cloud_user_Group ug inner join     
  user_detail ud on ud.User_ID = ug.userid    
  where Role = 'Admin' and ug.parentid = @user_id    
end     
     
 declare @validdt  date    
 select @validdt=CONVERT(date,valid_to) from dbo.Cloud_user_subscription     
 where CONVERT(date,getdate()) between     
 CONVERT(date,valid_from) and CONVERT(date,valid_to)     
 and Parentid = @user_id    
 if (DATEDIFF(day,CONVERT(date,GETDATE()),@validdt) <= @Alert_Duration)    
 begin    
    set @sub = 'account is going to Expired in '+     
    cast(DATEDIFF(day,CONVERT(date,GETDATE()),@validdt) as varchar) +' Days'    
    set @body = 'Dear '+ @user_login+' Your  your account is going to Expired on  '+    
     cast(@validdt as varchar)+'. Please Please Recharge Your Account.'      
      
  --select @user_id,@body,@sub,@emailid,@chargeable ,    
  --  @Alert_Duration    
      
  if @sms=1       
   exec Cloud_smsNotification_new  @user_id,@body,@mobile,@chargeable     
     if @email=1                      
   exec Cloud_emailNotification_new  @user_id,@body,@sub,@emailid,@chargeable            
    end    
        
 set @Min = @Min+1    
end    
drop table #tmpbalance    
drop table #tmpvalidaty    
end


GO

/* ============================================================
   Procedure: [dbo].[Cloud_Call_logNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_Call_logNotification] --335  
(  
@ParentId bigint,  
@fmdate as datetime ,  
@todate as datetime ,  
@user_no varchar(MAX),   
@chargeable bit,   
@sms bit,   
@email bit  
)  
as  
begin  
--drop table #tmp  
--Declare @ParentId bigint = 335,  
--@fmdate as datetime = '2018-11-20',  
--@todate as datetime = '2018-11-20',  
--@emailid varchar(250) = 'sks@gmail.com',   
--@mobileno varchar(250) ='971889711',   
--@chargeable bit =0,   
--@sms bit=1,   
--@email bit =1  
  
Declare @body nvarchar(max)=''  
Declare @totcal bigint = 0,@totmis bigint = 0,  
@totdur bigint = 0,  
@totNoOutCall bigint = 0,@totoutCallDur bigint = 0  
select *,ROW_NUMBER() over( order by User_id) rno into #tmp from dbo.Cloud_logSummery  
where CONVERT(date, CallDate)  
between CONVERT(date, @fmdate) and CONVERT(date, @todate) and  
 ParentId=@ParentId  
  
  
select @totcal= SUM(isnull(NOCalls,0)),@totmis =SUM(isnull(NoMiss,0)),  
  @totNoOutCall = SUM(isnull(NoOutCall,0)),  
 @totoutCallDur = sum(isnull(outCallDur,0)),  
    @totdur =sum(isnull(caldur,0))  from   
   #tmp group by ParentId  
  
set @body = '<!DOCTYPE html> <html> <head><style> table{width:100%;}'+  
   'table, th, td {border: 1px solid MediumSeaGreen; border-collapse: collapse;'+  
   '} th, td {padding: 5px;text-align: left;}</style></head><body><table><tr>'  
set @body =@body+ '<th>Total No. of Calls</th><td colspan="6">'+  
     cast(@totcal as varchar)+'</td></tr><tr>'    
  
  
set @body = @body+'<th>Total No. of Missed Calls</th><td colspan="6">'+  
     cast(@totmis as varchar)+'</td></tr><tr>'  
set @body = @body+'<th>Total Call Duration</th><td colspan="6">'+  
   cast(@totdur as varchar)+'</td></tr><tr>'  
  
set @body = @body+'<th>Total No. of Out Calls</th><td colspan="6">'+  
   cast(@totNoOutCall as varchar)+'</td></tr><tr>'  
  
set @body = @body+'<th>Total Out Duration</th><td colspan="6">'+  
   cast(@totoutCallDur as varchar)+'</td></tr><tr>'   
set @body = @body+'<th>Login</th><th>Agent.</th><th>Call</th>'  
   +'<th>Missed</th><th>Call</th>'+  
   +'<th>Out</th><th>Out</th></tr>'    
set @body = @body+'<th>ID</th><th>No.</th><th>Received</th>'  
   +'<th>Call</th><th>Duration</th>'+  
   +'<th>Bount</th><th>Duration</th></tr>'    
  
Declare @max int=0, @min int=0  
select @max=MAX(rno), @min=MIN(rno) from #tmp  
  
Declare @mbdy as varchar(max)=''  
while @min <= @max                        
begin   
set @totdur =0  
declare @user varchar(100)='' , @NOCalls bigint =0, @NoMiss  bigint =0,   
 @Mobile varchar(20)='', @NoOutCall bigint =0,@outCallDur bigint =0,@caldur bigint =0  
select @User= LoginId,@NOCalls= isnull(NOCalls,0),@NoMiss= isnull(NoMiss,0),  
  @Mobile=isnull(Mobile,''),  
 @caldur= isnull(caldur,0), @NoOutCall = isnull(NoOutCall,0),  
 @outCallDur=isnull(outCallDur,0) from #tmp where rno = @min  
    
set @mbdy = @mbdy+'<tr><td>'+@User+'</td><td>'+@Mobile+'</td><td>'+  
   Cast(@NOCalls as varchar)+'</td><td>'+  
   Cast(@NoMiss as varchar)+'</td><td>'+Cast(@caldur as varchar)+'</td><td>'+  
   Cast(@NoOutCall as varchar)+'</td><td>'+Cast(@outCallDur as varchar)+'</td></tr>'    
  
  
select @min=@min+1  
end  
 
set @body= @body+@mbdy   
set @body = @body+'</table></body></html>'    
declare @sub varchar(100)  
set @sub= 'Daily Call Log Report For '+ convert(varchar, getdate(), 107)  
  
Declare @Type as varchar =cast(@chargeable as varchar)  
  
if @sms=1  
   
 exec Cloud_smsNotification  @parentid,@body,@user_no,@Type                            
if @email=1    
 exec Cloud_emailNotification  @parentid,@body,@sub,@user_no, @Type  
  
  
drop table #tmp   
end  
  
  
  
  
     



GO

