/* ============================================================
   Procedure: [dbo].[Cloud_Copy_AppMst]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Cloud_Copy_AppMst (
	@User_id BIGINT
	,@AppId INT
	,@AppName VARCHAR(100)
	)
AS
BEGIN
	DECLARE @result INT

	IF EXISTS (
			SELECT AppName
			FROM Cloud_app_master
			WHERE AppName = @AppName
				AND User_id = @User_id
			)
	BEGIN
		SELECT '0' AS rslt
			,'App name exists' msg
	END
	ELSE
	BEGIN
		DECLARE @newid AS BIGINT

		INSERT INTO Cloud_app_master (
			User_id
			,AppName
			,PhoneNo
			)
		VALUES (
			@User_id
			,@AppName
			,''
			)

		SELECT @newid = SCOPE_IDENTITY()

		INSERT INTO dbo.Cloud_flow_api (
			Parentid
			,Appid
			,flow
			,Create_date
			,modified_date
			,ivrid
			,flowvalue
			)
		SELECT Parentid
			,@newid
			,flow
			,Create_date
			,modified_date
			,ivrid
			,flowvalue
		FROM Cloud_flow_api
		WHERE Appid = @AppId

		SELECT @newid rslt
			,'Saved successfully' msg

		DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM Cloud_app_master WITH (NOLOCK)
			WHERE AppId = @newid
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_id
		,@Activity_type = 'Inst_Ivrflw_cpy'
		,@ActionType = 'I'
		,@RowJson = @rowJson
		,@Table_name = 'Cloud_app_master'
	END
END



GO

