@type varchar(100)              
                                
)                                    
as                                     
begin                                    
                                  
                                    
Declare @compsubject nvarchar(max)='',                                    
 @compbody nvarchar(max)=''                                
Declare  @rexist int =0,@activityid int =0                                    
Declare @FromMailID nvarchar(max) = ''                                      
Declare @sms bit = 1              
-- select @ToEmailID= rtrim(EmailId),@sms=sms from dbo.Cloud_notificationsetting                                     
-- where User_id = @parentid               
              
              
--if @sms = 0                                    
--return;                   
select ROW_NUMBER() over( order by item) rno,* into #nomobile                    
from dbo.SplitString(@ToEmailID, ',')                
          
Create table #tmpfl           
( rno int, User_login varchar(100), email varchar(100),mobile varchar(20))          
          
insert into #tmpfl (rno,User_login,email)          
 select rno,Item, Item from #nomobile --nm inner join          
 --dbo.User_Detail ud on nm.Item = ud.User_login          
       
          
drop table #nomobile           
              
  select @FromMailID= Mail_ID  from DefaultMailID              
 where User_ID = @parentid               
 if rtrim(isnull(@FromMailID,''))=''               
 select @FromMailID='contactus@pelsoftlabs.in'                                   
               
                                    
                                    
declare @spos int =0 --,  @subject varchar(max)                                    
 Declare @fld varchar(max)=''                                    
declare @tbl varchar(max)=''                                    
declare @word table (fldval varchar (Max))                                    
Declare @email_cnt as int =1,@balance int =0             
Declare @acnt bigint = 335            
if @type = '1'             
set @acnt = @parentid                    
                        
SELECT TOP 1 @balance=isnull(balance,0) FROM                 
  MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND                               
USER_ID = @acnt  ORDER BY credit_id       DESC                                
                    
if (@balance-@email_cnt) < 0                    
  Begin                    
     select 'Balance is not sufficient'               
     set @email_cnt = 0                   
  End                    
                   
                              
if @email_cnt =1                             
begin                              
                              
DECLARE @Random INT;                                          
  DECLARE @Upper INT;                                          
  DECLARE @Lower INT                                          
                                            
  Declare @BatchID bigint                                          
                                            
  SET @Lower = 1 ---- The lowest random number                                          
  SET @Upper = 10000 ---- The highest random number                                          
  SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)                                         
  --SELECT @Random                                          
                                          
     insert into GetBatchRecord (User_id,RandNum)                                                  
        values(@parentid,@Random)                                                  
   select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock)                                           
   where User_id=@parentid and RandNum=@Random                                                  
        delete from GetBatchRecord  where User_id=@parentid and RandNum=@Random                                       
                 
                  
  insert into CloneEmailsFilter(                                          
    Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName                       
    ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID                                          
    ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime                               ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source                                   )                                          
     select @FromMailID,Email,@Subject,'',@body                                    
      , GETDATE(),@acnt,@acnt,@FromMailID,                                          
     @BatchID,2,'','','',@body ,1,0,1,                                          
     'Cloud'  from #tmpfl                                       
              
    select 'Mail sent successfully'                   
                                                 
 /* Insert into table for Mail */                                              
end                
drop table #tmpfl                                    
end 


