/* ============================================================
   Procedure: [dbo].[Cloud_gen_Avg_cost]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_gen_Avg_cost]

as
begin

declare @Min int, @max int,@chargeable int
declare @user_id bigint

select * from Cloud_avg_consumption

  select User_id,ROW_NUMBER() over( order by cn.User_id) rno
   into #tmptbl 
	from   Cloud_notificationsetting cn 
	group by User_id

select  @Min = MIN(rno) , @max= MAX(rno) from #tmptbl

while @Min <= @max
begin 
   select @user_id=user_id from #tmptbl where rno= @min

   delete from dbo.Cloud_avg_consumption where USER_ID = @user_id
   and ID = (select min(ID) from dbo.Cloud_avg_consumption where USER_ID = @user_id
   and convert(date,avg_date) =
   CONVERT(date,DATEADD(DAY,-8, getdate())))
   
	insert into Cloud_avg_consumption (user_id, debit, avg_date)
   select user_id,sum(debits),convert(date,DateCreated) from dbo.IntCredit_Details 
   where USER_ID = @user_id and
    convert(date,DateCreated) between
   CONVERT(date,DATEADD(DAY,-1, getdate())) and 
   CONVERT(date,DATEADD(DAY,-1, getdate()))
	Group by user_id,convert(date,DateCreated)
	set @Min=@Min+1
end

end


GO

