/* ============================================================
   Procedure: [dbo].[Cloud_get_audio_master1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Created On , Created By, Type (Public/Private),Play voice, Duration      
-- "Cloud_get_audio_master1", 1, "", 1, 4, 1,      
-- CreatedDate      
--                    Convert.ToInt64(Session["ParentID"].ToString()), fltr      
--select ud.User_Login,* from Cloud_audio_master am inner join user_detail ud       
--on ud.ParentID = am.user_id      
CREATE   PROCEDURE dbo.Cloud_get_audio_master1 (
	@LibraryId VARCHAR(100)
	,@FileName VARCHAR(100)
	,@Active INT
	,@opt INT
	,@AccessType BIT
	,@user_id BIGINT
	,@fltr VARCHAR(max)
	)
AS
BEGIN
	DECLARE @result INT
	DECLARE @ftr VARCHAR(1) = 0

	IF LTRIM(rtrim(@fltr)) != ''
		SET @ftr = '1'

	IF LTRIM(rtrim(@fltr)) = 'Private'
		SET @ftr = '2'

	IF LTRIM(rtrim(@fltr)) = 'Public'
		SET @ftr = '3'

	IF @opt = 1
	BEGIN
		IF @Active > 0
		BEGIN
			IF LTRIM(rtrim(@fltr)) = ''
				SELECT ud.User_Login
					,*
				FROM Cloud_audio_master am
				INNER JOIN user_detail ud ON ud.user_id = am.user_id
				WHERE Active = 1
					AND am.user_id = @user_id --AccessType=@AccessType            
			ELSE
			BEGIN
				IF @ftr = '1'
					SELECT ud.User_Login
						,*
					FROM Cloud_audio_master am
					INNER JOIN user_detail ud ON ud.user_id = am.user_id
					WHERE Active = 1
						AND am.user_id = @user_id
						AND (
							FileName LIKE '%' + LTRIM(rtrim(@fltr)) + '%'
							OR FileType LIKE '%' + LTRIM(rtrim(@fltr)) + '%'
							OR cast(CreatedDate AS VARCHAR) LIKE '%' + LTRIM(rtrim(@fltr)) + '%'
							)

				IF @ftr = '2'
					SELECT ud.User_Login
						,*
					FROM Cloud_audio_master am
					INNER JOIN user_detail ud ON ud.user_id = am.user_id
					WHERE Active = 1
						AND am.user_id = @user_id
						AND AccessType = 0

				IF @ftr = '3'
					SELECT ud.User_Login
						,*
					FROM Cloud_audio_master am
					INNER JOIN user_detail ud ON ud.user_id = am.user_id
					WHERE Active = 1
						AND am.user_id = @user_id
						AND AccessType = 1
			END
		END
	END

	IF @opt = 2
	BEGIN
		IF @Active > 0
		BEGIN
			SELECT ud.User_Login
				,*
			FROM Cloud_audio_master am
			INNER JOIN user_detail ud ON ud.user_id = am.user_id
			WHERE FileName = @FileName
		END
	END

	IF @opt = 3
	BEGIN
		IF @Active > 0
		BEGIN
			SELECT ud.User_Login
				,*
			FROM Cloud_audio_master am
			INNER JOIN user_detail ud ON ud.user_id = am.user_id
			WHERE LibraryId = @LibraryId
		END
	END

	IF @opt = 4
	BEGIN
		--if @Active = 0                
		IF LTRIM(rtrim(@fltr)) = ''
			IF (@user_id <> 335)
			BEGIN
				SELECT *
				FROM (
					SELECT ud.User_Login
						,am.*
					FROM Cloud_audio_master am
					INNER JOIN user_detail ud ON ud.user_id = am.user_id
					WHERE am.user_id = @user_id
						AND Active = 1 --order by LibraryId desc 
					
					UNION
					
					SELECT ud.User_Login
						,am.*
					FROM Cloud_audio_master am
					INNER JOIN user_detail ud ON ud.user_id = am.user_id
					WHERE am.user_id = 335
						AND Active = 1
						AND AccessType = 1
					) aat
				ORDER BY LibraryId DESC
			END
			ELSE
			BEGIN
				SELECT ud.User_Login
					,am.*
				FROM Cloud_audio_master am
				INNER JOIN user_detail ud ON ud.user_id = am.user_id
				WHERE am.user_id = @user_id
					AND Active = 1
				ORDER BY LibraryId DESC
			END
		ELSE
		BEGIN
			IF @ftr = '1'
				SELECT ud.User_Login
					,*
				FROM Cloud_audio_master am
				INNER JOIN user_detail ud ON ud.user_id = am.user_id
				WHERE am.user_id = @user_id
					AND (
						FileName LIKE '%' + LTRIM(rtrim(@fltr)) + '%'
						OR FileType LIKE '%' + LTRIM(rtrim(@fltr)) + '%'
						OR cast(CreatedDate AS VARCHAR) LIKE '%' + LTRIM(rtrim(@fltr)) + '%'
						)
				ORDER BY LibraryId DESC

			IF @ftr = '2'
				SELECT ud.User_Login
					,*
				FROM Cloud_audio_master am
				INNER JOIN user_detail ud ON ud.user_id = am.user_id
				WHERE am.user_id = @user_id
					AND AccessType = 0
				ORDER BY LibraryId DESC

			IF @ftr = '3'
				SELECT ud.User_Login
					,*
				FROM Cloud_audio_master am
				INNER JOIN user_detail ud ON ud.user_id = am.user_id
				WHERE am.user_id = @user_id
					AND AccessType = 1
				ORDER BY LibraryId DESC
		END
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id
		,@Activity_type = 'View_Audio_Amstr'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'Cloud_audio_master'
END



GO

/* ============================================================
   Procedure: [dbo].[Cloud_get_ivrflow]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_get_ivrflow] -- '8800879257'       
(        
@phno varchar(20)        
)        
as        
begin        
declare @active as bit        
declare @avl as int         
declare @rslt as varchar(max) = ''        
declare @costonecal as float        
declare @bal as float        
declare @Parentid as bigint         
Declare @output as int = 0        
declare @appid as bigint=0;      
if exists (select 1 from dbo.Cloud_app_master where PhoneNo =@phno)        
begin        
 select @active= active,@Parentid= User_id from dbo.Cloud_app_master where PhoneNo =@phno        
 if @active = 0        
 begin

  set @rslt = 'ERR'  
  end      
 else        
  begin       
    
   select @costonecal = CallingCharges        
    from Cloud_user_subscription sb inner join         
    Cloud_plan_master pm on pm.planid = sb.plan_id where sb.Parentid = @Parentid 
	   select @costonecal=dbo.fn_GetVoiceCreditCalculationScalar('trans',@parentid,300,1)  

   select top 1 @bal= Balance from dbo.IntCredit_Details         
   where USER_ID = @Parentid order by Credit_ID desc -- @        
     --select @active,@Parentid ,@bal,@costonecal     
   if @bal > @costonecal        
   begin        
    select @rslt= flow, @output= 1,@appid =cm.AppId  from dbo.Cloud_app_master cm         
    inner join Cloud_flow_api flo on flo.Appid = cm.AppId where PhoneNo =@phno        
   end        
   else        
    set @rslt = 'ERR'        
  end        
end        
else        
set @rslt = 'ERR'        
        
select @output as result,@rslt as msg,@appid  appid      
end 



GO

