-- Cloud_get_ivrflowNew '1204862610', '9811958433'    
--1204862708 are Not Registered
--Agent Registered on1204862610
CREATE   PROC Cloud_get_ivrflowNew
(              
@phno varchar(20),                        
@callerno varchar(20)              
)              
as              
begin              
 declare @active as bit                                  
 declare @avl as int                                   
 declare @rslt as varchar(max) = ''                                  
 declare @costonecal  as float                                  
 declare @bal as float                                  
 declare @Parentid as bigint =0                                  
 Declare @output as int = 0                                   
 declare @appid as bigint=0                        
 Declare @user_id bigint=0 ,@agent_id bigint,@PId bigint                
 DECLARE @REGNO INT = 0,@TOTNO INT =0           
 declare @tomob varchar(max),@toemail varchar(max)          
 declare @Group varchar(100)             
 Declare @touser int=0, @sms bit, @email bit,                          
 @body varchar(100)='', @sub varchar(100)='',@type varchar(10)=0                
 Declare @ofdate as int,@Loginid varchar(100) =''                
 declare @didexists int =1        
 Declare @ivrflo varchar(max) = ''      
 Declare @mxid int, @minid int        
          
 if exists(select 1 from cloud_user_phone where  PhoneNo = @phno)            
  begin   
   select @Parentid = User_id  from Cloud_app_master        
    where  PhoneNo = @phno        
  end        
 else        
  begin        
   if not exists(select 1 from dbo.Cloud_DIDDuty where didno =@phno)         
   begin        
    set @didexists  =0         
   end         
  end        
 if @didexists =0        
  begin        
    select @rslt = 'Invalid DNI No not defined in app or for Duity Log'+@phno, @output= 0        
      insert into Cloud_ivr_log(dnino, caller_id, error)        
    select @phno,@callerno,@rslt        
       
    return;        
  end        
                
 if exists(select 1 from User_Detail where  str(Mobile,10,0) = @callerno and ISNULL(Cloudrole,0)<>0)  
  begin   
   select @Parentid=ParentID,@user_id= user_id,@Loginid= User_Login  from User_Detail               
   where  str(Mobile,10,0) = @callerno and ISNULL(Cloudrole,0)<>0               
   
  end              
 if @user_id  !=0               
  begin               
    if exists(select 1 from dbo.Cloud_DIDDuty where didno =@phno)              
     begin   
      select PhoneNo,ROW_NUMBER() over( order by PhoneNo) rno         
       into #tmpfl from dbo.cloud_user_phone where Parentid=  @Parentid       
      --SELECT @REGNO = COUNT(*) FROM Cloud_DIDObtain WHERE Agent_No = @callerno              
      --SELECT @TOTNO = COUNT(*) FROM cloud_user_phone WHERE Parentid= @Parentid              
           
        select @mxid= MAX(rno),@minid = MIN(rno) from #tmpfl        
        Declare @regusr int= 1    
        Declare @didn  varchar(max) = ''    
      while @minid <= @mxid     
      begin        
         Declare @PhoneNo varchar(20)    
         select @PhoneNo = PhoneNo from #tmpfl where rno = @minid    
         if not exists(select 1 from dbo.Cloud_DIDObtain where Agent_No =@callerno    
         and DIDNo = @PhoneNo)    
         begin    
          if @didn =''    
          set @didn = @PhoneNo    
          else    
          set @didn = @didn+','+@PhoneNo    
         end    
         set @minid = @minid+1    
      end     
      if @didn != ''              
      begin              
       select @rslt = @didn+ ' are Not Registered', @output= 0               
      end  
     else
		begin
		declare @onduty int,@uid bigint  
		   update User_Detail set onduty = (case when isnull(onduty,0) = 1 then 0 else 1 end)            
					where Parentid =@Parentid and  str(Mobile,10,0) = @callerno 
					and ISNULL(Cloudrole,0)<>0                  
		   select  @ofdate =(case when isnull(onduty,0) = 1 then 1 else 0 end)          
		   from User_Detail  where Parentid =@Parentid and  str(Mobile,10,0) = @callerno   
		   and ISNULL(Cloudrole,0)<>0             
		     
			select @onduty = onduty,@uid= USER_ID from User_Detail   
			where Parentid =@Parentid and  str(Mobile,10,0) = @callerno and ISNULL(Cloudrole,0)<>0
		   insert into Cloud_Agent_OnDutyHistory(user_id, onduty, createddatetime,   
		   didno, Agent_no, Parentid)  
		   select @uid,@onduty, GETDATE(),@phno,@callerno,@Parentid  
  
		   
		   select            
		   @email=email,@sms=sms,@touser= rtrim(User_no),          
		   @tomob =ISNULL(mobileno,''),@toemail=ISNULL(EmailId,'')          
		   from dbo.Cloud_notificationsetting                            
		   where User_id=@Parentid and NotificationId= 3                          
		   select @type = cast(isnull(chargeable,0) as varchar) from Cloud_NotificationMast         
		   where NotificationId=3                           
		   if @ofdate=1                          
		   select @body = 'User '+@Loginid+' logged in into system',                          
		   @sub =@Loginid+' User Logged in'                          
		   if @ofdate=0                          
		   select @body = 'User '+@Loginid+' logged Off from system',                          
		   @sub =@Loginid+' User Logged off'                          
		 
		   --if @sms=1 AND @tomob!=''
		   --begin
		   --select 'sms', @parentid,@body,@tomob,@type
		   -- exec Cloud_smsNotification @parentid,@body,@tomob,@type
		   ----exec Cloud_smsNotification @parentid=@parentid,@body=@body,@ToMobile_No=@tomob,@type=@type
		   --end
		   --if @email=1 AND @toemail!=''  
		   --begin  
		   --select 'email', @parentid,@body,@sub,@toemail,@type                      
		   --  exec Cloud_emailNotification  @parentid,@body,@sub,@toemail,@type
		   --end
		   select @rslt = @sub, @output= 0 
		  
		             
		   select GroupId,ROW_NUMBER() over( order by GroupId) rno           
			into #grpfl from dbo.Cloud_user_Group where userid= @user_id          
		   --Declare @mxid int, @minid int          
		   select @mxid= MAX(rno),@minid = MIN(rno) from #grpfl          
		         
		   while @minid <= @mxid          
			 begin          
			 declare @gid bigint          
			 select @Group = gm.Groupname,@gid=ug.GroupId from #grpfl ug          
			 inner join dbo.Cloud_group_master gm          
			 on gm.GroupId = ug.GroupId          
			 where rno = @minid          
		         
			 set @touser =0          
		              
			 select @touser= isnull(COUNT(*),0)           
			 from user_detail where USER_ID in (select USER_ID           
			 from Cloud_user_Group where GroupId =@gid) and isnull(onduty,0) = 1           
			 and ISNULL(Cloudrole,0)<>0          
			 if @touser= 0                      
			 begin          
			  select            
			   @email=email,@sms=sms,@touser= rtrim(User_no),          
			   @tomob =ISNULL(mobileno,''),@toemail=ISNULL(EmailId,'')          
			   from dbo.Cloud_notificationsetting                            
			   where User_id=@Parentid and NotificationId= 2  
		   
			  select @body = 'All users of Group '+@Group+' logged Off from system',       
					@sub ='All users of Group '+@Group+ ' Loged off'            
		                  
			  --if @sms=1 AND @tomob!='' 
			  --begin  
			  --select 'grp sms', @parentid,@body,@tomob,@type
			  --exec Cloud_smsNotification  @parentid,@body,@tomob,@type  
			  --end      
			  --if @email=1 AND isnull(@toemail,'') !='' 
			  --begin 
			  --select 'grp email', @parentid,@body,@sub,@toemail,@type                       
			  --exec Cloud_emailNotification  @parentid,@body,@sub,@toemail,@type 
			  --end        
			 end           
			 set @minid = @minid+1             
			 end            
     end
     end              
  end  
        
         
 --else              
 --begin   
  
  if not exists(select 1 from Cloud_DIDObtain where Agent_No=@callerno and DIDNo=@phno  
     and DATEDIFF(mm,ObtarinDt,GETDATE()) >6  ) 
       
  begin 
  if not exists(select 1 from Cloud_DIDDuty  where didno =@phno)
   begin
   insert into dbo.Cloud_DIDObtain(DIDNo, ParentId, Agent_ID, Agent_No, ObtarinDt)      
   select @phno,@Parentid,@user_id,@callerno,GETDATE()      
   select @rslt = 'Agent Registered on'+@phno, @output= 0 
  end    
  end 
 if exists (select 1 from dbo.Cloud_app_master where PhoneNo =@phno ) 
                     
   begin    
   select @active= active,@Parentid= User_id from dbo.Cloud_app_master where PhoneNo =@phno   
   if @active = 0                                  
    select @rslt = 'Inactive App' ,@output= 88                                 
   else                                  
   begin   
   declare @validdt datetime  
   select @costonecal = CallingCharges , @validdt = valid_to                                 
   from Cloud_user_subscription sb inner join                                
   Cloud_plan_master pm on pm.planid = sb.plan_id where sb.Parentid = @Parentid                                  
   select top 1 @bal= Balance from dbo.IntCredit_Details                                   
   where USER_ID = @Parentid order by Credit_ID desc -- @                                  
   if CONVERT(date,@validdt) < CONVERT(date,getdate())  
    select @rslt = 'Account Expired on '+CONVERT(varchar,@validdt,102)+  
       'no IVR worked' ,@output= 88     
   else  
   begin  
    if @bal > @costonecal                                  
    begin   
     select @ivrflo= flow, @output= 1, @appid =cm.AppId  from dbo.Cloud_app_master cm                         inner join Cloud_flow_api flo on flo.Appid = cm.AppId where PhoneNo =@phno         
    end                                  
    else                                  
    select @rslt = 'No Credit Balance to run IVR' ,@output= 88   
   end                                 
   end                                  
    --end                                  
 end      
  
 if ltrim(rtrim(@rslt)) !=''       
 begin       
 insert into Cloud_ivr_log(dnino, caller_id, error)        
   select @phno,@callerno,@rslt        
  select 1 as result,@rslt as msg,@appid  appid          
 end       
 else        
  select 1 as result,@ivrflo as msg,@appid  appid             
end


GO

/* ============================================================
   Procedure: [dbo].[Cloud_get_ivrflowNew22]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Cloud_get_ivrflowNew22 '1204862610', '9811958433'              
--1204862708 are Not Registered          
--Agent Registered on1204862610          
CREATE   PROC [dbo].[Cloud_get_ivrflowNew22] --'8035391842',0000000000 --'1204862601','9718896162'        
(                        
@phno varchar(20),                                  
@callerno varchar(20)                        
)                        
as                        
begin                        
 declare @active as bit                                            
 declare @avl as int                                             
 declare @rslt as varchar(max) = ''                                            
 declare @costonecal  as float                                            
 declare @bal as float                                            
 declare @Parentid as bigint =0                                            
 Declare @output as int = 0                                             
 declare @appid as bigint=0                                  
 Declare @user_id bigint=0 ,@agent_id bigint,@PId bigint                          
 DECLARE @REGNO INT = 0,@TOTNO INT =0                     
 declare @tomob varchar(max),@toemail varchar(max)                    
 declare @Group varchar(100)                       
 Declare @touser int=0, @sms bit, @email bit,                                    
 @body varchar(100)='', @sub varchar(100)='',@type varchar(10)=0                          
 Declare @ofdate as int,@Loginid varchar(100) =''                          
 declare @didexists int =1                  
 Declare @ivrflo varchar(max) = ''                
 Declare @mxid int, @minid int                  

 set @phno=right(@phno,10)
                    
 if exists(select 1 from cloud_user_phone(nolock) where  PhoneNo = @phno)                      
  begin             
   select @Parentid = Parentid  from cloud_user_phone(nolock)                  
    where  PhoneNo = @phno                  
  end                  
 else                  
  begin 
if try_parse(@phno as bigint) between 8035394400 and 8035394699 or try_parse(@phno as bigint) between 8035391820 and 
8035391969 or try_parse(@phno as bigint) between 8069932600 and 8069932899
begin
select @rslt=1,@ivrflo=flow,@appid=appid,@parentid=parentid from Cloud_flow_api(nolock) where appid=5659--4795
GOTO RETURNRESULT
end

   if not exists(select 1 from dbo.Cloud_DIDDuty(nolock) where didno =@phno)                   
   begin                  
    set @didexists  =0                   
   end                   
  end                  
 if @didexists =0                  
  begin                  
    select @rslt = 'Invalid DNI No not defined in app or for Duty Log'+@phno, @output= 0                  
      insert into Cloud_ivr_log(dnino, caller_id, error)                  
   -- select @phno,@callerno,@rslt                  
     select 0 as result,@ivrflo as msg,@appid  appid                   
    return;                  
  end                  
                          
 if exists(select 1 from User_Detail(nolock) where  str(Mobile,10,0) = @callerno 
 and ISNULL(Cloudrole,0)<>0 and parentid= isnull(nullif(@parentid,0),parentid))            
  begin             
   select top 1 @Parentid=ParentID,@user_id= user_id,@Loginid= User_Login  from User_Detail(nolock)                         
   where  str(Mobile,10,0) = @callerno and ISNULL(Cloudrole,0)<>0                         
             
  end                        
 if @user_id  !=0                         
  begin                         
    if exists(select 1 from dbo.Cloud_DIDDuty(nolock) where didno =@phno)                        
     begin             
      select PhoneNo,ROW_NUMBER() over( order by PhoneNo) rno                   
       into #tmpfl from dbo.cloud_user_phone(nolock) where Parentid=  @Parentid                 
      --SELECT @REGNO = COUNT(*) FROM Cloud_DIDObtain WHERE Agent_No = @callerno                        
      --SELECT @TOTNO = COUNT(*) FROM cloud_user_phone WHERE Parentid= @Parentid                        
                     
        select @mxid= MAX(rno),@minid = MIN(rno) from #tmpfl                  
        Declare @regusr int= 1              
        Declare @didn  varchar(max) = ''              
      while @minid <= @mxid               
      begin                  
         Declare @PhoneNo varchar(20)              
         select @PhoneNo = PhoneNo from #tmpfl where rno = @minid         
         if not exists(select 1 from dbo.Cloud_DIDObtain(nolock) where Agent_No =@callerno              
         and DIDNo = @PhoneNo)              
         begin              
          if @didn =''              
          set @didn = @PhoneNo              
          else              
          set @didn = @didn+','+@PhoneNo              
         end              
         set @minid = @minid+1              
 end               
      if @didn != ''                        
      begin                        
       select @rslt = @didn+ ' are Not Registered', @output= 0                         
     end            
     else          
  begin          
  declare @onduty int,@uid bigint            
     update User_Detail set onduty = (case when isnull(onduty,0) = 1 then 0 else 1 end)                      
     where Parentid =@Parentid and  str(Mobile,10,0) = @callerno           
     and ISNULL(Cloudrole,0)<>0                            
     select  @ofdate =(case when isnull(onduty,0) = 1 then 1 else 0 end)                    
     from User_Detail(nolock)  where Parentid =@Parentid and  str(Mobile,10,0) = @callerno             
     and ISNULL(Cloudrole,0)<>0                       
                 
   select @onduty = onduty,@uid= USER_ID from User_Detail(nolock)             
   where Parentid =@Parentid and  str(Mobile,10,0) = @callerno and ISNULL(Cloudrole,0)<>0          
     insert into Cloud_Agent_OnDutyHistory(user_id, onduty, createddatetime,             
     didno, Agent_no, Parentid)            
     select @uid,@onduty, GETDATE(),@phno,@callerno,@Parentid            
            
               
     select                      
     @email=email,@sms=sms,@touser= rtrim(User_no),                    
     @tomob =ISNULL(mobileno,''),@toemail=ISNULL(EmailId,'')                    
     from dbo.Cloud_notificationsetting(nolock)                                      
     where User_id=@Parentid and NotificationId= 3                                    
     select @type = cast(isnull(chargeable,0) as varchar) from Cloud_NotificationMast                   
     where NotificationId=3                                     
     if @ofdate=1                                    
     select @body = 'User '+@Loginid+' logged in into system',                                    
     @sub =@Loginid+' User Logged in'                                    
     if @ofdate=0                                    
     select @body = 'User '+@Loginid+' logged Off from system',                                    
     @sub =@Loginid+' User Logged off'                                    
             
     if @sms=1 AND @tomob!=''          
     begin          
      exec Cloud_smsNotification_new @parentid,@body,@tomob,@type          
     --exec Cloud_smsNotification @parentid=@parentid,@body=@body,@ToMobile_No=@tomob,@type=@type          
     end          
     if @email=1 AND @toemail!=''            
     begin            
       exec Cloud_emailNotification_new  @parentid,@body,@sub,@toemail,@type          
     end          
     select @rslt = @sub, @output= 0           
              
                         
     select GroupId,ROW_NUMBER() over( order by GroupId) rno                     
   into #grpfl from dbo.Cloud_user_Group(nolock) where userid= @user_id                    
     --Declare @mxid int, @minid int                    
     select @mxid= MAX(rno),@minid = MIN(rno) from #grpfl                    
                     
     while @minid <= @mxid                    
    begin                    
    declare @gid bigint                    
    select @Group = gm.Groupname,@gid=ug.GroupId from #grpfl ug                    
    inner join dbo.Cloud_group_master(nolock) gm                    
    on gm.GroupId = ug.GroupId                    
    where rno = @minid                    
                     
    set @touser =0                    
                          
    select @touser= isnull(COUNT(*),0)                     
    from user_detail(nolock) where USER_ID in (select USER_ID                     
    from Cloud_user_Group(nolock) where GroupId =@gid) and isnull(onduty,0) = 1                     
    and ISNULL(Cloudrole,0)<>0                    
    if @touser= 0                                
    begin                    
     select                      
      @email=email,@sms=sms,@touser= rtrim(User_no),                    
      @tomob =ISNULL(mobileno,''),@toemail=ISNULL(EmailId,'')                    
    from dbo.Cloud_notificationsetting (nolock)                                     
      where User_id=@Parentid and NotificationId= 2            
               
     select @body = 'All users of Group '+@Group+' logged Off from system',                 
     @sub ='All users of Group '+@Group+ ' Logged off'                      
                      
     if @sms=1 AND @tomob!=''           
     begin            
     exec Cloud_smsNotification_new  @parentid,@body,@tomob,@type            
     end                
     if @email=1 AND isnull(@toemail,'') !=''           
     begin           
     exec Cloud_emailNotification_new  @parentid,@body,@sub,@toemail,@type           
     end           
    end                     
    set @minid = @minid+1                       
    end                      
     end          
     end                        
  end            
                  
                   
 --else                        
 --begin             
            
  if not exists(select 1 from Cloud_DIDObtain(nolock) where Agent_No=@callerno and DIDNo=@phno            
     and DATEDIFF(mm,ObtarinDt,GETDATE()) >6  )           
                 
  begin           
  if not exists(select 1 from Cloud_DIDDuty(nolock)  where didno =@phno)          
   begin          
   insert into dbo.Cloud_DIDObtain(DIDNo, ParentId, Agent_ID, Agent_No, ObtarinDt)                
   select @phno,@Parentid,@user_id,@callerno,GETDATE()                
   select @rslt = 'Agent Registered on'+@phno, @output= 0           
  end              
  end           
 --if exists (select 1 from dbo.Cloud_app_master where PhoneNo =@phno )           
                               
 --  begin              
 --  select @active= active,@Parentid= User_id from dbo.Cloud_app_master where PhoneNo =@phno  
   if exists (select 1 from dbo.Cloud_user_phone(nolock) where PhoneNo =@phno )           
                               
   begin         
  
   select @active= active,@Parentid= parentid from dbo.Cloud_user_phone(nolock) where PhoneNo =@phno             
   if @active = 0                                            
    select @rslt = 'Inactive App' ,@output= 88                                           
   else                                            
   begin        
    Print concat('Parentid: ',@parentid,' Phone is mapped to user',', Result: ',@rslt)
   declare @validdt datetime            
          
        
  select top 1 @validdt =planenddate from Price_UserSubscriptionDetails(nolock) where isnewplan=1 and userid=@Parentid        
  order by id desc
--  Declare @tptbl as tbl_IntMobtbl, @debit as decimal (18,4)              
              
--create table #tmpcrt (balance decimal(18,4),msg varchar(10))              
              
--insert into #tmpcrt (balance,msg)               
--exec sp_Calc_price_New @Parentid,@tptbl,'call','MTIX_TR',1,'',30              
--select @debit = isnull(balance,0) from #tmpcrt              
--drop table #tmpcrt         
        
          
   --select @costonecal = CallingCharges , @validdt = valid_to                                           
   --from Cloud_user_subscription sb inner join                                          
   --Cloud_plan_master pm on pm.planid = sb.plan_id where sb.Parentid = @Parentid                                            
          
   select top 1 @bal= Balance from dbo.IntCredit_Details(nolock)                                             
   where USER_ID = @Parentid order by Credit_ID desc -- @                                            
   if CONVERT(date,@validdt) < CONVERT(date,getdate()) 
   begin
    select @rslt = 'Account Expired on '+CONVERT(varchar,@validdt,102)+            
       'no IVR worked' ,@output= 88
	     Print concat('Parentid: ',@parentid,' Phone is mapped to user',', Result: ',@rslt)
	end
   else            
   begin            
    if @bal > 2            
   begin             

     select @ivrflo= flow, @output= 1, @appid =cm.AppId  from dbo.Cloud_app_master cm                                
           inner join Cloud_flow_api flo(nolock) on flo.Appid = cm.AppId   
           join Cloud_User_Phone cp(nolock) on cp.AppId=cm.appid  
           where cp.PhoneNo =@phno 
	Print concat('Parentid: ',@parentid,' flow: ',@appid)
    end                                            
    else                                            
    select @rslt = 'No Sufficient Credit Balance to run IVR' ,@output= 88  
	  Print concat('Parentid: ',@parentid,' Phone is mapped to user',', Result: ',@rslt)           
   end                                           
   end                                            
    --end                                            
 end                
 
 RETURNRESULT:
 if ltrim(rtrim(@rslt)) !=''                 
 begin
 print 'returnresult'
 declare @cldivrid bigint                
 insert into Cloud_ivr_log(dnino, caller_id, error)                  
select @phno,@callerno,@rslt                  
select @cldivrid=SCOPE_IDENTITY()
  --select 1 as result,@ivrflo as msg,@appid  appid  
  if @rslt = 'No Sufficient Credit Balance to run IVR'
  begin
declare @eventdesc nvarchar(1000)=(select 'User '+user_login+' has low International Balance. Current balance is 
'+cast(@bal as nvarchar)+' which is low & may not last for 7 days looking at the average consumption'
from user_detail(nolock) where user_id=@user_id)
exec Usp_InsertUserEventDetails 'Low Balance International Money',@user_id,@eventdesc,'Cloud_ivr_log',@cldivrid,
'UserID',null
end

/*Added below code to replace placeholders in flow for playtext, playdate and playmoney*/
if (@ivrflo like '%#lead.%')
begin

declare @entity nvarchar(20),@entityid bigint,@strvalue	nvarchar(max)
if exists(select 1 from userleads(nolock) where parentid=@parentid and @callerno in (isnull(nullif(mobileno,'0'),''),isnull(nullif(mobileno1,'0'),''),isnull(nullif(mobileno2,'0'),'')))
begin
select top 1 @entity='lead',@entityid=id from userleads(nolock) where parentid=@parentid and @callerno in (isnull(nullif(mobileno,'0'),''),isnull(nullif(mobileno1,'0'),''),isnull(nullif(mobileno2,'0'),'')) order by id desc
end
else if exists(select 1 from userenquiry(nolock) where parentid=@parentid and @callerno in (isnull(nullif(mobileno,'0'),''),isnull(nullif(mobileno1,'0'),''),isnull(nullif(mobileno2,'0'),'')))
begin
select top 1 @entity='enquiry',@entityid=enquiryid from userenquiry(nolock) where parentid=@parentid and @callerno in (isnull(nullif(mobileno,'0'),''),isnull(nullif(mobileno1,'0'),''),isnull(nullif(mobileno2,'0'),'')) order by enquiryid desc
select @ivrflo=replace(@ivrflo,'#lead.','#enquiry.')
end
 
if @entityid>0
 begin
exec [dbo].[usp_replaceentityplaceholders] @entityid,@entity,@ivrflo,@strvalue output
select @ivrflo=@strvalue
end
else
begin
select @ivrflo=dbo.fn_Strip_entityPlaceholders(@ivrflo)
end

end


 
if (@ivrflo like '%"timing"%')   
begin    
select 1 as result,replace(replace(replace(replace(replace(cast(dbo.fn_getchecktimeflow(@ivrflo,@Parentid) as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLE
RNO#') as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid     
end  
else  
begin  
select 1 as result,replace(replace(replace(replace(replace(cast(@ivrflo as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLERNO#') 
as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid  
end  
end                 
else                  
begin  
insert into Cloud_ivr_log(dnino, caller_id, error)                  
select @phno,@callerno,@rslt   
  --select 1 as result,@ivrflo as msg,@appid  appid    
if (@ivrflo like '%"timing"%')   
begin                     
select 1 as result,replace(replace(replace(replace(replace(cast(dbo.fn_getchecktimeflow(@ivrflo,@Parentid) as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLERNO#')
as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid     
end  
else  
begin  
select 1 as result,REPLACE(replace(replace(replace(replace(cast(@ivrflo as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLERNO#') 
as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid  
end  
  
end  
end   
  
  
  
  


GO

/* ============================================================
   Procedure: [dbo].[Cloud_get_ivrflowNew22_agents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Cloud_get_ivrflowNew22 '1204862610', '9811958433'                
--1204862708 are Not Registered            
--Agent Registered on1204862610            
CREATE   PROC [dbo].[Cloud_get_ivrflowNew22_agents] --1204862906,0000000000 --'1204862601','9718896162'          
(                          
@phno varchar(20),                                    
@callerno varchar(20)                          
)                          
as                          
begin                          
 declare @active as bit                                              
 declare @avl as int                                               
 declare @rslt as varchar(max) = ''                                              
 declare @costonecal  as float                                              
 declare @bal as float                                              
 declare @Parentid as bigint =0                                              
 Declare @output as int = 0                                               
 declare @appid as bigint=0                                    
 Declare @user_id bigint=0 ,@agent_id bigint,@PId bigint                            
 DECLARE @REGNO INT = 0,@TOTNO INT =0                       
 declare @tomob varchar(max),@toemail varchar(max)                      
 declare @Group varchar(100)                         
 Declare @touser int=0, @sms bit, @email bit,                                      
 @body varchar(100)='', @sub varchar(100)='',@type varchar(10)=0                            
 Declare @ofdate as int,@Loginid varchar(100) =''                            
 declare @didexists int =1                    
 Declare @ivrflo varchar(max) = ''                  
 Declare @mxid int, @minid int,@calling_agentid bigint                    
                      
 if exists(select 1 from cloud_user_phone(nolock) where  PhoneNo = @phno)                        
  begin               
   select @Parentid = Parentid  from cloud_user_phone(nolock)                    
    where  PhoneNo = @phno                    
  end                    
 else                    
  begin                    
   if not exists(select 1 from dbo.Cloud_DIDDuty(nolock) where didno =@phno)                     
   begin                    
    set @didexists  =0                     
   end                     
  end                    

 if @didexists =0                    
  begin                    
    select @rslt = 'Invalid DNI No not defined in app or for Duity Log'+@phno, @output= 0                    
      insert into Cloud_ivr_log(dnino, caller_id, error)                    
   -- select @phno,@callerno,@rslt                    
     select 0 as result,@ivrflo as msg,@appid  appid                     
    return;                    
  end                    
                            
 if exists(select 1 from calling_agents(nolock) where  str(Mobile,10,0) = @callerno 
 and parentid= isnull(nullif(@parentid,0),parentid))              
  begin               
   select top 1 @Parentid=ParentID,@user_id= kit19userid,@calling_agentid=id  from Calling_agents(nolock)                           
   where  str(Mobile,10,0) = @callerno and isactive=1 and isdeleted=0
  end
  
 if @calling_agentid  !=0                           
  begin                           
    if exists(select 1 from dbo.Cloud_DIDDuty(nolock) where didno =@phno)                          
     begin               
                  
  begin            
  declare @onduty int,@uid bigint              
     update Calling_Agents set onduty = (case when isnull(onduty,0) = 1 then 0 else 1 end)                        
     where Parentid =@Parentid and  str(Mobile,10,0) = @callerno             
     and isactive=1 and isdeleted=0
     select  @ofdate =(case when isnull(onduty,0) = 1 then 1 else 0 end)                      
     from Calling_Agents(nolock)  where Parentid =@Parentid and  str(Mobile,10,0) = @callerno               
     and isactive=1 and isdeleted=0
                   
   select @onduty = onduty,@uid= kit19userid,@calling_agentid=id from calling_agents(nolock)               
   where Parentid =@Parentid and  str(Mobile,10,0) = @callerno and isactive=1 and isdeleted=0
     
	 insert into Cloud_Agent_OnDutyHistory(user_id, onduty, createddatetime,didno, Agent_no, Parentid,calling_agentid,mode)              
     select @uid,@onduty, GETDATE(),@phno,@callerno,@Parentid,@calling_agentid,'Mobile'              
              
                 
     select                        
     @email=email,@sms=sms,@touser= rtrim(User_no),                      
     @tomob =ISNULL(mobileno,''),@toemail=ISNULL(EmailId,'')                      
     from dbo.Cloud_notificationsetting(nolock)                                        
     where User_id=@Parentid and NotificationId= 3                                      
     select @type = cast(isnull(chargeable,0) as varchar) from Cloud_NotificationMast(nolock)                     
     where NotificationId=3                                       
     if @ofdate=1                                      
     select @body = 'User '+@Loginid+' logged in into system',                                      
     @sub =@Loginid+' User Logged in'                                      
     if @ofdate=0                                      
     select @body = 'User '+@Loginid+' logged Off from system',                                      
     @sub =@Loginid+' User Logged off'                                      
               
     if @sms=1 AND @tomob!=''            
     begin            
      exec Cloud_smsNotification_new @parentid,@body,@tomob,@type            
     --exec Cloud_smsNotification @parentid=@parentid,@body=@body,@ToMobile_No=@tomob,@type=@type            
     end            
     if @email=1 AND @toemail!=''              
     begin              
       exec Cloud_emailNotification_new  @parentid,@body,@sub,@toemail,@type            
     end            
     select @rslt = @sub, @output= 0             
                
                           
     select GroupId,ROW_NUMBER() over( order by GroupId) rno                       
   into #grpfl from dbo.Cloud_user_Group(nolock) where userid= @user_id                      
     --Declare @mxid int, @minid int                      
     select @mxid= MAX(rno),@minid = MIN(rno) from #grpfl                      
                       
     while @minid <= @mxid                      
    begin                      
    declare @gid bigint                      
    select @Group = gm.Groupname,@gid=ug.GroupId from #grpfl ug                      
    inner join dbo.Cloud_group_master(nolock) gm                      
    on gm.GroupId = ug.GroupId                      
    where rno = @minid                      
                       
    set @touser =0                      
                            
    select @touser= isnull(COUNT(*),0)                       
    from calling_agents(nolock) where ID in (select calling_agentid                       
    from Cloud_user_Group(nolock) where GroupId =@gid) and onduty = 1                       
    and isactive=1 and isdeleted=0                     
    if @touser= 0                                  
    begin                      
     select                        
      @email=email,@sms=sms,@touser= rtrim(User_no),                      
      @tomob =ISNULL(mobileno,''),@toemail=ISNULL(EmailId,'')                      
    from dbo.Cloud_notificationsetting (nolock)                                       
      where User_id=@Parentid and NotificationId= 2              
                 
     select @body = 'All users of Group '+@Group+' logged Off from system',                   
     @sub ='All users of Group '+@Group+ ' Logged off'                        
                        
     if @sms=1 AND @tomob!=''             
     begin              
     exec Cloud_smsNotification_new  @parentid,@body,@tomob,@type              
     end                  
     if @email=1 AND isnull(@toemail,'') !=''             
     begin             
     exec Cloud_emailNotification_new  @parentid,@body,@sub,@toemail,@type             
     end             
    end                       
    set @minid = @minid+1                         
    end                        
     end            
     end                          
  end              
                    
                     
 --else                          
 --begin               
 /*   commented as we may not need this          
  if not exists(select 1 from Cloud_DIDObtain(nolock) where Agent_No=@callerno and DIDNo=@phno              
     and DATEDIFF(mm,ObtarinDt,GETDATE()) >6  )             
                   
  begin             
  if not exists(select 1 from Cloud_DIDDuty(nolock)  where didno =@phno)            
   begin            
   insert into dbo.Cloud_DIDObtain(DIDNo, ParentId, Agent_ID, Agent_No, ObtarinDt)                  
   select @phno,@Parentid,@user_id,@callerno,GETDATE()                  
   select @rslt = 'Agent Registered on'+@phno, @output= 0             
  end                
  end
  */
 --if exists (select 1 from dbo.Cloud_app_master where PhoneNo =@phno )             
                                 
 --  begin                
 --  select @active= active,@Parentid= User_id from dbo.Cloud_app_master where PhoneNo =@phno    
   if exists (select 1 from dbo.Cloud_user_phone(nolock) where PhoneNo =@phno )             
                                 
   begin                
   select @active= active,@Parentid= parentid from dbo.Cloud_user_phone(nolock) where PhoneNo =@phno               
   if @active = 0                                              
    select @rslt = 'Inactive App' ,@output= 88                                             
   else                                              
   begin               
   declare @validdt datetime              
            
          
  select top 1 @validdt =planenddate from Price_UserSubscriptionDetails(nolock) where isnewplan=1 and userid=@Parentid          
  order by id desc  
--  Declare @tptbl as tbl_IntMobtbl, @debit as decimal (18,4)                
                
--create table #tmpcrt (balance decimal(18,4),msg varchar(10))                
                
--insert into #tmpcrt (balance,msg)                 
--exec sp_Calc_price_New @Parentid,@tptbl,'call','MTIX_TR',1,'',30                
--select @debit = isnull(balance,0) from #tmpcrt                
--drop table #tmpcrt           
          
            
   --select @costonecal = CallingCharges , @validdt = valid_to                                             
   --from Cloud_user_subscription sb inner join                                            
  --Cloud_plan_master pm on pm.planid = sb.plan_id where sb.Parentid = @Parentid                                              
            
   select top 1 @bal= Balance from dbo.IntCredit_Details(nolock)                                               
   where USER_ID = @Parentid order by Credit_ID desc -- @                                              
   if CONVERT(date,@validdt) < CONVERT(date,getdate())              
    select @rslt = 'Account Expired on '+CONVERT(varchar,@validdt,102)+              
       'no IVR worked' ,@output= 88                 
   else              
   begin              
    if @bal > 2              
   begin               
     select @ivrflo= flow, @output= 1, @appid =cm.AppId  from dbo.Cloud_app_master cm                                  
           inner join Cloud_flow_api flo(nolock) on flo.Appid = cm.AppId     
           join Cloud_User_Phone cp(nolock) on cp.AppId=cm.appid    
           where cp.PhoneNo =@phno                     
    end                                              
    else                                              
    select @rslt = 'No Sufficient Credit Balance to run IVR' ,@output= 88    
              
   end                                             
   end                                              
    --end                                              
 end                  
              
 if ltrim(rtrim(@rslt)) !=''                   
 begin  
 declare @cldivrid bigint                  
 insert into Cloud_ivr_log(dnino, caller_id, error)                    
select @phno,@callerno,@rslt                    
select @cldivrid=SCOPE_IDENTITY()  
  --select 1 as result,@ivrflo as msg,@appid  appid    
  if @rslt = 'No Sufficient Credit Balance to run IVR'  
  begin  
declare @eventdesc nvarchar(1000)=(select 'User '+user_login+' has low International Balance. Current balance is   
'+cast(@bal as nvarchar)+' which is low & may not last for 7 days looking at the average consumption'  
from user_detail(nolock) where user_id=@user_id)  
exec Usp_InsertUserEventDetails 'Low Balance International Money',@user_id,@eventdesc,'Cloud_ivr_log',@cldivrid,  
'UserID',null  
end  
     
if (@ivrflo like '%"timing"%')     
begin      
select 1 as result,replace(replace(replace(replace(replace(cast(dbo.fn_getchecktimeflow(@ivrflo,@Parentid) as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLE 
 
RNO#') as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid       
end    
else    
begin    
select 1 as result,replace(replace(replace(replace(replace(cast(@ivrflo as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLERNO#')   
as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid    
end    
end                   
else                    
begin    
insert into Cloud_ivr_log(dnino, caller_id, error)                    
select @phno,@callerno,@rslt     
  --select 1 as result,@ivrflo as msg,@appid  appid      
if (@ivrflo like '%"timing"%')     
begin                       
select 1 as result,replace(replace(replace(replace(replace(cast(dbo.fn_getchecktimeflow(@ivrflo,@Parentid) as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLER
NO#')  
as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid       
end    
else    
begin    
select 1 as result,REPLACE(replace(replace(replace(replace(cast(@ivrflo as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLERNO#')   
as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid    
end    
    
end    
end     
    
    
    


GO

