   if @active = 0                                          
    select @rslt = 'Inactive App' ,@output= 88                                         
   else                                          
   begin           
   declare @validdt datetime          
        
      
  select  @validdt =planenddate from Price_UserSubscriptionDetails where isnewplan=1 and userid=@Parentid      
