     select @ivrflo= flow, @output= 1, @appid =cm.AppId  from dbo.Cloud_app_master cm                              
           inner join Cloud_flow_api flo on flo.Appid = cm.AppId 
           join Cloud_User_Phone cp on cp.AppId=cm.appid
           where cp.PhoneNo =@phno                 
    end                                          
    else                                          
    select @rslt = 'No Sufficient Credit Balance to run IVR' ,@output= 88           
   end                                         
   end                                          
    --end                                          
 end              
          
 if ltrim(rtrim(@rslt)) !=''               
 begin               
 insert into Cloud_ivr_log(dnino, caller_id, error)                
select @phno,@callerno,@rslt                
  --select 1 as result,@ivrflo as msg,@appid  appid 
if (@ivrflo like '%"timing"%') 
begin  
select 1 as result,replace(replace(replace(replace(replace(cast(dbo.fn_getchecktimeflow(@ivrflo,@Parentid) as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLERNO#') as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid   
