else
begin
select 1 as result,replace(replace(replace(replace(replace(cast(@ivrflo as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLERNO#') as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid
end
end               
else                
begin
insert into Cloud_ivr_log(dnino, caller_id, error)                
select @phno,@callerno,@rslt 
  --select 1 as result,@ivrflo as msg,@appid  appid  
declare @flowforinput nvarchar(max)
create table #finalresult(result int,msg nvarchar(max),appid bigint)
create table #flowwithgrpnumbers(flow nvarchar(max))
if (@ivrflo like '%"timing"%') 
begin                   
insert into #finalresult
select 1 as result,replace(replace(replace(replace(replace(cast(dbo.fn_getchecktimeflow(@ivrflo,@Parentid) as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLERNO#') as msg,@appid  appid from user_detail(nolock) where user_id=@Parentid   
select @flowforinput=msg from #finalresult
insert into #flowwithgrpnumbers(flow)
exec [usp_getgroupnumbers] @flowforinput,@callerno
update f set msg=flow from #finalresult f join #flowwithgrpnumbers on 1=1
end
else
begin
insert into #finalresult
select 1 as result,REPLACE(replace(replace(replace(replace(cast(@ivrflo as nvarchar(max)),'#user#',user_login),'#password#',pwd),'http://kit19','https://kit19'),'http://www.kit19','https://www.kit19'),'#caller#','#CALLERNO#') as msg,@appid  appid  from user_detail(nolock) where user_id=@Parentid
select @flowforinput=msg from #finalresult
insert into #flowwithgrpnumbers(flow)
exec [usp_getgroupnumbers] @flowforinput,@callerno
update f set msg=flow from #finalresult f join #flowwithgrpnumbers on 1=1
end
select * from #finalresult
drop table #finalresult
drop table #flowwithgrpnumbers
end
end 







