    SELECT @REGNO = COUNT(*) FROM Cloud_DIDObtain WHERE Agent_No = @callerno  
    SELECT @TOTNO = COUNT(*) FROM cloud_user_phone WHERE Parentid= @Parentid  
    if @REGNO <> @TOTNO  
    begin  
     select @rslt = 'Not Registered', @output= 0   
    end  
   else  
   begin   
    update User_Detail set onduty = (case when isnull(onduty,0) = 1 then 0 else 1 end)                 
    where Parentid =@Parentid and  Mobile = @callerno and ISNULL(Cloudrole,0)=1                 
        
   select             
   @touser= rtrim(User_no),@email=email,@sms=sms from dbo.Cloud_notificationsetting                
   where User_id=@Parentid and NotificationId= 3              
       
   select @type = cast(isnull(chargeable,0) as varchar) from Cloud_NotificationMast             
   where NotificationId=3               
   if @ofdate=1              
    select @body = 'User '+@Loginid+' logged in into system',              
    @sub ='User Logged in'              
   if @ofdate=0              
    select @body = 'User '+@Loginid+' logged Off into system',              
    @sub ='User Logged off'              
        
   if @touser!=''            
   begin              
   if @sms=1              
    exec Cloud_smsNotification  @parentid,@body,@touser,@type                                      
   if @email=1              
    exec Cloud_emailNotification  @parentid,@body,@sub,@touser,@type                     
   end    
   end          
 end  
 else  
 begin  
 if not exists(select 1 from dbo.Cloud_DIDObtain where didno =@phno and Agent_No= @callerno            
   and CONVERT(date,getdate()) between CONVERT(date,ObtarinDt) and            
    CONVERT(date,DATEADD(MONTH,6,ObtarinDt)))             
   begin            
    Insert into Cloud_DIDObtain(DIDNo, ParentId, Agent_ID, Agent_No, ObtarinDt)            
  select @phno,@Pid,@user_id,@callerno,getdate()            
  select @rslt = 'Registered Ok', @output= 1                 
  select @output as result,@rslt as msg,@appid  appid            
  return            
 end   
 ---new logic for ivr  
 if exists (select 1 from dbo.Cloud_app_master where PhoneNo =@phno )         
 begin                      
  select @active= active,@Parentid= User_id from dbo.Cloud_app_master where PhoneNo =@phno                      
  if @active = 0                      
   select @rslt = 'Inactive App' ,@output= 88                     
  else                      
  begin                     
    select @costonecal = CallingCharges                      
  from Cloud_user_subscription sb inner join                       
  Cloud_plan_master pm on pm.planid = sb.plan_id where sb.Parentid = @Parentid                      
    select top 1 @bal= Balance from dbo.IntCredit_Details                       
    where USER_ID = @Parentid order by Credit_ID desc -- @                      
   select @active,@Parentid ,@bal,@costonecal                   
    if @bal > @costonecal                      
    begin           
  if exists(select 1 from Cloud_user_subscription where CONVERT(date,getdate()) 
	between convert(date,valid_from) and convert(date,valid_to) and Parentid = @Parentid)                 begin 
                     
  select @rslt= flow, @output= 1, @appid =cm.AppId  from dbo.Cloud_app_master cm                       
  inner join Cloud_flow_api flo on flo.Appid = cm.AppId where PhoneNo =@phno 
  end                     
   else
	 select @rslt = 'Acct Exp' ,@output= 88                      
    end                      
    else                      
  select @rslt = 'No Balance' ,@output= 88                      
   end                      
             
 end                      
 -----------------------new logic for ivr     
 end  
end  
else  
begin  
  
 if exists (select 1 from dbo.Cloud_app_master where PhoneNo =@phno )         
 begin                      
           
  select @active= active,@Parentid= User_id from dbo.Cloud_app_master where PhoneNo =@phno                      
  if @active = 0                      
   select @rslt = 'Inactive App' ,@output= 88                     
  else                      
  begin                     
    select @costonecal = CallingCharges                      
  from Cloud_user_subscription sb inner join                       
  Cloud_plan_master pm on pm.planid = sb.plan_id where sb.Parentid = @Parentid                      
    select top 1 @bal= Balance from dbo.IntCredit_Details                       
    where USER_ID = @Parentid order by Credit_ID desc -- @                      
   select @active,@Parentid ,@bal,@costonecal                   
    if @bal > @costonecal                      
    begin
           
  if exists(select 1 from Cloud_user_subscription where CONVERT(date,getdate()) 
	between convert(date,valid_from) and convert(date,valid_to) and Parentid = @Parentid)                 begin 
  select @rslt= flow, @output= 1, @appid =cm.AppId  from dbo.Cloud_app_master cm                       
  inner join Cloud_flow_api flo on flo.Appid = cm.AppId 
   where PhoneNo =@phno
   
   end
   else
	 select @rslt = 'Acct Exp' ,@output= 88                      
    end                      
    else                      
  select @rslt = 'No Balance' ,@output= 88                      
   end                      
                 
 end                      
  
end 
select @output as result,@rslt as msg,@appid  appid   

end



GO

/* ============================================================
   Procedure: [dbo].[Cloud_get_master]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_get_master](                    
@AppName varchar(100),                    
@AppId int,                    
@User_id bigint,                    
@Active int,     
@fltr varchar(max),                   
@opt int                    
)                    
as                    
                    
begin                    
Declare @result int                    
                  
if @opt = 5                    
begin                    
if LTRIM(rtrim(@fltr)) =''                  
 select cm.*,um.User_Login  from Cloud_app_master cm  (nolock)                  
  inner join user_detail um  (nolock) on um.User_id = cm.User_id                    
  where Active = @Active and cm.User_id =@User_id order by AppId desc  --order by mobile desc       
else    
  select cm.*,um.User_Login  from Cloud_app_master cm     (nolock)                
 inner join user_detail um  (nolock) on um.User_id = cm.User_id                    
 where Active = @Active and cm.User_id =@User_id      
 and (AppName like '%'+LTRIM(rtrim(@fltr))+'%' or    
 PhoneNo like '%'+LTRIM(rtrim(@fltr))+'%')    
 order by AppId desc   
 --order by mobile desc            
 --and cm.PhoneNo=''                   
end                    
                  
if @opt = 4                    
begin                    
if @Active > 0                 
begin                
if LTRIM(rtrim(@fltr)) =''                  
select cm.*,um.User_Login  from Cloud_app_master cm   (nolock)                  
inner join user_detail um  (nolock) on um.User_id = cm.User_id                    
 where Active = @Active   order by AppId desc    
else    
 select cm.*,um.User_Login  from Cloud_app_master cm  (nolock)                   
inner join user_detail um  (nolock) on um.User_id = cm.User_id                    
 where Active = @Active and cm.User_id =@User_id      
 and (AppName like '%'+LTRIM(rtrim(@fltr))+'%' or    
 PhoneNo like '%'+LTRIM(rtrim(@fltr))+'%')    
        
   order by AppId desc            
end                   
else    
begin    
if LTRIM(rtrim(@fltr)) =''                    
select cm.*,um.User_Login  from Cloud_app_master cm  (nolock)                   
inner join user_detail um  (nolock) on um.User_id = cm.User_id order by AppId desc                     
else    
select cm.*,um.User_Login  from Cloud_app_master cm     (nolock)                
inner join user_detail um  (nolock) on um.User_id = cm.User_id     
where cm.User_id =@User_id      
 and (AppName like '%'+LTRIM(rtrim(@fltr))+'%' or    
 PhoneNo like '%'+LTRIM(rtrim(@fltr))+'%')    
  
 order by AppId desc  
  
end                     
                    
end                    
if @opt = 1                    
begin                    
if @Active > 0                    
select cm.*,um.User_Login  from Cloud_app_master cm   (nolock)                  
inner join user_detail um  (nolock) on um.User_id = cm.User_id                    
 where cm.User_id =@User_id and Active = @Active  
 order by AppId desc  
                      
else               
                   
select cm.*,um.User_Login  from Cloud_app_master cm    (nolock)                 
inner join user_detail um  (nolock) on um.User_id = cm.User_id                    
 where cm.User_id = @User_id                    
  order by AppId desc  
                    
end                    
if @opt = 3                    
begin                    
if @Active > 0                    
select cm.*,um.User_Login  from Cloud_app_master cm    (nolock)                 
inner join user_detail um  (nolock) on um.User_id = cm.User_id                    
 where cm.User_id =@User_id and AppName = @AppName and Active = @Active                     
order by AppId desc  
  
else                     
select cm.*,um.User_Login  from Cloud_app_master cm  (nolock)                   
inner join user_detail um  (nolock) on um.User_id = cm.User_id                     
 where cm.User_id =@User_id and AppName = @AppName                    
 order by AppId desc                   
end                    
if @opt = 2                    
begin                    
if @Active > 0                    
select cm.*,um.User_Login  from Cloud_app_master cm      (nolock)               
inner join user_detail um  (nolock) on um.User_id = cm.User_id                    
where cm.User_id =@User_id and AppId = @AppId and Active = @Active                     
order by AppId desc  
else                    
select cm.*,um.User_Login  from Cloud_app_master cm  (nolock)                   
inner join user_detail um  (nolock) on um.User_id = cm.User_id                    
 where cm.User_id =@User_id and AppId = @AppId                    
order by AppId desc  
end                  
                
if(@opt=4)                
begin                
select AppName,AppId from Cloud_app_master  (nolock) where User_id=@User_id                
order by AppId desc  
end                
                    
end 


GO

/* ============================================================
   Procedure: [dbo].[Cloud_get_master_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Cloud_get_master_New  --'',0,36305,1,'',5
(  
 @AppName VARCHAR(100)  
 ,@AppId INT  
 ,@User_id BIGINT  
 ,@Active INT  
 ,@fltr VARCHAR(max)  
 ,@opt INT  
 )  
AS  
BEGIN  
 --Declare @AppName varchar(100)='', @AppId int=0, @User_id bigint=32222, @Active int=1, @fltr varchar(max)='', @opt int=5        
 DECLARE @ParentId BIGINT = @User_id  
 DECLARE @tbluser TABLE (  
  User_ID BIGINT  
  ,Name VARCHAR(100)  
  ,IMAGE VARCHAR(100)  
  )  
  
 INSERT INTO @tbluser  
 EXEC Use_GetUserDetails @ParentId  
  
 --set @User_id = 0;  
 DECLARE @result INT  
 DECLARE @TeamCode VARCHAR(10) = ''  
 DECLARE @ScopeCode VARCHAR(10) = ''  
 DECLARE @UserIdTeamLst VARCHAR(Max) = ''  
 DECLARE @UserLoginTeamLst VARCHAR(Max) = ''  
  
 -- select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@User_id)         
 -- select @TeamCode TeamCode, @ScopeCode ScopeCode, @UserIdTeamLst UserIdTeamLst, @UserLoginTeamLst UserLoginTeamLst        
 IF @opt = 5  
 BEGIN  
  IF LTRIM(rtrim(@fltr)) = ''  
   
   /*
   
   SELECT DISTINCT cm.*  
    ,um.User_Login  
    ,ISNULL(CFA.ActivateParallelRinging, 0) AS ParallelRinging  
    ,isnull(CFA.moh, '') AS MOHFileName  
    ,isnull(CAM.LibraryId, 0) AS MohFileID  
   FROM Cloud_app_master cm WITH (NOLOCK)  
   INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
   LEFT JOIN Cloud_flow_api CFA WITH (NOLOCK) ON cm.AppId = CFA.Appid  
   LEFT JOIN Cloud_audio_master CAM WITH (NOLOCK) ON CFA.moh = CAM.FileName  
    AND CAM.user_id = @User_id  
   WHERE cm.Active = @Active  
    AND cm.User_id = @User_id  
   ORDER BY cm.AppId DESC --order by mobile desc    
   
   */

   select a.User_id,a.AppName,a.AppId,c.PhoneNo,a.Active,a.CreatedDate,a.Miss_Call,a.User_Login
      ,a.ParallelRinging, a.MOHFileName,a.MohFileID  
     from
     (
    
	 SELECT cm.*  
    ,um.User_Login  
    ,ISNULL(CFA.ActivateParallelRinging, 0) AS ParallelRinging  
    ,isnull(CFA.moh, '') AS MOHFileName  
    ,isnull(CAM.LibraryId, 0) AS MohFileID  
    
   FROM 
   Cloud_app_master cm WITH (NOLOCK) -- on 1=1
   INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
   LEFT JOIN Cloud_flow_api CFA WITH (NOLOCK) ON cm.AppId = CFA.Appid  
   LEFT JOIN Cloud_audio_master CAM WITH (NOLOCK) ON CFA.moh = CAM.FileName AND CAM.user_id = @User_id   
   WHERE cm.Active = @Active   
    AND cm.User_id = @User_id  ) 
	a
	left join
	 (select phoneno,appid from Cloud_User_Phone(nolock) where parentid=@ParentId and active=@Active)
	 c on a.AppId=c.appid


  ELSE  
   
   /*
   SELECT DISTINCT cm.*  
    ,um.User_Login  
    ,ISNULL(CFA.ActivateParallelRinging, 0) AS ParallelRinging  
    ,isnull(CFA.moh, '') AS MOHFileName  
    ,isnull(CAM.LibraryId, 0) AS MohFileID  
   FROM Cloud_app_master cm WITH (NOLOCK)  
   INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
   LEFT JOIN Cloud_flow_api CFA WITH (NOLOCK) ON cm.AppId = CFA.Appid  
   LEFT JOIN Cloud_audio_master CAM WITH (NOLOCK) ON CFA.moh = CAM.FileName  
    AND CAM.user_id = @User_id  
   WHERE cm.Active = @Active  
    AND cm.User_id IN (  
     CASE   
      WHEN @UserIdTeamLst != ''  
       THEN @UserIdTeamLst  
      ELSE @User_id  
      END  
     )  
    AND (  
     AppName LIKE '%' + LTRIM(rtrim(@fltr)) + '%'  
     OR PhoneNo LIKE '%' + LTRIM(rtrim(@fltr)) + '%'  
     )  
   ORDER BY cm.AppId DESC  
    
	*/

	     select a.User_id,a.AppName,a.AppId,c.PhoneNo,a.Active,a.CreatedDate,a.Miss_Call,a.User_Login
      ,a.ParallelRinging, a.MOHFileName,a.MohFileID  
     from
     (
    
	 SELECT cm.*  
    ,um.User_Login  
    ,ISNULL(CFA.ActivateParallelRinging, 0) AS ParallelRinging  
    ,isnull(CFA.moh, '') AS MOHFileName  
    ,isnull(CAM.LibraryId, 0) AS MohFileID  
    
   FROM 
   Cloud_app_master cm WITH (NOLOCK) -- on 1=1
   INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
   LEFT JOIN Cloud_flow_api CFA WITH (NOLOCK) ON cm.AppId = CFA.Appid  
   LEFT JOIN Cloud_audio_master CAM WITH (NOLOCK) ON CFA.moh = CAM.FileName AND CAM.user_id = 36305   
   WHERE cm.Active = 1  
   AND cm.User_id IN (  
     CASE   
      WHEN @UserIdTeamLst != ''  
       THEN @UserIdTeamLst  
      ELSE @User_id  
      END  
     )  
    AND (  
     AppName LIKE '%' + LTRIM(rtrim(@fltr)) + '%'  
          OR PhoneNo LIKE '%' + LTRIM(rtrim(@fltr)) + '%'  
      )
	 )  
	a

	left join
	 (
	 select phoneno,appid from Cloud_User_Phone(nolock) 
	 where parentid = @ParentId
	 
	 and active=@Active
	 )
	 c on a.AppId=c.appid
	
	
	--order by mobile desc                    
    --and cm.PhoneNo=''                           
 END  
  
 IF @opt = 4  
 BEGIN  
  IF @Active > 0  
  BEGIN  
   IF LTRIM(rtrim(@fltr)) = ''  
    SELECT DISTINCT cm.*  
     ,um.User_Login  
    FROM Cloud_app_master cm WITH (NOLOCK)  
    INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
    WHERE Active = @Active  
    ORDER BY AppId DESC  
   ELSE  
    SELECT cm.*  
     ,um.User_Login  
    FROM Cloud_app_master cm WITH (NOLOCK)  
    INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
    WHERE Active = @Active  
     AND cm.User_id IN (  
      CASE   
       WHEN @UserIdTeamLst != ''  
        THEN @UserIdTeamLst  
       ELSE @User_id  
       END  
      )  
     AND (  
      AppName LIKE '%' + LTRIM(rtrim(@fltr)) + '%'  
      OR PhoneNo LIKE '%' + LTRIM(rtrim(@fltr)) + '%'  
      )  
    ORDER BY AppId DESC  
  END  
  ELSE  
  BEGIN  
   IF LTRIM(rtrim(@fltr)) = ''  
    SELECT DISTINCT cm.*  
     ,um.User_Login  
    FROM Cloud_app_master cm WITH (NOLOCK)  
    INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
    ORDER BY AppId DESC  
   ELSE  
    SELECT DISTINCT cm.*  
     ,um.User_Login  
    FROM Cloud_app_master cm WITH (NOLOCK)  
    INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
    WHERE cm.User_id IN (  
      CASE   
       WHEN @UserIdTeamLst != ''  
        THEN @UserIdTeamLst  
       ELSE @User_id  
       END  
      )  
     AND (  
      AppName LIKE '%' + LTRIM(rtrim(@fltr)) + '%'  
      OR PhoneNo LIKE '%' + LTRIM(rtrim(@fltr)) + '%'  
      )  
    ORDER BY AppId DESC  
  END  
 END  
  
 IF @opt = 1  
 BEGIN  
  IF @Active > 0  
   SELECT DISTINCT cm.*  
    ,um.User_Login  
   FROM Cloud_app_master cm WITH (NOLOCK)  
   INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
   WHERE cm.User_id = @User_id  
    AND Active = @Active  
   ORDER BY AppId DESC  
  ELSE  
   SELECT DISTINCT cm.*  
    ,um.User_Login  
   FROM Cloud_app_master cm WITH (NOLOCK)  
   INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
   WHERE cm.User_id = @User_id  
   ORDER BY AppId DESC  
 END  
  
 IF @opt = 3  
 BEGIN  
  IF @Active > 0  
   SELECT DISTINCT cm.*  
    ,um.User_Login  
   FROM Cloud_app_master cm WITH (NOLOCK)  
   INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
   WHERE cm.User_id IN (  
     CASE   
      WHEN @UserIdTeamLst != ''  
       THEN @UserIdTeamLst  
      ELSE @User_id  
      END  
     )  
    AND AppName = @AppName  
    AND Active = @Active  
   ORDER BY AppId DESC  
  ELSE  
   SELECT DISTINCT cm.*  
    ,um.User_Login  
   FROM Cloud_app_master cm WITH (NOLOCK)  
   INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
   WHERE cm.User_id IN (  
     CASE   
      WHEN @UserIdTeamLst != ''  
       THEN @UserIdTeamLst  
      ELSE @User_id  
      END  
     )  
    AND AppName = @AppName  
   ORDER BY AppId DESC  
 END  
  
 IF @opt = 2  
 BEGIN  
  IF @Active > 0  
   SELECT DISTINCT cm.*  
    ,um.User_Login  
   FROM Cloud_app_master cm WITH (NOLOCK)  
   INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
   WHERE cm.User_id IN (  
     CASE   
      WHEN @UserIdTeamLst != ''  
       THEN @UserIdTeamLst  
      ELSE @User_id  
      END  
     )  
    AND AppId = @AppId  
    AND Active = @Active  
   ORDER BY AppId DESC  
  ELSE  
   SELECT DISTINCT cm.*  
    ,um.User_Login  
   FROM Cloud_app_master cm WITH (NOLOCK)  
   INNER JOIN user_detail um WITH (NOLOCK) ON um.User_id = cm.User_id  
   WHERE cm.User_id IN (  
     CASE   
      WHEN @UserIdTeamLst != ''  
       THEN @UserIdTeamLst  
      ELSE @User_id  
      END  
     )  
    AND AppId = @AppId  
   ORDER BY AppId DESC  
 END  
  
 IF (@opt = 4)  
 BEGIN  
  SELECT DISTINCT AppName  
   ,AppId  
  FROM Cloud_app_master WITH (NOLOCK)  
  WHERE User_id IN (  
    CASE   
     WHEN @UserIdTeamLst != ''  
      THEN @UserIdTeamLst  
     ELSE @User_id  
     END  
    )  
  ORDER BY AppId DESC  
 END  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_id  
  ,@Activity_type = 'View_Ivrflow'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'Cloud_app_master'  
END  


