/* ============================================================
   Procedure: [dbo].[Cloud_get_phone_master]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_get_phone_master]    
(                
@PhoneId varchar(100),                
@Operator varchar(100),                
@PhoneNo int,                
@Active bit,        
@fltr varchar(250) ,               
@opt int                
)                
as                
                
begin         
        
        
        
CREATE TABLE #rmpfl(        
 [PhoneId] [int] ,        
 [Operator] [varchar](100) NULL,        
 [PhoneNo] [varchar](20) NULL,        
 [PhoneType] [varchar](100) NULL,        
 [Category] [varchar](20) NULL,        
 [Active] [bit] NULL,        
 [CreatedDate] [datetime] NULL,        
 [free] [bit] NULL,        
)         
        
        
            
Declare @result int                
if @opt = 5              
begin         
insert into #rmpfl(PhoneId, Operator, PhoneNo, PhoneType, Category, Active, CreatedDate, free)             
 select *  from Cloud_phone_master(nolock) where free = 1    and Active=1 --and reservedfor is null          
end               
if @opt = 1                
begin                
if @Active > 0          
insert into #rmpfl(PhoneId, Operator, PhoneNo, PhoneType, Category, Active, CreatedDate, free)               
 select * from Cloud_phone_master(nolock) where Active=1  and free=1 --and reservedfor is null            
end                
if @opt = 2                
begin                
if @Active > 0         
insert into #rmpfl(PhoneId, Operator, PhoneNo, PhoneType, Category, Active, CreatedDate, free)                
  select * from Cloud_phone_master(nolock) where PhoneId=@PhoneId and Active=1  --and reservedfor is null              
                
               
end                
if @opt = 3                
begin                
if @Active > 0                
insert into #rmpfl(PhoneId, Operator, PhoneNo, PhoneType, Category, Active, CreatedDate, free)                
select * from Cloud_phone_master(nolock) where PhoneNo=@PhoneNo and Active=1 --and reservedfor is null               
                
end                
if @opt = 4                
begin                
if @Active = 0                
insert into #rmpfl(PhoneId, Operator, PhoneNo, PhoneType, Category, Active, CreatedDate, free)         
  select * from Cloud_User_Phone           
end         
        
if LTRIM(rtrim(@fltr)) !=''         
select * from #rmpfl where PhoneNo like '%'+LTRIM(rtrim(@fltr))+'%' or PhoneType like '%'+LTRIM(rtrim(@fltr))+'%' or         
Category like '%'+LTRIM(rtrim(@fltr))+'%' or  Cast(CreatedDate as varchar) like '%'+LTRIM(rtrim(@fltr))+'%'        
else        
select * from #rmpfl        
        
drop table #rmpfl             
end 


GO

