CREATE   PROC [dbo].[Cloud_get_phone_master_Cost] --8
(
@panid int
)  
as 
begin      
declare @Normal_landline int =0, @VIP_landlin int =0,       
@VVIP_landlin int = 0, @Normal_Mob int = 0, @Vip_mob int = 0,      
@vvip_mob int = 0, @normal_tf int = 0, @vip_tf int = 0, @vvip_tf  int = 0      
      
select @Normal_landline=Normal_landline , @VIP_landlin = VIP_landlin,       
 @VVIP_landlin=VVIP_landlin, @Normal_Mob = Normal_Mob, @Vip_mob=Vip_mob,       
 @vvip_mob=vvip_mob, @normal_tf=normal_tf, @vip_tf=vip_tf, @vvip_tf=vvip_tf      
 from dbo.Cloud_Phone_cost     

CREATE TABLE #tmp (
	Operator [varchar](100) NULL,
	PhoneNo [varchar](20) NULL,
	PhoneType [varchar](100) NULL,
	Category [varchar](20) NULL,
	ph_nm_tp [varchar](100) NULL,
	cost int
)


if @panid =0
begin
	
		insert into #tmp (Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
		 PhoneNo +' (Landline)',@Normal_landline from Cloud_phone_master 
		 where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='Normal'
		 and ltrim(RTRIM(Category)) = 'Landline' order by PhoneNo 
		
		insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
		  PhoneNo +' (Mobile)',@Normal_Mob from Cloud_phone_master 
		 where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='Normal'
		 and ltrim(RTRIM(Category)) = 'Mobile'  order by PhoneNo
		
		 insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category
		 , PhoneNo +' (Tollfree)',@normal_tf from Cloud_phone_master 
		 where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='Normal'
		 and ltrim(RTRIM(Category)) = 'Tollfree'  order by PhoneNo
	
		 insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
		 PhoneNo +' (Landline)',@VIP_landlin from Cloud_phone_master 
		 where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='VIP'
		 and ltrim(RTRIM(Category)) = 'Landline'  order by PhoneNo 
	
		 insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
