		 where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='Normal'
		 and ltrim(RTRIM(Category)) = 'Mobile'  order by PhoneNo
		if @istollfree =1
		 insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
		 PhoneNo +' (Tollfree)',0 from Cloud_phone_master 
		 where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='Normal'
		 and ltrim(RTRIM(Category)) = 'Tollfree'  order by PhoneNo
	end 
	if @No_of_VIP > 0
	 begin
		if @islandline =1
		 insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
		 PhoneNo +' (Landline)',0 from Cloud_phone_master 
		 where free=1 and ltrim(RTRIM(Phonetype))='VIP'
		 and ltrim(RTRIM(Category)) = 'Landline'   order by PhoneNo
		if @isMobile =1
		 insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
		 PhoneNo +' (Mobile)',0 from Cloud_phone_master 
		 where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='VIP'
		 and ltrim(RTRIM(Category)) = 'Mobile'  order by PhoneNo
		if @istollfree =1
		 insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
		 PhoneNo +' (Tollfree)',0 from Cloud_phone_master 
		 where free=1 and Active=1  and ltrim(RTRIM(Phonetype))='VIP'
		 and ltrim(RTRIM(Category)) = 'Tollfree'  order by PhoneNo
	end 
	if @No_of_VVIP > 0
	 begin
		if @islandline =1
		 insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
		 PhoneNo +' (Landline)',0 from Cloud_phone_master 
		 where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='VVIP'
		 and ltrim(RTRIM(Category)) = 'Landline'  order by PhoneNo 
		if @isMobile =1
		 insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
		 PhoneNo +' (Mobile)',0 from Cloud_phone_master 
		 where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='VVIP'
		 and ltrim(RTRIM(Category)) = 'Mobile'  order by PhoneNo
		if @istollfree =1
		 insert into #tmp ( Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)
		 select  Operator,PhoneNo,PhoneType,Category,
		 PhoneNo +' (Tollfree)',0 from Cloud_phone_master 
		 where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='VVIP'
		 and ltrim(RTRIM(Category)) = 'Tollfree'  order by PhoneNo
end 
 end
 select * from #tmp where ltrim(RTRIM(Phonetype))='Normal'
 select * from #tmp where ltrim(RTRIM(Phonetype))='VIP'
 select * from #tmp where ltrim(RTRIM(Phonetype))='VVIP'
drop table  #tmp 
 end
 
 
   



