/* ============================================================
   Procedure: [dbo].[Cloud_get_phone_master_frplan1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_get_phone_master_frplan1] --0,335  
(  
@userId int  
)    
as   
begin        
declare @Normal_landline int =0, @VIP_landlin int =0,         
@VVIP_landlin int = 0, @Normal_Mob int = 0, @Vip_mob int = 0,        
@vvip_mob int = 0, @normal_tf int = 0, @vip_tf int = 0, @vvip_tf  int = 0        
  
 declare @PlanId as int
	 select @PlanId = planid from Price_UserSubscriptionDetails where UserId=@UserId and isnewPlan=1            


CREATE TABLE #tmp ( PhoneId int null ,  
 Operator [varchar](100) NULL,  
 PhoneNo [varchar](20) NULL,  
 PhoneType [varchar](100) NULL,  
 Category [varchar](20) NULL,  
 ph_nm_tp [varchar](100) NULL,  
 cost int  
)  
  declare @No_of_Phone int,  
   @No_of_VIP int,  
   @No_of_VVIP int,  
   @islandline bit,  
   @isMobile bit,  
   @istollfree bit  
  
   declare @No_of_Phone1 as int ,@No_of_Phone2 as int ,@No_of_Phone3 as int

 
 select @No_of_Phone1=[Value],@isMobile = case when [Value] <> 0 then 1 else 0 end  from  Price_ServiceCategoryLinkUserCopy where categoryid=43 and userid =@userId 
 select @No_of_Phone2=[Value],@islandline = case when [Value] <> 0 then 1 else 0 end from  Price_ServiceCategoryLinkUserCopy where categoryid=44 and userid =@userId
 select @No_of_Phone3=[Value],@istollfree = case when [Value] <> 0 then 1 else 0 end from  Price_ServiceCategoryLinkUserCopy where categoryid=45 and userid =@userId
 set @No_of_Phone=@No_of_Phone1+@No_of_Phone2+@No_of_Phone3
  if @No_of_Phone > 0  
  begin  
  if @islandline =1  
   insert into #tmp ( PhoneId,Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)  
   select  PhoneId,Operator,PhoneNo,PhoneType,Category,  
   PhoneNo +' (Landline)',0 from Cloud_phone_master   
   where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='Normal'  
   and ltrim(RTRIM(Category)) = 'Landline'   order by PhoneNo  
  if @isMobile =1  
   insert into #tmp ( PhoneId,Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)  
   select  PhoneId,Operator,PhoneNo,PhoneType,Category,  
   PhoneNo +' (Mobile)',0 from Cloud_phone_master   
   where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='Normal'  
   and ltrim(RTRIM(Category)) = 'Mobile'  order by PhoneNo  
  if @istollfree =1  
   insert into #tmp ( PhoneId,Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)  
   select  PhoneId,Operator,PhoneNo,PhoneType,Category,  
   PhoneNo +' (Tollfree)',0 from Cloud_phone_master   
   where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='Normal'  
   and ltrim(RTRIM(Category)) = 'Tollfree'  order by PhoneNo  
 end   

 select @No_of_Phone1=[Value],@isMobile = case when [Value] <> 0 then 1 else 0 end  from  Price_ServiceCategoryLinkUserCopy where categoryid=46 and userid =@userId 
 select @No_of_Phone2=[Value],@islandline = case when [Value] <> 0 then 1 else 0 end from  Price_ServiceCategoryLinkUserCopy where categoryid=47 and userid =@userId
 select @No_of_Phone3=[Value],@istollfree = case when [Value] <> 0 then 1 else 0 end from  Price_ServiceCategoryLinkUserCopy where categoryid=48 and userid =@userId
 set @No_of_VIP=@No_of_Phone1+@No_of_Phone2+@No_of_Phone3

 if @No_of_VIP > 0  
  begin  
  if @islandline =1  
   insert into #tmp ( PhoneId,Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)  
   select  PhoneId,Operator,PhoneNo,PhoneType,Category,  
   PhoneNo +' (Landline)',0 from Cloud_phone_master   
   where free=1 and ltrim(RTRIM(Phonetype))='VIP'  
   and ltrim(RTRIM(Category)) = 'Landline'   order by PhoneNo  
  if @isMobile =1  
   insert into #tmp ( PhoneId,Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)  
   select  PhoneId,Operator,PhoneNo,PhoneType,Category,  
   PhoneNo +' (Mobile)',0 from Cloud_phone_master   
   where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='VIP'  
   and ltrim(RTRIM(Category)) = 'Mobile'  order by PhoneNo  
  if @istollfree =1  
   insert into #tmp ( PhoneId,Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)  
   select  PhoneId,Operator,PhoneNo,PhoneType,Category,  
   PhoneNo +' (Tollfree)',0 from Cloud_phone_master   
   where free=1 and Active=1  and ltrim(RTRIM(Phonetype))='VIP'  
   and ltrim(RTRIM(Category)) = 'Tollfree'  order by PhoneNo  
 end 
 
 select @No_of_Phone1=[Value],@isMobile = case when [Value] <> 0 then 1 else 0 end  from  Price_ServiceCategoryLinkUserCopy where categoryid=49 and userid =@userId 
 select @No_of_Phone2=[Value],@islandline = case when [Value] <> 0 then 1 else 0 end from  Price_ServiceCategoryLinkUserCopy where categoryid=50 and userid =@userId
 select @No_of_Phone3=[Value],@istollfree = case when [Value] <> 0 then 1 else 0 end from  Price_ServiceCategoryLinkUserCopy where categoryid=51 and userid =@userId
 set @No_of_VVIP=@No_of_Phone1+@No_of_Phone2+@No_of_Phone3
   
 if @No_of_VVIP > 0  
  begin  
  if @islandline =1  
   insert into #tmp ( PhoneId,Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)  
   select  PhoneId,Operator,PhoneNo,PhoneType,Category,  
   PhoneNo +' (Landline)',0 from Cloud_phone_master   
   where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='VVIP'  
   and ltrim(RTRIM(Category)) = 'Landline'  order by PhoneNo   
  if @isMobile =1  
   insert into #tmp ( PhoneId,Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)  
   select  PhoneId,Operator,PhoneNo,PhoneType,Category,  
   PhoneNo +' (Mobile)',0 from Cloud_phone_master   
   where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='VVIP'  
   and ltrim(RTRIM(Category)) = 'Mobile'  order by PhoneNo  
  if @istollfree =1  
   insert into #tmp ( PhoneId,Operator,PhoneNo,PhoneType,Category,ph_nm_tp,cost)  
   select  PhoneId,Operator,PhoneNo,PhoneType,Category,  
   PhoneNo +' (Tollfree)',0 from Cloud_phone_master   
   where free=1 and Active=1 and ltrim(RTRIM(Phonetype))='VVIP'  
   and ltrim(RTRIM(Category)) = 'Tollfree'  order by PhoneNo  
end   
   
 select * from #tmp where ltrim(RTRIM(Phonetype))='Normal'  
 select * from #tmp where ltrim(RTRIM(Phonetype))='VIP'  
 select * from #tmp where ltrim(RTRIM(Phonetype))='VVIP'
 select  @No_of_Phone as NoNormal,@No_of_VIP as NoVIP,@No_of_VVIP as NoVVIP  
drop table  #tmp   
 end
   



