/* ============================================================
   Procedure: [dbo].[Cloud_get_plan_master]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext Cloud_get_plan_master

CREATE   PROC [dbo].[Cloud_get_plan_master]      
(      
@Opt int = 0,      
@planid INT ,  
@flt varchar(max)     
)      
AS BEGIN      
IF @Opt = 0   
begin  
if LTRIM(rtrim(@flt)) =''    
 SELECT *, (case when islandline=1 then 'Landline' else '' end    
 +', '+ case when isMobile=1 then 'Mobile' else '' end    
  +', '+ case when istollfree=1 then 'Tollfree' else '' end    
 ) ph_type FROM Cloud_plan_master WHERE Active = 1  
else  
 SELECT *, (case when islandline=1 then 'Landline' else '' end    
 +', '+ case when isMobile=1 then 'Mobile' else '' end    
  +', '+ case when istollfree=1 then 'Tollfree' else '' end    
 ) ph_type FROM Cloud_plan_master WHERE Active = 1 and  
 (PlanName like '%'+LTRIM(rtrim(@flt))+'%'   
 or cast(CreatedDate as varchar) like '%'+LTRIM(rtrim(@flt))+'%'   
 or cast(SubscriptionCharge as varchar) like '%'+LTRIM(rtrim(@flt))+'%'  
 or cast(PlanDuration as varchar) like '%'+LTRIM(rtrim(@flt))+'%' )  
end     
IF @Opt = 1  
begin   
if LTRIM(rtrim(@flt)) =''       
 SELECT *, (case when islandline=1 then 'Landline' else '' end    
  +', '+ case when isMobile=1 then 'Mobile' else '' end    
  +', '+ case when istollfree=1 then 'Tollfree' else '' end    
 ) ph_type FROM Cloud_plan_master    
else  
 SELECT *, (case when islandline=1 then 'Landline' else '' end    
  +', '+ case when isMobile=1 then 'Mobile' else '' end    
  +', '+ case when istollfree=1 then 'Tollfree' else '' end    
 ) ph_type FROM Cloud_plan_master    
 WHERE   
 (PlanName like '%'+LTRIM(rtrim(@flt))+'%'   
 or cast(CreatedDate as varchar) like '%'+LTRIM(rtrim(@flt))+'%'   
 or cast(SubscriptionCharge as varchar) like '%'+LTRIM(rtrim(@flt))+'%'   
 or cast(PlanDuration as varchar) like '%'+LTRIM(rtrim(@flt))+'%')  
end     
IF @Opt = 2   
begin   
if LTRIM(rtrim(@flt)) =''      
 SELECT *, (case when islandline=1 then 'Landline' else '' end    
  +', '+ case when isMobile=1 then 'Mobile' else '' end    
  +', '+ case when istollfree=1 then 'Tollfree' else '' end    
 ) ph_type FROM Cloud_plan_master WHERE planid = @planid    
else  
 SELECT *, (case when islandline=1 then 'Landline' else '' end    
  +', '+ case when isMobile=1 then 'Mobile' else '' end    
  +', '+ case when istollfree=1 then 'Tollfree' else '' end    
 ) ph_type FROM Cloud_plan_master WHERE planid = @planid   
 and  (PlanName like '%'+LTRIM(rtrim(@flt))+'%'   
 or cast(CreatedDate as varchar) like '%'+LTRIM(rtrim(@flt))+'%'   
 or cast(SubscriptionCharge as varchar) like '%'+LTRIM(rtrim(@flt))+'%'   
 or cast(PlanDuration as varchar) like '%'+LTRIM(rtrim(@flt))+'%')   
    
end       
END  


--sp_helptext Cloud_get_plan_master



GO

