/* ============================================================
   Procedure: [dbo].[Cloud_get_UserPhone]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Cloud_get_UserPhone -- '',335                
 (      
 @fltr VARCHAR(max)      
 ,@User_id BIGINT      
 )      
AS      
BEGIN      
 IF @User_id > 0      
 BEGIN      
  IF LTRIM(rtrim(@fltr)) = ''      
   SELECT up.*      
    ,User_login      
    ,pm.PhoneType      
    ,Category      
    ,(      
     SELECT TOP 1 isnull(AppName, '')      
     FROM Cloud_app_master    (nolock)  
     WHERE AppId = up.Appid      
     ) AS AppName      
    ,isnull(am.AppId, 0) App_id1      
   FROM Cloud_User_Phone up  (nolock)    
   INNER JOIN Cloud_phone_master pm (nolock) ON pm.PhoneNo = up.PhoneNo      
   INNER JOIN dbo.User_Detail ud (nolock) ON ud.User_id = up.Parentid      
   LEFT OUTER JOIN dbo.Cloud_app_master am (nolock) ON am.PhoneNo = up.PhoneNo      
    AND am.User_id = up.Parentid      
   WHERE ud.Parentid = @User_id  -- and PM.reservedfor is null    
  ELSE      
   SELECT up.*      
    ,urlname      
    ,user_url      
    ,User_login      
    ,pm.PhoneType      
    ,Category      
    ,(      
     SELECT TOP 1 isnull(AppName, '')      
     FROM Cloud_app_master (nolock)     
     WHERE AppId = up.Appid      
     ) AS AppName      
    ,isnull(am.AppId, 0) App_id1      
   FROM Cloud_User_Phone up  (nolock)    
   INNER JOIN Cloud_phone_master pm (nolock) ON pm.PhoneNo = up.PhoneNo      
   INNER JOIN dbo.User_Detail ud (nolock) ON ud.User_id = up.Parentid      
   LEFT OUTER JOIN dbo.Cloud_app_master am (nolock)  ON am.PhoneNo = up.PhoneNo      
    AND am.User_id = up.Parentid      
   INNER JOIN Cloud_url_Mst um (nolock) ON um.Parentid = up.Parentid      
   WHERE up.Parentid = @User_id -- and PM.reservedfor is null    
    AND (      
     pm.PhoneType LIKE '%' + LTRIM(rtrim(@fltr)) + '%'      
     OR Category LIKE '%' + LTRIM(rtrim(@fltr)) + '%'      
     OR pm.PhoneNo LIKE '%' + LTRIM(rtrim(@fltr)) + '%'      
     OR AppName LIKE '%' + LTRIM(rtrim(@fltr)) + '%'      
     )      
 END      
 ELSE      
 BEGIN      
  IF LTRIM(rtrim(@fltr)) = ''      
   SELECT up.*      
    ,urlname      
    ,user_url      
    ,User_login      
    ,pm.PhoneType      
    ,Category      
    ,(      
     SELECT TOP 1 isnull(AppName, '')      
     FROM Cloud_app_master  (nolock)    
     WHERE AppId = up.Appid      
     ) AS AppName      
    ,isnull(am.AppId, 0) App_id1      
   FROM Cloud_User_Phone up      
   INNER JOIN Cloud_phone_master pm(nolock)  ON pm.PhoneNo = up.PhoneNo      
   INNER JOIN dbo.User_Detail ud (nolock) ON ud.User_id = up.Parentid      
   LEFT OUTER JOIN dbo.Cloud_app_master am (nolock) ON am.PhoneNo = up.PhoneNo      
    AND am.User_id = up.Parentid      
   INNER JOIN Cloud_url_Mst um (nolock) ON um.Parentid = up.Parentid --where  PM.reservedfor is null      
  ELSE      
   SELECT up.*      
    ,urlname      
    ,user_url      
    ,User_login      
    ,pm.PhoneType      
    ,Category      
    ,(      
     SELECT TOP 1 isnull(AppName, '')      
     FROM Cloud_app_master (nolock)     
     WHERE AppId = up.Appid      
     ) AS AppName      
    ,isnull(am.AppId, 0) App_id1      
   FROM Cloud_User_Phone up      
   INNER JOIN Cloud_phone_master pm (nolock) ON pm.PhoneNo = up.PhoneNo      
   INNER JOIN dbo.User_Detail ud (nolock) ON ud.User_id = up.Parentid      
   LEFT OUTER JOIN dbo.Cloud_app_master am (nolock) ON am.PhoneNo = up.PhoneNo      
    AND am.User_id = up.Parentid      
   INNER JOIN Cloud_url_Mst um (nolock) ON um.Parentid = up.Parentid      
   WHERE    
   -- PM.reservedfor is null and    
     (      
     pm.PhoneType LIKE '%' + LTRIM(rtrim(@fltr)) + '%'      
     OR Category LIKE '%' + LTRIM(rtrim(@fltr)) + '%'      
     OR pm.PhoneNo LIKE '%' + LTRIM(rtrim(@fltr)) + '%'      
     OR AppName LIKE '%' + LTRIM(rtrim(@fltr)) + '%'      
     )      
 END      
      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_id      
  ,@Activity_type = 'View_didpn'      
  ,@ActionType = 'S'      
  ,@RowJson = ''      
  ,@Table_name = 'Cloud_User_Phone'      
END 


GO

