/* ============================================================
   Procedure: [dbo].[Cloud_getduty_info]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_getduty_info]  
(  
@Parentid as bigint,  
@fmdate datetime,  
@todate datetime  
)  
as  
begin  
  
select user_login [User Id],case when od.onduty=0 then 'Off Duty' else 'On Duty' end duty,   
 od.user_id, od.createddatetime, isnull(od.didno,'') [Dni No],   
 isnull(od.Agent_no,'') [Agent no],  
 convert(varchar, createddatetime,102) [Date],  
 convert(varchar, createddatetime,108) [Time]   
 from dbo.Cloud_Agent_OnDutyHistory od  
 inner join user_detail ud on od.user_id = ud.User_ID  
 where (od.Parentid = @Parentid or od.user_id = @Parentid) and Convert(date,createddatetime) between   
 Convert(date,@fmdate) and Convert(date,@todate)  
end  


GO

