SET QUOTED_IDENTIFIER ON

CREATE   PROC Cloud_getduty_info_agents    
(    
@Parentid as bigint,    
@fmdate datetime,    
@todate datetime    
)    
as    
begin    
    
select isnull(user_login,'Unknown') [User Id],AgentName,ud.id AgentId,case when od.onduty=0 then 'Off Duty' else 'On Duty' end duty,     
 od.user_id, od.createddatetime, isnull(od.didno,'') [Dni No],     
 isnull(od.Agent_no,'') [Agent no],    
 convert(varchar, createddatetime,102) [Date],    
 convert(varchar, createddatetime,108) [Time],
 Mode
 from dbo.Cloud_Agent_OnDutyHistory od(nolock)    
 inner join calling_agents ud(nolock) on od.calling_agentid = ud.id
 left join user_detail u (nolock) on u.user_id=ud.kit19userid
 where od.Parentid = @Parentid and Convert(date,createddatetime) between     
 Convert(date,@fmdate) and Convert(date,@todate)    
end 


