/* ============================================================
   Procedure: [dbo].[Cloud_GetGroupWiseUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_GetGroupWiseUser]                                  
(                                            
@groupid bigint ,        
@parentid bigint,        
@opt int                                  
)                                            
as                                            
begin                                            
if @opt =1                                
 select ud.user_id,@groupid GroupId, User_login, FName+' '+Lname usr_name, Fname,Role, Lname,Mobile,Email                  
  from dbo.Cloud_user_Group ug inner join dbo.User_Detail ud        
 on ud.User_id = ug.userid  and ud.Status = 1                 
 where ug.GroupId = @groupid and ud.Parentid=@Parentid order by Role, ISNULL(SequenceGRP,0)  asc                             
        
if @opt =2                                
 select ud.User_id,User_login +'-> ('+ FName+' '+Lname + ')' usr_name --, Fname,Role, Lname,Mobile,Email        
 from dbo.User_Detail ud        
 where ud.User_id not in (select userid from Cloud_user_Group where        
 GroupId = @groupid) and ud.Status = 1  and   Parentid = @parentid              
        
if @opt =3        
    delete Cloud_user_Group  where GroupId = @groupid and Userid = @parentid   
    -- update Cloud_user_Group  set Active = 0  
      --    WHERE GroupId = @groupid    
       --   AND Userid = @parentid  
end 


GO

/* ============================================================
   Procedure: [dbo].[Cloud_GetInsertUserdetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE [dbo].[Cloud_GetInsertUserdetails] -- 335,4                                    
(                                      
@ParentId bigint,                                  
                                    
@opt int                                      
                                      
)                                      
as                                      
begin                                      
if(@opt=1)                                      
begin                            
select User_id, User_login,Pwd,FName+' '+Lname usr_name, FName,Lname,IsInternalUser,Mobile,EMail,              
dbo.Cloud_Get_User_Group(User_id) as Groupname from user_detail where ParentID = @ParentID       
and User_id !=@ParentID                                      
end                                    
if(@opt=2)              
begin               
select *,FName+' '+Lname usr_name,dbo.Cloud_Get_User_Group(User_id) as Groupname ,Create_Date, role1 role             
 from dbo.Cloud_User_Detail where User_id !=@ParentID  and Active=1               
end                                  
if(@opt=3)              
begin      
     
 select gm.Groupname ,GroupId FROM Cloud_group_master gm      
 where GroupId in (select GroupId from Cloud_user_Group where parentid = @ParentId and gm.Active=1 )                                     
--select GroupId,Groupname from dbo.Cloud_group_master   where ParentId=@ParentID  and Active=1                
end                           
if(@opt=4)                            
begin                            
if @ParentID = 335                            
begin               
                          
 select ug.id, User_login,User_id, FName+' '+Lname usr_name, Fname,Lname,Mobile,Email,              
 Pwd ,dbo.Cloud_Get_User_Group(User_id) as Groupname,DateCreated,              
 Assign,Active from dbo.User_Detail cud
    inner join Cloud_user_Group ug on ug.userid = cud.User_ID    
    where cud.parentid=@ParentID and Active=1 order by ug.id desc                       
end                            
else                            
begin                            
 if exists (select 1 from User_Detail  where User_id = @ParentID and TYPE = 1 )                            
 begin                
                       
  declare @Mid as bigint = 0                            
  select  @Mid = Reseller_ID from reseller_detail  where User_id = @ParentID                            
  select User_id,* ,dbo.Cloud_Get_User_Group(User_id) as Groupname, FName+' '+Lname usr_name,         
  Mobile,Email, DateCreated            
   from dbo.User_Detail cud
    inner join Cloud_user_Group ug on ug.userid = cud.User_ID               
   where cud.Parentid in                             
  (select @ParentID from User_Detail  where M_ID =@Mid)                              
 end                            
 else                            
 begin               
                        
 select  User_id,cud.User_login,cud.Fname,cud.Lname,cud.Pwd , FName+' '+Lname usr_name,         
 dbo.Cloud_Get_User_Group(User_id) as Groupname,DateCreated, Assign,Active,              
 dbo.Cloud_Get_User_Group(User_id) as Groupname from dbo.User_Detail as Cud
 inner join Cloud_user_Group ug on ug.userid = cud.User_ID               
 where cud.parentid=@ParentID               
 end                            
end                            
                            
end                                   
                                      
end   




