SET QUOTED_IDENTIFIER ON

--select ud.*  FROM  dbo.Cloud_User_Detail ud  
--  inner join dbo.Cloud_user_Group gp  
--  on gp.userid = ud.User_id  
--  where gp.GroupId = 6 and ud.Active = 1 and gp.Active = 1  
  
--  update ud set mobile ='9718896162' from  dbo.Cloud_User_Detail ud  
--  inner join dbo.Cloud_user_Group gp  
--  on gp.userid = ud.User_id  
--  where gp.GroupId = 6 and ud.Active = 1 and gp.Active = 1  

CREATE   PROC [dbo].[cloud_GetMaildetail] -- '7291889439' ,8,'group'
(  
@didno  varchar(20),  
@groupid varchar(50),
@opt varchar(10) 
 
)  
as  
begin  
declare @active as bit   
declare @Parentid as bigint  
declare @rslt as varchar(max) = ''     
if exists (select 1 from dbo.Cloud_app_master where PhoneNo =@didno)    
	begin    
		select @active= active,@Parentid= User_id from dbo.Cloud_app_master where PhoneNo =@didno    
		if @active = 0    
		select 'ERR' rslt    
		else    
	begin    
	DECLARE @email VARCHAR(8000), @mobile  VARCHAR(8000)
	if @opt='group'
	begin
		SELECT @email = COALESCE(@email + ', ', '') + email ,
		@mobile = COALESCE(@mobile + ', ', '') + mobile  
		FROM  dbo.Cloud_User_Detail ud  
		inner join dbo.Cloud_user_Group gp  
		on gp.userid = ud.User_id  
		where gp.GroupId = CAST(@groupid AS int) and ud.Active = 1 and gp.Active = 1  
	end
	else
	begin
		SELECT @email = COALESCE(@email + ', ', '') + SpecificEmail ,
		@mobile = COALESCE(@mobile + ', ', '') + SpecificMobileNo  
		from usersearchlist 
		where ParentID = @Parentid and IsSearch =1 and SearchName=@groupid and SpecificMobileNo is not null
	end
	select 'OK' rslt, isnull(email,'contactus@email19.in') email,User_Login,Pwd,user_id,
	email toemail,@mobile mobile  from user_detail   
	where user_id = @Parentid   

end 
END
ELSE
	select 'ERR' rslt   

end  



GO

