CREATE   PROCEDURE [dbo].[Cloud_GetUserdetails]  --27726,4                                                
(                                                  
@ParentId bigint,                                              
@filter varchar(100),                                              
@opt int                                                  
                                                  
)                                                  
as                                                  
begin                                                  
if(@opt=1)                                                  
begin            
if LTRIM(rtrim(@filter)) !=''                                       
begin            
 select User_id, User_login,Pwd,FName+' '+Lname usr_name, FName,Lname,IsInternalUser,              
 Mobile,EMail, isnull(dbo.Cloud_Get_User_Group(User_id),'') as Groupname into #tmptbl1            
 from user_detail where ParentID = @ParentID and User_id !=@ParentID  and Cloudrole=1 and Status=1            
             
 select * from #tmptbl1 where User_id like '%'+LTRIM(rtrim(@filter))+'%' or            
 User_login like '%'+LTRIM(rtrim(@filter))+'%' or            
 FName like '%'+LTRIM(rtrim(@filter))+'%' or            
 Lname like '%'+LTRIM(rtrim(@filter))+'%' or            
 Mobile like '%'+LTRIM(rtrim(@filter))+'%' or            
 EMail like '%'+LTRIM(rtrim(@filter))+'%' or            
 Groupname  like '%'+LTRIM(rtrim(@filter))+'%'            
 drop table #tmptbl1            
 return            
end                 
else            
select User_id, User_login,Pwd,FName+' '+Lname usr_name, FName,Lname,IsInternalUser,              
 Mobile,EMail,Pwd , isnull(dbo.Cloud_Get_User_Group(User_id),'') as Groupname             
 from user_detail where ParentID = @ParentID and User_id !=@ParentID  and Cloudrole=1 and Status=1            
             
end                                                
if(@opt=2)                          
begin            
if LTRIM(rtrim(@filter)) !=''                                       
begin            
 select *,isnull(dbo.Cloud_Get_User_Group(User_id),'') as Groupname                         
   into #tmptbl from dbo.User_Detail where User_id !=@ParentID  and Cloudrole=1 and Status=1      
                               
 select * from #tmptbl where User_id like '%'+LTRIM(rtrim(@filter))+'%' or            
  User_login like '%'+LTRIM(rtrim(@filter))+'%' or            
  FName like '%'+LTRIM(rtrim(@filter))+'%' or            
  Lname like '%'+LTRIM(rtrim(@filter))+'%' or            
  Mobile like '%'+LTRIM(rtrim(@filter))+'%' or            
  EMail like '%'+LTRIM(rtrim(@filter))+'%' or            
  Groupname  like '%'+LTRIM(rtrim(@filter))+'%'            
 drop table #tmptbl            
 return            
end            
else                          
 select *,isnull(dbo.Cloud_Get_User_Group(User_id),'') as Groupname                         
 from dbo.User_Detail where User_id !=@ParentID  and Cloudrole=1 and Status=1                            
end                                              
if(@opt=3)                          
begin            
if LTRIM(rtrim(@filter)) !=''                                                 
 select GroupId,Groupname from dbo.Cloud_group_master              
   where ParentId=@ParentID  and Active=1 and             
   Groupname like '%'+LTRIM(rtrim(@filter))+'%'            
else            
 select GroupId,Groupname from dbo.Cloud_group_master               
 where ParentId=@ParentID  and Active=1                             
end                                       
if(@opt=4)                                        
begin            
if LTRIM(rtrim(@filter)) !=''            
begin                                       
  select id, User_login,User_id, FName+' '+Lname usr_name, Fname,Lname,Mobile,Email,                      Pwd ,isnull(dbo.Cloud_Get_User_Group(User_id),'') as Groupname,              
   case when Cloudrole=0 then 'No Access' WHEN Cloudrole=2 then 'User' else 'Admin' End as [Role] , onduty ,status as Active, dbo.[Cloud_CheckUserPhoneActivated](User_id) subscribe                          ,case when @ParentID=User_id then 1 else 0 end noneditable  into #tmptbl2                          
  from dbo.User_Detail where                            
  parentid=@ParentID and Cloudrole=1 and Status=1            
  select * from #tmptbl2 where User_id like '%'+LTRIM(rtrim(@filter))+'%' or            
  User_login like '%'+LTRIM(rtrim(@filter))+'%' or            
  FName like '%'+LTRIM(rtrim(@filter))+'%' or            
  Lname like '%'+LTRIM(rtrim(@filter))+'%' or            
  Mobile like '%'+LTRIM(rtrim(@filter))+'%' or            
  EMail like '%'+LTRIM(rtrim(@filter))+'%' or            
  Groupname  like '%'+LTRIM(rtrim(@filter))+'%'            
    order by id desc            
 drop table #tmptbl2            
 return            
end            
else            
          
  select id, User_login,User_id, FName+' '+Lname usr_name, Fname,Lname,Mobile,Email,                      Pwd ,isnull(dbo.Cloud_Get_User_Group(User_id),'') as Groupname,              
   case when Cloudrole=0 then 'No Access' WHEN Cloudrole=2 then 'User' else 'Admin' End  
    as [Role] ,  onduty ,status as Active,  
  dbo.[Cloud_CheckUserPhoneActivated](User_id) subscribe   ,case   
  when @ParentID=User_id then 1 else 0 end noneditable from dbo.User_Detail where                            
   parentid=@ParentID  order by id desc                                  
end                                               
            
if(@opt=5)                                        
begin    
 select ud.User_login, User_login +'-> ('+ FName+' '+Lname+'-> '+Mobile+'-> '+Email+')' usr_name        from dbo.User_Detail ud              
 where ud.status = 1  and   Parentid = @Parentid and  Cloudrole=1 and Status=1                
end                                                   
end           
if(@opt=6)                                          
begin              
  select id, User_login,User_id, FName+' '+Lname usr_name, Fname,Lname,Mobile,Email,
		Pwd ,isnull(dbo.Cloud_Get_User_Group(User_id),'') as Groupname,                
	   case when Cloudrole=0 then 'No Access' WHEN Cloudrole=2 then 'User' else 'Admin' End    
		as [Role] ,  onduty ,status as Active,    
	   dbo.[Cloud_CheckUserPhoneActivated](User_id) subscribe   ,case
	  when @ParentId=User_id then 1 else 0 end noneditable from dbo.User_Detail where                  	   user_id=@ParentId  order by id desc                                    
end            
          
