/* ============================================================
   Procedure: [dbo].[cloud_insert_Audiofile]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext [cloud_insert_Audiofile]                
CREATE   PROC [dbo].[cloud_insert_Audiofile]  --0,335,'raju_3008201','D:\cloud\CloudTelephonic\Audiofile\raju_30082018.mp3', 'U','UTS','',2                    
(                      
@id bigint,                       
@clientid bigint,                       
@name varchar(500),                       
@R_url varchar(200),                        
@status varchar(1),                       
@RecType varchar(3),                      
@VText varchar(max),                        
@opt int =0                      
)                      
as                       
begin       
      
declare @ismoh int=isnull((select top 1 ismoh from cloud_audio_master(nolock) where filename+'_'+cast(FORMAT(GETDATE(), 'ddMMyyyy') as nvarchar)=@name       
and user_id in (select user_id from user_detail(nolock) where parentid=@clientid)      
 order by libraryid desc),0)                 
declare @mname varchar(100) ='' ,@rst bigint                      
if @opt= 0                      
if @RecType='TTS'                      
begin                      
if exists(select 1 from Cloud_PlayFile(nolock) where ltrim(rtrim(VText)) = ltrim(rtrim(@VText))                      
 and clientid = @clientid)                      
 select @mname=name from Cloud_PlayFile(nolock) where ltrim(rtrim(VText)) = ltrim(rtrim(@VText))                      
 and clientid = @clientid                      
end                      
if @RecType='UTS'                      
begin                      
if exists(select 1 from Cloud_PlayFile(nolock) where ltrim(rtrim(name)) = ltrim(rtrim(@name))                      
  and clientid = @clientid)                   
  begin                     
 select @mname=name from Cloud_PlayFile(nolock) where ltrim(rtrim(name)) = ltrim(rtrim(@name))                      
   and clientid = @clientid                     
   end                  
--select @name=replace(replace(replace(replace(@r_url,'.mp3',''),'.wav',''),'E:\SMS19.COM\CloudTelephonic\Audiofile\',''),'I:\temp\','')                  
end                  
if @mname!=''                      
 select 0 as reslt,@mname name                      
else                      
begin                      
 insert into dbo.Cloud_PlayFile(clientid, name, R_url, status, RecType,VText,ismoh)                      
 select @clientid, replace(@name,'Audiofile\\',''),  replace(@R_url,'Audiofile\\',''), 'U', @RecType,@VText,@ismoh                      
 select @rst=SCOPE_IDENTITY()        
 select @rst reslt,replace(@name,'Audiofile\\','') name     
if @ismoh=1 and @rst is not null       
begin        
begin try        
declare @directory nvarchar(1000)= '/usr/ELFEC/'+cast(@clientid as nvarchar)+'/moh/'+cast(@clientid as nvarchar)+'_'+        
@name,@q nvarchar(max)        
select @q='CALL asterisk.usp_insertmohfile('''+@name+''','''+@directory+''')'        
print @q   
begin try  
EXEC(@q) AT MYSQL  
end try  
begin catch        
exec usp_InsertErrorInfo        
end catch        
begin try  
EXEC(@q) AT MYSQL_New1  
end try  
begin catch        
exec usp_InsertErrorInfo        
end catch        
end try        
begin catch        
exec usp_InsertErrorInfo        
end catch        
end                       
end                       
if @opt= 1                      
begin                    
update dbo.Cloud_PlayFile set status='P' where id = @id                      
select @@ROWCOUNT reslt,'' name                      
end                    
if @opt= 2                      
select * from Cloud_PlayFile(nolock) where status= 'U'                      
end         
        
        
--declare @clientid bigint=33819,@name nvarchar(100)='test_remote_sql'        
--declare @directory nvarchar(1000)= '/usr/ELFEC/'+cast(@clientid as nvarchar)+'/moh/'+cast(@clientid as nvarchar)+'_'+        
--@name,@q nvarchar(max)        
--select @q='CALL asterisk.usp_insertmohfile('''+@name+''','''+@directory+''')'        
--print @q        
--EXEC(@q) AT MYSQL


