SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_Insert_UserPhone]  
(  
@User_id bigint,  
@PhoneNo Nvarchar(20),  
@AppId bigint,  
@Opt int  
)  
as   
begin  
declare @id bigint
if @Opt = 0  
begin  
insert into Cloud_User_Phone(Parentid, PhoneNo,AppId) values (@User_id,@PhoneNo,@AppId) 
select @id=scope_identity()
declare @m_id bigint,@user_login nvarchar(50),@count bigint,@description nvarchar(200)
select @m_id=M_id,@user_login=user_login from user_detail (nolock) where USER_ID=@user_id
select @count=COUNT(1) from Cloud_User_Phone(nolock) where Parentid=@user_id
if @m_id=10043 and @count=1
begin
select @description='User '+cast(@user_login as nvarchar)+' purchased first DID number '
exec Usp_InsertUserEventDetails 'User purchased first DID number',@user_ID,@Description,'Cloud_User_Phone',@ID  
end 
 
update dbo.Cloud_phone_master set free = 0 where PhoneNo = @PhoneNo  
update dbo.Cloud_app_master set PhoneNo = @PhoneNo where AppId = @AppId  


end  
if @Opt = 1  
begin  
update Cloud_User_Phone set AppId =@AppId where Parentid=@User_id  
update dbo.Cloud_app_master set  PhoneNo = @PhoneNo where AppId = @AppId  
end  
if @Opt = 4  
begin  
delete from Cloud_User_Phone where Parentid=@User_id  
update dbo.Cloud_phone_master set free = 1 where PhoneNo = @PhoneNo  
update dbo.Cloud_app_master set PhoneNo = ''  where AppId = @AppId    
end  
end  


GO

