   Procedure: [dbo].[Cloud_InsertTicket_Detail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_InsertTicket_Detail]                    
(                    
  @ParentID bigint,                    
  @Login_id nvarchar(100),                     
  @Pwd nvarchar(100),                     
  @Name nvarchar(100),                     
  @Mobile nvarchar(20),                     
  @Email nvarchar(100),                     
  @Company nvarchar(100),                     
  @Country nvarchar(100),                     
  @City nvarchar(100),                     
  @State nvarchar(100),                     
  @Address nvarchar(Max)='',                     
  @Zip int,         
  @appnm varchar(100),                    
  @Option nvarchar(50)='Insert'                    
)                    
--ser_user_id, , Status, Date_Created                    
--dbo.Serv_User_Detail                    
                    
as                    
Begin               
                    
declare  @oldpwd nvarchar(100)=''                
if @Pwd=''                
 set @pwd= ROUND((2998+ 25678)* RAND(),0)                
                  
declare @ser_user_id bigint                    
                   
 if(not exists (select 'x' from Serv_User_Detail where ParentID = @ParentID and Mobile = @Mobile))        Begin                    
   insert into Serv_User_Detail(ParentId,  Login_id, Pwd, Name, Mobile,                    
    Email, Company, Country, City, State, Address, Zip)                     
     values(@ParentId,  @Email, @Pwd, @Name, @Mobile,                    
    @Email, @Company, @Country, @City, @State, @Address, @Zip)                    
                    
                
  select @ser_user_id = SCOPE_IDENTITY()                    
                  
  update Serv_User_Detail set User_id= @ser_user_id where                 
      ser_user_id = @ser_user_id                
                  
   insert into Serv_User_Master (ParentID, Email_id,Service_User,Service_id)                    
   Values (@ParentID, @Email, 1, @ser_user_id)                    
               
  if not EXISTS(select 'x' from userleads where MobileNo = @Mobile or MobileNo1 = @Mobile        
      or MobileNo2 = @Mobile and parentid=@parentid)        
  begin            
   DECLARE @Leadno BIGINT = isnull((select MAX(LeadNo)                                               
     FROM   UserLeads WHERE  ParentID = @ParentId),0)+1                     
   declare @medium as varchar(100)        
   set @medium= 'ivr -'+@appnm        
       
   declare @SourceID bigint, @MediumID bigint          
   if not exists(select 1 from UserMediumSettings                          
   where NAME=@medium and UserID= @ParentID)        
   begin        
    Insert into UserMediumSettings(Name,UserID,IsEditable,IsActive,CreatedDate,        
    ModifiedDate,ModifiedBy)        
    select @medium,@ParentID,1,1,GETDATE(),GETDATE(),@ParentID        
    select @MediumID = SCOPE_IDENTITY()          
   end        
        
   else        
    select @MediumID=MediumID          
    from UserMediumSettings                          
    where  NAME=@medium and UserID= @ParentID               
           
   if not exists(select 1 from UserSourceSettings                          
   where NAME='Inbound call' and UserID= @ParentID )        
   begin        
    Insert into UserSourceSettings(Name,UserID,IsEditable,IsActive,CreatedDate,        
    ModifiedDate,ModifiedBy)        
    select 'Inbound call',@ParentID,1,1,GETDATE(),GETDATE(),@ParentID        
            
    select @SourceId = SCOPE_IDENTITY()          
   end        
   else        
    select @SourceID=SourceID          
    from UserSourceSettings                          
    where NAME='Inbound call' and UserID= @ParentID                
           
   Insert into userleads (LeadNo,PersonName,EmailID,MobileNo,          
    AssignedTo,SourceName,MediumName, ParentID,                            
      Remarks,CreatedOn,CreatedBy,FollowUpStatus,NextStatusDate,followupdate)                                  
      select @leadno,@Name,@Email,@Mobile,@ParentId,            
      @SourceID,@MediumID,@ParentId,'Lead Added From Support Ticket API',GETDATE(),        
      @ParentId,1 ,GETDATE(),GETDATE()                             
      declare @leadid bigint               
  end         
  else        
  begin        
          
   select @ser_user_id =ser_user_id from Serv_User_Detail         
     where ParentID = @ParentID and Mobile = @Mobile        
           
   --select PersonName, EmailID, MobileNo,'' Company, Country, City,         
   --State, '' Address, '' Zip,@ParentID ParentID,@ser_user_id ser_user_id from userleads         
   --where MobileNo = @Mobile or MobileNo1 = @Mobile or MobileNo2 = @Mobile        
  end                
 end        
 --else        
 --begin        
          
     
          
    --end               
                        
 exec serv_Raise_emailNotification 0,@ParentID,0 , @ser_user_id,@ser_user_id,'User Activation Email','Agent'              
    exec serv_Raise_emailNotification 0,@ParentID,0 , @ser_user_id,@ser_user_id,'User Activation Email','Requester'                      
    
 select @ser_user_id =ser_user_id from Serv_User_Detail         
     where ParentID = @ParentID and Mobile = @Mobile        
        
  select Name PersonName, Email EmailID,  Mobile MobileNo,  Company, Country, City,         
   State, Address, Zip,@ParentID ParentID,@ser_user_id ser_user_id from Serv_User_Detail         
   where ParentID = @ParentID and Mobile = @Mobile              
 end 


GO

