/* ============================================================
   Procedure: [dbo].[Cloud_InsertUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_InsertUser]            
(            
@tbl tbl_CloudUser READONLY ,            
@parentid bigint          
          
)            
as            
begin            
  declare @grpid as bigint  
  select top 1 @grpid= GroupId from dbo.Cloud_group_master where parentid = @parentid and Groupname='User'       
 insert into Cloud_User_Detail(parentid, User_id, User_login, Pwd, Fname, Lname, Mobile,Email,Role1)            
 select @parentid, User_id, User_login,Pwd, FName,Lname, Mobile, Email,'User' from @tbl  where            
 User_id not in (select USER_ID from Cloud_User_Detail) and             
 active = 1       
   declare @Userid bigint=(select top 1 CUG.User_id  from Cloud_User_Detail as CUG inner join @tbl 
   as TB on CUG.User_id=Tb.User_id and cug.Active=1)      
    
 insert Into Cloud_user_Group(GroupId,userid,parentid,Assign,Active)     
    select @grpid, User_id,@parentid, 1,1 from @tbl  where            
 User_id not in (select USER_ID from Cloud_User_Detail) and             
 active = 1             
    --values( 0, @Userid,@parentid,)        
                  
 update um set um.active = tbl.active from Cloud_User_Detail um inner join @tbl tbl             
 on tbl.User_id = um.User_id            
 --where tbl.active = 0            
            
 update um set um.IsInternalUser = tbl.active from user_detail um inner join @tbl tbl             
 on tbl.User_id = um.User_id      
     
 select @@ROWCOUNT rslt          
  end 



GO

/* ============================================================
   Procedure: [dbo].[Cloud_InsertUser_manual]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_InsertUser_manual]            
(            
@tbl tbl_CloudManualUser READONLY ,            
@parentid bigint ,        
@Groupid int,        
@Role varchar(10),        
@Assign bit,        
        
@Active bit ,      
@ids bigint,       
@opt int      
        
        
          
          
)            
as            
begin            
  if(@opt=1)     
 begin         
 insert into Cloud_User_Detail(parentid, User_login, Pwd, Fname, Lname, Mobile,Email, active)            
 select top 1 @parentid, User_login,Pwd, FName,Lname, Mobile, Email, 1 from @tbl           
 declare @id  bigint =  SCOPE_IDENTITY()        
 update Cloud_User_Detail set User_id= @id where id = @id      
   
 select 1    
         
 if (@id > 0)      
    insert Into Cloud_user_Group(GroupId,userid,parentid,Role,Assign,Active)     
    select group_id, @id,@parentid,@Role,@Assign,@Active from @tbl       
 end            
   if(@opt=2)  
   begin    
    update  Cloud_User_Detail set Active=@Active where id=@ids and parentid=@parentid     
      
    declare @userids bigint=(select User_id from Cloud_User_Detail where id=@ids and parentid=@parentid)  
 update Cloud_user_Group   set Active=@Active where userid=@userids and parentid=@parentid  
 end
 if(@opt=3)
 begin
 update ss set ss.Pwd=a.Pwd,ss.Fname=a.Fname,ss.Lname=a.Lname,
	ss.Email=a.Email,ss.Mobile=a.Mobile
   from Cloud_User_Detail ss inner join   @tbl a  
 on a.User_id = ss.User_id and ss.id=@ids 
 
 delete from Cloud_user_Group where  userid in (select User_id from @tbl)
 and  parentid=@parentid 

     insert Into Cloud_user_Group(GroupId,userid,parentid,Role,Assign,Active)     
    select group_id, User_id,@parentid,@Role,@Assign,@Active from @tbl     
end
  
        
end 



