/* ============================================================
   Procedure: [dbo].[Cloud_new_logRept]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_new_logRept]         
(                
@didNo as varchar(20),              
@parentid as bigint               
)                 
as                
begin                
if @didNo=''     
begin               
     
select dialstatus as Disposition,uniqueid,callerid,agentnumber,User_Login into #tmpfl from    
(    
select  lg.uniqueid,row_number() over (partition by kcd.puniqueid order by kcd.call_end_time desc)     
as rn, KCD.dialstatus,lg.callerid,kcd.agentnumber,ud.User_Login from kit19calls as LG inner join Kit19CallsDialled as KCD on    
KCD.puniqueid=lg.uniqueid  left  outer join User_detail AS ud on ud.Mobile=kcd.agentnumber    
)tt     
where rn=1    
    
    
 select tp.User_login as Agent_Name, call_start_time ,cam.AppName, lg.callerid ,isnull(ul.PersonName,'') name,              
  convert(varchar(5),DateDiff(s, call_start_time, call_end_time)/3600)+':'+convert(varchar(5),      
DateDiff(s, call_start_time,  call_end_time)%3600/60)+':'+convert(varchar(5),      
(DateDiff(s, call_start_time, call_end_time)%60))as      
   Duration, context,  tp.Disposition, recordurl, '' Credits,               
  Channel, dnid ,isnull(clientid,'') clientid,lg.appid               
  from [Kit19Calls] (nolock) lg left outer join #tmpfl tp    
  on tp.uniqueid = lg.uniqueid  left outer join UserLeads ul   (nolock)   
  on (ul.MobileNo = lg.callerid or ul.MobileNo1 = lg.callerid or ul.MobileNo2 = lg.callerid)  and @parentid=ul.ParentID          
  left join  Cloud_app_master As cam  on cam.AppId=lg.appid
  where dnid in (select PhoneNo from dbo.Cloud_app_master where USER_ID =@parentid)  order by call_start_time desc            
    
end    
else      
select dialstatus as Disposition,uniqueid,callerid,User_Login into #tmpf2 from    
(    
select  lg.uniqueid,row_number() over (partition by kcd.puniqueid order by kcd.call_end_time desc)     
as rn, KCD.dialstatus,lg.callerid,kcd.agentnumber,ud.User_Login from kit19calls as LG inner join Kit19CallsDialled as KCD on    
KCD.puniqueid=lg.uniqueid  left  outer join User_detail AS ud on ud.Mobile=kcd.agentnumber    
)tt1     
where rn=1              
  select  tp.User_login as Agent_Name, call_start_time , lg.callerid ,isnull(ul.PersonName,'') name,       
        
  convert(varchar(5),DateDiff(s, call_start_time, call_end_time)/3600)+':'+convert(varchar(5),      
DateDiff(s, call_start_time,  call_end_time)%3600/60)+':'+convert(varchar(5),      
(DateDiff(s, call_start_time, call_end_time)%60))as             
   Duration, context, '' Disposition, recordurl, '' Credits,               
  Channel, dnid ,isnull(clientid,'') clientid, lg.appid                
  from [Kit19Calls](nolock)  lg   left outer join #tmpfl tp    
  on tp.uniqueid = lg.uniqueid   left outer join UserLeads ul   (nolock)              
  on (ul.MobileNo = lg.callerid or ul.MobileNo1 = lg.callerid or ul.MobileNo2 = lg.callerid    )  and @parentid=ul.ParentID   
         
   where dnid = @didNo  order by call_start_time desc                
     
 drop table #tmpfl    
                 
end


GO

