   Procedure: [dbo].[Cloud_new_logRept1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_new_logRept1] --31078,'','1','20'                
(                        
                     
@parentid as bigint,      
@filtertext as NVARCHAR(max)=null,      
@srno NVARCHAR(100)=null,                                                          
@enno NVARCHAR(100)=null                      
)                         
as                        
begin   
if(@srno is null)    
begin  
set @srno='1';  
set @enno='20';  
end  
IF OBJECT_ID('tempdb.dbo.##call_log', 'U') IS NOT NULL                   
  begin                                 
  DROP TABLE ##call_log;                                   
  end           
  declare @Query nvarchar(max) = '';    
    select distinct a.id, a.call_start_time, a.uniqueid, a.callerid, a.channel, a.context, a.dnid, a.clientid, a.appid, a.recordurl,a.call_end_time , b.user_login,isnull(ul.PersonName,'') name into #tmp1 from kit19calls a (nolock) left join UserLeads ul (nolock) on (ul.MobileNo = a.callerid or ul.MobileNo1 = a.callerid or ul.MobileNo2 = a.callerid or ul.MobileNo = a.dnid or ul.MobileNo1 = a.dnid or ul.MobileNo2 = a.dnid) left join user_detail b on ul.parentid=b.parentid  where b.parentid=@parentid
          
  select distinct a.id, a.call_start_time, a.uniqueid, a.callerid, a.channel, a.context, a.dnid, a.clientid, a.appid, a.recordurl,a.call_end_time , b.user_login, '' as name into #tmp2 from kit19calls a (nolock) left join cloud_app_master c (nolock) on (a.dnid=c.PhoneNo or a.callerid=c.PhoneNo) left join user_detail b on c.user_id=b.User_ID where b.ParentID=@parentid
       
select * into #tmp3 from #tmp1 union select * from #tmp2
      
select a.id, a.call_start_time, a.uniqueid, a.callerid, a.Channel, a.CONTEXT, a.dnid, a.clientid, a.appid, b.appname, a.recordurl, a.call_end_time, a.user_login, a.name, dbo.billduration (a.uniqueid) as billduration, dbo.callstatus (a.uniqueid) as callstatus, dbo.callduration (a.uniqueid) as callduration into #tmp4 from #tmp3 a left join Cloud_app_master b on a.appid=b.AppId order by a.id desc    
if(@filtertext is not null and @filtertext!='')    
begin     
set @Query='select * into ##call_log from #tmp4 '+@filtertext;     
end       
else    
begin    
set @Query='select * into ##call_log from #tmp4';    
end             
       EXEC  sp_executesql @Query;     
       declare @rc varchar(15) ;                       
      select  @rc = Count(*) from ##call_log;                
           select * from (select ROW_NUMBER() OVER(Order By ID desc) AS RowNumber1, @rc AS rc1, * from ##call_log)aa where  RowNumber1 between @srno and @enno;                          
       IF OBJECT_ID('tempdb.dbo.##call_log', 'U') IS NOT NULL                   
  begin                                 
  DROP TABLE ##call_log;                                   
  end               
drop table #tmp1      
drop table #tmp2      
drop table #tmp3    
drop table #tmp4                     
end


GO

