/* ============================================================
   Procedure: [dbo].[Cloud_new_logRept3_Cache]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Cloud_new_logRept3_Cache]      
(                                    
	@parentid as bigint,      
	@filtertext as NVARCHAR(max)=null,      
	@srno NVARCHAR(100)=null,      
	@enno NVARCHAR(100)=null                                  
)                                         
as                                        
begin           
			if(@srno is null)            
			 begin            
			  set @srno='1';            
			  set @enno='20';            
			 end  
       
				Declare @fromdate NVARCHAR(50),@todate NVARCHAR(50);
				--declare @filtertext as NVARCHAR(max)=' where call_start_time >= ''11-26-2024'' and call_start_time <= ''11-27-2024''';
				  SET @fromdate = SUBSTRING(
						@filtertext,
						CHARINDEX('>=', @filtertext) + 4, -- Start after ">='"
						CHARINDEX('''', @filtertext, CHARINDEX('>=', @filtertext) + 4) - (CHARINDEX('>=', @filtertext) + 4) -- Length of the date
					);

					-- Extract the second date (after "<=")
					SET @todate = SUBSTRING(
						@filtertext,
						CHARINDEX('<=', @filtertext) + 4, -- Start after "<='"
						CHARINDEX('''', @filtertext, CHARINDEX('<=', @filtertext) + 4) - (CHARINDEX('<=', @filtertext) + 4) -- Length of the date
					);

				DECLARE @MonthStart NVARCHAR(50);
				DECLARE @MonthEnd NVARCHAR(50);
				declare @Parent_ID bigint = 0;		

			    --select @Parent_ID = ParentID from Mysms.[dbo].User_Detail(nolock) where User_ID = @parentid;

				-- Get the first and last date of the current month
				--SET @MonthStart = FORMAT(DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)), 'MM-dd-yyyy'); -- Format: Month Day, Year
				--SET @MonthEnd = FORMAT(EOMONTH(GETDATE()), 'MM-dd-yyyy'); -- Format: Month Day, Year

				Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			    SET @MonthStart      = FORMAT(DATEADD(DAY, -30, @Currentdate), 'MM-dd-yyyy'); -- 30 days before today
				SET @MonthEnd  =  FORMAT(DATEADD(DAY, -1, @Currentdate), 'MM-dd-yyyy');

					DECLARE @sql NVARCHAR(MAX);

				-- Check conditions and select data
				IF (@FromDate Between @MonthStart AND @MonthEnd AND @ToDate Between @MonthStart AND @MonthEnd)
					BEGIN
						SET @sql = 'SELECT [CallLogsId]
								  ,[RowNumber1]
								  ,[rc1]
								  ,[id]
								  ,[call_last_dtmf]
								  ,[call_start_time]
								  ,[uniqueid]
								  ,[callerid]
								  ,[channel]
								  ,[context]
								  ,[dnid]
								  ,[clientid]
								  ,[appid]
								  ,[recordurl]
								  ,[call_end_time]
								  ,[user_login]
								  ,[name]
								  ,[billduration]
								  ,[callstatus]
								  ,[callduration]
								  ,[AgentUser]
								  ,[UserId]
								  ,[ParentId]
							  FROM [dbo].[tbl_CallLogs_Cache](nolock)
							' + @filtertext + ' AND [UserId] = '+ CAST(@parentid AS NVARCHAR)  + ' and RowNumber1 between ' + @srno + ' and ' + @enno + ' order by id desc;';
					END
				ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
					BEGIN
						SET @sql = 'SELECT [CallLogsId]
							  ,[RowNumber1]
							  ,[rc1]
							  ,[id]
							  ,[call_last_dtmf]
							  ,[call_start_time]
							  ,[uniqueid]
							  ,[callerid]
							  ,[channel]
							  ,[context]
							  ,[dnid]
							  ,[clientid]
							  ,[appid]
							  ,[recordurl]
							  ,[call_end_time]
							  ,[user_login]
							  ,[name]
							  ,[billduration]
							  ,[callstatus]
							  ,[callduration]
							  ,[AgentUser]
							  ,[UserId]
							  ,[ParentId]
						  FROM [dbo].[tbl_CallLogs_Archive](nolock)
						' + @filtertext + ' AND [UserId] = '+ CAST(@parentid AS NVARCHAR)  + ' and RowNumber1 between ' + @srno + ' and ' + @enno + ' order by id desc;';
					END
				ELSE
					BEGIN
						EXEC [Mysms].[dbo].Cloud_new_logRept3 @parentid,@filtertext, @srno, @enno;
					END

					EXEC sp_executesql @sql, 
                       N'@ParentID BIGINT', 
                       @ParentID = @parentid;                           
end 



GO

/* ============================================================
   Procedure: [dbo].[Cloud_new_logRept3_ForExport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_new_logRept3_ForExport] --27741,'',null,null                           
(                                
@parentid as bigint,
@filtertext as NVARCHAR(max)=null,
@srno NVARCHAR(100)=null,
@enno NVARCHAR(100)=null
)                                     
as                                    
begin       

-- declare @parentid bigint=35396,@filtertext NVARCHAR(max)=' where call_start_time >= ''09/21/2020'' and call_start_time <= ''09/22/2020'' and dbo.callstatus1 (a.uniqueid) = ''NOANSWER''',@srno NVARCHAR(100)='1',@enno NVARCHAR(100)='20'
-- declare @parentid bigint=35396,@filtertext NVARCHAR(max)='',@srno NVARCHAR(100)='1',@enno NVARCHAR(100)='20'

