 /*IF OBJECT_ID('tempdb.dbo.##call_log', 'U') IS NOT NULL            
 begin            
 DROP TABLE ##call_log;            
 end*/            

DECLARE @isadmin int;                                              
SELECT @parentid=ParentID,@isadmin=IsAdmin  FROM dbo.User_Detail(NOLOCK) WHERE User_ID = @UserId;                      
Declare @TeamCode varchar(10) = ''    
Declare @ScopeCode varchar(10) = ''     
Declare @UserIdTeamLst varchar(5000) = ''     
Declare @UserLoginTeamLst varchar(5000) = ''     
Declare @HierarchyJSON varchar(Max) = ''

 if Exists(select 1 from tbl_UA_UserHierarchy where ParentId = @ParentId) 
 Begin 
 Select @HierarchyJSON = HierarchyJSON from tbl_UA_UserHierarchy where ParentId = @ParentId 

  Create TABLE #TableData2 ([user_id] bigint, team_name Varchar(50), user_login varchar(50), username varchar(50), [parentid] bigint)
  Insert into #TableData2 ([user_id], team_name, user_login,username,[parentid])               
  Select [user_id], '', user_login, username, [parentid] from OPENJSON(@HierarchyJSON) with ([user_id] bigint, user_login Varchar(100), username Varchar(100), [parentid] bigint)

  ;with CTE(user_id) 
 as ( 
  select user_id 
  from #TableData2 where (User_id = @UserId or parentid = @UserId)
  union all 
  -- recursively add children
  select c.user_id
  from #TableData2 c 
  join CTE on c.parentid = CTE.User_id
 ) 
SELECT @UserIdTeamLst = STUFF((SELECT distinct ',' + Cast( a.user_id as varchar(4000)) from #TableData2 a join CTE on CTE.user_id = a.User_id FOR XML PATH('')),1,1,'')
 
--, @UserIdTeamLst = ''
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode from ufn_GetUserRoleScope(@UserId) 

 --select * from #TableData2 
 --select @UserIdTeamLst 
 End
 Else
 Begin
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId) 
 End            

 declare @Query nvarchar(max) = ''            
 --Added code below, comment further below            
 declare @query1 nvarchar(max)=''            
            
 set @query1=            
 '
 Select * from (
 Select  ROW_NUMBER() OVER(Order By A.ID desc) AS RowNumber1, count(*)over(order by A.User_Login) AS rc1, * From (            
 select            
 a.id,      
 a.call_last_dtmf,            
 a.call_start_time,            
 a.uniqueid,            
 a.callerid,            
 a.channel,            
 a.context,            
 a.dnid,            
 a.clientid,            
 c.AppName as appid,            
 a.recordurl,            
 a.call_end_time ,            
 b.user_login,  
 isnull(b.FName,'''') + '' '' + isnull(b.LName,'''')  as [User FullName] ,
 isnull(ul.PersonName,'+''''+''''+') name,            
 dbo.billduration1 (a.uniqueid) as billduration,            
 dbo.callstatus1 (a.uniqueid) as callstatus,            
 dbo.callduration (a.uniqueid) as callduration,            
 isnull(dbo.lastagentattended(a.uniqueid),'+''''+''''+') as AgentUser            
 --into ##Call_log            
 from kit19calls a (nolock)            
 left outer join cloud_app_master (nolock) c on c.AppId=a.appid            
 --left join cloud_user_phone(nolock) cu on cu.PhoneNo = isnull(a.clientid,(select case when a.context<>''inbound'' then a.callerid else a.dnid end))            
 --left outer join UserLeads ul (nolock) on isnull(a.clientid,cu.parentid)=ul.ParentID and    
 left outer join UserLeads ul (nolock) on a.clientid=ul.ParentID and          
 case            
 when a.context<>''inbound'' and a.dnid in (ul.MobileNo,ul.MobileNo1,ul.MobileNo2) then 1            
 when a.context=''inbound'' and a.callerid in (ul.MobileNo,ul.MobileNo1,ul.MobileNo2) then 1            
 else 0 end=1            
 --inner join user_detail (NOLOCK) b on b.user_id=isnull(a.clientid,cu.parentid)            
 inner join user_detail (NOLOCK) b on b.user_id=a.clientid  
 where b.user_id='+cast(@parentid as nvarchar)+' '+case when @ft IS not null and @ft<>'' then @ft else '' end+' ) A Where A.AgentUser ' +   
  case when @isadmin=1 then   
  ' = A.AgentUser '  
  when isnull(@UserLoginTeamLst, '') != '' then ' in (' + @UserLoginTeamLst + ')'  
  else   
  ' like ''%'+@UserLogin+'%''  '  
  end 
  +') B Where RowNumber1 between ' + @srno + ' and ' + @enno 
  
 print @query1            
 exec (@query1)            
            
 -- Replace  like ''%'+@UserLogin+'%'' to in (' + @UserLoginTeamLst + ')  
 /*            
 declare @rc varchar(15) ;            
 select @rc = Count(*) from ##call_log;            
 select * from (select ROW_NUMBER() OVER(Order By ID desc) AS RowNumber1, @rc AS rc1, * from ##call_log) A where RowNumber1 between @srno and @enno;                                          
 IF OBJECT_ID('tempdb.dbo.##call_log', 'U') IS NOT NULL                                         
 begin                                                       
 DROP TABLE ##call_log;                                                         
 end            
 */            
            
  /*              
                            
select distinct        
 a.id,                     
 a.call_start_time,                     
 a.uniqueid,                     
 a.callerid,                     
 a.channel,                     
 a.context,                     
 a.dnid,                     
 a.clientid,                     
 c.AppName as appid,                    
 --a.appid,                     
 a.recordurl,                    
 a.call_end_time ,                     
 b.user_login,                    
isnull(ul.PersonName,'') name,          
dbo.billduration (a.uniqueid) as billduration,                     
dbo.callstatus (a.uniqueid) as callstatus,                     
dbo.callduration (a.uniqueid) as callduration                      
into #tmp4                     
from kit19calls a (nolock)                     
left outer join cloud_app_master (nolock) c on c.AppId=a.appid                    
left outer join UserLeads ul (nolock) on a.clientid=ul.ParentID and                    
case                     
when a.context='outbound' and a.dnid in (ul.MobileNo,ul.MobileNo1,ul.MobileNo2) then 1                     
when a.context<>'outbound' and a.callerid in (ul.MobileNo,ul.MobileNo1,ul.MobileNo2) then 1                     
else 0 end=1                     
inner join  user_detail (NOLOCK) b  on a.clientid=b.user_id                      
where b.user_id=@parentid order by a.id desc                          
if(@filtertext is not null and @filtertext!='')                          
begin                           
set @Query='select * into ##call_log from #tmp4 '+@filtertext;                           
end                             
else                          
begin                          
set @Query='select * into ##call_log from #tmp4';                          
end                                   
       EXEC  sp_executesql @Query;                           
       declare @rc varchar(15) ;                                             
      select  @rc = Count(*) from ##call_log;                                      
           select * from (select ROW_NUMBER() OVER(Order By ID desc) AS RowNumber1, @rc AS rc1, * from ##call_log)aa where  RowNumber1 between @srno and @enno;                                                
                    
IF OBJECT_ID('tempdb.dbo.##call_log', 'U') IS NOT NULL                                         
  begin                                                       
  DROP TABLE ##call_log;                                                         
  end                                     
--drop table #tmp1                            
--drop table #tmp2                            
--drop table #tmp3                          
drop table #tmp4   */                                        
end     




