/* ============================================================
   Procedure: [dbo].[Cloud_new_logRept3_ForSingleUser_Cache]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Cloud_new_logRept3_ForSingleUser_Cache]            
(        
@UserID as bigint,
@parentid as bigint,
@filtertext as NVARCHAR(max)=null,            
@srno NVARCHAR(100)=null,            
@enno NVARCHAR(100)=null                                        
)                                               
as                                              
begin                 
            select @parentid = ParentID from Mysms.[dbo].User_Detail(nolock) where User_ID = @UserID;

			if(@srno is null)            
			 begin            
			  set @srno='1';            
			  set @enno='20';            
			 end  

			Declare @fromdate NVARCHAR(50),@todate NVARCHAR(50);
				--declare @filtertext as NVARCHAR(max)=' where call_start_time >= ''11-26-2024'' and call_start_time <= ''11-27-2024''';
				  SET @fromdate = SUBSTRING(
						@filtertext,
						CHARINDEX('>=', @filtertext) + 4, -- Start after ">='"
						CHARINDEX('''', @filtertext, CHARINDEX('>=', @filtertext) + 4) - (CHARINDEX('>=', @filtertext) + 4) -- Length of the date
					);

					-- Extract the second date (after "<=")
					SET @todate = SUBSTRING(
						@filtertext,
						CHARINDEX('<=', @filtertext) + 4, -- Start after "<='"
						CHARINDEX('''', @filtertext, CHARINDEX('<=', @filtertext) + 4) - (CHARINDEX('<=', @filtertext) + 4) -- Length of the date
					);

				DECLARE @MonthStart NVARCHAR(50);
				DECLARE @MonthEnd NVARCHAR(50);
				declare @Parent_ID bigint = 0;		

				Declare @UserLoginTeamLst varchar(5000) = ''  
				DECLARE @isadmin int; 

				Declare @UserLogin nvarchar(200) = ''        
        
			 select @UserLogin = isnull(User_login,'') from Mysms.[dbo].User_Detail where User_ID = @UserID 
			--select @Parent_ID = ParentID, @isadmin=IsAdmin from Mysms.[dbo].User_Detail(nolock) where User_ID = @parentid;

				-- Get the first and last date of the current month
				--SET @MonthStart = DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)); -- First day of current month
				--SET @MonthEnd = EOMONTH(GETDATE()); -- Last day of current month

				--SET @MonthStart = FORMAT(DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)), 'MM-dd-yyyy'); -- Format: Month Day, Year
				--SET @MonthEnd = FORMAT(EOMONTH(GETDATE()), 'MM-dd-yyyy'); -- Format: Month Day, Year


				Declare @Currentdate  DATE  = GETDATE();  -- Today's date
			    SET @MonthStart      = FORMAT(DATEADD(DAY, -30, @Currentdate), 'MM-dd-yyyy'); -- 30 days before today
				SET @MonthEnd  =  FORMAT(DATEADD(DAY, -1, @Currentdate), 'MM-dd-yyyy');

					DECLARE @sql NVARCHAR(MAX);

				-- Check conditions and select data
				IF (@FromDate Between @MonthStart AND @MonthEnd AND @ToDate Between @MonthStart AND @MonthEnd)
					BEGIN
						SET @sql = 'SELECT [CallLogsId]
							  ,[RowNumber1]
							  ,[rc1]
							  ,[id]
							  ,[call_last_dtmf]
							  ,[call_start_time]
							  ,[uniqueid]
							  ,[callerid]
							  ,[channel]
							  ,[context]
							  ,[dnid]
							  ,[clientid]
							  ,[appid]
							  ,[recordurl]
							  ,[call_end_time]
							  ,[user_login]
							  ,[name]
							  ,[billduration]
							  ,[callstatus]
							  ,[callduration]
							  ,[AgentUser]
							  ,[UserId]
							  ,[ParentId]
						  FROM [dbo].[tbl_CallLogs_Cache](nolock)
						' + @filtertext + ' AND [UserId] = '+  CAST(@UserID AS NVARCHAR) +' AND AgentUser ' +   
							  case when @isadmin=1 then   
							  ' = AgentUser '  
							  when isnull(@UserLoginTeamLst, '') != '' then ' in (' + @UserLoginTeamLst + ')'  
							  else   
							  ' like ''%'+@UserLogin+'%''  '  
							  end 
							  +'';
					END
				ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
					BEGIN
						SET @sql = 'SELECT [CallLogsId]
							  ,[RowNumber1]
							  ,[rc1]
							  ,[id]
							  ,[call_last_dtmf]
							  ,[call_start_time]
							  ,[uniqueid]
							  ,[callerid]
							  ,[channel]
							  ,[context]
							  ,[dnid]
							  ,[clientid]
							  ,[appid]
							  ,[recordurl]
							  ,[call_end_time]
							  ,[user_login]
							  ,[name]
							  ,[billduration]
							  ,[callstatus]
							  ,[callduration]
							  ,[AgentUser]
							  ,[UserId]
							  ,[ParentId]
						  FROM [dbo].[tbl_CallLogs_Archive](nolock)
						' + @filtertext + ' AND [UserId] = '+ CAST( @UserID  AS NVARCHAR) +' AND AgentUser ' +   
							  case when @isadmin=1 then   
							  ' = AgentUser '  
							  when isnull(@UserLoginTeamLst, '') != '' then ' in (' + @UserLoginTeamLst + ')'  
							  else   
							  ' like ''%'+@UserLogin+'%''  '  
							  end 
							  +'';
					END
				ELSE
					BEGIN
						EXEC [Mysms].[dbo].Cloud_new_logRept3_ForSingleUser @UserID, @parentid, @filtertext, @srno, @enno;
					END


					EXEC sp_executesql @sql, 
                       N'@UserId BIGINT', 
                       @UserId = @UserID;                                   
end     



GO

