left join cloud_user_phone(nolock) cu on cu.PhoneNo = isnull(a.clientid,(select case when a.context=''outbound'' then a.callerid else a.dnid end))        
left outer join UserLeads ul (nolock) on isnull(a.clientid,cu.parentid)=ul.ParentID and          
case           
when a.context=''outbound'' and a.dnid in (ul.MobileNo,ul.MobileNo1,ul.MobileNo2) then 1     
when a.context<>''outbound'' and a.callerid in (ul.MobileNo,ul.MobileNo1,ul.MobileNo2) then 1        
else 0 end=1    
inner join  user_detail (NOLOCK) b  on b.user_id=isnull(a.clientid,cu.parentid)            
where b.user_id='+cast(@parentid as nvarchar)+' '+case when @ft IS not null and @ft<>'' then @ft else '' end+' order by a.id desc'    
