select distinct           
 a.id,           
 a.call_start_time,           
 a.uniqueid,           
 a.callerid,           
 a.channel,           
 a.context,           
 a.dnid,           
 a.clientid,           
 c.AppName as appid,          
 --a.appid,           
 a.recordurl,          
 a.call_end_time ,           
 b.user_login,          
isnull(ul.PersonName,'') name,          
dbo.billduration (a.uniqueid) as billduration,           
