 	@UserID bigint, 
 	@parentid bigint,
 	@FilterText nvarchar(max) = N'',  
 	@FullText as NVARCHAR(max) = N'',
 	@SearchText as NVARCHAR(max) = N'',
 	@OffsetValue INT = 0, 
 	@PagingSize INT = 100  
 )
 as
begin
	
	--declare 
	--	@UserID bigint=46657, 
	--	@parentid as bigint = 46622,
	--	@FilterText nvarchar(max) = N'cast([name] as varchar ) like ''%pawan%''',  
	--	@FullText as NVARCHAR(max) = N'',
	--	@SearchText as NVARCHAR(max) = N'',
	--	@OffsetValue INT = 0, 
	--	@PagingSize INT = 100  

	declare @isadmin int, @ft nvarchar(max), @TeamCode varchar(10) = '', @ScopeCode varchar(10) = '', 
		@UserIdTeamLst varchar(500) = ''
	
	select @parentid = ParentID, @isadmin = IsAdmin  from MySMS.dbo.User_Detail(nolock) where User_ID = @UserId;                        
  

	if(@OffsetValue is null)            
	begin            
		set @OffsetValue='1';            
		set @PagingSize='20';            
	end            

	if(@FullText != '')
	Begin
		set @FullText = concat(N' and 1 = (case ',
				N' when ul.PersonName like ''%', @FullText ,'%'' then 1 ',
				N' when ul.MobileNo like ''%', @FullText ,'%'' then 1 ',
				N' when ul.MobileNo1 like ''%', @FullText ,'%'' then 1 ',
				N' when ul.MobileNo2 like ''%', @FullText ,'%'' then 1 ',
				N' when ul.EmailId like ''%', @FullText ,'%'' then 1 ',
				N' when ul.EmailId1 like ''%', @FullText ,'%'' then 1 ',
				N' when ul.EmailId2 like ''%', @FullText ,'%'' then 1 ',
				N' when ul.LeadNo like ''%', @FullText ,'%'' then 1 ',
				N' when c.Customernumber like ''%', @FullText ,'%'' then 1 ',
				' else 0 end )'
			);
		set @FilterText = '';
		set @SearchText = '';
	end
	
	if(@FilterText != '')
	begin
		set @ft = 'and ' + @FilterText            
		set @FullText = '';
		set @SearchText = '';
	end

	if(@SearchText != '')          
	begin
		--set @SearchText = ' and CallsMsgStatus like ''%' + @SearchText + '%'''
		set @FullText = '';
		set @FilterText = '';
	end 

	select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from MySMS.dbo.ufn_GetUserRoleScope(@UserId)    

	declare @StartPoint int = @OffsetValue + 1, @EndPoint int  = (@OffsetValue + @PagingSize )

	set @FilterText = REPLACE(@FilterText, 'Agent not attempted', '')
	declare @FinalQuery nvarchar(max), @SqlQuery1 nvarchar(max), @SqlQuery2 nvarchar(max), @SqlQuery3 nvarchar(max)

	drop table if exists #tempUsers    
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))    
	insert into #tempUsers(User_ID, Name, Image)    
	exec Use_GetUserDetails @UserID = @UserId 

	declare @sqlCallLog1 nvarchar(max),@sqlCallLog2 nvarchar(max), @sqlCallLog3 nvarchar(max), @sqlCallLogFinal nvarchar(max);

	set @sqlCallLog1 = concat(N';with calllogData as ( select ',
				N'ROW_NUMBER() OVER(order by cl.parentid, cast(cl.callcreatedon as datetime) desc) AS [RowNumber1], ',
				N'id, parentid, Date, Customernumber, customerentity, customerentityid, uniqueid, callerid, channel, context, clientid, appid, CustomerName, ',
				N'dnid, Gateway, IVFlow, CallsMsgStatus, [name], LeadNo, LeadId, Image, CsvMobileNo, CsvEmailId, billduration, callstatus, AgentUser, agentname, ',
				N'agentid, direction, Outcome, OutcomeName, RecodingUrl, Remarks, MobileNo, CallGetway, user_login, CustomerDisposition, AgentDisposition, ',
				N'call_start_time, call_end_time, CustomerDuration, agentDuration, Callduration, recordurl, AgentMode, call_last_dtmf, callcreatedon ',
			N'from ( select c.id, c.parentid, c.callcreatedon as Date, Customernumber, customerentity, customerentityid, a.uniqueid, a.callerid, a.channel, ',
				N'(case when c.direction = ''incoming'' then ''inbound'' when c.direction in (''out'', ''Outgoing'') then ''outbound-user'' else a.context end) as [context], ',
				N'a.clientid, m.AppName as appid, isnull (dbo.fn_getentityfullname(customerentity, customerentityid), '''') as CustomerName, ',
				N'isnull(c.dnid, '''') as [dnid], ',
				N'(case when c.gatewayid = 0 then ''Sim'' else s.provider_name end) as Gateway, ',
				N'isnull(m.AppName, '''') IVFlow, ',
				N'iif(a.id is null, '''', ( case ',
				N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') or (a.context = ''inbound'')) ',
					N'and (dbo.callstatus1(a.uniqueid) = ''ANSWER'') and (Cast(a.clientid as varchar(10)) = ', @UserId, N' )) then ''Calls answered by me'' ',
				N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') or (a.context = ''inbound'')) ',
					N'and (dbo.callstatus1(a.uniqueid) = ''NO ANSWER'') and (Cast(a.clientid as varchar(10)) = ', @UserId, N')) then ''Calls missed by me'' ',
				N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') or (a.context = ''inbound'')) ',
					N'and (dbo.callstatus1 (a.uniqueid) = ''ANSWER'') and (Cast(a.clientid as varchar(10)) != ', @UserId, N')) then ''Calls answered by me'' ',
				N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') or (a.context = ''inbound'')) ',
					N'and (dbo.callstatus1 (a.uniqueid) = ''NO ANSWER'') and ( Cast(a.clientid as varchar(10)) != ', @UserId, N')) then ''Calls missed today'' ',
				N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') or (a.context = ''inbound'')) ',
					N'and (dbo.callstatus1 (a.uniqueid) = ''ANSWER'')) then ''Calls answered'' ',
				N'when ((cast(a.call_start_time as Date) = cast(GetDate() as Date)) and ((a.context = ''DialerCalls'') or (a.context = ''inbound'')) ',
					N'and (dbo.callstatus1 (a.uniqueid) = ''NO ANSWER'')) then ''Calls missed'' ',
				N'else ''Calls overdue'' End)) as [CallsMsgStatus], ')
	set @sqlCallLog2 = concat(N'isnull(ul.PersonName, '''') name, ul.LeadNo, ul.Id LeadId, ul.ProfileImgFileName as Image, ',
			N'concat(ul.MobileNo, iif(ul.MobileNo1 <> '''', concat('''', '''', ul.MobileNo1), ''''), ',
				N'iif(ul.MobileNo2 <> '''', concat('''', '''', ul.MobileNo2), '''')) as CsvMobileNo, ',
			N'concat(ul.EmailId, iif(ul.EmailId1 <> '''', concat('''', '''', ul.EmailId1), ''''), ',
				N'iif(ul.EmailId2 <> '''', concat('''', '''', ul.EmailId2), '''')) as CsvEmailId, ',
			N'dbo.billduration1 (a.uniqueid) as billduration, ',
			N'dbo.callstatus1 (a.uniqueid) as callstatus, ',
			N'isnull(dbo.lastagentattended(a.uniqueid), '''') as AgentUser, ',
			N'isnull(dbo.lastagentattended(a.uniqueid), '''') as agentname, 0 agentid, ',
			N'isnull(c.Direction, '''') direction, isnull(c.outcomeid, 0) Outcome, isnull(o.OutcomeName, '''') OutcomeName, ',
			N'isnull(c.recordurl, '''') RecodingUrl, isnull(c.Remarks, '''') Remarks, Customernumber MobileNo, '''' CallGetway, ',
			N'isnull(u.user_login, case when c.agentcalldisposition is null then '' '' else ''Agent No Changed'' end) user_login, ',
			N'isnull(c.customercalldisposition, ''Unknown'') as CustomerDisposition, ',
			N'isnull(c.agentcalldisposition, case when c.agentcalldisposition is null then ''NOT ATTEMPTED'' else ''Unknown'' end) as AgentDisposition, ',
			N'isnull(c.Callstarttime, '''') as [call_start_time], ',
			N'isnull(cast(c.callendtime as nvarchar), ''Unknown'') as call_end_time, ',
			N'coalesce(customerduration, c.Calldurationseconds, 0) AS CustomerDuration, ',
			N'(case when c.agentcalldisposition is null then 0 when c.agentcalldisposition = ''NOANSWER'' then 0 ',
				N'else coalesce(agentduration, Calldurationseconds, 0) end) as agentDuration, ',
			N'(case when c.agentcalldisposition IS NULL then 0 else isnull (Calldurationseconds, 0) end) as Callduration, ',
			N'c.recordurl as [recordurl], isnull(c.agentmode, ''Mobile'') as AgentMode, ',
			N'isnull(c.lastdtmf, '''') [call_last_dtmf], c.callcreatedon ',
			N'from calendar(nolock) ca ',
				N'left join calllog(nolock) c on cast(c.callstarttime as date)= cast(ca.start_dts as date) ',
				N'left join kit19calls(nolock) a on c.reftable = ''kit19calls'' ',
				N'and c.refid = a.id  ',
				N'left join user_detail(nolock) u on c.agentuserid = u.User_ID ',
				N'left join UserLeads(nolock) ul on c.customerentity = ''lead'' ',
				N'and c.customerentityid = ul.id ',
				N'left join TelephonyCostDeducted(nolock) t on t.parentid = c.parentid ',
				N'and 1 = case when t.gatewaytype <> 0 ',
				N'and t.kit19callsdialledid = c.refid then 1 when t.GatewayType = 0 ',
				N'and t.uniqueid = c.uniqueid then 1 else 0 end ',
				N'left join tbl_voip_ServiceProvider s on s.id = c.gatewayid ',
				N'left join tbl_CallLogOutcomeMaster(nolock) o on o.id = c.outcomeid ',
				N'left join Cloud_app_master(nolock) m on m.AppId = c.appid ')
	set @sqlCallLog3 = concat(N'where c.parentid = ', @ParentId, ' ',
				N'and 1 = ( case when exists(select 1 from #tempUsers tu where tu.User_ID = isnull(c.agentuserid, 0)) then 1 else 0 end ) ',
				(case when ISNULL(@FullText, '') <> '' then @FullText else '' end),
				N'and 1 = (case ',
				N'when isnull(''', @SearchText, ''', '''')  = '''' then 1 ',
				N'when ''Calls today'' = ''', @SearchText, ''' and cast(c.Callstarttime as date) = cast(getdate() as date) then 1 ',
				N'when ''Calls missed today'' = ''', @SearchText, ''' and   c.agentcalldisposition in (''NOANSWER'') ',
					N'and cast(c.Callstarttime as date) = cast(getdate() as date) then 1 ',
				N'when ''Calls missed'' = ''', @SearchText, ''' and c.agentcalldisposition in (''NOANSWER'') then 1 ',
				N'when ''Calls missed by me'' = ''', @SearchText, ''' and c.agentcalldisposition in (''NOANSWER'') ',
					N'and c.agentuserid = ', @UserId, N' then 1 ',
				N'when ''Calls scheduled today'' = ''', @SearchText, ''' ',
					N'and cast(c.Callstarttime as date) = cast(getdate() as date) then 1 ',
				N'when ''Calls answered'' = ''', @SearchText, ''' and c.agentcalldisposition in (''Answer'', ''ANSWERED'') then 1 ',
				N'when ''Calls answered by me'' = ''', @SearchText, ''' and c.agentcalldisposition in (''Answer'', ''ANSWERED'') ',
					N'and c.agentuserid = ', @UserId, N' then 1 ',
				N'when ''Calls answered today'' = ''', @SearchText, ''' and c.agentcalldisposition in (''Answer'', ''ANSWERED'') ',
					N'and c.agentuserid = ', @UserId, N' and cast(c.Callstarttime as date) = cast(getdate() as date) then 1 ',
				N'when ''Upcoming calls scheduled'' = ''', @SearchText, ''' ',
					N'and cast(c.Callstarttime as date) = cast(getdate() as date) then 1 ',
				N'when ''Calls overdue'' = ''', @SearchText, ''' ',
					N'and cast(c.callscheduledfor as date) < cast(getdate() as date) then 1 ',
				N'when ''My calls scheduled today'' = ''', @SearchText, ''' ',
					N'and cast(c.callscheduledfor as date) = cast(getdate() as date) then 1 ',
				N'when ''Calls with positive outcome'' = ''', @SearchText, ''' and o.Indent = ''Positive'' then 1 ',
				N'when ''Calls with negative outcome'' = ''', @SearchText, ''' and o.Indent = ''Negative'' then 1 ',
				N'when ''Calls with positive outcome today'' = ''', @SearchText, ''' and o.Indent = ''Positive'' ',
					N'and cast(c.Callstarttime as date) = cast(getdate() as date) then 1 ',
				N'when ''Calls with negative outcome today'' = ''', @SearchText, ''' and o.Indent = ''Negative'' ',
					N'and cast(c.Callstarttime as date) = cast(getdate() as date) then 1 ',
				N'when ''Calls with neutral outcome'' = ''', @SearchText, ''' and o.Indent = ''Neutral'' then 1 ',
				N'when ''Calls with neutral outcome today'' = ''', @SearchText, ''' and o.Indent = ''Neutral'' ',
					N'and cast(c.Callstarttime as date) = cast(getdate() as date) then 1 ',
				N'when ''Calls missed by customer'' = ''', @SearchText, ''' ',
					N'and c.customercalldisposition in (''NOANSWER'') then 1 ',
				N'when ''Calls answered by customer'' = ''', @SearchText, ''' ', 
					N'and c.customercalldisposition in (''Answer'', ''ANSWERED'') then 1 ',
				N'else 0 end )) cl ',
			N'where 1 = 1 ', case when len(@ft) > 0 then @ft else  N' ' end ,  -- Dynamic Filter Variable
		N' ) select RowNumber1, (select count(1) from calllogData) as [rc1], id, parentid, Date, Customernumber, ',
			N'customerentity, customerentityid, uniqueid, callerid, channel, context, clientid, appid, CustomerName, ',
			N'dnid, Gateway, IVFlow, CallsMsgStatus, [name], LeadNo, LeadId, Image, CsvMobileNo, CsvEmailId, billduration, ',
			N'callstatus, AgentUser, agentname, agentid, direction, Outcome, OutcomeName, RecodingUrl, Remarks, MobileNo, ',
			N'CallGetway, user_login, CustomerDisposition, AgentDisposition, call_start_time, call_end_time, CustomerDuration, ',
			N'agentDuration, Callduration, recordurl, AgentMode, call_last_dtmf, callcreatedon ',
		N'from calllogData where RowNumber1 between ', @StartPoint, N' and ', @EndPoint )

	print @sqlCallLog1
	print @sqlCallLog2
	print @sqlCallLog3

	set @sqlCallLogFinal = @sqlCallLog1 + @sqlCallLog2 + @sqlCallLog3

	execute sp_executesql @sqlCallLogFinal

end



GO

/* ============================================================
   Procedure: [dbo].[Cloud_plan_master_Insert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_plan_master_Insert]        
(        
@planid bigint,         
@PlanName nvarchar(50),        
@SubscriptionCharge int,         
@CallingCharges float,        
@Pulse_Rate int,    
@PlanDuration varchar(20),        
@No_of_agent int,         
@Resselar_rate int,         
@No_of_Phone int,   
@No_of_VIP int,   
@No_of_VVIP int,
@No_of_landline int,   
@islandline bit,  
@isMobile bit,  
@istollfree bit,  
@Active bit,        
@User_id bigint,        
@Opt int = 0        
)        
as        
BEGIN        
if @Opt = 0        
begin        
if exists(select 1 from dbo.Cloud_plan_master where PlanName = @PlanName)        
 select 0,'Plan Already Exist' rsult        
else       
   
insert into Cloud_plan_master (PlanName, SubscriptionCharge, CallingCharges, Pulse_Rate,PlanDuration, No_of_agent, Resselar_rate, No_of_Phone,  
No_of_VIP, No_of_VVIP,No_of_landline, islandline, isMobile, istollfree, CreatedBy )        
 values (@PlanName, @SubscriptionCharge, @CallingCharges, @Pulse_Rate,@PlanDuration ,        
 @No_of_agent, @Resselar_rate, @No_of_Phone,  
 @No_of_VIP, @No_of_VVIP,@No_of_landline, @islandline, @isMobile, @istollfree, @User_id )        
SELECT SCOPE_IDENTITY(),'Inserted Successfully' rsult        
end        
if @Opt = 2        
BEGIN        
UPDATE Cloud_plan_master SET SubscriptionCharge=@SubscriptionCharge,         
 CallingCharges=@CallingCharges, Pulse_Rate=@Pulse_Rate,PlanDuration=@PlanDuration,         
 No_of_agent=@No_of_agent,  Resselar_rate=@Resselar_rate,         
 No_of_Phone=@No_of_Phone, CreatedBy =@User_id,  CreatedDate= GETDATE(),  
 No_of_VIP=@No_of_VIP, No_of_VVIP=@No_of_VVIP,No_of_landline=@No_of_landline, islandline=@islandline,   
 isMobile=@isMobile, istollfree =@istollfree       
WHERE planid = @planid        
SELECT @@ROWCOUNT,'Updated Successfully' rsult        
END        
if @Opt = 3        
BEGIN        
UPDATE Cloud_plan_master SET Active=@Active,CreatedBy =@User_id , CreatedDate= GETDATE()        
WHERE planid = @planid        
SELECT @@ROWCOUNT,'Deactivated Successfully' rsult        
END        
End 



GO

/* ============================================================
   Procedure: [dbo].[Cloud_PlanCoupen_Validate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_PlanCoupen_Validate]  
(@PlanID bigint,
@Coupen varchar(50)
)  
AS  
BEGIN  
 if exists (SELECT 1  
--select * 
FROM  dbo.Cloud_plan_master pm inner join dbo.Cloud_Plan_Coupen pc
 on pc.Planid = pm.planid where pm.planid =@PlanID and CoupenCode= @Coupen ) 
begin
if exists (SELECT 1  
FROM  dbo.Cloud_plan_master pm inner join dbo.Cloud_Plan_Coupen pc
 on pc.Planid = pm.planid inner join dbo.M_Coupon mc
 on mc.CouponCode = pc.CoupenCode
 where pm.planid =@PlanID  and CoupenCode= @Coupen and GETDATE() between
 ValidFrom and ValidTo) 
	SELECT mc.*,'Valid Coupen' msg  
	 FROM  dbo.Cloud_plan_master pm inner join dbo.Cloud_Plan_Coupen pc
	 on pc.Planid = pm.planid inner join dbo.M_Coupon mc
	 on mc.CouponCode = pc.CoupenCode
	 where pm.planid =@PlanID  and CoupenCode= @Coupen and GETDATE() between
	 ValidFrom and ValidTo
else
	select 0 as rslt,'Coupen Expired' msg
end
else
	select 0 as rslt,'Invalid Coupen' msg
END 




