/* ============================================================
   Procedure: [dbo].[Cloud_send_logdata]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_send_logdata]
as
begin
select Parentid ,ROW_NUMBER() over( order by Parentid) rno into #tmpdb from Cloud_User_Detail 
where Active=1 group by Parentid
Declare @max int=0, @min int=0
select @max=MAX(rno), @min=MIN(rno) from #tmpdb

while @min <= @max                      
begin
declare @user_no varchar(max), @chargeable bit
Declare @Parentid bigint,@sms bit, @email bit

--select *
--	from #tmpdb tp inner join dbo.Cloud_notificationsetting ns
--	on ns.User_id = tp.Parentid and NotificationId=1
--	inner join dbo.Cloud_NotificationMast nm
--	on nm.NotificationId=ns.NotificationId 
--	 where rno = @min
select @Parentid= Parentid,@sms =sms,@email =email,
		@user_no =  ns.User_no ,
		@chargeable = chargeable
	from #tmpdb tp inner join dbo.Cloud_notificationsetting ns
	on ns.User_id = tp.Parentid and NotificationId=1
	inner join dbo.Cloud_NotificationMast nm
	on nm.NotificationId=ns.NotificationId 
	 where rno = @min
if @sms=1 or @email=1
declare @dte Datetime = getdate()
exec Cloud_Call_logNotification @Parentid,@dte,@dte,
	@user_no ,  @chargeable, @sms, @email

set @min = @min+1
end

end





