/* ============================================================
   Procedure: [dbo].[Cloud_smsNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext serv_Raise_emailNotification                     
--exec serv_Raise_emailNotification 0,335,0,14,0,'Password Reset Email','Requester'                                 
--serv_Raise_emailNotification 6,335,3,335,6,'',''                                    
--exec serv_Raise_emailNotification 34,335,0 , 14,14,'New Ticket Created','Agent'                       Cloud_smsNotification '335', 'User  logged Off into system', 0, 0         
      
--335 User  logged in into system 9718896162 sanjeeva.shrivastava@pelsoftlabs.in 0      
      
 --select Parentid,* from user_detail where mobile='9811958433' 
 --Cloud_smsNotification 27053,'User promotion678633 logged Off from system','9811958433',0      
CREATE   PROCEDURE Cloud_smsNotification                                    
(                                    
@parentid bigint,                                    
@Body varchar(MAX),            
@ToMobile_No varchar(max),            
@type varchar(100)             
            
                                 
)                                    
as                                     
begin                                    
                                    
                                   
                                    
Declare @compsubject nvarchar(max)='',                                    
 @compbody nvarchar(max)='', @isunicode bit=0,@SenderID nvarchar(250) =''                  
Declare @subject nvarchar(max)='',                                    
@rexist int =0,@activityid int =0 ,@email as bit = 1                                   
Declare @FrommobileID nvarchar(max) = ''                     
                                   
            
            
-- select @ToMobile_No= rtrim(mobileno),@email=email from dbo.Cloud_notificationsetting                                
--if @email = 0                                  
--return;            
 select ROW_NUMBER() over( order by item) rno,* into #nomobile                  
from dbo.SplitString(@ToMobile_No, ',')    
  
           
         
Create table #tmpfl         
( rno int, User_login varchar(100), email varchar(100),tmobile varchar(20))        
 select rno,item,item from #nomobile       
  
  
insert into #tmpfl (rno,User_login,tmobile)        
 select rno,Item,Item from #nomobile         
        
drop table #nomobile        
        
        
          
 select top 1 @SenderID=Sender_Name  from Default_SenderID            
 where User_ID = @parentid and sender_id<>0     
   
   
               
 if rtrim(isnull(@SenderID,''))=''             
 set @SenderID='TXTSMS'                                    
              
                              
                  
              
declare @maxrow BIGINT, @minrow BIGINT                  
select @maxrow= MAX(rno),@minrow = MIN(rno)  From #tmpfl                  
Declare @prcsms as int = 1            
Declare @acnt bigint = 335          
if @type = '1'           
set @acnt = @parentid          
            
begin                           
      DECLARE @CurrentBalance BIGINT = (                                    
             SELECT TOP 1 isnull(cd.Balance,0)                                    
             FROM   Credit_Details AS cd                                    
             WHERE  cd.[User_ID] = @acnt                                    
             ORDER BY                                    
             cd.Credit_ID DESC )                        
                   
                  
select @maxrow= (case when @isunicode=0 and len(@body)<=160  then 1                                 
 when @isunicode=0 and LEN(@body)>160 then ceiling(LEN(@body)/cast(153 as FLOat))                                 
  when @isunicode=1 and len(@body)<=70 then 1                   
  else ceiling(LEN(@body)/cast(67 as float)) end )*@maxrow                  
                  
 set @CurrentBalance = @CurrentBalance-@maxrow                   
if @CurrentBalance <= 0                    
  Begin                    
    set @prcsms = 0            
     select 'Balance is not sufficient'                    
  End            
end                    
                  
if @prcsms = 1                  
begin                              
 DECLARE @Random INT;                                          
  DECLARE @Upper INT;                                          
  DECLARE @Lower INT                                          
                                           
  Declare @BatchID bigint                                          
                                            
  SET @Lower = 1 ---- The lowest random number                                          
  SET @Upper = 10000 ---- The highest random number                                          
  SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)                                          
  --SELECT @Random                                          
     insert into GetBatchRecord (User_id,RandNum)                                                  
        values(@parentid,@Random)                                                  
   select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock)                                           
   where User_id=@parentid and RandNum=@Random                                                  
        delete from GetBatchRecord  where User_id=@parentid and RandNum=@Random                          
  INSERT INTO CloneMessageDeliveryStatus                                      
    (BatchID, Mobile, Message, MessageStatus, SenderID,                                      
   MessageInsertDate, ScheduledDate, ScheduledTime,                                      
   SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                      
   ValidNo, IsPrority, IsAllowDND, DBType)                                  
  select @BatchID, tmobile, @body, null, @SenderID,                                      
   GETDATE(), '', '',                    
     (SELECT ud.SmppID                                      
     FROM   User_Detail AS ud                                      
     WHERE  ud.[User_ID] = @parentid                                      
    )   AS SmppID, @acnt, @IsUniCode, 0, 0, 0,                                      
   1, 1, 0, 0  from #tmpfl                               
          
 select 'sms sent successfully'                           
 /* Insert into table for Mail */                                              
end            
drop table #tmpfl                                   
end  
  
  
  
  
  
  


GO

/* ============================================================
   Procedure: [dbo].[Cloud_smsNotification_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
--sp_helptext serv_Raise_emailNotification                       
--exec serv_Raise_emailNotification 0,335,0,14,0,'Password Reset Email','Requester'                                   
--serv_Raise_emailNotification 6,335,3,335,6,'',''                                      
--exec serv_Raise_emailNotification 34,335,0 , 14,14,'New Ticket Created','Agent'                       Cloud_smsNotification '335', 'User  logged Off into system', 0, 0           
        
--335 User  logged in into system 9718896162 sanjeeva.shrivastava@pelsoftlabs.in 0        
        
 --select Parentid,* from user_detail where mobile='9811958433'   
 --Cloud_smsNotification 27053,'User promotion678633 logged Off from system','9811958433',0     
  
      
CREATE  PROCEDURE Cloud_smsNotification_new                                      
(                                      
@parentid bigint,                                      
@Body varchar(MAX),              
@ToMobile_No varchar(max),              
@type varchar(100)               
              
                                   
)                                      
as                                       
begin                                      
                                      
                                     
                                      
Declare @compsubject nvarchar(max)='',                                      
 @compbody nvarchar(max)='', @isunicode bit=0,@SenderID nvarchar(250) =''                    
Declare @subject nvarchar(max)='',                                      
@rexist int =0,@activityid int =0 ,@email as bit = 1                                     
Declare @FrommobileID nvarchar(max) = ''                       
                                     
              
              
-- select @ToMobile_No= rtrim(mobileno),@email=email from dbo.Cloud_notificationsetting                                  
--if @email = 0                                    
--return;              
 select ROW_NUMBER() over( order by item) rno,* into #nomobile                    
from dbo.SplitString(@ToMobile_No, ',')      
    
             
           
--Create table #tmpfl           
--( rno int, User_login varchar(100), email varchar(100),tmobile varchar(20))          
       
    
    
--insert into #tmpfl (rno,User_login,tmobile)          
-- select rno,Item,Item from #nomobile           
          
--drop table #nomobile          
          
          
            
 select top 1 @SenderID=Sender_Name  from Default_SenderID              
 where User_ID = @parentid and sender_id<>0       
     
     
                 
 if rtrim(isnull(@SenderID,''))=''               
 set @SenderID='TXTSMS'                                      
                
                                
                    
                
declare @maxrow BIGINT, @minrow BIGINT                    
--select @maxrow= MAX(rno),@minrow = MIN(rno)  From #tmpfl                    
Declare @prcsms as int = 1              
Declare @acnt bigint = 335            
if @type = '1'             
set @acnt = @parentid            
              
begin                             
      DECLARE @CurrentBalance BIGINT = (                                      
             SELECT TOP 1 isnull(cd.Balance,0)                                      
             FROM   Credit_Details AS cd                                      
             WHERE  cd.[User_ID] = @acnt                                      
             ORDER BY                                      
             cd.Credit_ID DESC )                          
                     
                    
select @maxrow= (case when @isunicode=0 and len(@body)<=160  then 1                                   
 when @isunicode=0 and LEN(@body)>160 then ceiling(LEN(@body)/cast(153 as FLOat))                                   
  when @isunicode=1 and len(@body)<=70 then 1                     
  else ceiling(LEN(@body)/cast(67 as float)) end )*@maxrow                    
                    
 set @CurrentBalance = @CurrentBalance-@maxrow     
if @CurrentBalance <= 0                      
  Begin                      
    set @prcsms = 0              
    -- select 'Balance is not sufficient'                      
  End              
end                      
                    
if @prcsms = 1                    
begin                                
 DECLARE @Random INT;                                            
  DECLARE @Upper INT;                                            
  DECLARE @Lower INT                                            
                                             
  Declare @BatchID bigint                                            
                                              
  SET @Lower = 1 ---- The lowest random number                                            
  SET @Upper = 10000 ---- The highest random number                                            
  SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)                                            
  --SELECT @Random                                            
     insert into GetBatchRecord (User_id,RandNum)                                                    
        values(@parentid,@Random)                                                    
   select @BatchID = max(BatchID)  from GetBatchRecord With (Nolock)                                             
   where User_id=@parentid and RandNum=@Random                                                    
        delete from GetBatchRecord  where User_id=@parentid and RandNum=@Random                            
 
  INSERT INTO CloneMessageDeliveryStatus                                        
    (BatchID, Mobile, Message, MessageStatus, SenderID,                                        
   MessageInsertDate, ScheduledDate, ScheduledTime,                                        
   SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                        
   ValidNo, IsPrority, IsAllowDND, DBType,sms_source)                                    
  select @BatchID, item, @body, null, @SenderID,                                        
   GETDATE(), '', '',                      
     (SELECT ud.SmppID                                        
     FROM   User_Detail AS ud                                        
     WHERE  ud.[User_ID] = @parentid                                        
    )   AS SmppID, @acnt, @IsUniCode, 0, 0, 0,                                        
   1, 1, 0, 0,'IVR : Notification'  from #nomobile                                 
            
 --select 'sms sent successfully'                             
 /* Insert into table for Mail */                                                
end              
--drop table #tmpfl   
drop table #nomobile                                     
end    
    
    
    
    
    


GO

/* ============================================================
   Procedure: [dbo].[Cloud_SP_Adduser_by_role]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[Cloud_SP_Adduser_by_role]    
(    
@id int,    
@groupid varchar(max),    
@userid int,    
@parentid int,    
@cloudrole int,    
@Assing bit,    
@Active bit,    
@opt varchar(10)    
)    
as    
begin    
if(@opt='Insert')    
begin   
   
insert into Cloud_user_Group(GroupId,userid,parentid,Assign,Active)    
values(@groupid,@userid,@parentid,@Assing,@Active)    
    
end    
  
if(@opt='Insertuser')    
begin   
update User_Detail set Cloudrole=@cloudrole where User_ID=@userid  
  
 CREATE TABLE #TempTable(  
 ID int identity(1,1),  
 value varchar(20)  
)  
  
INSERT INTO #TempTable (value)   
SELECT value from dbo.fn_Split(@groupid,'#')  
  
DECLARE @first AS INT = 1,@last int,@groupid1 varchar(10)  
select @last =MAX(id) from #TempTable
WHILE(@first <= @last)  
BEGIN  
select @groupid1= value from #TempTable where ID=@first  
    insert into Cloud_user_Group(GroupId,userid,parentid,Assign,Active)    
values(@groupid1,@userid,@parentid,@Assing,@Active)   
  
 SET @first += 1  
END  
   
  
    
end   
end    
  



GO

