/* ============================================================
   Procedure: [dbo].[Cloud_SP_Adduser_by_role_WithSequence]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_SP_Adduser_by_role_WithSequence] (    
 @id INT    
 ,@groupid VARCHAR(max)    
 ,@userid BIGINT    
 ,@parentid BIGINT    
 ,@cloudrole INT    
 ,@Assing BIT    
 ,@Active BIT    
 ,@opt VARCHAR(10)    
 )    
AS    
BEGIN    
 DECLARE @rowJson VARCHAR(MAX) = ''    
  ,@activity VARCHAR(MAX) = ''    
  ,@action VARCHAR(1) = ''    
  ,@rid BIGINT = 0    
    
 IF (@opt = 'Insert')    
 BEGIN    
  DECLARE @Sequence INT = 0;    
    
  SELECT @Sequence = (isnull(count(1), 0) + 1)    
  FROM Cloud_user_Group(NOLOCK)    
  WHERE GroupId = @groupid    
  
  if not exists(select 1 from Cloud_user_Group(nolock) where GroupId=@groupid and userid=@userid)
  begin
  INSERT INTO Cloud_user_Group (    
   GroupId    
   ,userid    
   ,parentid    
   ,Assign    
   ,Active    
   ,SequenceGRP    
   )    
  VALUES (    
   @groupid    
   ,@userid    
   ,@parentid    
   ,@Assing    
   ,@Active    
   ,@Sequence    
   )   
   SET @rid = SCOPE_IDENTITY()    
    end
    else
    begin
    select top 1 @rid=id from Cloud_user_Group(NOLOCK) WHERE GroupId=@groupid and userid=@userid order by id desc
    end
  
  SET @rowJson = (    
    SELECT *    
    FROM Cloud_user_Group(NOLOCK)    
    WHERE id = @rid    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
  SET @action = 'I'    
  SET @activity = 'Inst_teleGrp'    
 END    
    
 IF (@opt = 'Insertuser')    
 BEGIN    
  UPDATE User_Detail    
  SET Cloudrole = @cloudrole    
  WHERE User_ID = @userid    
    
  CREATE TABLE #TempTable (    
   ID INT identity(1, 1)    
   ,value VARCHAR(20)    
   )    
    
  INSERT INTO #TempTable (value)    
  SELECT value    
  FROM dbo.fn_Split(@groupid, '#')    
    
  DECLARE @first AS INT = 1    
   ,@last INT    
   ,@groupid1 VARCHAR(10)    
    
  SELECT @last = MAX(id)    
  FROM #TempTable    
    
  WHILE (@first <= @last)    
  BEGIN    
   SELECT @groupid1 = value    
   FROM #TempTable    
   WHERE ID = @first    
    
   DECLARE @SequenceMS INT = 0;    
    
   SELECT @SequenceMS = (isnull(count(1), 0) + 1)    
   FROM Cloud_user_Group(NOLOCK)    
   WHERE GroupId = @groupid1    
    
  if not exists(select 1 from Cloud_user_Group(nolock) where GroupId=@groupid1 and userid=@userid)
  begin

   INSERT INTO Cloud_user_Group (    
    GroupId    
    ,userid    
    ,parentid    
    ,Assign    
    ,Active    
    ,SequenceGRP    
    )    
   VALUES (    
    @groupid1    
    ,@userid    
    ,@parentid    
    ,@Assing    
    ,@Active    
    ,@SequenceMS    
    )    
    
   end
   SET @first += 1 
  END    
    
  SET @rowJson = (    
    SELECT *    
    FROM Cloud_user_Group(NOLOCK)    
    WHERE GroupId = @groupid1    
     AND userid = @userid    
     AND parentid = @parentid    
     AND Assign = @Assing    
     AND Active = @Active    
     AND SequenceGRP = @SequenceMS    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
  SET @action = 'I'    
  SET @activity = 'Inst_teleGrp'    
 END    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid    
  ,@Activity_type = @activity    
  ,@ActionType = @action    
  ,@RowJson = @rowJson    
  ,@Table_name = 'Cloud_user_Group'    
END 


GO

