/* ============================================================
   Procedure: [dbo].[Cloud_SP_app_master_Insert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Cloud_SP_app_master_Insert (
	@AppName VARCHAR(100)
	,@AppId INT
	,@PhoneNo VARCHAR(100)
	,@Miss_Call BIT
	,@Active BIT
	,@User_id BIGINT
	,@opt INT
	)
AS
BEGIN
	DECLARE @result INT
		,@activity VARCHAR(MAX) = ''
		,@action VARCHAR(1) = ''

	IF @opt = 1
	BEGIN
		IF EXISTS (
				SELECT AppName
				FROM Cloud_app_master
				WHERE AppName = @AppName
					AND User_ID = @User_id
				)
		BEGIN
			SELECT '1' AS Appid
		END
		ELSE
		BEGIN
			INSERT INTO Cloud_app_master (
				User_ID
				,AppName
				,PhoneNo
				,Miss_Call
				)
			VALUES (
				@User_id
				,@AppName
				,@PhoneNo
				,@Miss_Call
				)

			SET @AppId = SCOPE_IDENTITY();

			SELECT @AppId AS Appid

			SELECT @result
				,'Saved successfully'

			SET @activity = 'Inst_Ivrflow'
			SET @action = 'I'

			DECLARE @count INT = (
					SELECT COUNT(1)
					FROM Cloud_app_master(NOLOCK)
					WHERE User_ID = @User_id
					)
			DECLARE @m_id BIGINT
				,@user_login NVARCHAR(50)

			SELECT @m_id = M_ID
				,@user_login = User_Login
			FROM User_Detail(NOLOCK)
			WHERE User_ID = @User_id

			IF @m_id = 10043
				AND @count = 1
			BEGIN
				DECLARE @description NVARCHAR(200) = 'User ' + CAST(@user_login AS NVARCHAR) + ' created an IVR flow first time'

				EXEC Usp_InsertUserEventDetails 'IVR Created'
					,@User_id
					,@description
					,'Cloud_app_master'
					,@AppId
			END
		END
	END

	IF @opt = 2
	BEGIN
		UPDATE Cloud_app_master
		SET AppName = @AppName
			,PhoneNo = @PhoneNo
		WHERE User_ID = @User_id
			AND AppId = @AppId

		SET @result = @@rowcount

		SELECT @result
			,'Updated successfully'

		SET @activity = 'Updt_Ivrflow'
		SET @action = 'U'
	END

	IF @opt = 3
	BEGIN
		UPDATE Cloud_app_master
		SET Active = @Active
		WHERE User_ID = @User_id
			AND AppId = @AppId

		SET @result = @@rowcount

		SELECT @result
			,'Updated successfully'

		SET @activity = 'Updt_Ivrflow_active'
		SET @action = 'U'
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM Cloud_app_master WITH(NOLOCK)
			WHERE AppId = @AppId
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_id
		,@Activity_type = @activity
		,@ActionType = @action
		,@RowJson = @rowJson
		,@Table_name = 'Cloud_app_master'
END



GO

/* ============================================================
   Procedure: [dbo].[Cloud_SP_audio_master_Insert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Cloud_SP_audio_master_Insert (    
 @LibraryId INT    
 ,@FileName VARCHAR(100)    
 ,@Path VARCHAR(max)    
 ,@FileType VARCHAR(10)    
 ,@Active BIT    
 ,@opt INT    
 ,@AccessType BIT    
 ,@user_id BIGINT  
 --,@ismoh int       
 )    
AS    
BEGIN    
 --set @Path=REPLACE(@path,cast(@user_id as nvarchar) +'/','')                  
 DECLARE @result INT    
    
 IF @opt = 1    
 BEGIN    
  INSERT INTO Cloud_audio_master (    
   FileName    
   ,Path    
   ,FileType    
   ,user_id    
   ,AccessType    
   --,ismoh  
   )    
  VALUES (    
   @FileName    
   ,@Path    
   ,@FileType    
   ,@user_id    
   ,@AccessType    
   --,@ismoh  
   )    
    
  SELECT SCOPE_IDENTITY()    
    
  DECLARE @rowJson NVARCHAR(MAX) = (    
    SELECT *    
    FROM Cloud_audio_master    
    WHERE LibraryId = @LibraryId    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
 END    
    
 --if @opt = 2                        
 --begin                        
 --update Cloud_audio_master set FileName=@FileName,Path=@Path                        
 -- ,FileType =@FileType where  LibraryId= @LibraryId                        
 --set @result = @@ROWCOUNT                         
 --end                        
 IF @opt = 3    
 BEGIN    
  UPDATE Cloud_audio_master    
  SET Active = @Active    
  WHERE LibraryId = @LibraryId    
    
  SET @result = @@ROWCOUNT    
    
  SELECT @result    
   ,'Updateed successfully'    
 END    
    
 IF (@opt = 4)    
 BEGIN    
  UPDATE Cloud_audio_master    
  SET AccessType = @AccessType    
  WHERE LibraryId = @LibraryId    
    
  SET @result = @@ROWCOUNT    
    
  SELECT @result    
   ,'Updateed successfully'    
 END    
    
 IF (@opt = 5)    
 BEGIN    
  SELECT path    
   ,FileName + CASE     
    WHEN AccessType = 0    
     THEN ' (Private)'    
    ELSE ' (Public)'    
    END FileName    
  FROM Cloud_audio_master    
  WHERE user_id = @user_id    
   AND Active = 1    
   AND FileType IN (    
    'mp3'    
    ,'gsm'    
    ,'.wav'    
    ,'.mp3'    
    ,'.gsm'    
    )    
      
  UNION ALL    
      
  SELECT path    
   ,FileName + CASE     
    WHEN AccessType = 0    
     THEN ' (Private)'    
    ELSE ' (Public)'    
    END FileName    
  FROM Cloud_audio_master    
  WHERE Active = 1    
   AND AccessType = 1    
   AND user_id != @user_id    
   AND FileType IN (    
    'mp3'    
    ,'gsm'    
    ,'.wav'    
    ,'.mp3'    
    ,'.gsm'    
    )    
 END    
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id    
  ,@Activity_type = 'Inst_Voicrec'    
  ,@ActionType = 'I'    
  ,@RowJson = @rowJson    
  ,@Table_name = 'Cloud_audio_master'    
END    


GO

/* ============================================================
   Procedure: [dbo].[Cloud_SP_audio_master_Insert_WithIsMOH]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_SP_audio_master_Insert_WithIsMOH] (        
 @LibraryId INT        
 ,@FileName VARCHAR(100)        
 ,@Path VARCHAR(max)        
 ,@FileType VARCHAR(10)        
 ,@Active BIT        
 ,@opt INT        
 ,@AccessType BIT        
 ,@user_id BIGINT        
 ,@ismoh INT        
 )        
AS        
BEGIN        
 --set @Path=REPLACE(@path,cast(@user_id as nvarchar) +'/','')        
 DECLARE @clientid BIGINT = (        
   SELECT parentid        
   FROM User_Detail(NOLOCK)        
   WHERE user_id = @user_id        
   )        
 DECLARE @result INT        
 DECLARE @rowJson VARCHAR(MAX) = ''        
  ,@activity VARCHAR(MAX) = ''        
  ,@action VARCHAR(1) = ''        
  ,@id BIGINT = 0        
        
 IF @opt = 1        
 BEGIN  
   
  --set @Path = REPLACE(@Path,'Audiofile/','Audiofile/'+ cast(@user_id as nvarchar(50)) + '/')  
  --set @Path = REPLACE(@Path,'Audiofile\','Audiofile\'+ cast(@user_id as nvarchar(50)) + '\')  
  --set @Path = REPLACE(@Path,'\','/')  
  
  INSERT INTO Cloud_audio_master (        
   FileName        
   ,Path        
   ,FileType        
   ,user_id        
   ,AccessType        
   ,ismoh        
   )        
  VALUES (        
   @FileName        
   ,@Path        
   ,@FileType        
   ,@user_id        
   ,@AccessType        
   ,@ismoh        
   )        
        
  SET @id = SCOPE_IDENTITY()        
        
  SELECT @id        
        
  SET @rowJson = (        
    SELECT *        
    FROM Cloud_audio_master cam(NOLOCK)        
    WHERE cam.LibraryId = @id        
    FOR JSON AUTO        
     ,INCLUDE_NULL_VALUES        
    )        
  SET @action = 'I'        
  SET @activity = 'Inst_Audio_Amstr'        
        
  IF @ismoh = 1        
  BEGIN        
   DECLARE @f NVARCHAR(200) = @filename + '_' + cast(FORMAT(GETDATE(), 'ddMMyyyy') AS NVARCHAR)        
        
   EXEC [cloud_insert_Audiofile] 0        
    ,@clientid        
    ,@f        
    ,@Path        
    ,'U'        
    ,'UTS'        
    ,''        
    ,0        
  END        
 END        
        
 --if @opt = 2                                
 --begin                                
 --update Cloud_audio_master set FileName=@FileName,Path=@Path                                
 -- ,FileType =@FileType where  LibraryId= @LibraryId                                
 --set @result = @@ROWCOUNT                                 
 --end                                
 IF @opt = 3        
 BEGIN        
  UPDATE Cloud_audio_master        
  SET Active = @Active        
  WHERE LibraryId = @LibraryId        
        
  SET @result = @@ROWCOUNT        
        
  SELECT @result        
   ,'Updateed successfully'        
        
  SET @rowJson = (        
    SELECT *        
    FROM Cloud_audio_master cam(NOLOCK)        
    WHERE cam.LibraryId = @LibraryId        
    FOR JSON AUTO        
     ,INCLUDE_NULL_VALUES        
    )        
  SET @action = 'U'        
  SET @activity = 'Updt_Audio_Amstr'        
 END        
        
 IF (@opt = 4)        
 BEGIN        
  UPDATE Cloud_audio_master        
  SET AccessType = @AccessType        
  WHERE LibraryId = @LibraryId        
        
  SET @result = @@ROWCOUNT        
        
  SELECT @result        
   ,'Updateed successfully'        
        
  SET @rowJson = (        
    SELECT *        
    FROM Cloud_audio_master cam(NOLOCK)        
    WHERE cam.LibraryId = @LibraryId        
    FOR JSON AUTO        
     ,INCLUDE_NULL_VALUES        
    )        
  SET @action = 'U'        
  SET @activity = 'Updt_Audio_Amstr'        
 END        
        
 IF (@opt = 5)        
 BEGIN        
  SELECT path        
   ,FileName + CASE         
    WHEN AccessType = 0        
     THEN ' (Private)'        
    ELSE ' (Public)'        
    END FileName        
   ,isNull(ismoh, 0) AS ismoh        
  FROM Cloud_audio_master        
  WHERE user_id = @user_id        
   AND Active = 1        
   AND FileType IN (        
    'mp3'        
    ,'gsm'        
    ,'.wav'        
    ,'.mp3'        
    ,'.gsm'        
    )        
          
  UNION ALL        
          
  SELECT path        
   ,FileName + CASE         
    WHEN AccessType = 0        
     THEN ' (Private)'        
    ELSE ' (Public)'        
    END FileName        
   ,isNull(ismoh, 0) AS ismoh        
  FROM Cloud_audio_master        
  WHERE Active = 1        
   AND AccessType = 1        
   AND user_id != @user_id        
   AND FileType IN (        
 'mp3'        
    ,'gsm'        
    ,'.wav'        
    ,'.mp3'        
    ,'.gsm'        
    )        
        
  SET @action = 'S'        
  SET @activity = 'View_Audio_Amaster'        
 END        
        
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @user_id        
  ,@Activity_type = @activity        
  ,@ActionType = @action        
  ,@RowJson = @rowJson        
  ,@Table_name = 'Cloud_audio_master'        
END 


GO

