(        
@parentid bigint        
)        
as        
begin     

Declare @isKYCRequired as bit
select @isKYCRequired=isKYCRequired from Price_UserSubscriptionDetails where UserID=@parentid and IsNewPlan=1
if(@isKYCRequired = 1)
begin    
if exists(select parentd_id from Cloud_userkyc UK where parentd_id=@parentid )        
begin        
    
--select Approved,UD.Name as MainDocName from Cloud_userkyc UK join Cloud_kycdoc UD on UK.MainDocID=UD.id         
--where parentd_id=@parentid        
--and Approved <> 1      
    
declare @isIndividualval as int =0    
declare @docCount as int =0    
select top 1 @isIndividualval=IsIndividual from  Cloud_userkyc where parentd_id=@parentid      
      
if(@isIndividualval = 1)    
begin    
select @docCount=COUNT(1) from Cloud_userkyc UK     
--join Cloud_kycdoc UD on UK.MainDocID=UD.id         
where uk.parentd_id=@parentid        
and uk.Approved = 1  and uk.MainDocID in (1,2,3,4)    
if(@docCount=4)    
  select 1    
else    
  select 0    
    
end    
     
else if (@isIndividualval = 2)  --@isIndividualval=2      
