select @docCount=COUNT(1) from Cloud_userkyc UK     
where uk.parentd_id=@parentid        
and uk.Approved = 1  and uk.MainDocID in (1,2,3,4,5,6)    
if(@docCount=6)    
  select 1    
else    
  select 0    
end     
    
else    
select 0    

end

end      
 
    
end    
      
    
