/* ============================================================
   Procedure: [dbo].[Cloud_SP_Cloud_group_master_Insert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext Cloud_SP_Cloud_group_master_Insert  
  
CREATE   PROCEDURE [dbo].[Cloud_SP_Cloud_group_master_Insert]      
(                  
@ParentId bigint,                  
@GroupId varchar(100),                  
@Groupname varchar(max),                  
@Active bit,       
@filter varchar(250),                 
@opt int                  
)                  
as                  
begin                  
Declare @result int                  
if @opt = 1                  
begin      
    
 if not exists(select Groupname from Cloud_group_master  where    Groupname=@Groupname and ParentId=@ParentId and active = 1 )    
 begin    
 insert into Cloud_group_master(ParentId,Groupname)                   
 values(@ParentId, @Groupname)                  
 select @result =SCOPE_IDENTITY()        
 select @result, 'Saved successfully'       
 return      
 end    
 else    
 begin    
 select '1'    
 end     
end    
    
             
       
if @opt = 3                  
begin                  
 update Cloud_group_master set Active = @Active,createdate=GETDATE() where                   
  GroupId= @GroupId and ParentId  =@ParentId               
 set @result = @@ROWCOUNT          
 Delete from dbo.Cloud_user_Group where                   
 GroupId= @GroupId   and ParentId  =@ParentId                       
 select @result, 'Updateed successfully'       
 return                 
end       
  
drop table if Exists #tmptbl  
      
CREATE TABLE #tmptbl(      
 [ParentId] [bigint] NULL,      
 [GroupId] [int] NOT NULL,      
 [Groupname] [varchar](50) NULL,      
 [createdate] [datetime] NULL,      
 [Active] [bit] NULL,      
 uname varchar(max), role varchar(100)      
)       
                      
if @opt = 2                  
begin      
                 
 if LTRIM(rtrim(@filter))!=''      
 insert into #tmptbl (gm.ParentId, gm.GroupId, gm.Groupname, gm.createdate, gm.Active,      
  uname, role)          
  select gm.ParentId, gm.GroupId, gm.Groupname, gm.createdate, gm.Active,      
  ud.Fname+' '+ud.Fname uname,Cloudrole role from Cloud_group_master gm            
  inner join dbo.User_Detail ud            
  on ud.User_id = gm.ParentId            
  where gm.ParentId=@ParentId and gm.Active= @Active and Groupname like '%'+LTRIM(rtrim(@filter))+'%'      
   else      
     
     
   insert into #tmptbl (gm.ParentId, gm.GroupId, gm.Groupname, gm.createdate, gm.Active,      
  uname, role)          
  select gm.ParentId, gm.GroupId, gm.Groupname, gm.createdate, gm.Active,      
  ud.Fname+' '+ud.Fname uname,Cloudrole role from Cloud_group_master gm            
  inner join dbo.User_Detail ud            
  on ud.User_id = gm.ParentId            
  where gm.ParentId=@ParentId and gm.Active= @Active                
end                  
          
              
if @opt = 4              
begin              
       
 insert into #tmptbl (gm.ParentId, gm.GroupId, gm.Groupname, gm.createdate, gm.Active,      
   uname, role)          
   select gm.ParentId, gm.GroupId, gm.Groupname, gm.createdate, gm.Active,      
   ud.Fname+' '+ud.Fname uname,Role1 role from Cloud_group_master gm            
   inner join dbo.Cloud_User_Detail ud            
   on ud.User_id = gm.ParentId               
   where GroupId=@GroupId              
end      
      
select * from #tmptbl      
                
--select @result, 'Updateed successfully'                  
end  
  
--select * from Cloud_group_master  


GO

