if @Opt = 1                  
begin                  
insert into Cloud_user_subscription(Parentid,Plan_id,              
Gr_Amount,GST_per,Net_Amount,discount_per,disc_value,               
Coupen_id,valid_from,valid_to,TransDate)values                  
(@Parentid,@Plan_id,              
@Gr_Amount,@GST_per,@Net_Amount,@discount_per,@disc_value,               
@Coupen_id,@valid_from,@valid_to,GETDATE())                
 declare @id  bigint =  SCOPE_IDENTITY()         
insert into dbo.Cloud_user_Subscription_trnas        
(Trans_id, TransDate, Trans_Type, Sub_Amount, Add_onUser, Add_onPhone, qty, months, Amount)        
select @id,GETDATE(), Trans_Type, Sub_Amount, Add_onUser, Add_onPhone, qty, months, Amount        
from @ttbl        
        
insert into Cloud_User_Phone (Parentid, PhoneNo,AppId) 
select user_id, Phone_No, 0    from @tbl        

update dbo.Cloud_phone_master set free = 0 where PhoneNo in (select  Phone_No from @tbl )           
end                 
RETURN
  declare @icount as int    
select @icount= COUNT(1) from Cloud_user_subscription where parentid=@Parentid    
if(1 = @icount)    
begin   
 declare @email as varchar(250), @mobile varchar(250), @User_login varchar(100)  
 select @email=Email,@mobile=CONVERT(varchar(100), Cast(Mobile as decimal(38, 0))) from user_detail where user_id=@Parentid    
 Insert into Cloud_notificationsetting(NotificationId,Activity,User_id,NotificationType,                    
 Alert_Duration,EmailId,mobileno,User_no)                     
 select NotificationId,Activity,@ParentId ,Notification_Type , Alert_Duration,@email, @mobile,  
 @User_login  
 from dbo.Cloud_NotificationMast where Active = 1 and Access_Public = 1                   
    
  update User_Detail set Cloudrole=1 where User_ID= @ParentId    
end    
              
end  


GO

