/* ============================================================
   Procedure: [dbo].[Cloud_SP_Get_Cloud_subscription_Admin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Cloud_SP_Get_Cloud_subscription_Admin]          
(          
      
@fmdate datetime,
@todate datetime,
@searchtxt varchar(100)
        
)          
as          
begin          

select sb.*,um.User_login,pm.*, (select COUNT(*) from User_Detail where Parentid = um.ParentID  
 and Cloudrole=1) no_user,  
(select COUNT(*) from dbo.Cloud_User_Phone where Parentid = um.ParentID) no_phone,  
 dbo.Cloud_Phone_string(um.ParentID) Phone_no into #tmpfl  
 from Cloud_user_subscription sb        
 inner join dbo.User_Detail um        
 on um.User_id = sb.Parentid        
 inner join dbo.Cloud_plan_master pm        
 on pm.planid = sb.plan_id   
 where  Cloudrole=1 and
   CONVERT(date,TransDate) between CONVERT(date,@fmdate) and CONVERT(date,@todate)          

 if  @searchtxt =''  
 select * from #tmpfl  order by TransDate,PlanName     
 else  
 select * from #tmpfl    
 where (User_login like '%'+@searchtxt+'%'  
 or PlanName like '%'+@searchtxt+'%'  
 or Phone_no like  '%'+@searchtxt+'%'  
 or CONVERT(date,valid_to) like '%'+@searchtxt+'%')  
	 order by TransDate,PlanName      
drop table #tmpfl     

end   
     
  


GO

/* ============================================================
   Procedure: [dbo].[Cloud_SP_Get_Cloud_user_subscription]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--[Cloud_SP_Get_Cloud_user_subscription] 335,0,2     PlanName

CREATE   PROCEDURE [dbo].[Cloud_SP_Get_Cloud_user_subscription]        
(        
@Parentid bigint,        
@userID bigint,        
@opt int        
)        
as        
begin        
if(@opt=1)        
begin        
select top 1 sb.*,um.User_login,pm.* from Cloud_user_subscription sb      
inner join dbo.User_Detail um      
on um.User_id = sb.Parentid      
inner join dbo.Cloud_plan_master pm      
on pm.planid = sb.plan_id      
where um.Parentid=@Parentid      
   order by TransDate desc           
        
end 
if(@opt=2)        
begin        
select sb.*,um.User_login,pm.*, (select COUNT(*) from User_Detail where Parentid = um.ParentID
	and Cloudrole=1) no_user,
(select COUNT(*) from dbo.Cloud_User_Phone where Parentid = um.ParentID) no_phone,
	dbo.Cloud_Phone_string(um.ParentID) Phone_no 
	from Cloud_user_subscription sb      
	inner join dbo.User_Detail um      
	on um.User_id = sb.Parentid      
	inner join dbo.Cloud_plan_master pm      
	on pm.planid = sb.plan_id 
	where  Cloudrole=1           
        
end       
if(@opt=0)        
begin        
select sb.*,um.User_login,pm.*, (select COUNT(*) from User_Detail where Parentid = um.ParentID
	and Cloudrole=1) no_user,
(select COUNT(*) from dbo.Cloud_User_Phone where Parentid = um.ParentID) no_phone,
 dbo.Cloud_Phone_string(um.ParentID) Phone_no 
 from Cloud_user_subscription sb      
inner join dbo.User_Detail um      
on um.User_id = sb.Parentid      
inner join dbo.Cloud_plan_master pm      
on pm.planid = sb.plan_id 
where  Cloudrole=1 and um.parentid =  @Parentid    
      
end      
end 




GO

