/* ============================================================
   Procedure: [dbo].[cloud_sp_getivrLog]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC cloud_sp_getivrLog -- '2019/01/01','2019/01/31'  
 (    
--@parentid as bigint,   
 @fmdate as datetime,  
 @todate as datetime   
 )    
as    
 begin    
 select il.*,ISNULL(am.AppName,'') AppName,isnull(ud.User_Login,'') User_Login,  
  isnull(cl.User_Login,'') Agentnm    --,  into #tmpfl  
 from Cloud_ivr_log il   
  left outer join dbo.Cloud_app_master am    
 on am.PhoneNo = il.dnino     
 left outer join dbo.user_detail ud    
 on ud.User_ID = am.User_id   
 left outer join dbo.user_detail cl  
 on str(cl.Mobile) = il.caller_ID   
where   
  CONVERT(date, logdate) between Convert(date, @fmdate) and   
  Convert(date, @todate) order by logdate desc  
  
 end
  



GO

/* ============================================================
   Procedure: [dbo].[Cloud_sp_GetMoniteringMasterData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE Cloud_sp_GetMoniteringMasterData  
AS  
BEGIN  
  
  
select count(1)  as ChannelInUse from kit19channels(nolock) where channel_inuse='Y' and cast(channel_lastaccesstime as date) = cast(Getdate() as date)   
select MaxUsedChannel  as MaxUseToday from [Kit19MaxChannelUsed](nolock) where cast(InsertDateTime as date) = cast(Getdate() as date) 
  
select 'Channel-' + cast([id] as varchar(50)) as ChannelName   
           ,[channel_calltime]  
           ,[channel_uniqueid]  
           ,[channel_clientid]  
           ,[channel_flowid]  
           ,[channel_flowstep]  
           ,[chnnel_dni]  
           ,[channel_cli]  
           ,[channel_inuse]  
           ,[channel_lastaccesstime] from kit19channels(nolock)  
     order by [channel_lastaccesstime] desc  
    
END  



