set @result = @@ROWCOUNT   
end  
if @opt = 2  
begin  
update Cloud_UserVoicemail set VoiceMail_Duration =@VoiceMail_Duration , Silence=@Silence  
  where VoicemailId = @VoicemailId  
 set @result = @@ROWCOUNT   
end  
  
select @result, 'Updateed successfully'  
end  
  



