/* ============================================================
   Procedure: [dbo].[Cloud_subscribeMemberlist]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROC [dbo].[Cloud_subscribeMemberlist] -- 'test', 'add', '1204862606', '7840002738', '1'            
(             
@pass1 varchar(50),         
@opt varchar(10),           
@didno  varchar(20),         
@callerNo  varchar(20),           
@appno as varchar(20)           
)              
as              
begin            
declare @Parentid as bigint,@serchid as bigint =0            
select @Parentid= Parentid from dbo.Cloud_user_phone where (PhoneNo = @didno) or ('0' +cast(PhoneNo as nvarchar) =  cast(@didno as nvarchar))  and Active=1           
        
select @serchid=id  from usersearchlist where ParentID = @Parentid and IsSearch =1            
   --and SpecificMobileNo  like '%'+@callerNo+'%'       
   and SearchName = @pass1        
--declare @call varchar(20) ='7530824177'         
--set @call ='%'+@call+'%'         
--select @call        
        
if (@opt= 'remove' and @serchid>0 )        
begin        
select 1        
update usersearchlist set SpecificMobileNo= replace(REPLACE(SpecificMobileNo, ','+@callerNo,''),@callerNo,''),        
ExcludesMobileNo=case when isnull(excludesmobileno,'') not like '%'+@callerno+'%' and LTRIM(RTRIM(isnull(ExcludesMobileNo,'')))='' then isnull(ExcludesMobileNo,'')+@callerNo       
when isnull(ExcludesMobileNo,'') not like '%'+@callerno+'%' and LTRIM(RTRIM(isnull(ExcludesMobileNo,'')))<>'' then isnull(ExcludesMobileNo,'')+','+@callerNo else ExcludesMobileNo end        
where id=@serchid        
        
end        
        
if (@opt= 'add' and @serchid>0)        
begin        
select 2        
update usersearchlist set SpecificMobileNo=(case when SpecificMobileNo not like '%'+@callerno+'%' and LTRIM(RTRIM(SpecificMobileNo))='' then isnull(SpecificMobileNo,'')+@callerNo         
when isnull(SpecificMobileNo,'') not like '%'+@callerno+'%' and LTRIM(RTRIM(isnull(SpecificMobileNo,'')))<>'' then isnull(SpecificMobileNo,'')+','+@callerNo else specificmobileno end),        
ExcludesMobileNo=replace(REPLACE(ExcludesMobileNo,','+ @callerNo,''),@callerNo,'')         
where id=@serchid        
end        
    
/*Start Lead activity  Added to GroupList/Removed from Grouplist */    
     
 Begin try    
    
  Declare @Action_LDACTV nvarchar(50) = @opt    
  Declare @UserID_LDACTV bigint = @Parentid    
  DEclare @ParentID_LDACTV bigint = @Parentid    
  Declare @CallerNo_LDACTV nvarchar(50) = @callerNo    
  Declare @EventName_LDACTV nvarchar(500) = ''    
  Declare @LeadID_LDACTV bigint = 0     
    
  select  @LeadID_LDACTV = isnull(ID,0) from UserLeads where ((MobileNo = @CallerNo_LDACTV) or (MobileNo1 = @CallerNo_LDACTV)  or (MobileNo2 = @CallerNo_LDACTV))     
    
    
  if(@Action_LDACTV = 'add')    
       Begin    
       set @EventName_LDACTV = 'Added to GroupList'        
    End    
    else    
    Begin    
        set @EventName_LDACTV = 'Removed from GroupList'    
    End      
       
    create table #tblEventDescrb    
     (    
    
       EVNT_Description nvarchar(max)     
     )    
    
  if( isnull(@LeadID_LDACTV,0) > 0)    
   Begin    
        
   insert into #tblEventDescrb    
      exec  Usp_EventTemplate_DynamicVarReplacement @EventName_LDACTV,@UserID_LDACTV,'',@CallerNo_LDACTV,@LeadID_LDACTV,'',null    
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null    
   ,null,null,null,null,null,null,null,null,    
   null,null,null,null,null,null,0,null,null,null,null,null,null    
         
   declare @evntMessage nvarchar(max) = ''     
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb    
     
   if(@evntMessage <> '')    
   Begin    
  
     select  @evntMessage = replace(@evntMessage,'#group#',@pass1)  
    
     exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage, @EventName_LDACTV ,'usersearchlist',@serchid   
       
       
       
   end    
    
   End      
    
   End try    
   Begin catch    
       exec usp_insertErrorInfo    
   End Catch    
       
    IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence      
     Begin      
        DROP TABLE #tblEventDescrb      
     End      
       
        
   /*end Lead activity  Added to GroupList/Removed from Grouplist */    
    
    
    
    
    
        
end 


GO

