/* ============================================================
   Procedure: [dbo].[Cloud_Updte_UserPhone]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Cloud_Updte_UserPhone (
	@User_id BIGINT
	,@PhoneNo NVARCHAR(20)
	,@AppId BIGINT
	,@Opt INT
	)
AS
BEGIN
	IF @Opt = 1
	BEGIN
		UPDATE Cloud_User_Phone
		SET AppId = 0
		WHERE Parentid = @User_id
			AND PhoneNo = @PhoneNo

		UPDATE dbo.Cloud_app_master
		SET PhoneNo = ''
		WHERE AppId = @AppId
	END

	IF @Opt = 2
	BEGIN
		--update Cloud_User_Phone set AppId=0 where Parentid=@User_id and AppId = @AppId  
		UPDATE dbo.Cloud_app_master
		SET PhoneNo = ''
		WHERE PhoneNo = @PhoneNo

		UPDATE Cloud_User_Phone
		SET AppId = @AppId
		WHERE Parentid = @User_id
			AND PhoneNo = @PhoneNo

		UPDATE dbo.Cloud_app_master
		SET PhoneNo = @PhoneNo
		WHERE AppId = @AppId
	END

	DECLARE @rowJson NVARCHAR(MAX) = (
			SELECT *
			FROM Cloud_User_Phone
			WHERE Parentid = @User_id
			AND PhoneNo = @PhoneNo
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_id
		,@Activity_type = 'Updt_didphn'
		,@ActionType = 'U'
		,@RowJson = @rowJson
		,@Table_name = 'Cloud_User_Phone'
END



GO

