as 
begin
select cm.*, 
(select COUNT(*) from Cloud_User_Detail with (NOLOCK) where Parentid = cm.Parentid) as user_cnt,
(select COUNT(*) from Cloud_User_Phone  with (NOLOCK) where Parentid = cm.Parentid) as Phone_cnt, 
