/* ============================================================
   Procedure: [dbo].[Cloud_User_masterinsert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

----sp_helptext Cloud_InsertUser   
--select * from Cloud_user_Group   
CREATE   PROCEDURE [dbo].[Cloud_User_masterinsert]                
(                  
@tbl tbl_CloudManualUser READONLY ,                  
@parentid bigint ,              
@Groupid varchar(30),  
@Role varchar(30),            
@ids bigint,             
@opt int            
)                  
as                  
begin     
 declare @id  bigint                  
if(@opt=1)           
 begin               
  insert into Cloud_User_Detail(parentid, User_login, Pwd, Fname, Lname, Mobile,Email, active,role1)
                  select top 1 @parentid, User_login,Pwd, FName,Lname, Mobile, Email, 1,@Role from @tbl                 
  set @id   =  SCOPE_IDENTITY()              
  update Cloud_User_Detail set User_id= @id where id = @id            
 end                  
 if(@opt=3)      
 begin      
 update ss set ss.Fname=a.Fname,ss.Lname=a.Lname,      
 ss.Email=a.Email,ss.Mobile=a.Mobile,role1 = @Role      
   from Cloud_User_Detail ss inner join   @tbl a        
 on a.User_id = ss.User_id --and User_id=@ids     
select @id = User_id From @tbl    
end    
    
declare @Groupid11 varchar(50)    
set @Groupid11 = @Groupid  --'123#678#88' --    
while  @Groupid11!=''    
begin    
declare @str1 varchar(20)    
 declare @gpid int     
 set @gpid =  CHARINDEX('#', @Groupid11)    
 if @gpid =0    
 begin    
 select @str1 = @Groupid11    
 select @Groupid11=''     
 end    
 else    
 begin    
 set @str1 = substring(@Groupid11,1,@gpid-1)    
 set @Groupid11 = substring(@Groupid11,@gpid+1,(LEN(@Groupid11)-(@gpid)))    
 end    
 --select @str1, @Groupid11,@gpid    
 delete from dbo.Cloud_user_Group where Userid in (select User_id from @tbl)    
 insert into dbo.Cloud_user_Group (GroupId, userid, parentid,  Assign, Role)    
 select @str1 ,@id,@parentid,1,@Role from @tbl    
end    
       
              
end 



