/* ============================================================
   Procedure: [dbo].[Cloud_User_Phone_distribution]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

   
CREATE   PROCEDURE [dbo].[Cloud_User_Phone_distribution]          
(          
@Parentid bigint  
)          
as           
begin          
 select pm.*,ISNULL(ud.Fname,'')+' '+ISNULL(ud.Lname,'') u_name, ISNULL(am.AppName,'') AppName,
 ud.User_Login  
 from dbo.Cloud_phone_master pm  
 left outer join dbo.Cloud_User_Phone up  
 on up.PhoneNo = pm.PhoneNo   
 left outer join dbo.User_Detail ud   
 on ud.User_id= up.Parentid 
 left outer join dbo.Cloud_app_master am   
 on am.User_id= up.Parentid  
 and am.AppId = up.AppId  
 where ud.Parentid=@Parentid  order by ud.Parentid,APPNAME desc,PhoneNo  
end  



GO

/* ============================================================
   Procedure: [dbo].[Cloud_User_Phone_distribution_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

        
CREATE   PROCEDURE [dbo].[Cloud_User_Phone_distribution_new]            
(              
--@Parentid bigint   
@searchtxt varchar(100)     
)              
as               
begin              
 select pm.*,ISNULL(ud.Fname,'')+' '+ISNULL(ud.Lname,'') u_name, ISNULL(am.AppName,'') AppName,    
 ud.User_Login,up.Parentid   into #tmp    
 from dbo.Cloud_phone_master pm      
 left outer join dbo.Cloud_User_Phone up      
 on up.PhoneNo = pm.PhoneNo       
 left outer join dbo.User_Detail ud       
 on ud.User_id= up.Parentid     
 left outer join dbo.Cloud_app_master am       
 on am.User_id= up.Parentid      
 and am.AppId = up.AppId   
  where pm.reservedfor is null 
 
 if  @searchtxt =''  
 select * from #tmp  order by Parentid,APPNAME desc,PhoneNo    
 else  
 select * from #tmp    
 where (PhoneType like '%'+@searchtxt+'%'  
 or Category like '%'+@searchtxt+'%'  
 or User_Login like  '%'+@searchtxt+'%'  
 or PhoneNo like '%'+@searchtxt+'%'  
 or CreatedDate  like '%'+@searchtxt+'%')  
 order by Parentid,APPNAME desc,PhoneNo    
drop table #tmp     
end      


GO

