/* ============================================================
   Procedure: [dbo].[Cloud_ValidateMember]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--[Cloud_ValidateMember] '733','3444555567',36                   
CREATE   PROC [dbo].[Cloud_ValidateMember] -- 'Blocked Contact','9919548186',5674                      
(                       
@pass1 nvarchar(max),                          
@callerNo  varchar(20),                      
@appno as bigint                  
)                  
as                        
begin          
--declare @pass1 varchar(100)='All Enquiries,All Leads',                          
--@callerNo  varchar(20)='9315028328',                      
--@appno as bigint=5914    
declare @Parentid as bigint,@searchid as bigint,@entity varchar(20),@entityid bigint=0,@leadno bigint,@entityid1 bigint=0 
,@count int ,@pass nvarchar(200),@passid int=0  
declare @status int    =0  

select @Parentid= User_Id from dbo.Cloud_app_master(nolock) where appid = @appno         
drop table if exists #searchnames
create table #searchnames(id int identity (1,1),pass nvarchar(200))
insert into #searchnames(pass)
select item from SplitString(@pass1,',')

--select * from #searchnames
select @count=count(1) from #searchnames

while @count>0
begin
select @passid=min(id),@status=0 from #searchnames where id>@passid
select @pass=pass from #searchnames where id=@passid

select @searchid=id,@entity=criteriatype from tbl_SearchCriteria(nolock) where parentid=@parentid and       
CriteriaName=@pass      
 
print concat('searchid: ',@searchid,', name: ',@pass)
 
select @entityid=case when @entity='enquiry'  or @entity='All'     
then (select top 1 enquiryid from userenquiry_mobile_email(nolock) where parentid=@parentid and mobile=dbo.fn_trim0prefix(@callerno) order by enquiryid desc)      
when @entity='lead' then       
(select top 1 ulme_id  from Userleads_Mobile_Email(nolock) where       
parentid=@parentid and mobile=dbo.fn_trim0prefix(@callerno) order by ulme_id desc) end     
    
print @parentid    
print @entity    
print @entityid    
    
if @entity='All'    
select @entity='enquiry'    
    
exec [Usp_ContactExistsInSearch] @entity,@entityid,@searchid,@status output      
    
