/* ============================================================
   Procedure: [dbo].[Cloud_ValidatePassword]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_ValidatePassword]    
(   
@opt varchar(10),   
@callerNo  varchar(20),  
@appno as varchar(20),  
@password as varchar(50)    
)    
as    
begin  
declare @Parentid as bigint  
select @Parentid= User_Id from dbo.Cloud_app_master where PhoneNo = @appno  
if @opt='ticket'  
begin  
   
 select isnull(AssignTo, isnull(Assign_Group,'')) AssignedTo  , um.email,um.Mobile,um.Name   
 from Serv_TicketMaster tk  
 inner join Serv_User_Detail um on um.User_id = tk.User_id  
 where tk.ParentID = @Parentid and TicketNo = @password  
 and um.Mobile = @callerNo  
end  
if @opt='lead'  
begin  
 select AssignedTo from UserLeads where ParentID = @Parentid and  
 (MobileNo=@callerNo or MobileNo1 =@callerNo or MobileNo2 =@callerNo)  
end  
if @opt='searchlist'  
begin  
select *,'ok' rslt from usersearchlist where ParentID = @Parentid and IsSearch =1  
   and SpecificMobileNo = @callerNo and SearchName = @password  
end  
end



GO

/* ============================================================
   Procedure: [dbo].[Cloud_Validateuser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[Cloud_Validateuser] --'9718896162',0,1
(
@val varchar(100),
@user_id bigint,
@useropt int
)
as 
begin
declare @rslt as varchar(10)
set @rslt = 'ok'
if @user_id =0
begin
if @useropt = 0
begin
if exists(select 1 from Cloud_User_Detail where rtrim(email)= rtrim(@val))
	set @rslt = 'Email Id Already Exist'	
end
if @useropt = 1
begin
if exists(select 1 from Cloud_User_Detail where rtrim(mobile)= rtrim(@val))
	set @rslt = 'Mobile No Already Exist'	
end
end
else

begin
if @useropt = 0
begin
if exists(select 1 from Cloud_User_Detail where rtrim(email)= rtrim(@val) and user_id !=@user_id)
	set @rslt = 'Email Id Already Exist'	
end
if @useropt = 1
begin
if exists(select 1 from Cloud_User_Detail where rtrim(mobile)= rtrim(@val) and user_id !=@user_id)
	set @rslt = 'Mobile No Already Exist'	
end

end
select @rslt
end



GO

/* ============================================================
   Procedure: [dbo].[Cloud_voice_finaltblProcess]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_voice_finaltblProcess]      
      
as       
begin      
declare @t int,@c int,@s int  
select @t= 100-count(1) from Kit19Cloudvoicefinaltbl where processed=0  
create table #tmpfl(Voicequeueid bigint,didno nvarchar(20),mobile nvarchar(20),appid int,voiceid bigint,batchid bigint, isdnd int )  
  
select @s=COUNT(1) from Voice_QueueNew(nolock)  
  
select @t=dbo.fn_min_no(@s,@t)  
select @s = @t  
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,isdnd)  
select top (@t) VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,0  
from dbo.Voice_QueueNew   
 where Priority=2 and lower(route)='trans'  
order by VoiceQueueID   
  
select @c=COUNT(1) from #tmpfl  
  
select @t=@t-@c  
while @c<=@t  
begin  
  
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,isdnd)  
select top (@t) VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,0  
from dbo.Voice_QueueNew (nolock)  
where Priority=1 and lower(route)='trans'  
order by VoiceQueueID   
  
--insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid)  
--select top (@t-@c) VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid  
--from dbo.Voice_QueueNew where Priority=1 and route='trans'  
--order by VoiceQueueID   
--select '1 loop'  
select @c=COUNT(1) from #tmpfl  
select @t=@t-@c  
  
--insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid)  
--select top (@t) VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid  
--from dbo.Voice_QueueNew where Priority=0 and route='trans'  
--order by VoiceQueueID  
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,isdnd)  
select top (@t) VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,0  
from dbo.Voice_QueueNew (nolock)  
 where Priority=1 and lower(route)='trans'  
order by VoiceQueueID   
  
--select '2 loop'   
select @c=COUNT(1) from #tmpfl  
  
if @c =@s   
 break  
select @t=@t-@c  
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,isdnd)  
select top (@t) VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,   
case when ISNULL(d.DNDMobileNo,'') != '' then 1 else 0 end   
from dbo.Voice_QueueNew v  (nolock) left join mygroupappcomb.dbo.dnddirectory d  (nolock) on v.mobile=d.dndmobileno   
where priority=2 and lower(route)='promo'  
order by VoiceQueueID   
  
select @c=COUNT(1) from #tmpfl  
--select @c,@s, '3 loop'  
if @c =@s   
 break  
   
select @t=@t-@c  
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,isdnd)  
select top (@t) VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,   
case when ISNULL(d.DNDMobileNo,'') != '' then 1 else 0 end   
from dbo.Voice_QueueNew v (nolock) left join mygroupappcomb.dbo.dnddirectory d  (nolock) on v.mobile=d.dndmobileno   
where priority=1 and lower(route)='promo'  
order by VoiceQueueID   
   
select @c=COUNT(1) from #tmpfl  
--select @c,@s, '4 loop'  
if @c =@s   
 break  
  
select @t=@t-@c  
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,isdnd)  
select top (@t) VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,   
case when ISNULL(d.DNDMobileNo,'') != '' then 1 else 0 end   
from dbo.Voice_QueueNew v (nolock) left join mygroupappcomb.dbo.dnddirectory d  (nolock) on v.mobile=d.dndmobileno   
where priority=0 and lower(route)='promo'  
order by VoiceQueueID   
  
  
  
select @c=@t+1  
end  
  
  
insert into dbo. Kit19Cloudvoicefinaltbl(dnino, clino, appid, VoiceQueueID,messageid,batchid,sipname)      
select didno,Mobile,AppId ,VoiceQueueID,VoiceID,batchid,dbo.fn_getsipname(didno)

from #tmpfl where isdnd = 0  
     
  
update VD set IsDND=1 from dbo.Voice_DeliveryStatus VD  
 inner join #tmpfl tp on tp.VoiceID = VD.VoiceID and tp.mobile= VD.Mobile  
 where tp.isdnd = 1  
  
delete From Voice_QueueNew where VoiceQueueID in (select VoiceQueueID from #tmpfl)   
  
--select * From Voice_QueueNew Voice_QueueNew where VoiceQueueID in (select VoiceQueueID from #tmpfl)   
  
--select * from Voice_DeliveryStatus VD  
-- inner join #tmpfl tp on tp.VoiceID = VD.VoiceID and tp.mobile= VD.Mobile  
drop table #tmpfl    
end    
  


GO

/* ============================================================
   Procedure: [dbo].[Cloud_voice_finaltblProcess1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_voice_finaltblProcess1]                          
                          
as                           
begin                          
declare @t int,@c int,@s int,@qsize int=100                
if exists (select 1 from Kit19Cloudvoicefinaltbl(nolock) where processed=0 and       
(lastaccesstime<dateadd(d,-2,getdate()) or scheduledatetime<dateadd(d,-2,getdate()) or dbo.fn_getsipname(dnino) not in ('jio','tata','airtel2')))      
begin      
update Kit19Cloudvoicefinaltbl set processed=4 where processed=0 and       
(lastaccesstime<dateadd(d,-2,getdate()) or scheduledatetime<dateadd(d,-2,getdate()) or dbo.fn_getsipname(dnino) not in ('jio','tata','airtel2'))      
end      
select @t= @qsize-count(1) from Kit19Cloudvoicefinaltbl(nolock) where processed=0                    
--select @t         
begin try        
create table #tmpfl(Voicequeueid bigint,didno nvarchar(20),mobile nvarchar(20),appid int,voiceid bigint,batchid bigint,        
priority int,v_activityid bigint,v_entity nvarchar(20),p_id bigint)                      
                      
select @s=COUNT(1) from Voice_QueueNew(nolock)                      
select @t=dbo.fn_min_no(@s,@t)                      
if @t>0 and datepart(hh,getdate()) between 9 and 20                      
begin                      
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,priority,v_activityid,v_entity,p_id)                      
select top (@t) VoiceQueueID,didno,Mobile,AppId,VoiceID,v.batchid,b.Pri,v_activityid,v_entity,parentid       
from dbo.Voice_QueueNew v(nolock) join         
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end as Pri  
,TotalRecords  
from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID        
where Priority=2 and route='trans' and mobile like '%[0-9]%' and (parentid in (40856,33819)      
or b.TotalRecords<=3)  
order by Processed,VoiceQueueID desc                      
                      
select @c=COUNT(1) from #tmpfl                 
--select * from #tmpfl                   
                      
while @c<@t                       
begin                      
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,Priority,v_activityid,v_entity,p_id)                      
select top (case when @t-@c>0 then (@t-@c) else 0 end) VoiceQueueID,didno,Mobile,AppId,VoiceID,v.batchid,b.Pri,v_activityid,v_entity  
,parentid  
from dbo.Voice_QueueNew v(nolock) join         
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end as Pri,TotalRecords  from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID                      
where Priority=1 and route='trans'  and mobile like '%[0-9]%'  and (parentid in (40856,33819) or b.TotalRecords<=3)    
order by Processed,VoiceQueueID                       
select @c=COUNT(1) from #tmpfl                      
select @t=@t-@c                      
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,Priority,v_activityid,v_entity)                      
select top (case when @t-@c>0 then (@t-@c) else 0 end) VoiceQueueID,didno,Mobile,AppId,VoiceID,v.batchid,b.Pri,v_activityid,v_entity        
from dbo.Voice_QueueNew v(nolock) join         
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end as Pri,TotalRecords  from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID        
where Priority=0 and route='trans'   and mobile like '%[0-9]%'  and (parentid in (40856,33819) or b.TotalRecords<=3)                     
order by Processed,VoiceQueueID                       
select @c=COUNT(1) from #tmpfl                      
select @t=@t-@c                      
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,Priority,v_activityid,v_entity,p_id)                      
select top (case when @t-@c>0 then (@t-@c) else 0 end) VoiceQueueID,didno,Mobile,AppId,VoiceID,v.batchid,b.Pri,v_activityid,v_entity   ,parentid     
from dbo.Voice_QueueNew v(nolock) join         
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end as Pri,TotalRecords  from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID           
--left join mygroupappcomb.dbo.dnddirectory d (nolock)  on v.mobile=d.dndmobileno           
--left join userleads u (nolock) on u.parentid=v.parentid and v.Mobile in           
--(u.MobileNo,u.MobileNo1,u.MobileNo2)          
where --(d.DNDMobileNo is null or u.ID is not null) and     
--u.id is not null and  
priority=2 and route='promo'  and mobile like '%[0-9]%'  and (parentid in (40856,33819) or b.TotalRecords<=3)   --and dbo.fn_getsipname(didno)<>'tata'              
order by Processed,VoiceQueueID                       
            
select @c=COUNT(1) from #tmpfl                      
select @t=@t-@c                      
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,Priority,v_activityid,v_entity,p_id)                      
select top (case when @t-@c>0 then (@t-@c) else 0 end) VoiceQueueID,didno,Mobile,AppId,VoiceID,v.batchid,b.Pri,v_activityid,v_entity      ,parentid  
from dbo.Voice_QueueNew v(nolock) join         
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end as Pri,TotalRecords  from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID           
--left join mygroupappcomb.dbo.dnddirectory d  (nolock)  on v.mobile=d.dndmobileno           
--left join userleads u  (nolock) on u.parentid=v.parentid and v.Mobile in           
--(u.MobileNo,u.MobileNo1,u.MobileNo2)          
where --(d.DNDMobileNo is null or u.ID is not null) and    
--u.id is not null and  
priority=1 and route='promo' and mobile like '%[0-9]%'  and (parentid in (40856,33819) or b.TotalRecords<=3)    --and dbo.fn_getsipname(didno)<>'tata'                               
order by Processed,VoiceQueueID                       
select @c=COUNT(1) from #tmpfl                      
select @t=@t-@c                      
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,v.Priority,v_activityid,v_entity,p_id)                      
select top (case when @t-@c>0 then (@t-@c) else 0 end) VoiceQueueID,didno,Mobile,AppId,VoiceID,v.batchid,b.Pri,v_activityid,v_entity  
,parentid  
from dbo.Voice_QueueNew v(nolock) join         
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end as Pri,TotalRecords  from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID        
--left join mygroupappcomb.dbo.dnddirectory d  (nolock) on v.mobile=d.dndmobileno          
--left join userleads u  (nolock) on u.parentid=v.parentid and v.Mobile in           
--(u.MobileNo,u.MobileNo1,u.MobileNo2)          
where --(d.DNDMobileNo is null or u.ID is not null) and     
--u.id is not null and  
priority=0 and route='promo'  and mobile like '%[0-9]%'  and (parentid in (40856,33819) or b.TotalRecords<=3)   -- and dbo.fn_getsipname(didno)<>'tata'                              
order by Processed,VoiceQueueID                       
select @c=@t                      
end                      
  
/*            
select VoiceQueueID,BatchID into #d from Voice_QueueNew v (nolock)   
join mygroupappcomb.dbo.dnddirectory d(nolock)  on v.mobile=d.dndmobileno   
where route='promo'            
declare @count int=(select COUNT(1) from #d)            
        
select * into #tmpfldnd from #d        
          
while @count>0            
begin            
update v set isdnd=1 from   
(select top 100 v.* from Voice_QueueNew v join #d d on d.voicequeueid=v.voicequeueid order by d.voicequeueid) v           
      
insert into voice_queuenewDND(CountryCode,VoiceID,Mobile,VoiceInsertDate,Priority,            
IsDND,BatchID,Isallowdnd,issent,isProcessed,voice_type,AppId,didno,user_id,voiceDuration,route,            
parentid)            
select top 100 CountryCode,VoiceID,Mobile,VoiceInsertDate,Priority,            
IsDND,BatchID,Isallowdnd,issent,isProcessed,voice_type,AppId,didno,user_id,voiceDuration,route,            
parentid from Voice_QueueNew v where IsDND=1 order by v.voicequeueid            
            
delete d from (select top 100 * from voice_queuenew where isdnd=1 order by voicequeueid) d            
delete d from (select top 100 * from #d order by voicequeueid) d            
            
set @count=@count-100            
end            
*/                      
insert into dbo. Kit19Cloudvoicefinaltbl(dnino, clino, appid, VoiceQueueID,messageid,batchid,ScheduleDateTime,Priority,v_activityid,      
v_entity,sipname,context,processed,kit19uniqueid)            
select distinct trim(didno),trim(Mobile),AppId ,VoiceQueueID,VoiceID,batchid,getdate(),Priority,v_activityid,v_entity,dbo.fn_getsipname(didno),case when dbo.fn_getsipname(didno) in ('jio','airtel2') then 'outbound-in/n' else 'outbound-tata/n' end ,case when p_id=40856 then 6 else 0 end,case when p_id=40856 then cast(lower(newid()) as nvarchar(100)) else null end
--case when p_id<>40856 then 4 else 0 end      
from #tmpfl --where trim(didno)<>'1204759570'          
        
update b set isprocess=case when isnull(isprocessed,0)+isnull(ProcessedRecords,0)  
--+isnull(DNDProcessed,0)  
>=totalRecords then 1 else isprocess end,        
isprocessed=isnull(isprocessed,0)+isnull(ProcessedRecords,0)  
--+isnull(DNDProcessed,0)  
,BatchProcessTime=getdate() from BatchVoiceInfo b         
join         
(select batchid,count(batchid) ProcessedRecords from #tmpfl group by batchid)         
v on b.BatchID=v.BatchID         
--left join         
--(select batchid,count(1) DNDProcessed from #tmpfldnd group by batchid)         
--t on t.BatchID=b.BatchID                      
 

if exists (select 1 from #tmpfl where p_id=40856)
begin
begin try
INSERT INTO OPENQUERY(mysql_new1, 'SELECT aleg_number, aleg_context, aleg_gateway, aleg_uniqueid, callerid, appid, bleg_number, bleg_context, bleg_gateway, channel_variable, priority FROM calls')
(
    aleg_number,
    aleg_context,
    aleg_gateway,
    aleg_uniqueid,
    callerid,
    appid,
    bleg_number,
    bleg_context,
    bleg_gateway,
    channel_variable,
    priority
)
SELECT
    '0' + clino AS aleg_number,
    'airtel' AS aleg_context,
    'airtel' AS aleg_gateway,
    '' AS aleg_uniqueid,
    originatedniprefix + dnino AS callerid,
    k.appid,
    '' AS bleg_number,
    'outbound-user-airtel' AS bleg_context,
    '' AS bleg_gateway,
    CAST(k.appid AS NVARCHAR) + '~' + kit19uniqueid + '~' + sipheader + originatedniprefix + dnino + originatednipostfix + '~' + CAST(k.id AS NVARCHAR) AS channel_variable,
    1 AS priority -- Adjust or replace if `priority` needs to be a different value
FROM Kit19Cloudvoicefinaltbl (NOLOCK) k join #tmpfl t on k.VoiceQueueID=t.Voicequeueid and k.messageid=t.voiceid
where p_id=40856 and k.processed=6

update k set processed=7,LastAccessTime=getdate() from Kit19Cloudvoicefinaltbl k join #tmpfl t on k.VoiceQueueID=t.Voicequeueid and k.messageid=t.voiceid where p_id=40856 and k.processed=6

end try
begin catch
exec usp_inserterrorinfo
end catch
end

                      
delete From Voice_QueueNew where VoiceQueueID in (select VoiceQueueID from #tmpfl)                      
end                      
drop table if exists #tmpfl          
drop table  if exists  #d        
drop table  if exists #tmpfldnd                     
end try        
begin catch        
exec usp_inserterrorinfo        
end catch        
end


GO

/* ============================================================
