   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Cloud_voice_finaltblProcess1_int]                          
                          
as                           
begin                          
declare @t int,@c int,@s int,@qsize int=10                
if exists (select 1 from Kit19Cloudvoicefinaltbl(nolock) where processed=0 and       
(lastaccesstime<dateadd(d,-2,getdate()) or scheduledatetime<dateadd(d,-2,getdate()) or dbo.fn_getsipname(dnino) not in ('jio','tata','go')))      
begin      
