,parentid  
from dbo.Voice_QueueNew v(nolock) join         
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end as Pri,TotalRecords  from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID                      
where Priority=1 and route='trans'  and mobile like '%[0-9]%'  and (parentid in (40856,33819) or b.TotalRecords<=3)    
