(lastaccesstime<dateadd(d,-2,getdate()) or scheduledatetime<dateadd(d,-2,getdate()) or dbo.fn_getsipname(dnino) in ('jio','tata')))    
begin    
update Kit19Cloudvoicefinaltbl set processed=4 where processed=0 and     
(lastaccesstime<dateadd(d,-2,getdate()) or scheduledatetime<dateadd(d,-2,getdate()) or dbo.fn_getsipname(dnino) not in ('jio','tata'))    
