begin                    
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,priority,v_activityid,v_entity)                    
select VoiceQueueID,didno,Mobile,AppId,VoiceID,v.batchid,b.Pri,v_activityid,v_entity      
from dbo.Voice_QueueNew v(nolock) join       
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end       
as Pri from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID      
where Priority=2 and route='trans' and mobile like '%[0-9]%'       
order by Processed,VoiceQueueID desc                    
                    
