select @c=COUNT(1) from #tmpfl                    
select @t=@t-@c                    
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,Priority,v_activityid,v_entity)                    
select top (case when @t-@c>0 then (@t-@c) else 0 end) VoiceQueueID,didno,Mobile,AppId,VoiceID,v.batchid,b.Pri,v_activityid,v_entity      
from dbo.Voice_QueueNew v(nolock) join       
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end as Pri  from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID      
where Priority=0 and route='trans'   and mobile like '%[0-9]%'                  
order by Processed,VoiceQueueID                     
select @c=COUNT(1) from #tmpfl                    
select @t=@t-@c                    
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,Priority,v_activityid,v_entity)                    
select top (case when @t-@c>0 then (@t-@c) else 0 end) VoiceQueueID,didno,Mobile,AppId,VoiceID,v.batchid,b.Pri,v_activityid,v_entity      
from dbo.Voice_QueueNew v(nolock) join       
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end as Pri  from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID         
--left join mygroupappcomb.dbo.dnddirectory d (nolock)  on v.mobile=d.dndmobileno         
left join userleads u (nolock) on u.parentid=v.parentid and v.Mobile in         
(u.MobileNo,u.MobileNo1,u.MobileNo2)        
where --(d.DNDMobileNo is null or u.ID is not null) and   
u.id is not null and
priority=2 and route='promo'  and mobile like '%[0-9]%'                   
order by Processed,VoiceQueueID                     
          
select @c=COUNT(1) from #tmpfl                    
select @t=@t-@c                    
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,Priority,v_activityid,v_entity)                    
select top (case when @t-@c>0 then (@t-@c) else 0 end) VoiceQueueID,didno,Mobile,AppId,VoiceID,v.batchid,b.Pri,v_activityid,v_entity      
from dbo.Voice_QueueNew v(nolock) join       
(select batchid,100*(isprocessed/cast(totalrecords as float)) Processed,case when TotalRecords between 1 and 10 then 2 else 0 end as Pri  from BatchVoiceInfo(nolock)) b on b.BatchID=v.BatchID         
--left join mygroupappcomb.dbo.dnddirectory d  (nolock)  on v.mobile=d.dndmobileno         
left join userleads u  (nolock) on u.parentid=v.parentid and v.Mobile in         
(u.MobileNo,u.MobileNo1,u.MobileNo2)        
where --(d.DNDMobileNo is null or u.ID is not null) and  
u.id is not null and
priority=1 and route='promo' and mobile like '%[0-9]%'                    
order by Processed,VoiceQueueID                     
select @c=COUNT(1) from #tmpfl                    
select @t=@t-@c                    
insert into #tmpfl(VoiceQueueID,didno,Mobile,AppId,VoiceID,batchid,v.Priority,v_activityid,v_entity)                    
