/* ============================================================
   Procedure: [dbo].[cnvrtlead_wrongdt_to_date]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC cnvrtlead_wrongdt_to_date

as
begin
select top 1000 NextStatusDate,followupdate,id, ROW_NUMBER() over(order by id) rcno into #Tmp
 FROM   UserLeads UL(NOLOCK) where  ParentID = 30124 and  
ISDATE(NextStatusDate) =0  order by id 
declare @maxid bigint, @minid as bigint
select @maxid = MAX(rcno), @minid = MIN(rcno) from #Tmp
while @minid <= @maxid
begin
declare @dte  varchar(20)='', @id as bigint
declare @dd1 varchar(4)='',@dd2 varchar(4)='',@dd3 varchar(4)='', @ps as varchar(1)='/'
select @dte=NextStatusDate, @id= id from #Tmp where rcno = @minid
if  CHARINDEX('/', @dte) <0 
	set @ps = '-'
	
declare @mpos int  = CHARINDEX(@ps, @dte)
select @dd1=SUBSTRING(@dte,1,@mpos-1),@dte=SUBSTRING(@dte,@mpos+1,LEN(@dte)-@mpos )	

select @mpos   = CHARINDEX(@ps, @dte)
select @dd2=SUBSTRING(@dte,1,@mpos-1),@dd3=SUBSTRING(@dte,@mpos+1,LEN(@dte)-@mpos )


set @dte = @dd3+'-'+@dd2+'-'+@dd1
update UserLeads set NextStatusDate = @dte where   id = @id
update UserLeads set followupdate = @dte where id = @id and followupdate is null


set @minid= @minid+1

end
select * from #Tmp
drop table #Tmp
end


GO

