SET QUOTED_IDENTIFIER ON


-- =============================================
-- Author:		<Author,,Rajvir Singh Mahala>
-- Create date: <Create Date,, Apr 19, 2012>
-- Description:	<Description,,>
-- =============================================
CREATE   PROCEDURE [dbo].[Convexicon_SelectMessage]
AS
BEGIN
	DECLARE @MessageID INT
	SELECT top(1) @MessageID = MessageID FROM Convexicon_Message WHERE Status = 'I' ORDER BY Insert_TimeStamp
	SELECT top(1) MessageID, MessageText, MobileNo FROM Convexicon_Message WHERE MessageID = @MessageID
	UPDATE Convexicon_Message SET Send_TimeStamp = GETDATE(), Status = 'S' WHERE MessageID = @MessageID
END




