/* ============================================================
   Procedure: [dbo].[dashboard_get_call_timeline]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- -----------------------------------------------------------------
-- 3) PER-CALL TIMELINE (3 result sets: summary, turns, errors)
-- -----------------------------------------------------------------
CREATE   PROCEDURE dbo.dashboard_get_call_timeline
    @callsid NVARCHAR(100)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @calllogid BIGINT;
    SELECT TOP 1 @calllogid = cl.id
    FROM TwilioCalls c (NOLOCK)
    INNER JOIN calllog cl (NOLOCK) ON cl.reftable = 'twiliocalls' AND cl.refid = c.id
    WHERE c.CallSid = @callsid;

    -- Result set 1: Summary
    SELECT TOP 1
        c.CallSid                                 AS call_sid,
        cl.id                                     AS calllog_id,
        c.direction                               AS direction,
        c.call_start_time                         AS started_at,
        c.call_end_time                           AS ended_at,
        c.CallDuration                            AS duration_sec,
        ISNULL(t.turn_count, 0)                   AS turn_count,
        t.avg_turn_ms                             AS avg_turn_ms,
        t.max_turn_ms                             AS max_turn_ms,
        ISNULL(e.cnt, 0)                          AS error_count,
        ISNULL(cl.customernumber, c.CallerId)     AS customer_number,
        c.Dnid                                    AS did_number,
        cl.customercalldisposition                AS disposition,
        b.bot_name                                 AS bot_name
    FROM TwilioCalls c (NOLOCK)
    LEFT JOIN calllog cl (NOLOCK) ON cl.reftable = 'twiliocalls' AND cl.refid = c.id
    LEFT JOIN voice_bot_details b (NOLOCK) ON b.id = cl.bot_id
    LEFT JOIN (
        SELECT calllog_id,
               COUNT(*)              AS turn_count,
               AVG(total_latency_ms) AS avg_turn_ms,
               MAX(total_latency_ms) AS max_turn_ms
        FROM voice_bot_conversation_turns (NOLOCK)
        WHERE calllog_id = @calllogid
        GROUP BY calllog_id
    ) t ON t.calllog_id = cl.id
    LEFT JOIN (
        SELECT CallSid, COUNT(*) AS cnt
        FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
        WHERE CallSid = @callsid
        GROUP BY CallSid
    ) e ON e.CallSid = c.CallSid
    WHERE c.CallSid = @callsid;

    -- Result set 2: Turns
    SELECT
        turn_number                               AS turn_number,
        created_at                                AS created_at,
        user_input                                AS user_input,
        bot_response                              AS bot_response,
        stt_latency_ms                            AS stt_latency_ms,
        llm_latency_ms                            AS llm_latency_ms,
        tts_latency_ms                            AS tts_latency_ms,
        total_latency_ms                          AS total_latency_ms,
        ChatAgentInputTokens                      AS input_tokens,
        ChatAgentOutputTokens                     AS output_tokens,
        TTSCharacters                             AS tts_characters,
        llmcostusd                                AS llm_cost_usd,
        TtsCostUsd                                AS tts_cost_usd,
        CAST(WasBargedIn AS INT)                  AS was_barged_in
    FROM voice_bot_conversation_turns (NOLOCK)
    WHERE calllog_id = @calllogid
    ORDER BY turn_number ASC;

    -- Result set 3: Errors
    -- IMPORTANT: Use createdate (IST) for display, not ErrorDateTime (UTC).
    -- All other tables in this DB are IST; aligning on createdate keeps timestamps comparable.
    IF OBJECT_ID('dbo.tbl_vb_VoiceBotErrors', 'U') IS NOT NULL
    BEGIN
        SELECT
            errorid                                    AS error_id,
            ISNULL(createdat, ErrorDateTime)     AS error_time,
            CallSid                               AS call_sid,
            ErrorMethodName                       AS error_method,
            ErrorType                             AS error_type,
            ErrorDescription                      AS error_description,
            LogFileName                           AS log_file
        FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
        WHERE CallSid = @callsid
        ORDER BY ISNULL(createdat, ErrorDateTime) ASC;
    END
    ELSE
    BEGIN
        -- Return empty result set with the right shape
        SELECT TOP 0
            CAST(0 AS BIGINT)                     AS error_id,
            CAST(NULL AS DATETIME)                AS error_time,
            CAST(NULL AS NVARCHAR(100))           AS call_sid,
            CAST(NULL AS NVARCHAR(200))           AS error_method,
            CAST(NULL AS NVARCHAR(100))           AS error_type,
            CAST(NULL AS NVARCHAR(MAX))           AS error_description,
            CAST(NULL AS NVARCHAR(200))           AS log_file;
    END
END



GO

/* ============================================================
   Procedure: [dbo].[dashboard_get_fleet_metrics]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- -----------------------------------------------------------------
-- 1) FLEET METRICS (single-row snapshot)
-- -----------------------------------------------------------------
CREATE   PROCEDURE dbo.dashboard_get_fleet_metrics
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @now DATETIME = GETDATE();
    DECLARE @t5 DATETIME = DATEADD(MINUTE, -5,  @now);
    DECLARE @t15 DATETIME = DATEADD(MINUTE, -15, @now);
    DECLARE @t60 DATETIME = DATEADD(MINUTE, -60, @now);

    DECLARE @active INT = (
        SELECT COUNT(*) FROM TwilioCalls (NOLOCK)
        WHERE call_end_time IS NULL
          AND call_start_time >= DATEADD(MINUTE, -60, @now)
    );
    DECLARE @c5 INT = (SELECT COUNT(*) FROM TwilioCalls (NOLOCK) WHERE call_start_time >= @t5);
    DECLARE @c15 INT = (SELECT COUNT(*) FROM TwilioCalls (NOLOCK) WHERE call_start_time >= @t15);
    DECLARE @c60 INT = (SELECT COUNT(*) FROM TwilioCalls (NOLOCK) WHERE call_start_time >= @t60);

    DECLARE @p50 INT, @p95 INT;
    SELECT @p50 = CAST(PERCENTILE_CONT(0.50) WITHIN GROUP (ORDER BY total_latency_ms) OVER() AS INT),
           @p95 = CAST(PERCENTILE_CONT(0.95) WITHIN GROUP (ORDER BY total_latency_ms) OVER() AS INT)
    FROM voice_bot_conversation_turns (NOLOCK)
    WHERE created_at >= @t60 AND total_latency_ms IS NOT NULL;
    -- PERCENTILE_CONT returns one row per source row; collapse to one
    SELECT @p50 = MAX(@p50), @p95 = MAX(@p95);

    DECLARE @errs15 INT = 0, @errs60 INT = 0;
    IF OBJECT_ID('dbo.tbl_vb_VoiceBotErrors', 'U') IS NOT NULL
    BEGIN
        SELECT @errs15 = COUNT(*) FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK) WHERE ErrorDateTime >= @t15;
        SELECT @errs60 = COUNT(*) FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK) WHERE ErrorDateTime >= @t60;
    END

    DECLARE @errRate DECIMAL(6,2) = NULL;
    IF @c60 > 0
        SET @errRate = CAST(@errs60 * 100.0 / @c60 AS DECIMAL(6,2));

    SELECT
        @active        AS active_calls,
        @c5            AS calls_5m,
        @c15           AS calls_15m,
        @c60           AS calls_60m,
        @p50           AS p50_turn_ms,
        @p95           AS p95_turn_ms,
        @errs15        AS errors_15m,
        @errRate       AS error_rate_60m_pct;
END



GO

/* ============================================================
   Procedure: [dbo].[dashboard_get_latency_histogram]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- -----------------------------------------------------------------
-- 5) LATENCY HISTOGRAM
--      Buckets (ms): [0,500), [500,1000), [1000,1500), [1500,2000),
--                    [2000,3000), [3000,5000), [5000,10000), [10000,+inf)
-- -----------------------------------------------------------------
CREATE   PROCEDURE dbo.dashboard_get_latency_histogram
    @windowMinutes INT = 60
AS
BEGIN
    SET NOCOUNT ON;
    SET @windowMinutes = ISNULL(@windowMinutes, 60);
    IF @windowMinutes < 1 SET @windowMinutes = 1;
    IF @windowMinutes > 24*60 SET @windowMinutes = 24*60;

    DECLARE @t DATETIME = DATEADD(MINUTE, -@windowMinutes, GETDATE());

    ;WITH buckets AS (
        SELECT 0    AS lower_ms,    500  AS upper_ms UNION ALL
        SELECT 500,                  1000             UNION ALL
        SELECT 1000,                 1500             UNION ALL
        SELECT 1500,                 2000             UNION ALL
        SELECT 2000,                 3000             UNION ALL
        SELECT 3000,                 5000             UNION ALL
        SELECT 5000,                 10000            UNION ALL
        SELECT 10000,                2147483647
    ),
    src AS (
        SELECT total_latency_ms
        FROM voice_bot_conversation_turns (NOLOCK)
        WHERE created_at >= @t AND total_latency_ms IS NOT NULL
    )
    SELECT
        b.lower_ms,
        b.upper_ms,
        ISNULL(SUM(CASE WHEN s.total_latency_ms >= b.lower_ms AND s.total_latency_ms < b.upper_ms THEN 1 ELSE 0 END), 0) AS cnt
    FROM buckets b
    LEFT JOIN src s ON 1 = 1
    GROUP BY b.lower_ms, b.upper_ms
    ORDER BY b.lower_ms;
END



GO

/* ============================================================
   Procedure: [dbo].[dashboard_get_llm_health]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- -----------------------------------------------------------------
-- 6) LLM HEALTH / TIMEOUT-FALLBACK STATS
--      Specifically focused on rows logged by the LLM-timeout fallback
--      path in ConversationOrchestrator (ErrorType = 'LLMTimeoutFallback'
--      or 'AzureFallbackError'). These are NOT crashes — they mean the
--      primary LLM did not return its first token in time and we had
--      to switch to the fallback. They still cost the user 5+ seconds
--      of dead air per turn, so they're a real UX signal.
--
--      Returns 3 result sets:
--        (1) Headline tiles (last 24h + last 1h)
--        (2) Per-provider breakdown over last 24h
--        (3) Hourly bucket sparkline for last 24h (24 rows, oldest first)
-- -----------------------------------------------------------------
CREATE   PROCEDURE dbo.dashboard_get_llm_health
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @now    DATETIME = GETDATE();
    DECLARE @t1h    DATETIME = DATEADD(HOUR, -1,  @now);
    DECLARE @t24h   DATETIME = DATEADD(HOUR, -24, @now);

    -- Calls in the same windows (denominator for "% of calls degraded")
    DECLARE @calls1h  INT = (SELECT COUNT(*) FROM TwilioCalls (NOLOCK) WHERE call_start_time >= @t1h);
    DECLARE @calls24h INT = (SELECT COUNT(*) FROM TwilioCalls (NOLOCK) WHERE call_start_time >= @t24h);

    -- Headline numbers — "degraded" = primary LLM was slow OR failed.
    -- Includes both legacy LLMTimeoutFallback (full 5s burn → fallback) AND
    -- LLMHedgeWon (primary slow > hedge delay, Azure beat it — recovered cleanly).
    DECLARE @to1h   INT = (SELECT COUNT(*) FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
                            WHERE ErrorDateTime >= @t1h
                              AND ErrorType IN ('LLMTimeoutFallback','AzureFallbackError','LLMHedgeWon'));
    DECLARE @to24h  INT = (SELECT COUNT(*) FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
                            WHERE ErrorDateTime >= @t24h
                              AND ErrorType IN ('LLMTimeoutFallback','AzureFallbackError','LLMHedgeWon'));

    -- Hedge "saves" (primary slow but Azure delivered first — clean recovery)
    DECLARE @hedgeWon24h INT = (SELECT COUNT(*) FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
                            WHERE ErrorDateTime >= @t24h AND ErrorType = 'LLMHedgeWon');
    -- Hard timeouts (primary AND fallback failed first-token in 5s)
    DECLARE @hardTo24h   INT = (SELECT COUNT(*) FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
                            WHERE ErrorDateTime >= @t24h
                              AND ErrorType IN ('LLMTimeoutFallback','AzureFallbackError'));

    DECLARE @callsHit24h INT = (
        SELECT COUNT(DISTINCT CallSid)
        FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
        WHERE ErrorDateTime >= @t24h
          AND ErrorType IN ('LLMTimeoutFallback','AzureFallbackError','LLMHedgeWon')
          AND CallSid IS NOT NULL AND CallSid <> ''
    );

    SELECT
        @to1h                                                                      AS timeouts_1h,
        @to24h                                                                     AS timeouts_24h,
        @hedgeWon24h                                                               AS hedge_won_24h,
        @hardTo24h                                                                 AS hard_timeouts_24h,
        @callsHit24h                                                               AS calls_hit_24h,
        @calls24h                                                                  AS total_calls_24h,
        CASE WHEN @calls24h = 0 THEN NULL
             ELSE CAST(100.0 * @callsHit24h / @calls24h AS DECIMAL(5,2)) END       AS pct_calls_degraded_24h,
        CASE WHEN @calls1h  = 0 THEN NULL
             ELSE CAST(1.0  * @to1h  / NULLIF(@calls1h ,0) AS DECIMAL(8,3)) END    AS timeouts_per_call_1h;

    -- (2) Per-provider breakdown over last 24h
    SELECT
        ISNULL(NULLIF(LTRIM(RTRIM(ErrorMethodName)), ''), '(unknown)')              AS provider,
        ErrorType                                                                   AS error_type,
        COUNT(*)                                                                    AS cnt,
        COUNT(DISTINCT CallSid)                                                     AS distinct_calls,
        MIN(ErrorDateTime)                                                          AS first_seen,
        MAX(ErrorDateTime)                                                          AS last_seen
    FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
    WHERE ErrorDateTime >= @t24h
      AND ErrorType IN ('LLMTimeoutFallback','AzureFallbackError','LLMHedgeWon')
    GROUP BY ErrorMethodName, ErrorType
    ORDER BY cnt DESC;

    -- (3) Hourly sparkline for last 24h (gap-filled so the chart has 24 points)
    ;WITH hours AS (
        SELECT 0 AS h
        UNION ALL SELECT h+1 FROM hours WHERE h < 23
    ),
    samples AS (
        SELECT
            DATEDIFF(HOUR, ErrorDateTime, @now) AS hours_ago
        FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
        WHERE ErrorDateTime >= @t24h
          AND ErrorType IN ('LLMTimeoutFallback','AzureFallbackError','LLMHedgeWon')
    )
    SELECT
        DATEADD(HOUR, -h.h, @now)                                                  AS bucket_end,
        ISNULL(SUM(CASE WHEN s.hours_ago = h.h THEN 1 ELSE 0 END), 0)              AS cnt
    FROM hours h
    LEFT JOIN samples s ON s.hours_ago = h.h
    GROUP BY h.h
    ORDER BY h.h DESC                                                              -- oldest first → newest last
    OPTION (MAXRECURSION 30);
END



GO

/* ============================================================
   Procedure: [dbo].[dashboard_get_recent_calls]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- -----------------------------------------------------------------
-- 2) RECENT CALLS LIST
-- -----------------------------------------------------------------
CREATE   PROCEDURE dbo.dashboard_get_recent_calls
    @top INT = 50
AS
BEGIN
    SET NOCOUNT ON;
    SET @top = ISNULL(@top, 50);
    IF @top > 500 SET @top = 500;

    DECLARE @errCounts TABLE (CallSid NVARCHAR(100) PRIMARY KEY, cnt INT);
    IF OBJECT_ID('dbo.tbl_vb_VoiceBotErrors', 'U') IS NOT NULL
    BEGIN
        INSERT INTO @errCounts (CallSid, cnt)
        SELECT CallSid, COUNT(*)
        FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
        WHERE ErrorDateTime >= DATEADD(HOUR, -24, GETDATE())
          AND CallSid IS NOT NULL AND CallSid <> ''
        GROUP BY CallSid;
    END

    SELECT TOP (@top)
        c.CallSid                                            AS call_sid,
        cl.id                                                AS calllog_id,
        c.direction                                          AS direction,
        c.call_start_time                                    AS started_at,
        c.call_end_time                                      AS ended_at,
        c.CallDuration                                       AS duration_sec,
        ISNULL(t.turn_count, 0)                              AS turn_count,
        t.avg_turn_ms                                        AS avg_turn_ms,
        t.max_turn_ms                                        AS max_turn_ms,
        ISNULL(e.cnt, 0)                                     AS error_count,
        -- customer_number is ALWAYS the non-DID side regardless of direction.
        -- Prefer calllog.customernumber (canonical), fall back to TwilioCalls.CallerId.
        ISNULL(cl.customernumber, c.CallerId)                AS customer_number,
        c.Dnid                                               AS did_number,
        cl.customercalldisposition                           AS disposition,
        b.bot_name                                            AS bot_name
    FROM TwilioCalls c (NOLOCK)
    LEFT JOIN calllog cl (NOLOCK) ON cl.reftable = 'twiliocalls' AND cl.refid = c.id
    LEFT JOIN voice_bot_details b (NOLOCK) ON b.id = cl.bot_id
    LEFT JOIN (
        SELECT calllog_id,
               COUNT(*)              AS turn_count,
               AVG(total_latency_ms) AS avg_turn_ms,
               MAX(total_latency_ms) AS max_turn_ms
        FROM voice_bot_conversation_turns (NOLOCK)
        GROUP BY calllog_id
    ) t ON t.calllog_id = cl.id
    LEFT JOIN @errCounts e ON e.CallSid = c.CallSid
    WHERE c.call_start_time >= DATEADD(HOUR, -48, GETDATE())
    ORDER BY c.call_start_time DESC;
END



GO

/* ============================================================
   Procedure: [dbo].[dashboard_get_recent_errors]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- -----------------------------------------------------------------
-- 4) RECENT ERRORS (fleet-wide)
-- -----------------------------------------------------------------
CREATE   PROCEDURE dbo.dashboard_get_recent_errors
    @top INT = 50
AS
BEGIN
    SET NOCOUNT ON;
    SET @top = ISNULL(@top, 50);
    IF @top > 500 SET @top = 500;

    IF OBJECT_ID('dbo.tbl_vb_VoiceBotErrors', 'U') IS NOT NULL
    BEGIN
        -- Use createdate (IST) for display, ErrorDateTime as fallback only.
        SELECT TOP (@top)
            errorid                                   AS error_id,
            ISNULL(createdat, ErrorDateTime)    AS error_time,
            CallSid                              AS call_sid,
            ErrorMethodName                      AS error_method,
            ErrorType                            AS error_type,
            ErrorDescription                     AS error_description,
            LogFileName                          AS log_file
        FROM dbo.tbl_vb_VoiceBotErrors (NOLOCK)
        ORDER BY ISNULL(createdat, ErrorDateTime) DESC;
    END
    ELSE
    BEGIN
        SELECT TOP 0
            CAST(0 AS BIGINT)                     AS error_id,
            CAST(NULL AS DATETIME)                AS error_time,
            CAST(NULL AS NVARCHAR(100))           AS call_sid,
            CAST(NULL AS NVARCHAR(200))           AS error_method,
            CAST(NULL AS NVARCHAR(100))           AS error_type,
            CAST(NULL AS NVARCHAR(MAX))           AS error_description,
            CAST(NULL AS NVARCHAR(200))           AS log_file;
    END
END



GO

