/* ============================================================
   Procedure: [dbo].[eshop_add_cart]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[eshop_add_cart]  
(  
@Product varchar(150),  
@Variant varchar(50),  
@Quantity int,  
@UserName varchar(50)  
)  
as  
begin  
declare @Price numeric(18,2)  
set @Price = (select distinct PRICE from Variant_detail where PRODUCTNAME = @Product and Variant = @Variant)  
  
if not exists(select '*' from eshop_cart_items where UserName = @UserName and ProductName = @Product and Variant = @Variant)  
begin  
insert into eshop_cart_items(UserName,ProductName,Variant,Quantity,Price)  
values (@UserName, @Product,@Variant,@Quantity,@Price)  
end  
else  
begin  
update eshop_cart_items  
set Quantity = isnull(Quantity,0) + @Quantity, Price = @Price  
where UserName = @UserName and ProductName = @Product and Variant = @Variant  
end  
  
end  


GO

/* ============================================================
   Procedure: [dbo].[eshop_after_loyalty_point]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_after_loyalty_point --1000,33097,101,1212            
(            
@loyaltyCurrency int,                                   
@ParentID BIGINT =null,                                   
@CustomerID int,            
@BIllAmount VARCHAR(500)= null             
)            
as            
begin  
	SELECT 0;
	RETURN;
	-- Please update the procedure before removing the previous statement
	Declare @CustPoint int, @EquivalentQuantity int,@EquivalentCurrency int,     
	@CustomerName varchar(200), @TotalPoint int            
            
	Set @CustomerName = (Select  First_Name +' '+Last_Name from Customers where User_ID = @ParentID and CustomerID = @CustomerID)            
            
    
	select @EquivalentQuantity = EquivalentQuantity, @EquivalentCurrency = EquivalentCurrency             
	from eshop_loyalty_global_setting (nolock) where User_ID = @ParentID            
	set @TotalPoint = (select TotalPoint from eshop_cust_loyalty_total where CustomerName = @CustomerName and User_ID = @ParentID         
	and CustomerID = @CustomerID)            
            
	set @CustPoint = (@loyaltyCurrency *@EquivalentQuantity) / @EquivalentCurrency            
	insert into Eshop_Cust_Loyalty_Details (CustomerName,Date,RuleName,Status,Points,User_ID, CustomerID)            
	values(@CustomerName, getdate(),'Purchase','Debit',@CustPoint,@ParentID,@CustomerID)            
	update eshop_cust_loyalty_total            
	set TotalPoint = TotalPoint - @CustPoint, TotalCurrency = TotalCurrency - @loyaltyCurrency            
	where CustomerName = @CustomerName and User_ID = @ParentID  and CustomerID = @CustomerID          
            
end 


GO

/* ============================================================
   Procedure: [dbo].[eshop_apply_loyalty_point]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_apply_loyalty_point --10000,33097,49,404            
(            
@loyaltyPoint int,                                   
@ParentID BIGINT =null,                                   
@CustomerID int,            
@BIllAmount VARCHAR(500)= null             
)            
as            
begin            
Declare @MinimumPoint int =0, @Maximumlimit int =0, @CustPoint int =0, @EquivalentQuantity int =0,             
@EquivalentCurrency int =0, @CurrentCurrency int =0, @Bill int = 0, @TotalRedeempercentage int =0, @MaxRedeemPercentage int =0,            
@CustomerName varchar(200), @TotalPoint int = 0           
            
Set @CustomerName = (Select  First_Name +' '+Last_Name from Customers where User_ID = @ParentID and CustomerID = @CustomerID)            
select @MinimumPoint = ISNULL(Minimum_Points,0), @Maximumlimit = ISNULL(Maximum_Limit,0) from eshop_loyalty_redemption where User_ID = @ParentID            
            
set @Bill = CONVERT(int, ISNULL(@BIllAmount,0))            
select @EquivalentQuantity = ISNULL(EquivalentQuantity,0), @EquivalentCurrency = ISNULL(EquivalentCurrency,0)             
from eshop_loyalty_global_setting (nolock) where User_ID = @ParentID            
set @TotalPoint = (select isnull(TotalPoint,0) from eshop_cust_loyalty_total where CustomerID = @CustomerID and User_ID = @ParentID) 
if exists(select '*' from eshop_loyalty_rules (nolock) where User_ID = @ParentID and RuleName = 'Loyalty' and IsActive = 1)
begin  
--select     @TotalPoint return     
if (isnull(@TotalPoint,0) < isnull(@loyaltyPoint,0) )            
begin            
select 'Your Current Points are less than the Point you want to redeem' as Message, 0 as LoyaltyAmount            
return            
end            
            
            
if (isnull(@loyaltyPoint,0) < isnull(@MinimumPoint,0) )            
begin            
select 'Point are less than Minimum Limit to redeem.' as Message, 0 as LoyaltyAmount            
return            
end            
            
set @CurrentCurrency =  (isnull(@loyaltyPoint,0) * isnull(@EquivalentCurrency,0)) / isnull(@EquivalentQuantity,0)            
set @TotalRedeempercentage = (isnull(@CurrentCurrency,0) / isnull(@Bill,0) )*100 
           
if (isnull(@TotalRedeempercentage,0) > isnull(@Maximumlimit,0))            
begin            
set @CurrentCurrency = (isnull(@Maximumlimit,0) * isnull(@Bill,0)) / 100            
set @CustPoint = (isnull(@CurrentCurrency,0) *isnull(@EquivalentQuantity,0)) / isnull(@EquivalentCurrency,0)            
select 'Total Point redeem is equal to ' + CAST((isnull(@CustPoint,0)) as nvarchar) as Message, isnull(@CurrentCurrency,0) as LoyaltyAmount            
return            
end            
select 'Total Loyalty Currency equal to your Points is   ' as Message, isnull(@CurrentCurrency,0) as LoyaltyAmount            
end
else
select 'Loyalty Rule not applicable for you ' as Message, 0 as LoyaltyAmount         
end 


GO

/* ============================================================
   Procedure: [dbo].[eshop_check_Coupon_code]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_check_Coupon_code    
(    
@CouponCode VARCHAR(50)=null,                           
@ParentID BIGINT =null,                           
@CustomerID int,    
@BIllAmount VARCHAR(500)= null     
)    
as    
begin    
SELECT * INTO   #tempcoupon FROM   eshop_coupon AS ucs WHERE  ucs.parentid = @ParentID AND ucs.CouponName = @CouponCode      
and Status = 1    
declare @MobileNo VARCHAR(50)= null ,                           
    @EmailID VARCHAR(50) =null   ,@UserName Varchar(200)  
 set   @UserName = (Select UserName From Customers where CustomerID = @CustomerID)             
select @MobileNo = Mobile1, @EmailID = Email from Customers (nolock)  where CustomerID = @CustomerID and User_ID = @ParentId     
if not exists(select '*' from  Eshop_Coupon(nolock) where CouponName = @CouponCode and ParentID = @ParentID and Status = 1)    
begin    
select 'Not a Valid Coupon' as Message    
Return    
end    
if not exists(select '*' from  Eshop_Coupon(nolock) where CouponName = @CouponCode and ParentID = @ParentID     
   and GETDATE() between StartDate and ExpiryDate  and Status = 1)    
begin    
select 'Coupon Already Expired' as Message    
Return    
end     
if exists(select '*' from  Eshop_Coupon(nolock) where CouponName = @CouponCode and ParentID = @ParentID     
   and GETDATE() between StartDate and ExpiryDate  and Status = 1 and IsBillApplicability=1)    
begin    
if not exists(select '*' from  Eshop_Coupon(nolock) where CouponName = @CouponCode and ParentID = @ParentID     
   and GETDATE() between StartDate and ExpiryDate  and Status = 1     
   and @BIllAmount between minbillamount and MaxBillAmount)    
begin    
Declare @MinBillAmount numeric(18,2)    
Declare @MaxBillAmount numeric(18,2)    
select @MinBillAmount = MinBillAmount, @MaxBillAmount = MaxBillAmount from  Eshop_Coupon(nolock) where CouponName = @CouponCode and ParentID = @ParentID     
   and GETDATE() between StartDate and ExpiryDate  and Status = 1    
select 'Coupon is applicable only on bill amount between ' + CAST((@MinBillAmount) as nvarchar) + ' and ' + CAST((@MaxBillAmount) as nvarchar) as Message    
Return    
end     
end    
if exists(select 1 from Eshop_Coupon(nolock) where CouponName = @CouponCode and ParentID = @ParentID     
   and GETDATE() between StartDate and ExpiryDate  and ISProductApplicability = 1)
   begin    
if exists(select 1 from eshop_coupon_product p     
   join eshop_cart_items t on p.ProductName=t.ProductName      
   and t.Quantity  between p.minqty and p.maxqty join #tempcoupon tc on p.CouponID=tc.CouponID   
 where t.UserName = @UserName)                              
    begin                  
    Goto Checksegment                         
    end                        
    else                         
    begin                         
    Select 'Coupon is not applicable for the products in cart'  as Message                       
    Return                         
    end
	end
	else
	begin
	Goto Checksegment                         
    end     
end    
    
CheckSegment:               
if exists(select 1 from #tempcoupon where ISSearchApplicability =1)                      
begin          
declare @mediumtype nvarchar(20)= (select mediumtype from #tempcoupon)          
SELECT ROW_NUMBER()Over(Order by Ucm.couponID,Ucm.ParentID) AS Id,             
       Ucm.couponID,                                                
                   Ucm.ParentID,                                                
                   A.[value]  AS IncludeSearches,                                                
                   AGL.[value]         AS IncludeList,                                                
                   EGL.[value]        AS ExclusionsGroupList,                                                
                   case when ucm.Mediumtype = 'Email' then '' else Ucm.ExcludeMobile end as ExcludeMobile,          
                   case when ucm.Mediumtype = 'Mobile' then '' else Ucm.Excludemail end as Excludemail,                                          E.[value]           AS Exclusions,                                                
                   case when ucm.Mediumtype = 'Email' then @EmailID else Ucm.ExcludeMobile end as IncludeMail,          
                   case when ucm.Mediumtype = 'Mobile' then @MobileNo else Ucm.Excludemail end as IncludeMobile           
            INTO #temptemplate             
            FROM   #tempcoupon Ucm   (nolock)                                                 
            OUTER APPLY Dbo.Fn_split(Ucm.IncludeSearches, '#') AS A           
   OUTER APPLY Dbo.Fn_split(Ucm.IncludeList, '#') AS AGL          
   OUTER APPLY Dbo.Fn_split(Ucm.ExcludeList, '#') AS  EGL           
   OUTER APPLY Dbo.Fn_split(Ucm.ExcludeSearch, '#') AS E           
--Check medium & Check if contact details are in exclusions--          
if @mediumtype='Both' and exists(select 'x' from #temptemplate outer apply dbo.Fn_split(ExcludeMobile, ',')  AS fs outer apply dbo.Fn_split(Excludemail, ',') as fsmail  WHERE  fs.[value]=@MobileNo or fsmail.[value]=@EmailID)            
begin          
Select 'Oops! Coupon is not applicable to you'  as Message                  
Return                          
end          
else if exists(select 'x' from #temptemplate outer apply dbo.Fn_split(ExcludeMobile, ',')  AS fs outer apply dbo.Fn_split(Excludemail, ',') as fsmail  WHERE  fs.[value]=@MobileNo and fsmail.[value]=@EmailID)                         
begin          
Select 'Oops! Coupon is not applicable to you'  as Message                  
Return                             
end    
else          
begin            
CREATE TABLE #temptablesearchapp                                
     (                                          
      campaignid             BIGINT,                                          
      searchid               BIGINT,                                          
      parentid         BIGINT,           
      userid           bigint,                                         
      personname             NVARCHAR(200),                                          
      companyname            NVARCHAR(200),                                          
      mobileno               NVARCHAR(200),                                          
      mobileno1              NVARCHAR(200),                                          
      mobileno2              NVARCHAR(200),                                          
      emailid                NVARCHAR(200),                                          
      emailid1               NVARCHAR(200),                                          
      emailid2               NVARCHAR(200),                                          
      city                   NVARCHAR(200),                                          
      STATE                  NVARCHAR(200),                                          
      country                NVARCHAR(200),                                          
      countrycode            NVARCHAR(200),                                          
      pincode                NVARCHAR(200),                                          
      residentialaddress     NVARCHAR(200),                                          
      officeaddress          NVARCHAR(200),                                          
      sourcename       NVARCHAR(200),                                          
      mediumname             NVARCHAR(200),                                          
      campaignname           NVARCHAR(200),                                          
      initialremarks         NVARCHAR(1000)                                          
     )                                          
                                        
     CREATE TABLE #temptablesearchexc                                          
     (                                          
      campaignid             BIGINT,                                          
      searchid               BIGINT,                                          
      parentid               BIGINT,          
      userid     bigint,                           
      personname             NVARCHAR(200),                                          
      companyname            NVARCHAR(200),                        
      mobileno               NVARCHAR(200),                                          
      mobileno1              NVARCHAR(200),                                  
      mobileno2              NVARCHAR(200),                                          
      emailid            NVARCHAR(200),                                          
      emailid1               NVARCHAR(200),                                          
      emailid2               NVARCHAR(200),                   
      city                   NVARCHAR(200),                                          
      STATE                  NVARCHAR(200),                                          
      country                NVARCHAR(200),                                          
      countrycode            NVARCHAR(200),                                          
      pincode                NVARCHAR(200),                                          
      residentialaddress     NVARCHAR(200),                                          
      officeaddress          NVARCHAR(200),                                          
      sourcename             NVARCHAR(200),                                          
      mediumname             NVARCHAR(200),                                        
      campaignname           NVARCHAR(200),                                          
      initialremarks         NVARCHAR(1000)                           
     )                                          
INSERT INTO #temptablesearchapp(mobileno,emailid,ParentID  )                                                
Select ISNULL(Usd.MobileNumber, ''),ISNULL(usd.EmailID,''),Tt.ParentID            
FROM  #temptemplate TT          
Inner join  Usersearchdata AS Usd  (nolock)  on Usd.ParentID =  Tt.ParentID AND Usd.ImportedListID = Tt.IncludeList and Tt.IncludeList is not null           
          
INSERT INTO #temptablesearchexc (mobileno,emailID,ParentID  )                    
SELECT ISNULL(Usd.Mobilenumber, ''),usd.emailID, Tt.ParentID FROM #temptemplate TT   Inner join   Usersearchdata AS Usd  (nolock) on Usd.ParentID =  Tt.ParentID AND Usd.ImportedListID = Tt.ExclusionsGroupList and Tt.ExclusionsGroupList is not null        
 
   
           
 --check if user is included in exclusion list till now          
if @mediumtype ='both' and exists(select 1 from #temptablesearchexc ttse where isnull(mobileno,0)=@MobileNo or isnull(emailid,0)=@EmailID)               
begin          
Select 'Oops! Coupon is not applicable to you'  as Message                  
Return          
end          
if @mediumtype='mobile' and exists(select 1 from #temptablesearchexc ttse where isnull(mobileno,0)=@MobileNo)               
begin          
Select 'Oops! Coupon is not applicable to you'  as Message                  
Return         
end          
if @mediumtype='email' and exists(select 1 from #temptablesearchexc ttse where isnull(emailid,0)=@EmailID)               
begin          
Select 'Oops! Coupon is not applicable to you'  as Message                  
Return          
end          
          
DECLARE @CountCampaign     INT = (Select MAX(Id) from #temptemplate)                                               
DECLARE @Count INT = 1                                                                                                            
          
WHILE (@Count <= @CountCampaign) or not exists(select 1 from #temptablesearchexc ttse where (isnull(mobileno,0)= @MobileNo         
  or isnull(mobileno1,0)= @MobileNo or isnull(mobileno2,0)= @MobileNo) and (isnull(emailid,0)=@EmailID         
   or isnull(emailid1,0)=@EmailID or isnull(emailid2,0)=@EmailID))          
BEGIN                                          
DECLARE @Applicability BIGINT,@Exclusions BIGINT          
Select @Applicability = tt.IncludeSearches,@Exclusions = tt.Exclusions from #temptemplate tt Where Id = @Count           
If(@Applicability is not null)          
Begin                                         
INSERT INTO #temptablesearchapp                                                
       (                                               
      PersonName,                  
      CompanyName,                                                
      MobileNo,                                                
      MobileNo1,                                                
      MobileNo2,                                                
      EmailID,                                                
      EmailID1,                         
      EmailID2,                                                
      Country,                                                
      [STATE],                      
      City,                                          
      PinCode,                               
      ResidentialAddress,                                                
      OfficeAddress,                                                
      SourceName,                                                
      MediumName,                                                
      CampaignName,                                                
      InitialRemarks,                                                
      SearchID,                                                
      ParentID,                                                
      CampaignID                                                
       )                                                
     EXEC Usp_executeusersearch                                                
       @ParentId,                                                
       @Applicability,                                                
       @Campaignid=NULL          
                 
           End                                           
if(@Exclusions is not null)          
Begin                                           
INSERT INTO #temptablesearchexc                                                
           (                                                
             PersonName,                                                
             CompanyName,                                                
             MobileNo,                                                
             MobileNo1,                                                
       MobileNo2,                                                
             EmailID,                                                
             EmailID1,                                                
             EmailID2,                                                
             Country,                                                
             [STATE],                                                
             City,                                                
             PinCode,                                                
             ResidentialAddress,                                                
             OfficeAddress,                                                
             SourceName,                                                
             MediumName,                                                
             CampaignName,                                                
             InitialRemarks,                                                
             SearchID,                                                
             ParentID,                                                
             CampaignID                                                
    )                                                
         EXEC Usp_executeusersearch                                                
              @Parentid,                                                
              @Exclusions,                                                
              @Campaignid=NULL          
              
    END          
SET @Count = @Count+1          
END               
if (@mediumtype='mobile' or @mediumtype='both') and exists(select 1 from #temptablesearchexc ttse         
where (isnull(mobileno,0)= @MobileNo or isnull(mobileno1,0)= @MobileNo or isnull(mobileno2,0)= @MobileNo))          
begin          
Select 'Oops! Coupon is not applicable to you'  as Message       
Return        
end           
if (@mediumtype='email' or @mediumtype='both') and exists(select 1 from #temptablesearchexc ttse         
where (isnull(emailid,0)=@EmailID or isnull(emailid1,0)=@EmailID or isnull(emailid2,0)=@EmailID))          
begin          
Select 'Oops! Coupon is not applicable to you'  as Message                  
Return         
end     
end    
end    


GO

