/* ============================================================
   Procedure: [dbo].[eshop_check_loyalty_custwise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_check_loyalty_custwise    
(    
@CustomerID int,    
@User_ID bigint    
)    
as    
begin    
Declare @DateofBirth date , @CurrentDate date, @CurrentMonth varchar(30), @Currentday int, @Month varchar(30), @Day int    
declare @CustomerName varchar(500), @CustPoint int, @CustCurrency int, @EquiQuantity int, @EquiCurrency int,     
@LastOrderDate date    
set @CurrentDate = getdate()    
set @Currentday = Datename(dd,@CurrentDate)    
set @CurrentMonth = Datename(mm,@CurrentDate)    
set @LastOrderDate = (select max(OrderDate) from [Order] where CustomerID = @CustomerID and User_ID = @User_ID)    
select @EquiQuantity = EquivalentQuantity, @EquiCurrency = EquivalentCurrency from eshop_loyalty_global_setting       
where User_ID = @User_ID      
set @DateofBirth = (select DateofBirth from Customers where CustomerID = @CustomerID and User_ID = @User_ID)    
set @CustomerName = (select First_Name + ' '+ Last_Name from Customers where CustomerID = @CustomerID and User_ID = @User_ID)    
set @Day = Datename(dd,@DateofBirth)    
set @Month = Datename(mm,@DateofBirth)    
    
if exists (select '*' from eshop_loyalty_rules(nolock) where RuleName = 'Birthday' and User_ID = @User_ID and IsActive = 1)    
begin    
set @CustPoint = (select PointCount from eshop_loyalty_rules WHERE User_ID = @User_ID         
     and RuleName = 'Birthday' and IsActive = 1)        
set @CustCurrency = (@CustPoint * @EquiCurrency) / @EquiQuantity      
if (@Currentday = @Day and @CurrentMonth = @Month)    
begin    
if not exists (select '*' from Eshop_Cust_Loyalty_Details (nolock) where CustomerName = @CustomerName and User_ID = @User_ID        
     and RuleName = 'Birthday' and CustomerID = @CustomerID )        
begin        
insert into Eshop_Cust_Loyalty_Details (CustomerName,Date,RuleName,Status,Points,User_ID, CustomerID)        
values (@CustomerName,getdate(),'Birthday','Credit',@CustPoint,@User_ID, @CustomerID)        
if exists(select '*' from eshop_cust_loyalty_total where CustomerName = @CustomerName and User_ID = @User_ID and CustomerID = @CustomerID)        
begin        
update eshop_cust_loyalty_total        
set TotalPoint = TotalPoint + @CustPoint, TotalCurrency = TotalCurrency +@CustCurrency        
where CustomerName = @CustomerName and User_ID = @User_ID  and CustomerID = @CustomerID       
end        
else        
insert into eshop_cust_loyalty_total(CustomerName,TotalPoint,TotalCurrency,User_ID, CustomerID)        
values(@CustomerName, @CustPoint, @CustCurrency, @User_ID, @CustomerID)        
end        
end    
end    
    
if exists (select '*' from eshop_loyalty_rules(nolock) where RuleName = 'Celebration' and User_ID = @User_ID and IsActive = 1)    
begin    
set @CustPoint = (select PointCount from eshop_loyalty_rules WHERE User_ID = @User_ID         
     and RuleName = 'Celebration' and IsActive = 1)     
set @Day = (select MDays from eshop_loyalty_rules WHERE User_ID = @User_ID         
     and RuleName = 'Celebration' and IsActive = 1)    
set @Month = (select Month from eshop_loyalty_rules WHERE User_ID = @User_ID         
     and RuleName = 'Celebration' and IsActive = 1)     
set @CustCurrency = (@CustPoint * @EquiCurrency) / @EquiQuantity      
if (@Currentday = @Day and @CurrentMonth = @Month)    
begin    
if not exists (select '*' from Eshop_Cust_Loyalty_Details (nolock) where CustomerName = @CustomerName and User_ID = @User_ID        
     and RuleName = 'Celebration' and CustomerID = @CustomerID  )        
begin        
insert into Eshop_Cust_Loyalty_Details (CustomerName,Date,RuleName,Status,Points,User_ID, CustomerID)        
values (@CustomerName,getdate(),'Celebration','Credit',@CustPoint,@User_ID,@CustomerID)        
if exists(select '*' from eshop_cust_loyalty_total where CustomerName = @CustomerName and User_ID = @User_ID and CustomerID = @CustomerID )        
begin        
update eshop_cust_loyalty_total        
set TotalPoint = TotalPoint + @CustPoint, TotalCurrency = TotalCurrency +@CustCurrency        
where CustomerName = @CustomerName and User_ID = @User_ID  and CustomerID = @CustomerID        
end        
else        
insert into eshop_cust_loyalty_total(CustomerName,TotalPoint,TotalCurrency,User_ID,CustomerID)        
values(@CustomerName, @CustPoint, @CustCurrency, @User_ID,@CustomerID)        
end        
end    
end    
if exists (select '*' from eshop_loyalty_rules(nolock) where RuleName = 'Expiration' and User_ID = @User_ID and IsActive = 1)    
begin    
if (DATEDIFF(dd,@CurrentDate, @LastOrderDate) > 365)    
begin    
set @CustPoint = (select TotalPoint from eshop_cust_loyalty_total WHERE CustomerName = @CustomerName and User_ID =@User_ID 
and CustomerID = @CustomerID)     
update eshop_cust_loyalty_total    
set TotalPoint = 0    
where CustomerName = @CustomerName and User_ID =@User_ID and CustomerID = @CustomerID    
insert into Eshop_Cust_Loyalty_Details (CustomerName,Date,RuleName,Status,Points,User_ID, CustomerID)     
values (@CustomerName,getdate(),'Expiration','Debit',@CustPoint,@User_ID,@CustomerID)    
end    
END    
end


GO

