/* ============================================================
   Procedure: [dbo].[eshop_check_product_quantity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- eshop_check_product_quantity 'Women Beige Wedges Sandal','m',0,212,33097
-- eshop_check_product_quantity 'Womens Black Bellies Sandals','L',0,267,33097
-- eshop_check_product_quantity 'Men casual shoes Sneakers For Men (Blue)','default',2,267,33097
CREATE   PROC eshop_check_product_quantity
(    
@ProductName varchar(150),    
@Variant varchar(150),    
@FulfillQuantity int,    
@OrderID int,  
@User_ID bigint   
)    
as    
begin    
if(@Variant = 'default')        
begin        
set @Variant = '';        
end     
declare @StockQuantity int , @TotalQuantity int , @FulfillQty int  
if (@Variant <> '')    
begin    
select @StockQuantity =  INVENTORY from Variant_detail where PRODUCTNAME = @ProductName      
and Variant = @Variant      
and User_ID = @User_ID    
end    
else    
select @StockQuantity =  UnitInStock from Products where Name = @ProductName     
and User_ID = @User_ID and Name not in (select ProductName from Variant_detail where ProductName = @ProductName       
   and User_ID = @User_ID)  
     
select @TotalQuantity = sum(Quantity) from OrderDetails (nolock) where OrderID = @OrderID and ProductName = @ProductName and isnull(Variant,'') = @Variant and User_ID = @User_ID  
select @FulfillQty = isnull(sum(FulfillQuantity),0) from Order_Fulfillment (nolock) where OrderNo = @OrderID and ProductName = @ProductName and Product_det = @Variant  
set @TotalQuantity = @TotalQuantity - @FulfillQty  
if(@FulfillQuantity > @StockQuantity)    
begin    
select 'Quantity in Stock in less than Fulfillment' as Message    
return    
end    
else if (@FulfillQuantity > @TotalQuantity)  
begin  
select 'Fulfill Quantity cannot be greater than Ordered Quantity' as Message   
end  
else    
begin    
select 'Ok'as Message    
end    
end 



GO

/* ============================================================
   Procedure: [dbo].[eshop_collection_criteria]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[eshop_collection_criteria]      
(      
@collectionid int,      
@searchvalue varchar(max),      
@conjunction varchar(20)      
)      
as      
begin  
if(@searchvalue = 'default')
begin
return
end   
if exists(select '*' from collection_criteria where collectionid = @collectionid)  
begin  
Delete from collection_criteria where collectionid = @collectionid   
end   
create table #temp123      
(columnname varchar(500))      
insert into #temp123      
select * from dbo.SplitString(@searchvalue,'|')      
DECLARE @delimiter VARCHAR(50)      
SET @delimiter='`'       
;WITH CTE AS      
(       
    SELECT      
        CAST('<M>' + REPLACE(columnname, @delimiter , '</M><M>') + '</M>' AS XML)       
        AS [columnname XML]      
    FROM  #temp123      
)      
insert into collection_criteria (collectionid,Op1,Operator,Op2,Conjunction,Active)      
SELECT @collectionid,      
     [columnname XML].value('/M[1]', 'varchar(50)') As Op1,      
     [columnname XML].value('/M[2]', 'varchar(50)') As Operator,      
     [columnname XML].value('/M[3]', 'varchar(50)') As Op2,      
  @conjunction,1        
FROM CTE      
drop table #temp123     
Delete from  collection_criteria where collectionid = @collectionid and Op1 = ''  
--select * from collection_criteria      
end 


GO

/* ============================================================
   Procedure: [dbo].[eshop_collection_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- eshop_collection_details 34,335       
CREATE   PROC [dbo].[eshop_collection_details]  --34,335      
(      
@collectionid int,      
@User_ID int      
)      
as      
begin      
declare @cccount int, @vcount int = 1, @Conjunction varchar(20), @search varchar(max), @Op1 varchar(100),      
@Op2 varchar(100),@Operator varchar(100)      
declare @SQL varchar(max)      
      
set @cccount = (select count(*) from collection_criteria where collectionid = @collectionid and Active = 1)      
      
set @Conjunction = (select distinct Conjunction from collection_criteria where collectionid = @collectionid and Active = 1  
     AND Conjunction <> '')      
      
select Name,SupplierID,CategoryID,UnitPrice,OldPrice,Discount,UnitInStock,AltText,AddBadge,OfferTitle,OfferBadgeClass,LongDescription,CreatedDate into #Products from Products where 1 = 2      
      
(SELECT @Op1 = Op1,@Operator = Operator,@Op2 = Op2 FROM (SELECT Op1,replace(CASE  WHEN Operator = 'is equal to' THEN '=' WHEN Operator = 'is not equal to' THEN '!='      
WHEN Operator = 'is greater than' THEN '>' WHEN Operator = 'is less than' THEN '<' WHEN Operator = 'Starts with' THEN 'Starts'       
WHEN Operator = 'ends with' THEN 'ends' WHEN Operator = 'contains' THEN 'like' WHEN Operator = 'does not contain' THEN 'not like' end,'''','') Operator,Op2,ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber                        
FROM collection_criteria WHERE collectionid  = @collectionid ) as collection_criteria WHERE rownumber = @vcount)      
      
if (@Op1 = 'variant')      
begin      
set @search =  '''name in (select PRODUCTNAME from VARIANTS where V_VALUE''' +' '+ @Operator +CASE  WHEN  @Operator = 'like' THEN ' ''%'+@Op2+'%''' ELSE ''''+ @Op2 +''''END +')'+''''        
end      
else      
begin      
set @search = @Op1 +' '+ @Operator + CASE  WHEN @Operator = 'like' THEN ' ''%'+@Op2+'%''' ELSE ' '''+ @Op2+''''END +''       
end      
      
--set @search = exec(@SQL);      
      
set @vcount = 2      
set @Op1 = ''      
set @Operator = ''      
set @Op2 = ''      
      
While (@vcount <= @cccount)      
begin      
      
(SELECT @Op1 = Op1,@Operator = Operator,@Op2 = Op2 FROM (SELECT Op1,replace(CASE  WHEN Operator = 'is equal to' THEN '=' WHEN Operator = 'is not equal to' THEN '!='      
WHEN Operator = 'is greater than' THEN '>' WHEN Operator = 'is less than' THEN '<' WHEN Operator = 'Starts with' THEN 'Starts'       
WHEN Operator = 'ends with' THEN 'ends' WHEN Operator = 'contains' THEN 'like' WHEN Operator = 'does not contain' THEN 'not like' end,'''','') Operator,Op2,ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber                        
FROM collection_criteria WHERE collectionid  = @collectionid ) as collection_criteria WHERE rownumber = @vcount)      
      
if (@Op1 = 'variant')      
begin      
set @search = @search + ' '+ @Conjunction + ' '+  '''name in (select PRODUCTNAME from VARIANTS where V_VALUE''' +' '+ @Operator +CASE  WHEN  @Operator = 'like' THEN ' ''%'+@Op2+'%''' ELSE ''''+ @Op2 +''''END +')'+''''        
end      
else      
begin      
set @search = @search + ' '+ @Conjunction + ' '+  @Op1 +' '+ @Operator + CASE  WHEN @Operator = 'like' THEN ' ''%'+@Op2+'%''' ELSE ' '''+ @Op2+''''END +''       
end      
      
      
set @vcount = @vcount + 1      
end      
      
set @SQL = 'select * from Products where isActive = 1 and User_ID = '+ Convert(varchar(10),@User_ID)+' and  '+ @search      
      
exec (@SQL);      
      
      
end 


GO

/* ============================================================
   Procedure: [dbo].[eshop_collection_manual]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- eshop_collection_manual 15,33737      
CREATE   PROC [dbo].[eshop_collection_manual]       
(        
@collectionid int,        
@User_ID int        
)        
as        
begin       
CREATE TABLE #PRODUCT (PRODUCTID VARCHAR(50))      
INSERT INTO #PRODUCT       
select * from dbo.SplitString((SELECT  ProductID  from collection where id = @collectionid and isactive = 1),',')      
select * from Products where Name in (select ProductID from #PRODUCT)        
and User_ID = @User_ID and isActive = 1  
UNION ALL
select * from Products where ProductID in (select CAST(ProductID AS INT) from #PRODUCT)        
and User_ID = @User_ID and isActive = 1       
        
end 


GO

