/* ============================================================
   Procedure: [dbo].[eshop_confirm_delivery]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     
--eshop_confirm_delivery 5,'2019-10-27 15:45','Test','Bellies For Women', 'Black','10/24/2019 19:22',1    
CREATE   PROC eshop_confirm_delivery    
(    
@OrderNo int,    
@DeliverDate datetime,    
@DeliverRemarks varchar(500),    
@ProductName varchar(150),    
@Product_det varchar(500),    
@ID int,    
@FulfillQuantity int    
)    
as    
begin    
    
if (@DeliverRemarks = 'blank')    
begin    
set @DeliverRemarks = ''    
end    
    
update Order_Fulfillment    
set DeliveryStatus = 1, DeliverDate = @DeliverDate, DeliverRemarks = @DeliverRemarks    
where OrderNo = @OrderNo and ProductName = @ProductName and Product_det = @Product_det    
and ID = @ID and FulfillQuantity = @FulfillQuantity    
  
UPDATE [Order]  
set Deliver = 1, DeliveryDate = @DeliverDate  
where OrderID = @OrderNo  
       
end


GO

