/* ============================================================
   Procedure: [dbo].[eshop_create_customer]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[eshop_create_customer]           
(            
@First_Name varchar(50),            
@Last_Name varchar(50),            
@UserName varchar(50),            
@Password varchar(50),            
@Email varchar(50),            
@Mobile1 varchar(50),            
@User_ID bigint            
)            
as            
begin         
declare @CustomerID int     
insert into Customers(First_Name,Last_Name,UserName,Password,Email, Mobile1, User_ID, Created)            
values(@First_Name,@Last_Name,@UserName,@Password,@Email,@Mobile1,@User_ID, getdate())      
set @CustomerID = SCOPE_IDENTITY()
--(select CustomerID from Customers (nolock) where UserName = @UserName and User_ID = @User_ID)        
        
declare @CustomerName varchar(500), @CustPoint int, @CustCurrency int, @EquiQuantity int, @EquiCurrency int        
set @CustomerName = @First_Name+' '+@Last_Name        
select @EquiQuantity = EquivalentQuantity, @EquiCurrency = EquivalentCurrency from eshop_loyalty_global_setting where User_ID = @User_ID        
IF EXISTS(SELECT '*' FROM eshop_loyalty_rules WHERE User_ID = @User_ID and RuleName = 'Sign up' and IsActive = 1)        
begin        
set @CustPoint = (select PointCount from eshop_loyalty_rules WHERE User_ID = @User_ID         
     and RuleName = 'Sign up' and IsActive = 1)        
set @CustCurrency = (@CustPoint * @EquiCurrency) / @EquiQuantity        
if not exists (select '*' from Eshop_Cust_Loyalty_Details (nolock) where CustomerName = @CustomerName and User_ID = @User_ID        
     and RuleName = 'Sign up' and CustomerID = @CustomerID )        
begin        
insert into Eshop_Cust_Loyalty_Details (CustomerName,Date,RuleName,Status,Points,User_ID,CustomerID)        
values (@CustomerName,getdate(),'Sign up','Credit',@CustPoint,@User_ID,@CustomerID)        
if exists(select '*' from eshop_cust_loyalty_total where CustomerName = @CustomerName and User_ID = @User_ID and CustomerID = @CustomerID)        
begin        
update eshop_cust_loyalty_total        
set TotalPoint = TotalPoint + @CustPoint, TotalCurrency = TotalCurrency +@CustCurrency        
where CustomerName = @CustomerName and User_ID = @User_ID  and CustomerID = @CustomerID  
end        
else        
insert into eshop_cust_loyalty_total(CustomerName,TotalPoint,TotalCurrency,User_ID,CustomerID)        
values(@CustomerName, @CustPoint, @CustCurrency, @User_ID,@CustomerID)        
end        
end        
            
end


GO

