@TransactionID varchar(100),                    
@Remarks varchar(500),                    
@StageDate datetime,                  
@ReturnRequestNo VARCHAR(15)                    
)                    
as                    
begin                    
if(@Payment_Mode = 'blank')                    
begin                    
set @Payment_Mode = ''                    
end                    
if(@TransactionID = 'blank')                    
begin                    
set @TransactionID = ''                    
end                 
if(@Remarks = 'blank')                    
begin                    
set @Remarks = ''                    
end                   
if(@Reason = 'blank')                    
begin                    
set @Reason = ''                    
end                    
if not exists(select '*' from eshop_Order_Return_Stage (nolock) where ReturnID =  @ReturnID and OrderID = @OrderID and Stage_Name = @Stage_Name)                    
begin                    
insert into eshop_Order_Return_Stage(ReturnID,OrderID,Stage_Name,Reason,Expected_Outcome,User_ID,Order_Amount,Amount_Refunded,Payment_Mode,TransactionID,  Remarks, StageDate,ReturnRequestNo)                    
values(@ReturnID,@OrderID,@Stage_Name,@Reason,@Expected_Outcome,@User_ID,@Order_Amount,@Amount_Refunded,@Payment_Mode, @TransactionID,@Remarks,@StageDate, @ReturnRequestNo)                    
end                    
else                    
begin                    
update eshop_Order_Return_Stage                    
set Reason = @Reason,Expected_Outcome = @Expected_Outcome,Amount_Refunded = @Amount_Refunded,                    
  Payment_Mode = @Payment_Mode,TransactionID = @TransactionID ,Remarks = @Remarks,StageDate = @StageDate, ReturnRequestNo = @ReturnRequestNo                    
where ReturnID =  @ReturnID and OrderID = @OrderID and Stage_Name = @Stage_Name                    
end                    
                    
update a                    
set a.Order_Amount = b.Order_Amount                    
from eshop_Order_Return_Stage a, eshop_Order_Return_Stage b                    
where a.ReturnID = b.ReturnID                    
and a.OrderID = b.OrderID                    
and a.StageID -1 = b.StageID                    
                    
update eshop_Order_Return                    
set StageDate = @StageDate, Remarks = @Remarks, Reason = @Reason, Stage_Name = @Stage_Name                    
where ReturnID = @ReturnID               
              
if(@Stage_Name in ('Product Replaced','Product Exchanged'))          
begin              
Declare @NextOrderID int, @LastUpdateNumber int, @NextOrderNo varchar(100), @Prefix varchar(25), @Suffix varchar(25), @ShippingID int, @BillingID int, @PaymentID int, @ProductName varchar(150), @Rep_Variant varchar(100), @ProductID int, 
@OrderDetailsID int, @Variant varchar(150), @Quantity_Return int          
set @NextOrderID = (select max(OrderID)+1 from [Order](nolock))              
set @ShippingID = (select max(ShippingID)+ 1 from ShippingDetails (nolock))              
set @BillingID = (select max(BillingID)+ 1 from BillingDetails (nolock))              
set @PaymentID = (select max(PaymentID)+ 1 from Payment (nolock))              
set @ProductName = (select ProductName from eshop_Order_Return (nolock) where ReturnID = @ReturnID)          
set @Rep_Variant = (select Rep_Variant from eshop_Order_Return (nolock) where ReturnID = @ReturnID)          
set @Variant = (select Variant from eshop_Order_Return (nolock) where ReturnID = @ReturnID)          
set @ProductID = (select ProductID from Products (nolock) where Name = @ProductName and User_ID = @User_ID)          
set @OrderDetailsID = (select OrderDetailsID from eshop_Order_Return where ReturnID = @ReturnID)          
set @Quantity_Return = (select Quantity_Return from eshop_Order_Return where ReturnID = @ReturnID)          
          
select @Prefix = Prefix, @Suffix = Suffix, @LastUpdateNumber = LastUpdatedNumber from eshop_order_number_setting (nolock) where User_ID = @User_ID              
set @NextOrderNo = isnull(@Prefix,'') +'_'+Convert(varchar(10),@LastUpdateNumber)+'_'+isnull(@Suffix,'')+'_RE'               
              
insert into ShippingDetails(ShippingID,FirstName,LastName,Email,Mobile,Address,State_Name,City_Name,PostCode,CustomerID, OrderID, Country_Name)              
select @ShippingID,FirstName,LastName,Email,Mobile,Address,State_Name,City_Name,PostCode,CustomerID,@NextOrderID,              
Country_Name from ShippingDetails (nolock) where OrderID = @OrderID              
              
insert into BillingDetails(BillingID,FirstName,LastName,Email,Mobile,Address,State_Name,City_Name,PostCode,CustomerID, OrderID,         
Country_Name)              
select @BillingID,FirstName,LastName,Email,Mobile,Address,State_Name,City_Name,PostCode,CustomerID,@NextOrderID,              
Country_Name from BillingDetails (nolock) where OrderID = @OrderID              
              
insert into Payment(OrderNo,Total_Amount,Amount_Paid,PaymentDate,PaymentStatus,PaymentMode,PaymentType,User_ID)              
select @NextOrderID,0,'0.00',getdate(),@Stage_Name,PaymentMode,PaymentType,User_ID from Payment (nolock) where User_ID = @User_ID and OrderNo = @OrderID               
              
Insert into [Order](OrderID, CustomerID,PaymentID,ShippingID,Discount,Taxes,TotalAmount,isCompleted,OrderDate,DIspatched, DispatchedDate, Shipped,ShippingDate,Deliver,DeliveryDate,Notes,CancelOrder,User_ID,CustomerName,PaymentDetails, fulfillmentdetails
,OrderNo)              
select @NextOrderID,CustomerID,@PaymentID,@ShippingID,0,0,0,0,getdate(),0, DispatchedDate, 0, ShippingDate,0,DeliveryDate,@Stage_Name+'-'+ isnull(OrderNo,Convert(varchar(10),@OrderID)),0,User_ID, CustomerName, PaymentDetails, 'Unfulfilled', @NextOrderNo from [Order] (nolock) where OrderID = @OrderID              
              
Insert into OrderDetails(OrderID,ProductID,UnitPrice,Quantity,Discount,TotalAmount,OrderDate,User_ID,ProductName,Variant, fulfillmentstatus,CancelOrder,ReturnOrder,OrderNo,ReturnDate,ExchangeDate)              
select @NextOrderID,@ProductID,UnitPrice,Quantity,0,0,getdate(),User_ID,@ProductName,@Rep_Variant, 'Unfulfilled', 0,0,@NextOrderNo,getdate(),getdate() from OrderDetails (nolock) where OrderID = @OrderID and OrderDetailsID = @OrderDetailsID              
              
  EXEC eshop_update_last_number @User_ID            
            
update a              
set a.PaymentID = b.PaymentID              
from [Order] a, Payment b              
Where a.OrderID = b.OrderNo              
and a.User_ID = b.User_ID           
          
--Declare @TotalAmount decimal          
--Set @TotalAmount = (select sum(TotalAmount) from OrderDetails (nolock) where OrderID = @NextOrderID)            
          
--update [Order]          
--set TotalAmount = @TotalAmount          
--Where OrderID = @NextOrderID          
              
update a              
set a.ReturnDate = Dateadd(dd,isnull(b.Return_days,0),a.ReturnDate),              
 a.ExchangeDate = Dateadd(dd,isnull(b.Exchange_days,0),a.ExchangeDate)              
from OrderDetails a(nolock), Products b(nolock)              
where a.ProductID = b.ProductID              
and a.User_ID = b.User_ID              
              
Update eshop_Order_Return              
set Remarks = @NextOrderID              
where OrderID = @OrderID            
        
Declare @Balance int, @Balance1 int        
set @Balance = (select Balance from eshop_product_Invenory p(nolock) where ProductID = @ProductID and Variant = @Variant and User_ID = @User_ID and ModifiedDate = (select max(ModifiedDate) from eshop_product_Invenory (nolock) where ProductID = p.ProductID
  
    
      
 and Variant = p.Variant and User_ID = p.User_ID))        
set @Balance1 = @Balance + @Quantity_Return        
insert into eshop_product_Invenory(ProductID,ProductName,Variant,Quantity,ModifiedDate,ModifiedType,Remarks,User_ID,Vendor, Balance)        
select p.ProductID,p.ProductName,p.Variant,@Quantity_Return,getdate(),'Order Return',@Stage_Name,p.User_ID,p.Vendor, @Balance1 from  eshop_product_Invenory p(nolock) where ProductID = @ProductID and Variant = @Variant and User_ID = @User_ID and ModifiedDate = (select max(ModifiedDate) from eshop_product_Invenory (nolock) where ProductID = p.ProductID and Variant = p.Variant and User_ID = p.User_ID)        
        
        
        
          
end       
    
/*    
/*Start lead activity Lead cancels order */    
    
 Begin try    
    
    
   Declare @UserID_LDACTV bigint = @User_ID    
   Declare @ParentID_LDACTV bigint = @User_ID    
       
   Declare  @OrderID_LDACTV int =  @OrderID        
   Declare  @OrderNo_LDACTV nvarchar(50) = ''     
   Declare  @Orderdate_LDACTV nvarchar(50) = ''    
   Declare  @CustomerID_LDACTV int = 0      
   Declare @LeadID_LDACTV bigint =0     
       
   select @OrderNo_LDACTV = isnull(OrderNo,''), @Orderdate_LDACTV = isnull(OrderDate,''), @CustomerID_LDACTV = isnull(CustomerID,0)    
    from [Order] where OrderID =  @OrderID_LDACTV    
    
   --select  @ParentID_LDACTV = isnull(ParentID,0) from User_Detail where User_ID = @UserID_LDACTV     
    
   select @LeadID_LDACTV = isnull(LeadID,0) from Customers where CustomerID = @CustomerID_LDACTV    
    
    
 create table #tblEventDescrb    
     (    
    
       EVNT_Description nvarchar(max)     
     )    
    
  if( isnull(@LeadID_LDACTV,0) > 0)    
   Begin    
        
   insert into #tblEventDescrb    
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead cancels order',@UserID_LDACTV,'','',@LeadID_LDACTV,'',null    
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null    
   ,null,null,null,null,null,null,null,null,    
   @OrderNo_LDACTV,null,null,@Orderdate_LDACTV,null,null,0,null,null,null,null,null,null    
         
   declare @evntMessage nvarchar(max) = ''     
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb    
     
   if(@evntMessage <> '')    
   Begin    
   exec UspSaveLeadActivity @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage,    'Lead cancels order'    
      end    
    
   End      
    
   end try    
   Begin catch    
    
    exec usp_insertErrorInfo    
    
   End catch    
    
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence      
    Begin      
         DROP TABLE #tblEventDescrb      
    End      
           
    
   /*End lead activity Lead cancels order */    
    
    
  /*Start Lead activity  Leads return accepted or rejected */  
  
     
  Declare @StageName_1 nvarchar(500) = @Stage_Name   -- "Return Approved" , "Return Disapproved"  from procedures    
  
 if(@StageName_1 in('Return Approved' , 'Return Disapproved'))  
    Begin  
   
 Begin try  
       
   Declare @ReturnID_LDACTV_1 int = @ReturnID  
   Declare @ReturnReuqest_LDACTV_1 nvarchar(200) = '0'  
   Declare @OrderID_LDACTV_1 int = @OrderID   
   Declare @UserID_LDACTV_1 bigint = @User_ID  
   Declare @ParentID_LDACTV_1 bigint = @User_ID  
   Declare @OrderNo_LDACTV_1 nvarchar(500) = ''  
   --Declare @OrderDate_LDACTV nvarchar(50) = ''  
   Declare @CustID_LDACTV_1 int = 0  
   Declare @LeadID_LDACTV_1 bigint = 0  
         
 select @ReturnReuqest_LDACTV_1 = isnull(ReturnRequestNo,'') From [eshop_Order_Return] where ReturnID = @ReturnID_LDACTV_1  
  
    --Select @ParentID_LDACTV_1 = isnull(ParentID,0) from User_Detail where USER_ID = @UserID_LDACTV_1   
      
    Select top 1 @OrderNo_LDACTV_1 = isnull(OrderNo,''), @CustID_LDACTV_1 = isnull(CustomerID,0)  from [order] where OrderID = @OrderID_LDACTV_1  
  
 select top 1  @LeadID_LDACTV_1 = isnull(LeadID,0)  from Customers where CustomerID = @CustID_LDACTV_1  
    
  
  
  create table #tblEventDescrb_1  
     (  
  
       EVNT_Description nvarchar(max)   
     )  
  
  if( isnull(@LeadID_LDACTV_1,0) > 0)  
   Begin  
      
   insert into #tblEventDescrb_1  
      exec  Usp_EventTemplate_DynamicVarReplacement 'Leads return accepted or rejected',@UserID_LDACTV_1,'','',@LeadID_LDACTV_1,'',null  
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null  
   ,null,null,null,null,null,null,null,null,  
   @OrderNo_LDACTV_1,null,null,null,@ReturnReuqest_LDACTV_1,null,0,null,null,null,null,null,null  
       
   declare @evntMessage_1 nvarchar(max) = ''   
   select @evntMessage_1 = isnull( EVNT_Description,'') from #tblEventDescrb_1  
   
   if(@evntMessage_1 <> '')  
   Begin  
  
     if(@StageName_1 ='Return Approved')  
    Begin  
             set @evntMessage_1 = REPLACE(@evntMessage_1,'or rejected','')              
    End  
       else  
      Begin  
       set @evntMessage_1 = REPLACE(@evntMessage_1,'accepted or','')              
   End    
  
  
   exec UspSaveLeadActivity @LeadID_LDACTV_1,@UserID_LDACTV_1,@ParentID_LDACTV_1,@evntMessage_1,    'Leads return accepted or rejected'  
        
     
     
   end  
  
   End    
  
   End Try  
     
   Begin Catch  
  
    exec usp_InsertErrorInfo   
  
   End catch  
  
    IF OBJECT_ID('tempdb..#tblEventDescrb_1') IS NOT NULL -- Check for table existence    
   Begin    
        DROP TABLE #tblEventDescrb_1    
   End   
  
   End  
  
  
   /*End Lead activity  Leads return accepted or rejected */  
  */
  
  
  
  
                
end


