SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_create_policy
(
@User_Id			bigint,
@PolicyName			varchar(100),
@Description		varchar(max),
@Title				varchar(150),
@Meta_description	varchar(100),
@Meta_Tags			varchar(100),
@PageName			varchar(150)
)
as
begin
if exists(select '*' from eshop_Policy (nolock) where User_Id = @User_Id and PolicyName = @PolicyName)
begin
update eshop_Policy
set Description = @Description, Title = @Title, Meta_description = @Meta_description, Meta_Tags = @Meta_Tags,
PageName = @PageName
where User_Id = @User_Id and PolicyName = @PolicyName
end
else
begin
insert into eshop_policy (User_Id,PolicyName,Description,Title,Meta_description,Meta_Tags,PageName)
values(@User_Id,@PolicyName,@Description,@Title,@Meta_description,@Meta_Tags,@PageName)
end
end


