/* ============================================================
   Procedure: [dbo].[eshop_create_variant]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[eshop_create_variant]       
(        
@PRODUCTNAME varchar(150),        
@NAME varchar(100),        
@V_VALUE  varchar(500),        
@PRICE numeric(18,4),        
@StockKeepingUnit  varchar(100),        
@INVENTORY int,        
@Barcode  varchar(100),        
@User_ID int        
)        
as         
begin        
Declare @Date_Modified datetime        
set @Date_Modified = GETDATE();        
        
if (@StockKeepingUnit = 'default')        
begin        
set @StockKeepingUnit = '';        
end        
if (@Barcode = 'default')        
begin        
set @Barcode = '';        
end        
create table #temp123      
(columnname varchar(100))      
insert into #temp123   
select * from dbo.SplitString(@V_VALUE,'#')       
  
DECLARE @RCOUNT INT = 0, @I INT = 0  
SET @RCOUNT = (SELECT COUNT(*) FROM #temp123)  
WHILE (@RCOUNT > @I)  
BEGIN  
IF (@I = 0)
BEGIN
IF EXISTS (SELECT '*' FROM VARIANTS (NOLOCK) WHERE V_VALUE = ( SELECT columnname FROM (SELECT columnname,  
 ROW_NUMBER() OVER (ORDER BY columnname ASC) AS rownumber FROM #temp123) as VARIANTS WHERE rownumber = @I +1)  
 AND PRODUCTNAME = @PRODUCTNAME AND NAME = @NAME AND USER_ID = @User_ID)  
BEGIN  
UPDATE VARIANTS  
SET PRICE = @PRICE,StockKeepingUnit = @StockKeepingUnit,INVENTORY = @INVENTORY,Barcode = @Barcode,   
 Date_Modified = @Date_Modified  
WHERE V_VALUE = ( SELECT columnname FROM (SELECT columnname,  
 ROW_NUMBER() OVER (ORDER BY columnname ASC) AS rownumber FROM #temp123) as VARIANTS WHERE rownumber = @I +1)  
 AND PRODUCTNAME = @PRODUCTNAME AND NAME = @NAME AND USER_ID = @User_ID  
END  
ELSE  
BEGIN  
INSERT INTO VARIANTS (V_VALUE,PRODUCTNAME,NAME,PRICE,StockKeepingUnit,INVENTORY,Barcode,User_ID,Date_Modified)  
VALUES((SELECT columnname FROM (SELECT columnname,  
 ROW_NUMBER() OVER (ORDER BY columnname ASC) AS rownumber FROM #temp123) as VARIANTS WHERE rownumber = @I +1),  
 @PRODUCTNAME,@NAME,@PRICE,@StockKeepingUnit,@INVENTORY,@Barcode,@User_ID,@Date_Modified )  
END  
SET @I = @I + 1 
END
ELSE
BEGIN
IF EXISTS (SELECT '*' FROM VARIANTS (NOLOCK) WHERE V_VALUE = ( SELECT columnname FROM (SELECT columnname,  
 ROW_NUMBER() OVER (ORDER BY columnname ASC) AS rownumber FROM #temp123) as VARIANTS WHERE rownumber = @I +1)  
 AND PRODUCTNAME = @PRODUCTNAME AND NAME = @NAME AND USER_ID = @User_ID)  
BEGIN  
UPDATE VARIANTS  
SET PRICE = @PRICE,StockKeepingUnit = @StockKeepingUnit,INVENTORY = 0,Barcode = @Barcode,   
 Date_Modified = @Date_Modified  
WHERE V_VALUE = ( SELECT columnname FROM (SELECT columnname,  
 ROW_NUMBER() OVER (ORDER BY columnname ASC) AS rownumber FROM #temp123) as VARIANTS WHERE rownumber = @I +1)  
 AND PRODUCTNAME = @PRODUCTNAME AND NAME = @NAME AND USER_ID = @User_ID  
END  
ELSE  
BEGIN  
INSERT INTO VARIANTS (V_VALUE,PRODUCTNAME,NAME,PRICE,StockKeepingUnit,INVENTORY,Barcode,User_ID,Date_Modified)  
VALUES((SELECT columnname FROM (SELECT columnname,  
 ROW_NUMBER() OVER (ORDER BY columnname ASC) AS rownumber FROM #temp123) as VARIANTS WHERE rownumber = @I +1),  
 @PRODUCTNAME,@NAME,@PRICE,@StockKeepingUnit,0,@Barcode,@User_ID,@Date_Modified )  
END  
SET @I = @I + 1  
END
END
DROP TABLE #temp123        
end 


GO

/* ============================================================
   Procedure: [dbo].[eshop_create_variant1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- eshop_create_variant1 'TEST123','SIZE','S#M#L#XL','1000','default',10,'default',33097
CREATE   PROC [dbo].[eshop_create_variant1]     
(      
@PRODUCTNAME varchar(150),      
@NAME varchar(100),      
@V_VALUE  varchar(500),      
@PRICE numeric(18,4),      
@StockKeepingUnit  varchar(100),      
@INVENTORY int,      
@Barcode  varchar(100),      
@User_ID int      
)      
as       
begin      
Declare @Date_Modified datetime      
set @Date_Modified = GETDATE();      
      
if (@StockKeepingUnit = 'default')      
begin      
set @StockKeepingUnit = '';      
end      
if (@Barcode = 'default')      
begin      
set @Barcode = '';      
end      
create table #temp123    
(columnname varchar(100))    
insert into #temp123 
select * from dbo.SplitString(@V_VALUE,'#')     

DECLARE @RCOUNT INT = 0, @I INT = 0
SET @RCOUNT = (SELECT COUNT(*) FROM #temp123)
WHILE (@RCOUNT > @I)
BEGIN
IF EXISTS (SELECT '*' FROM VARIANTS (NOLOCK) WHERE V_VALUE = ( SELECT columnname FROM (SELECT columnname,
	ROW_NUMBER() OVER (ORDER BY columnname ASC) AS rownumber FROM #temp123) as VARIANTS WHERE rownumber = @I +1)
	AND PRODUCTNAME = @PRODUCTNAME AND NAME = @NAME AND USER_ID = @User_ID)
BEGIN
UPDATE VARIANTS
SET PRICE = @PRICE,StockKeepingUnit = @StockKeepingUnit,INVENTORY = @INVENTORY,Barcode = @Barcode, 
	Date_Modified = @Date_Modified
WHERE V_VALUE = ( SELECT columnname FROM (SELECT columnname,
	ROW_NUMBER() OVER (ORDER BY columnname ASC) AS rownumber FROM #temp123) as VARIANTS WHERE rownumber = @I +1)
	AND PRODUCTNAME = @PRODUCTNAME AND NAME = @NAME AND USER_ID = @User_ID
END
ELSE
BEGIN
INSERT INTO VARIANTS (V_VALUE,PRODUCTNAME,NAME,PRICE,StockKeepingUnit,INVENTORY,Barcode,User_ID,Date_Modified)
VALUES((SELECT columnname FROM (SELECT columnname,
	ROW_NUMBER() OVER (ORDER BY columnname ASC) AS rownumber FROM #temp123) as VARIANTS WHERE rownumber = @I +1),
	@PRODUCTNAME,@NAME,@PRICE,@StockKeepingUnit,@INVENTORY,@Barcode,@User_ID,@Date_Modified )
END
SET @I = @I + 1
END     

DROP TABLE #temp123      
end 


GO

/* ============================================================
   Procedure: [dbo].[eshop_customer_list]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_customer_list --33097
(
@User_ID bigint
)
as
begin

select c.CustomerID,c.First_Name+''+c.Last_Name as CustomerName, c.Created,
min(o.OrderDate) as FirstSale, Max(o.OrderDate) as LastSale, Sum(o.TotalAmount) as TotalBusiness,
sum(r.Amount_Refunded) as TotalRefund, count(distinct o.OrderID) as TotalOrder
from Customers c(nolock)
Left Outer join [Order] o (nolock)
on c.CustomerID = o.CustomerID
Left Outer join eshop_Order_Return_Stage r(nolock)
on o.OrderID = r.OrderID
and c.User_ID = r.User_ID
and r.Stage_Name in ('Fully Refunded','Partially Refunded')
Where c.User_ID = @User_ID
group by c.CustomerID,c.First_Name,c.Last_Name, c.Created
end



