/* ============================================================
   Procedure: [dbo].[eshop_delete_order]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_delete_order          
(          
@OrderID int          
)          
as          
begin         
        
Declare @RCount int, @Count int = 0    
set @RCount = (select count(*) from OrderDetails (nolock) where OrderID = @OrderID)    
Declare @ProductName Varchar(150), @Variant varchar(150), @Quantity int     
While (@RCount > @Count)    
begin     
select @ProductName = ProductName, @Variant = Variant from OrderDetails (nolock)     
where OrderID = @OrderID    
set @ProductName = (SELECT ProductName FROM (SELECT ProductName,ROW_NUMBER() OVER (ORDER BY OrderDetailsID ASC) AS rownumber      FROM OrderDetails where OrderID = @OrderID) as VARIANTS WHERE rownumber = 1)    
set @Variant = (SELECT Variant FROM (SELECT Variant,ROW_NUMBER() OVER (ORDER BY OrderDetailsID ASC) AS rownumber   
    FROM OrderDetails where OrderID = @OrderID) as VARIANTS WHERE rownumber = 1)    
     
if exists(select '*' from Order_Fulfillment (nolock) where OrderNo = @OrderID)    
begin    
if(@Variant <> '')    
begin    
update a    
set a.INVENTORY = a.INVENTORY + b.FulfillQuantity    
from Variant_detail a (nolock) inner join Order_Fulfillment b(nolock)    
on a.PRODUCTNAME = b.ProductName    
and a.Variant = b.Product_det    
where a.PRODUCTNAME = @ProductName    
and a.Variant = @Variant    
and b.OrderNo = @OrderID    
and a.User_ID = (Select User_ID from [Order] where OrderID = @OrderID)    
end    
else    
begin    
update a    
set a.UnitInStock = a.UnitInStock + b.FulfillQuantity    
from Products a(nolock) inner join Order_Fulfillment b(nolock)    
on a.Name = b.ProductName    
and b.Product_det = ''    
Where a.Name  = @ProductName    
and a.Name not in (select ProductName from Variant_detail where ProductName = @ProductName     
   and User_ID = (Select User_ID from [Order] where OrderID = @OrderID))    
and b.OrderNo = @OrderID    
and a.User_ID = (Select User_ID from [Order] where OrderID = @OrderID)    
end    
end    
set @Count = @Count +1    
end       


declare @user_id bigint,@leadid bigint,@customerid bigint,@orderno nvarchar(100),@orderdate date
select @user_id=User_ID,@customerid=CustomerID,@orderno=OrderNo,@orderdate=cast(OrderDate as date) from [order](nolock) where orderid=@OrderID
select @leadid=leadid from customers (nolock) where customerid=@customerid

 if @leadid is not null
 begin   
 Begin try      
 Declare @UserID_LDACTV bigint = @User_ID      
 Declare @ParentID_LDACTV bigint = @User_ID      
 Declare @LeadID_LDACTV bigint = @leadid      
 Declare @Domain_LDACTV nvarchar(500) = ''       
 Declare @UserNameOrLeadName nvarchar(500) = '' ,@leadname nvarchar(100)     
 --select @ParentID_LDACTV = isnull(parentid,0), @UserNameOrLeadName = isnull(User_login,'') from User_Detail where USER_ID = @UserID_LDACTV        
select @UserNameOrLeadName = isnull(User_login,'') from User_Detail where USER_ID = @UserID_LDACTV        
 select @Domain_LDACTV = isnull(Domain,'') from eshop_client_domain where USER_ID = @UserID_LDACTV         
 select @leadname=isnull(nullif(personname,''),cast(leadno as nvarchar)) from userleads(nolock) where id=@leadid     
      
  --create table #tblEventDescrb ( EVNT_Description nvarchar(max) )      
      
  if( isnull(@LeadID_LDACTV,0) > 0)      
   Begin      
          
   --insert into #tblEventDescrb      
   --exec  Usp_EventTemplate_DynamicVarReplacement 'Lead signs up in Eshop',@UserID_LDACTV,'','',@LeadID_LDACTV,'',null      
   --,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null      
   --,null,null,null,null,@Domain_LDACTV,@UserNameOrLeadName,null,null,      
   --null,null,null,null,null,null,0,null,null,null,null,null,null      
           
--select * from ActivityMaster where eventtype='eshop'
   declare @evntMessage nvarchar(max) = @leadname+'''s order no '+cast(@orderno as nvarchar) +' placed on '+cast(@orderdate as nvarchar(20))+' is cancelled.'       
   --select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb      
       
   if(@evntMessage <> '')      
   Begin      
      
     exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage, 'Lead cancels order','Order',@orderid      
      
   end      
      
   End        
      
   end try      
   Begin catch      
      
     exec usp_InsertErrorInfo      
      
   End catch      
      
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence        
   Begin        
        DROP TABLE #tblEventDescrb        
   End        
end

          
Update[Order]       
set CancelOrder = 1      
where  OrderID = @OrderID       
      
