from Variant_detail a (nolock) inner join Order_Fulfillment b(nolock)
on a.PRODUCTNAME = b.ProductName
and a.Variant = b.Product_det
where a.PRODUCTNAME = @ProductName
and a.Variant = @Variant
and b.OrderNo = @OrderID
and a.User_ID = (Select User_ID from [Order] where OrderID = @OrderID)
end
else
begin
update a
set a.UnitInStock = a.UnitInStock + b.FulfillQuantity
from Products a(nolock) inner join Order_Fulfillment b(nolock)
on a.Name = b.ProductName
and b.Product_det = ''
Where a.Name  = @ProductName
and a.Name not in (select ProductName from Variant_detail where ProductName = @ProductName 
			and User_ID = (Select User_ID from [Order] where OrderID = @OrderID))
