/* ============================================================
   Procedure: [dbo].[eshop_edit_cust_address]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_edit_cust_address  
 @CustomerID   INT,   
 @First_Name   VARCHAR(50),   
 @Last_Name    VARCHAR(50),   
 @Country_Name VARCHAR(50),   
 @State_Name   VARCHAR(50),   
 @City_Name    VARCHAR(50),   
 @PostalCode   VARCHAR(50),   
 @EMail        VARCHAR(50),   
 @Mobile       VARCHAR(50),   
 @Address      VARCHAR(50),   
 @ID           INT,   
 @isdefault    BIT  ,
 @AddressType VARCHAR(50)
AS  
    BEGIN  
        IF(@Country_Name = 'default')  
            BEGIN  
                SET @Country_Name = '';  
        END;  
        IF(@State_Name = 'default')  
            BEGIN  
                SET @State_Name = '';  
        END;  
        IF(@City_Name = 'default')  
            BEGIN  
                SET @City_Name = '';  
        END;  
        IF(@isdefault = 1)  
            BEGIN  
                UPDATE Cust_Address  
                  SET   
                      isdefault = 0  
                WHERE CustomerID = @CustomerID;  
        END;  
        IF(@ID = 0)  
            BEGIN  
                INSERT INTO Cust_Address (First_Name, Last_Name, Country, State, City, PostalCode, EMail, Mobile, Address, isdefault, CustomerID, AddressType)  
     VALUES ( @First_Name, @Last_Name, @Country_Name, @State_Name, @City_Name, @PostalCode, @EMail, @Mobile, @Address,@isdefault, @CustomerID, @AddressType);  
   END;  
        ELSE  
            BEGIN  
                UPDATE Cust_Address  
                  SET   
                      First_Name = @First_Name,   
                      Last_Name = @Last_Name,   
                      Country = @Country_Name,   
                      State = @State_Name,   
                      City = @City_Name,   
                      PostalCode = @PostalCode,   
                      EMail = @EMail,   
                      Mobile = @Mobile,   
                      Address = @Address,   
                      isdefault = @isdefault  
      WHERE CustomerID = @CustomerID  
         AND ID = @ID;  
   END;  
    END;  


