/* ============================================================
   Procedure: [dbo].[eshop_edit_order_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_edit_order_details  
(  
@OrderDetailsID int,  
@OrderID int,  
@UnitPrice decimal(18,0),  
@Quantity int,  
@TotalAmount decimal(18,0)  
)  
as  
begin  
  
update OrderDetails  
set Quantity = @Quantity, TotalAmount = (@Quantity * @UnitPrice), OrderDate = getdate()  
where OrderDetailsID = @OrderDetailsID and OrderID = @OrderID  
  
declare @grandtotal int  
set @grandtotal = (select sum(TotalAmount) from OrderDetails (nolock) where OrderID = @OrderID)  
update [Order]  
set TotalAmount = @grandtotal  
where OrderID = @OrderID  


 /*Start Lead Activity  Lead placed order */
       
 Begin try

	Declare @OrderID_LDACTV Int = @OrderID
	Declare @OrderDetailsID_LDACTV Int = @OrderDetailsID
	
	Declare @UserID_LDACTV Bigint = 0
	Declare @CustID_LDACTV int = 0
	Declare @LeadID_LDACTV Bigint = 0
    Declare @PaymentID_LDACTV int = 0
	Declare @PaymentMode_LDACTV nvarchar(100) 
	Declare @OrderNo_LDACTV nvarchar(100) = ''
	Declare @TotalAmount_LDACTV decimal(18,0) = @TotalAmount 
	Declare @Quantity_LDACTV int = @Quantity 
	
	Declare @ParentID_LDACTV bigint = 0 
	


    Select  @OrderNo_LDACTV = isnull(OrderNo,''), @CustID_LDACTV = isnull(CustomerID,0),@PaymentID_LDACTV = ISNULL(PaymentID,0)  from [Order] where OrderID = @OrderID_LDACTV     
	Select @PaymentMode_LDACTV = ISNULL(PaymentMode,'') from Payment where PaymentID = @PaymentID_LDACTV
	select @LeadID_LDACTV = ISNULL(LeadID,0),@UserID_LDACTV = ISNULL(USER_ID,0)  from Customers where CustomerID = @CustID_LDACTV 
	
	select  @ParentID_LDACTV = isnull(ParentID,0) from User_Detail where User_ID = @UserID_LDACTV
	


 create table #tblEventDescrb
   (
     EVNT_Description nvarchar(max) 
   )

  if( isnull(@LeadID_LDACTV,0) > 0)
   Begin
    
	

	  insert into #tblEventDescrb
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead placed order',@UserID_LDACTV,'','',@LeadID_LDACTV,'',null
	  ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null
	  ,null,null,null,null,null,null,null,@PaymentMode_LDACTV,
	  @OrderNo_LDACTV,@Quantity_LDACTV,@TotalAmount_LDACTV,null,null,null,0,null,null,null,null,null,null
		   
	  declare @evntMessage nvarchar(max) = '' 
	  select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb
	
	  if(@evntMessage <> '')
	  Begin
	  exec UspSaveLeadActivity @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage,
	  'Lead placed order'
	  end

   End  

   End try

   Begin catch

     exec usp_insertErrorInfo

   End catch


    IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence  
   Begin  
        DROP TABLE #tblEventDescrb  
   End  


   /*End  Lead Activity  Lead placed order */


  
end


GO

/* ============================================================
   Procedure: [dbo].[eshop_edit_variant]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[eshop_edit_variant]               
(                
@productname varchar(150),                
@name varchar(100),                
@v_value varchar(500),                
@PRICE decimal(18,0),                
@StockKeepingUnit varchar(100),                
@inventory int,                
@barcode  varchar(100) ,              
@User_ID int               
)                
as                
begin           
          
DECLARE @V_NAME1 varchar(100)          
DECLARE @V_NAME2 VARCHAR(100)          
DECLARE @V_NAME3 VARCHAR(100)          
        
if (@StockKeepingUnit = 'default')    
begin    
set @StockKeepingUnit = ''    
end    
if (@barcode = 'default')    
begin    
set @barcode = ''    
end    
create table #temp123      
(columnname varchar(100))      
insert into #temp123   
select * from dbo.SplitString(@V_VALUE,'#')     
Declare @ProductID int , @Vendor varchar(100) 
set @ProductID = (select ProductID from Products (Nolock) where Name = @productname AND USER_ID = @User_ID)  
set @Vendor = (select CompanyName from Suppliers (nolock) where User_ID = @User_ID and SupplierID = (select SupplierID from Products (nolock) where ProductID = @ProductID and User_ID = @User_ID))  
          
UPDATE Variant_detail  
SET  PRICE = @PRICE,  
StockKeepingUnit = @StockKeepingUnit,  
INVENTORY = @inventory,  
Barcode = @barcode,  
Date_Modified = getdate()  
WHERE PRODUCTNAME = @productname  
AND USER_ID = @User_ID  
AND Variant = @v_value  
  
  
UPDATE VARIANTS  
SET  PRICE = @PRICE,  
StockKeepingUnit = @StockKeepingUnit,  
INVENTORY = @inventory,  
Barcode = @barcode,  
Date_Modified = getdate()  
WHERE PRODUCTNAME = @productname  
AND USER_ID = @User_ID  
AND V_VALUE IN (SELECT * FROM #temp123)  
            
insert into eshop_product_Invenory (ProductID,ProductName,Variant,Quantity,ModifiedDate,ModifiedType,Remarks,User_ID, Balance, Vendor)  
Values(@ProductID, @productname,@v_value,@inventory,getdate(),'Add Variant','Add Variant',@User_ID,@inventory,@Vendor )            
            
declare @total int              
set @total = (select sum(INVENTORY) from Variant_detail where PRODUCTNAME = @productname  and User_ID = @User_ID)               
 
UPDATE Products              
SET UnitInStock = UnitInStock + @inventory              
WHERE Name = @ProductName AND User_ID = @User_ID 
              
UPDATE Variant_detail              
SET INVENTORY = INVENTORY + @inventory              
WHERE PRODUCTNAME = @ProductName AND Variant = @v_value AND User_ID = @User_ID     
DROP TABLE #temp123           
end 


GO

