CREATE   PROC eshop_get_billingaddress --49  
(  
@CustomerID bigint  
)  
as  
begin  

SELECT   
	max(ID) AS BillingID,
	First_Name  FirstName,
	Last_Name LastName,
	Email AS [Email],
	Mobile AS [Mobile],
	[Address] AS [Address],
	[State] AS State_Name,
	City AS City_Name,
	PostalCode AS PostCode,    
	Country AS Country_Name    
 FROM Cust_Address WHERE CustomerID = @CustomerID and  AddressType = 'BillingAddress'
 GROUP BY First_Name,  Last_Name, Email, Mobile, [Address], [State], City, PostalCode, Country  

--select min(BillingID) BillingID, FirstName,LastName,Email,Mobile,Address,State_Name,City_Name,PostCode,Country_Name    
--from BillingDetails where CustomerID =@CustomerID  
--group by FirstName,LastName,Email,Mobile,Address,State_Name,City_Name,PostCode,Country_Name  
end  


