/* ============================================================
   Procedure: [dbo].[eshop_get_city]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec eshop_get_city 'punjab', 'india'
--go


CREATE   PROC eshop_get_city
(
	@State_Name  VARCHAR(500), 
	@CountryName VARCHAR(500)
)
AS
BEGIN
    SELECT *
    FROM m_city1(NOLOCK) WHERE State_ID =  (
        SELECT State_ID
        FROM m_state1(NOLOCK) s
		INNER JOIN m_country1  c on s.Country_ID = c.Country_ID
			WHERE State_Name = @State_Name and c.Country_Name = @CountryName
    );
END;




