/* ============================================================
   Procedure: [dbo].[eshop_get_fulfillment_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_get_fulfillment_details --33097
(
@User_ID bigint
)
as
begin

select f.ID,f.FulfillmentDate,p.ProductID as TotalQuantity, f.OrderNo as OrderID,isnull(o.OrderNo,'') as DeliverRemarks, f.ProductName, f.Product_det, f.FulfillQuantity, f.ShippingCarier, f.TrackingNumber, f.TrackingURL
from Order_Fulfillment f(nolock)
inner join [Order] o(nolock)
on f.OrderNo = o.OrderID
inner join Products p(nolock)
on f.ProductName = p.Name
and o.User_ID = p.User_ID
where o.User_ID = @User_ID
Order by f.FulfillmentDate desc
end


GO

