Order by f.FulfillmentDate desc  
end

if(@searchcriteria = 'ShippedFrom')
begin  
select f.ID,f.FulfillmentDate,p.ProductID as TotalQuantity, f.OrderNo as OrderID,isnull(o.OrderNo,'') as DeliverRemarks, f.ProductName, f.Product_det, f.FulfillQuantity, f.ShippingCarier, f.TrackingNumber, f.TrackingURL  
