/* ============================================================
   Procedure: [dbo].[Eshop_Get_Inventory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].Eshop_Get_Inventory  --3,'42#43#44'                    
(                          
@ProductID Int,          
@Variant varchar(100)                       
)                          
as                          
begin              
IF @Variant = 'Blank'          
begin          
set @Variant = NULL          
end                              
select ProductName,Variant,Quantity,ModifiedDate,ModifiedType,Remarks, Vendor, Balance from   eshop_product_Invenory (nolock)
where ProductID  = @ProductID and Variant = isnull(@Variant,NULL)            
UNION all      
SELECT NAME ProductName, '' Variant,UnitInStock Quantity, CreatedDate ModifiedDate, 'Add Product' ModifiedType,'' Remarks, s.CompanyName as Vendor, UnitInStock   Balance  
FROM Products p(NOLOCK) inner join Suppliers s(nolock) on p.SupplierID = s.SupplierID and p.User_ID = s.User_ID    
WHERE ProductID NOT IN (SELECT ProductID FROM eshop_product_Invenory (NOLOCK) where ProductID  = @ProductID)    
and Name not in (select PRODUCTNAME from Variant_detail where User_ID = p.User_ID)      
and ProductID  = @ProductID    
union all    
select v.PRODUCTNAME as ProductName, v.Variant as Variant, v.INVENTORY as Quantity, v.Date_Modified as ModifiedDate,    
'Add Product' ModifiedType,'' Remarks, s.CompanyName as Vendor,v.INVENTORY as Balance      
from Variant_detail v(nolock) inner Join Products p(nolock)        
on v.PRODUCTNAME = p.Name        
and v.User_ID = p.User_ID     
inner join Suppliers s(nolock) on p.SupplierID = s.SupplierID and p.User_ID = s.User_ID    
where p.ProductID NOT IN (SELECT ProductID FROM eshop_product_Invenory (NOLOCK) where ProductID  = @ProductID)    
and p.ProductID  = @ProductID   
and v.Variant = isnull(@Variant,NULL)  
Order by ModifiedDate desc      
end 


GO

