CREATE   PROC eshop_get_inventory1
(
@ProductID int,
@User_ID bigint
)
as
begin

select a.ProductID, a.ProductName, c.Variant,c.PRICE,a.Balance as INVENTORY
from eshop_product_Invenory a(nolock) inner join Products b(nolock) on a.ProductID = b.ProductID and a.User_ID = b.User_ID
inner join Variant_detail c(nolock) on a.ProductName = c.ProductName and b.Name = c.ProductName and b.User_ID = c.User_ID
and a.User_ID = c.User_ID
where a.ProductID = @ProductID and a.User_ID = @User_ID
and a.ModifiedDate =(select max(ModifiedDate) from eshop_product_Invenory d(nolock) where a.ProductID = d.ProductID and a.User_ID = d.User_ID)
