/* ============================================================
   Procedure: [dbo].[eshop_get_return_reason]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- eshop_get_return_reason 4  
CREATE   PROC eshop_get_return_reason   
(    
@ReturnID int    
)    
as    
begin    
Declare @ReturnStage Varchar(100), @StageID int, @LastStageID int, @User_ID bigint    
set @StageID = (select max(StageID) from eshop_Order_Return_Stage (nolock) where ReturnID = @ReturnID)    
set @User_ID = (select User_ID from eshop_Order_Return (nolock) where ReturnID = @ReturnID)    
set @ReturnStage = (select Stage_Name from eshop_Order_Return_Stage (nolock) where ReturnID = @ReturnID and StageID = @StageID)    
  
IF(@ReturnStage = 'Return Approved')  
begin  
set @LastStageID = (select SeqNo from Return_Stage (nolock) where Stage_Name = 'Product returned to Client' and User_ID = @User_ID)    
end  
else  
begin  
set @LastStageID = (select SeqNo from Return_Stage (nolock) where Stage_Name = @ReturnStage and User_ID = @User_ID)  
end  
  
if(@ReturnStage = 'Return Disapproved')  
begin  
select * from Return_Stage (nolock) where SeqNo = @LastStageID +1 and User_ID = @User_ID    
end  
else if(@ReturnStage = 'Product returned to Client')  
begin  
select * from Return_Stage (nolock) where SeqNo = @LastStageID +5 and User_ID = @User_ID    
end  
else if(@ReturnStage = 'Product Exchanged')  
begin  
select * from Return_Stage (nolock) where SeqNo = @LastStageID +4 and User_ID = @User_ID    
end  
else if(@ReturnStage = 'Product Replaced')  
begin  
select * from Return_Stage (nolock) where SeqNo = @LastStageID +3 and User_ID = @User_ID    
end  
else if(@ReturnStage = 'Partially Refunded')  
begin  
select * from Return_Stage (nolock) where SeqNo = @LastStageID +2 and User_ID = @User_ID    
end  
else if(@ReturnStage = 'Fully Refunded')  
begin  
select * from Return_Stage (nolock) where SeqNo = @LastStageID +1 and User_ID = @User_ID    
end  
else  
begin  
select * from Return_Stage (nolock) where SeqNo > @LastStageID and User_ID = @User_ID    
end  
    
end


GO

