/* ============================================================
   Procedure: [dbo].[eshop_get_variant_det]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[eshop_get_variant_det]   --'Dual Tone Plain Shirt','M'   
(      
@Productname varchar(150),      
@Variant varchar(500)      
)      
as      
begin   
if exists(select '*' from   eshop_product_Invenory (nolock) where ProductName = @ProductName and Variant = @Variant)  
begin  
select a.ProductName, c.Variant,c.PRICE,a.Balance as INVENTORY  
from eshop_product_Invenory a(nolock) inner join Products b(nolock) on a.ProductID = b.ProductID and a.User_ID = b.User_ID  
inner join Variant_detail c(nolock) on a.ProductName = c.ProductName and b.Name = c.ProductName and b.User_ID = c.User_ID  
and a.User_ID = c.User_ID   and a.Variant = c.Variant
where a.ProductName = @Productname and a.Variant = @Variant  
and a.ModifiedDate =(select max(ModifiedDate) from eshop_product_Invenory d(nolock) where a.ProductID = d.ProductID and a.User_ID = d.User_ID  and a.Variant = Variant)    
end  
else  
select PRODUCTNAME,Variant,PRICE,INVENTORY from Variant_detail (nolock) where ProductName = @ProductName and Variant = @Variant  
end 


