/* ============================================================
   Procedure: [dbo].[eshop_get_Vendor_Details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- eshop_get_Vendor_Details 33097  
CREATE   PROC eshop_get_Vendor_Details   
(  
@User_ID bigint  
)  
as  
begin  
  
select s.SupplierID, s.CompanyName, s.City_Name,s.State_Name,s.Country_Name,s.ContactName,s.ContactTitle,s.Email,s.Mobile,  
count(DISTINCT p.ProductID) as ProductSupplied, (select sum(i.Quantity) from eshop_product_Invenory i(nolock) where i.User_ID = @User_ID and s.CompanyName = i.Vendor and i.ModifiedType in ('Add','Add Product','Add Variant','Order Fulfillment','Stock Adjustment Minus','Stock Adjustment Plus')) as UnitSupplied, (select sum(ii.Quantity) from eshop_product_Invenory ii(nolock) where ii.User_ID  = @User_ID and s.CompanyName = ii.Vendor and ii.ModifiedType in ('Dispose','Return To Vendor')) as UnitReturn from Suppliers s(nolock) left outer join Products p(nolock) on s.SupplierID = p.SupplierID and s.User_ID = p.User_ID  Where s.User_ID = @User_ID  
group by s.SupplierID, s.CompanyName, s.City_Name,s.State_Name,s.Country_Name,s.ContactName,s.ContactTitle,s.Email,s.Mobile  
order by s.SupplierID, s.CompanyName, s.City_Name,s.State_Name,s.Country_Name,s.ContactName,s.ContactTitle,s.Email,s.Mobile desc  
end


