/* ============================================================
   Procedure: [dbo].[eshop_insert_customer_lead]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[eshop_insert_customer_lead]            
(              
 @First_Name varchar(100),              
 @Last_Name varchar(100),              
 @Email varchar(100),              
 @Mobile varchar(100),              
 @User_ID Bigint,          
 @Username nvarchar(255) = ''          
)              
as              
begin              
if not EXISTS(select 'x' from userleads(nolock) where (EmailID = @Email or EmailID1 = @Email                  
 or EmailID2 = @Email) and ParentID =@User_ID )                           
 begin                            
  DECLARE @Leadno BIGINT = isnull((select MAX(LeadNo) FROM UserLeads(nolock) WHERE  ParentID = @User_ID),0)+1               
              
 if(not exists(select 'x' from UserSourceSettings(nolock) where Name = 'EshopSignUp' and UserID = @User_ID))          
 begin          
  INSERT INTO UserSourceSettings (NAME,UserID, IsEditable,IsActive,CreatedDate,ModifiedDate,ModifiedBy)                                        
   VALUES ('EshopSignUp',@User_ID,0,1,GETDATE(),GETDATE(),@User_ID)              
 end          
          
 declare @SourceID bigint, @Name varchar(200)                
 select @SourceID=SourceID from UserSourceSettings where NAME='EshopSignUp' and UserID= @User_ID              
              
 set @Name = @First_Name +' '+@Last_Name              
      
      
  if(exists (select 1 from crmCampaignSettings(nolock) where UserID = @User_ID  and isnull(AutoLeadFollowup,0) = 1))        
      Begin        
        
    Insert into userleads (LeadNo,PersonName,EmailID, AssignedTo,SourceName,ParentID,                                    
    Remarks,CreatedOn,CreatedBy,FollowUpStatus,NextStatusDate,followupdate,lastfollowupcreatedby,lastfollowupcreatedon)                                          
    select @leadno,@Name,@Email,@User_ID,                    
    @SourceID,@User_ID,'Lead Added from New signup in Eshop Portal',GETDATE(),@User_ID,null,GETDATE(),getdate(), @User_ID , getdate()                                     
      
 end      
 else      
   Begin      
     Insert into userleads (LeadNo,PersonName,EmailID, AssignedTo,SourceName,ParentID,                                    
    Remarks,CreatedOn,CreatedBy,FollowUpStatus,NextStatusDate,followupdate,lastfollowupcreatedby,lastfollowupcreatedon)                                          
    select @leadno,@Name,@Email,@User_ID,                    
    @SourceID,@User_ID,'Lead Added from New signup in Eshop Portal',GETDATE(),@User_ID,1,GETDATE(),getdate() , @User_ID , getdate()                                    
          
      
   End      
      
      
    declare @leadid bigint              
    set @leadid = (select ID from userleads where PersonName = @Name and LeadNo = @Leadno and ParentID = @User_ID)              
              
   update Customers              
    set LeadID = @leadid              
  where email=@Email and
        Mobile1=@Mobile
  -- Username = @Username 
  and User_ID = @User_ID              
              
   declare @customerid bigint=(select customerid from customers where Username = @Username and User_ID = @User_ID      )        
            
    /* Start lead activity  Lead signs up in Eshop */            
            
  Begin try            
          
 Declare @UserID_LDACTV bigint = @User_ID            
 Declare @ParentID_LDACTV bigint = @User_ID            
 Declare @LeadID_LDACTV bigint = @leadid            
 Declare @Domain_LDACTV nvarchar(500) = ''             
 Declare @UserNameOrLeadName nvarchar(500) = ''            
            
            
 --select @ParentID_LDACTV = isnull(parentid,0), @UserNameOrLeadName = isnull(User_login,'') from User_Detail where USER_ID = @UserID_LDACTV              
    select @UserNameOrLeadName = isnull(User_login,'') from User_Detail where USER_ID = @UserID_LDACTV              
            
 select @Domain_LDACTV = isnull(Domain,'') from eshop_client_domain where USER_ID = @UserID_LDACTV               
            
            
            
  create table #tblEventDescrb ( EVNT_Description nvarchar(max) )            
            
  if( isnull(@LeadID_LDACTV,0) > 0)            
   Begin            
                
   insert into #tblEventDescrb            
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead signs up in Eshop',@UserID_LDACTV,'','',@LeadID_LDACTV,'',null            
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null            
   ,null,null,null,null,@Domain_LDACTV,@UserNameOrLeadName,null,null,            
   null,null,null,null,null,null,0,null,null,null,null,null,null            
                 
   declare @evntMessage nvarchar(max) = ''             
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb            
             
   if(@evntMessage <> '')            
   Begin            
            
     exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage, 'Lead signs up in Eshop','Customers',@customerid            
                  
               
               
   end            
            
   End              
            
   end try            
   Begin catch            
            
     exec usp_InsertErrorInfo            
            
   End catch            
            
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence              
   Begin              
        DROP TABLE #tblEventDescrb              
   End              
               
            
  /* End lead activity  Lead signs up in Eshop */            
            
            
            
end              
          
else          
begin          
           
 select 'x' from userleads where (EmailID = @Email or EmailID1 = @Email                  
 or EmailID2 = @Email) and ParentID =@User_ID          
          
 UPDATE Customers          
  SET           
   LeadID = ( SELECT TOP 1 ID FROM userleads WHERE (           
       EmailID = @Email          
       OR EmailID1 = @Email          
       OR EmailID2 = @Email)          
      AND ParentID = @User_ID )          
  WHERE Username = @Username and User_ID = @User_ID          
end          
          
          
              
end 

