TotalProduct int     
)      
      
insert into #temp (CategoryID,CategoryName,Description,isActive,IsPublished, User_ID)      
select CategoryID,Name,Description,isActive,IsPublished, User_ID       
from Categories where User_ID = @User_ID and ParentCategory is null      
  
select CategoryID, Count(distinct ProductID) as TotalProduct, User_ID into #Product  
from Products where User_ID = @User_ID  
group by  CategoryID , User_ID   
      
select ParentCategoryName, count(CategoryID)  subCategory, User_ID      
into #Parent      
from Categories where User_ID = @User_ID group by  ParentCategoryName, User_ID      
      
update a      
set a.SubCategory = b.subCategory      
from #temp a, #Parent b      
where a.CategoryName = b.ParentCategoryName      
and a.User_ID = b.User_ID   
  
update a  
set a.TotalProduct = b.TotalProduct  
from #Product b, #temp a  
where a.CategoryID = b.CategoryID  
and a.User_ID = b.User_ID     
      
select CategoryID,CategoryName as Name, Description as Description, isnull(SubCategory,0) as SubCategory,      
isActive,IsPublished,User_ID,TotalProduct as ParentCategory  from #temp      
      
drop table #Parent      
drop table #temp   
drop table #Product      
    
end  


GO

/* ============================================================
   Procedure: [dbo].[eshop_list_RecentlyView]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_list_RecentlyView 
(  
@ProductID int  
)  
as  
begin  
  
select r.CustomerID, c.First_Name+' '+c.Last_Name as CustomerName,  
r.ProductID, p.Name, max(r.ViewDate) as LastDate, count(r.ViewDate) as TotalCount 
from RecentlyViews r inner join Customers c on r.CustomerID = c.CustomerID  
inner join Products p on r.ProductID = p.ProductID  
where r.ProductID = @ProductID 
group by  r.CustomerID, c.First_Name,c.Last_Name,r.ProductID, p.Name
order by LastDate desc
end  


