/* ============================================================
   Procedure: [dbo].[eshop_list_SubCategory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[eshop_list_SubCategory] --'Food', 31642    
(    
@ParentCategory varchar(100),    
@User_ID int    
)    
as    
begin    
create table #temp    
(    
CategoryID int,    
ParentCategoryName varchar(100),    
CategoryName varchar(100),    
SubCategory int,    
Description VARCHAR(100),    
isActive bit,    
IsPublished bit,    
User_ID  BIGINT,
TotalProduct int    
)    
insert into #temp (CategoryID,ParentCategoryName,CategoryName,Description,isActive,IsPublished, User_ID)    
select CategoryID,ParentCategoryName,Name,Description,isActive,IsPublished, User_ID from Categories     
where User_ID = @User_ID and ParentCategoryName  = @ParentCategory    

SELECT a.CategoryID, Count(distinct ProductID) as TotalProduct, p.User_ID into #Product
FROM   #temp a(NOLOCK), Products p(nolock)
where  a.CategoryID = p.CategoryID
and a.User_ID = p.User_ID and p.User_ID = @User_ID
group by a.CategoryID, p.User_ID
    
select ParentCategoryName, count(CategoryID)  subCategory, User_ID    
into #Parent    
from Categories where User_ID = @User_ID    
group by  ParentCategoryName, User_ID    
    
update a    
set a.SubCategory = b.subCategory    
from #temp a, #Parent b    
where a.CategoryName = b.ParentCategoryName    
and a.User_ID = b.User_ID    

update a
set a.TotalProduct = b.TotalProduct
from #Product b, #temp a
where a.CategoryID = b.CategoryID
and a.User_ID = b.User_ID 
    
select CategoryID,ParentCategoryName, CategoryName Name, Description, isnull(SubCategory,0) SubCategory,isActive,IsPublished,User_ID,TotalProduct as ParentCategory 
from #temp    
where ParentCategoryName = @ParentCategory    
    
drop table #Parent    
drop table #temp      
    
end  


