/* ============================================================
   Procedure: [dbo].[eshop_order_fulfillment_Delete]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_order_fulfillment_Delete        
(        
@ID int,        
@OrderNo int,        
@ProductName varchar(150),        
@Product_det varchar(500),        
@FulfillmentDate Datetime,        
@TotalQuantity int,        
@FulfillQuantity int,        
@FulfillmentStatus varchar(25)        
)        
as         
begin      
  
Declare @FulfillQuantity1 int  
select @FulfillQuantity1 = FulfillQuantity from Order_Fulfillment(nolock)  
WHERE PRODUCTNAME = @ProductName  
and Product_det = @Product_det  
and OrderNo = @OrderNo  
and ID = @ID  
  
if(@Product_det <> '')  
begin  
update Variant_detail  
set INVENTORY = INVENTORY + @FulfillQuantity1  
WHERE PRODUCTNAME = @ProductName  
and Variant = @Product_det  
and User_ID = (Select User_ID from [Order] where OrderID = @OrderNo)  
  
end  
else  
BEGIN  
UPDATE Products      
SET UnitInStock = UnitInStock + @FulfillQuantity1,  
 TotalSell = TotalSell - @FulfillQuantity1     
WHERE Name = @ProductName   
and Name not in (select ProductName from Variant_detail where ProductName = @ProductName   
   and User_ID = (Select User_ID from [Order] where OrderID = @OrderNo))  
and User_ID = (Select User_ID from [Order] where OrderID = @OrderNo)  
END   

Declare @Balance int, @ProductID int, @User_ID bigint, @Vendor varchar(150), @Order varchar(15)    
set @User_ID = (select distinct User_ID from [Order] (nolock) where OrderID = @OrderNo)    
set @ProductID = (select distinct ProductID from Products (nolock) where Name = @ProductName and User_ID = @User_ID)    
set @Vendor = (select s.CompanyName from Suppliers s(nolock) inner join Products p(nolock) on p.SupplierID = s.SupplierID where p.ProductID = @ProductID and p.User_ID = @User_ID)    
set @Balance = (select Top 1 Balance from eshop_product_Invenory (nolock) where ProductID = @ProductID Order by ID desc)      
set @Balance = @Balance + @FulfillQuantity    
set @Order = (select OrderNo from [Order] (nolock) where OrderID = @OrderNo)    

insert into eshop_product_Invenory(ProductID,ProductName,Variant,Quantity,ModifiedDate,ModifiedType,Remarks,User_ID,Vendor,Balance)    
Values(@ProductID,@ProductName,@Product_det,-@FulfillQuantity,getdate(),'Revarsal Order Fulfillment',@Order,@User_ID,@Vendor,@Balance)    

Delete from Order_Fulfillment where ID = @ID and OrderNo = @OrderNo       
and ProductName = @ProductName and Product_det = @Product_det         
      
if not exists(select '*' from Order_Fulfillment where ID = @ID and OrderNo = @OrderNo)      
begin      
update [Order]        
set DIspatched = 0,        
DispatchedDate = null,        
Shipped = 0,        
ShippingDate = null       
where OrderID = @OrderNo       
end      
        
        
        
end



GO

/* ============================================================
   Procedure: [dbo].[eshop_order_fulfillment_edit]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_order_fulfillment_edit        
(        
@ID int,        
@OrderNo int,        
@ProductName varchar(150),        
@Product_det varchar(500),        
@FulfillmentDate Datetime,        
@TotalQuantity int,        
@FulfillQuantity int,        
@FulfillmentStatus varchar(25)       
)        
as         
begin 
Declare @FulfillQuantity1 int
select @FulfillQuantity1 = FulfillQuantity from Order_Fulfillment(nolock)
WHERE PRODUCTNAME = @ProductName
and Product_det = @Product_det
and OrderNo = @OrderNo
and ID = @ID

if(@Product_det <> '')
begin
update Variant_detail
set INVENTORY = INVENTORY + @FulfillQuantity1
WHERE PRODUCTNAME = @ProductName
and Variant = @Product_det
and User_ID = (Select User_ID from [Order] where OrderID = @OrderNo)
update Variant_detail
set INVENTORY = INVENTORY - @FulfillQuantity
WHERE PRODUCTNAME = @ProductName
and Variant = @Product_det
and User_ID = (Select User_ID from [Order] where OrderID = @OrderNo)
end
else
BEGIN
UPDATE Products    
SET UnitInStock = UnitInStock + @FulfillQuantity1,
	TotalSell = TotalSell - @FulfillQuantity1   
WHERE Name = @ProductName 
and Name not in (select ProductName from Variant_detail where ProductName = @ProductName 
			and User_ID = (Select User_ID from [Order] where OrderID = @OrderNo))
and User_ID = (Select User_ID from [Order] where OrderID = @OrderNo)
UPDATE Products    
SET UnitInStock = UnitInStock - @FulfillQuantity,
	TotalSell = TotalSell + @FulfillQuantity   
WHERE Name = @ProductName 
and Name not in (select ProductName from Variant_detail where ProductName = @ProductName 
			and User_ID = (Select User_ID from [Order] where OrderID = @OrderNo))
and User_ID = (Select User_ID from [Order] where OrderID = @OrderNo)
END   
    
update Order_Fulfillment        
set FulfillQuantity = @FulfillQuantity, FulfillmentDate = @FulfillmentDate, FulfillmentStatus = @FulfillmentStatus      
where ID = @ID and OrderNo = @OrderNo and ProductName = @ProductName and Product_det = @Product_det     
    
update [Order]    
set DIspatched = 1,    
DispatchedDate = @FulfillmentDate,    
Shipped = 1,    
ShippingDate = @FulfillmentDate    
where OrderID = @OrderNo       
        
        
end


GO

