/* ============================================================
   Procedure: [dbo].[eshop_order_return_request]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_order_return_request              
(              
@OrderID int,     
@OrderDetailsID int,              
@ProductName varchar(150),              
@Variant varchar(500),              
@Quantity_Return int,              
@Remarks varchar(500),              
@Reason varchar(500),              
@Expected_Outcome varchar(500),              
@ReturnInitiatedDate datetime,              
@User_ID bigint,
@Rep_Variant varchar(100)             
)              
as              
begin             
 if (@Variant = 'Variant')            
begin            
set @Variant = '';            
end 
 if (@Rep_Variant = 'Variant')            
begin            
set @Rep_Variant = '';            
end 
 if (@ProductName = 'ProductName')            
begin            
set @ProductName = '';            
end            
Declare @ReturnRequestNo Varchar(15), @ReturnID int, @OrderAmount int              
set @ReturnRequestNo = 'Req'+'_'+convert(varchar(5),@User_ID)+'_'+convert(varchar(5),@OrderID);              
insert into eshop_Order_Return (ReturnRequestNo,OrderID,ProductName,Variant,Quantity_Return,              
       ReturnInitiatedDate,StageDate,Remarks,Reason,Expected_Outcome,User_ID, Stage_Name, OrderDetailsID,Rep_Variant )              
Values(@ReturnRequestNo,@OrderID,@ProductName,@Variant,@Quantity_Return,@ReturnInitiatedDate,@ReturnInitiatedDate,              
  @Remarks,@Reason,@Expected_Outcome,@User_ID,'Return Requested' , @OrderDetailsID, @Rep_Variant)              
              
set @ReturnID = SCOPE_IDENTITY()               
set @OrderAmount = (select TotalAmount from [Order] where OrderID = @OrderID and User_ID = @User_ID)              
              
insert into eshop_Order_Return_Stage (ReturnID,OrderID,Stage_Name,Reason,Expected_Outcome,User_ID,Order_Amount,StageDate, Amount_Refunded)              
values(@ReturnID, @OrderID, 'Return Requested',@Reason,@Expected_Outcome,@User_ID,@OrderAmount, @ReturnInitiatedDate, '0.00')              
      
update OrderDetails      
set CancelOrder = 1  , ReturnOrder = 1    
where OrderID = @OrderID and OrderDetailsID = @OrderDetailsID      

select distinct ReturnOrder into #temp1234 from OrderDetails (nolock) where OrderID = @OrderID
    
if not exists ( select '*' from #temp1234 where ReturnOrder in (0,NULL)  )    
begin    
update [Order]    
set CancelOrder = 1    
where OrderID = @OrderID    
end    
              
end 


GO

/* ============================================================
   Procedure: [dbo].[eshop_order_return_request_stage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_order_return_request_stage                   
(                    
@ReturnID  int,           
@OrderID int,       
@Stage_Name varchar(150),                    
@Reason varchar(500),                    
@Expected_Outcome   varchar(500),                 
@User_ID bigint,      
@StageDate datetime                
)                    
as                    
begin                   
          
if (@Reason = '')      
begin      
set @Reason = '';      
end              
Declare @OrderAmount int                    
                
set @OrderAmount = (select TotalAmount from [Order] where OrderID = @OrderID and User_ID = @User_ID)                    
                    
insert into eshop_Order_Return_Stage (ReturnID,OrderID,Stage_Name,Reason,Expected_Outcome,User_ID,Order_Amount,StageDate, Amount_Refunded)                    
values(@ReturnID, @OrderID, 'Return Requested',@Reason,@Expected_Outcome,@User_ID,@OrderAmount, @StageDate, '0.00')                    
            
         
  
    /* Start Lead activity  Lead requested return */  
   Begin try  
     
   Declare @ReturnID_LDACTV int = @ReturnID  
   Declare @ReturnReuqest_LDACTV nvarchar(200) = '0'  
   Declare @OrderID_LDACTV int = @OrderID  
   Declare @UserID_LDACTV bigint = @User_ID  
   Declare @ParentID_LDACTV bigint = @User_ID  
   Declare @OrderNo_LDACTV nvarchar(500) = ''  
   Declare @OrderDate_LDACTV nvarchar(50) = ''  
   Declare @CustID_LDACTV int = 0  
   Declare @LeadID_LDACTV bigint = 0  
  
      
 select @ReturnReuqest_LDACTV = isnull(ReturnRequestNo,'') From [eshop_Order_Return] where ReturnID = @ReturnID_LDACTV  
  
    --Select @ParentID_LDACTV = isnull(ParentID,0) from User_Detail where USER_ID = @UserID_LDACTV   
      
    Select top 1 @OrderNo_LDACTV = isnull(OrderNo,''),@OrderDate_LDACTV = isnull(OrderDate,''), @CustID_LDACTV = isnull(CustomerID,0)  from [order] where OrderID = @OrderID_LDACTV  
  
 select top 1  @LeadID_LDACTV = isnull(LeadID,0)  from Customers where CustomerID = @CustID_LDACTV  
    
  
  
  create table #tblEventDescrb  
     (  
  
       EVNT_Description nvarchar(max)   
     )  
  
  if( isnull(@LeadID_LDACTV,0) > 0)  
   Begin  
      
   insert into #tblEventDescrb  
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead requested return',@UserID_LDACTV,'','',@LeadID_LDACTV,'',null  
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null  
   ,null,null,null,null,null,null,null,null,  
   @OrderNo_LDACTV,null,null,@Orderdate_LDACTV,@ReturnReuqest_LDACTV,null,0,null,null,null,null,null,null  
       
   declare @evntMessage nvarchar(max) = ''   
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb  
   
   if(@evntMessage <> '')  
   Begin  
   exec UspSaveLeadActivity @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage,    'Lead requested return'  
      end  
  
   End    
  
   End try  
   Begin catch   
        exec usp_InsertErrorInfo  
   End Catch  
  
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence    
   Begin    
        DROP TABLE #tblEventDescrb    
   End   
  
   /* End Lead activity  Lead requested return */  
  
  
  
  exec usp_es_PunchFreshOrderOnExchangeOrReplaced @ReturnID, @Stage_Name
                    
end 


