/* ============================================================
   Procedure: [dbo].[eshop_payment_details]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_payment_details(@User_ID BIGINT)
AS
BEGIN
    SELECT o.OrderID, 
            o.OrderNo, 
            p.PaymentMode, 
            p.PaymentDate, 
            p.Amount_Paid, 
            ( o.TotalAmount - (select sum(py.Amount_Paid) from Payment py where OrderNo = o.OrderID and py.PaymentID<= p.PaymentID)) TotalAmount
    FROM Payment p(NOLOCK)
            INNER JOIN [Order] o(NOLOCK) ON p.OrderNo = o.OrderID
			WHERE o.User_ID = @User_ID AND p.PaymentStatus = 'Paid'
				ORDER BY p.PaymentDate DESC;
END;


GO

/* ============================================================
   Procedure: [dbo].[eshop_payment_details_search]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_payment_details_search  
(  
@User_ID bigint,
@searchvalue varchar(500),
@searchcriteria varchar(500)  
)  
as  
begin  

if(@searchcriteria = 'OrderNo')
begin  
select o.OrderID, o.OrderNo, p.PaymentMode, p.PaymentDate, p.Amount_Paid, (o.TotalAmount - p.Amount_Paid) TotalAmount  
from Payment p(nolock) inner join [Order] o (nolock)  
on p.OrderNo = o.OrderID  
WHERE o.User_ID = @User_ID  
and p.PaymentStatus = 'Paid' 
and o.OrderNo like '%'+ @searchvalue +'%' 
Order by p.PaymentDate desc
end

if(@searchcriteria = 'Date')
begin  

select o.OrderID, o.OrderNo, p.PaymentMode, p.PaymentDate, p.Amount_Paid, (o.TotalAmount - p.Amount_Paid) TotalAmount  
from Payment p(nolock) inner join [Order] o (nolock)  
on p.OrderNo = o.OrderID  
WHERE o.User_ID = @User_ID  
and p.PaymentStatus = 'Paid' 
and p.PaymentDate =  @searchvalue 
Order by p.PaymentDate desc
end

 
end


GO

/* ============================================================
   Procedure: [dbo].[eshop_Prc_usp_UserApplyCoupon]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--declare @tbl table(ProductID bigint,Qty bigint)              
--insert into @tbl values(5,6)              
--exec eshop_Prc_usp_UserApplyCoupon 'TEST33',33097,49,498            
              
CREATE   PROCEDURE [dbo].[eshop_Prc_usp_UserApplyCoupon] --'Hariom_coupon',335,'9891461152','testing@gmail.com','250',null                        
@CouponCode VARCHAR(50)=null,                           
@ParentID BIGINT =null,                           
@CustomerID int,                           
@BIllAmount VARCHAR(500)= null        
AS                           
BEGIN                          
SELECT * INTO   #tempcoupon FROM   eshop_coupon AS ucs WHERE  ucs.parentid = @ParentID AND ucs.CouponName = @CouponCode          
create table  #tempnew (ProductName  varchar(150),Qty bigint)                  
declare @couponid int=(select CouponID FROM #tempcoupon)                 
declare @MobileNo VARCHAR(50)= null ,                           
    @EmailID VARCHAR(50) =null     , @UserName Varchar(200)
	set   @UserName = (Select UserName From Customers where CustomerID = @CustomerID)       
select @MobileNo = Mobile1, @EmailID = Email from Customers (nolock)  where CustomerID = @CustomerID and User_ID = @ParentId        
                                
----------------- Check Coupon Code is active or Not------------------                           
IF not EXISTS (SELECT 1 FROM   #tempcoupon tt WHERE  tt.Status =1 and GETDATE() between StartDate and ExpiryDate)             BEGIN                         
 select case when tt.Status=0 then 'Coupon is not Valid' else 'Coupon has expired' END AS FreeProduct,0 AS MinQty,0 as DiscountAmount      
 FROM   #tempcoupon tt                       
    Goto OReturn                                 
END                   
--Check Bill Applicability--                      
if exists(select 1 from #tempcoupon where IsBillApplicability=1)                         
 begin                         
  if exists(select 1 from #tempcoupon where @BIllAmount between minbillamount and MaxBillAmount)                         
  begin           
   goto checkproduct                        
  end                  
  else                  
  Begin                  
   Select 'Coupon is applicable only on bill amount between ' + CAST((select minbillamount from #tempcoupon) as nvarchar) + ' and ' + CAST((select MaxBillAmount from #tempcoupon) as nvarchar)  AS FreeProduct,0 AS MinQty,0 as DiscountAmount                
  
       
   GoTo OReturn                                        
  ENd                   
 End                  
 Else                  
 Begin                  
  goto checkproduct                         
End           
          
--Check if coupon is applicable to produts in cart          
CheckProduct:                         
if exists(select 1 from #tempcoupon where ISProductApplicability=1)                         
begin                   
    if exists(select 1 from eshop_coupon_product p   
    join eshop_cart_items t on p.ProductName=t.ProductName  and t.Quantity    
    between p.minqty and p.maxqty join #tempcoupon tc on p.CouponID=tc.CouponID 
	where t.UserName = @UserName )                              
    begin   
	SET @BIllAmount = CONVERT(INT,@BIllAmount) - (SELECT TotalAmount FROM eshop_cart_items   
             where ProductName NOT  in (select ProductName from eshop_coupon_product  
                    where CouponID = @couponid))                
    Goto Checksegment     
    end                        
    else                         
    begin                         
    Select 'Coupon is not applicable for the products in cart'  AS FreeProduct,0 AS MinQty,0 as DiscountAmount                       
    Goto OReturn                         
    end                         
end                         
          
--Check if coupon is applicable to the user applying the coupon          
CheckSegment:               
if exists(select 1 from #tempcoupon where ISSearchApplicability =1)                      
begin          
declare @mediumtype nvarchar(20)= (select mediumtype from #tempcoupon)          
SELECT ROW_NUMBER()Over(Order by Ucm.couponID,Ucm.ParentID) AS Id,         
       Ucm.couponID,                                                
                   Ucm.ParentID,                                                
                   A.[value]  AS IncludeSearches,                                                
                   AGL.[value]         AS IncludeList,                                                
                   EGL.[value]        AS ExclusionsGroupList,                                                
                   case when ucm.Mediumtype = 'Email' then '' else Ucm.ExcludeMobile end as ExcludeMobile,          
                   case when ucm.Mediumtype = 'Mobile' then '' else Ucm.Excludemail end as Excludemail,                                          E.[value]           AS Exclusions,                                                
                   case when ucm.Mediumtype = 'Email' then @EmailID else Ucm.ExcludeMobile end as IncludeMail,          
                   case when ucm.Mediumtype = 'Mobile' then @MobileNo else Ucm.Excludemail end as IncludeMobile           
            INTO #temptemplate             
            FROM   #tempcoupon Ucm   (nolock)                                                 
            OUTER APPLY Dbo.Fn_split(Ucm.IncludeSearches, '#') AS A           
   OUTER APPLY Dbo.Fn_split(Ucm.IncludeList, '#') AS AGL          
   OUTER APPLY Dbo.Fn_split(Ucm.ExcludeList, '#') AS  EGL           
   OUTER APPLY Dbo.Fn_split(Ucm.ExcludeSearch, '#') AS E           
--Check medium & Check if contact details are in exclusions--          
if @mediumtype='Both' and exists(select 'x' from #temptemplate outer apply dbo.Fn_split(ExcludeMobile, ',')  AS fs outer apply dbo.Fn_split(Excludemail, ',') as fsmail  WHERE  fs.[value]=@MobileNo or fsmail.[value]=@EmailID)            
begin          
Select 'Oops! Coupon is not applicable to you'  AS FreeProduct,0 AS MinQty,0 as DiscountAmount                  
goto OReturn                             
end          
else if exists(select 'x' from #temptemplate outer apply dbo.Fn_split(ExcludeMobile, ',')  AS fs outer apply dbo.Fn_split(Excludemail, ',') as fsmail  WHERE  fs.[value]=@MobileNo and fsmail.[value]=@EmailID)                         
begin          
Select 'Oops! Coupon is not applicable to you'  AS FreeProduct,0 AS MinQty,0 as DiscountAmount                  
goto OReturn                             
end          
--Check if user is in inclusions          
else          
begin            
CREATE TABLE #temptablesearchapp                                
     (                                          
      campaignid             BIGINT,                                          
      searchid               BIGINT,                                          
      parentid         BIGINT,           
      userid           bigint,                                         
      personname             NVARCHAR(200),                                          
      companyname            NVARCHAR(200),                                          
      mobileno               NVARCHAR(200),                                          
      mobileno1              NVARCHAR(200),                                          
      mobileno2              NVARCHAR(200),                                          
      emailid                NVARCHAR(200),                                          
      emailid1               NVARCHAR(200),                                          
      emailid2               NVARCHAR(200),                                          
      city                   NVARCHAR(200),                                          
      STATE                  NVARCHAR(200),                                          
      country                NVARCHAR(200),                                          
      countrycode            NVARCHAR(200),                                          
      pincode                NVARCHAR(200),                                          
      residentialaddress     NVARCHAR(200),          
      officeaddress          NVARCHAR(200),                                          
      sourcename       NVARCHAR(200),                                          
      mediumname             NVARCHAR(200),                                          
      campaignname           NVARCHAR(200),                                          
      initialremarks         NVARCHAR(1000)                                          
     )                                          
                                  
     CREATE TABLE #temptablesearchexc                                          
     (                                          
      campaignid             BIGINT,                                          
      searchid               BIGINT,                                          
      parentid               BIGINT,          
      userid     bigint,                           
      personname             NVARCHAR(200),                                          
      companyname            NVARCHAR(200),                        
      mobileno               NVARCHAR(200),                                          
      mobileno1              NVARCHAR(200),                                  
      mobileno2              NVARCHAR(200),                                          
      emailid            NVARCHAR(200),                                          
      emailid1               NVARCHAR(200),                                          
      emailid2               NVARCHAR(200),                                          
      city                   NVARCHAR(200),                                          
      STATE                  NVARCHAR(200),                                          
      country                NVARCHAR(200),                                          
      countrycode            NVARCHAR(200),                                          
      pincode                NVARCHAR(200),                                          
      residentialaddress     NVARCHAR(200),                                          
      officeaddress          NVARCHAR(200),                                          
      sourcename             NVARCHAR(200),                                          
      mediumname             NVARCHAR(200),                                        
      campaignname           NVARCHAR(200),                                          
      initialremarks         NVARCHAR(1000)                           
     )                                          
INSERT INTO #temptablesearchapp(mobileno,emailid,ParentID  )                                                
Select ISNULL(Usd.MobileNumber, ''),ISNULL(usd.EmailID,''),Tt.ParentID            
FROM  #temptemplate TT          
Inner join  Usersearchdata AS Usd  (nolock)  on Usd.ParentID =  Tt.ParentID AND Usd.ImportedListID = Tt.IncludeList and Tt.IncludeList is not null           
          
INSERT INTO #temptablesearchexc (mobileno,emailID,ParentID  )                    
SELECT ISNULL(Usd.Mobilenumber, ''),usd.emailID, Tt.ParentID FROM #temptemplate TT   Inner join   Usersearchdata AS Usd  (nolock) on Usd.ParentID =  Tt.ParentID AND Usd.ImportedListID = Tt.ExclusionsGroupList and Tt.ExclusionsGroupList is not null       
   
           
 --check if user is included in exclusion list till now          
if @mediumtype ='both' and exists(select 1 from #temptablesearchexc ttse where isnull(mobileno,0)=@MobileNo or isnull(emailid,0)=@EmailID)               
begin          
Select 'Oops! Coupon is not applicable to you'  AS FreeProduct,0 AS MinQty,0 as DiscountAmount                  
goto OReturn           
end          
if @mediumtype='mobile' and exists(select 1 from #temptablesearchexc ttse where isnull(mobileno,0)=@MobileNo)               
begin          
Select 'Oops! Coupon is not applicable to you'  AS FreeProduct,0 AS MinQty,0 as DiscountAmount                  
goto OReturn           
end          
if @mediumtype='email' and exists(select 1 from #temptablesearchexc ttse where isnull(emailid,0)=@EmailID)               
begin          
Select 'Oops! Coupon is not applicable to you'  AS FreeProduct,0 AS MinQty,0 as DiscountAmount                  
goto OReturn           
end          
          
DECLARE @CountCampaign     INT = (Select MAX(Id) from #temptemplate)                                               
DECLARE @Count INT = 1                                                                                                            
          
WHILE (@Count <= @CountCampaign) or not exists(select 1 from #temptablesearchexc ttse where (isnull(mobileno,0)= @MobileNo       
  or isnull(mobileno1,0)= @MobileNo or isnull(mobileno2,0)= @MobileNo) and (isnull(emailid,0)=@EmailID         
   or isnull(emailid1,0)=@EmailID or isnull(emailid2,0)=@EmailID))          
BEGIN                                          
DECLARE @Applicability BIGINT,@Exclusions BIGINT          
Select @Applicability = tt.IncludeSearches,@Exclusions = tt.Exclusions from #temptemplate tt Where Id = @Count           
If(@Applicability is not null)          
Begin                                         
INSERT INTO #temptablesearchapp                                                
       (                                               
      PersonName,                  
      CompanyName,                                                
      MobileNo,                                                
      MobileNo1,                                                
      MobileNo2,                                                
      EmailID,                                                
      EmailID1,                         
      EmailID2,                                                
      Country,                                                
      [STATE],                                   
      City,                                          
      PinCode,                               
      ResidentialAddress,                                                
      OfficeAddress,                                                
      SourceName,                                                
      MediumName,                                                
      CampaignName,                                                
      InitialRemarks,                                                
      SearchID,                                                
      ParentID,                                                
      CampaignID                                                
       )                                                
     EXEC Usp_executeusersearch                                                
       @ParentId,                                                
       @Applicability,                                                
       @Campaignid=NULL          
                 
           End                                           
if(@Exclusions is not null)          
Begin                                           
INSERT INTO #temptablesearchexc                                                
           (                                                
             PersonName,                                                
             CompanyName,                                                
             MobileNo,                                                
             MobileNo1,                                                
       MobileNo2,                                                
             EmailID,                                                
             EmailID1,                                                
             EmailID2,                                                
             Country,                                                
             [STATE],                                                
             City,                                                
             PinCode,                                                
             ResidentialAddress,                                                
             OfficeAddress,                                                
             SourceName,                                                
             MediumName,                                                
             CampaignName,                                                
             InitialRemarks,                                                
             SearchID,                                                
             ParentID,                                                
             CampaignID                                                
    )                                                
         EXEC Usp_executeusersearch     
              @Parentid,                                                
              @Exclusions,                                                
              @Campaignid=NULL          
              
    END          
SET @Count = @Count+1          
END               
if (@mediumtype='mobile' or @mediumtype='both') and exists(select 1 from #temptablesearchexc ttse         
where (isnull(mobileno,0)= @MobileNo or isnull(mobileno1,0)= @MobileNo or isnull(mobileno2,0)= @MobileNo))          
begin          
Select 'Oops! Coupon is not applicable to you'  AS FreeProduct,0 AS MinQty,0 as DiscountAmount                  
goto OReturn          
end           
if (@mediumtype='email' or @mediumtype='both') and exists(select 1 from #temptablesearchexc ttse         
where (isnull(emailid,0)=@EmailID or isnull(emailid1,0)=@EmailID or isnull(emailid2,0)=@EmailID))          
begin          
Select 'Oops! Coupon is not applicable to you'  AS FreeProduct,0 AS MinQty,0 as DiscountAmount                 
goto OReturn          
end          
            
if exists(select 'x' from #temptemplate outer apply dbo.Fn_split(IncludeMobile, ',')  AS fs         
outer apply dbo.Fn_split(Includemail, ',') as fsmail  WHERE  fs.[value]=@MobileNo and fsmail.[value]=@EmailID)            
begin          
Goto CouponSuccess          
end              
else if @mediumtype='mobile' and exists(select 1 from #temptablesearchapp ttse where (isnull(mobileno,0)= @MobileNo         
or isnull(mobileno1,0)= @MobileNo or isnull(mobileno2,0)= @MobileNo))          
begin          
goto CouponSuccess          
end           
else if @mediumtype='email' and exists(select 1 from #temptablesearchapp ttse where (isnull(emailid,0)=@EmailID         
    or isnull(emailid1,0)=@EmailID or isnull(emailid2,0)=@EmailID))          
begin          
goto CouponSuccess          
end           
else if @mediumtype='both' and exists(select 1 from #temptablesearchapp ttse where (isnull(mobileno,0)= @MobileNo         
or isnull(mobileno1,0)= @MobileNo or isnull(mobileno2,0)= @MobileNo) and (isnull(emailid,0)=@EmailID         
or isnull(emailid1,0)=@EmailID or isnull(emailid2,0)=@EmailID))          
begin          
goto CouponSuccess          
end           
end          
end          
--select * from eshop_coupon          
CouponSuccess:          
declare @discount int,@others nvarchar(400)          
if (select isdiscount from #tempcoupon)=1          
begin          
select @discount=case when DiscountAmount<>0 then DiscountAmount else DiscountPrcnt*@BIllAmount/100 end from #tempcoupon          
end          
SELECT isnull(f.ProductName,'')as FreeProduct,isnull(f.MinQty,0) MinQty, 0 as DiscountAmount --isnull(@discount, 0) discount         
FROM eshop_freebeecoupon_product f          
where f.CouponID=@couponid  and f.ParentID = @ParentID         
union        
select '',0, @discount as DiscountAmount        
OReturn:                       
END 


GO

/* ============================================================
   Procedure: [dbo].[eshop_product_list]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_product_list  --33859            
(              
@User_ID bigint              
)              
as              
begin       
    
Create Table #ProductRemain    
(    
ProductID int,              
RemainQuanity int    
)           
insert into #ProductRemain    
select ProductID, sum(UnitInStock - ReOrderLevel) from Products (nolock) where User_ID = @User_ID group by ProductID      
              
Create table #productsold              
(              
ProductID int,              
SoldQuantity int              
)              
insert into #productsold              
select ProductID, sum(Quantity) from OrderDetails (nolock) where User_ID = @User_ID      
and CancelOrder = 0         
and fulfillmentstatus <> 'NULL'      
group by ProductID              
      
Create table #productfulfill              
(              
ProductID int,              
FulfillQuantity int              
)              
insert into #productfulfill              
select ProductID, sum(Quantity) from OrderDetails (nolock) where User_ID = @User_ID      
and CancelOrder = 0      
and fulfillmentstatus not in ('UnFulfilled','NULL')      
group by ProductID      
              
Create table #productreturn              
(              
ProductID int,              
ReturnQuantity int              
)              
insert into #productreturn              
select p.ProductID, sum(Quantity_Return) as ReturnQuantity from eshop_order_return e (nolock)        
inner join  Products p (nolock)               
on e.ProductName = p.Name         
where e.User_ID = @User_ID               
group by p.ProductID              
              
Create table #productbrowsed              
(              
ProductID int,              
BrowseQuantity int              
)              
insert into #productbrowsed              
select p.ProductID, count(r.ProductID) as BrowseQuantity from RecentlyViews r (nolock)         
inner join Products p (nolock)               
on r.ProductID = p.ProductID              
where p.User_ID = @User_ID               
group by p.ProductID              
              
Create table #productcart              
(              
ProductID int,              
CartQuantity int              
)              
insert into #productcart              
select e.ProductID, sum(Quantity) as CartQuantity               
from eshop_cart_items e(nolock)               
inner join Products p(nolock)              
on e.ProductID = p.ProductID    
inner join Customers c(nolock)    
on e.UserName = c.UserName              
where p.User_ID = @User_ID               
group by e.ProductID              
              
Create table #productwish              
(              
ProductID int,             
WishQuantity int              
)              
insert into #productwish              
select p.ProductID, count(e.ProductID) as WishQuantity               
from Wishlist e(nolock)               
inner join Products p(nolock)              
on e.ProductID = p.ProductID              
where p.User_ID = @User_ID               
group by p.ProductID              
              
select p.User_ID, p.ProductID, p.Name, p.CreatedDate, p.isActive,              
isnull(s.SoldQuantity,0) as TotalSell, isnull(r.ReturnQuantity,0) as TotalReturn,              
isnull(b.BrowseQuantity,0) as TotalBrowse, isnull(c.CartQuantity,0) as TotalCart,              
isnull(w.WishQuantity,0) as Totalwish, isnull(P.UnitInStock,0) as UnitInStock,isnull(f.FulfillQuantity,0) as TotalFulfill               
from Products p(nolock)              
LEFT OUTER join #productsold s              
on p.ProductID = s.ProductID              
LEFT OUTER join #productreturn r              
on p.ProductID = r.ProductID              
LEFT OUTER join #productbrowsed b              
on p.ProductID = b.ProductID              
LEFT OUTER join #productcart c              
on p.ProductID = c.ProductID              
LEFT OUTER join #productwish w              
on p.ProductID = w.ProductID       
LEFT OUTER join #productfulfill f              
on p.ProductID = f.ProductID        
left outer join #ProductRemain re    
on p.ProductID = re.ProductID            
where p.User_ID = @User_ID               
Order by re.RemainQuanity     
              
drop table #productsold              
drop table #productreturn              
drop table #productbrowsed              
drop table #productcart              
drop table #productwish              
              
end


GO

/* ============================================================
   Procedure: [dbo].[eshop_product_list_Categorywise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_product_list_Categorywise              
(              
@User_ID bigint,
@CategoryID int              
)              
as              
begin       
    
Create Table #ProductRemain    
(    
ProductID int,              
RemainQuanity int    
)           
insert into #ProductRemain    
select ProductID, sum(UnitInStock - ReOrderLevel) from Products (nolock) where User_ID = @User_ID and CategoryID = @CategoryID 
group by ProductID      
              
Create table #productsold              
(              
ProductID int,              
SoldQuantity int              
)              
