select ProductID, sum(Quantity) from OrderDetails (nolock) where User_ID = @User_ID      
and CancelOrder = 0         
and fulfillmentstatus <> 'NULL'      
group by ProductID              
      
Create table #productfulfill              
(              
ProductID int,              
FulfillQuantity int              
)              
insert into #productfulfill              
select ProductID, sum(Quantity) from OrderDetails (nolock) where User_ID = @User_ID      
and CancelOrder = 0      
and fulfillmentstatus not in ('UnFulfilled','NULL')      
group by ProductID      
              
Create table #productreturn              
(              
ProductID int,              
ReturnQuantity int              
)              
insert into #productreturn              
select p.ProductID, sum(Quantity_Return) as ReturnQuantity from eshop_order_return e (nolock)        
inner join  Products p (nolock)               
on e.ProductName = p.Name         
where e.User_ID = @User_ID               
group by p.ProductID              
              
Create table #productbrowsed              
(              
ProductID int,              
BrowseQuantity int              
)              
insert into #productbrowsed              
select p.ProductID, count(r.ProductID) as BrowseQuantity from RecentlyViews r (nolock)         
inner join Products p (nolock)               
on r.ProductID = p.ProductID              
where p.User_ID = @User_ID               
group by p.ProductID              
              
Create table #productcart              
(              
ProductID int,              
CartQuantity int              
)              
insert into #productcart              
select e.ProductID, sum(Quantity) as CartQuantity               
from eshop_cart_items e(nolock)               
inner join Products p(nolock)              
on e.ProductID = p.ProductID    
inner join Customers c(nolock)    
on e.UserName = c.UserName              
where p.User_ID = @User_ID               
group by e.ProductID              
              
Create table #productwish              
(              
ProductID int,             
WishQuantity int              
)              
insert into #productwish              
select p.ProductID, count(e.ProductID) as WishQuantity               
from Wishlist e(nolock)               
inner join Products p(nolock)              
on e.ProductID = p.ProductID              
where p.User_ID = @User_ID               
group by p.ProductID              
              
select p.User_ID, p.ProductID, p.Name, p.CreatedDate, p.isActive,              
isnull(s.SoldQuantity,0) as TotalSell, isnull(r.ReturnQuantity,0) as TotalReturn,              
isnull(b.BrowseQuantity,0) as TotalBrowse, isnull(c.CartQuantity,0) as TotalCart,              
isnull(w.WishQuantity,0) as Totalwish, P.UnitInStock,isnull(f.FulfillQuantity,0) as TotalFulfill               
from Products p(nolock)              
LEFT OUTER join #productsold s              
on p.ProductID = s.ProductID              
LEFT OUTER join #productreturn r              
on p.ProductID = r.ProductID              
LEFT OUTER join #productbrowsed b              
on p.ProductID = b.ProductID              
LEFT OUTER join #productcart c              
on p.ProductID = c.ProductID              
LEFT OUTER join #productwish w              
on p.ProductID = w.ProductID       
LEFT OUTER join #productfulfill f              
on p.ProductID = f.ProductID        
left outer join #ProductRemain re    
on p.ProductID = re.ProductID            
where p.User_ID = @User_ID 
and p.CategoryID = @CategoryID              
Order by re.RemainQuanity     
              
drop table #productsold              
drop table #productreturn              
drop table #productbrowsed              
drop table #productcart              
drop table #productwish              
              
end


