/* ============================================================
   Procedure: [dbo].[eshop_productwise_list]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- EXEC [].DBO.[eshop_productwise_list] 
CREATE   PROC [dbo].[eshop_productwise_list] --33097 ,'CreatedOn','01/22/2020'       
(          
@User_ID bigint,    
@searchcriteria varchar(100),    
@searchvalue varchar(100)          
)          
as          
begin 
   
create table #Product    
(    
ProductID int,    
Name varchar(150),    
CreatedDate datetime,    
isActive bit,    
User_ID bigint,    
UnitInStock int    
)       
if (@searchcriteria = 'Category')    
begin    
insert into #Product (ProductID, Name, CreatedDate, isActive,User_ID, UnitInStock)    
select p.ProductID, p.Name, p.CreatedDate, p.isActive,P.User_ID, p.UnitInStock     
from Products p(nolock) inner join Categories c(nolock)     
on p.CategoryID = c.CategoryID and p.User_ID= c.User_ID where c.Name like '%'+@searchvalue +'%'  
and c.User_ID = @User_ID    
end     
if (@searchcriteria = 'Status')    
begin    
if (@searchvalue = 'true')    
begin    
insert into #Product (ProductID, Name, CreatedDate, isActive,User_ID, UnitInStock)    
select p.ProductID, p.Name, p.CreatedDate, p.isActive,P.User_ID, p.UnitInStock     
from Products p(nolock) where isActive = 1 and p.User_ID = @User_ID    
end    
else    
begin    
insert into #Product (ProductID, Name, CreatedDate, isActive,User_ID, UnitInStock)    
select p.ProductID, p.Name, p.CreatedDate, p.isActive,P.User_ID, p.UnitInStock     
from Products p(nolock) where isActive = 0 and p.User_ID = @User_ID    
end    
end     
if (@searchcriteria = 'Name')    
begin    
insert into #Product (ProductID, Name, CreatedDate, isActive,User_ID, UnitInStock)    
select p.ProductID, p.Name, p.CreatedDate, p.isActive,P.User_ID, p.UnitInStock     
from Products p(nolock) where p.Name like '%'+@searchvalue +'%' and p.User_ID = @User_ID    
end     
if (@searchcriteria = 'CreatedOn')    
begin    
insert into #Product (ProductID, Name, CreatedDate, isActive,User_ID, UnitInStock)    
select p.ProductID, p.Name, p.CreatedDate, p.isActive,P.User_ID, p.UnitInStock     
from Products p(nolock) where p.User_ID = @User_ID     
and substring(convert(varchar(10),CreatedDate,101),1,10) = substring(convert(varchar(10),@searchvalue,101),1,10)     
end       
          
Create table #productsold          
(          
ProductID int,          
SoldQuantity int          
)          
insert into #productsold          
select o.ProductID, sum(Quantity) from OrderDetails o(nolock)     
inner join #Product p on o.ProductID = p.ProductID    
and p.User_ID = o.User_ID    
where p.User_ID = @User_ID    
and o.CancelOrder = 0    
and o.fulfillmentstatus <> 'NULL'    
group by o.ProductID      
    
Create table #productfulfill            
(            
ProductID int,            
FulfillQuantity int            
)            
insert into #productfulfill       
select o.ProductID, sum(Quantity) from OrderDetails o(nolock)     
inner join #Product p on o.ProductID = p.ProductID    
and p.User_ID = o.User_ID    
where p.User_ID = @User_ID    
and o.CancelOrder = 0    
and o.fulfillmentstatus not in ('UnFulfilled','NULL')    
group by o.ProductID         
          
Create table #productreturn          
(          
ProductID int,          
ReturnQuantity int          
)          
insert into #productreturn          
select p.ProductID, sum(Quantity_Return) as ReturnQuantity from eshop_order_return e (nolock)    
inner join  #Product p (nolock)           
on e.ProductName = p.Name     
where e.User_ID = @User_ID           
group by p.ProductID          
          
Create table #productbrowsed          
(          
ProductID int,          
BrowseQuantity int          
)          
insert into #productbrowsed          
select p.ProductID, count(r.ProductID) as BrowseQuantity from RecentlyViews r (nolock)     
inner join #Product p (nolock)           
on r.ProductID = p.ProductID          
where p.User_ID = @User_ID           
group by p.ProductID          
          
Create table #productcart          
(          
ProductID int,          
CartQuantity int          
)          
insert into #productcart          
select e.ProductID, sum(Quantity) as CartQuantity           
from eshop_cart_items e(nolock)   
inner join #Product p(nolock)          
on e.ProductID = p.ProductID          
where p.User_ID = @User_ID           
group by e.ProductID          
          
Create table #productwish          
(          
ProductID int,         
WishQuantity int          
)         
insert into #productwish          
select p.ProductID, count(e.ProductID) as WishQuantity           
from Wishlist e(nolock)           
inner join #Product p(nolock)          
on e.ProductID = p.ProductID          
where p.User_ID = @User_ID           
group by p.ProductID          
          
select p.User_ID, p.ProductID, p.Name, p.CreatedDate, p.isActive,          
isnull(s.SoldQuantity,0) as TotalSell, isnull(r.ReturnQuantity,0) as TotalReturn,          
isnull(b.BrowseQuantity,0) as TotalBrowse, isnull(c.CartQuantity,0) as TotalCart,          
isnull(w.WishQuantity,0) as Totalwish, P.UnitInStock,isnull(f.FulfillQuantity,0) as TotalFulfill          
from #Product p(nolock)          
LEFT OUTER join #productsold s          
on p.ProductID = s.ProductID          
LEFT OUTER join #productreturn r          
on p.ProductID = r.ProductID          
LEFT OUTER join #productbrowsed b          
on p.ProductID = b.ProductID          
LEFT OUTER join #productcart c          
on p.ProductID = c.ProductID          
LEFT OUTER join #productwish w          
on p.ProductID = w.ProductID       
LEFT OUTER join #productfulfill f            
on p.ProductID = f.ProductID         
where p.User_ID = @User_ID           
Order by p.CreatedDate          
          
drop table #productsold          
drop table #productreturn          
drop table #productbrowsed          
drop table #productcart          
drop table #productwish       
drop table #Product   
          
end 


GO

/* ============================================================
   Procedure: [dbo].[Eshop_Raise_emailNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

            
--exec Eshop_Raise_emailNotification  27, 31028, 'Payment Successful'  ,66
CREATE procedure [dbo].[Eshop_Raise_emailNotification]                                
(                                                                        
                                                                        
@CustomerID INT,                                                                        
@User_ID bigint,                                                     
@event varchar(100),        
@OrderID INT = 0        
)                                                                        
as                                                                         
begin                                                                        
                                                                        
                                      
Declare @compsubject nvarchar(max)='',                                                                        
 @compbody nvarchar(max)=''                                                                        
Declare @subject nvarchar(max)='',                                                                        
 @body nvarchar(max)='', @rexist int =0,@activityid int =0                                                                        
Declare @ToEmailID nvarchar(max) = '',@FromMailID nvarchar(max) = '',@FromMailID1 nvarchar(max) = ''                         
                                            
                                                                     
 select @rexist= COUNT(*), @body = max(n.Messagebody),@subject = max(n.subject)                                                                        
   from eshop_notification n (nolock)                                                     
 where n.User_ID = @User_ID  and n.Activity_Desc =  @event            
 if(@OrderID <> 0)        
 begin        
 select @ToEmailID = Email from ShippingDetails where OrderID = @OrderID and CustomerID = @CustomerID  
 SET @ToEmailID = @ToEmailID +','+(Select Email from User_Detail where User_ID = @User_ID)          
 end        
 else        
 begin        
 select @ToEmailID = Email from Customers where CustomerID = @CustomerID
 SET @ToEmailID = @ToEmailID +','+(Select Email from User_Detail where User_ID = @User_ID)         
 end        
 select @FromMailID = Email from User_Detail where User_ID = @User_ID                     
                                      
                                                                   
                                     
if @rexist <=0                                                                        
 return;                                                                        
else                             
                                                                        
declare @link_Account as bigint, @balance as int=0                                                                  
                                                                      
                                                                        
select @link_Account = User_ID from User_Detail  where User_ID = @User_ID        
                                                                        
declare @spos int =0                                                                        
 Declare @fld varchar(max)=''                                                                      
declare @tbl varchar(max)=''                                                          
declare @word table (fldval varchar (Max))                                                            
                                                         
                                                         
--select @subject                                                                         
while LEN(@subject) > 0                                                                        
begin                                                                        
                                                                       
                                                                     
 select @spos = CHARINDEX( '#' , @subject , 0 )                                                   
 if @spos=0          
 begin                                                              
 set @compsubject = @compsubject+' '+@subject            
 break;                                                              
 end                           
 set @compsubject =@compsubject+ SUBSTRING(@subject,0,@spos)                                                                        
 set @subject = SUBSTRING(@subject,@spos+1,LEN(@subject)-@spos)                  
 select @spos = CHARINDEX( '#' , @subject , 0 )                                                                        
 set @fld = SUBSTRING(@subject,0,@spos)                
 set @subject = SUBSTRING(@subject,@spos+1,LEN(@subject)-@spos)                                                                        
 select @spos = CHARINDEX( '.' , @fld , 0 )                                                                        
 set @tbl = SUBSTRING(@fld,0,@spos)                                                               
 set @fld = SUBSTRING(@fld,@spos+1,LEN(@fld)-@spos)         
                                                                        
 insert @word                                                                        
 exec get_eshop_notification_val @CustomerID,@User_ID ,@tbl, @fld, @OrderID        
                                                              
 select @fld=isnull(fldval,'') from @word                                                                        
 set @compsubject = @compsubject+' '+@fld+' '                                                                        
 declare @sqlstr varchar(max)=''                                                                        
                                                                       
 delete From @word                                                                        
end                                                     
--select @body                                                                        
while LEN(@body) > 0                                                                        
begin                                                                        
                                                                     
 select @spos = CHARINDEX( '#' , @body , 0 )                                                                         
if @spos=0                                                              
 begin                                                              
 set @compbody =@compbody+' '+@body                                                              
 break;                                     
 end                                                                
 set @compbody =@compbody+ SUBSTRING(@body,0,@spos)                                                                        
 set @body = SUBSTRING(@body,@spos+1,LEN(@body)-@spos)                                
 select @spos = CHARINDEX( '#' , @body , 0 )                                                                        
 set @fld = SUBSTRING(@body,0,@spos)                                                                        
 set @body = SUBSTRING(@body,@spos+1,LEN(@body)-@spos)                                                                        
                                                                         
 select @spos = CHARINDEX( '.' , @fld , 0 )                                                                        
 set @tbl = SUBSTRING(@fld,0,@spos)                                                          
 set @fld = SUBSTRING(@fld,@spos+1,LEN(@fld)-@spos)                                                                        
 --select @spos,@compsubject, @body, @fld,@tbl                                                                        
 insert @word                                    
 exec get_eshop_notification_val  @CustomerID, @User_ID ,@tbl, @fld, @OrderID        
 select @fld=fldval from @word                                                    
  --select @OrderID,@CustomerID ,@tbl, @fld         
                                    
 set @compbody = @compbody+' '+@fld+' '                                                                        
 delete From @word                                                                        
                                   
                                                                   
end          
                                                       
select @body= @compbody, @subject = @compsubject                                                                        
---- This will create a random number between 1 and 999                                                                              
select ROW_NUMBER() over( order by item) rno,* into #nomobile                                                        
from dbo.SplitString(@ToEmailID, ',')                                                      
                                                    
Declare @email_cnt as int =0                                                    
select @email_cnt = COUNT(*) from #nomobile                                   
                            
                                             
                                               
                                                             
SELECT TOP 1 @balance=isnull(balance,0) FROM   MailCreditDetails with(nolock) WHERE  --m_id = @m_id  AND                                                                   
USER_ID = @link_Account  ORDER BY credit_id DESC                                                                    
                                                        
--if (@balance-@email_cnt) < 0 and (@event != 'User Activation Email'   or   @event != 'Signup')                                                   
--  Begin                                                        
--     select 'Balance is not sufficient'                                                        
--  End                                                        
                                                          
                                                                  
                                                    
                                                                  
DECLARE @Random INT;                                                                              
  DECLARE @Upper INT;                                                                              
  DECLARE @Lower INT                                                                              
                        
  Declare @BatchID bigint                                                                              
                                                                                
                       
      begin tran                                                                        
     insert into GetBatchRecord (User_id,RandNum)                                                                                      
        values(@User_ID,@User_ID)                                                                                      
   select @BatchID = SCOPE_IDENTITY()                              
                                      
        delete from GetBatchRecord  where BatchID=@BatchID                                      
   commit                                                                           
if (@balance-@email_cnt) > 0                                                                  
begin                       
                                                 
  insert into CloneEmailsFilter(                                                                              
    Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName                                                                              
    ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID                            
  ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime                                                                              
    ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source                                                                           
     )                                                                              
     select @FromMailID,item,@Subject,'',@body                                                                        
      , GETDATE(),@User_ID,@User_ID,@FromMailID,                                                                              
     @BatchID,1,'','','',@body ,1,0,1,                                                        
     'E-Shop'  from #nomobile                                  
                                                         
                                                            
                                                                             
                                                
end                     
else                    
begin                    
                    
set @Subject = 'Insufficient Balance'         
if (@OrderID <> 0 )        
begin                   
set @body = 'Due to insuficient balance, Not able to send Order details but Order has been generated on EShop portal with Order No:'+ CONVERT(VARCHAR(20),@OrderID)                    
end        
else        
begin        
set @body = 'Due to insuficient balance, Not able to send details.'        
end                    
                    
select @FromMailID1= Email from dbo.User_Detail                                                                         
 where User_ID = 335                 
 insert into CloneEmailsFilter(                                                                              
    Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName                                                                              
    ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID                                                                              
  ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime                                                                  
    ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source                                                                              
     )                    
  select @FromMailID1,@FromMailID,@Subject,'',@body                                                                        
      , GETDATE(),335,335,@FromMailID1,                                                                              
     @BatchID,1,'','','',@body ,1,0,1,                                                                            
     'E-Shop'  from #nomobile                    
                    
end                                                                       
end 


GO

