/* ============================================================
   Procedure: [dbo].[Eshop_Raise_smsNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec Eshop_Raise_smsNotification 30,33097 , 'New Login Create'           
CREATE procedure [dbo].[Eshop_Raise_smsNotification]                                                                
(                                                                        
@CustomerID INT,                                                                        
@User_ID bigint,                                                     
@event varchar(100),        
@OrderID INT = 0        
)                                                                        
as                                                                         
begin                                                                
                                                              
                                                             
                                                              
Declare @compsubject nvarchar(max)='',                                                              
 @compbody nvarchar(max)='', @isunicode bit = 0,@SenderID nvarchar(250) ='', @SenderID1 nvarchar(250) =''                                            
Declare @subject nvarchar(max)=''           
Declare @BatchID bigint    ,                                                        
 @body nvarchar(max)='', @rexist int =0,@activityid int =0                                                              
Declare @ToMobile_No nvarchar(max) = '',@FrommobileID nvarchar(max) = ''        
 DECLARE @Random INT;                                                                    
  DECLARE @Upper INT;                                                                    
  DECLARE @Lower INT                      
                
                  
                                                             
                                                          
 select @rexist= COUNT(*)                                                            
   from eshop_notification                                                              
 where User_ID = @User_ID  and Activity_Desc =  @event          
         
 select @body = smsbody      from eshop_notification                                                              
 where User_ID = @User_ID  and Activity_Desc =  @event                                                            
                                            
                             
 SET @ToMobile_No = (Select cast(cast(Mobile as bigint) as nvarchar(max)) from User_Detail where User_ID = @User_ID)                         
 SET @ToMobile_No = @ToMobile_No +','+(Select Mobile1  from Customers where CustomerID = @CustomerID)      
 set @SenderID =  isnull((select top 1 sender_name from default_senderid where USER_ID= @User_ID AND sender_id<>0),'TXTSMS')                   
                            
                                                            
if @rexist <=0                                                              
 return;                                                              
else                                                              
                                       
                                                        
declare @link_Account as bigint, @balance as int=0                                                        
                                        
                                                         
 --@FrommobileID= virtual_sms,                                                             
--select @link_Account = User_ID from User_Detail  where User_ID = @User_ID                                                              
   
 select @link_Account = User_ID from User_Detail  where User_ID = @User_ID                                                                                                                          
  
declare @spos int =0 --,  @subject varchar(max)                                                              
 Declare @fld varchar(max)=''                                                              
declare @tbl varchar(max)=''                                                              
declare @word table (fldval varchar (Max))                                                              
                                               
                      
                                                            
--select @body           
while LEN(@body) > 0                                                              
begin                                                              
                                                           
 select @spos = CHARINDEX( '#' , @body , 0 )                                                               
if @spos=0                                                    
 begin                                                    
 set @compbody =@compbody+' '+@body                                                    
 break;                                                    
 end                                                      
 set @compbody =@compbody+ SUBSTRING(@body,0,@spos)                                                              
 set @body = SUBSTRING(@body,@spos+1,LEN(@body)-@spos)                                                              
 select @spos = CHARINDEX( '#' , @body , 0 )                                                              
 set @fld = SUBSTRING(@body,0,@spos)                               
 set @body = SUBSTRING(@body,@spos+1,LEN(@body)-@spos)                                                              
                                                               
 select @spos = CHARINDEX( '.' , @fld , 0 )                                                              
 set @tbl = SUBSTRING(@fld,0,@spos)                                                              
 set @fld = SUBSTRING(@fld,@spos+1,LEN(@fld)-@spos)                               
                                            
 insert @word                                                              
 exec get_eshop_notification_val  @CustomerID,@User_ID ,@tbl, @fld, @OrderID                                   
                                                 
 select @fld=isnull(fldval,'') from @word                                                              
 set @compbody = @compbody+' '+@fld+' '                                                              
 delete From @word                                                              
                                                        
                                                            
end                                                              
                                            
select @body= @compbody                                         
                                        
---- This will create a random number between 1 and 999                                                                    
select ROW_NUMBER() over( order by item) rno,* into #nomobile                                            
from dbo.SplitString(@ToMobile_No, ',')                                             
                                        
declare @maxrow BIGINT, @minrow BIGINT                                            
select @maxrow= MAX(rno),@minrow = MIN(rno)  From #nomobile                                   
                                            
                                            
                                                     
      DECLARE @CurrentBalance BIGINT = (                                                              
             SELECT TOP 1 isnull(cd.Balance,0)                                                              
  FROM   Credit_Details AS cd                                                              
             WHERE  cd.[User_ID] = @link_Account                                                              
             ORDER BY                                                              
             cd.Credit_ID DESC )                                          
                 
                                            
select @maxrow= (case when @isunicode=0 and len(@body)<=160  then 1                                                           
 when @isunicode=0 and LEN(@body)>160 then ceiling(LEN(@body)/cast(153 as FLOat))                                                           
  when @isunicode=1 and len(@body)<=70 then 1                                             
  else ceiling(LEN(@body)/cast(67 as float)) end )*@maxrow                                            
                      
 set @CurrentBalance = @CurrentBalance-@maxrow                                             
if @CurrentBalance <= 0                                              
  Begin                                              
     --select 'Balance is not sufficient'              
                                                                 
                                           
                                                                  
                                
      begin tran                                                              
     insert into GetBatchRecord (User_id,RandNum)                                                                            
     values(@User_ID,@User_ID)                                                                            
     select @BatchID = scope_identity()                              
     delete from GetBatchRecord  where batchid=@batchid                              
      commit               
 --select @link_Account=User_ID from dbo.User_Detail                                                               
 --where User_ID = 335              
   
 select @link_Account=User_ID from dbo.User_Detail                                                               
  where User_ID = 335              
   
                  
   select @SenderID1 = isnull(SenderID,'')                                                      
   from Serv_SMS_Notification_Agent                                                              
 where ParentID = 335                              
                            
 set @body = 'Due to insuficient balance, Not able to send sms.'              
              
    INSERT INTO CloneMessageDeliveryStatus                                                                
    (BatchID, Mobile, Message, MessageStatus, SenderID,                                                                
   MessageInsertDate, ScheduledDate, ScheduledTime,                                                                
   SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                                                                
   ValidNo, IsPrority, IsAllowDND, DBType)                                                            
  select @BatchID, @SenderID, @body, null, @SenderID1,                                                                
   GETDATE(), GETDATE(), '',                                              
   (                                                                
     SELECT TOP 1 ud.SmppID                                                                
     FROM   User_Detail AS ud                                                                
     WHERE  ud.[User_ID] = @link_Account                                                                
    )   AS SmppID, @link_Account, @IsUniCode, 0, 0, 0,                                                                
   1, 1, 0, 0                                         
   from #nomobile                  
                                              
  End                                
else                                            
begin                                                        
                                                                   
                                             
                                                                
                             
      begin tran                                                              
     insert into GetBatchRecord (User_id,RandNum)                                                                            
     values(@User_ID,@User_ID)                                                                            
     select @BatchID = scope_identity()                              
     delete from GetBatchRecord  where batchid=@batchid                              
      commit               
              
                            
                                          
  INSERT INTO CloneMessageDeliveryStatus                                                                
    (BatchID, Mobile, Message, MessageStatus, SenderID,                                                                
   MessageInsertDate, ScheduledDate, ScheduledTime,                                                                
   SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet,                               
   ValidNo, IsPrority, IsAllowDND, DBType)                                                            
  select @BatchID, item, @body, null, @SenderID,                                                                
   GETDATE(), GETDATE(), '',                                              
   (                                                                
     SELECT TOP 1 ud.SmppID             
     FROM   User_Detail AS ud                                                                
     WHERE  ud.[User_ID] = @link_Account                                                                
    )   AS SmppID, @link_Account, @IsUniCode, 0, 0, 0,                                           
   1, 1, 0, 0                                         
   from #nomobile                                
end                                                        
end 


GO

