/* ============================================================
   Procedure: [dbo].[eshop_update_cart]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_update_cart  
(@UserName    VARCHAR(50),   
 @ProductName VARCHAR(150),   
 @Variant     VARCHAR(50),   
 @Quantity    INT,   
 @Price       NUMERIC(18, 2)  
)  
AS  
    BEGIN  
        DECLARE @TotalAmount decimal(18, 2);  
        SET @TotalAmount = (@Quantity * @Price);  
  
  if(@Variant = 'default')  
  begin  
   set @Variant = null;  
  end  
  
        UPDATE eshop_cart_items  
          SET   
              Quantity = @Quantity,   
              Price = @Price,   
              TotalAmount = @TotalAmount  
        WHERE UserName = @UserName  
              AND ProductName = @ProductName  
              AND ISNULL(Variant, '') = ISNULL(@Variant, '');  
    END;


