/* ============================================================
   Procedure: [dbo].[eshop_update_inventory_manual]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_update_inventory_manual              
(              
@ProductName varchar(150),              
@Quantity Int,              
@Variant Varchar(500),              
@User_ID bigint,              
@Mode varchar(100),              
@Remarks varchar(500),        
@Vendor   varchar(250)        
)              
as              
begin          
if(@Variant = 'default')            
begin            
set @Variant = '';            
end    
if(@Remarks = 'default')            
begin            
set @Remarks = '';            
end               
Declare @ProductID int       
Declare @Balance int             
set @ProductID = (select distinct ProductID from Products (nolock) where Name = @ProductName and User_ID = @User_ID)              
set @Balance = (select Top 1 Balance from eshop_product_Invenory (nolock) where ProductID = @ProductID Order by ID desc)      
IF (@Mode like '%Add%' or @Mode like '%Plus%')      
begin      
set @Balance = @Balance + @Quantity      
end      
else      
begin      
set @Balance = @Balance - @Quantity      
end       
      
insert into eshop_product_Invenory(ProductID,ProductName,Variant,Quantity,ModifiedDate,ModifiedType, Remarks, User_ID,Vendor, Balance)        
Values(@ProductID, @ProductName,@Variant,@Quantity,getdate(),@Mode, @Remarks,@User_ID,@Vendor,@Balance)              
              
IF (@Mode like '%Add%' or @Mode like '%Plus%')             
BEGIN           
if  (@Variant = '')          
BEGIN          
UPDATE Products              
SET UnitInStock = UnitInStock + @Quantity              
WHERE Name = @ProductName AND User_ID = @User_ID          
END          
ELSE          
BEGIN          
UPDATE Variant_detail              
SET INVENTORY = INVENTORY + @Quantity              
WHERE PRODUCTNAME = @ProductName AND Variant = @Variant AND User_ID = @User_ID              
END          
END              
ELSE              
BEGIN           
if  (@Variant = '')          
BEGIN          
UPDATE Products              
SET UnitInStock = UnitInStock - @Quantity              
WHERE Name = @ProductName AND User_ID = @User_ID          
END          
ELSE          
BEGIN             
UPDATE Variant_detail              
SET INVENTORY = INVENTORY - @Quantity              
WHERE PRODUCTNAME = @ProductName AND Variant = @Variant AND User_ID = @User_ID              
END          
END              
               
end


GO

