--exec eshop_update_product @ProductID=139,@Name=N'Magic Plain Shirt',@SupplierID=15,@CategoryID=150,@UnitPrice=660.00,@OldPrice=0.00,@UnitWeight=N'0',@UnitInStock=0,@ImageURL=N'default',@Picture1=N'default',@Picture2=N'default',@Picture3=N'default',@Picture4=N'default',@Picture5=N'default',@AltText=N'default',@LongDescription=N'<p>Magic Plain Shirt</p>',@StockKeepingUnit=N'default',@Barcode=N'default',@HarmonizedSystemCode=N'5.00',@PublicationStartDate='2020-01-11 00:00:00', @Country_Name=default,@User_ID=33859,@CreatedDate='2020-06-06 17:44:50.510', @Video=N'default', @Return_days=0,@Exchange_days=0,@Shipped_days=0,@TaxName1=N'GST',@Tax1=0,@isActive=1,@Title=N'Plain magic shirt',@Meta_description=N'Plain magic shirt',@Meta_Tags=N'Plain magic shirt',@PageName=N'Magic-Plain-Shirt',@ProductAvailable=0,@ReOrderLevel=20,@minorderquantity=1,@maxorderquantity=9999
CREATE   PROC eshop_update_product        
(        
@ProductID int,        
@Name varchar(150),        
@SupplierID int,        
@CategoryID int,        
@UnitPrice numeric(18,2),        
@OldPrice numeric(18,2),        
@UnitWeight varchar(50),        
@UnitInStock int,        
@ImageURL varchar(500),        
@AltText varchar(50),        
@LongDescription varchar(max),        
@Picture1  varchar(500),        
@Picture2 varchar(500),        
@Picture3 varchar(500),        
@Picture4 varchar(500),        
@StockKeepingUnit   varchar(100),        
@Picture5  varchar(500),        
@Barcode  varchar(100),        
@HarmonizedSystemCode  varchar(200),        
@PublicationStartDate datetime=null,        
@Country_Name  varchar(500)=null,        
@User_ID bigint,        
@CreatedDate datetime,        
@Video  varchar(500),        
@Return_days int,        
@Exchange_days int,        
@Shipped_days bit,        
@TaxName1 varchar(50),        
@Tax1 numeric(18,2),        
@isActive bit,        
@Title varchar(150),        
@Meta_description  varchar(100),        
@Meta_Tags  varchar(100),        
@PageName  varchar(150),      
@ProductAvailable bit,  
@ReOrderLevel INT,  
@minorderquantity INT,  
@maxorderquantity INT       
)        
as         
begin        
        
if(@Picture1 = 'default')        
begin        
set @Picture1 = (select Picture1 from Products where ProductID = @ProductID);        
end        
if(@Picture2 = 'default')        
begin        
set @Picture2 = (select Picture2 from Products where ProductID = @ProductID);        
end        
if(@Picture3 = 'default')        
begin        
set @Picture3 = (select Picture3 from Products where ProductID = @ProductID);        
end        
if(@Picture4 = 'default')        
begin        
set @Picture4 = (select Picture4 from Products where ProductID = @ProductID);        
end        
if(@Picture5 = 'default')        
begin        
set @Picture5 = (select Picture5 from Products where ProductID = @ProductID);        
end        
if(@ImageURL = 'default')        
begin        
set @ImageURL = (select ImageURL from Products where ProductID = @ProductID);        
end        
if(@AltText = 'default')        
begin        
set @AltText = (select AltText from Products where ProductID = @ProductID);        
end        
if(@StockKeepingUnit = 'default')        
begin        
set @StockKeepingUnit = (select StockKeepingUnit from Products where ProductID = @ProductID);        
end        
if(@Barcode = 'default')        
begin        
set @Barcode = (select Barcode from Products where ProductID = @ProductID);        
end        
if(@HarmonizedSystemCode = 'default')        
begin        
set @HarmonizedSystemCode = (select HarmonizedSystemCode from Products where ProductID = @ProductID);        
end        
if(@Video = 'default')        
begin        
set @Video = (select Video from Products where ProductID = @ProductID);        
end        
        
update products        
set Name = @Name, LongDescription = @LongDescription, SupplierID = @SupplierID,CategoryID = @CategoryID, UnitPrice = @UnitPrice,        
OldPrice = @OldPrice, UnitWeight =  @UnitWeight,UnitInStock = @UnitInStock, ImageURL = @ImageURL,AltText=@AltText, Picture1 = isnull(@Picture1,Picture1),        
Picture2 = isnull(@Picture2,Picture2), Picture3 = isnull(@Picture3,Picture3), Picture4 = isnull(@Picture4,Picture4), Picture5 = isnull(@Picture5,Picture5), StockKeepingUnit = @StockKeepingUnit, Barcode = @Barcode,        
HarmonizedSystemCode = @HarmonizedSystemCode,PublicationStartDate = @PublicationStartDate,  Country_Name = @Country_Name, CreatedDate = @CreatedDate,        
Video = @Video, Return_days = @Return_days, Exchange_days = @Exchange_days, Shipped_days = @Shipped_days, TaxName1 = @TaxName1, Tax1 = @Tax1,        
isActive = @isActive, Title = @Title, Meta_description = @Meta_description, Meta_Tags = @Meta_Tags, PageName = @PageName,       
ProductAvailable = @ProductAvailable , ReOrderLevel = @ReOrderLevel, minorderquantity = @minorderquantity, maxorderquantity = @maxorderquantity  
where ProductID = @ProductID and User_ID = @User_ID        
        
end



