/* ============================================================
   Procedure: [dbo].[eshop_variant]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec eshop_variant @PRODUCTNAME=N'Roller Pen',@User_ID=33097
-- eshop_variant 'Bellies For Women',33097        
CREATE   PROC [dbo].[eshop_variant]
(
	@PRODUCTNAME VARCHAR(150),
	@User_ID     INT
)
AS
BEGIN
	DECLARE @V_COUNT INT;
	SET @V_COUNT = (SELECT COUNT(DISTINCT [NAME])
					FROM   VARIANTS(NOLOCK)
					WHERE  [PRODUCTNAME] = @PRODUCTNAME
						   AND User_ID = @User_ID);

	SELECT DISTINCT
		   [NAME]
	INTO [#VARIANT]
	FROM   VARIANTS(NOLOCK)
	WHERE  [PRODUCTNAME] = @PRODUCTNAME
		   AND User_ID = @User_ID;

	SELECT *
	INTO [#Variant_detail]
	FROM   Variant_detail(NOLOCK)
	WHERE  1 = 2;

	IF @V_COUNT = 1
	BEGIN
		INSERT INTO #Variant_detail
			   SELECT [v].[PRODUCTNAME] AS [PRODUCTNAME],
					  [v].[V_VALUE] AS [Variant],
					  [v].[PRICE] AS [PRICE],
					  [v].[StockKeepingUnit] AS [StockKeepingUnit],
					  [v].[INVENTORY] AS [INVENTORY],
					  [v].[Barcode] AS [Barcode],
					  [v].User_ID AS User_ID,
					  [v].[NAME] AS [Variant_Name],
					  [v].[Date_Modified] AS [Date_Modified]
			   FROM   VARIANTS AS v(NOLOCK)
			   WHERE  [v].User_ID = @User_ID
					  AND [v].[PRODUCTNAME] = @PRODUCTNAME;
	END;
	ELSE
	BEGIN
		IF @V_COUNT = 2
		BEGIN
			INSERT INTO #Variant_detail
				   SELECT DISTINCT
						  [v1].[PRODUCTNAME] AS [PRODUCTNAME],
						  [v1].[V_VALUE] + '#' + [v2].[V_VALUE] AS
						  [Variant],
						  [v1].[PRICE] AS [PRICE],
						  [v1].[StockKeepingUnit] AS [StockKeepingUnit],
						  [v1].[INVENTORY] AS [INVENTORY],
						  [v1].[Barcode] AS [Barcode],
						  [v1].User_ID AS User_ID,
						  [v1].[NAME] + '#' + [v2].[NAME] AS
						  [Variant_Name],
						  [v1].[Date_Modified] AS [Date_Modified]
				   FROM   VARIANTS AS v1(NOLOCK) CROSS JOIN VARIANTS AS v2
				   (NOLOCK)
				   WHERE  [v1].[PRODUCTNAME] = @PRODUCTNAME
						  AND [v1].User_ID = @User_ID
						  AND [v1].[PRODUCTNAME] = [v2].[PRODUCTNAME]
						  AND [v1].User_ID = [v2].User_ID
						  AND [v1].[NAME] <> [v2].[NAME]
						  AND [v1].[NAME] = (SELECT [NAME]
											 FROM   (SELECT [NAME],
															ROW_NUMBER()
															OVER(
															ORDER BY
															[NAME] ASC) AS
															[rownumber]
													 FROM   [#VARIANT]) AS
													 [VARIANTS]
											 WHERE  [rownumber] = 1)
						  AND [v2].[NAME] = (SELECT [NAME]
											 FROM   (SELECT [NAME],
															ROW_NUMBER()
															OVER(
															ORDER BY
															[NAME] ASC) AS
															[rownumber]
													 FROM   [#VARIANT]) AS
													 [VARIANTS]
											 WHERE  [rownumber] = 2);
		END;
		ELSE
		BEGIN
			IF @V_COUNT = 3
			BEGIN
				INSERT INTO #Variant_detail
					   SELECT DISTINCT
							  [v1].[PRODUCTNAME] AS [PRODUCTNAME],
							  [v1].[V_VALUE] + '#' + [v2].[V_VALUE] + '#'
							  + [v3].[V_VALUE],
							  [v1].[PRICE] AS [PRICE],
							  [v1].[StockKeepingUnit] AS
							  [StockKeepingUnit],
							  [v1].[INVENTORY] AS [INVENTORY],
							  [v1].[Barcode] AS [Barcode],
							  [v1].User_ID AS User_ID,
							  [v1].[NAME] + '#' + [v2].[NAME] + '#' + [v3]
							  .[NAME],
							  [v1].[Date_Modified]
					   FROM   VARIANTS AS v1(NOLOCK) CROSS JOIN VARIANTS
					   AS v2(NOLOCK) CROSS JOIN VARIANTS AS v3(NOLOCK)
					   WHERE  [v1].[PRODUCTNAME] = @PRODUCTNAME
							  AND [v1].User_ID = @User_ID
							  AND [v1].[PRODUCTNAME] = [v2].[PRODUCTNAME]
							  AND [v1].User_ID = [v2].User_ID
							  AND [v1].[PRODUCTNAME] = [v3].[PRODUCTNAME]
							  AND [v1].User_ID = [v3].User_ID
							  AND [v2].[PRODUCTNAME] = [v3].[PRODUCTNAME]
							  AND [v2].User_ID = [v3].User_ID
							  AND [v1].[NAME] <> [v2].[NAME]
							  AND [v1].[NAME] <> [v3].[NAME]
							  AND [v3].[NAME] <> [v2].[NAME]
							  AND [v1].[NAME] = (SELECT [NAME]
												 FROM   (SELECT [NAME],
																ROW_NUMBER
																() OVER(
																ORDER BY
																[NAME] ASC)
																AS [rownumber]
														 FROM   [#VARIANT])
														 AS [VARIANTS]
												 WHERE  [rownumber] = 1)
							  AND [v2].[NAME] = (SELECT [NAME]
												 FROM   (SELECT [NAME],
																ROW_NUMBER
																() OVER(
																ORDER BY
																[NAME] ASC)
																AS [rownumber]
														 FROM   [#VARIANT])
														 AS [VARIANTS]
												 WHERE  [rownumber] = 2)
							  AND [v3].[NAME] = (SELECT [NAME]
												 FROM   (SELECT [NAME],
																ROW_NUMBER
																() OVER(
																ORDER BY
																[NAME] ASC)
																AS [rownumber]
														 FROM   [#VARIANT])
														 AS [VARIANTS]
												 WHERE  [rownumber] = 3);
			END;
			ELSE
			BEGIN
				IF @V_COUNT = 4
				BEGIN
					INSERT INTO #Variant_detail
						   SELECT DISTINCT
								  [v1].[PRODUCTNAME] AS [PRODUCTNAME],
								  [v1].[V_VALUE] + '#' + [v2].[V_VALUE] +
								  '#' + [v3].[V_VALUE] + '#' + [v4].[V_VALUE] AS [Variant],
								  [v1].[PRICE] AS [PRICE],
								  [v1].[StockKeepingUnit] AS
								  [StockKeepingUnit],
								  [v1].[INVENTORY] AS [INVENTORY],
								  [v1].[Barcode] AS [Barcode],
								  [v1].User_ID AS User_ID,
								  [v1].[NAME] + '#' + [v2].[NAME] + '#' +
								  [v3].[NAME] + '#' + [v4].[NAME] AS [Variant_Name],
								  [v1].[Date_Modified] AS [Date_Modified]
						   FROM   VARIANTS AS v1(NOLOCK) CROSS JOIN
						   VARIANTS AS v2(NOLOCK) CROSS JOIN VARIANTS AS
						   v3(NOLOCK) CROSS JOIN VARIANTS AS v4(NOLOCK)
						   WHERE  [v1].[PRODUCTNAME] = @PRODUCTNAME
								  AND [v1].User_ID = @User_ID
								  AND [v1].[PRODUCTNAME] = [v2].
								  [PRODUCTNAME]
								  AND [v1].User_ID = [v2].User_ID
								  AND [v1].[PRODUCTNAME] = [v3].
								  [PRODUCTNAME]
								  AND [v1].User_ID = [v3].User_ID
								  AND [v2].[PRODUCTNAME] = [v3].
								  [PRODUCTNAME]
								  AND [v2].User_ID = [v3].User_ID
								  AND [v1].[PRODUCTNAME] = [v4].
								  [PRODUCTNAME]
								  AND [v1].User_ID = [v4].User_ID
								  AND [v4].[PRODUCTNAME] = [v3].
								  [PRODUCTNAME]
								  AND [v4].User_ID = [v3].User_ID
								  AND [v2].[PRODUCTNAME] = [v4].
								  [PRODUCTNAME]
								  AND [v2].User_ID = [v4].User_ID
								  AND [v1].[NAME] <> [v2].[NAME]
								  AND [v1].[NAME] <> [v3].[NAME]
								  AND [v3].[NAME] <> [v2].[NAME]
								  AND [v3].[NAME] <> [v4].[NAME]
								  AND [v4].[NAME] <> [v1].[NAME]
								  AND [v4].[NAME] <> [v2].[NAME]
								  AND [v1].[NAME] = (SELECT [NAME]
													 FROM   (SELECT [NAME],
																	ROW_NUMBER
																	()
																	OVER(
																	ORDER
																	BY [NAME] ASC)
																	AS [rownumber]
															 FROM
															 [#VARIANT])
															 AS [VARIANTS]
													 WHERE  [rownumber] =
													 1)
								  AND [v2].[NAME] = (SELECT [NAME]
													 FROM   (SELECT [NAME],
																	ROW_NUMBER
																	()
																	OVER(
																	ORDER
																	BY [NAME] ASC)
																	AS [rownumber]
															 FROM
															 [#VARIANT])
															 AS [VARIANTS]
													 WHERE  [rownumber] =
													 2)
								  AND [v3].[NAME] = (SELECT [NAME]
													 FROM   (SELECT [NAME],
																	ROW_NUMBER
																	()
																	OVER(
																	ORDER
																	BY [NAME] ASC)
																	AS [rownumber]
															 FROM
															 [#VARIANT])
															 AS [VARIANTS]
													 WHERE  [rownumber] =
													 3)
								  AND [v4].[NAME] = (SELECT [NAME]
													 FROM   (SELECT [NAME],
																	ROW_NUMBER
																	()
																	OVER(
																	ORDER
																	BY [NAME] ASC)
																	AS [rownumber]
															 FROM
															 [#VARIANT])
															 AS [VARIANTS]
													 WHERE  [rownumber] =
													 4);
				END;
			END;
		END;
	END;

	/*
	IF EXISTS(SELECT '*'
			  FROM   #Variant_detail AS V INNER JOIN Variant_detail AS V2
			  ON V.PRODUCTNAME = V2.PRODUCTNAME
				 AND V.User_ID = V2.User_ID
				 AND V.Variant = V2.Variant)
	BEGIN
		UPDATE V2 SET [V2].[Variant] = [V].[Variant], [V2].[PRICE] = [V].
		[PRICE], [V2].[StockKeepingUnit] = [V].[StockKeepingUnit], [V2].
		[INVENTORY] = [V].[INVENTORY], [V2].[Barcode] = [V].[Barcode],
		[V2].[Date_Modified] = GETDATE()
		FROM [#Variant_detail] [V] INNER JOIN [Variant_detail] [V2]
		ON [V].[PRODUCTNAME] = [V2].[PRODUCTNAME]
		   AND [V].User_ID = [V2].User_ID
		   AND [V].[Variant] = [V2].[Variant];
	END;
	ELSE
	BEGIN
		INSERT INTO               Variant_detail( [PRODUCTNAME],
												  [Variant],
												  [PRICE],
												  [StockKeepingUnit],
												  [INVENTORY],
												  [Barcode],
												  User_ID,
												  [Variant_Name],
												  [Date_Modified] )
			   SELECT [PRODUCTNAME],
					  [Variant],
					  [PRICE],
					  [StockKeepingUnit],
					  [INVENTORY],
					  [Barcode],
					  User_ID,
					  [Variant_Name],
					  GETDATE()
			   FROM   #Variant_detail;
	END;
	*/

	DECLARE @ProductID INT, @SupplierID INT, @Vendor VARCHAR(150);
	SET @ProductID = (SELECT TOP 1 [ProductID]
					  FROM         Products(NOLOCK)
					  WHERE        User_ID = @User_ID
								   AND [Name] = @PRODUCTNAME);
	SET @SupplierID = (SELECT TOP 1 [SupplierID]
					   FROM         Products(NOLOCK)
					   WHERE        User_ID = @User_ID
									AND [ProductID] = @ProductID);
	SET @Vendor = (SELECT [CompanyName]
				   FROM   Suppliers(NOLOCK)
				   WHERE  [SupplierID] = @SupplierID);
	
	IF EXISTS(SELECT * FROM   Products(NOLOCK) WHERE  User_ID = @User_ID AND [Name] = @PRODUCTNAME)
	BEGIN
		/*IF NOT EXISTS(SELECT *
					  FROM   Variant_detail AS v(NOLOCK) LEFT OUTER JOIN
					  eshop_product_Invenory AS p(NOLOCK)
					  ON v.PRODUCTNAME = p.ProductName
						 AND v.Variant = p.Variant
						 AND v.Date_Modified = p.ModifiedDate
					  WHERE  [v].User_ID = @User_ID
							 AND [v].[PRODUCTNAME] = @PRODUCTNAME)
		BEGIN
			INSERT INTO                       eshop_product_Invenory(
			[ProductID],
			[ProductName],
			[Variant],
			[Quantity],
			[ModifiedDate],
			[ModifiedType],
			[Remarks],
			User_ID,
			[Vendor],
			[Balance] )
				   SELECT DISTINCT
						  @ProductID,
						  [v].[PRODUCTNAME],
						  [v].[Variant],
						  [v].[INVENTORY],
						  [v].[Date_Modified],
						  'Add Product',
						  'Add Product',
						  @User_ID,
						  @Vendor,
						  [v].[INVENTORY]
				   FROM   Variant_detail AS v(NOLOCK) LEFT OUTER JOIN
				   Products AS p(NOLOCK)
				   ON v.PRODUCTNAME = p.Name
					  AND v.User_ID = p.User_ID
				   WHERE  [v].User_ID = @User_ID
						  AND [v].[PRODUCTNAME] = @PRODUCTNAME;
		END;*/
		SELECT DISTINCT
			   [p].[ProductID] AS [ID],
			   [v].[PRODUCTNAME] AS [PRODUCTNAME],
			   [v].[Variant] AS [Variant],
			   [v].[PRICE] AS [PRICE],
			   [v].[StockKeepingUnit] AS [StockKeepingUnit],
			   [v].[INVENTORY] AS [INVENTORY],
			   [v].[Barcode] AS [Barcode],
			   [v].User_ID AS User_ID,
			   [v].[Variant_Name] AS [NAME],
			   [v].[Date_Modified] AS [Date_Modified]
		FROM   Variant_detail AS v(NOLOCK) LEFT OUTER JOIN Products AS p(
		NOLOCK)
		ON v.PRODUCTNAME = p.Name
		   AND v.User_ID = p.User_ID
		WHERE  [v].User_ID = @User_ID
			   AND [v].[PRODUCTNAME] = @PRODUCTNAME;
	END;
	--else  
	--if not exists(select * from   Variant_detail v(nolock) left Outer Join eshop_product_Invenory p(nolock)        
	--on v.PRODUCTNAME = p.ProductName and v.Variant = p.Variant and v.Date_Modified = p.ModifiedDate    
	--where v.User_ID = @User_ID and v.PRODUCTNAME = @PRODUCTNAME   )  
	--begin   
	--insert into eshop_product_Invenory(ProductID,ProductName,Variant,Quantity,ModifiedDate,ModifiedType, Remarks, User_ID, Vendor, Balance)        
	--select distinct @ProductID,v.PRODUCTNAME,v.Variant,v.INVENTORY,v.Date_Modified, 'Add Product','Add Product',@User_ID, @Vendor, v.INVENTORY FROM  Variant_detail V(NOLOCK)       
	--WHERE V.PRODUCTNAME = @PRODUCTNAME AND V.User_ID = @User_ID    
	--end  
	--SELECT distinct V.ID,      
	--v.PRODUCTNAME PRODUCTNAME,              
	--v.Variant Variant,              
	--v.PRICE PRICE,              
	--v.StockKeepingUnit StockKeepingUnit,              
	--v.INVENTORY INVENTORY,              
	--v.Barcode Barcode,              
	--v.User_ID User_ID,              
	--v.Variant_Name NAME,               
	--v.Date_Modified  Date_Modified       
	--FROM  Variant_detail V(NOLOCK)       
	--WHERE V.PRODUCTNAME = @PRODUCTNAME AND V.User_ID = @User_ID        
	DROP TABLE #VARIANT;
	DROP TABLE #Variant_detail;
END;



GO

