/* ============================================================
   Procedure: [dbo].[eshop_variant_list_search]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC eshop_variant_list_search  --33097                
(                      
@User_ID int ,
@searchvalue varchar(500),
@searchcriteria varchar(500)                    
)                      
as                      
begin    
  
if (@searchcriteria = 'Product')
begin 
select p.ProductID as ID, p.ProductName PRODUCTNAME, p.Variant Variant, ISNULL(v.PRICE,0) PRICE, isnull(v.StockKeepingUnit,'') StockKeepingUnit, p.Balance INVENTORY, isnull(v.Barcode,'') Barcode, p.User_ID User_ID, isnull(v.Variant_Name,'') NAME, p.ModifiedDate Date_Modified  
from eshop_product_Invenory p(nolock)  
left outer join Variant_detail v(nolock)  
on p.User_ID = v.User_ID and p.ProductName = v.PRODUCTNAME and p.Variant = v.Variant  
where p.User_ID = @User_ID 
and p.ProductName like '%' + @searchvalue + '%'
and p.ModifiedDate = (select max(ModifiedDate) from eshop_product_Invenory (nolock) where p.ProductID = ProductID and p.User_ID = User_ID and p.Variant = Variant)  
Order by p.ProductID, p.Variant  
end
if (@searchcriteria = 'greater')
begin 
select p.ProductID as ID, p.ProductName PRODUCTNAME, p.Variant Variant, ISNULL(v.PRICE,0) PRICE, isnull(v.StockKeepingUnit,'') StockKeepingUnit, p.Balance INVENTORY, isnull(v.Barcode,'') Barcode, p.User_ID User_ID, isnull(v.Variant_Name,'') NAME, p.ModifiedDate Date_Modified  
from eshop_product_Invenory p(nolock)  
left outer join Variant_detail v(nolock)  
on p.User_ID = v.User_ID and p.ProductName = v.PRODUCTNAME and p.Variant = v.Variant  
where p.User_ID = @User_ID 
and p.Balance >=  @searchvalue
and p.ModifiedDate = (select max(ModifiedDate) from eshop_product_Invenory (nolock) where p.ProductID = ProductID and p.User_ID = User_ID and p.Variant = Variant)  
Order by p.ProductID, p.Variant 
end
if (@searchcriteria = 'Variant')
begin 
select p.ProductID as ID, p.ProductName PRODUCTNAME, p.Variant Variant, ISNULL(v.PRICE,0) PRICE, isnull(v.StockKeepingUnit,'') StockKeepingUnit, p.Balance INVENTORY, isnull(v.Barcode,'') Barcode, p.User_ID User_ID, isnull(v.Variant_Name,'') NAME, p.ModifiedDate Date_Modified  
from eshop_product_Invenory p(nolock)  
left outer join Variant_detail v(nolock)  
on p.User_ID = v.User_ID and p.ProductName = v.PRODUCTNAME and p.Variant = v.Variant  
where p.User_ID = @User_ID 
and v.Variant like '%' + @searchvalue + '%'
and p.ModifiedDate = (select max(ModifiedDate) from eshop_product_Invenory (nolock) where p.ProductID = ProductID and p.User_ID = User_ID and p.Variant = Variant)  
Order by p.ProductID, p.Variant  
end
if (@searchcriteria = 'less')
begin 
select p.ProductID as ID, p.ProductName PRODUCTNAME, p.Variant Variant, ISNULL(v.PRICE,0) PRICE, isnull(v.StockKeepingUnit,'') StockKeepingUnit, p.Balance INVENTORY, isnull(v.Barcode,'') Barcode, p.User_ID User_ID, isnull(v.Variant_Name,'') NAME, p.ModifiedDate Date_Modified  
from eshop_product_Invenory p(nolock)  
left outer join Variant_detail v(nolock)  
on p.User_ID = v.User_ID and p.ProductName = v.PRODUCTNAME and p.Variant = v.Variant  
where p.User_ID = @User_ID 
and p.Balance <=  @searchvalue
and p.ModifiedDate = (select max(ModifiedDate) from eshop_product_Invenory (nolock) where p.ProductID = ProductID and p.User_ID = User_ID and p.Variant = Variant)  
Order by p.ProductID, p.Variant  
end

if (@searchcriteria = 'UpdatedOn')
begin 
select p.ProductID as ID, p.ProductName PRODUCTNAME, p.Variant Variant, ISNULL(v.PRICE,0) PRICE, isnull(v.StockKeepingUnit,'') StockKeepingUnit, p.Balance INVENTORY, isnull(v.Barcode,'') Barcode, p.User_ID User_ID, isnull(v.Variant_Name,'') NAME, p.ModifiedDate Date_Modified  
from eshop_product_Invenory p(nolock)  
left outer join Variant_detail v(nolock)  
on p.User_ID = v.User_ID and p.ProductName = v.PRODUCTNAME and p.Variant = v.Variant  
where p.User_ID = @User_ID 
and substring(convert(varchar(10),p.ModifiedDate,101),1,10) = substring(convert(varchar(10),@searchvalue,101),1,10)
and p.ModifiedDate = (select max(ModifiedDate) from eshop_product_Invenory (nolock) where p.ProductID = ProductID and p.User_ID = User_ID and p.Variant = Variant)  
Order by p.ProductID, p.Variant  
end          
     
end 


GO

/* ============================================================
   Procedure: [dbo].[eshop_variant_list_SupplierWise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[eshop_variant_list_SupplierWise]  --33097              
(                    
@User_ID Bigint,
@SupplierID int                   
)                    
as                    
begin                    
           
select distinct p.ProductID ID,    
v.PRODUCTNAME PRODUCTNAME,          
v.Variant Variant,          
v.PRICE PRICE,          
v.StockKeepingUnit StockKeepingUnit,          
v.INVENTORY INVENTORY,          
v.Barcode Barcode,          
v.User_ID User_ID,          
v.Variant_Name NAME,           
v.Date_Modified  Date_Modified          
from   Variant_detail v(nolock) left Outer Join Products p(nolock)    
on v.PRODUCTNAME = p.Name    
and v.User_ID = p.User_ID    
where v.User_ID = @User_ID           
and   v.PRODUCTNAME IN (select Name from Products where User_ID = @User_ID and SupplierID = @SupplierID)    
union     
select ProductID ID,    
Name PRODUCTNAME,          
'' Variant,          
UnitPrice PRICE,          
StockKeepingUnit StockKeepingUnit,          
UnitInStock INVENTORY,          
Barcode Barcode,          
User_ID User_ID,          
'' NAME,           
CreatedDate  Date_Modified     
from Products (nolock)    
where User_ID = @User_ID 
and SupplierID = @SupplierID   
--and UnitInStock > 0    
and Name not in (select PRODUCTNAME from Variant_detail where User_ID = @User_ID)    
end 


GO

/* ============================================================
   Procedure: [dbo].[eshop_variant_Order_list]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec eshop_variant_Order_list 'Women','33097'             
CREATE   PROC eshop_variant_Order_list  --   'DEFAULT',34261               
(                            
@PRODUCTNAME varchar(150) = '' ,                      
@User_ID BIGINT                           
)                            
as                            
begin     
--IF (@PRODUCTNAME = 'DEFAULT')    
--BEGIN    
--SET @PRODUCTNAME = '';    
--END                       
DECLARE @V_COUNT INT, @COUNT INT, @V_VALUE VARCHAR(500), @NAME VARCHAR(500),  @ID INT, @PNAME VARCHAR(150),                          
@PRICE decimal(18, 0),@StockKeepingUnit  VARCHAR(100),  @INVENTORY int, @Barcode  VARCHAR(100) , @Date datetime,          
@P_Count int , @P1_Count int = 0                           
SELECT @id as ID,PRODUCTNAME,NAME, V_VALUE,PRICE,StockKeepingUnit,INVENTORY,Barcode,[User_ID],Date_Modified,           
@COUNT AS RNO INTO #TEMP FROM VARIANTS WHERE 1 = 2     
SELECT Name into #temp2 from Products (nolock) WHERE 1 = 2     
IF (@PRODUCTNAME <> '')    
BEGIN                    
insert into #temp2           
Select distinct Name from Products where Name like '%'+ @PRODUCTNAME +'%'          
END    
ELSE    
BEGIN    
insert into #temp2    
Select distinct Name  from Products where [User_ID] = @User_ID    
END    
Set @P_Count = (select Count(*) from #temp2)          
--select *, @P_Count from #temp2 return          
While (@P1_Count < @P_Count)          
begin          
set @V_COUNT = 0          
SET @V_COUNT = (SELECT COUNT(*) FROM ( SELECT ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber FROM VARIANTS           
  WHERE PRODUCTNAME  = ( SELECT Name FROM (SELECT Name,ROW_NUMBER() OVER (ORDER BY Name ASC) AS rownumber    
    FROM #temp2) as t1 WHERE rownumber = @P1_Count +1) and [User_ID] = @User_ID ) as VARIANTS)                            
SET @COUNT = 0              
--select @V_COUNT return                        
WHILE (@COUNT < @V_COUNT)                            
BEGIN                            
                          
SET @ID = ( SELECT ID FROM (SELECT ID,ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber                            
    FROM VARIANTS WHERE PRODUCTNAME  = isnull(@PRODUCTNAME,PRODUCTNAME) and [User_ID] = @User_ID ) as VARIANTS WHERE rownumber = @COUNT +1)                           
SET @PNAME = ( SELECT PRODUCTNAME FROM (SELECT PRODUCTNAME,ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber                            
    FROM VARIANTS WHERE PRODUCTNAME  = isnull(@PRODUCTNAME,PRODUCTNAME) and [User_ID] = @User_ID ) as VARIANTS WHERE rownumber = @COUNT +1)                           
SET @V_VALUE = ( SELECT V_VALUE FROM (SELECT V_VALUE,ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber                            
    FROM VARIANTS WHERE PRODUCTNAME  = isnull(@PRODUCTNAME,PRODUCTNAME) and [User_ID] = @User_ID  ) as VARIANTS WHERE rownumber = @COUNT +1)                            
SET @NAME = ( SELECT NAME FROM (SELECT NAME,ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber                            
    FROM VARIANTS  WHERE PRODUCTNAME  = isnull(@PRODUCTNAME,PRODUCTNAME) and [User_ID] = @User_ID ) as VARIANTS WHERE rownumber = @COUNT +1)                            
SET @PRICE = ( SELECT PRICE FROM (SELECT PRICE,ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber                            
    FROM VARIANTS WHERE PRODUCTNAME  = isnull(@PRODUCTNAME,PRODUCTNAME) and [User_ID] = @User_ID ) as VARIANTS WHERE rownumber = @COUNT +1)                            
SET @StockKeepingUnit = ( SELECT StockKeepingUnit FROM (SELECT StockKeepingUnit,ROW_NUMBER() OVER                             
 (ORDER BY ID ASC) AS rownumber FROM VARIANTS WHERE PRODUCTNAME  = isnull(@PRODUCTNAME,PRODUCTNAME) and [User_ID] = @User_ID ) as VARIANTS WHERE rownumber = @COUNT +1)                            
SET @INVENTORY = ( SELECT INVENTORY FROM (SELECT INVENTORY,ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber                            
    FROM VARIANTS WHERE PRODUCTNAME  = isnull(@PRODUCTNAME,PRODUCTNAME) and [User_ID] = @User_ID ) as VARIANTS WHERE rownumber = @COUNT +1)                            
SET @Barcode = ( SELECT Barcode FROM (SELECT Barcode,ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber                            
    FROM VARIANTS  WHERE PRODUCTNAME  = @PRODUCTNAME and [User_ID] = @User_ID ) as VARIANTS WHERE rownumber = @COUNT +1)                            
SET @Date = ( SELECT Date_Modified FROM (SELECT Date_Modified,ROW_NUMBER() OVER (ORDER BY ID ASC) AS rownumber                            
    FROM VARIANTS  WHERE PRODUCTNAME  = isnull(@PRODUCTNAME,PRODUCTNAME) and [User_ID] = @User_ID ) as VARIANTS WHERE rownumber = @COUNT +1)                            
INSERT INTO #TEMP (V_VALUE, RNO, NAME,PRICE,StockKeepingUnit,INVENTORY,Barcode,ID,PRODUCTNAME, User_ID)                            
SELECT *, @COUNT +1, @NAME,@PRICE,@StockKeepingUnit,@INVENTORY,@Barcode,@ID,@PNAME,@User_ID  from dbo.SplitString(ltrim(rtrim(@V_VALUE)), '#')                             
                            
SET @NAME = ''                            
SET @V_VALUE = ''                            
SET @COUNT = @COUNT + 1                            
                            
END                            
                           
IF @V_COUNT = 1                            
BEGIN                     
if not exists(select * from Variant_detail v, #TEMP t where v.PRODUCTNAME = t.PRODUCTNAME                   
and v.Variant_Name = T.NAME and v.User_ID = t.User_ID)                  
begin                  
insert into Variant_detail                         
SELECT T.PRODUCTNAME,LTRIM(RTRIM(t.V_VALUE)) as Variant,t.PRICE,t.StockKeepingUnit,t.INVENTORY,t.Barcode, T.User_ID, t.NAME,                            
T.Date_Modified FROM #TEMP t                            
end                  
else                  
begin                  
Delete v from Variant_detail v, #TEMP t where v.PRODUCTNAME = t.PRODUCTNAME                   
and v.Variant_Name = T.NAME and v.User_ID = t.User_ID                  
insert into Variant_detail                         
SELECT T.PRODUCTNAME,LTRIM(RTRIM(t.V_VALUE)) as Variant,t.PRICE,t.StockKeepingUnit,t.INVENTORY,t.Barcode, T.User_ID, t.NAME,                            
T.Date_Modified FROM #TEMP t                   
                   
end                  
                      
END                            
ELSE IF @V_COUNT = 2                            
BEGIN                        
if not exists(select * from Variant_detail v , #TEMP t where v.PRODUCTNAME = t.PRODUCTNAME                   
and v.Variant_Name = T.NAME and v.User_ID = t.User_ID)                  
begin                   
insert into Variant_detail                       
SELECT T1.PRODUCTNAME,LTRIM(RTRIM(T1.V_VALUE+'#'+T2.V_VALUE)) as Variant,T1.PRICE, T1.StockKeepingUnit,T1.INVENTORY,                  
T1.Barcode ,T1.User_ID,t1.NAME,T1.Date_Modified                           
FROM #TEMP T1 CROSS JOIN #TEMP T2                             
WHERE T1.NAME <> T2.NAME                             
AND T1.RNO = 1 AND T2.RNO = 2                    
end                  
else                  
begin                  
Delete v from Variant_detail v, #TEMP t where v.PRODUCTNAME = t.PRODUCTNAME                   
and v.Variant_Name = T.NAME and v.User_ID = t.User_ID                    
insert into Variant_detail                       
SELECT T1.PRODUCTNAME,LTRIM(RTRIM(T1.V_VALUE+'#'+T2.V_VALUE)) as Variant,T1.PRICE, T1.StockKeepingUnit,T1.INVENTORY,                  
T1.Barcode ,T1.User_ID,t1.NAME,T1.Date_Modified                           
FROM #TEMP T1 CROSS JOIN #TEMP T2                             
WHERE T1.NAME <> T2.NAME                             
AND T1.RNO = 1 AND T2.RNO = 2                     
end                  
                  
                            
END                            
ELSE IF @V_COUNT = 3                            
BEGIN                    
if not exists(select * from Variant_detail v , #TEMP t where v.PRODUCTNAME = t.PRODUCTNAME                   
and v.Variant_Name = T.NAME and v.User_ID = t.User_ID)             
begin                      
insert into Variant_detail                         
SELECT T1.PRODUCTNAME,LTRIM(RTRIM(T1.V_VALUE+'#'+T2.V_VALUE+'#'+T3.V_VALUE)) as Variant, T1.PRICE, T1.StockKeepingUnit,                  
T1.INVENTORY,T1.Barcode ,T1.User_ID,t1.NAME,T1.Date_Modified                           
FROM #TEMP T1 CROSS JOIN #TEMP T2 CROSS JOIN #TEMP T3                             
WHERE T1.NAME <> T2.NAME                             
AND T1.NAME <> T3.NAME                             
AND T1.NAME <> T3.NAME                             
AND T1.RNO = 1 AND T2.RNO = 2 AND T3.RNO = 3                    
end                  
else                  
begin                  
Delete v from Variant_detail v, #TEMP t where v.PRODUCTNAME = t.PRODUCTNAME                   
and v.Variant_Name = T.NAME and v.User_ID = t.User_ID                    
insert into Variant_detail                   
SELECT T1.PRODUCTNAME,LTRIM(RTRIM(T1.V_VALUE+'#'+T2.V_VALUE+'#'+T3.V_VALUE)) as Variant, T1.PRICE, T1.StockKeepingUnit,                  
T1.INVENTORY,T1.Barcode ,T1.User_ID,t1.NAME,T1.Date_Modified                           
FROM #TEMP T1 CROSS JOIN #TEMP T2 CROSS JOIN #TEMP T3                             
WHERE T1.NAME <> T2.NAME                             
AND T1.NAME <> T3.NAME                             
AND T1.NAME <> T3.NAME                             
AND T1.RNO = 1 AND T2.RNO = 2 AND T3.RNO = 3                       
end                            
END           
          
SET @P1_Count = @P1_Count + 1            
end      
if (@PRODUCTNAME <> '')    
begin                 
select distinct p.ProductID ID,          
v.PRODUCTNAME PRODUCTNAME,                
v.Variant Variant,                
v.PRICE PRICE,                
v.StockKeepingUnit StockKeepingUnit,                
v.INVENTORY INVENTORY,                
v.Barcode Barcode,                
v.User_ID User_ID,                
v.Variant_Name NAME,                 
v.Date_Modified  Date_Modified                
from   Variant_detail v(nolock) left Outer Join Products p(nolock)          
on v.PRODUCTNAME = p.Name          
and v.User_ID = p.User_ID          
where v.User_ID = @User_ID             
and  (v.PRODUCTNAME IN (select Name from Products where User_ID = @User_ID and ProductAvailable = 1)
or v.PRODUCTNAME IN (select Name from Products where User_ID = @User_ID and UnitInStock > 0))  
		      
and v.PRODUCTNAME  like '%'+ @PRODUCTNAME +'%'           
union          
select ProductID ID,          
Name PRODUCTNAME,                
'' Variant,                
UnitPrice PRICE,                
StockKeepingUnit StockKeepingUnit,                
UnitInStock INVENTORY,                
Barcode Barcode,                
User_ID User_ID,                
'' NAME,                 
CreatedDate  Date_Modified           
from Products (nolock)          
where User_ID = @User_ID          
and( UnitInStock > 0  or ProductAvailable = 1)     
and Name  like '%'+ @PRODUCTNAME +'%'           
and Name not in (select PRODUCTNAME from Variant_detail (nolock) where User_ID = @User_ID)                     
end    
else    
begin    
select distinct p.ProductID ID,          
v.PRODUCTNAME PRODUCTNAME,                
v.Variant Variant,                
v.PRICE PRICE,                
v.StockKeepingUnit StockKeepingUnit,                
v.INVENTORY INVENTORY,                
v.Barcode Barcode,                
v.User_ID User_ID,                
v.Variant_Name NAME,                 
v.Date_Modified  Date_Modified                
from   Variant_detail v(nolock) left Outer Join Products p(nolock)          
on v.PRODUCTNAME = p.Name          
and v.User_ID = p.User_ID          
where v.User_ID = @User_ID                 
and  (v.PRODUCTNAME IN (select Name from Products where User_ID = @User_ID and ProductAvailable = 1)
or v.PRODUCTNAME IN (select Name from Products where User_ID = @User_ID and UnitInStock > 0))         
union          
select ProductID ID,          
Name PRODUCTNAME,                
'' Variant,                
UnitPrice PRICE,                
StockKeepingUnit StockKeepingUnit,                
UnitInStock INVENTORY,                
Barcode Barcode,                
User_ID User_ID,                
'' NAME,                 
CreatedDate  Date_Modified           
from Products (nolock)          
where User_ID = @User_ID     
and( UnitInStock > 0  or ProductAvailable = 1)     
and Name not in (select PRODUCTNAME from Variant_detail (nolock) where User_ID = @User_ID)    
end    
DROP TABLE #TEMP                            
DROP TABLE #temp2          
end 


