/* ============================================================
   Procedure: [dbo].[eshop_variant123]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- [eshop_variant123] 'TEST123','33097'             
CREATE   PROC [dbo].[eshop_variant123]                      
(                            
@PRODUCTNAME varchar(150) ,                      
@User_ID int                           
)                            
as                            
begin                            
DECLARE @V_COUNT INT
SET @V_COUNT = (SELECT COUNT (DISTINCT NAME) FROM VARIANTS (NOLOCK) 
				WHERE PRODUCTNAME = @PRODUCTNAME AND User_ID = @User_ID )

SELECT DISTINCT NAME INTO #VARIANT FROM VARIANTS (NOLOCK)
WHERE PRODUCTNAME = @PRODUCTNAME AND User_ID = @User_ID               
    
SELECT * INTO #Variant_detail FROM Variant_detail (NOLOCK) WHERE 1 = 2                           

IF @V_COUNT = 1                            
BEGIN     
INSERT INTO #Variant_detail             
select v.PRODUCTNAME PRODUCTNAME,              
v.V_VALUE Variant,              
v.PRICE PRICE,              
v.StockKeepingUnit StockKeepingUnit,              
v.INVENTORY INVENTORY,              
v.Barcode Barcode,              
v.User_ID User_ID,              
v.NAME Variant_Name,               
v.Date_Modified  Date_Modified              
from   VARIANTS v(nolock)     
where v.User_ID = @User_ID   
and v.PRODUCTNAME  = @PRODUCTNAME  
end                       
ELSE IF @V_COUNT = 2                            
BEGIN     
INSERT INTO #Variant_detail                    
select distinct v1.PRODUCTNAME PRODUCTNAME, v1.V_VALUE+'#'+v2.V_VALUE as Variant,
v1.PRICE PRICE,              
v1.StockKeepingUnit StockKeepingUnit,              
v1.INVENTORY INVENTORY,              
v1.Barcode Barcode,              
v1.User_ID User_ID,              
v1.NAME+'#'+v2.NAME Variant_Name,               
v1.Date_Modified  Date_Modified
from VARIANTS v1(nolock) cross join VARIANTS v2(nolock)
where v1.PRODUCTNAME = @PRODUCTNAME
and v1.User_ID = @User_ID
and v1.PRODUCTNAME = v2.PRODUCTNAME
and v1.User_ID = v2. User_ID
and v1.NAME <> v2. NAME
and v1.NAME = (SELECT NAME FROM (SELECT NAME,ROW_NUMBER() OVER (ORDER BY NAME ASC) AS rownumber                            
    FROM #VARIANT) as VARIANTS WHERE rownumber = 1)
and v2.NAME = (SELECT NAME FROM (SELECT  NAME,ROW_NUMBER() OVER (ORDER BY NAME ASC) AS rownumber                            
    FROM #VARIANT) as VARIANTS WHERE rownumber = 2)
END                            
ELSE IF @V_COUNT = 3                            
BEGIN            
INSERT INTO #Variant_detail         
select distinct v1.PRODUCTNAME PRODUCTNAME, v1.V_VALUE+'#'+v2.V_VALUE+'#'+v3.V_VALUE as Variant,
v1.PRICE PRICE,              
v1.StockKeepingUnit StockKeepingUnit,              
v1.INVENTORY INVENTORY,              
v1.Barcode Barcode,              
v1.User_ID User_ID,              
v1.NAME+'#'+v2.NAME+'#'+v3.NAME Variant_Name,               
v1.Date_Modified  Date_Modified
from VARIANTS v1(nolock) cross join VARIANTS v2(nolock) cross join VARIANTS v3(nolock)
where v1.PRODUCTNAME = @PRODUCTNAME
and v1.User_ID = @User_ID
and v1.PRODUCTNAME = v2.PRODUCTNAME
and v1.User_ID = v2. User_ID
and v1.PRODUCTNAME = v3.PRODUCTNAME
and v1.User_ID = v3. User_ID
and v2.PRODUCTNAME = v3.PRODUCTNAME
and v2.User_ID = v3. User_ID
and v1.NAME <> v2. NAME
and v1.NAME <> v3. NAME
and v3.NAME <> v2. NAME
and v1.NAME = (SELECT NAME FROM (SELECT NAME,ROW_NUMBER() OVER (ORDER BY Variant_Name ASC) AS rownumber                            
    FROM #VARIANT) as VARIANTS WHERE rownumber = 1)
and v2.NAME = (SELECT NAME FROM (SELECT  NAME,ROW_NUMBER() OVER (ORDER BY Variant_Name ASC) AS rownumber                            
    FROM #VARIANT) as VARIANTS WHERE rownumber = 2)  
and v3.NAME = (SELECT NAME FROM (SELECT  NAME,ROW_NUMBER() OVER (ORDER BY Variant_Name ASC) AS rownumber                            
    FROM #VARIANT) as VARIANTS WHERE rownumber = 3)                 
END                    
ELSE IF @V_COUNT = 4                           
BEGIN      
INSERT INTO #Variant_detail               
select distinct v1.PRODUCTNAME PRODUCTNAME, v1.V_VALUE+'#'+v2.V_VALUE+'#'+v3.V_VALUE+'#'+v4.V_VALUE as Variant,
v1.PRICE PRICE,              
v1.StockKeepingUnit StockKeepingUnit,              
v1.INVENTORY INVENTORY,              
v1.Barcode Barcode,              
v1.User_ID User_ID,              
v1.NAME+'#'+v2.NAME+'#'+v3.NAME+'#'+v4.NAME Variant_Name,               
v1.Date_Modified  Date_Modified
from VARIANTS v1(nolock) cross join VARIANTS v2(nolock) cross join VARIANTS v3(nolock) cross join VARIANTS v4(nolock)
where v1.PRODUCTNAME = @PRODUCTNAME
and v1.User_ID = @User_ID
and v1.PRODUCTNAME = v2.PRODUCTNAME
and v1.User_ID = v2. User_ID
and v1.PRODUCTNAME = v3.PRODUCTNAME
and v1.User_ID = v3. User_ID
and v2.PRODUCTNAME = v3.PRODUCTNAME
and v2.User_ID = v3. User_ID
and v1.PRODUCTNAME = v4.PRODUCTNAME
and v1.User_ID = v4. User_ID
and v4.PRODUCTNAME = v3.PRODUCTNAME
and v4.User_ID = v3. User_ID
and v2.PRODUCTNAME = v4.PRODUCTNAME
and v2.User_ID = v4. User_ID
and v1.NAME <> v2. NAME
and v1.NAME <> v3. NAME
and v3.NAME <> v2. NAME
and v3.NAME <> v4. NAME
and v4.NAME <> v1. NAME
and v4.NAME <> v2. NAME
and v1.NAME = (SELECT NAME FROM (SELECT NAME,ROW_NUMBER() OVER (ORDER BY NAME ASC) AS rownumber                            
    FROM #VARIANT) as VARIANTS WHERE rownumber = 1)
and v2.NAME = (SELECT NAME FROM (SELECT  NAME,ROW_NUMBER() OVER (ORDER BY Variant_Name ASC) AS rownumber                            
    FROM #VARIANT) as VARIANTS WHERE rownumber = 2)  
and v3.NAME = (SELECT NAME FROM (SELECT  NAME,ROW_NUMBER() OVER (ORDER BY Variant_Name ASC) AS rownumber                            
    FROM #VARIANT) as VARIANTS WHERE rownumber = 3)  
and v4.NAME = (SELECT NAME FROM (SELECT  NAME,ROW_NUMBER() OVER (ORDER BY Variant_Name ASC) AS rownumber                            
    FROM #VARIANT) as VARIANTS WHERE rownumber = 4)                 
END     
IF EXISTS (SELECT '*' FROM #Variant_detail V INNER JOIN Variant_detail V2 ON V.PRODUCTNAME = V2.PRODUCTNAME
			AND V.User_ID = V2.User_ID AND V.Variant_Name = V2.Variant_Name AND (V.Variant LIKE '%'+V2.Variant+'%' OR 
			V2.Variant LIKE '%'+V.Variant+'%'))   
BEGIN
UPDATE V2
SET V2.Variant = V.Variant, V2.PRICE = V.PRICE, V2.StockKeepingUnit = V.StockKeepingUnit,  V2.INVENTORY = V.INVENTORY, 
		V2.Barcode = V.Barcode, V2.Date_Modified = GETDATE()
FROM #Variant_detail V INNER JOIN Variant_detail V2 ON V.PRODUCTNAME = V2.PRODUCTNAME
			AND V.User_ID = V2.User_ID AND V.Variant_Name = V2.Variant_Name AND (V.Variant LIKE '%'+V2.Variant+'%' OR 
			V2.Variant LIKE '%'+V.Variant+'%')
END  
ELSE
INSERT INTO Variant_detail (PRODUCTNAME,Variant,PRICE,StockKeepingUnit,INVENTORY,Barcode,User_ID,Variant_Name,Date_Modified)
SELECT PRODUCTNAME,Variant,PRICE,StockKeepingUnit,INVENTORY,Barcode,User_ID,Variant_Name,GETDATE() FROM #Variant_detail 

SELECT * FROM  Variant_detail (NOLOCK) WHERE PRODUCTNAME = @PRODUCTNAME AND User_ID = @User_ID
DROP TABLE #VARIANT                           
end 


GO

/* ============================================================
   Procedure: [dbo].[ExecCloneEmailFilterTriggerTasks1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[ExecCloneEmailFilterTriggerTasks1]    
@batchid bigint  
AS         
BEGIN         
drop table if exists #CloneEmailsFilter    
select * into #CloneEmailsFilter from CloneEmailsFilter where Mail_BatchID=@batchid        
declare         
@Mail_BatchID bigint,        
@Mail_ParentID bigint,        
@Mail_userID  bigint,        
@TemplateID bigint,        
@count int,        
@actualcount int,        
@parentsuperresellerid bigint,        
@hassufficientvirtualcredits int,        
@source nvarchar(20),        
@scheduleddate nvarchar(50),        
@frommail nvarchar(200),@ismonitor int,@mailroute nvarchar(20) ,@mail_subject nvarchar(500)       
        
select top 1 @Mail_BatchID= mail_batchid,@count=count(1),@Mail_ParentID=Mail_ParentID,@Mail_userID=Mail_userID,        
@source=source,@scheduleddate=mail_scheduledate,@TemplateID=templateid,@frommail=Mail_FromEmail,@mailroute=isnull(mailroute,'T'),  
@ismonitor=ismonitor ,@mail_subject=case when isnull(templateid,0)<>0         
then (select mailsubject from UserMailTemplate where ID=@TemplateID)         
when isnull(Mail_subject,'')='' then 
(select mail_subject from campaignmessages with (nolock) where batchid=@batchid)
else @mail_subject end 
from #cloneemailsfilter(nolock)      
  
if @scheduleddate=''        
begin        
select @actualcount = @count  
if 1=1--@count=@actualcount and @count > 0    
begin        
print '@Mail_USERID: ' + cast(@Mail_USERID as varchar)    
if @ismonitor is null        
begin        
select @ismonitor=case when status=1 and plimit<=@actualcount and @mailroute='T' then 0 else 1 end from ProcessMailLimit        
end        
        
IF 1=1          
BEGIN         
RETRY:                                                   
BEGIN TRY                                                
--BEGIN TRAN         
print 'F1'    
INSERT INTO Batchemail_infos(BatchID,UserID,SenderName,
[Message],TotalRecords,TotalProcessed,ProcessTable,IsProcess,Priority_Level,BatchInsertTime,BatchProcessTime,ScheduledDate,ScheduledTime,TemplateID,[Route],PageName        
,IsScheduled,Email_Subject,ReplyTo,ispersonalized,Mail_Source,mailroute,bmonitor)          
SELECT top 1 Mail_BatchID,Mail_UserID,coalesce(Mail_FromEmail,U.Email) as SenderName,        
case  when isnull(s.templateid,0)<>0 then         
(select MailContent from UserMailTemplate where ID=s.TemplateID)         
when isnull(cast(s.messages as nvarchar(max)),'')<>''         
then cast(s.messages as nvarchar(max))         
else cast(c.Messages as nvarchar(max)) end as Message,        
@Count,0,0,0,        
case when aws.user_id is not null then 2 when @count>10 then Mail_Priority when @count<=10 then 1 else 0 end,                          Getdate(),NULL,NULL,NULL,@TemplateID,0,0,0,@mail_subject,        
ReplyTo,0,s.source,s.mailroute,@ismonitor         
FROM #CloneEmailsFilter s (nolock) join user_detail u (nolock) on u.user_id=s.mail_UserID 
left join campaignmessages c on c.batchid=s.mail_batchid        
left join 
(select user_id,frommailid from awsmailroute aws (nolock) join user_detail(nolock) u on aws.parentid=u.user_id where isactive=1) aws   
on  
 aws.User_ID=Mail_UserID and aws.frommailid=Mail_FromEmail        
  
  
INSERT INTO Mailcreditdetails (ID,M_ID,FromUser_ID, [User_ID],  Debits,  Credits,  Balance,  Validity,  Default_Credit,  FromDate,   
 ToDate,  DateCreated,  DateUpdated,  EmpUpdated,  MachineName,  LastModified,  typecredit,  campaignid,batchid)   
 SELECT top 1 Newid(),  Ud.M_ID,  @Mail_ParentID,  @Mail_ParentID,  @count,  0, dbo.fn_GetMailBalance(@Mail_ParentID) - @count,   
 99999,  '',Getdate(),Getdate(),Getdate(),Getdate(),'', '',Getdate(),'',0,@Mail_BatchID   
 FROM user_detail ud (nolock) where ud.User_ID=@mail_userid  
  
  
  
  
END TRY                                                
                      
BEGIN CATCH                                                                                                    
--IF @@TRANCOUNT>0                                                
--ROLLBACK                                                
EXECUTE USP_INSERTERRORINFO;           
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number          
BEGIN          
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms          
GOTO RETRY -- Go to Label RETRY          
END                                                     
END CATCH        
end  
end  
end  
end  
  


GO

/* ============================================================
   Procedure: [dbo].[ExecCloneEmailFilterTriggerTasks2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[ExecCloneEmailFilterTriggerTasks2]  
@batchid bigint
AS       
BEGIN       
drop table if exists #CloneEmailsFilter  
select * into #CloneEmailsFilter from CloneEmailsFilter where Mail_BatchID=@batchid      
declare       
@Mail_BatchID bigint,      
@Mail_ParentID bigint,      
@Mail_userID  bigint,      
@TemplateID bigint,      
@count int,      
@actualcount int,      
@parentsuperresellerid bigint,      
@hassufficientvirtualcredits int,      
@source nvarchar(20),      
@scheduleddate nvarchar(50),      
@frommail nvarchar(200),@ismonitor int,@mailroute nvarchar(20)      
      
select top 1 @Mail_BatchID= mail_batchid,@count=count(1),@Mail_ParentID=Mail_ParentID,@Mail_userID=Mail_userID,      
@source=source,@scheduleddate=mail_scheduledate,@TemplateID=templateid,@frommail=Mail_FromEmail,@mailroute=isnull(mailroute,'T'),
@ismonitor=ismonitor
from #cloneemailsfilter(nolock)    
select @actualcount = @count

create table #output (GUID nvarchar(100) collate SQL_Latin1_General_CP1_CI_AS ,Email nvarchar(200) collate SQL_Latin1_General_CP1_CI_AS,      
Batchid bigint)            


if @ismonitor is null      
begin      
select @ismonitor=case when status=1 and plimit<=@actualcount and @mailroute='T' then 0 else 1 end from ProcessMailLimit      
end      
      
RETRY:                                                 
BEGIN TRY                                              
      
      
while @actualcount>0 and OBJECT_ID('tempdb..#CloneEmailsFilter') IS NOT NULL  
begin      
declare @minid bigint=0      
select @minid=min(mail_id) from #CloneEmailsFilter where mail_id>@minid      
INSERT INTO Clientemails(GUID,                                            
                   Email_Id,                                            
                   SentDateTime,                                            
                   UserId,                                            
                   ReplyTo,                                
                   [Status],                            
                   BatchID,                                            
                   [Message],        
                   campaignid,        
                   parentid)         
      OUTPUT inserted.GUID  as GUId,inserted.email_id as email,inserted.batchid as batchid INTO #output                                               
      SELECT top 1000 Mail_GUID,                                            
             Efce.Mail_ToEmail,                                            
             Getdate(),                                            
             Efce.Mail_UserID,            
             Efce.ReplyTo,                                            
             '',                                            
             efce.mail_BatchID,                                            
             case when isnull(efce.templateid,0)<>0       
    then (select MailContent from UserMailTemplate where ID=efce.TemplateID)       
    when isnull(cast(efce.messages as nvarchar(max)),'')<>''      
     then cast(efce.messages as nvarchar(max))       
     else cast(c.Messages as nvarchar(max)) end,        
             0,        
             efce.mail_ParentID                                            
      FROM   #cloneemailsfilter AS Efce left join UserMailTemplate umt (nolock) on umt.ID=Efce.TemplateID       
   left join campaignmessages c (nolock) on c.batchid=efce.Mail_BatchID      
   where efce.mail_id between @minid and @minid +1000      
   order by efce.mail_id      
       
                                    
INSERT INTO Emailsfilter                                           
                  (Mail_GUID,                                            
                   Mail_FromEmail,                                            
                   Mail_ToEmail,                                            
                   Mail_Subject,                                            
                   Mail_TempleteName,                                            
                   Messages,        
                   Mail_InsertedDate,           
                   Mail_UserID,                                            
                   ReplyTo,                                            
                   Mail_BatchID,                                            
                   Mail_Priority,                                            
                   Mail_ScheduleDate,                                            
                   Mail_Attechement,                                            
                   Mail_TempleteBody,                                            
                   IsMonitor)                                            
SELECT top 1000 O.Guid,                                            
             Efce.Mail_FromEmail,                                            
             Efce.Mail_ToEmail,                
             case when isnull(efce.templateid,0)<>0 then umt.MailSubject       
    when isnull(efce.mail_subject,'')<>'' then efce.mail_subject       
    else c.Mail_Subject end as Mail_Subject,                                           Efce.Mail_TempleteName,                                            
             case when isnull(efce.templateid,0)<>0       
    then umt.MailContent when isnull(cast(efce.messages as nvarchar(max)),'')<>''       
    then cast(efce.messages as nvarchar(max)) else cast(c.Messages as nvarchar(max)) end,                  
     isnull(Efce.Mail_InsertedDate,getdate()),                                            
             Efce.Mail_UserID,                                            
             Efce.ReplyTo,                                            
             efce.mail_BatchID,                                            
             case       
    when aws.user_id is not null then 2 when @count>10 then efce.Mail_Priority when @count<=10 then 1 else 0 end,                                              
    isnull(Efce.Mail_ScheduleDate,getdate()),                                            
             Efce.Mail_Attechement,                                            
            case when isnull(efce.templateid,0)<>0 then umt.MailContent       
    when isnull(cast(efce.messages as nvarchar(max)),'')<>''       
    then cast(efce.messages as nvarchar(max))       
    else cast(c.Messages as nvarchar(max)) end as Mail_TempleteBody,                                            
    @ismonitor AS Limit                                            
             --1 AS Limit                                            
      FROM   #cloneemailsfilter AS Efce                                            
             inner join #output o on o.email=Efce.mail_toemail and cast(o.guid as nvarchar(100))=cast(efce.Mail_GUID as nvarchar(100))      
             left join UserMailTemplate umt on umt.ID=Efce.TemplateID       
    left join campaignmessages c on c.batchid=efce.Mail_BatchID      
    left join       
             (select user_id,frommailid from awsmailroute aws (nolock) join user_detail(nolock) u on aws.mailuser=u.user_id where isactive=1) aws on aws.User_ID=Mail_UserID and aws.frommailid=Mail_FromEmail      
    where efce.mail_id between @minid and @minid +1000      
   order by efce.mail_id      
      
delete c from (select top 1000 * FROM   #cloneemailsfilter where mail_id between @minid and @minid +1000 order by mail_id) c      
set @actualcount=@actualcount-1000      
end      
select @actualcount = @count

      
drop table if exists #CloneEmailsFilter       

END TRY                                              
                    
BEGIN CATCH                                                                                                  
EXECUTE USP_INSERTERRORINFO;         
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number        
BEGIN        
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms        
GOTO RETRY -- Go to Label RETRY        
END                                                   
END CATCH      
end




