SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[ExecCloneEmailFilterTriggerTasks3]    
@batchid bigint
AS         
BEGIN         
declare @tablename varchar(100),@sql nvarchar(max)
select @tablename=tablename from BatchEmail_Infos(nolock) where batchid=@batchid
if @tablename is null and exists (select 1 from cloneemailsfilter(nolock) where mail_batchid=@batchid)
begin
select @tablename ='cloneemailsfilter'
end
select @sql = 
'if @tablename <> ''cloneemailsfilter'' 
begin
drop table '+quotename(@tablename)+ '  
end
else 
begin
while exists (select 1 from cloneemailsfilter where mail_batchid='+cast(@batchid as nvarchar)+')
begin        
delete top (1000) From CloneEmailsFilter where Mail_BatchID  ='+cast(@batchid as nvarchar)+'         
end        
end'

print @sql
exec sp_executesql @sql
end  

