update l set isprocessed=2,processedon=getdate() from leadscoreactivities l join #executeleadscrore e on l.id=e.id  
declare @c int=(select count(1) from #executeleadscrore),@eid bigint=0,@parentid bigint,@catid int,    
@eventid int,@activityid bigint    
while @c>0    
begin    
begin try    
select @eid=min(id) from #executeleadscrore where id>@eid    
select @parentid=parentid,@eventid=eventid,@catid=cat_id,@activityid=activityid from #executeleadscrore    
where id=@eid    
if exists(select 1 from lead_scoring_rules(nolock) where parentid=@parentid and isdeleted=0 and cat_id=@catid )              
begin    
declare @count int,@id bigint,@rule_desc nvarchar(max),@ccount int,@operation nvarchar(20),@points int,@leadid bigint,@ruleid int=0,              
@attribute nvarchar(100),@operator nvarchar(50),@value nvarchar(max)              
select @count=count(1),@id=0 from lead_scoring_rules(nolock) where parentid=@parentid and isdeleted=0 and cat_id=@catid        
declare @rulesparsed as dbo.Rulesparsed              
--create table #rulesparsed(ruleid int identity(1,1),Attribute nvarchar(200),operator nvarchar(50),value nvarchar(max))              
while @count>0              
begin              
select @id=min(id) from lead_scoring_rules(nolock) where parentid=@parentid and isdeleted=0 and cat_id=@catid and id>@id              
select @rule_desc=rule_desc,@operation=Operation,@points=points from lead_scoring_rules(nolock) where id=@id              
select @rule_desc=replace(replace(@rule_desc,'{"Rule":',''),'}]}]}','}]}]')              
insert into @rulesparsed(ruleid,Attribute,Operator,Value)              
SELECT @id,Attribute,Operator,Value FROM OPENJSON(@rule_desc)              
WITH (EventName nvarchar(50),Conditions NVARCHAR(MAX) AS JSON,Operation nvarchar(50),Points int) AS a              
cross apply openjson(Conditions)               
with(Attribute nvarchar(50),Operator nvarchar(50),Value nvarchar(max))              
select @ccount=count(1) from @rulesparsed              
--create table ##exists(checkifexists bigint)              
--while @ccount>0              
--begin              
declare @matches int=0              
--select @ruleid=min(id) from @rulesparsed where id>@id              
--select @attribute=attribute,@value=value,@operator=operator from @rulesparsed where id=@ruleid              
--if (@eventid in (17,18,57))--lead added or edited              
--begin              
select @leadid=leadid from tbl_LeadEventHistory(nolock) where HistoryID=@activityid              
     declare @checkmatchcondition table(matches int)            
           
          
   --insert into @checkmatchcondition(matches)            
  --  exec usp_checkleadcondition @rulesparsed,@activityid            
           
   declare @MatchOutputPRM bigint = 0          
    exec usp_checkleadcondition_WithOutputPRM @rulesparsed,@activityid , @MatchOutputPRM output          
             
   --select top 1 @matches=matches from @checkmatchcondition            
   select top 1 @matches = @MatchOutputPRM          
          
   --select @MatchOutputPRM          
          
--select @matches=(select dbo.fn_checkleadcondition(@rulesparsed,@activityid))              
              
--begin              
--declare @eventname nvarchar(100)=(select eventname from activityMaster(nolock) where id=@eventid)              
--insert into lead_scoring_events(catid,event_name,createdon,activity_master_id,leadid,parentid)              
--select 1,@eventname,getdate(),@activityid,@leadid,@parentid              
--end              
--truncate table ##exists              
--end              
--else if @eventid in ()              
--begin              
--end              
--set @ccount=@ccount-1              
--end              if @matches=1              
begin              
declare @currentscore bigint=isnull((select top 1 currentscore from lead_score_history(nolock) where leadid=@leadid order by id desc),0)              
insert into lead_score_history(lsh_eventid,parentid,leadid,rule_id,ScoreAdded,CurrentScore,createdon,lead_activity_id)              
select @eventid,@parentid,@leadid,@id,case when @operation='Add' then @points else 0-@points end,@currentscore+(case when @operation='Add' then @points else 0-@points end),getdate(),@activityid               
end              
--drop table if exists ##exists              
delete from @rulesparsed              
set @count=@count-1              
end         
drop table if exists #rulesparsed              
end     
update leadscoreactivities set isprocessed=1,processedon=getdate() where id=@eid     
set @c=@c-1    
end try    
begin catch    
exec usp_inserterrorinfo   
declare @er_p nvarchar(100),@er_l nvarchar(20),@er_m nvarchar(1500)  
select @er_p=ERROR_PROCEDURE(),@er_l=ERROR_LINE(),@er_m=ERROR_MESSAGE()  
update leadscoreactivities set error=1,errordescription='proc: '+ @er_p+ ', line: '+@er_l+', Message: '+@er_m  
where id=@id  
set @c=@c-1  
end catch    
end      
drop table if exists #executeleadscrore          
end   
  


