/* ============================================================
   Procedure: [dbo].[ExtractMYSMSObjects]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE ExtractMYSMSObjects  
AS  
BEGIN  
    -- Truncate the ScriptOutput table before inserting new data
    TRUNCATE TABLE DBATools.dbo.ScriptOutput;

    -- Create a temporary table to hold the scripts  
    CREATE TABLE #Scripts (  
        Script NVARCHAR(MAX)  
    );  
    
    DECLARE @TableName NVARCHAR(256);  
    DECLARE @SchemaName NVARCHAR(256);  
    DECLARE @sql NVARCHAR(MAX);  
    
    -- Scripting Tables  
    DECLARE TableCursor CURSOR FOR   
    SELECT TABLE_SCHEMA, TABLE_NAME   
    FROM INFORMATION_SCHEMA.TABLES   
    WHERE TABLE_TYPE = 'BASE TABLE'  

    OPEN TableCursor  
    FETCH NEXT FROM TableCursor INTO @SchemaName, @TableName  

    WHILE @@FETCH_STATUS = 0  
    BEGIN  
        SET @sql = 'CREATE TABLE [' + @SchemaName + '].[' + @TableName + '] ('  
        
        SELECT @sql = @sql + '[' + COLUMN_NAME + '] ' +   
        CASE 
            WHEN DATA_TYPE = 'nvarchar' AND CHARACTER_MAXIMUM_LENGTH = -1 THEN 'nvarchar(max)' 
            WHEN DATA_TYPE = 'varchar' AND CHARACTER_MAXIMUM_LENGTH = -1 THEN 'varchar(max)' 
            ELSE DATA_TYPE +   
                CASE 
                    WHEN CHARACTER_MAXIMUM_LENGTH > 0 THEN '(' + CAST(CHARACTER_MAXIMUM_LENGTH AS VARCHAR) + ')' 
                    WHEN DATA_TYPE IN ('decimal', 'numeric') THEN '(' + CAST(NUMERIC_PRECISION AS VARCHAR) + ', ' + CAST(NUMERIC_SCALE AS VARCHAR) + ')' 
                    ELSE '' 
                END 
        END + ', '  
        FROM INFORMATION_SCHEMA.COLUMNS   
        WHERE TABLE_SCHEMA = @SchemaName AND TABLE_NAME = @TableName  
        
        SET @sql = LEFT(@sql, LEN(@sql) - 1) + ');'  
        
        -- Insert the script into the temporary table  
        INSERT INTO #Scripts (Script) VALUES (@sql)  

        FETCH NEXT FROM TableCursor INTO @SchemaName, @TableName  
    END   

    CLOSE TableCursor  
    DEALLOCATE TableCursor  

    -- Scripting Views  
    INSERT INTO #Scripts (Script)  
    SELECT definition  
    FROM sys.sql_modules  
    WHERE object_id IN (SELECT object_id FROM sys.views);  

    -- Scripting Stored Procedures  
    INSERT INTO #Scripts (Script)  
    SELECT definition  
    FROM sys.sql_modules  
    WHERE object_id IN (SELECT object_id FROM sys.procedures);  

    -- Scripting Functions  
    INSERT INTO #Scripts (Script)  
    SELECT definition  
    FROM sys.sql_modules  
    WHERE object_id IN (SELECT object_id FROM sys.objects WHERE type_desc LIKE '%FUNCTION%');  

    -- Insert the scripts from the temporary table into the ScriptOutput table
    INSERT INTO DBATools.dbo.ScriptOutput (Script)
    SELECT Script FROM #Scripts;

    -- Drop the temporary table  
    DROP TABLE #Scripts;  
END


GO

