/* ============================================================
   Procedure: [dbo].[filter_EnquiryCampaign_analysis]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[filter_EnquiryCampaign_analysis]                  
(                  
@USER_ID as bigint =null,                  
@Source as varchar(100)='All',         
@Medium as varchar(100)='All',      
@Campaign as varchar(100)='All',      
@country as varchar(max)='All',      
@state as varchar(max)='All',      
@city as varchar(max)='All',      
@FromDate as date = null,        
@Todate as Date =null,                
@Range nvarchar(50)='Day',                
@RangeValue int=7,              
@rpttype int = 1              
)                  
as                  
begin  
declare @pid bigint=(select Parentid from user_detail(nolock) where USER_ID=@USER_ID)               
 declare @MediumID as int = 0          
if (@Medium != 'All')               
 select @MediumID = MediumID from dbo.UserMediumSettings (nolock)       
   where Name=@Medium and UserID=@pid        
         
  declare @SourceID as int = 0          
if (@Source != 'All')               
 select @SourceID = SourceID from dbo.UserSourceSettings (nolock)       
   where Name=@Source  and UserID=@pid       
-----------------------------------      
select Convert(date,enq.CreatedDate) CreatedDate,             
  isnull(cmp.Name,'Unknown') CampaignName, MediumName,SourceName, Parentid,       
 State,City, Country  into #enquiry_tmp   from userenquiry (nolock) enq          
  left outer join UserCampaignSettings (nolock) cmp on cmp.CampaignID =  enq.CampaignName          
  where enq.Parentid = @pID and Convert(date,enq.CreatedDate) between           
 @FromDate and @Todate       
  -----------------------------------      
       
      
if (@country <>'All')      
   delete From #enquiry_tmp where Country not in (@country)      
if (@state <>'All')      
   delete From #enquiry_tmp where State not in (@state)      
if (@city<>'All')      
    delete From #enquiry_tmp where City not in (@city)      
if (@Medium<>'All')      
    delete From #enquiry_tmp where MediumName not in (@MediumID)      
if (@Source <> 'All')               
  delete From #enquiry_tmp where SourceName  not in      
  (@SourceID)       
if (@Campaign <> 'All')               
  delete From #enquiry_tmp where CampaignName  not in      
  (@Campaign)         
      
select @FromDate = MIN(CreatedDate) ,@Todate =MAX(CreatedDate)       
from  #enquiry_tmp      
        
------------------------------------      
      
         
 create table #UserStats(dt date,FromTo varchar(100), Campaign varchar(100),          
 qCount bigint )                
 create table #UserStatsAll(dt date,FromTo varchar(100), Campaign varchar(100),          
 qCount bigint)                
    declare @RangeValue1 int                
 set @RangeValue1=coalesce(@rangevalue,15)                
            
 StartBuildingTable:                
               
               
 set @Range=coalesce(@range,'Day')                
 set @RangeValue=coalesce(@rangevalue,7)                
 declare @datecreated1 Date               
 set @datecreated1=@FromDate                
              
                 
 If @Range='Day'                
  begin                
   if datediff(dd,@fromdate,@todate)>12*@RangeValue                
   begin                
    set @RangeValue=ceiling((datediff(dd,@fromdate,@todate))/12) +1                
   end               
   end              
   else if @Range = 'Month'                
  begin                
  if datediff(mm,@fromdate,@todate)>12*@RangeValue                
  begin                
  set @RangeValue=ceiling((datediff(mm,@fromdate,@todate))/12) +1                
  end               
  end                 
while @datecreated1 <= @todate                
 begin                
                
   If @Range='Day'                
  begin               
        
       
  insert into #userstats(dt ,FromTo , Campaign ,qCount )                
 select @datecreated1,           
   convert(varchar, @datecreated1, 103)+'-'+            
   convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),          
   CampaignName, COUNT(*) from #enquiry_tmp         
   where Convert(date,CreatedDate) between           
   @datecreated1 and dateadd(dd,(@Rangevalue-1),@datecreated1)          
   group by CampaignName order by CampaignName         
       
      
set @datecreated1=dateadd(dd,@Rangevalue, @datecreated1)                
end                
                  
                
                
  else if @Range = 'Month'                
  begin                
                 
  declare @monthend date                
  set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + @Rangevalue, 0))                
        
        
      
  insert into #userstats(dt ,FromTo , Campaign ,qCount )                
 select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+            
   convert(varchar, @monthend, 103), CampaignName, COUNT(*) from #enquiry_tmp         
   where Convert(date,CreatedDate) between @datecreated1 and @monthend          
   group by CampaignName order by CampaignName         
       
 --select @datecreated1,           
 -- convert(varchar, @datecreated1, 103)+'-'+            
 -- convert(varchar, @monthend, 103),           
 -- isnull(sou.Name,'Unknown'), COUNT(*) from userenquiry enq          
 -- left outer join UserCampaignSettings sou on sou.CampaignID =  enq.CampaignName          
 -- where enq.Parentid = @USER_ID and Convert(date,enq.CreatedDate) between           
 -- @datecreated1 and @monthend          
 -- group by sou.Name order by sou.Name         
        
      
   set @datecreated1=dateadd(dd,1,@monthend)                 
  end                
              
end                
              
insert into #UserStatsAll (dt ,FromTo , Campaign ,qCount  )                
    select dt,max(FromTo),Campaign,sum(qCount)            
    from #UserStats   group by dt,Campaign order by dt,Campaign                    
             
  select max(FromTo) FromTo, Campaign,sum(qCount) qCount            
    from #UserStats   group by Campaign order by Campaign                  
            
   --select * from #UserStatsAll            
     drop table #UserStatsAll            
     drop table #UserStats            
      drop table #enquiry_tmp                
 SET NOCOUNT ON;                
                 
               
end


GO

/* ============================================================
   Procedure: [dbo].[filter_EnquiryMedium_analysis]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext filter_EnquiryMedium_analysis  
--exec get_EnquiryMedium_analysis 335,'All','All','All','All','All',     
--'2017-01-01','2018-04-28','Day',7,1          
          
CREATE   PROCEDURE [dbo].[filter_EnquiryMedium_analysis]                  
(                  
@USER_ID as bigint =null,                  
@Source as varchar(max)='All',      
@Medium as varchar(max)='All',      
@country as varchar(max)='All',      
@state as varchar(max)='All',      
@city as varchar(max)='All',      
@FromDate as date = null,        
@Todate as Date =null,                
@Range nvarchar(50)='Day',                
@RangeValue int=7,              
@rpttype int = 1              
)                  
as                  
begin                 
 declare @SourceID as int = 0          
----------------------------      
select Convert(date,enq.CreatedDate) CreatedDate,           
 case when isnull(med.Name,'')='' then 'Unknown' else med.Name end MediumName,SourceName, Parentid,       
 State,City, Country  into #enquiry_tmp from userenquiry (nolock) enq          
 left outer join UserMediumSettings (nolock) med on med.MediumID =  enq.MediumName          
 where Parentid = @USER_ID and Convert(date,enq.CreatedDate) between           
 @FromDate and @Todate      
      
if (@Source != 'All')               
 select @SourceID = SourceID from dbo.UserSourceSettings (nolock)       
   where Name=@Source        
         
if (@country <>'All')      
   delete From #enquiry_tmp where Country not in (@country)      
if (@state <>'All')      
   delete From #enquiry_tmp where State not in (@state)      
if (@city<>'All')      
    delete From #enquiry_tmp where City not in (@city)      
if (@Medium<>'All')      
    delete From #enquiry_tmp where MediumName not in (@Medium)      
if (@Source <> 'All')               
  delete From #enquiry_tmp where SourceName  not in (@SourceID)        
      
select @FromDate = MIN(CreatedDate) ,@Todate =MAX(CreatedDate)       
from  #enquiry_tmp      
----------------------------      
          
 create table #UserStats(dt date,FromTo varchar(100), Medium varchar(100),          
 qCount bigint )                
 create table #UserStatsAll(dt date,FromTo varchar(100), Medium varchar(100),          
 qCount bigint)                
    declare @RangeValue1 int                
 set @RangeValue1=coalesce(@rangevalue,15)                
            
 StartBuildingTable:                
               
               
 set @Range=coalesce(@range,'Day')                
 set @RangeValue=coalesce(@rangevalue,7)                
 declare @datecreated1 Date               
 set @datecreated1=@FromDate                
              
                 
  If @Range='Day'                
  begin                
   if datediff(dd,@fromdate,@todate)>12*@RangeValue                
   begin                
    set @RangeValue=ceiling((datediff(dd,@fromdate,@todate))/12) +1                
   end               
   end              
   else if @Range = 'Month'                
  begin   
  if ceiling(datediff(mm,@fromdate,@todate))>12                
   begin                
   set @RangeValue=ceiling((datediff(mm,@fromdate,@todate))/12) +1       
  end   
  else  
 begin  
  set @RangeValue= ceiling(datediff(mm,@fromdate,@todate))  
 end  
  end        
set @RangeValue1 =  @RangeValue     
               
while @datecreated1 <= @todate                
 begin                
                
   If @Range='Day'                
  begin   
  if   dateadd(dd,(@Rangevalue-1),@datecreated1) >  @todate   
 BEGIN  
  set  @Rangevalue = ceiling(datediff(dd,@datecreated1,@todate))+1   
 END               
 insert into #userstats(dt ,FromTo , Medium ,qCount )                
 select @datecreated1,           
 convert(varchar, @datecreated1, 103)+'-'+            
 convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),           
 MediumName, COUNT(*)       
 from #enquiry_tmp       
 where Parentid = @USER_ID and Convert(date,CreatedDate) between           
 @datecreated1 and dateadd(dd,(@Rangevalue-1),@datecreated1)          
 group by MediumName order by MediumName         
       
          
      set @datecreated1=dateadd(dd,@Rangevalue, @datecreated1)                
  end                
                  
                
                
  else if @Range = 'Month'                
  begin                
                 
  declare @monthend date                
  if (@Rangevalue > 12)  
 set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + @Rangevalue, 0))  
  else  
  set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + 1, 0))  
   
  if   @monthend >  @todate   
 BEGIN  
 set @monthend =  @todate   
 END    
           
 insert into #userstats(dt ,FromTo , Medium ,qCount )                
 select @datecreated1,           
 convert(varchar, @datecreated1, 103)+'-'+            
 convert(varchar, @monthend, 103),           
 MediumName, COUNT(*)       
 from #enquiry_tmp       
 where Parentid = @USER_ID and Convert(date,CreatedDate) between           
 @datecreated1 and @monthend          
 group by MediumName order by MediumName         
       
 -- insert into #userstats(dt ,FromTo , Medium ,qCount )                
 --  select @datecreated1,           
 --  convert(varchar, @datecreated1, 103)+'-'+            
 -- convert(varchar, @monthend, 103),         
 --   case when isnull(sou.Name,'')='' then 'Unknown' else sou.Name end, COUNT(*) from userenquiry enq          
 --left outer join UserMediumSettings sou on sou.MediumID =  enq.MediumName          
 --where Parentid = @USER_ID and Convert(date,enq.CreatedDate) between           
 --@datecreated1 and @monthend          
 --group by sou.Name order by sou.Name         
      
   set @datecreated1=dateadd(dd,1,@monthend)                 
  end                
              
end                
              
insert into #UserStatsAll (dt ,FromTo , Medium ,qCount  )                
    select dt,max(FromTo),Medium,sum(qCount)            
    from #UserStats   group by dt,Medium order by dt,Medium                    
             
  select max(FromTo) FromTo, Medium,sum(qCount) qCount            
    from #UserStats   group by Medium order by Medium                  
            
   --select * from #UserStatsAll            
     drop table #UserStatsAll            
     drop table #UserStats            
      drop table #enquiry_tmp                
 SET NOCOUNT ON;                
                 
               
end


