/* ============================================================
   Procedure: [dbo].[filter_EnquirySource_analysis]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext filter_EnquirySource_analysis  
  
--sp_helptext filter_EnquirySource_analysis    
--sp_helptext get_EnquirySource_analysis        
        
--exec filter_EnquirySource_analysis 335,'All','All','All','All', '2017-12-01','2018-12-01','Day',1          
--sp_helptext get_EnquirySource_analysis        
--select City,State,Country,* from userenquiry      
        
CREATE   PROCEDURE filter_EnquirySource_analysis                  
(                  
@USER_ID as bigint =null,      
@country as varchar(max)='All',      
@state as varchar(max)='All',      
@city as varchar(max)='All',      
@SourceName as varchar(max)='All',      
@FromDate as date = null,                  
@Todate as Date =null,                
@Range nvarchar(50)='Day',                
@RangeValue int=7,              
@rpttype int = 1              
)                  
as                  
begin                 
declare @MID bigint                
                
select Convert(date,enq.CreatedDate) CreatedDate,           
 sou.Name, Parentid, State,City, Country  into #enquiry_tmp from userenquiry (nolock) enq          
 inner join UserSourceSettings (nolock) sou on sou.SourceID = enq.SourceName          
 where Parentid = @USER_ID and Convert(date,enq.CreatedDate) between           
 @FromDate and @Todate      
      
if (@country <>'All')      
   delete From #enquiry_tmp where Country not in (@country)      
        
if (@state <>'All')      
   delete From #enquiry_tmp where State not in (@state)      
if (@city<>'All')      
    delete From #enquiry_tmp where City not in (@city)      
    if (@SourceName<>'All')      
    delete From #enquiry_tmp where Name not in (@SourceName)      
--if (@uType<>'All')      
--    delete From #user_tmp where uType not in (@uType)       
      
      
select @FromDate = MIN(CreatedDate) ,@Todate =MAX(CreatedDate)       
from  #enquiry_tmp      
      
          
 create table #UserStats(dt date,FromTo varchar(100), Source varchar(100),          
 qCount bigint )                
 create table #UserStatsAll(dt date,FromTo varchar(100), Source varchar(100),          
 qCount bigint, RangeValue int)                
    declare @RangeValue1 int                
 set @RangeValue1=coalesce(@rangevalue,15)                
            
 StartBuildingTable:                
               
               
 set @Range=coalesce(@range,'Day')                
 set @RangeValue=coalesce(@rangevalue,7)                
 declare @datecreated1 Date               
 set @datecreated1=@FromDate                
              
 If @Range='Day'                
  begin                
   if datediff(dd,@fromdate,@todate)>12*@RangeValue                
   begin                
    set @RangeValue=ceiling((datediff(dd,@fromdate,@todate))/12) +1                
   end               
   end              
   else if @Range = 'Month'                
  begin   
  if ceiling(datediff(mm,@fromdate,@todate))>12                
   begin                
   set @RangeValue=ceiling((datediff(mm,@fromdate,@todate))/12) +1       
  end   
  else  
 begin  
  set @RangeValue= ceiling(datediff(mm,@fromdate,@todate))  
 end  
  end        
set @RangeValue1 =  @RangeValue                  
               
while @datecreated1 <= @todate                
 begin                
                
   If @Range='Day'                
  begin               
    if   dateadd(dd,(@Rangevalue-1),@datecreated1) >  @todate   
 BEGIN  
  set  @Rangevalue = ceiling(datediff(dd,@datecreated1,@todate))+1   
 END   
 insert into #userstats(dt ,FromTo , Source ,qCount )                
 select @datecreated1,           
 convert(varchar, @datecreated1, 103)+'-'+            
 convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),           
 Name, COUNT(*) from #enquiry_tmp enq          
 where Convert(date,enq.CreatedDate) between           
 @datecreated1 and dateadd(dd,(@Rangevalue-1),@datecreated1)          
 group by Name order by Name        
          
      set @datecreated1=dateadd(dd,@Rangevalue, @datecreated1)                
  end                
                  
                
               
  else if @Range = 'Month'                
  begin                
                 
  declare @monthend date                
  if (@Rangevalue > 12)  
 set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + @Rangevalue, 0))  
  else  
  set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + 1, 0))  
   
  if   @monthend >  @todate   
 BEGIN  
 set @monthend =  @todate   
 END    
      
insert into #userstats(dt ,FromTo , Source ,qCount )                
 select @datecreated1,           
 convert(varchar, @datecreated1, 103)+'-'+            
 convert(varchar, @monthend, 103),           
 Name, COUNT(*) from #enquiry_tmp enq          
 where Convert(date,enq.CreatedDate) between           
 @datecreated1 and @monthend          
 group by Name order by Name       
            
 --insert into #userstats(dt ,FromTo , Source ,qCount )                
 --  select @datecreated1,           
 --  convert(varchar, @datecreated1, 103)+'-'+            
 -- convert(varchar, @monthend, 103),           
 --  sou.Name, COUNT(*) from userenquiry enq          
 --inner join UserSourceSettings sou on sou.SourceID = enq.SourceName          
 --where Parentid = @USER_ID and Convert(date,enq.CreatedDate) between           
 --@datecreated1 and @monthend          
 --group by sou.Name order by sou.Name          
           
   set @datecreated1=dateadd(dd,1,@monthend)                 
  end                
              
end                
    
insert into #UserStatsAll (dt ,FromTo , Source ,qCount, RangeValue  )                
    select dt,max(FromTo),Source,sum(qCount), @RangeValue            
    from #UserStats   group by dt,Source order by dt,Source                    
             
  select max(FromTo) FromTo, Source,sum(qCount) qCount            
    from #UserStats   group by Source order by Source                  
     
     
-- select * into  san_tmpsou    
-- from #UserStatsAll     
     
--select * from san_tmpsou    
--pivot (max (qCount) for source in ([MON],[TUE],[WED],[THU],[FRI],[SAT],[SUN])) as MaxIncomePerDay    
    
--declare @tmp varchar(max)    
--declare @tmpstr varchar(Max)    
--SET @tmp = ''    
--select @tmp = @tmp + source + ', ' from san_tmpsou    
    
--select @tmpstr =  SUBSTRING(@tmp, 0, LEN(@tmp))     
--select * from san_tmpsou    
--pivot (sum(qCount) for source in (@tmpstr) as MaxIncomePerDay           
    
    
--where VendorId in ('SPIKE')    
          
     drop table #UserStatsAll            
     drop table #UserStats            
     drop table #enquiry_tmp               
 SET NOCOUNT ON;                
                 
               
end


