/* ============================================================
   Procedure: [dbo].[filter_MailConsumption_analysis]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

               
CREATE   PROCEDURE filter_MailConsumption_analysis                    
(                    
@USER_ID as bigint =null,         
@Country as varchar(max)='All',          
@state as varchar(max)='All',          
@city as varchar(max)='All',          
@uType as varchar(max)='All',          
@constRange as bigint= 0,          
@constndRange as bigint= 0,                    
@FromDate as date = null,                    
@Todate as Date =null,                  
@Range nvarchar(50)='Day',                  
@RangeValue int=7,                
@rpttype int = 1                
)                    
as                    
begin                   
declare @MID bigint                  
                  
--select @FromDate ='2009-08-01',                  
-- @Todate ='2018-12-31'                  
                   
                  
                  
select @MID =                  
rd.Reseller_ID from user_detail (nolock) ud inner join reseller_detail (nolock) rd                  
on rd.User_ID = ud.User_ID --inner join user_detail md                  
where ud.TYPE in (1,2) and ud.USER_ID = @USER_ID                  
          
-------------------          
select user_id,Country,city,state,m_id,          
 (Case when Type=0 then 'User' else case when Type=2 then 'Sub Reseller' else 'Reseller' end end)        uType           
 into #user_tmp             
   from user_detail (nolock) where m_id = @MID order by Convert(date,DateCreated)           
          
    if (@Country <>'All')            
   delete From #user_tmp where Country not in (@Country)           
 if (@state <>'All')          
   delete From #user_tmp where state not in (@state)          
if (@city<>'All')          
    delete From #user_tmp where City not in (@city)          
if (@uType<>'All')          
    delete From #user_tmp where uType not in (@uType)              
          
select Convert(date,DateCreated) DateCreated, Debits,User_ID into #rmp_Credit_Details                  
  from MailCreditDetails (nolock) where Convert(date,DateCreated)                 
 between @FromDate and @Todate and m_id = @MID and FromUser_ID = User_ID                
 and User_ID in (select USER_ID from #user_tmp)           
           
drop table #user_tmp          
                
select @FromDate = MIN(DateCreated) ,@Todate =MAX(DateCreated)           
from  #rmp_Credit_Details               
-------------------          
          
 create table #UserStats(dt date,FromTo varchar(100),tCount int, user_id bigint)                  
    create table #UserStatsAll(Fromto varchar(100),db100 bigint,db1k bigint,                
    db10k bigint,db1L bigint,db10L bigint, dbgr10L bigint, Rangevalue nvarchar(50),dt date)                  
    declare @RangeValue1 int                  
 set @RangeValue1=coalesce(@rangevalue,15)                  
              
 StartBuildingTable:                  
                 
                 
 set @Range=coalesce(@range,'Day')                  
 set @RangeValue=coalesce(@rangevalue,7)                  
 declare @datecreated1 Date                 
 set @datecreated1=@FromDate                  
                
 If @Range='Day'                
  begin                
   if datediff(dd,@fromdate,@todate)>12*@RangeValue                
   begin                
    set @RangeValue=ceiling((datediff(dd,@fromdate,@todate))/12) +1                
   end               
   end              
   else if @Range = 'Month'                
  begin   
  if ceiling(datediff(mm,@fromdate,@todate))>12                
   begin                
   set @RangeValue=ceiling((datediff(mm,@fromdate,@todate))/12) +1       
  end   
  else  
 begin  
  set @RangeValue= ceiling(datediff(mm,@fromdate,@todate))  
 end  
  end        
set @RangeValue1 =  @RangeValue                   
                 
while @datecreated1 <= @todate                  
 begin                  
                  
   If @Range='Day'                  
 begin   
 if   dateadd(dd,(@Rangevalue-1),@datecreated1) >  @todate   
 BEGIN  
  set  @Rangevalue = ceiling(datediff(dd,@datecreated1,@todate))+1   
 END                 
   if @constRange = 0 and @constndRange = 0          
  insert into #userstats(dt,FromTo,tCount, user_id )                  
  select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+              
  convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),              
  SUM(Debits),User_ID                 
  from #rmp_Credit_Details where Convert(date,DateCreated)               
  between @datecreated1 and dateadd(dd,(@Rangevalue-1),@datecreated1)                  
  --and m_id = @MID and FromUser_ID = User_ID              
  group by User_ID                  
   else          
  insert into #userstats(dt,FromTo,tCount, user_id )                  
  select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+              
  convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),              
  SUM(Debits),User_ID                 
  from #rmp_Credit_Details where Convert(date,DateCreated)               
  between @datecreated1 and dateadd(dd,(@Rangevalue-1),@datecreated1)                  
  --and m_id = @MID and FromUser_ID = User_ID              
  group by User_ID having SUM(Debits) between @constRange and @constndRange                 
             
   set @datecreated1=dateadd(dd,@Rangevalue, @datecreated1)                  
  end                  
                    
                  
                  
  else if @Range = 'Month'                  
  begin                  
                   
  declare @monthend date                  
  if (@Rangevalue > 12)  
 set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + @Rangevalue, 0))  
  else  
  set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + 1, 0))  
   
  if   @monthend >  @todate   
 BEGIN  
 set @monthend =  @todate   
 END      
  if @constRange = 0 and @constndRange = 0              
  insert into #userstats(dt,FromTo,tCount, user_id )                  
  select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+              
  convert(varchar, @monthend, 103),              
  SUM(Debits),User_ID                 
  from #rmp_Credit_Details where Convert(date,DateCreated)               
  between @datecreated1 and @monthend                 
  --and m_id = @MID and FromUser_ID = User_ID              
  group by User_ID                 
  else          
  insert into #userstats(dt,FromTo,tCount, user_id )                  
  select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+              
  convert(varchar, @monthend, 103),              
  SUM(Debits),User_ID                 
  from #rmp_Credit_Details where Convert(date,DateCreated)               
  between @datecreated1 and @monthend                 
  --and m_id = @MID and FromUser_ID = User_ID              
  group by User_ID  having SUM(Debits) between @constRange and @constndRange                       
          
                    
   set @datecreated1=dateadd(dd,1,@monthend)                   
  end             
                
end                  
                
                 
   insert into #UserStatsAll(dt,Fromto,db100 ,db1k ,                
    db10k ,db1L ,db10L , dbgr10L )                  
    select dt,max(FromTo),                
    sum(case when tCOUNT <= 100 then tCOUNT else 0 end),                    
    sum(case when tCOUNT > 100 and tCOUNT <= 1000 then tCOUNT else 0 end),              
    sum(case when tCOUNT > 1000 and tCOUNT <= 10000 then tCOUNT else 0 end),                
    sum(case when tCOUNT > 10000 and tCOUNT <= 100000 then tCOUNT else 0 end),               
    sum(case when tCOUNT > 100000 and tCOUNT <=1000000 then tCOUNT else 0 end),               
    sum(case when tCOUNT > 1000000 then tCOUNT else 0 end)               
    from #UserStats   group by dt order by dt                      
             
  if @constRange = 0 and @constndRange = 0             
   select Fromto,db100 ,db1k ,                
    db10k ,db1L ,db10L , dbgr10L from #UserStatsAll          
  else          
 select max(FromTo) FromTo,                 
    sum(tCOUNT) tCOUNT                
    from #UserStats  group by  dt order by dt              
  select @RangeValue1 RangeValue    
  drop table #rmp_Credit_Details          
     drop table #UserStatsAll              
     drop table #UserStats              
                        
 SET NOCOUNT ON;                  
                   
    
end


GO

/* ============================================================
   Procedure: [dbo].[Filter_MonthlyMailConsumption_analysis]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE Filter_MonthlyMailConsumption_analysis                    
(                    
@USER_ID as bigint =null,                    
@Country as varchar(max)='All',                
@state as varchar(max)='All',              
@city as varchar(max)='All',              
@uType as varchar(max)='All',              
@fMonth as int = 0,                    
@fYear as int = 2018,    
@eMonth as int = 0,                    
@eYear as int = 2018                
)                    
as                    
begin                   
declare @MID bigint                  
                  
--select @FromDate ='2009-08-01',                  
-- @Todate ='2018-12-31'                  
                   
 Declare @fmdate as date     
Declare @todate as date               
 set @fmdate =  CAST(@fYear as varchar(4))+'-'+replicate('0', 2 - len(cast(@fMonth as varchar(2))))+     
 cast(@fMonth as varchar(2))+'-'+'01'                
  set @todate =  CAST(@eYear as varchar(4))+'-'+replicate('0', 2 - len(cast(@eMonth as varchar(2))))+     
 cast(@eMonth as varchar(2))+'-'+'01'                     
  
select  @todate = dateadd(dd,-1,dateadd(mm,1,@todate))                  
select @MID =                        
rd.Reseller_ID from user_detail (nolock) ud inner join reseller_detail (nolock) rd                       on rd.User_ID = ud.User_ID --inner join user_detail md                        
where ud.TYPE in (1,2) and ud.USER_ID = @USER_ID              
-------------------------              
              
 select user_id,Country,city,state,m_id,              
 (Case when Type=0 then 'User' else case when Type=2 then 'Sub Reseller' else 'Reseller' end end)                  
 uType  into #user_tmp                 
   from user_detail (nolock) where m_id = @MID order by Convert(date,DateCreated)               
             
   if (@Country <>'All')                
   delete From #user_tmp where Country not in (@Country)              
                
 if (@state <>'All')              
   delete From #user_tmp where state not in (@state)              
if (@city<>'All')              
    delete From #user_tmp where City not in (@city)              
if (@uType<>'All')              
    delete From #user_tmp where uType not in (@uType)                  
    
 create table #UserStats(tCount int, mMonth int,mYEAR int,user_id bigint)                  
    create table #UserStatsAll(FromTo varchar(20), db100 bigint,db1k bigint,                
    db10k bigint,db1L bigint,db10L bigint, dbgr10L bigint,mMonth int,mYEAR int,user_id bigint)                  
      
          
              
 StartBuildingTable:                  
 select MC.* into #mnthconstmp     
 from [MonthlyMailConsumption] (nolock) Mc     
    where FirstDate >= @fmdate and FirstDate < @todate  
    and USER_ID in (select User_ID from #user_tmp)    
                 
insert into #UserStatsAll(FromTo,db100 ,db1k ,                
    db10k ,db1L ,db10L , dbgr10L, mMonth,mYEAR )                  
   select LEFT(DATENAME(MONTH,max(FirstDate)),3)+'-'+ cast(YEAR( max(FirstDate)) as varchar(4)),     
   sum(case when TotalConsumption <= 100 then 1 else 0 end),                 
     sum(case when TotalConsumption > 100 and TotalConsumption <= 1000     
     then 1 else 0 end),              
    sum(case when TotalConsumption > 1000 and TotalConsumption <= 10000     
    then 1 else 0 end),                
    sum(case when TotalConsumption > 10000 and TotalConsumption <= 100000     
    then 1 else 0 end),               
    sum(case when TotalConsumption > 100000 and TotalConsumption <=1000000     
    then 1 else 0 end),               
    sum(case when TotalConsumption > 1000000 then 1 else 0 end),     
    Month, YEAR  from #mnthconstmp     
   --where mdate >= @fmdate and mdate < @todate     
    group by Month,YEAR    
              
   select * from #UserStatsAll order by mYEAR,mMonth             
     drop table #UserStatsAll              
     drop table #UserStats              
     drop table #mnthconstmp                   
 SET NOCOUNT ON;                  
                   
                 
end


GO

