   Procedure: [dbo].[filter_purchase_analysis]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext filter_purchase_analysis  
  
           
--exec get_smsConsumprion_analysis 335,'2017-01-01', '2018-07-31', 'Days', 7              
--exec get_purchase_analysis 335,'2017-01-01', '2018-07-31', 'Days', 7              
CREATE   PROCEDURE filter_purchase_analysis                  
(                  
@USER_ID as bigint =null,        
@Country as varchar(max)='All',          
@state as varchar(max)='All',          
@city as varchar(max)='All',          
@uType as varchar(max)='All',                 
@FromDate as date = null,                  
@Todate as Date =null,                
@Range nvarchar(50)='Day',                
@RangeValue int=7,              
@rpttype int = 1              
)                  
as                  
begin                 
declare @MID bigint                
                
              
--select IsSMS,IsMail,* from AddCreditDetails where Reason ='Purchase'              
--and userid in (select USER_ID from user_detail where M_ID = 10043)            
-- and (IsSMS=1 or IsMail =1)            
               
select @MID =                
rd.Reseller_ID from user_detail (nolock) ud inner join reseller_detail (nolock) rd                
on rd.User_ID = ud.User_ID --inner join user_detail md                
where ud.TYPE in (1,2) and ud.USER_ID = @USER_ID                
          
-------------------          
select user_id,Country, city,state,m_id,          
 (Case when Type=0 then 'User' else case when Type=2 then 'Sub Reseller' else 'Reseller' end end)              
 uType           
 into #user_tmp             
   from user_detail (nolock) where m_id = @MID order by Convert(date,DateCreated)         
             
 if (@Country <>'All')            
   delete From #user_tmp where Country not in (@Country)          
 if (@state <>'All')          
   delete From #user_tmp where state not in (@state)          
if (@city<>'All')          
    delete From #user_tmp where City not in (@city)          
if (@uType<>'All')          
    delete From #user_tmp where uType not in (@uType)              
          
select Convert(date,CreatedDate) CreatedDate,IsSMS,IsMail,          
Credits,Amount,userid into #rmp_Credit_Details                  
  from AddCreditDetails (nolock) where Convert(date,CreatedDate)                 
 between @FromDate and @Todate and userid in (select USER_ID from #user_tmp)           
  and (IsSMS=1 or IsMail =1) and  Reason ='Purchase'          
          
           
drop table #user_tmp          
                
select @FromDate = MIN(CreatedDate) ,@Todate =MAX(CreatedDate)           
from  #rmp_Credit_Details               
-------------------          
          
 create table #UserStats(dt date,FromTo varchar(100), smsno bigint,mailno bigint,            
 smsVal bigint,mailVal bigint, userid bigint)                
 create table #UserStatsAll(Fromto varchar(100),smsno bigint,mailno bigint,            
 smsVal bigint,mailVal bigint, userid bigint, Rangevalue nvarchar(50),dt date)                
    declare @RangeValue1 int                
 set @RangeValue1=coalesce(@rangevalue,15)                
            
 StartBuildingTable:                
               
               
 set @Range=coalesce(@range,'Day')                
 set @RangeValue=coalesce(@rangevalue,7)                
 declare @datecreated1 Date               
 set @datecreated1=@FromDate                
              
 If @Range='Day'                
  begin                
   if datediff(dd,@fromdate,@todate)>12*@RangeValue                
   begin                
    set @RangeValue=ceiling((datediff(dd,@fromdate,@todate))/12) +1                
   end               
   end              
   else if @Range = 'Month'                
  begin   
  if ceiling(datediff(mm,@fromdate,@todate))>12                
   begin                
   set @RangeValue=ceiling((datediff(mm,@fromdate,@todate))/12) +1       
  end   
  else  
 begin  
  set @RangeValue= ceiling(datediff(mm,@fromdate,@todate))  
 end  
  end        
set @RangeValue1 =  @RangeValue    
                
while @datecreated1 <= @todate                
 begin                
               
   If @Range='Day'                
  begin               
     if   dateadd(dd,(@Rangevalue-1),@datecreated1) >  @todate   
 BEGIN  
  set  @Rangevalue = ceiling(datediff(dd,@datecreated1,@todate))+1   
 END           
 insert into #userstats(dt,FromTo,smsno,mailno,smsVal,mailVal, userid )                
 select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+            
 convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),            
 SUM(case when IsSMS=1 then Credits else 0 end) smsno,            
 SUM(case when IsMail=1 then Credits else 0 end) mailno,            
 SUM(case when IsSMS=1 then Amount else 0 end) smsVal,            
 SUM(case when IsMail=1 then Amount else 0 end) mailVal,            
 userid               
 from #rmp_Credit_Details where Convert(date,CreatedDate)             
 between @datecreated1 and dateadd(dd,(@Rangevalue-1),@datecreated1)                
 group by userid                
   set @datecreated1=dateadd(dd,@Rangevalue, @datecreated1)                
  end                
                  
                
                
  else if @Range = 'Month'                
  begin                
                 
  declare @monthend date                
  if (@Rangevalue > 12)  
 set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + @Rangevalue, 0))  
  else  
  set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + 1, 0))  
   
  if   @monthend >  @todate   
 BEGIN  
 set @monthend =  @todate   
 END      
             
 insert into #userstats(dt,FromTo,smsno,mailno,smsVal,mailVal, userid )                
 select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+            
 convert(varchar, @monthend, 103),            
 SUM(case when IsSMS=1 then Credits else 0 end) smsno,            
 SUM(case when IsMail=1 then Credits else 0 end) mailno,            
 SUM(case when IsSMS=1 then Amount else 0 end) smsVal,            
 SUM(case when IsMail=1 then Amount else 0 end) mailVal,            
 userid               
 from #rmp_Credit_Details where Convert(date,CreatedDate)             
 between @datecreated1 and @monthend               
 group by userid                
                  
   set @datecreated1=dateadd(dd,1,@monthend)                 
  end                
              
end                
              
insert into #UserStatsAll (dt,Fromto ,smsno ,mailno ,            
   smsVal ,mailVal,userid, RangeValue  ) -- , Rangevalue nvarchar(50))                
    select dt,max(FromTo),sum(smsno),sum(mailno),sum(smsVal),              
    sum(mailVal),MAX(userid),@RangeValue            
    from #UserStats   group by dt order by dt                    
             
                
            
   select Fromto ,smsno ,mailno ,            
 smsVal ,mailVal,userid, RangeValue from #UserStatsAll            
         
     select @RangeValue1 RangeValue    
         
     drop table #UserStatsAll            
     drop table #UserStats           
     drop table #rmp_Credit_Details           
                      
 SET NOCOUNT ON;                
                 
               
end


GO

/* ============================================================
   Procedure: [dbo].[filter_SMSConsumption_analysis]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext filter_SMSConsumption_analysis

--sp_helptext filter_SMSConsumption_analysis  
--sp_helptext filter_SMSConsumption_analysis    
    
--sp_helptext filter_SMSConsumption_analysis      
--exec filter_SMSConsumption_analysis 335,'Delhi','New Delhi','Sub Reseller',0,0,'2018-01-01', '2018-07-31', 'Day', 7                
CREATE   PROCEDURE filter_SMSConsumption_analysis                    
(                    
@USER_ID as bigint =null,      
@Country as varchar(max)='All',          
@state as varchar(max)='All',        
@city as varchar(max)='All',        
@uType as varchar(max)='All',        
@constRange as bigint= 0,        
@constndRange as bigint= 0,        
@FromDate as date = null,                    
@Todate as Date =null,                  
@Range nvarchar(50)='Day',                  
@RangeValue int=7,                
@rpttype int = 1                
)                    
as                    
begin                   
declare @MID bigint                  
                  
--select @FromDate ='2009-08-01',                  
-- @Todate ='2018-12-31'                  
                   
                  
                  
select @MID =                  
rd.Reseller_ID from user_detail ud inner join reseller_detail rd                  
on rd.User_ID = ud.User_ID --inner join user_detail md                  
where ud.TYPE in (1,2) and ud.USER_ID = @USER_ID        
-------------------------        
        
 select user_id,Country,city,state,m_id,        
 (Case when Type=0 then 'User' else case when Type=2 then 'Sub Reseller' else 'Reseller' end end)            
 uType  into #user_tmp           
   from user_detail  where m_id = @MID order by Convert(date,DateCreated)         
       
   if (@Country <>'All')          
   delete From #user_tmp where Country not in (@Country)        
          
 if (@state <>'All')        
   delete From #user_tmp where state not in (@state)        
if (@city<>'All')        
    delete From #user_tmp where City not in (@city)        
if (@uType<>'All')        
    delete From #user_tmp where uType not in (@uType)            
        
select Convert(date,DateCreated) DateCreated, Debits,User_ID into #rmp_Credit_Details                
  from Credit_Details where Convert(date,DateCreated)               
 between @FromDate and @Todate and m_id = @MID and FromUser_ID = User_ID              
 and User_ID in (select USER_ID from #user_tmp)         
         
drop table #user_tmp        
              
select @FromDate = MIN(DateCreated) ,@Todate =MAX(DateCreated)         
from  #rmp_Credit_Details             
        
-------------------------                
 create table #UserStats(dt date,FromTo varchar(100),tCount int, user_id bigint)                  
    create table #UserStatsAll(Fromto varchar(100),db100 bigint,db1k bigint,                
    db10k bigint,db1L bigint,db10L bigint, dbgr10L bigint, Rangevalue nvarchar(50),dt date)                  
    declare @RangeValue1 int                  
 set @RangeValue1=coalesce(@rangevalue,15)                  
              
 StartBuildingTable:                  
                 
                 
 set @Range=coalesce(@range,'Day')                  
 set @RangeValue=coalesce(@rangevalue,7)                  
 declare @datecreated1 Date                 
 set @datecreated1=@FromDate                  
                
                   
If @Range='Day'              
  begin              
   if datediff(dd,@fromdate,@todate)>12*@RangeValue              
   begin              
    set @RangeValue=ceiling((datediff(dd,@fromdate,@todate))/12) +1              
   end             
   end            
   else if @Range = 'Month'              
  begin 
  if ceiling(datediff(mm,@fromdate,@todate))>12              
	  begin              
	  set @RangeValue=ceiling((datediff(mm,@fromdate,@todate))/12) +1     
	 end 
  else
	begin
	 set @RangeValue= ceiling(datediff(mm,@fromdate,@todate))
	end
  end      
set @RangeValue1 =  @RangeValue 
                
while @datecreated1 <= @todate                  
 begin                  
                  
   If @Range='Day'                  
  begin 
  if   dateadd(dd,(@Rangevalue-1),@datecreated1) >  @todate 
	BEGIN
	 set  @Rangevalue = ceiling(datediff(dd,@datecreated1,@todate))+1 
	END                   
if @constRange = 0 and @constndRange = 0        
 insert into #userstats(dt,FromTo,tCount, user_id )                  
 select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+              
 convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),              
 SUM(Debits),User_ID                 
 from #rmp_Credit_Details         
 where Convert(date,DateCreated)               
 between @datecreated1 and dateadd(dd,(@Rangevalue-1),@datecreated1)                  
 --and m_id = @MID and FromUser_ID = User_ID              
   group by User_ID        
   else        
  insert into #userstats(dt,FromTo,tCount, user_id )                  
 select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+              
 convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),              
 SUM(Debits),User_ID                 
 from #rmp_Credit_Details         
 where Convert(date,DateCreated)          between @datecreated1 and dateadd(dd,(@Rangevalue-1),@datecreated1)                  
 --and m_id = @MID and FromUser_ID = User_ID              
   group by User_ID having SUM(Debits) between @constRange and @constndRange        
                     
   set @datecreated1=dateadd(dd,@Rangevalue, @datecreated1)                  
  end                  
                    
                     
                     
                  
  else if @Range = 'Month'                  
  begin                  
                   
  declare @monthend date                  
  if (@Rangevalue > 12)
	set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + @Rangevalue, 0))
  else
 	set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + 1, 0))
	
  if   @monthend >  @todate 
	BEGIN
	set @monthend =  @todate 
	END   
         
  if @constRange = 0 and @constndRange = 0              
 insert into #userstats(dt,FromTo,tCount, user_id )                  
 select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+              
 convert(varchar, @monthend, 103),              
 SUM(Debits),User_ID                 
 from #rmp_Credit_Details where Convert(date,DateCreated)               
 between @datecreated1 and @monthend               
 --and m_id = @MID and FromUser_ID = User_ID              
 group by User_ID                 
  else        
  insert into #userstats(dt,FromTo,tCount, user_id )                  
 select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+              
 convert(varchar, @monthend, 103),              
 SUM(Debits),User_ID                 
 from #rmp_Credit_Details where Convert(date,DateCreated)               
 between @datecreated1 and @monthend               
 --and m_id = @MID and FromUser_ID = User_ID              
 group by User_ID having SUM(Debits) between @constRange and @constndRange                 
                    
   set @datecreated1=dateadd(dd,1,@monthend)                   
  end                  
end                  
                
                 
   insert into #UserStatsAll(dt,Fromto,db100 ,db1k ,                
    db10k ,db1L ,db10L , dbgr10L )                  
    select dt,max(FromTo),                
    sum(case when tCOUNT <= 100 then tCOUNT else 0 end),                 
     sum(case when tCOUNT > 100 and tCOUNT <= 1000 then tCOUNT else 0 end),              
    sum(case when tCOUNT > 1000 and tCOUNT <= 10000 then tCOUNT else 0 end),                
    sum(case when tCOUNT > 10000 and tCOUNT <= 100000 then tCOUNT else 0 end),               
    sum(case when tCOUNT > 100000 and tCOUNT <=1000000 then tCOUNT else 0 end),               
    sum(case when tCOUNT > 1000000 then tCOUNT else 0 end)               
    from #UserStats   group by dt order by dt                      
               
    --select dt,max(FromTo) FromTo,               
    --sum(case when tCOUNT <= 100 then 1 else 0 end) db100,                 
    -- sum(case when tCOUNT > 100 and tCOUNT <= 1000 then 1 else 0 end) db1k,              
    --sum(case when tCOUNT > 1000 and tCOUNT <= 10000 then 1 else 0 end) db10k,                
    --sum(case when tCOUNT > 10000 and tCOUNT <= 100000 then 1 else 0 end) db1L,               
    --sum(case when tCOUNT > 100000 and tCOUNT <=1000000 then 1 else 0 end) db10L,               
    --sum(case when tCOUNT > 1000000 then tCOUNT else 0 end) dbgr10L              
    --from #UserStats              
    --group by  dt order by dt                     
  if @constRange = 0 and @constndRange = 0              
   select Fromto,db100 ,db1k ,                
    db10k ,db1L ,db10L , dbgr10L from #UserStatsAll          
  else        
    select max(FromTo) FromTo,               
    sum(tCOUNT) tCOUNT              
    from #UserStats  group by  dt order by dt                
       
   select @RangeValue1 RangeValue      
     drop table #rmp_Credit_Details          
     drop table #UserStatsAll              
     drop table #UserStats              
                        
 SET NOCOUNT ON;                  
                   
                 
end


GO

/* ============================================================
   Procedure: [dbo].[filter_user_analysis]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [filter_user_analysis]                    
(                    
@USER_ID as bigint =null,      
@Country as varchar(max)='All',          
@state as varchar(max)='All',          
@city as varchar(max)='All',          
@uType as varchar(max)='All',          
@FromDate as date = null,                    
@Todate as Date =null,                  
@Range nvarchar(50)='Day',                  
@RangeValue int=7,                
@rpttype int = 1                
)                    
as                    
begin                   
declare @MID bigint                  
                  
--select @FromDate ='2009-08-01',                  
-- @Todate ='2018-12-31'                  
                   
                  
                  
select @MID =                  
rd.Reseller_ID from user_detail (nolock) ud inner join reseller_detail (nolock) rd                  
on rd.User_ID = ud.User_ID --inner join user_detail md                  
where ud.TYPE in (1,2) and ud.USER_ID = @USER_ID                  
           
 select Convert(date,DateCreated) DateCreated,Type ,user_id,Country,city,state,m_id,                 
   (Case when Type=0 then 'User' else case when Type=2 then 'Sub Reseller' else 'Reseller' end end)          
   uType into #user_tmp             
   from user_detail (nolock)  where Convert(date,DateCreated) between @FromDate               
   and @Todate                  
  and m_id = @MID order by Convert(date,DateCreated)           
       
  if (@Country <>'All')          
   delete From #user_tmp where Country not in (@Country)          
 if (@state <>'All')          
   delete From #user_tmp where state not in (@state)          
if (@city<>'All')          
    delete From #user_tmp where City not in (@city)          
if (@uType<>'All')          
    delete From #user_tmp where uType not in (@uType)              
          
select @FromDate = MIN(DateCreated) ,@Todate =MAX(DateCreated)           
from  #user_tmp               
           
 create table #UserStats(dt date, FromTo varchar(100),tCount int, Type nvarchar(20))                  
    create table #UserStatsAll(Fromto varchar(100),muser bigint,resaller bigint,                
    sub_resaller bigint, Rangevalue nvarchar(50),dt date )                  
    declare @RangeValue1 int                  
 set @RangeValue1=coalesce(@rangevalue,15)                  
              
                 
                  
              
              
 StartBuildingTable:                  
                 
                 
 set @Range=coalesce(@range,'Day')                  
 set @RangeValue=coalesce(@rangevalue,7)                  
 declare @datecreated1 date              
 set @datecreated1=@FromDate                  
            
           
                   
If @Range='Day'                
  begin                
   if datediff(dd,@fromdate,@todate)>12*@RangeValue                
   begin                
    set @RangeValue=ceiling((datediff(dd,@fromdate,@todate))/12) +1                
   end               
   end              
   else if @Range = 'Month'                
  begin   
  if ceiling(datediff(mm,@fromdate,@todate))>12                
   begin                
   set @RangeValue=ceiling((datediff(mm,@fromdate,@todate))/12) +1       
  end   
  else  
 begin  
  set @RangeValue= ceiling(datediff(mm,@fromdate,@todate))  
 end  
  end        
set @RangeValue1 =  @RangeValue           
           
            
                   
  --   select @datecreated1,convert(varchar, Convert(date,@datecreated1), 103)+'-'+              
  --convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103)              
                   
while @datecreated1 <= @todate                  
 begin                  
                  
   If @Range='Day'  or @Range='Days'                 
  begin    
  if   dateadd(dd,(@Rangevalue-1),@datecreated1) >  @todate   
 BEGIN  
  set  @Rangevalue = ceiling(datediff(dd,@datecreated1,@todate))+1   
 END                   
   insert into #userstats(dt, FromTo,tCount, Type)                 
   select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+              
  convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),              
   Count(*),                 
   (Case when Type=0 then 'User' else case when Type=2 then 'Sub Reseller' else 'Reseller' end end)        
   from #user_tmp       where Convert(date,DateCreated) between @datecreated1               
   and dateadd(dd,(@Rangevalue-1),@datecreated1) --and          
   --user_id in (select user_id from #user_tmp)                  
    --and m_id = @MID            
    group by Type                  
               
                  
                  
   set @datecreated1=dateadd(dd,@Rangevalue, @datecreated1)                  
              
                
  -- select convert(varchar, Convert(date,@datecreated1), 103)+'-'+              
  --convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),              
  -- Count(*),                 
  -- (Case when Type=0 then 'User' else case when Type=2 then 'Sub Reseller' else 'Reseller' end end)              
  -- from user_detail       where Convert(date,DateCreated) between @datecreated1               
  -- and dateadd(dd,(@Rangevalue-1),@datecreated1)                  
  --  and m_id = @MID  group by Type                 
                  
  --  select @Rangevalue,@datecreated1               
  end                  
                    
                
                     
                  
  else if @Range = 'Month'                  
  begin                  
                   
  declare @monthend date                
  if (@Rangevalue > 12)  
 set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + @Rangevalue, 0))  
  else  
  set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + 1, 0))  
   
  if   @monthend >  @todate   
 BEGIN  
 set @monthend =  @todate   
 END       
  insert into #userstats(FromTo,tCount,Type)                  
  select convert(varchar, @datecreated1, 103)+'-'+              
  convert(varchar, @monthend, 103)  ,Count(*),                 
  (Case when Type=0 then 'User' else case when Type=2 then 'Sub Reseller' else 'Reseller' end end)                 
   from #user_tmp                     
    where Convert(date,DateCreated) between @datecreated1 and @monthend            
    --and  user_id in (select user_id from #user_tmp)                    
    --and m_id = @MID            
    group by Type                  
  set @datecreated1=dateadd(dd,1,@monthend)                   
  end                  
                  
                      
                
end                  
                
                 
   insert into #UserStatsAll(dt,Fromto,muser,resaller, sub_resaller)                  
    select dt, max(FromTo),                
    sum(Case when Type='User' then tCOUNT else 0 end),                 
    sum(Case when Type='Reseller' then tCOUNT else 0 end),                
    sum(Case when Type='Sub Reseller' then tCOUNT else 0 end)                
      from #UserStats   group by dt order by dt                       
 --if (@uType<>'All')      
 --select dt, max(FromTo),                
 --   sum(tCOUNT) tCOUNT               
 --   from #UserStats   group by dt order by dt         
               
    ----select SUM(tcount) uTotal, Type base from #UserStats              
    ----group by Type                      
              
    ----select SUM(tcount) uTotal, max(FromTo) base from #UserStats              
    ----group by dt  order by dt               
     --select * from #user_tmp          
                   
     select Fromto, resaller, sub_resaller, muser from #UserStatsAll              
     select @RangeValue1 RangeValue    
                   
     drop table #UserStatsAll              
     ---drop table #alltbl              
     drop table #UserStats           
     drop table #user_tmp             
                        
 SET NOCOUNT ON;                  
                   
                 
end


GO

/* ============================================================
   Procedure: [dbo].[final_deduction_VoiveCost]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROCEDURE [dbo].[final_deduction_VoiveCost]
as    
begin    
    
exec usp_voicecdrsync    
    
--alter table BatchVoiceInfo add isprocessed  int default 0    
--maxduration,isprocessed,refund,pulse,creditdeducted,costperpulse    
select ROW_NUMBER() over(order by BATCHID) rcn,batchid,TotalRecords,PulseRate,     
 Price, VoiceCredit,BatchInsertTime,Appid into #temp from BatchVoiceInfo bth    
 where not exists(select 1 from kit19cloudvoicefinaltbl(nolock) where processed=0 and    
  batchid= bth.batchid) and isprocessed=1 and refund=0    
    
    
declare @TotalRecords int,@PulseRate int, @Price Decimal(18,4), @VoiceCredit Decimal(18,4)    
Declare @bmin int, @bmax int, @bcount int    
declare @min int =0, @max int =0     
select @bmin = MIN(rcn), @bmax = MAX(rcn)  --, @bcount = COUNT(*)    
 from #temp    
 declare @batch bigint,@BatchInsertTime datetime,@Appid bigint    
 while @bmin <@bmax    
 begin    
     
 select @batch = Batchid,@TotalRecords= TotalRecords,@PulseRate=PulseRate,     
  @Price=Price, @VoiceCredit=VoiceCredit,@BatchInsertTime=BatchInsertTime,@Appid=Appid from #temp    
 where rcn = @bmin    
    
 select ROW_NUMBER() over(order by kd.id) rcn,  fl.dnino,fl.VoiceQueueID,messageid,    
  kd.duration, kd.billsec,kl.*,0.0 cal_cost,batchid, 0 [USER_ID],kd.uniqueid  into #tmpfldtl     
  from kit19calls kl (nolock)    
  inner join kit19cdr kd (nolock)   
 on kd.uniqueid = kl.uniqueid     
 inner join kit19cloudvoicefinaltbl fl(nolock) on fl.kit19uniqueid = kl.kit19uniqueid    
 where kl.context='outbound' and batchid =@batch order by rcn    
     
 declare @caltot as int    
 select @caltot=count(*) from kit19cloudvoicefinaltbl where batchid =@batch    
     
 set  @caltot =@TotalRecords-@caltot    
 declare @IntCost Decimal(18,4)    
 set @IntCost =(@caltot*@PulseRate)+@Price    
 declare @uid bigint,@billsec int    
     
    
 select @max=MAX(rcn), @min=MIN(rcn) from #tmpfldtl     
    
 --Declare @tptbl as tbl_IntMobtbl,@ROW_COUNT int, @duration int,@BATCHID bigint,    
 --@uid    
 declare @TotCost Decimal(18,4), @uniqueid varchar(50)    
 while @min <= @max    
 begin    
  select @billsec=billsec,@uid=tp.USER_ID,@uniqueid=uniqueid from #tmpfldtl tp inner join dbo.Cloud_app_master ap    
   on ap.appid = tp.appid where rcn = @min    
  declare @intdur int    
  select @intdur =Convert(int,@billsec/@PulseRate)                            
  if @billsec%@PulseRate  > 0                           
    set @intdur = @intdur+1                              
       update kit19cdr set  call_cost = @intdur*@Price where uniqueid = @uniqueid       
   set @min =@min +1    
   set @TotCost =@TotCost+(@intdur*@Price)    
 end     
  declare @balance decimal(18,4), @M_ID bigint, @creditid bigint    
  select @creditid=(select max(Credit_ID) from IntCredit_Details where User_ID=@uid)       
     
   select @Balance=  Balance                  
   from IntCredit_Details where User_ID=@uid                   
             and Credit_ID = @creditid      
      
  SELECT TOP(1) @M_ID=M_ID FROM USER_DETAIL with (nolock) WHERE USER_ID=@uid     
                
  if @VoiceCredit > @TotCost+@IntCost 
 insert into IntCredit_Details(FromUser_ID,M_ID,User_ID,Debits,Credits,              
  Balance,Validity,Remarks,typecredit,batchid )                            
  values(@uid,@M_ID,@uid,0, @VoiceCredit-(@TotCost+@IntCost),@Balance+(@VoiceCredit-(@TotCost+@IntCost)),99999,    
  'REVERSE for voice Brodcast',1,@batch)  

  declare @intCreditId bigint = scope_identity()
  exec usp_rf_UpdateReserveFundTransaction @CreditId = @intCreditId     
      
insert into voice_finalCharge(Batchid, UserId,appid,TotalRec ,CallsRate ,ActCharge ,Reverc_amt ,Date_Deducted  ,    
 Date_Reversed ) select @batch, @uid,@Appid,@caltot, @Price,@VoiceCredit, @TotCost+@IntCost ,@BatchInsertTime,GETDATE()     
     
 set @bmin=@bmin+1    
     
end     
end 



