/* ============================================================
   Procedure: [dbo].[fn_GetGroupMessage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

   

CREATE   PROCEDURE [dbo].[fn_GetGroupMessage] --12 -- 335,'#personname#'
AS
BEGIN
	CREATE TABLE #tempTemplate1
	(
		TemplateID     BIGINT,
		ParentID       BIGINT
	)
	
	
	
	CREATE TABLE #tempTemplate2
	(
		TemplateID     BIGINT,
		ParentID       BIGINT
	)  
	
	
	
	IF EXISTS (
	       SELECT 'x'
	       FROM   UserGroupTemplateMix AS ugtm2
	              INNER JOIN UserCampaignMaster AS ucm2
	                   ON  ugtm2.GroupID = ucm2.TemplateGroupID
	       WHERE  ucm2.ID IN (SELECT ucerm.CampaignID
	                          FROM   UserCampaignExecutionRecipientsMessage AS 
	                                 ucerm)
	              AND ugtm2.IsActivated = 1
	   )
	BEGIN
	    INSERT INTO #tempTemplate1
	      (
	        TemplateID,
	        ParentID
	      )
	    SELECT DISTINCT ugtm.TemplateID,
	           ugtm.ParentID
	    FROM   UserGroupTemplateMix AS ugtm
	           INNER JOIN UserCampaignMaster AS ucm
	                ON  ugtm.GroupID = ucm.TemplateGroupID
	    WHERE  ucm.ID   IN (SELECT ucerm.CampaignID
	                        FROM   UserCampaignExecutionRecipientsMessage AS 
	                               ucerm)
	           AND ugtm.OrderNo = (
	                   SELECT ugtm2.OrderNo + 1
	                   FROM   UserGroupTemplateMix AS ugtm2
	                          INNER JOIN UserCampaignMaster AS ucm2
	                               ON  ugtm2.GroupID = ucm2.TemplateGroupID
	                   WHERE  ucm2.ID   IN (SELECT ucerm.CampaignID
	                                        FROM   
	                                               UserCampaignExecutionRecipientsMessage AS 
	                                               ucerm)
	                          AND ugtm2.IsActivated = 1
	               )
	END
	ELSE
	BEGIN
	    INSERT INTO #tempTemplate2
	      (
	        TemplateID,
	        ParentID
	      )
	    SELECT DISTINCT ugtm.TemplateID,
	           ugtm.ParentID
	    FROM   UserGroupTemplateMix AS ugtm
	           INNER JOIN UserCampaignMaster AS ucm
	                ON  ugtm.GroupID = ucm.TemplateGroupID
	    WHERE  ucm.ID IN (SELECT ucerm.CampaignID
	                      FROM   UserCampaignExecutionRecipientsMessage AS ucerm)
	           AND ugtm.OrderNo = (
	                   SELECT TOP 1 ugtm2.OrderNo
	                   FROM   UserGroupTemplateMix AS ugtm2
	                          INNER JOIN UserCampaignMaster AS ucm2
	                               ON  ugtm2.GroupID = ucm2.TemplateGroupID
	                   WHERE  ucm2.ID IN (SELECT ucerm.CampaignID
	                                      FROM   
	                                             UserCampaignExecutionRecipientsMessage AS 
	                                             ucerm)
	                   ORDER BY
	                          ugtm2.OrderNo
	               )
	END
	
	
	
	
	
	
	
	SELECT TemplateID INTO     #tempTemplate
	FROM   (
	           SELECT TemplateID
	           FROM   #tempTemplate1
	           
	           
	           
	           UNION
	           
	           
	           
	           SELECT TemplateID
	           FROM   #tempTemplate2
	       )                   A
	
	
	
	
	
	DROP TABLE #tempTemplate1
	
	
	
	DROP TABLE #tempTemplate2
	
	
	
	
	
	
	
	UPDATE UserGroupTemplateMix
	SET    IsActivated = 0
	WHERE  GroupID IN (SELECT ucm.TemplateGroupID
	                   FROM   UserCampaignMaster AS ucm
	                   WHERE  ucm.ID IN (SELECT ucerm.CampaignID
	                                     FROM   
	                                            UserCampaignExecutionRecipientsMessage AS 
	                                            ucerm))
	
	
	
	
	
	
	
	UPDATE UserGroupTemplateMix
	SET    IsActivated = 1
	WHERE  TemplateID IN (SELECT TemplateID
	                      FROM   #tempTemplate)
	
	
	
	UPDATE UserGroupTemplateMix
	SET    IsActivated = 0
	
	
	
	SELECT A.CampaignID,
	       A.ParentID,
	       A.messageContent,
	       A.Mobile,
	       A.SenderID,
	       A.AccountUsed,
	       A.IsUnicode
	FROM   (
	           SELECT uceh.CampaignID,
	                  uceh.ParentID,
	                  CAST(
	                      CAST(
	                          dbo.fn_getEnquiryMessage(ucm.ParentID, umt.MailContent, ucerm.Mobile) 
	                          AS VARCHAR(MAX)
	                      ) 
	                      
	                      
	                      
	                      COLLATE 
	                      
	                      
	                      
	                      
	                      
	                      
	                      
	                      Latin1_General_CI_AI AS 
	                      VARCHAR(MAX)
	                  ) AS messageContent,
	                  ucerm.Mobile,
	                  ucm.SenderID,
	                  ucm.AccountUsed,
	                  ucm.IsUnicode
	           FROM   UserCampaignExecutionHistory uceh
	                  INNER JOIN UserCampaignMaster ucm
	                       ON  ucm.ID = uceh.CampaignID
	                  INNER JOIN UserMailTemplate umt
	                       ON  umt.ID  IN (SELECT TemplateID
	                                       FROM   #tempTemplate)
	                  INNER JOIN UserCampaignExecutionRecipientsMessage 
	                       ucerm
	                       ON  ucerm.CampaignID = uceh.CampaignID
	                       AND ucerm.ParentID = umt.ParentID
	           WHERE  uceh.IsRecipients = 1
	                  AND umt.IsEnquiry = 1
	                  AND umt.ID  IN (SELECT TemplateID
	                                  FROM   #tempTemplate)
	           
	           
	           
	           UNION ALL 
	           
	           
	           
	           SELECT uceh.CampaignID,
	                  uceh.ParentID,
	                  CAST(
	                      CAST(
	                          dbo.fn_getLeadsMessage(ucm.ParentID, umt.MailContent, ucerm.Mobile)
	                          AS VARCHAR(MAX)
	                      ) 
	                      
	                      
	                      
	                      COLLATE 
	                      
	                      
	                      
	                      
	                      
	                      
	                      
	                      Latin1_General_CI_AI AS 
	                      VARCHAR(MAX)
	                  ),
	                  ucerm.Mobile,
	                  ucm.SenderID,
	                  ucm.AccountUsed,
	                  ucm.IsUnicode
	           FROM   UserCampaignExecutionHistory uceh
	                  INNER JOIN UserCampaignMaster ucm
	                       ON  ucm.ID = uceh.CampaignID
	                  INNER JOIN UserMailTemplate umt
	                       ON  umt.ID  IN (SELECT TemplateID
	                                       FROM   #tempTemplate)
	                  INNER JOIN UserCampaignExecutionRecipientsMessage 
	                       ucerm
	                       ON  ucerm.CampaignID = uceh.CampaignID
	                       AND ucerm.ParentID = umt.ParentID
	           WHERE  uceh.IsRecipients = 1
	                  AND (umt.IsLeads = 1 OR umt.IsConversion = 1)
	                  AND umt.ID  IN (SELECT TemplateID
	                                  FROM   #tempTemplate)
	           
	           
	           
	           UNION ALL 
	           
	           SELECT uceh.CampaignID,
	                  uceh.ParentID,
	                  CAST(
	                      CAST(
	                          dbo.fn_GetListMessage(umt.MailContent, umt.ListID, uceh.ParentID, ucerm.Mobile) 
	                          AS VARCHAR(MAX)
	                      ) 
	                      
	                      
	                      
	                      COLLATE 
	                      
	                      
	                      
	                      
	                      
	                      
	                      
	                      Latin1_General_CI_AI AS 
	                      VARCHAR(MAX)
	                  ),
	                  ucerm.Mobile,
	                  ucm.SenderID,
	                  ucm.AccountUsed,
	                  ucm.IsUnicode
	           FROM   UserCampaignExecutionHistory 
	                  uceh
	                  INNER JOIN UserCampaignMaster ucm
	                       ON  ucm.ID = uceh.CampaignID
	                  INNER JOIN UserMailTemplate 
	                       umt
	                       ON  umt.ID  IN (SELECT TemplateID
	                                       FROM   #tempTemplate)
	                  INNER JOIN UserCampaignExecutionRecipientsMessage 
	                       ucerm
	                       ON  ucerm.CampaignID = uceh.CampaignID
	                       AND ucerm.ParentID = umt.ParentID
	           WHERE  uceh.IsRecipients = 1
	                  AND umt.IsList = 1
	                  AND umt.ID  IN (SELECT TemplateID
	                                  FROM   #tempTemplate)
	       ) A
	
	
	
	
	
	
	
	DROP TABLE #tempTemplate
END





GO

/* ============================================================
   Procedure: [dbo].[fn_GetGroupMessageMails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[fn_GetGroupMessageMails] --12 -- 335,'#personname#'
AS
BEGIN
	CREATE TABLE #tempTemplate1
	(
		TemplateID     BIGINT,
		ParentID       BIGINT
	)
	
	
	
	CREATE TABLE #tempTemplate2
	(
		TemplateID     BIGINT,
		ParentID       BIGINT
	)
	
	
	
	
	
	
	
	IF EXISTS (
	       SELECT 'x'
	       FROM   UserGroupTemplateMix AS ugtm2
	              INNER JOIN UserCampaignMaster AS ucm2
	                   ON  ugtm2.GroupID = ucm2.TemplateGroupID
	       WHERE  ucm2.ID IN (SELECT ucerm.CampaignID
	                          FROM   EmailsFilterCampaignExecution AS ucerm)
	              AND ugtm2.IsActivated = 1
	   )
	BEGIN
	    INSERT INTO #tempTemplate1
	      (
	        TemplateID,
	        ParentID
	      )
	    SELECT DISTINCT ugtm.TemplateID,
	           ugtm.ParentID
	    FROM   UserGroupTemplateMix AS ugtm
	           INNER JOIN UserCampaignMaster AS ucm
	                ON  ugtm.GroupID = ucm.TemplateGroupID
	    WHERE  ucm.ID   IN (SELECT ucerm.CampaignID
	                        FROM   EmailsFilterCampaignExecution AS ucerm)
	           AND ugtm.OrderNo = (
	                   SELECT ugtm2.OrderNo + 1
	                   FROM   UserGroupTemplateMix AS ugtm2
	                          INNER JOIN UserCampaignMaster AS ucm2
	                               ON  ugtm2.GroupID = ucm2.TemplateGroupID
	                   WHERE  ucm2.ID   IN (SELECT ucerm.CampaignID
	                                        FROM   EmailsFilterCampaignExecution AS 
	                                               ucerm)
	                          AND ugtm2.IsActivated = 1
	               )
	END
	ELSE
	BEGIN
	    INSERT INTO #tempTemplate2
	      (
	        TemplateID,
	        ParentID
	      )
	    SELECT DISTINCT ugtm.TemplateID,
	           ugtm.ParentID
	    FROM   UserGroupTemplateMix AS ugtm
	           INNER JOIN UserCampaignMaster AS ucm
	                ON  ugtm.GroupID = ucm.TemplateGroupID
	    WHERE  ucm.ID IN (SELECT ucerm.CampaignID
	                      FROM   EmailsFilterCampaignExecution AS ucerm)
	           AND ugtm.OrderNo = (
	                   SELECT TOP 1 ugtm2.OrderNo
	                   FROM   UserGroupTemplateMix AS ugtm2
	                          INNER JOIN UserCampaignMaster AS ucm2
	                               ON  ugtm2.GroupID = ucm2.TemplateGroupID
	                   WHERE  ucm2.ID IN (SELECT ucerm.CampaignID
	                                      FROM   EmailsFilterCampaignExecution AS 
	                                             ucerm)
	                   ORDER BY
	                          ugtm2.OrderNo
	               )
	END
	
	
	
	
	
	
	
	SELECT TemplateID INTO     #tempTemplate
	FROM   (
	           SELECT TemplateID
	           FROM   #tempTemplate1
	           
	           
	           
	           UNION
	           
	           
	           
	           SELECT TemplateID
	           FROM   #tempTemplate2
	       )                   A
	
	
	
	
	
	DROP TABLE #tempTemplate1
	
	
	
	DROP TABLE #tempTemplate2
	
	
	
	
	
	
	
	UPDATE UserGroupTemplateMix
	SET    IsActivated = 0
	WHERE  GroupID IN (SELECT ucm.TemplateGroupID
	                   FROM   UserCampaignMaster AS ucm
	                   WHERE  ucm.ID IN (SELECT ucerm.CampaignID
	                                     FROM   EmailsFilterCampaignExecution AS 
	                                            ucerm))
	
	
	
	
	
	
	
	UPDATE UserGroupTemplateMix
	SET    IsActivated = 1
	WHERE  TemplateID IN (SELECT TemplateID
	                      FROM   #tempTemplate)
	
	
	
	UPDATE UserGroupTemplateMix
	SET    IsActivated = 0
	
	
	
	SELECT A.CampaignID,
	       A.ParentID,
	       A.messageContent,
	       A.Mail_ToEmail,
	       A.MailReplyTo,
	       A.AccountUsed,
	       A.MailSubject
	FROM   (
	           SELECT uceh.CampaignID,
	                  uceh.ParentID,
	                  dbo.fn_getEnquiryMessageMail(ucm.ParentID, umt.MailContent, ucerm.Mail_ToEmail) AS 
	                  messageContent,
	                  ucerm.Mail_ToEmail,
	                  ucm.MailReplyTo,
	                  (
	                      SELECT TOP 1 ud.EMail
	                      FROM   User_Detail AS ud
	                      WHERE  ud.[User_ID] = ucm.AccountUsed
	                  ) AS AccountUsed,
	                  ucm.MailSubject
	           FROM   UserCampaignExecutionHistory uceh
	                  INNER JOIN UserCampaignMaster ucm
	                       ON  ucm.ID = uceh.CampaignID
	                  INNER JOIN UserMailTemplate umt
	                       ON  umt.ID  IN (SELECT TemplateID
	                                       FROM   #tempTemplate)
	                  INNER JOIN EmailsFilterCampaignExecution ucerm
	                       ON  ucerm.CampaignID = uceh.CampaignID
	                       AND ucerm.ParentID = umt.ParentID
	           WHERE  uceh.IsRecipients = 1
	                  AND umt.IsEnquiry = 1
	                  AND umt.ID  IN (SELECT TemplateID
	                                  FROM   #tempTemplate)
	           
	           
	           
	           UNION ALL 
	           
	           
	           
	           SELECT uceh.CampaignID,
	                  uceh.ParentID,
	                  dbo.fn_getLeadsMailMessage(ucm.ParentID, umt.MailContent, ucerm.Mail_ToEmail),
	                  ucerm.Mail_ToEmail,
	                  ucm.MailReplyTo,
	                  (
	                      SELECT TOP 1 ud.EMail
	                      FROM   User_Detail AS ud
	                      WHERE  ud.[User_ID] = ucm.AccountUsed
	                  ) AS AccountUsed,
	                  ucm.MailSubject
	           FROM   UserCampaignExecutionHistory uceh
	                  INNER JOIN UserCampaignMaster ucm
	                       ON  ucm.ID = uceh.CampaignID
	                  INNER JOIN UserMailTemplate umt
	                       ON  umt.ID  IN (SELECT TemplateID
	                                       FROM   #tempTemplate)
	                  INNER JOIN EmailsFilterCampaignExecution ucerm
	                       ON  ucerm.CampaignID = uceh.CampaignID
	                       AND ucerm.ParentID = umt.ParentID
	           WHERE  uceh.IsRecipients = 1
	                  AND (umt.IsLeads = 1 OR umt.IsConversion = 1)
	                  AND umt.ID  IN (SELECT TemplateID
	                                  FROM   #tempTemplate)
	           
	           
	           
	           UNION ALL 
	           
	           SELECT uceh.CampaignID,
	                  uceh.ParentID,
	                  dbo.fn_GetListMessageMails(
	                      umt.MailContent,
	                      umt.ListID,
	                      uceh.ParentID,
	                      ucerm.Mail_ToEmail
	                  ),
	                  ucerm.Mail_ToEmail,
	                  ucm.MailReplyTo,
	                  (
	                      SELECT TOP 1 ud.EMail
	                      FROM   User_Detail AS ud
	                      WHERE  ud.[User_ID] = ucm.AccountUsed
	                  ) AS AccountUsed,
	                  ucm.MailSubject
	           FROM   UserCampaignExecutionHistory uceh
	                  INNER JOIN UserCampaignMaster ucm
	                       ON  ucm.ID = uceh.CampaignID
	                  INNER JOIN UserMailTemplate umt
	                       ON  umt.ID  IN (SELECT TemplateID
	                                       FROM   #tempTemplate)
	                  INNER JOIN EmailsFilterCampaignExecution ucerm
	                       ON  ucerm.CampaignID = uceh.CampaignID
	                       AND ucerm.ParentID = umt.ParentID
	           WHERE  uceh.IsRecipients = 1
	                  AND umt.IsList = 1
	                  AND umt.ID  IN (SELECT TemplateID
	                                  FROM   #tempTemplate)
	       ) A
	
	
	
	
	
	
	DROP TABLE #tempTemplate
END



GO

/* ============================================================
   Procedure: [dbo].[fn_GetGroupMessageMailsNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[fn_GetGroupMessageMailsNew] --12 -- 335,'#personname#'
AS
BEGIN
	CREATE TABLE #temptemplate1
	(
		templateid     BIGINT,
		parentid       BIGINT
	)
	
	
	
	CREATE TABLE #temptemplate2
	(
		templateid     BIGINT,
		parentid       BIGINT
	)
	
	
	
	IF EXISTS (
	       SELECT 'x'
	       FROM   usergrouptemplatemix AS ugtm2
	              INNER JOIN usercampaignmaster AS ucm2
	                   ON  ugtm2.groupid = ucm2.templategroupid
	       WHERE  ucm2.id IN (SELECT ucerm.campaignid
	                          FROM   emailsfiltercampaignexecution AS ucerm)
	              AND ugtm2.isactivated = 1
	   )
	BEGIN
	    INSERT INTO #temptemplate1
	      (
	        templateid,
	        parentid
	      )
	    SELECT DISTINCT ugtm.templateid,
	           ugtm.parentid
	    FROM   usergrouptemplatemix AS ugtm
	           INNER JOIN usercampaignmaster AS ucm
	                ON  ugtm.groupid = ucm.templategroupid
	    WHERE  ucm.id IN (SELECT ucerm.campaignid
	                      FROM   emailsfiltercampaignexecution AS ucerm)
	           AND ugtm.orderno = (
	                   SELECT ugtm2.orderno + 1
	                   FROM   usergrouptemplatemix AS ugtm2
	                          INNER JOIN usercampaignmaster AS ucm2
	                               ON  ugtm2.groupid = ucm2.templategroupid
	                   WHERE  ucm2.id IN (SELECT ucerm.campaignid
	                                      FROM   emailsfiltercampaignexecution AS 
	                                             ucerm)
	                          AND ugtm2.isactivated = 1
	               )
	END
	ELSE
	BEGIN
	    INSERT INTO #temptemplate2
	      (
	        templateid,
	        parentid
	      )
	    SELECT DISTINCT ugtm.templateid,
	           ugtm.parentid
	    FROM   usergrouptemplatemix AS ugtm
	           INNER JOIN usercampaignmaster AS ucm
	                ON  ugtm.groupid = ucm.templategroupid
	    WHERE  ucm.id IN (SELECT ucerm.campaignid
	                      FROM   emailsfiltercampaignexecution AS ucerm)
	           AND ugtm.orderno = (
	                   SELECT TOP 1 ugtm2.orderno
	                   FROM   usergrouptemplatemix AS ugtm2
	                          INNER JOIN usercampaignmaster AS ucm2
	                               ON  ugtm2.groupid = ucm2.templategroupid
	                   WHERE  ucm2.id IN (SELECT ucerm.campaignid
	                                      FROM   emailsfiltercampaignexecution AS 
	                                             ucerm)
	                   ORDER BY
	                          ugtm2.orderno
	               )
	END
	
	
	
	SELECT templateid
	       
	       INTO     #temptemplate
	FROM   (
	           SELECT templateid
	           FROM   #temptemplate1
	           
	           UNION
	           
	           SELECT templateid
	           FROM   #temptemplate2
	       )        A
	
	
	
	DROP TABLE #temptemplate1
	
	
	
	DROP TABLE #temptemplate2
	
	
	
	UPDATE usergrouptemplatemix
	SET    isactivated = 0
	WHERE  groupid IN (SELECT ucm.templategroupid
	                   FROM   usercampaignmaster AS ucm
	                   WHERE  ucm.id IN (SELECT ucerm.campaignid
	                                     FROM   emailsfiltercampaignexecution AS 
	                                            ucerm))
	
	
	
	UPDATE usergrouptemplatemix
	SET    isactivated = 1
	WHERE  templateid IN (SELECT templateid
	                      FROM   #temptemplate)
	
	
	
	SELECT A.campaignid,
	       A.parentid,
	       A.messagecontent,
	       A.mail_toemail,
	       A.mailreplyto,
	       A.accountused,
	       A.mailsubject
	FROM   (
	           SELECT uceh.campaignid,
	                  uceh.parentid,
	                  CAST(
	                      CAST(
	                          dbo.Fn_getenquirymessagemail(
	                              ucm.parentid,
	                              umt.mailcontent,
	                              ucerm.mail_toemail
	                          )
	                          
	                          AS VARCHAR(MAX)
	                      ) COLLATE
	                      
	                      latin1_general_ci_ai
	                      
	                      AS
	                      
	                      VARCHAR(MAX)
	                  ) AS messageContent,
	                  ucerm.mail_toemail,
	                  ucm.mailreplyto,
	                  ucm.accountused,
	                  umt.mailsubject
	           FROM   usercampaignexecutionhistory uceh
	                  INNER JOIN usercampaignmaster ucm
	                       ON  ucm.id = uceh.campaignid
	                  INNER JOIN usermailtemplate umt
	                       ON  umt.id IN (SELECT templateid
	                                      FROM   #temptemplate)
	                  INNER JOIN emailsfiltercampaignexecution ucerm
	                       ON  ucerm.campaignid = uceh.campaignid
	                       AND ucerm.parentid = umt.parentid
	           WHERE  uceh.isrecipients = 1
	                  AND umt.isenquiry = 1
	                  AND umt.id IN (SELECT templateid
	                                 FROM   #temptemplate)
	           
	           UNION ALL
	           
	           SELECT uceh.campaignid,
	                  uceh.parentid,
	                  CAST(
	                      CAST(
	                          dbo.Fn_getleadsmailmessage(
	                              ucm.parentid,
	                              umt.mailcontent,
	                              ucerm.mail_toemail
	                          ) 
	                          
	                          AS
	                          
	                          VARCHAR(MAX)
	                      ) COLLATE latin1_general_ci_ai
	                      
	                      AS
	                      
	                      VARCHAR(MAX)
	                  ),
	                  ucerm.mail_toemail,
	                  ucm.mailreplyto,
	                  ucm.accountused,
	                  umt.mailsubject
	           FROM   usercampaignexecutionhistory uceh
	                  INNER JOIN usercampaignmaster ucm
	                       ON  ucm.id = uceh.campaignid
	                  INNER JOIN usermailtemplate umt
	                       ON  umt.id IN (SELECT templateid
	                                      FROM   #temptemplate)
	                  INNER JOIN emailsfiltercampaignexecution ucerm
	                       ON  ucerm.campaignid = uceh.campaignid
	                       AND ucerm.parentid = umt.parentid
	           WHERE  uceh.isrecipients = 1
	                  AND (umt.isleads = 1 OR umt.isconversion = 1)
	                  AND umt.id IN (SELECT templateid
	                                 FROM   #temptemplate)
	           
	           UNION ALL
	           
	           SELECT uceh.campaignid,
	                  uceh.parentid,
	                  CAST(
	                      CAST(
	                          dbo.Fn_getlistmessagemails(
	                              umt.mailcontent,
	                              umt.listid,
	                              uceh.parentid,
	                              ucerm.mail_toemail
	                          ) AS VARCHAR(MAX)
	                      )
	                      
	                      COLLATE
	                      
	                      latin1_general_ci_ai AS VARCHAR(MAX)
	                  ),
	                  ucerm.mail_toemail,
	                  ucm.mailreplyto,
	                  ucm.accountused,
	                  umt.mailsubject
	           FROM   usercampaignexecutionhistory uceh
	                  INNER JOIN usercampaignmaster ucm
	                       ON  ucm.id = uceh.campaignid
	                  INNER JOIN usermailtemplate umt
	                       ON  umt.id IN (SELECT templateid
	                                      FROM   #temptemplate)
	                  INNER JOIN emailsfiltercampaignexecution ucerm
	                       ON  ucerm.campaignid = uceh.campaignid
	                       AND ucerm.parentid = umt.parentid
	           WHERE  uceh.isrecipients = 1
	                  AND umt.islist = 1
	                  AND umt.id IN (SELECT templateid
	                                 FROM   #temptemplate)
	       ) A
	
	
	
	DROP TABLE #temptemplate
END 



GO

/* ============================================================
   Procedure: [dbo].[fn_GetGroupMessageMailsNew1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[fn_GetGroupMessageMailsNew1] --12 -- 335,'#personname#'    
AS    
BEGIN    
 CREATE TABLE #temptemplate1    
 (    
  templateid     BIGINT,    
  parentid       BIGINT    
 )    
     
     
     
 CREATE TABLE #temptemplate2    
 (    
  templateid     BIGINT,    
  parentid       BIGINT    
 )    
     
     
     
 IF EXISTS (    
        SELECT 'x'    
        FROM   usergrouptemplatemix AS ugtm2    
               INNER JOIN usercampaignmaster AS ucm2    
                    ON  ugtm2.groupid = ucm2.templategroupid    
        WHERE  ucm2.id IN (SELECT ucerm.campaignid    
                           FROM   emailsfiltercampaignexecutiontest2 AS ucerm)    
               AND ugtm2.isactivated = 1    
    )    
 BEGIN    
     INSERT INTO #temptemplate1    
       (    
         templateid,    
         parentid    
       )    
     SELECT DISTINCT ugtm.templateid,    
            ugtm.parentid    
     FROM   usergrouptemplatemix AS ugtm    
            INNER JOIN usercampaignmaster AS ucm    
                 ON  ugtm.groupid = ucm.templategroupid    
     WHERE  ucm.id IN (SELECT ucerm.campaignid    
                       FROM   emailsfiltercampaignexecutiontest2 AS ucerm)    
            AND ugtm.orderno = (    
                    SELECT ugtm2.orderno + 1    
                    FROM   usergrouptemplatemix AS ugtm2    
                           INNER JOIN usercampaignmaster AS ucm2    
                                ON  ugtm2.groupid = ucm2.templategroupid    
                    WHERE  ucm2.id IN (SELECT ucerm.campaignid    
                                       FROM   emailsfiltercampaignexecutiontest2 AS     
                                              ucerm)    
                           AND ugtm2.isactivated = 1    
                )    
 END    
