                                       FROM   #temptemplate)    
                   INNER JOIN emailsfiltercampaignexecutiontest2 ucerm    
                        ON  ucerm.campaignid = uceh.campaignid    
                        AND ucerm.parentid = umt.parentid    
            WHERE  uceh.isrecipients = 1    
                   AND umt.isenquiry = 1    
                   AND umt.id IN (SELECT templateid    
                                  FROM   #temptemplate)    
                
            UNION ALL    
                
            SELECT uceh.campaignid,    
                   uceh.parentid,    
                   CAST(    
                       CAST(    
                           dbo.Fn_getleadsmailmessage(    
                               ucm.parentid,    
                               umt.mailcontent,    
                               ucerm.mail_toemail    
                           )     
                               
                           AS    
                               
                           VARCHAR(MAX)    
                       ) COLLATE latin1_general_ci_ai    
                           
                       AS    
                           
                       VARCHAR(MAX)    
                   ),    
