/* ============================================================
   Procedure: [dbo].[get_Cloud_agent_no]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC get_Cloud_agent_no -- 1,8,17,'7291889439'    
(      
@sticky int,      
@groupid bigint,      
@appid bigint,      
@caller varchar(20)      
      
)      
as      
begin      
DECLARE @mobile  VARCHAR(8000),@parentid bigint        
Declare @stno varchar(20)=''      
set @stno=''    
set @mobile = ''      
if @sticky=1      
begin     
    
select @stno= agentno from dbo.cloud_stickey_agent where caller_no = @caller and      
app_id = @appid       
end      
     
if (@stno = null)    
begin    
    
SELECT        
  @mobile = COALESCE(case when @mobile!='' then @mobile+ ', '  
  else '' end , '') + mobile  
          
  FROM  dbo.Cloud_User_Detail ud          
  inner join dbo.Cloud_user_Group gp          
  on gp.userid = ud.User_id          
  where gp.GroupId = CAST(@groupid AS int) and ud.Active = 1 and gp.Active = 1  
  and isnull(ud.onduty,0) = 1   
 end        
else    
begin     
     
SELECT        
  @mobile = COALESCE(case when @mobile!='' then @mobile+ ', '  
  else '' end , '') + mobile          
  FROM  dbo.Cloud_User_Detail ud          
  inner join dbo.Cloud_user_Group gp          
  on gp.userid = ud.User_id          
  where gp.GroupId = CAST(@groupid AS int) and ud.Active = 1 and gp.Active = 1        
 and mobile !=@stno and isnull(ud.onduty,0) = 1      
 end     
if @stno !=''  
set @mobile = @stno+','+@mobile      
select @mobile mobile      
end 


GO

