GO

/* ============================================================
   Procedure: [dbo].[get_Cloud_agent_no_new_withSequence_agents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[get_Cloud_agent_no_new_withSequence_agents] --0,3098,4862,7232060382,'Equally'--1,1269,2354,'9811958433','Equally' --0,1547,2672,0000000000,'Equally'--0,911,2360,7266895785,'Equally'-- 0,178,1803,7840000000-- 0,911,1499,'7840002738',0  
  (                                                
   @sticky int,                                                
   @groupid bigint,                                                
   @appid bigint,                                                
   @caller varchar(20)  ,                                              
   @Sequence nvarchar(50)                                                
 )                                                
 as                                                
 begin                      
--exec get_Cloud_agent_no_new @sticky,@groupid,@appid,@caller        
  -- sequnce could be Sequence = "Random" or Sequence = "Equally"            
    --declare  @sticky int = 0,                                                
    --       @groupid bigint = 28,                                                
    --       @appid bigint = 2965,                                                
    --       @caller varchar(20) =  7266895785 ,                                              
    --       @Sequence nvarchar(50) =  'Equally'                                              
                         
--declare @p int=(select ActivateParallelRinging from Cloud_flow_api where appid=@appid )                                               
  
DECLARE @mobile  VARCHAR(8000),@parentid bigint,@moh nvarchar(100),@isparellelringing int                                                  
Declare @stno varchar(20)=''                                                
set @stno=''                                              
set @mobile = ''                     
select @parentid=parentid,@isparellelringing=ActivateParallelRinging,@moh=moh  
from Cloud_flow_api(nolock) where appid=@appid  
select @Sequence=case when @appid in (4746,4763,4765,4777,4831,4868) or @parentid=31871 then 'Fixed' else @sequence end  
  
  
declare @lastagent varchar(50) ,@lastagenttype nvarchar(10),@lastagentondutystatus int    
  
if @isparellelringing<>1 or (@isparellelringing=1 and @sticky=1)                    
begin          
print 'parallel<>1 or parallel=1&sticky'  
select top 1 @lastagent= agentnumber,@lastagenttype=AgentType     
from lastagentdialled(nolock) where appid=@appid   
and 1= case when @isparellelringing=0 then 1  
when clientmobile=dbo.fn_trim0prefix(@caller) then 1 else 0 end  
order by id desc  
end  
  
declare @nextagent bigint,@lastagentuser bigint                    
select @lastagentuser=case when @lastagenttype='Mobile'   
then (select top 1 u.id from Calling_Agents u(nolock) where mobile=dbo.fn_trim0prefix(@lastagent) or id=@lastagent   
and parentid=@parentid) else @lastagent end           
select @lastagentondutystatus=onduty from calling_agents(nolock) where id=@lastagentuser  
  
if @lastagent is not null and  @sticky<>1                     
begin                    
--==============            
declare @lid int=(select top 1 SequenceGRP from Cloud_user_Group(nolock) where calling_agentid=@lastagentuser and GroupId=@groupid 
order by id desc)            
declare @gid int            
select @gid=case when (select min(SequenceGRP) from Cloud_user_Group(nolock) c join Calling_Agents u(nolock) on c.calling_agentid=u.id  where SequenceGRP>@lid and GroupId=@groupid and active=1
and u.isactive=1 and u.isdeleted=0 ) 
is not null              
then (select min(SequenceGRP) from Cloud_user_Group(nolock) c join Calling_Agents u(nolock) on c.calling_agentid=u.id 
where SequenceGRP>@lid and GroupId=@groupid and active=1 and u.isactive=1 and u.isdeleted=0 )  else            
       (select min(SequenceGRP) from Cloud_user_Group(nolock) c join Calling_Agents u(nolock) on c.calling_agentid=u.id  where GroupId=@groupid and active=1 and u.isactive=1 and u.isdeleted=0 ) end            
select @nextagent=Calling_Agentid from Cloud_user_Group(nolock) where SequenceGRP=@gid    
print 'Lastagent not null,sticky<>1, @nextagent='+cast(@nextagent as nvarchar)  
           
--if exists(select min(userid) from Cloud_user_Group(nolock) where userid>@lastagentuser and GroupId=@groupid)                     
--select @nextagent=min(userid) from Cloud_user_Group(nolock) where userid>@lastagentuser  and GroupId=@groupid                    
--else                    
--select @nextagent=min(userid) from Cloud_user_Group(nolock) where GroupId=@groupid                    
---------------------            
end                    
else if @lastagent is not null and  @sticky=1  and @sequence<>'Fixed'                
begin                    
select top 1 @nextagent= u.id from Calling_Agents u(nolock) join cloud_user_group (nolock) c on c.calling_agentid=u.id              
where (mobile=dbo.fn_trim0prefix(@lastagent) or u.id=@lastagent) and u.parentid=@parentid  and GroupId=@groupid    
and u.isactive=1 and u.isdeleted=0   
order by c.SequenceGRP asc                 
print 'Lastagent not null,sticky=1,fixed, @nextagent='+cast(@nextagent as nvarchar)  
end                    
else if @lastagent is null or @sequence='Fixed'                 
begin                    
set @nextagent=0    
print 'Lastagent null, @nextagent='+cast(@nextagent as nvarchar)  
end                    
set @nextagent=isnull(@nextagent,0)                    
  
  if isnull(@isparellelringing,0)=0      
  begin        
if @nextagent<>0    and @sequence<>'Fixed'          
  begin            
print 1              
create table #A(id int identity(1,1),mobileN varchar(20),user_idN bigint,agentid bigint)            
insert into #A(mobileN,user_idN,agentid)            
SELECT mobile,userid,ud.id            
  FROM  dbo.Calling_Agents ud                                                    
  inner join dbo.Cloud_user_Group gp                                                    
  on gp.calling_agentid = ud.id                          
  join cloud_flow_api c on c.Appid=@appid                                                    
  where gp.GroupId = CAST(@groupid AS int) and ud.isactive = 1 and ud.isdeleted=0 and gp.Active = 1                     
  and ud.id=case when @sticky=1 and @nextagent <>0 then @nextagent              
       else  ud.id              
    end                                           
  and isnull(ud.onduty,0) = 1                                             
     order by case when  gp.id = @gid then 0  else 1 end , gp.SequenceGRP            
            
  SELECT @mobile =                          
  COALESCE(        
  case         
  when @mobile!='' then @mobile         
  when @mobile='' and @appid=892 then 'local/17626s-'+ @mobile        
  when @mobile='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then 'local/'+@mobile                         
  else '' end +                        
  case         
  when @mobile!='' and @appid=892 then '-'        
  when @mobile!='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then '-'                         
  when @mobile!='' and c.activateparallelringing=1 then '&'         
  when @mobile!='' then ', ' else '' end , '') +                           
  case         
  when @appid=892 and len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' then '0'+str(ud.mobile)+'p'                        
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and u.presence=1 then cast(u.user_id as nvarchar) +'s'        
  --when @appid in (2360,2961) and ud.presence=1 then ''      
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and u.presence=0 and len(str(ud.mobile))=10 and 
  str(ud.mobile) like '[6-9]'+'%' then '0'+str(ud.mobile)+'p'                        
  when ud.presence=1 and ud.parentid in 
  (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874)     
  then                               
  'local/'+cast(#A.user_idN as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                              
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                               
  --'SIP/4862600/' + str(mobile)                             
  --when ud.parentid in (33942,33351)                         
  -- then                         
  when len(str(mobileN))=10 and str(mobileN) like '[6-9]'+'%' then 'local/0'+str(mobileN)+'@setcalleridpstn/n'--Created to enable finding answered call in parallel ringing             
  --else 'SIP/4862600/' + str(mobile)                         
  else ''   
  end                          
  FROM #A join            
   dbo.Calling_Agents ud(nolock) on #A.agentid=ud.ID                                                   
  inner join dbo.Cloud_user_Group gp (nolock)                                                   
  on gp.calling_agentid = ud.id 
  join cloud_flow_api c (nolock) on c.Appid=@appid 
  left join user_detail(nolock) u on u.User_ID=ud.kit19userid
  --left join Kit19CallsDialled(nolock) kc on kc.agentnumber=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<=2      
  where gp.GroupId = CAST(@groupid AS int) and ud.isactive = 1 and ud.isdeleted=0 and gp.Active = 1                     
  --and kc.agentnumber is null       
  and ud.id=case when @sticky=1 and @nextagent <>0 then @nextagent              
       else  ud.id              
    end                                           
  and isnull(ud.onduty,0) = 1                                     
     order by #A.id               
             
  drop table #A            
   end      
else            
begin            
if @Sequence='Fixed'  
begin  
print 2  
SELECT                                                  
  @mobile =                          
  COALESCE(case         
  when @mobile!='' then @mobile         
  when @mobile='' and @appid=892 then 'local/17626s-'+ @mobile         
  when @mobile='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then 'local/'+@mobile        
  else '' end +                        
  case         
  when @mobile!='' and @appid=892 then '-'        
  when @mobile!='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then '-'        
  when @mobile!='' and c.activateparallelringing=1 then '&'         
  when @mobile!='' then ', ' else '' end , '') +                           
  case         
  when @appid=892 and len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' then '0'+str(ud.mobile)+'p'                        
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and u.presence=1 and len(str(ud.mobile))=10 
  and str(ud.mobile) like '[6-9]'+'%'    
  and not exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(u.user_id as nvarchar) 
  and call_end_time is null and datediff(mi,call_answer_time,getdate())<2)   
  then cast(u.user_id as nvarchar) +'s'        
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and u.presence=1  
  and exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(u.user_id as nvarchar) 
  and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) then ''  
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and u.presence=0 and len(str(ud.mobile))=10 
  and str(ud.mobile) like '[6-9]'+'%' then '0'+str(ud.mobile)+'p'                        
  when u.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874)     
  then                               
  'local/'+cast(u.user_id as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                               
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                               
  --'SIP/4862600/' + str(mobile)                             
  --when ud.parentid in (33942,33351)                         
  -- then                         
  when len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' then 'local/0'+str(ud.mobile)+'@setcalleridpstn/n'--Created to enable finding answered call in parallel ringing                              
  --else 'SIP/4862600/' + str(mobile)                         
  else ''  
  end                          
  FROM  dbo.Calling_Agents ud(nolock)                                                    
  inner join dbo.Cloud_user_Group gp (nolock)                                                   
  on gp.calling_agentid = ud.id                    
  join cloud_flow_api c (nolock) on c.Appid=@appid                                                    
  --left join Kit19CallsDialled(nolock) kc on kc.agentnumber=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<=2      
  left join User_Detail u (nolock) on u.User_ID=ud.kit19userid
  where gp.GroupId = CAST(@groupid AS int) and ud.isactive = 1 and isdeleted=0 and gp.Active = 1                     
  --and kc.agentnumber is null       
  --where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                     
  and ud.id=case when @sticky=1 and @nextagent <>0 then @nextagent              
       else  ud.id              
    end                                           
  and isnull(ud.onduty,0) = 1                                             
     order by gp.SequenceGRP             
end  
else  
begin  
print 3  
SELECT                                                  
  @mobile =                          
  COALESCE(case         
  when @mobile!='' then @mobile         
  when @mobile='' and @appid=892 then 'local/17626s-'+ @mobile         
  when @mobile='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then 'local/'+@mobile        
  else '' end +                        
  case         
  when @mobile!='' and @appid=892 then '-'        
  when @mobile!='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then '-'        
  when @mobile!='' and c.activateparallelringing=1 then '&'         
  when @mobile!='' then ', ' else '' end , '') +                           
  case         
  when @appid=892 and len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' then '0'+str(ud.mobile)+'p'                        
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and u.presence=1 and len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%'    
  and not exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(u.user_id as nvarchar) 
  and call_end_time is null and datediff(mi,call_answer_time,getdate())<2)   
  then cast(u.user_id as nvarchar) +'s'        
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and u.presence=1  
  and exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(u.user_id as nvarchar) 
  and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) then ''  
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and u.presence=0 and len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' 
  then '0'+str(ud.mobile)+'p'                        
  when u.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874)     
  then                               
  'local/'+cast(u.user_id as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                               
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                               
  --'SIP/4862600/' + str(mobile)                             
  --when ud.parentid in (33942,33351)                         
  -- then                         
  when len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' then 'local/0'+str(ud.mobile)+'@setcalleridpstn/n'--Created to enable finding answered call in parallel ringing                              
  --else 'SIP/4862600/' + str(mobile)                         
  else ''  
  end                          
  FROM  dbo.Calling_Agents ud(nolock)                                                    
  inner join dbo.Cloud_user_Group gp (nolock)                                                   
  on gp.calling_agentid = ud.id                          
  join cloud_flow_api c (nolock) on c.Appid=@appid 
  left join User_Detail u (nolock) on u.User_ID=ud.kit19userid
  --left join Kit19CallsDialled(nolock) kc on kc.agentnumber=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<=2      
  where gp.GroupId = CAST(@groupid AS int) and ud.isactive = 1 and ud.isdeleted=0 and gp.Active = 1                     
  --and kc.agentnumber is null       
  --where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                     
  and ud.id=case when @sticky=1 and @nextagent <>0 then @nextagent              
       else  ud.id              
    end                                           
  and isnull(ud.onduty,0) = 1                                             
     order by --case when gp.userid = @nextagent  then 0 else 1 end  ,--commented as it was omitted some numbers   
  gp.SequenceGRP asc  
end  
  
  
  end          
  end   
  else if @isparellelringing=1 and @sticky=1 and @lastagent is not null and @lastagentondutystatus=1  
   begin  
   print 4  
   --select 1  
   SELECT @mobile =                          
  case         
  when @mobile='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436)   
  and u.presence=1 then 'local/'+cast(u.user_id as nvarchar) +'s'        
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and u.presence=0   
  and len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' then 'local/'+'0'+str(ud.mobile)+'p'    
  when u.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)  
  then 'local/'+cast(u.user_id as nvarchar)+'@setcallerid/n'  
  when len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' then 'local/0'+str(ud.mobile)+'@setcalleridpstn/n'  
  else dbo.fn_trim0prefix(@lastagent) end                         
  from Calling_Agents ud (nolock) 
  left join User_Detail u (nolock) on u.User_ID=ud.kit19userid
  where ud.id=@lastagentuser  
end                
 --order by case when @Sequence = 'Random' then cast( NEWID() as nvarchar)            
     --           else  gp.userid             
     --    end                 
 -----------------------------------------------------------             
                             
                      
                       
 --end                                                  
--else                                              
--begin                                               
                         
                         
if @isparellelringing=1 and @mobile=''--isnull(@lastagentondutystatus,0)<>1 and @lastagent is not null  
begin       
print 5  
SELECT                                                  
  @mobile = COALESCE(        
  case         
  when @mobile!='' then @mobile         
  when @mobile='' and @appid=892 then 'local/17626s'+ @mobile                         
  when @mobile='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then 'local/'+@mobile        
  when @mobile='' and @appid=2961 then 'local/'+@mobile        
  else '' end +                        
  case         
  when @mobile!='' and @appid=892  then '-'                         
  --when @mobile!='' and @appid=2360 then '-'        
  when @mobile!='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then '-'        
  when @mobile!='' and c.activateparallelringing=1 then '&'         
  when @mobile!='' then ', ' else '' end , '') +                           
  case         
  when @appid=892 and len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' then '0'+str(ud.mobile)+'p'                        
  --when @appid=2360 and ud.presence=1 then cast(ud.user_id as nvarchar) +'s'        
  --when @appid=2360 and ud.presence=0 then str(mobile)+'p'                        
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and u.presence=1       
   --and not exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2)       
   then cast(u.user_id as nvarchar) +'s'      
  --when @appid in (2360,2961) and ud.presence=1 and exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) then ''      
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' 
  and u.presence=0 then '0'+str(ud.mobile)+'p'            
  when u.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874)     
  then                               
  'local/'+cast(u.user_id as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                               
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                               
  --'SIP/4862600/' + str(mobile)                             
  --when ud.parentid in (33942,33351)                         
  -- then                         
  when len(str(ud.mobile))=10 and str(ud.mobile) like '[6-9]'+'%' then 'local/0'+str(ud.mobile)+'@setcalleridpstn/n'--Created to enable finding answered call in parallel ringing                                
  else ''  
  --else 'SIP/4862600/' + str(mobile)                         
  end                                                          
  FROM  dbo.Calling_Agents ud  (nolock)                                                  
  inner join dbo.Cloud_user_Group gp (nolock)                                                    
  on gp.calling_agentid = ud.id                                                    
  join cloud_flow_api c (nolock) on c.Appid=@appid 
  left join User_Detail u (nolock) on u.User_ID=ud.kit19userid
  where gp.GroupId = CAST(@groupid AS int) and ud.isactive = 1 and ud.isdeleted=0 and gp.Active = 1                                                  
 and ud.mobile !=@stno and isnull(ud.onduty,0) = 1                                                
  order by gp.SequenceGRP asc    
                     
                      
 end                             
                     
                      
if @stno !=''                                            
set @mobile = @stno+','+replace(@mobile,'local/local/','local/')                                                
select isnull(@moh+'~','')+case when   
(@appid=892       
or @appid in (2360,2961,3122,2672,3798,3847,3922,4436))-- and @isparellelringing=1      
then replace(replace(@mobile,'local/0','local/'),'local/local/','local/') + '@loopcall/n'   
else replace(@mobile,'local/local/','local/') end mobile                                                
        
end     
    
/*    
select * from user_detail(nolock) where     
 len(str(mobile))<>10 or str(mobile) not like '[6-9]'+'%'    
 and isverify=1    
 */


GO

/* ============================================================
   Procedure: [dbo].[get_Cloud_agent_no_new_withSequence_did]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[get_Cloud_agent_no_new_withSequence_did] --@sticky=1,@groupid=4043,@appid=6515,@caller='0',@Sequence=N'Random',@didno=8035714561
--@sticky=0,@groupid=1723,@appid=4927,@caller='7827521993',@Sequence=N'Random',@didno=0015165003004
--0,3045,5550,9667808866,'Equally'--0,3045,5550,7840049991,'Random'--1,1269,2354,'9811958433','Equally' --0,1547,2672,0000000000,'Equally'--0,911,2360,7266895785,'Equally'-- 0,178,1803,7840000000-- 0,911,1499,'7840002738'                                        0
  (                                              
   @sticky int,                                              
   @groupid bigint,                                              
   @appid bigint,                                              
   @caller varchar(20)  ,                                            
   @Sequence nvarchar(50), 
   @didno nvarchar(50)=null
 )                                              
 as                                              
 begin                    
 set @sticky=0
set @didno=coalesce(@didno,'')

DECLARE @mobile  VARCHAR(8000),@parentid bigint,@moh nvarchar(100),@isparellelringing int ,@agentprefix nvarchar(50),@agentsuffix nvarchar(50),@didtype nvarchar(20)   

select @didtype=case when ph_country<>'India' then 'I' else 'D' end
from Cloud_phone_master(nolock) where right(@didno,len(phoneno))=PhoneNo

set @didtype=isnull(@didtype,'D')

select @agentprefix=case when @didtype='D' then 'local/0' else 'local/00' end,@agentsuffix= case when @didtype='D' then '@setcalleridpstn/n' 
else '@setcalleridpstngo/n' end


Declare @stno varchar(20)=''                                              
set @stno=''                                            
set @mobile = ''                   
select @parentid=parentid,@isparellelringing=ActivateParallelRinging,@moh=moh
from Cloud_flow_api(nolock) where appid=@appid
select @Sequence=case when @appid=5550 then 'Random' 
when @appid in (4746,4763,4765,4777,4831,4868,5083,5259,4945,4867,4945,5470,5547,5603,5604,5649) 
or @parentid in (31871,41020) or @Sequence='Equally' then 'Fixed' else @sequence end
print @Sequence


declare @lastagent varchar(50) ,@lastagenttype nvarchar(10),@lastagentondutystatus int,@lastagentcountrycode nvarchar(5)  
declare @nextagent bigint,@lastagentuser bigint,@lct datetime,@nextagentcountrycode nvarchar(5)                  

if @isparellelringing<>1 or (@isparellelringing=1 and @sticky=1)                  
begin    

print 'parallel<>1 or parallel=1&sticky'
select top 1 @lastagentuser= agentuserid,@lastagent=agentnumber,@lct=Callstarttime from calllog(nolock) where parentid=@parentid and 
 --customernumber=dbo.fn_trim0prefix(@caller) and 
 isnull(agentuserid,0) <>0 and direction='Incoming'
order by id desc
print concat('Lastagentnumber: ',@lastagent,', lastcalltime: ',@lct,', lastagentuserid: ',@lastagentuser)
end

select @lastagentondutystatus=onduty,@lastagentcountrycode=replace(countrycode,'+','') from User_Detail(nolock) where user_id=@lastagentuser
if exists 
(select 1 from stickyagentappids(nolock) where appid=@appid)
begin
select @nextagent=0
declare @nextagentm nvarchar(20)
create table #tr_agent(agentmobile nvarchar(20))
insert into #tr_agent(agentmobile)
exec [usp_getagentforcalltransfer_cloud] @caller,@parentid
select top 1 @nextagentm=agentmobile from #tr_agent
	if (@nextagentm<>'No')
	begin
	select @nextagent=u.user_id,@nextagentcountrycode=replace(isnull(c.cloud_countrycode, u.countrycode),'+','') from user_detail(nolock) u left join cloud_call_no c(nolock)
	on u.user_id=c.user_id
	where isnull(c.cloud_no, str(mobile))=@nextagentm and parentid=@parentid
	print concat('Next agent mobile : ',@nextagentm)
	select @mobile=@agentprefix+ case when @didtype='D' then '' else @nextagentcountrycode end+@nextagentm+@agentsuffix
	GOTO ENDFLOW
	end
end

if (@lastagent is not null and  @sticky<>1  ) or  @nextagentm='No'                
begin                  
--==============          
declare @lid int=(select top 1 id from Cloud_user_Group(nolock) where userid=@lastagentuser and GroupId=@groupid order by id desc)          
declare @gid int          
select @gid=case when (select min(id) from Cloud_user_Group(nolock) where id>@lid and GroupId=@groupid  and dbo.fn_getondutystatus(userid)=1) is not null            
then (select min(id) from Cloud_user_Group(nolock) where id>@lid and GroupId=@groupid and dbo.fn_getondutystatus(userid)=1)  else          
       (select min(id) from Cloud_user_Group(nolock) where GroupId=@groupid  and dbo.fn_getondutystatus(userid)=1) end          
select @nextagent=userid from Cloud_user_Group(nolock) where id=@gid  
print 'Lastagent not null,sticky<>1, @nextagent='+cast(@nextagent as nvarchar)
         
end                  
else if @lastagent is not null and  @sticky=1  and @sequence<>'Fixed'              
begin                  
select top 1 @nextagent= u.user_id,@nextagentcountrycode=replace(countrycode,'+','') from user_detail u(nolock) join cloud_user_group (nolock) c on c.userid=u.User_ID            
where (dbo.fn_trim0prefix(str(mobile))=dbo.fn_trim0prefix(@lastagent) or user_id=@lastagent) and u.parentid=@parentid  
and GroupId=@groupid and u.Status=1 and u.onduty=1 order by c.SequenceGRP asc               
print 'Lastagent not null,sticky=1,fixed, @nextagent='+cast(@nextagent as nvarchar)
end                  
else if @lastagent is null or @sequence='Fixed'               
begin                  
set @nextagent=0  
print 'Lastagent null, @nextagent='+cast(@nextagent as nvarchar)
end                  
set @nextagent=isnull(@nextagent,0)                  

  if isnull(@isparellelringing,0)=0    
  begin      
if @nextagent<>0    and @sequence<>'Fixed'        
  begin          
print 1            
create table #A(id int identity(1,1),mobileN varchar(20),user_idN bigint)          
insert into #A(mobileN,user_idN)          
SELECT isnull(cc.cloud_no, str(mobile)),ud.user_id          
  FROM  dbo.User_Detail ud (nolock) left join cloud_call_no cc(nolock)
	on ud.user_id=cc.user_id                                                 
  inner join dbo.Cloud_user_Group gp    (nolock)                                              
  on gp.userid = ud.User_id                        
  join cloud_flow_api c(nolock) on c.Appid=@appid                                                  
  where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                   
  and ud.user_id=case when @sticky=1 and @nextagent <>0 then @nextagent            
       else  ud.user_id            
    end                                         
  and isnull(ud.onduty,0) = 1                                           
     order by 
	 case when ud.user_id=@nextagent then 0 else 1 end, 
	 case when  gp.id = @gid then 0  else 1 end , gp.SequenceGRP          
  
    --commented cases for desktop calling through out proc with --**--
  SELECT @mobile =                        
  COALESCE(      
  case       
  when @mobile!='' then @mobile       
  --**--when @mobile='' and @appid=892 then 'local/17626s-'+ @mobile  
  --**--when @mobile='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then 'local/'+@mobile                       
  else '' end +                      
  case       
  --**--when @mobile!='' and @appid=892 then '-'      
  --**--when @mobile!='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then '-'                       
  when @mobile!='' and c.activateparallelringing=1 then '&'       
  when @mobile!='' then ', ' else '' end , '') +                         
  case       
  --**--when @appid=892 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then '0'+str(mobile)+'p'                      
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and ud.presence=1 then cast(ud.user_id as nvarchar) +'s'      
  --when @appid in (2360,2961) and ud.presence=1 then ''    
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and ud.presence=0 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then '0'+str(mobile)+'p'                      
  --**--when ud.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874)   
  --**--then 'local/'+cast(#A.user_idN as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                            
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                             
  --'SIP/4862600/' + str(mobile)                           
  --when ud.parentid in (33942,33351)                       
  -- then                       
  when 
  @didtype='D' and len(str(mobileN))=10 and str(mobileN) like '[1-9]'+'%' then @agentprefix+str(mobileN)+@agentsuffix
  when @didtype='D' and (len(str(mobileN))<>10 or str(mobileN) not like '[1-9]'+'%') then ''
  else @agentprefix + replace(ud.countrycode,'+','')+ltrim(str(mobileN))+ @agentsuffix
  end                        
  FROM #A join          
   dbo.User_Detail ud(nolock) on #A.user_idN=ud.User_ID                                                 
  inner join dbo.Cloud_user_Group gp (nolock)                                                 
  on gp.userid = ud.User_id                        
  join cloud_flow_api c (nolock) on c.Appid=@appid                                                  
  where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                   
  and ud.user_id=case when @sticky=1 and @nextagent <>0 then @nextagent            
       else  ud.user_id            
    end                                         
  and isnull(ud.onduty,0) = 1                                   
     order by #A.id             
           
  drop table #A    
  print @mobile
   end    
else          
begin          
if @Sequence='Fixed'
begin
print 2
SELECT                                                
  @mobile =                        
  COALESCE(case       
  when @mobile!='' then @mobile       
  --**--when @mobile='' and @appid=892 then 'local/17626s-'+ @mobile       
  --**--when @mobile='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then 'local/'+@mobile      
  else '' end +                      
  case       
  --**--when @mobile!='' and @appid=892 then '-'      
  --**--when @mobile!='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then '-'      
  when @mobile!='' and c.activateparallelringing=1 then '&'       
  when @mobile!='' then ', ' else '' end , '') +                         
  case       
  when @appid=892 and len(isnull(cc.cloud_no, str(mobile)))=10 and isnull(cc.cloud_no, str(mobile)) like '[1-9]'+'%' then '0'+isnull(cc.cloud_no, str(mobile))+'p'                      
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and ud.presence=1 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%'  
  --**--and not exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) 
  --**--then cast(ud.user_id as nvarchar) +'s'      
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and ud.presence=1  and exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) then ''
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and ud.presence=0 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then '0'+str(mobile)+'p'                      
  --**--when ud.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874)   
  --**--then 'local/'+cast(ud.user_id as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                             
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                             
  --'SIP/4862600/' + str(mobile)                           
  --when ud.parentid in (33942,33351)                       
  -- then                       
  when 
   @didtype='D' and len(isnull(cc.cloud_no, str(mobile)))=10 and isnull(cc.cloud_no, str(mobile)) like '[1-9]'+'%' then @agentprefix+isnull(cc.cloud_no, str(mobile))+@agentsuffix
  when @didtype='D' and (len(isnull(cc.cloud_no, str(mobile)))<>10 or isnull(cc.cloud_no, str(mobile)) not like '[1-9]'+'%') then ''
  else @agentprefix + replace(isnull(cc.cloud_countrycode, ud.countrycode),'+','')+ltrim(isnull(cc.cloud_no, str(mobile)))+ @agentsuffix

  end                        
  FROM  dbo.User_Detail ud(nolock) left join cloud_call_no  cc(nolock) on ud.user_id=cc.user_id                                               
  inner join dbo.Cloud_user_Group gp (nolock)                                                 
  on gp.userid = ud.User_id                        
  join cloud_flow_api c (nolock) on c.Appid=@appid                                                  
  where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                   
  and ud.user_id=case when @sticky=1 and @nextagent <>0 then @nextagent            
       else  ud.user_id            
    end                                         
  and isnull(ud.onduty,0) = 1                                           
     order by gp.SequenceGRP           
end
else
begin
print 3
SELECT                                                
  @mobile =                        
  COALESCE(case       
  when @mobile!='' then @mobile       
  --**--when @mobile='' and @appid=892 then 'local/17626s-'+ @mobile       
  --**--when @mobile='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then 'local/'+@mobile      
  else '' end +                      
  case       
  --**--when @mobile!='' and @appid=892 then '-'      
  --**--when @mobile!='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then '-'      
  when @mobile!='' and c.activateparallelringing=1 then '&'       
  when @mobile!='' then ', ' else '' end , '') +                         
  case       
  --**--when @appid=892 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then '0'+str(mobile)+'p'                      
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and ud.presence=1 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%'  
  --**--and not exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) 
  --**--then cast(ud.user_id as nvarchar) +'s'      
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and ud.presence=1  and exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) then ''
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and ud.presence=0 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then '0'+str(mobile)+'p'                      
  --**--when ud.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874)   
  --**--then 'local/'+cast(ud.user_id as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                             
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                             
  --'SIP/4862600/' + str(mobile)                           
  --when ud.parentid in (33942,33351)                       
  -- then                       
  when 
  @didtype='D' and len(isnull(cc.cloud_no, str(mobile)))=10 and isnull(cc.cloud_no, str(mobile)) like '[1-9]'+'%' then @agentprefix+isnull(cc.cloud_no, str(mobile))+@agentsuffix
  when @didtype='D' and (len(isnull(cc.cloud_no, str(mobile)))<>10 or isnull(cc.cloud_no, str(mobile)) not like '[1-9]'+'%') then ''
  else @agentprefix + replace(isnull(cc.cloud_countrycode, ud.countrycode),'+','')+ltrim(isnull(cc.cloud_no, str(mobile)))+ @agentsuffix

  end                        
  FROM  dbo.User_Detail ud(nolock)    left join cloud_call_no cc(nolock) on cc.user_id=ud.user_id                                              
  inner join dbo.Cloud_user_Group gp (nolock)                                                 
  on gp.userid = ud.User_id                        
  join cloud_flow_api c (nolock) on c.Appid=@appid                                                  
  --left join Kit19CallsDialled(nolock) kc on kc.agentnumber=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<=2    
  where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                   
  --and kc.agentnumber is null     
  --where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                   
  and ud.user_id=case when @sticky=1 and @nextagent <>0 then @nextagent            
       else  ud.user_id            
    end                                         
  and isnull(ud.onduty,0) = 1                                           
     order by case when gp.userid = @nextagent  then 0 else 1 end  ,--commented as it was omitted some numbers 
	 gp.SequenceGRP asc
end


  end        
  end 
  else if @isparellelringing=1 and @sticky=1 and @lastagent is not null and @lastagentondutystatus=1
   begin
   print 4
   --select 1
   SELECT @mobile =                        
  case       
  --**--when @mobile='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) 
  --**--and ud.presence=1 then 'local/'+cast(ud.user_id as nvarchar) +'s'      
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and ud.presence=0 
  --**--and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then 'local/'+'0'+str(mobile)+'p'  
  --**--when ud.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)
  --**--then 'local/'+cast(user_id as nvarchar)+'@setcallerid/n'
  when 
  @didtype='D' and len(isnull(cc.cloud_no, str(mobile)))=10 and isnull(cc.cloud_no, str(mobile)) like '[1-9]'+'%' then @agentprefix+isnull(cc.cloud_no, str(mobile))+@agentsuffix
  when @didtype='D' and (len(isnull(cc.cloud_no, str(mobile)))<>10 or isnull(cc.cloud_no, str(mobile)) not like '[1-9]'+'%') then ''
  else @agentprefix + replace(isnull(cc.cloud_countrycode, ud.countrycode),'+','')+ltrim(isnull(cc.cloud_no, str(mobile)))+ @agentsuffix
 end                       
  from user_detail ud (nolock) left join cloud_call_no cc (nolock) on cc.user_id=ud.user_id
  
  where ud.user_id=@lastagentuser
end              
 --order by case when @Sequence = 'Random' then cast( NEWID() as nvarchar)          
     --           else  gp.userid           
     --    end               
 -----------------------------------------------------------           
                           
                    
                     
 --end                                                
--else                                            
--begin                                             
                       
                       
if @isparellelringing=1 and @mobile=''--isnull(@lastagentondutystatus,0)<>1 and @lastagent is not null
begin     
print 5
SELECT                                                
  @mobile = COALESCE(      
  case       
  when @mobile!='' then @mobile       
  --**--when @mobile='' and @appid=892 then 'local/17626s'+ @mobile                       
  --**--when @mobile='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then 'local/'+@mobile      
  when @mobile='' and @appid=2961 then 'local/'+@mobile      
  else '' end +                      
  case       
  --**--when @mobile!='' and @appid=892  then '-'                       
  --when @mobile!='' and @appid=2360 then '-'      
  --**--when @mobile!='' and @appid in (2360,2961,3122,2672,3798,3847,3922,4436) then '-'      
  when @mobile!='' and c.activateparallelringing=1 then '&'       
  when @mobile!='' then ', ' else '' end , '') +                         
  case       
  --**--when @appid=892 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then '0'+str(mobile)+'p'                      
  --when @appid=2360 and ud.presence=1 then cast(ud.user_id as nvarchar) +'s'      
  --when @appid=2360 and ud.presence=0 then str(mobile)+'p'                      
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and ud.presence=1     
   --and not exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2)     
   --**--then cast(ud.user_id as nvarchar) +'s'    
  --when @appid in (2360,2961) and ud.presence=1 and exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) then ''    
  --**--when @appid in (2360,2961,3122,2672,3798,3847,3922,4436) and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' and ud.presence=0 then '0'+str(mobile)+'p'                      
  --**--when ud.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874)   
  --**--then 'local/'+cast(ud.user_id as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                             
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                             
  --'SIP/4862600/' + str(mobile)                           
  --when ud.parentid in (33942,33351)                       
  -- then                       
  when 
  @didtype='D' and len(isnull(cc.cloud_no, str(mobile)))=10 and isnull(cc.cloud_no, str(mobile)) like '[1-9]'+'%' then @agentprefix+str(mobile)+@agentsuffix
  when @didtype='D' and (len(isnull(cc.cloud_no, str(mobile)))<>10 or isnull(cc.cloud_no, str(mobile)) not like '[1-9]'+'%') then ''
  else @agentprefix + replace(isnull(cc.cloud_countrycode, ud.countrycode),'+','')+ltrim(isnull(cc.cloud_no, str(mobile)))+ @agentsuffix

  end                                                        
  FROM  dbo.User_Detail ud  (nolock)    left join cloud_call_no cc(nolock) on cc.user_id=ud.user_id                                            
  inner join dbo.Cloud_user_Group gp (nolock)                                                  
  on gp.userid = ud.User_id                                                  
  join cloud_flow_api c (nolock) on c.Appid=@appid          
