 and isnull(cc.cloud_no,mobile) !=@stno and isnull(ud.onduty,0) = 1                                              
  order by gp.SequenceGRP asc  
                   
                    
 end                           
                   
                    
if @stno !=''                                          
set @mobile = @stno+','+replace(@mobile,'local/local/','local/') 

ENDFLOW:
select isnull(@moh+'~','')+replace(replace(@mobile,'local/local/','local/'),'&&','&') as mobile

