/* ============================================================
   Procedure: [dbo].[get_Cloud_agent_no_new_withSequence_international]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[get_Cloud_agent_no_new_withSequence_international] --0,3045,5550,7840049991,'Random'--1,1269,2354,'9811958433','Equally' --0,1547,2672,0000000000,'Equally'--0,911,2360,7266895785,'Equally'-- 0,178,1803,7840000000-- 0,911,1499,'7840002738'                                        0
  (                                              
   @sticky int,                                              
   @groupid bigint,                                              
   @appid bigint,                                              
   @caller varchar(20)  ,                                            
   @Sequence nvarchar(50)                                              
 )                                              
 as                                              
 begin                    
 set @sticky=0

--exec get_Cloud_agent_no_new @sticky,@groupid,@appid,@caller      
  -- sequnce could be Sequence = "Random" or Sequence = "Equally"          
    --declare  @sticky int = 0,                                              
    --       @groupid bigint = 28,                                              
    --       @appid bigint = 2965,                                              
    --       @caller varchar(20) =  7266895785 ,                                            
    --       @Sequence nvarchar(50) =  'Equally'                                            
                       
--declare @p int=(select ActivateParallelRinging from Cloud_flow_api where appid=@appid )                                             

DECLARE @mobile  VARCHAR(8000),@parentid bigint,@moh nvarchar(100),@isparellelringing int ,@countrycode nvarchar(5)                                               
Declare @stno varchar(20)=''                                              
set @stno=''                                            
set @mobile = ''                   
select @parentid=parentid,@isparellelringing=ActivateParallelRinging,@moh=moh
from Cloud_flow_api(nolock) where appid=@appid
select @Sequence=case when @appid in (4746,4763,4765,4777,4831,4868,5083,5259,4945,4867,4945,5470,5547,5603,5604,5649) 
or @parentid in (31871,41020) or @Sequence='Equally' then 'Fixed' when @appid=5550 then 'Random' else @sequence end



declare @lastagent varchar(50) ,@lastagenttype nvarchar(10),@lastagentondutystatus int  
declare @nextagent bigint,@lastagentuser bigint                  

if @isparellelringing<>1 or (@isparellelringing=1 and @sticky=1)                  
begin        
print 'parallel<>1 or parallel=1&sticky'
select top 1 @lastagentuser= agentuserid,@lastagent=agentnumber from calllog(nolock) where parentid=@parentid and 
 --customernumber=dbo.fn_trim0prefix(@caller) and 
 isnull(agentuserid,0) <>0
order by id desc
end

