if @appid in (5514,5524,5562,4537,5338,5541,5543,5544,5545,5546,5533,5633,5547,5603,5604,5568,5513,571,5605,5620,5450,5646,5650,5730
,4440,5733,5750,5753,5752,5751,5750,5749,5742,5743,5744,5745,5746,5748,5815,5782, 5783, 5781,5832, 5789,5832,5852,5855, 5856,5857,5858,5914, 5918 ,5872,5771,5592,5593,5594,5595,5596,5926,5881, 5872, 5858,5857,5856,5855
)
begin
select @nextagent=0
declare @nextagentm nvarchar(20)
create table #tr_agent(agentmobile nvarchar(20))
insert into #tr_agent(agentmobile)
exec [usp_getagentforcalltransfer] @caller,@parentid
select top 1 @nextagentm=agentmobile from #tr_agent
if (@nextagentm<>'No')
begin
select @nextagent=user_id,@countrycode=CountryCode from user_detail(nolock) where str(mobile)=@nextagentm
print concat('Next agent mobile : ',@nextagentm, ', countrycode: ',@countrycode)
select @mobile='local/0'+@nextagentm+'@setcalleridpstn/n'
--select @mobile='local/0'+@countrycode+@nextagentm+'@setcalleridpstn/n' -- for international numbers

GOTO ENDFLOW
end
end
