begin                  
--==============          
declare @lid int=(select top 1 id from Cloud_user_Group(nolock) where userid=@lastagentuser and GroupId=@groupid order by id desc)          
declare @gid int          
select @gid=case when (select min(id) from Cloud_user_Group(nolock) where id>@lid and GroupId=@groupid) is not null            
then (select min(id) from Cloud_user_Group(nolock) where id>@lid and GroupId=@groupid)  else          
       (select min(id) from Cloud_user_Group(nolock) where GroupId=@groupid) end          
select @nextagent=userid from Cloud_user_Group(nolock) where id=@gid  
print 'Lastagent not null,sticky<>1, @nextagent='+cast(@nextagent as nvarchar)
         
end                  
else if @lastagent is not null and  @sticky=1  and @sequence<>'Fixed'              
begin                  
select top 1 @nextagent= u.user_id from user_detail u(nolock) join cloud_user_group (nolock) c on c.userid=u.User_ID            
where (dbo.fn_trim0prefix(str(mobile))=dbo.fn_trim0prefix(@lastagent) or user_id=@lastagent) and u.parentid=@parentid  
and GroupId=@groupid and u.Status=1 and u.onduty=1 order by c.SequenceGRP asc               
print 'Lastagent not null,sticky=1,fixed, @nextagent='+cast(@nextagent as nvarchar)
end                  
