SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[get_Cloud_agent_no_new_withSequence_sticky] --1,3349,5514,0000000000,'Equally'--1,1269,2354,'9811958433','Equally' --0,1547,2672,0000000000,'Equally'--0,911,2360,7266895785,'Equally'-- 0,178,1803,7840000000-- 0,911,1499,'7840002738'                                        0
  (                                              
   @sticky int,                                              
   @groupid bigint,                                              
   @appid bigint,                                              
   @caller varchar(20)  ,                                            
   @Sequence nvarchar(50)                                              
 )                                              
 as                                              
 begin                    
 --set @sticky=0
--exec get_Cloud_agent_no_new @sticky,@groupid,@appid,@caller      
  -- sequnce could be Sequence = "Random" or Sequence = "Equally"          
    --declare  @sticky int = 0,                                              
    --       @groupid bigint = 28,                                              
    --       @appid bigint = 2965,                                              
    --       @caller varchar(20) =  7266895785 ,                                            
    --       @Sequence nvarchar(50) =  'Equally'                                            
                       
--declare @p int=(select ActivateParallelRinging from Cloud_flow_api where appid=@appid )                                             

DECLARE @mobile  VARCHAR(8000),@parentid bigint,@moh nvarchar(100),@isparellelringing int                                                
Declare @stno varchar(20)=''                                              
set @stno=''                                            
set @mobile = ''                   
select @parentid=parentid,@isparellelringing=ActivateParallelRinging,@moh=moh
from Cloud_flow_api(nolock) where appid=@appid
select @Sequence=case when @appid in (4746,4763,4765,4777,4831,4868,5083,5259,4945,4867,4945,5470) 
or @parentid in (31871,41020) or @Sequence='Equally' then 'Fixed' else @sequence end



declare @lastagent varchar(50) ,@lastagenttype nvarchar(10),@lastagentondutystatus int  
declare @nextagent bigint,@lastagentuser bigint                  

if @isparellelringing<>1 or (@isparellelringing=1 and @sticky=2)                  
begin        
print 'parallel<>1 or parallel=1&sticky'
select top 1 @lastagentuser= agentuserid,@lastagent=agentnumber from calllog(nolock) where parentid=@parentid and 
 customernumber=dbo.fn_trim0prefix(@caller) and isnull(agentuserid,0) <>0
order by id desc
end

select @lastagentondutystatus=onduty from User_Detail(nolock) where user_id=@lastagentuser
if @appid in (5514,5524) or @sticky=1
begin
select @nextagent=0
declare @nextagentm nvarchar(20)
create table #tr_agent(agentmobile nvarchar(20))
insert into #tr_agent(agentmobile)
exec [usp_getagentforcalltransfer] @caller,@parentid
select top 1 @nextagentm=agentmobile from #tr_agent
if (@nextagentm<>'No')
begin
select @nextagent=user_id from user_detail(nolock) where str(mobile)=@nextagentm
print concat('Next agent mobile : ',@nextagentm)
select @mobile='local/0'+@nextagentm+'@setcalleridpstn/n'
GOTO ENDFLOW
end
end
else if @lastagent is not null and  @sticky<>1                   
begin                  
--==============          
declare @lid int=(select top 1 id from Cloud_user_Group(nolock) where userid=@lastagentuser and GroupId=@groupid order by id desc)          
declare @gid int          
select @gid=case when (select min(id) from Cloud_user_Group(nolock) where id>@lid and GroupId=@groupid) is not null            
then (select min(id) from Cloud_user_Group(nolock) where id>@lid and GroupId=@groupid)  else          
       (select min(id) from Cloud_user_Group(nolock) where GroupId=@groupid) end          
select @nextagent=userid from Cloud_user_Group(nolock) where id=@gid  
print 'Lastagent not null,sticky<>1, @nextagent='+cast(@nextagent as nvarchar)
         
end                  
else if @lastagent is not null and  @sticky=2  and @sequence<>'Fixed'              
begin                  
select top 1 @nextagent= u.user_id from user_detail u(nolock) join cloud_user_group (nolock) c on c.userid=u.User_ID            
where (dbo.fn_trim0prefix(str(mobile))=dbo.fn_trim0prefix(@lastagent) or user_id=@lastagent) and u.parentid=@parentid  and GroupId=@groupid  
and u.Status=1 
order by c.SequenceGRP asc               
print 'Lastagent not null,sticky=2,fixed, @nextagent='+cast(@nextagent as nvarchar)
end                  
else if @lastagent is null or @sequence='Fixed'               
