  when @appid in (2360,2961,3122,2672,3798,3847,3922,4428,4436,3712) and ud.presence=1 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%'  
  and not exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) 
  then cast(ud.user_id as nvarchar) +'s'      
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4428,4436,3712) and ud.presence=1  and exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) then ''
  when @appid in (2360,2961,3122,2672,3798,3847,3922,4428,4436,3712) and ud.presence=0 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then '0'+str(mobile)+'p'                      
  when ud.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874)   
