  join cloud_flow_api c on c.Appid=@appid                                                
  where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                 
  and ud.user_id=case when @sticky=1 and @nextagent <>0 then @nextagent          
       else  ud.user_id          
    end                                       
  and isnull(ud.onduty,0) = 1                                         
     order by case when  gp.id = @gid then 0  else 1 end        
        
          
  --SELECT str(mobile),user_id        
  --FROM  dbo.User_Detail ud                                                
  --inner join dbo.Cloud_user_Group gp                                                
  --on gp.userid = ud.User_id                      
  --join cloud_flow_api c on c.Appid=@appid                                                
  --where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                 
  --and ud.user_id=case when @sticky=1 and @nextagent <>0 then @nextagent          
  --     else  ud.user_id          
  --  end                                       
  --and isnull(ud.onduty,0) = 1                                         
  --order by case when gp.id = @gid then 0  else 1 end        
        
        
        
SELECT @mobile =                      
  COALESCE(    
  case     
  when @mobile!='' then @mobile     
  when @mobile='' and @appid=892 then 'local/17626s-'+ @mobile    
  when @mobile='' and @appid in (2360,2961,3122,2672) then 'local/'+@mobile                     
  else '' end +                    
  case     
  when @mobile!='' and @appid=892 then '-'    
  when @mobile!='' and @appid in (2360,2961,3122,2672) then '-'                     
  when @mobile!='' and c.activateparallelringing=1 then '&'     
  when @mobile!='' then ', ' else '' end , '') +                       
  case     
  when @appid=892 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then str(mobile)+'p'                    
  when @appid in (2360,2961,3122,2672) and ud.presence=1 then cast(ud.user_id as nvarchar) +'s'    
  --when @appid in (2360,2961) and ud.presence=1 then ''  
  when @appid in (2360,2961,3122,2672) and ud.presence=0 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then str(mobile)+'p'                    
  when ud.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874) 
  then                           
  'local/'+cast(#A.user_idN as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                          
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                           
  --'SIP/4862600/' + str(mobile)                         
  --when ud.parentid in (33942,33351)                     
  -- then                     
  else 'local/'+str(mobileN)+'@setcalleridpstn/n'--Created to enable finding answered call in parallel ringing         
  --else 'SIP/4862600/' + str(mobile)                     
  end                      
  FROM #A join        
   dbo.User_Detail ud(nolock) on #A.user_idN=ud.User_ID                                               
  inner join dbo.Cloud_user_Group gp (nolock)                                               
  on gp.userid = ud.User_id                      
  join cloud_flow_api c (nolock) on c.Appid=@appid                                                
  --left join Kit19CallsDialled(nolock) kc on kc.agentnumber=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<=2  
  where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                 
  --and kc.agentnumber is null   
  and ud.user_id=case when @sticky=1 and @nextagent <>0 then @nextagent          
       else  ud.user_id          
    end                                       
  and isnull(ud.onduty,0) = 1                                 
     order by #A.id           
         
  drop table #A        
   end        
   else        
   begin        
                         
SELECT                                              
  @mobile =                      
  COALESCE(case     
  when @mobile!='' then @mobile     
  when @mobile='' and @appid=892 then 'local/17626s-'+ @mobile     
  when @mobile='' and @appid in (2360,2961,3122,2672) then 'local/'+@mobile    
  else '' end +                    
  case     
  when @mobile!='' and @appid=892 then '-'    
  when @mobile!='' and @appid in (2360,2961,3122,2672) then '-'    
  when @mobile!='' and c.activateparallelringing=1 then '&'     
  when @mobile!='' then ', ' else '' end , '') +                       
  case     
  when @appid=892 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then str(mobile)+'p'                    
  when @appid in (2360,2961,3122,2672) and ud.presence=1 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%'
  and not exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) then cast(ud
.user_id as nvarchar) +'s'    
  when @appid in (2360,2961,3122,2672) and ud.presence=1  and exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) then ''  
  when @appid in (2360,2961,3122,2672) and ud.presence=0 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then str(mobile)+'p'                    
  when ud.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874) 
  then                           
  'local/'+cast(ud.user_id as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                           
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                           
  --'SIP/4862600/' + str(mobile)                         
  --when ud.parentid in (33942,33351)                     
  -- then                     
  else 'local/'+str(mobile)+'@setcalleridpstn/n'--Created to enable finding answered call in parallel ringing                          
  --else 'SIP/4862600/' + str(mobile)                     
  end                      
  FROM  dbo.User_Detail ud(nolock)                                                
  inner join dbo.Cloud_user_Group gp (nolock)                                               
  on gp.userid = ud.User_id                      
  join cloud_flow_api c (nolock) on c.Appid=@appid                                                
  --left join Kit19CallsDialled(nolock) kc on kc.agentnumber=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<=2  
  where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                 
  --and kc.agentnumber is null   
  --where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                 
  and ud.user_id=case when @sticky=1 and @nextagent <>0 then @nextagent          
       else  ud.user_id          
    end                                       
  and isnull(ud.onduty,0) = 1                                         
     order by case when gp.userid = @nextagent  then 0 else 1 end           
  end      
  end        
 --order by case when @Sequence = 'Random' then cast( NEWID() as nvarchar)        
     --           else  gp.userid         
     --    end             
 -----------------------------------------------------------         
                         
                  
                   
 --end                                              
--else                                          
--begin                                           
                     
                     
if @isparellelringing=1    
begin                                    
SELECT                                              
  @mobile = COALESCE(    
  case     
  when @mobile!='' then @mobile     
  when @mobile='' and @appid=892 then 'local/17626s'+ @mobile                     
  when @mobile='' and @appid in (2360,2961,3122,2672) then 'local/'+@mobile    
  when @mobile='' and @appid=2961 then 'local/'+@mobile    
  else '' end +                    
  case     
  when @mobile!='' and @appid=892  then '-'                     
  --when @mobile!='' and @appid=2360 then '-'    
  when @mobile!='' and @appid in (2360,2961,3122,2672) then '-'    
  when @mobile!='' and c.activateparallelringing=1 then '&'     
  when @mobile!='' then ', ' else '' end , '') +                       
  case     
  when @appid=892 and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' then str(mobile)+'p'                    
  --when @appid=2360 and ud.presence=1 then cast(ud.user_id as nvarchar) +'s'    
  --when @appid=2360 and ud.presence=0 then str(mobile)+'p'                    
  when @appid in (2360,2961,3122,2672) and ud.presence=1   
   --and not exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2)   
   then cast(ud.user_id as nvarchar) +'s'  
  --when @appid in (2360,2961) and ud.presence=1 and exists (select 1 from kit19callsdialled(nolock) where cast(agentnumber as nvarchar)=cast(ud.user_id as nvarchar) and call_end_time is null and datediff(mi,call_answer_time,getdate())<2) then ''  
  when @appid in (2360,2961,3122,2672) and len(str(mobile))=10 and str(mobile) like '[6-9]'+'%' and ud.presence=0 then str(mobile)+'p'                    
  when ud.presence=1 and ud.parentid in (select parentid from allowdesktopinbound (nolock) where isactive=1)--(26023,32222,34175,36238,37003,36874) 
  then                           
  'local/'+cast(ud.user_id as nvarchar)+'@setcallerid/n'--Created to enable dialing only non busy numbers                           
  --'SIP/'+cast(ud.user_id as nvarchar)--Commented till incoming is not fixed                           
  --'SIP/4862600/' + str(mobile)                         
  --when ud.parentid in (33942,33351)                     
  -- then                     
  else 'local/'+str(mobile)+'@setcalleridpstn/n'--Created to enable finding answered call in parallel ringing                            
  --else 'SIP/4862600/' + str(mobile)                     
  end                                                      
  FROM  dbo.User_Detail ud  (nolock)                                              
  inner join dbo.Cloud_user_Group gp (nolock)                                                
  on gp.userid = ud.User_id                                                
  join cloud_flow_api c (nolock) on c.Appid=@appid        
  where gp.GroupId = CAST(@groupid AS int) and ud.status = 1 and gp.Active = 1                                              
 and mobile !=@stno and isnull(ud.onduty,0) = 1                                            
      
                 
                  
 end                         
                 
                  
if @stno !=''                                        
set @mobile = @stno+','+replace(@mobile,'local/local/','local/')                                            
select case when (@appid=892   
or @appid in (2360,2961,3122,2672))-- and @isparellelringing=1  
then replace(@mobile,'local/local/','local/') + '@loopcall/n' else replace(@mobile,'local/local/','local/') end mobile                                            
    
end 

