--sp_helptext get_EnquiryCampaign_analysis  
--exec get_EnquiryCampaign_analysis 335,'All', '2017-01-01','2018-02-28','Day',7      
CREATE   PROCEDURE dbo.get_EnquiryCampaign_analysis (
	@USER_ID AS BIGINT = NULL
	,@Source AS VARCHAR(100)
	,@Medium AS VARCHAR(100)
	,@FromDate AS DATE = NULL
	,@Todate AS DATE = NULL
	,@Range NVARCHAR(50) = 'Day'
	,@RangeValue INT = 7
	,@rpttype INT = 1
	)
AS
BEGIN
	DECLARE @MediumID AS INT = 0

	IF (@Medium != 'All')
		SELECT @MediumID = MediumID
		FROM dbo.UserMediumSettings(NOLOCK)
		WHERE Name = @Medium

	DECLARE @SourceID AS INT = 0

	IF (@Source != 'All')
		SELECT @SourceID = SourceID
		FROM dbo.UserSourceSettings(NOLOCK)
		WHERE Name = @Source

	CREATE TABLE #UserStats (
		dt DATE
		,FromTo VARCHAR(100)
		,Campaign VARCHAR(100)
		,qCount BIGINT
		)

	CREATE TABLE #UserStatsAll (
		dt DATE
		,FromTo VARCHAR(100)
		,Campaign VARCHAR(100)
		,qCount BIGINT
		)

	DECLARE @RangeValue1 INT

	SET @RangeValue1 = coalesce(@rangevalue, 15)

	StartBuildingTable:

	SET @Range = coalesce(@range, 'Day')
	SET @RangeValue = coalesce(@rangevalue, 7)

	DECLARE @datecreated1 DATE

	SET @datecreated1 = @FromDate

	IF @Range = 'Day'
	BEGIN
		IF datediff(dd, @fromdate, @todate) > 12 * @RangeValue
		BEGIN
			SET @RangeValue = ceiling((datediff(dd, @fromdate, @todate)) / 12) + 1
		END
	END
	ELSE IF @Range = 'Month'
	BEGIN
		IF ceiling(datediff(mm, @fromdate, @todate)) > 12
		BEGIN
			SET @RangeValue = ceiling((datediff(mm, @fromdate, @todate)) / 12) + 1
		END
		ELSE
		BEGIN
			SET @RangeValue = ceiling(datediff(mm, @fromdate, @todate))
		END
	END

	SET @RangeValue1 = @RangeValue

	WHILE @datecreated1 <= @todate
	BEGIN
		IF @Range = 'Day'
		BEGIN
			IF dateadd(dd, (@Rangevalue - 1), @datecreated1) > @todate
			BEGIN
				SET @Rangevalue = ceiling(datediff(dd, @datecreated1, @todate)) + 1
			END

			IF (
					@SourceID = 0
					AND @MediumID = 0
					)
			BEGIN
				INSERT INTO #userstats (
					dt
					,FromTo
					,Campaign
					,qCount
					)
				SELECT @datecreated1
					,convert(VARCHAR, @datecreated1, 103) + '-' + convert(VARCHAR, dateadd(dd, (@Rangevalue - 1), @datecreated1), 103)
					,isnull(sou.Name, 'Unknown')
					,COUNT(*)
				FROM userenquiry(NOLOCK) enq
				LEFT OUTER JOIN UserCampaignSettings(NOLOCK) sou ON sou.CampaignID = enq.CampaignName
				WHERE enq.Parentid = @USER_ID
					AND Convert(DATE, enq.CreatedDate) BETWEEN @datecreated1
						AND dateadd(dd, (@Rangevalue - 1), @datecreated1)
				GROUP BY sou.Name
				ORDER BY sou.Name
			END

			IF (
					@SourceID > 0
					AND @MediumID = 0
					)
			BEGIN
				INSERT INTO #userstats (
					dt
					,FromTo
					,Campaign
					,qCount
					)
				SELECT @datecreated1
					,convert(VARCHAR, @datecreated1, 103) + '-' + convert(VARCHAR, dateadd(dd, (@Rangevalue - 1), @datecreated1), 103)
					,isnull(sou.Name, 'Unknown')
					,COUNT(*)
				FROM userenquiry(NOLOCK) enq
				LEFT OUTER JOIN UserCampaignSettings(NOLOCK) sou ON sou.CampaignID = enq.CampaignName
				WHERE enq.Parentid = @USER_ID
					AND enq.SourceName = @SourceID
					AND Convert(DATE, enq.CreatedDate) BETWEEN @datecreated1
						AND dateadd(dd, (@Rangevalue - 1), @datecreated1)
				GROUP BY sou.Name
				ORDER BY sou.Name
			END

			IF (
					@SourceID = 0
					AND @MediumID > 0
					)
			BEGIN
				INSERT INTO #userstats (
					dt
					,FromTo
					,Campaign
					,qCount
					)
				SELECT @datecreated1
					,convert(VARCHAR, @datecreated1, 103) + '-' + convert(VARCHAR, dateadd(dd, (@Rangevalue - 1), @datecreated1), 103)
					,isnull(sou.Name, 'Unknown')
					,COUNT(*)
				FROM userenquiry(NOLOCK) enq
				LEFT OUTER JOIN UserCampaignSettings(NOLOCK) sou ON sou.CampaignID = enq.CampaignName
				WHERE enq.Parentid = @USER_ID
					AND enq.MediumName = @Medium
					AND Convert(DATE, enq.CreatedDate) BETWEEN @datecreated1
						AND dateadd(dd, (@Rangevalue - 1), @datecreated1)
				GROUP BY sou.Name
				ORDER BY sou.Name
			END

			IF (
					@SourceID > 0
					AND @MediumID > 0
					)
			BEGIN
				INSERT INTO #userstats (
					dt
					,FromTo
					,Campaign
					,qCount
					)
				SELECT @datecreated1
					,convert(VARCHAR, @datecreated1, 103) + '-' + convert(VARCHAR, dateadd(dd, (@Rangevalue - 1), @datecreated1), 103)
					,isnull(sou.Name, 'Unknown')
					,COUNT(*)
				FROM userenquiry(NOLOCK) enq
				LEFT OUTER JOIN UserCampaignSettings(NOLOCK) sou ON sou.CampaignID = enq.CampaignName
				WHERE enq.Parentid = @USER_ID
					AND enq.MediumName = @Medium
					AND enq.SourceName = @SourceID
					AND Convert(DATE, enq.CreatedDate) BETWEEN @datecreated1
						AND dateadd(dd, (@Rangevalue - 1), @datecreated1)
				GROUP BY sou.Name
				ORDER BY sou.Name
			END

			SET @datecreated1 = dateadd(dd, @Rangevalue, @datecreated1)
		END
		ELSE IF @Range = 'Month'
		BEGIN
			DECLARE @monthend DATE

			IF (@Rangevalue > 12)
				SET @monthend = DATEADD(d, - 1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + @Rangevalue, 0))
			ELSE
				SET @monthend = DATEADD(d, - 1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + 1, 0))

			IF @monthend > @todate
			BEGIN
				SET @monthend = @todate
			END

			IF (
					@SourceID = 0
					AND @MediumID = 0
					)
			BEGIN
				INSERT INTO #userstats (
					dt
					,FromTo
					,Campaign
					,qCount
					)
				SELECT @datecreated1
					,convert(VARCHAR, @datecreated1, 103) + '-' + convert(VARCHAR, @monthend, 103)
					,isnull(sou.Name, 'Unknown')
					,COUNT(*)
				FROM userenquiry(NOLOCK) enq
				LEFT OUTER JOIN UserCampaignSettings(NOLOCK) sou ON sou.CampaignID = enq.CampaignName
				WHERE enq.Parentid = @USER_ID
					AND Convert(DATE, enq.CreatedDate) BETWEEN @datecreated1
						AND @monthend
				GROUP BY sou.Name
				ORDER BY sou.Name
			END

			IF (
					@SourceID > 0
					AND @MediumID = 0
					)
			BEGIN
				INSERT INTO #userstats (
					dt
					,FromTo
					,Campaign
					,qCount
					)
				SELECT @datecreated1
					,convert(VARCHAR, @datecreated1, 103) + '-' + convert(VARCHAR, @monthend, 103)
					,isnull(sou.Name, 'Unknown')
					,COUNT(*)
				FROM userenquiry(NOLOCK) enq
				LEFT OUTER JOIN UserCampaignSettings(NOLOCK) sou ON sou.CampaignID = enq.CampaignName
				WHERE enq.Parentid = @USER_ID
					AND enq.SourceName = @SourceID
					AND Convert(DATE, enq.CreatedDate) BETWEEN @datecreated1
						AND @monthend
				GROUP BY sou.Name
				ORDER BY sou.Name
			END

			IF (
					@SourceID = 0
					AND @MediumID > 0
					)
			BEGIN
				INSERT INTO #userstats (
					dt
					,FromTo
					,Campaign
					,qCount
					)
				SELECT @datecreated1
					,convert(VARCHAR, @datecreated1, 103) + '-' + convert(VARCHAR, @monthend, 103)
					,isnull(sou.Name, 'Unknown')
					,COUNT(*)
				FROM userenquiry(NOLOCK) enq
				LEFT OUTER JOIN UserCampaignSettings(NOLOCK) sou ON sou.CampaignID = enq.CampaignName
				WHERE enq.Parentid = @USER_ID
					AND enq.MediumName = @Medium
					AND Convert(DATE, enq.CreatedDate) BETWEEN @datecreated1
						AND @monthend
				GROUP BY sou.Name
				ORDER BY sou.Name
			END

			IF (
					@SourceID > 0
					AND @MediumID > 0
					)
			BEGIN
				INSERT INTO #userstats (
					dt
					,FromTo
					,Campaign
					,qCount
					)
				SELECT @datecreated1
					,convert(VARCHAR, @datecreated1, 103) + '-' + convert(VARCHAR, @monthend, 103)
					,isnull(sou.Name, 'Unknown')
					,COUNT(*)
				FROM userenquiry(NOLOCK) enq
				LEFT OUTER JOIN UserCampaignSettings(NOLOCK) sou ON sou.CampaignID = enq.CampaignName
				WHERE enq.Parentid = @USER_ID
					AND enq.MediumName = @Medium
					AND enq.SourceName = @SourceID
					AND Convert(DATE, enq.CreatedDate) BETWEEN @datecreated1
						AND @monthend
				GROUP BY sou.Name
				ORDER BY sou.Name
			END

			SET @datecreated1 = dateadd(dd, 1, @monthend)
		END
	END

	INSERT INTO #UserStatsAll (
		dt
		,FromTo
		,Campaign
		,qCount
		)
	SELECT dt
		,max(FromTo)
		,Campaign
		,sum(qCount)
	FROM #UserStats
	GROUP BY dt
		,Campaign
	ORDER BY dt
		,Campaign

	SELECT max(dt) dt
		,max(FromTo) FromTo
		,Campaign
		,sum(qCount) qCount
	FROM #UserStats
	GROUP BY Campaign
	ORDER BY Campaign

	--select * from #UserStatsAll        
	DROP TABLE #UserStatsAll

	DROP TABLE #UserStats

	SET NOCOUNT ON;

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @USER_ID
		,@Activity_type = 'View_Enq_CampnRpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'userenquiry'
END



