	SELECT max(dt) dt
		,max(FromTo) FromTo
		,Medium
		,sum(qCount) qCount
	FROM #UserStats
	GROUP BY Medium
	ORDER BY Medium

	--select * from #UserStatsAll        
	DROP TABLE #UserStatsAll

	DROP TABLE #UserStats

	SET NOCOUNT ON;

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @USER_ID
		,@Activity_type = 'View_Enq_MedRpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'userenquiry'
