   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE get_Enquirymst_list               
(                
@USER_ID as bigint =null  
)  
as  
begin   
  select Name from UserCampaignSettings where UserID = @USER_ID  
  group by Name order by name  
 select Name from UserMediumSettings where UserID = @USER_ID  
  group by Name order by name  
 select Name from UserSourceSettings  where UserID = @USER_ID  
 group by Name  
 end


