--get_eshop_notification_val   19,5,'shippingdetails','FirstName'                              
           
CREATE   PROCEDURE [dbo].[get_eshop_notification_val]                                  
(                                    
                                    
@CustomerID int,      
@User_ID bigint,                                  
@TableNm varchar(Max),                                    
@fldNm varchar(max),    
@OrderID int = 0            
)      
as      
begin      
declare @return varchar(max)='',@sqlstr varchar(max)=''                                    
declare @word table (fldval varchar (Max))                                   
--if lower(@fldNm) ='orderid' or lower(@fldNm) ='firstname' or lower(@fldNm) = 'lastname'      
--begin      
declare @tblnm as varchar(100) ='', @flnm as varchar(100) = ''   , @tickethistoryid bigint        
            
select @tblnm = Case when  lower(@TableNm)='order' then 'OrderDetails' else             
 case when lower(@TableNm)='shippingdetails' then 'ShippingDetails'             
 else case when lower(@TableNm)='billingdetails'  then 'BillingDetails'             
 else case when lower(@TableNm)= 'orderdet'  then 'OrderDetails'              
 else  case when lower(@TableNm)= 'order_fulfillment'  then 'Order_Fulfillment'    
 else  case when lower(@TableNm)= 'domain'  then 'Eshop_client_domain'    
 else  case when lower(@TableNm)= 'customers'  then 'Customers'   
 else  case when lower(@TableNm)= 'payment'  then 'Payment'    
 else  case when lower(@TableNm)= 'eshop_order_return_stage'  then 'Eshop_Order_Return_Stage'  
 else  case when lower(@TableNm)= 'eshop_order_return'  then 'Eshop_Order_Return'    
 else lower(@TableNm)             
 end end end end end end end end end end             
       
      
            
if @fldNm != 'responsetime'            
begin            
if not exists(select 1 FROM sys.tables AS t            
INNER JOIN sys.columns c ON t.OBJECT_ID = c.OBJECT_ID            
WHERE lower(c.name) = lower(@fldNm) and lower(t.name) = @tblnm)            
 begin            
 select '#'+@TableNm+'.'+@fldNm+'#'             
 RETURN              
 end            
end             
             
          
                                
 if lower(@TableNm)='order'                              
 begin                         
 if lower(@fldNm) ='orderid'                                        
 begin                        
select @sqlstr = 'Select '+@fldNm+' from OrderDetails where OrderID = '+ cast(@OrderID as varchar(max))                                    
 end                         
end       
      
                                          
 if lower(@TableNm) ='shippingdetails'                                    
 begin                                    
 select @sqlstr = 'Select '+@fldNm+' from ShippingDetails where OrderID='+ cast(@OrderID as varchar(max))       
 +' and CustomerID='+cast(@CustomerID as varchar(max))                                    
 end                                    
 if lower(@TableNm)='billingdetails'                                    
 begin                                    
 select @sqlstr = 'Select '+@fldNm+' from BillingDetails where OrderID='+ cast(@OrderID as varchar(max))         
 +' and CustomerID='+cast(@CustomerID as varchar(max))                                    
 end                                    
 if lower(@TableNm)='orderdet'                                    
 begin                                    
 select @sqlstr = 'Select '+@fldNm+' from dbo.OrderDetails where OrderID='+ cast(@OrderID as varchar(max))                                     
 end                                    
 if lower(@TableNm)='fulfill'                                    
 begin                  
 select @sqlstr = 'Select '+@fldNm+' from Order_Fulfillment where OrderNo='+ cast(@OrderID as varchar(max))                                    
 end  
  if lower(@TableNm)='order_fulfillment'                                    
 begin                  
 select @sqlstr = 'Select '+@fldNm+' from Order_Fulfillment where OrderNo='+ cast(@OrderID as varchar(max))                                    
 end    
 if lower(@TableNm)='domain'                                    
 begin                  
 select @sqlstr = 'Select '+@fldNm+' from Eshop_client_domain where User_ID='+ cast(@User_ID as varchar(max))                                    
 end    
 if lower(@TableNm)='customers'                                    
 begin                  
 select @sqlstr = 'Select '+@fldNm+' from Customers where CustomerID='+ cast(@CustomerID as varchar(max))                                    
 end   
 if lower(@TableNm)='payment'                                    
 begin                  
 select @sqlstr = 'Select '+@fldNm+' from Payment where OrderNo='+ cast(@OrderID as varchar(max))                                    
 end   
 if lower(@fldNm)='remarks'  
 begin  
 if lower(@TableNm)='eshop_order_return_stage'                                    
 begin                  
 select @sqlstr = 'Select '+@fldNm+' from Eshop_Order_Return_Stage where Stage_Name = ' +'''Return Disapproved'''  
 +' and OrderID='+cast(@OrderID as varchar(max))   
 end  
 end   
 if lower(@fldNm)='stagedate'  
 begin  
 if lower(@TableNm)='eshop_order_return_stage'                                    
 begin                  
 select @sqlstr = 'Select '+@fldNm+' from Eshop_Order_Return_Stage where Stage_Name = ' +'''Product Exchanged'''  
 +' and OrderID='+cast(@OrderID as varchar(max))   
 end  
 end   
  if lower(@fldNm)='stagedate'  
 begin  
 if lower(@TableNm)='eshop_order_return'                                    
 begin                  
 select @sqlstr = 'Select '+@fldNm+' from Eshop_Order_Return where Stage_Name = ' +'''Product Replaced'''  
 +' and OrderID='+cast(@OrderID as varchar(max))   
 end  
 end 
                   
 exec(@sqlstr)                                    
       
                           
                                 
                                  
end                                    


