/* ============================================================
   Procedure: [dbo].[get_purchase_analysis]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext get_purchase_analysis  
  
--sp_helptext get_purchase_analysis    
--exec get_smsConsumprion_analysis 335,'2017-01-01', '2018-07-31', 'Days', 7            
--exec get_purchase_analysis 335,'2017-01-01', '2018-07-31', 'Days', 7            
CREATE   PROCEDURE get_purchase_analysis                
(                
@USER_ID as bigint =null,                
@FromDate as date = null,                
@Todate as Date =null,              
@Range nvarchar(50)='Day',              
@RangeValue int=7,            
@rpttype int = 1            
)                
as                
begin               
declare @MID bigint              
              
          
select @MID =              
rd.Reseller_ID from user_detail (nolock) ud inner join reseller_detail (nolock) rd              
on rd.User_ID = ud.User_ID --inner join user_detail md              
where ud.TYPE in (1,2) and ud.USER_ID = @USER_ID              
 create table #UserStats(dt date,FromTo varchar(100), smsno bigint,mailno bigint,          
 smsVal bigint,mailVal bigint, userid bigint)              
 create table #UserStatsAll(Fromto varchar(100),smsno bigint,mailno bigint,          
 smsVal bigint,mailVal bigint, userid bigint, Rangevalue nvarchar(50),dt date)              
    declare @RangeValue1 int              
 set @RangeValue1=coalesce(@rangevalue,15)              
          
 StartBuildingTable:              
             
             
 set @Range=coalesce(@range,'Day')              
 set @RangeValue=coalesce(@rangevalue,7)              
 declare @datecreated1 Date             
 set @datecreated1=@FromDate              
            
          
 If @Range='Day'                
  begin                
   if datediff(dd,@fromdate,@todate)>12*@RangeValue                
   begin                
    set @RangeValue=ceiling((datediff(dd,@fromdate,@todate))/12) +1                
   end               
   end              
   else if @Range = 'Month'                
  begin   
  if ceiling(datediff(mm,@fromdate,@todate))>12                
   begin                
   set @RangeValue=ceiling((datediff(mm,@fromdate,@todate))/12) +1       
  end   
  else  
 begin  
  set @RangeValue= ceiling(datediff(mm,@fromdate,@todate))  
 end  
  end        
set @RangeValue1 =  @RangeValue   
                        
while @datecreated1 <= @todate              
 begin              
              
   If @Range='Day'              
  begin             
    if   dateadd(dd,(@Rangevalue-1),@datecreated1) >  @todate   
 BEGIN  
  set  @Rangevalue = ceiling(datediff(dd,@datecreated1,@todate))+1   
 END             
   insert into #userstats(dt,FromTo,smsno,mailno,smsVal,mailVal, userid )              
   select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+          
  convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),          
    SUM(case when IsSMS=1 then Credits else 0 end) smsno,          
    SUM(case when IsMail=1 then Credits else 0 end) mailno,          
    SUM(case when IsSMS=1 then Amount else 0 end) smsVal,          
    SUM(case when IsMail=1 then Amount else 0 end) mailVal,          
    userid             
  from AddCreditDetails (nolock) where Convert(date,CreatedDate)           
 between @datecreated1 and dateadd(dd,(@Rangevalue-1),@datecreated1)              
    and userid in (select USER_ID from user_detail where M_ID = @MID)          
 and (IsSMS=1 or IsMail =1) and Reason ='Purchase'        
      group by userid              
   set @datecreated1=dateadd(dd,@Rangevalue, @datecreated1)              
  end              
                
              
              
  else if @Range = 'Month'              
  begin              
               
  declare @monthend date              
  if (@Rangevalue > 12)  
 set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + @Rangevalue, 0))  
  else  
  set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + 1, 0))  
   
  if   @monthend >  @todate   
 BEGIN  
 set @monthend =  @todate   
 END       
          
 insert into #userstats(dt,FromTo,smsno,mailno,smsVal,mailVal, userid )    
   select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+          
  convert(varchar, @monthend, 103),          
    SUM(case when IsSMS=1 then Credits else 0 end) smsno,          
    SUM(case when IsMail=1 then Credits else 0 end) mailno,          
    SUM(case when IsSMS=1 then Amount else 0 end) smsVal,          
    SUM(case when IsMail=1 then Amount else 0 end) mailVal,          
    userid             
  from AddCreditDetails (nolock) where Convert(date,CreatedDate)           
 between @datecreated1 and @monthend             
    and userid in (select USER_ID from user_detail where M_ID = @MID)          
 and (IsSMS=1 or IsMail =1)  and Reason ='Purchase'         
      group by userid              
                
   set @datecreated1=dateadd(dd,1,@monthend)               
  end              
            
end              
            
insert into #UserStatsAll (dt,Fromto ,smsno ,mailno ,          
   smsVal ,mailVal,userid  ) -- , Rangevalue nvarchar(50))              
    select dt,max(FromTo),sum(smsno),sum(mailno),sum(smsVal),            
    sum(mailVal),MAX(userid)          
    from #UserStats   group by dt order by dt                  
           
    select max(FromTo) FromTo,sum(smsno),sum(mailno),sum(smsVal),            
    sum(mailVal),MAX(userid), dt           
    from #UserStats   group by dt order by dt        
              
          
   select * from #UserStatsAll          
 --select * from #UserStats      
 select @Rangevalue1 Rangevalue          
     drop table #UserStatsAll          
     drop table #UserStats          
                    
 SET NOCOUNT ON;              
               
             
end


GO

/* ============================================================
   Procedure: [dbo].[get_serv_notification_val]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select * from Serv_TicketMaster
--get_serv_notification_val11   23,335,0,0,0,'Serv_TicketHistory','tickeno','',1                     
--select * from Serv_TicketMaster  
CREATE   PROCEDURE get_serv_notification_val   --0,335,0,0,0,'','','ResetPasswordUrl',1                     
(                        
@ticketid bigint,                        
@parentid bigint,                        
@groupid bigint,                        
@userid bigint,                        
@Agentid bigint,                        
@TableNm varchar(Max),                        
@fldNm varchar(max),                      
@type varchar(100),                  
@opt int =1            
                     
)                        
                        
                        
as                        
begin   
  
 
                     
declare @return varchar(max)='',@sqlstr varchar(max)=''                        
declare @word table (fldval varchar (Max))                       
if lower(@fldNm) !='ticketurl' and lower(@fldNm) !='domainurl' and lower(@fldNm) != 'siteurl'                   
 and lower(@fldNm) != 'resetpasswordurl' and lower(@fldNm) != 'forgotpasswordurl'                    
begin   

declare @tblnm as varchar(100) ='', @flnm as varchar(100) = ''
--declare @TableNm as varchar(100) ='ticket', @fldNm as varchar(100) = 'ticketno'

select @tblnm = Case when  lower(@TableNm)='ticket' then 'Serv_TicketMaster' else 
	case when lower(@TableNm)='agent' OR lower(@TableNm)='requester' then 'Serv_User_Detail' 
	else case when lower(@TableNm)='group'  then 'Serv_Group_Mast' 
	else case when lower(@TableNm)= 'company'  then 'Serv_User_Detail'  
	else  case when lower(@TableNm)= 'domain'  then 'serv_user_domain' else lower(@TableNm) 
	end end end end end


if @fldNm != 'responsetime'
begin
if not exists(select 1 FROM sys.tables AS t
INNER JOIN sys.columns c ON t.OBJECT_ID = c.OBJECT_ID
WHERE lower(c.name) = lower(@fldNm) and lower(t.name) = @tblnm)
	begin
	select '#'+@TableNm+'.'+@fldNm+'#'	
	RETURN  
	end
end	
	

                    
 if lower(@TableNm)='ticket'                  
 begin   
  
                   
 if lower(@fldNm) ='ticketno' and @opt = 1                            
 begin   
                  
select @sqlstr = 'Select ''#ticket No:''+ '+@fldNm+'+''#'' from dbo.Serv_TicketMaster  
 where TicketID = '+ cast(@TicketId as varchar(max))                        
 end                  
 else                  
 begin                  
 if lower(@fldNm) ='responsetime'                
  select GETDATE()                  
 else                  
  select @sqlstr = 'Select '+@fldNm+' from dbo.Serv_TicketMaster'+                        
   ' where TicketID = '+ cast(@TicketId as varchar(max))                  
end                  
end                               
 if lower(@TableNm) ='agent'                        
 begin                        
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where User_id='                        
  + cast(@Agentid as varchar(max))                         
 end                        
 if lower(@TableNm)='requester'                        
 begin                        
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where User_id='                        
 +  cast(@userid as varchar(max))                         
 end                        
 if lower(@TableNm)='group'                        
 begin                        
 select @sqlstr = 'Select '+@fldNm+' from dbo.Serv_Group_Mast where Groupid='                        
 +  cast(@groupid as varchar(max))                         
 end                        
 if lower(@TableNm)='company'                        
 begin                  
                      
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where User_id='                        
 +  cast(@userid as varchar(max)) +' and parentid='+cast(@parentid as varchar(max))                        
 end                        
 if lower(@TableNm)='domain'                        
 begin                        
 select @sqlstr = 'Select '+@fldNm+' from dbo.serv_user_domain where parentid='                        
 + cast(@parentid as varchar(max))                        
 end                        
                    
 exec(@sqlstr)                        
end                      
else                      
begin                      
declare @virtual_domain as varchar(max), @TicketNo varchar(20)                      
select @virtual_domain= virtual_domain from dbo.serv_user_domain                             
 where ParentID = @parentid                      
                       
select @TicketNo= TicketNo from dbo.Serv_TicketMaster                      
  where TicketID =  @TicketId                      
if lower(@fldNm) ='ticketurl'                      
begin                         
if @type != 'Agent'                        
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/login_user.aspx')                      
                  
  set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo                       
                      
end                        
if lower(@fldNm) ='domainurl'                        
begin                         
if @type != 'Agent'                    
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/home.aspx')                      
-- set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo                       
                  
end                        
if lower(@fldNm) = 'siteurl'                  
begin                 
if @type != 'Agent'                        
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/home.aspx')                    
end                  
  declare @guid as nvarchar(200)           
  select @guid =resetguid from  dbo.Serv_User_Detail where USER_ID = @userid                       
if lower(@fldNm) = 'resetPasswordurl'      
begin          
 set @virtual_domain  = REPLACE(@virtual_domain,'signin.aspx','ResetPassword.aspx?GUID='+@guid)                   
end                          
if lower(@fldNm) = 'forgotpasswordurl'                   
 set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','Forgotpassword.aspx')                   
                  
select @virtual_domain                  
                      
end                      
                      
end                        
                        
--select [dbo].[fn_FindDND]('7840002738') 


GO

