 and lower(@fldNm) != 'resetpasswordurl' and lower(@fldNm) != 'forgotpasswordurl'    
 and lower(@fldNm) != 'feedbackurl'                                
begin                 
              
declare @tblnm as varchar(100) ='', @flnm as varchar(100) = ''              
--declare @TableNm as varchar(100) ='ticket', @fldNm as varchar(100) = 'ticketno'              
              
select @tblnm = Case when  lower(@TableNm)='ticket' then 'Serv_TicketMaster' else               
 case when lower(@TableNm)='agent' OR lower(@TableNm)='requester' then 'Serv_User_Detail'               
 else case when lower(@TableNm)='group'  then 'Serv_Group_Mast'               
 else case when lower(@TableNm)= 'company'  then 'Serv_User_Detail'                
 else  case when lower(@TableNm)= 'domain'  then 'serv_user_domain' else lower(@TableNm)               
 end end end end end              
              
              
if @fldNm != 'responsetime'              
begin              
if not exists(select 1 FROM sys.tables AS t              
INNER JOIN sys.columns c ON t.OBJECT_ID = c.OBJECT_ID              
WHERE lower(c.name) = lower(@fldNm) and lower(t.name) = @tblnm)              
 begin              
 select '#'+@TableNm+'.'+@fldNm+'#'               
 RETURN                
 end              
end               
               
              
                                  
 if lower(@TableNm)='ticket'                                
 begin                 
                
                                 
 if lower(@fldNm) ='ticketno' and @opt = 1                                          
 begin                 
                                
select @sqlstr = 'Select ''#ticket No:''+ '+@fldNm+'+''#'' from dbo.Serv_TicketMaster                
 where TicketID = '+ cast(@TicketId as varchar(max))                                      
 end                                
 else                                
 begin                                
 if lower(@fldNm) ='responsetime'                              
  select GETDATE()                                
 else                                
  select @sqlstr = 'Select '+@fldNm+' from dbo.Serv_TicketMaster'+                                      
   ' where TicketID = '+ cast(@TicketId as varchar(max))                                
end                                
end                                             
 if lower(@TableNm) ='agent'                                      
 begin                                      
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where ser_user_id='                                      
  + cast(@Agentid as varchar(max))                                       
 end                                      
 if lower(@TableNm)='requester'                                      
 begin                                       
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where ser_user_id='                                      
 --+  cast(@userid as varchar(max))                                       
 +  cast(@ser_user_id as varchar(max))                        
 end                                      
 if lower(@TableNm)='group'                                      
 begin                                      
 select @sqlstr = 'Select '+@fldNm+' from dbo.Serv_Group_Mast where Groupid='                                      
 +  cast(@groupid as varchar(max))                                       
 end                                      
 if lower(@TableNm)='company'                                      
 begin                                
                                    
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where ser_user_id='                                
 +  cast(@ser_user_id as varchar(max)) +' and parentid='+cast(@parentid as varchar(max))                                      
 end                                      
