  set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo                                     
                                    
end              
 if  lower(@fldNm) ='feedbackurl'              
begin          
IF EXISTS (SELECT '*' FROM Serv_Ticket_url_link WHERE TICKETID =  @ticketid and DomainUrl like '%Feedback%')      
BEGIN      
set @virtual_domain = (select ShortUrl from Serv_Ticket_url_link where TicketId =  @ticketid and DomainUrl like '%Feedback%')      
