ELSE      
BEGIN                                    
select @virtual_domain= virtual_domain from dbo.serv_user_domain                                                   
 where ParentID = @parentid                                       
                                             
select @TicketNo= M.TicketNo, @tickethistoryid = MAX(H.tickethistoryid) from dbo.Serv_TicketMaster M          
INNER JOIN Serv_TicketHistory H                  
ON M.TicketID = H.TicketID                  
  where M.TicketID =  @TicketId     GROUP BY M.TicketNo               
                 
Select @randomexp = randomexp from randomexp where id = (isnull((select max(id) from serv_ticket_feedback_tbl),0)+1)            
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','Feedback/TicketFeedback.aspx')                                            
  set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo +'_'+Convert(varchar(15),@tickethistoryid) +'_'+Convert(varchar(15),@randomexp)                
               
          
SET @Randomexp1 = ( Select randomexp from randomexp where id = (isnull((select max(id) from Serv_Ticket_url_link),0)+1)and randomexp not in (select Randomexp from Serv_Ticket_url_link))              
Set @ShortUrl = 'ans.pm'+'/'+ @Randomexp1                
           
if not exists (Select '*' from Serv_Ticket_url_link where DomainURl = @virtual_domain)                
begin                
                
insert into Serv_Ticket_url_link(DomainURl, ShortURl, TicketId, TICKETHISTORYID,CreatedDate, CreatedBY,Status, Randomexp)                
values (@virtual_domain,@ShortUrl, @TicketId, @tickethistoryid, getdate(), @ser_user_id,1,@Randomexp1)                
                
end                
                
                
set @virtual_domain = (select ShortUrl from Serv_Ticket_url_link where DomainURl = @virtual_domain  )       
END             
end                
if lower(@fldNm) ='domain'                                      
begin                                       
if @type != 'Agent'                                  
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/home.aspx')                                    
-- set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo                                     
                                
end                                      
if lower(@fldNm) = 'siteurl'                                
begin                               
if @type != 'Agent'                                     
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/home.aspx')                                  
end                                
  declare @guid as nvarchar(200)                         
  select @guid =resetguid from  dbo.Serv_User_Detail where USER_ID = @ser_user_id                                     
if lower(@fldNm) = 'resetPasswordurl'                    
begin                        
 set @virtual_domain  = REPLACE(@virtual_domain,'signin.aspx','ResetPassword.aspx?GUID='+@guid)                                 
end                                        
if lower(@fldNm) = 'forgotpasswordurl'                                 
 set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','Forgotpassword.aspx')                                 
                                
select @virtual_domain                                
                                    
end                                    
                                    
end                                      
                                      



GO

/* ============================================================
   Procedure: [dbo].[get_serv_notification_val_support1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec get_serv_notification_val_support1 @ticketid=41863,@ParentID=37540,@groupid=953, @userid=2556,@Agentid=2556, @tableNm='Requester', @fldNm='Address' ,@type='Agent'   
--exec get_serv_notification_val_support1 @ticketid=41863,@ParentID=37540,@groupid=953, @userid=2556,@Agentid=2556, @tableNm='Requester', @fldNm='Address' ,@type='Requester'   
--exec get_serv_notification_val_support1 @ticketid=41873,@ParentID=37540,@groupid=0, @userid=2556,@Agentid=2556, @tableNm='Ticket', @fldNm='FeedbackURL' ,@type='Agent' 
--exec get_serv_notification_val_support1 @ticketid=41873,@ParentID=37540,@groupid=0, @userid=2556,@Agentid=2556, @tableNm='Company', @fldNm='Description' ,@type='Requester' 
--exec get_serv_notification_val_support1 @ticketid=32,@ParentID=335,@groupid=0, @userid=100,@Agentid=2437, @tableNm='Company', @fldNm='Description' ,@type='Agent'
/*
its SLA for Resolution at #SLAResolutionDatetIme#. This is a reminder for you for the following ticket:  Subject -    <p>#Company.Description#</p>  <p>#Company.Notes#</p>  <p>#Requester.Email_ID#</p>  <p>#Ticket.Active#</p>   
<p>#Ticket.ARemindRSPNSSent#</p>  <p>#Ticket.ARemindResolveSent#</p>  <p>#Ticket.ARSPSent#</p>  <p>#Ticket.A1RSLSent#</p><p>#Ticket.A2RSLSent#</p>  <p>#Ticket.A3RSLSent#</p>  <p>#Ticket.A4RSLSent#</p>  <p>#Ticket.agrp_unassigned#</p> 
  <p>#Ticket.user_id_old#</p>  <p>#Ticket.assignedby_old#</p>  <p>#Ticket.assignto_old#</p>
*/
CREATE   PROCEDURE [dbo].[get_serv_notification_val_support1]
(
 @ticketid BIGINT, 
 @parentid BIGINT, 
 @groupid  BIGINT, 
 @userid   BIGINT, 
 @Agentid  BIGINT, 
 @TableNm  VARCHAR(MAX), 
 @fldNm    VARCHAR(MAX), 
 @type     VARCHAR(100), 
 @opt      INT          = 1
)
AS
BEGIN

-- declare @ticketid BIGINT=41863, @parentid BIGINT=37540, @groupid  BIGINT=953, @userid BIGINT=2556, @Agentid  BIGINT=2556, @TableNm VARCHAR(MAX)='Requester',@fldNm VARCHAR(MAX)='name', @type VARCHAR(100)='Requester',@opt INT=1
-- declare @ticketid BIGINT=41873, @parentid BIGINT=37540, @groupid  BIGINT=0, @userid BIGINT=2556, @Agentid  BIGINT=2556, @TableNm VARCHAR(MAX)='Ticket',@fldNm VARCHAR(MAX)='FeedbackURL', @type VARCHAR(100)='Agent',@opt INT=1
-- declare @ticketid BIGINT=0, @parentid BIGINT=37540, @groupid  BIGINT=0, @userid BIGINT=2556, @Agentid  BIGINT=2556, @TableNm VARCHAR(MAX)='user',@fldNm VARCHAR(MAX)='ResetPasswordUrl', @type VARCHAR(100)='Requester',@opt INT=1
/*
declare @tblnm VARCHAR(MAX)='Serv_User_Detail',@fldNm VARCHAR(MAX)='name'
SELECT * FROM   sys.tables AS t INNER JOIN sys.columns AS c ON t.OBJECT_ID = c.OBJECT_ID WHERE  LOWER([c].[name]) = LOWER(@fldNm) AND LOWER([t].[name]) = @tblnm
*/

DECLARE @return VARCHAR(MAX)= '', @sqlstr VARCHAR(MAX)= '';
DECLARE @virtual_domain as varchar(max), @TicketNo varchar(20), @virtual_domain1 as varchar(max), @randomexp NVARCHAR(10)
DECLARE @Randomexp1 VARCHAR(10), @ShortUrl VARCHAR(50), @tickethistoryid bigint            
DECLARE @word TABLE
(
	[fldval] VARCHAR(MAX)
);

IF LOWER(@fldNm) != 'ticketurl' AND LOWER(@fldNm) != 'url' AND LOWER(@fldNm) != 'domainurl' AND LOWER(@fldNm) != 'siteurl' AND LOWER(@fldNm) != 'resetpasswordurl' AND LOWER(@fldNm) != 'forgotpasswordurl'
BEGIN

	DECLARE @tblnm AS VARCHAR(100)= '', @flnm AS VARCHAR(100)= '';

	SELECT @tblnm = CASE WHEN LOWER(@TableNm) = 'ticket' THEN 'Serv_TicketMaster'
					ELSE CASE WHEN LOWER(@TableNm) = 'agent' OR LOWER(@TableNm) = 'requester' THEN 'Serv_User_Detail'
						 ELSE CASE WHEN LOWER(@TableNm) = 'group' THEN 'Serv_Group_Mast'
							  ELSE CASE WHEN LOWER(@TableNm) = 'company' THEN 'Serv_User_Detail'
								   ELSE CASE WHEN LOWER(@TableNm) = 'domain' THEN 'serv_user_domain'
										ELSE LOWER(@TableNm)
										END
								   END
							  END
						 END
					END;

	IF LOWER(@fldNm) != 'responsetime' AND LOWER(@fldNm) != 'feedbackurl'
	BEGIN
		IF NOT EXISTS(SELECT 1
					  FROM   sys.tables AS t INNER JOIN sys.columns AS c
					  ON t.OBJECT_ID = c.OBJECT_ID
					  WHERE  LOWER([c].[name]) = LOWER(@fldNm) AND LOWER([t].[name]) = @tblnm)
		BEGIN
			SELECT '#' + @TableNm + '.' + @fldNm + '#';
			RETURN;
		END;
	END;

	IF LOWER(@TableNm) = 'ticket'
	BEGIN
		IF LOWER(@fldNm) = 'ticketno' AND @opt = 1
		BEGIN
			SELECT @sqlstr = 'Select ''#ticket No:''+ ' + @fldNm + '+''#'' from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX));
		END;
		ELSE
		BEGIN
			IF LOWER(@fldNm) = 'responsetime'
			BEGIN
				SELECT GETDATE();
			END
			ELSE IF LOWER(@fldNm) = 'userresponse' OR LOWER(@fldNm) = 'product' OR LOWER(@fldNm) = 'company' OR LOWER(@fldNm) = 'emailid'
			BEGIN
				SELECT @sqlstr = 'Select isnull(' + @fldNm + ','''') from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX));
			END
			ELSE IF LOWER(@fldNm) = 'resolved_dt' or LOWER(@fldNm) = 'assigneddatetime' or LOWER(@fldNm) = 'update_date'
			BEGIN
				SELECT @sqlstr = 'Select case when ' + @fldNm + ' is null then '''' else convert(varchar,' + @fldNm + ',120) end from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX));
			END
			ELSE IF LOWER(@fldNm) = 'assignedby' or LOWER(@fldNm) = 'update_by' or LOWER(@fldNm) = 'assignto'
			BEGIN
				SELECT @sqlstr = 'Select isnull((Select isnull(name,email) from serv_User_Detail(nolock) where ser_user_id in (select ' + @fldNm + ' from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX)) + ')),'''')';
			END
			ELSE IF LOWER(@fldNm) = 'ticket_type'
			BEGIN
				SELECT @sqlstr = 'Select isnull((Select isnull(Type_Desc,'''') from Serv_TicketType_Mast(nolock) where Type_ID in (select ' + @fldNm + ' from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX)) + ')),'''')';
			END
			ELSE IF LOWER(@fldNm) = 'status'
			BEGIN
				SELECT @sqlstr = 'Select isnull((Select isnull(Stat_Desc,'''') from Serv_Ticket_Stat_Mast(nolock) where Stat_ID in (select ' + @fldNm + ' from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX)) + ')),'''')';
			END
			ELSE IF LOWER(@fldNm) = 'priority'
			BEGIN
				SELECT @sqlstr = 'Select isnull((Select isnull(Priority_Desc,'''') from Serv_Priority_Mast(nolock) where Priority_ID in (select ' + @fldNm + ' from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX)) + ')),'''')';
			END
			ELSE IF LOWER(@fldNm) = 'assign_group'
			BEGIN
				SELECT @sqlstr = 'Select isnull((Select isnull(group_name,'''') from Serv_Group_Mast(nolock) where groupid in (select ' + @fldNm + ' from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX)) + ')),'''')';
			END
			ELSE IF LOWER(@fldNm) = 'user_id_old' OR LOWER(@fldNm) = 'assignedby_old' OR LOWER(@fldNm) = 'assignto_old'
			BEGIN
				SELECT @sqlstr = 'Select isnull(' + @fldNm + ',0) from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX));
			END
			ELSE IF LOWER(@fldNm) = 'feedbackurl'
			BEGIN
				IF EXISTS(SELECT * FROM Serv_Ticket_url_link WHERE [TICKETID] = @ticketid AND [DomainUrl] LIKE '%Feedback%')
				BEGIN
					SELECT @virtual_domain = [ShortUrl] FROM Serv_Ticket_url_link WHERE [TicketId] = @ticketid AND [DomainUrl] LIKE '%Feedback%'
				END
				ELSE
				BEGIN
					SELECT @virtual_domain = [virtual_domain] FROM dbo.serv_user_domain	WHERE [ParentID] = @parentid;

					SELECT	@TicketNo = [M].[TicketNo], @tickethistoryid = MAX([H].[tickethistoryid])
					FROM	dbo.Serv_TicketMaster AS M INNER JOIN Serv_TicketHistory AS H
					ON		M.TicketID = H.TicketID
					WHERE	[M].[TicketID] = @ticketid
					GROUP BY [M].[TicketNo];

					SELECT @randomexp = [randomexp]
					FROM   randomexp
					WHERE  [id] = (ISNULL((SELECT MAX([id]) FROM [serv_ticket_feedback_tbl]), 0) + 1);

					SET @virtual_domain = REPLACE(@virtual_domain, 'signin.aspx', 'Feedback/TicketFeedback.aspx');
					SET @virtual_domain = @virtual_domain + '?tktn=' + @TicketNo + '_' + CONVERT(VARCHAR(15), @tickethistoryid) + '_' + CONVERT(VARCHAR(15),	@randomexp);

					SET @Randomexp1 = (SELECT [randomexp]
										FROM   randomexp
										WHERE  [id] = (ISNULL((SELECT MAX([id]) FROM [Serv_Ticket_url_link]), 0) + 1)
												AND [randomexp] NOT IN (SELECT [Randomexp] FROM [Serv_Ticket_url_link]))
					SET @ShortUrl = 'ans.pm' + '/' + @Randomexp1;

					IF NOT EXISTS(SELECT * FROM Serv_Ticket_url_link WHERE  [DomainURl] = @virtual_domain)
					BEGIN
						INSERT INTO Serv_Ticket_url_link
						([DomainURl], [ShortURl], [TicketId], [TICKETHISTORYID], [CreatedDate], [CreatedBY], STATUS, [Randomexp])
						VALUES (@virtual_domain, @ShortUrl, @ticketid, @tickethistoryid, GETDATE(), @userid, 1, @Randomexp1)
					END;

					SELECT @virtual_domain = [ShortUrl] FROM Serv_Ticket_url_link WHERE [DomainURl] = @virtual_domain
				END;

				select @virtual_domain 
			END
			ELSE
			BEGIN
				SELECT @sqlstr = 'Select ' + @fldNm + ' from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX));
			END;
		END;
	END;

	IF LOWER(@TableNm) = 'agent'
	BEGIN
		If(LOWER(@fldNm)='name')
		Begin
			SELECT @sqlstr = 'Select name=case when name='''' then login_id else name end from Serv_User_Detail(nolock) where ser_user_id=' + CAST(@Agentid AS VARCHAR(MAX));
		End
		Else If(LOWER(@fldNm)='address' or LOWER(@fldNm)='email')
		Begin
			SELECT @sqlstr = 'Select isnull(' + @fldNm + ','''') from Serv_User_Detail(nolock) where ser_user_id=' + CAST(@Agentid AS VARCHAR(MAX));
		End
		Else
		Begin
			SELECT @sqlstr = 'Select ' + @fldNm + ' from Serv_User_Detail(nolock) where ser_user_id=' + CAST(@Agentid AS VARCHAR(MAX));
		End
	END;

	IF LOWER(@TableNm) = 'requester'
	BEGIN
		If(LOWER(@fldNm)='name')
		Begin
			SELECT @sqlstr = 'Select name=case when name='''' then login_id else name end from Serv_User_Detail(nolock) where ser_user_id=' + CAST(@userid AS VARCHAR(MAX));
		End
		Else If(LOWER(@fldNm)='address' or LOWER(@fldNm)='email')
		Begin
			SELECT @sqlstr = 'Select isnull(' + @fldNm + ','''') from Serv_User_Detail(nolock) where ser_user_id=' + CAST(@userid AS VARCHAR(MAX));
		End
		Else
		Begin
			SELECT @sqlstr = 'Select ' + @fldNm + ' from Serv_User_Detail(nolock) where ser_user_id=' + CAST(@userid AS VARCHAR(MAX));
		End
	END;

	IF LOWER(@TableNm) = 'group'
	BEGIN
		SELECT @sqlstr = 'Select ' + @fldNm + ' from dbo.Serv_Group_Mast(nolock) where Groupid=' + CAST(@groupid AS VARCHAR(
		MAX));
	END;

	IF LOWER(@TableNm) = 'company'
	BEGIN
		SELECT @sqlstr = 'Select ' + @fldNm + ' from Serv_User_Detail(nolock) where ser_user_id=' + CAST(@userid AS VARCHAR(
		MAX)) + ' and parentid=' + CAST(@parentid AS VARCHAR(MAX));
	END;

	IF LOWER(@TableNm) = 'domain'
	BEGIN
		SELECT @sqlstr = 'Select ' + @fldNm + ' from dbo.serv_user_domain(nolock) where parentid=' + CAST(@parentid AS
		VARCHAR(MAX));
	END;
	print @sqlstr
	EXEC (@sqlstr);

END
ELSE
BEGIN
	SELECT @virtual_domain = [virtual_domain] FROM   dbo.serv_user_domain(nolock) WHERE  [ParentID] = @parentid;

	SELECT @TicketNo = [TicketNo] FROM   dbo.Serv_TicketMaster(nolock) WHERE  [TicketID] = @TicketId;

	IF LOWER(@fldNm) = 'ticketurl' or LOWER(@fldNm) = 'url'
	BEGIN
		IF @type != 'Agent'
		BEGIN
			SET @virtual_domain = REPLACE(@virtual_domain, 'signin.aspx','website/login_user.aspx')
		END;

		SET @virtual_domain = @virtual_domain + '?tktn=' + @TicketNo;
	END;

	IF LOWER(@fldNm) = 'domainurl'
	BEGIN
		IF @type != 'Agent'
		BEGIN
			SET @virtual_domain = REPLACE(@virtual_domain, 'signin.aspx','website/home.aspx')
		END;
		-- set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo                           
	END;

	IF LOWER(@fldNm) = 'siteurl'
	BEGIN
		IF @type != 'Agent'
		BEGIN
			SET @virtual_domain = REPLACE(@virtual_domain, 'signin.aspx','website/home.aspx')
		END;
	END;

	DECLARE @guid AS NVARCHAR(200);

	SELECT @guid = [resetguid] FROM   dbo.Serv_User_Detail(nolock)	WHERE  [ser_user_id] = @userid;
	--print cast(@guid as varchar)
	IF LOWER(@fldNm) = 'resetPasswordurl'
	BEGIN
		SET @virtual_domain = REPLACE(@virtual_domain, 'signin.aspx','ResetPassword.aspx?GUID=' + isnull(@guid,''));
	END;

	IF LOWER(@fldNm) = 'forgotpasswordurl'
	BEGIN
		SET @virtual_domain = REPLACE(@virtual_domain, 'signin.aspx','Forgotpassword.aspx')
	END;

	SELECT @virtual_domain;

END;                          

end                            



GO

/* ============================================================
   Procedure: [dbo].[get_serv_notification_val1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec get_serv_notification_val1 @ticketid=41863,@ParentID=37540,@groupid=953, @ser_user_id=2556,@Agentid=2556, @tableNm='Ticket', @fldNm='ticketurl' ,@type='Agent'
--exec get_serv_notification_val1 @ticketid=41863,@ParentID=37540,@groupid=953, @ser_user_id=2556,@Agentid=2556, @tableNm='Ticket', @fldNm='requester' ,@type='name'
CREATE   PROCEDURE [dbo].[get_serv_notification_val1]
(                                          
@ticketid bigint,                                          
@parentid bigint,                                          
@groupid bigint,                                          
@ser_user_id bigint,                                          
@Agentid bigint,                                          
@TableNm varchar(Max),                                          
@fldNm varchar(max),                                        
@type varchar(100),                                    
@opt int =1                              
)                                          
as                                          
begin                     
                                      
declare @return varchar(max)='',@sqlstr varchar(max)=''                                          
--declare @word table (fldval varchar (Max))           
Create table #short  (shorturl varchar (Max))                
declare @virtual_domain as varchar(max)     ,@TicketNo varchar(20)             
declare  @virtual_domain1 as varchar(max) , @randomexp NVARCHAR(10)            
  Declare @Randomexp1 VARCHAR(10)            
Declare @ShortUrl VARCHAR(50)          
                                   
if lower(@fldNm) !='url' and lower(@fldNm) !='ticketurl' and lower(@fldNm) !='domainurl' and lower(@fldNm) != 'siteurl'
 and lower(@fldNm) != 'resetpasswordurl' and lower(@fldNm) != 'forgotpasswordurl'              
 and lower(@fldNm) != 'feedbackurl'                                   
begin                     
                  
declare @tblnm as varchar(100) ='', @flnm as varchar(100) = ''   , @tickethistoryid bigint               
--declare @TableNm as varchar(100) ='ticket', @fldNm as varchar(100) = 'ticketno'                  
                  
select @tblnm = Case when  lower(@TableNm)='ticket' then 'Serv_TicketMaster' else                   
 case when lower(@TableNm)='agent' OR lower(@TableNm)='requester' then 'Serv_User_Detail'                   
 else case when lower(@TableNm)='group'  then 'Serv_Group_Mast'                   
 else case when lower(@TableNm)= 'company'  then 'Serv_User_Detail'                    
 else  case when lower(@TableNm)= 'domain'  then 'serv_user_domain' else lower(@TableNm)                   
 end end end end end                  
                  
                  
if @fldNm != 'responsetime'                  
begin                  
if not exists(select 1 FROM sys.tables AS t                  
INNER JOIN sys.columns c ON t.OBJECT_ID = c.OBJECT_ID                  
WHERE lower(c.name) = lower(@fldNm) and lower(t.name) = @tblnm)                  
 begin                  
 select '#'+@TableNm+'.'+@fldNm+'#'                   
 RETURN                    
 end                  
end                   
                   
                  
                                      
 if lower(@TableNm)='ticket'                                    
 begin                     
	 if lower(@fldNm) ='ticketno' and @opt = 1
	 begin
		select @sqlstr = 'Select ''#ticket No:''+ '+@fldNm+'+''#'' from dbo.Serv_TicketMaster                    
		where TicketID = '+ cast(@TicketId as varchar(max))                                          
	 end                                    
	 else                                    
	 begin                                    
		if lower(@fldNm) ='responsetime'                                  
			select GETDATE()                                    
		else                                    
		  select @sqlstr = 'Select '+@fldNm+' from dbo.Serv_TicketMaster'+                                          
		   ' where TicketID = '+ cast(@TicketId as varchar(max))                                    
	 end
 end

 if lower(@TableNm) ='agent'                                          
 begin                                          
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where ser_user_id='                                          
  + cast(@Agentid as varchar(max))                                           
 end                                          
 if lower(@TableNm)='requester'                                          
 begin                                          
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where ser_user_id='                                          
 +  cast(@ser_user_id as varchar(max))                                           
 end                                          
 if lower(@TableNm)='group'                                        
 begin                                          
 select @sqlstr = 'Select '+@fldNm+' from dbo.Serv_Group_Mast where Groupid='                   
 +  cast(@groupid as varchar(max))                                           
 end                                          
 if lower(@TableNm)='company'                                          
 begin                                    
                               
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where ser_user_id='                                          
 +  cast(@ser_user_id as varchar(max)) +' and parentid='+cast(@parentid as varchar(max))                                          
 end                                          
 if lower(@TableNm)='domain'                                          
 begin                                          
 select @sqlstr = 'Select '+@fldNm+' from dbo.serv_user_domain where parentid='                                          
 + cast(@parentid as varchar(max))                                          
 end            
                                      
 exec(@sqlstr)                                          
          
end                
else                                        
begin                                        
                               
select @virtual_domain= virtual_domain from dbo.serv_user_domain where ParentID = @parentid
                                         
select @TicketNo= M.TicketNo, @tickethistoryid = tickethistoryid 
from dbo.Serv_TicketMaster M  INNER JOIN Serv_TicketHistory H
ON M.TicketID = H.TicketID
where M.TicketID =  @TicketId

if lower(@fldNm) ='url' or lower(@fldNm) ='ticketurl'
begin                                           
if @type != 'Agent'                                          
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/login_user.aspx')                                        
                                    
  set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo      
end         

 if  lower(@fldNm) ='feedbackurl'          
begin      
IF EXISTS (SELECT '*' FROM Serv_Ticket_url_link WHERE TICKETID =  @ticketid and DomainUrl like '%Feedback%')  
BEGIN  
set @virtual_domain = (select ShortUrl from Serv_Ticket_url_link where TicketId =  @ticketid and DomainUrl like '%Feedback%')  
END      
ELSE  
BEGIN                                
select @virtual_domain= virtual_domain from dbo.serv_user_domain                                               
 where ParentID = @parentid                                   
                                         
select @TicketNo= M.TicketNo, @tickethistoryid = MAX(H.tickethistoryid) from dbo.Serv_TicketMaster M      
INNER JOIN Serv_TicketHistory H              
ON M.TicketID = H.TicketID              
  where M.TicketID =  @TicketId     GROUP BY M.TicketNo           
             
Select @randomexp = randomexp from randomexp where id = (isnull((select max(id) from serv_ticket_feedback_tbl),0)+1)        
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','Feedback/TicketFeedback.aspx')                                        
  set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo +'_'+Convert(varchar(15),@tickethistoryid) +'_'+Convert(varchar(15),@randomexp)            
           
      
SET @Randomexp1 = ( Select randomexp from randomexp where id = (isnull((select max(id) from Serv_Ticket_url_link),0)+1)and randomexp not in (select Randomexp from Serv_Ticket_url_link))          
Set @ShortUrl = 'ans.pm'+'/'+ @Randomexp1            
            
if not exists (Select '*' from Serv_Ticket_url_link where DomainURl = @virtual_domain)            
begin            
            
insert into Serv_Ticket_url_link(DomainURl, ShortURl, TicketId, TICKETHISTORYID,CreatedDate, CreatedBY,Status, Randomexp)            
values (@virtual_domain,@ShortUrl, @TicketId, @tickethistoryid, getdate(), @ser_user_id,1,@Randomexp1)            
            
end            
            
            
set @virtual_domain = (select ShortUrl from Serv_Ticket_url_link where DomainURl = @virtual_domain  )   
END         
end              
                                          
if lower(@fldNm) ='domainurl'                                  
begin                                           
if @type != 'Agent'                                      
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/home.aspx')                                        
-- set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo                                         
                                    
end                                          
if lower(@fldNm) = 'siteurl'                                    
begin                                   
if @type != 'Agent'                                          
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/home.aspx')                                      
end                                    
  declare @guid as nvarchar(200)                             
  select @guid =resetguid from  dbo.Serv_User_Detail where ser_user_id = @ser_user_id                                         
if lower(@fldNm) = 'resetPasswordurl'                        
begin                            
 set @virtual_domain  = REPLACE(@virtual_domain,'signin.aspx','ResetPassword.aspx?GUID='+@guid)                                     
end                                            
if lower(@fldNm) = 'forgotpasswordurl'                                     
 set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','Forgotpassword.aspx')                                     
                                    
select @virtual_domain                                   
                                        
end           
          
                                        
                                        
end                                          



GO

/* ============================================================
   Procedure: [dbo].[get_serv_notification_val11]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--select * from Serv_TicketMaster
--get_serv_notification_val11   23,335,0,0,0,'Ticket','ticketno','',1                     
--select * from Serv_TicketMaster  
CREATE   PROCEDURE get_serv_notification_val11   --0,335,0,0,0,'','','ResetPasswordUrl',1                     
(                        
@ticketid bigint,                        
@parentid bigint,                        
@groupid bigint,                        
@userid bigint,                        
@Agentid bigint,                        
@TableNm varchar(Max),                        
@fldNm varchar(max),                      
@type varchar(100),                  
@opt int =1            
                     
)                        
                        
                        
as                        
begin   
  
 
                     
declare @return varchar(max)='',@sqlstr varchar(max)=''                        
declare @word table (fldval varchar (Max))                       
if lower(@fldNm) !='ticketurl' and lower(@fldNm) !='domainurl' and lower(@fldNm) != 'siteurl'                   
 and lower(@fldNm) != 'resetpasswordurl' and lower(@fldNm) != 'forgotpasswordurl'                    
begin   

declare @tblnm as varchar(100) ='', @flnm as varchar(100) = ''
--declare @TableNm as varchar(100) ='ticket', @fldNm as varchar(100) = 'ticketno'

select @tblnm = Case when  lower(@TableNm)='ticket' then 'Serv_TicketMaster' else 
	case when lower(@TableNm)='agent' OR lower(@TableNm)='requester' then 'Serv_User_Detail' 
	else case when lower(@TableNm)='group'  then 'Serv_Group_Mast' 
	else case when lower(@TableNm)= 'company'  then 'Serv_User_Detail'  
	else  case when lower(@TableNm)= 'domain'  then 'serv_user_domain' else lower(@TableNm) 
	end end end end end


if @fldNm != 'responsetime'
begin
if not exists(select 1 FROM sys.tables AS t
INNER JOIN sys.columns c ON t.OBJECT_ID = c.OBJECT_ID
WHERE lower(c.name) = lower(@fldNm) and lower(t.name) = @tblnm)
	begin
	select '#'+@TableNm+'.'+@fldNm+'#'	
	RETURN  
	end
end	
	

                    
 if lower(@TableNm)='ticket'                  
 begin   
  
                   
 if lower(@fldNm) ='ticketno' and @opt = 1                            
 begin   
                  
select @sqlstr = 'Select ''#ticket No:''+ '+@fldNm+'+''#'' from dbo.Serv_TicketMaster  
 where TicketID = '+ cast(@TicketId as varchar(max))                        
 end                  
 else                  
 begin                  
 if lower(@fldNm) ='responsetime'                
  select GETDATE()                  
 else                  
  select @sqlstr = 'Select '+@fldNm+' from dbo.Serv_TicketMaster'+                        
   ' where TicketID = '+ cast(@TicketId as varchar(max))                  
end                  
end                               
 if lower(@TableNm) ='agent'                        
 begin                        
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where User_id='                        
  + cast(@Agentid as varchar(max))                         
 end                        
 if lower(@TableNm)='requester'                        
 begin                        
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where User_id='                        
 +  cast(@userid as varchar(max))                         
 end                        
 if lower(@TableNm)='group'                        
 begin                        
 select @sqlstr = 'Select '+@fldNm+' from dbo.Serv_Group_Mast where Groupid='                        
 +  cast(@groupid as varchar(max))                         
 end                        
 if lower(@TableNm)='company'                        
 begin                  
                      
 select @sqlstr = 'Select '+@fldNm+' from Serv_User_Detail where User_id='                        
 +  cast(@userid as varchar(max)) +' and parentid='+cast(@parentid as varchar(max))                        
 end                        
 if lower(@TableNm)='domain'                        
 begin                        
 select @sqlstr = 'Select '+@fldNm+' from dbo.serv_user_domain where parentid='                        
 + cast(@parentid as varchar(max))                        
 end                        
                    
 exec(@sqlstr)                        
end                      
else                      
begin                      
declare @virtual_domain as varchar(max), @TicketNo varchar(20)                      
select @virtual_domain= virtual_domain from dbo.serv_user_domain                             
 where ParentID = @parentid                      
                       
select @TicketNo= TicketNo from dbo.Serv_TicketMaster                      
  where TicketID =  @TicketId                      
if lower(@fldNm) ='ticketurl'                      
begin                         
if @type != 'Agent'                        
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/login_user.aspx')                      
                  
  set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo                       
                      
end                        
if lower(@fldNm) ='domainurl'                        
begin                         
if @type != 'Agent'                    
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/home.aspx')                      
-- set @virtual_domain = @virtual_domain+'?tktn='+@TicketNo                       
                  
end                        
if lower(@fldNm) = 'siteurl'                  
begin                 
if @type != 'Agent'                        
  set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','website/home.aspx')                    
end                  
  declare @guid as nvarchar(200)           
  select @guid =resetguid from  dbo.Serv_User_Detail where USER_ID = @userid                       
if lower(@fldNm) = 'resetPasswordurl'      
begin          
 set @virtual_domain  = REPLACE(@virtual_domain,'signin.aspx','ResetPassword.aspx?GUID='+@guid)                   
end                          
if lower(@fldNm) = 'forgotpasswordurl'                   
 set @virtual_domain = REPLACE(@virtual_domain,'signin.aspx','Forgotpassword.aspx')                   
                  
select @virtual_domain                  
                      
end                      
                      
end                        
                        
