/* ============================================================
   Procedure: [dbo].[get_SMSConsumption_analysis]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



--sp_helptext get_SMSConsumption_analysis  
  
    
          
--exec get_SMSConsumption_analysis 335,'2018-01-01', '2018-07-31', 'Days', 7            
CREATE   PROCEDURE get_SMSConsumption_analysis                
(                
@USER_ID as bigint =null,                
@FromDate as date = null,                
@Todate as Date =null,              
@Range nvarchar(50)='Day',              
@RangeValue int=7,            
@rpttype int = 1            
)                
as                
begin               
declare @MID bigint              
              
--select @FromDate ='2009-08-01',              
-- @Todate ='2018-12-31'              
               
              
              
select @MID =              
rd.Reseller_ID from user_detail ud inner join reseller_detail rd              
on rd.User_ID = ud.User_ID --inner join user_detail md              
where ud.TYPE in (1,2) and ud.USER_ID = @USER_ID              
 create table #UserStats(dt date,FromTo varchar(100),tCount int, user_id bigint)              
    create table #UserStatsAll(Fromto varchar(100),db100 bigint,db1k bigint,            
    db10k bigint,db1L bigint,db10L bigint, dbgr10L bigint, Rangevalue nvarchar(50),dt date)              
    declare @RangeValue1 int              
 set @RangeValue1=coalesce(@rangevalue,15)              
          
 StartBuildingTable:              
             
             
 set @Range=coalesce(@range,'Day')              
 set @RangeValue=coalesce(@rangevalue,7)              
 declare @datecreated1 Date             
 set @datecreated1=@FromDate              
            
               
If @Range='Day'                
  begin                
   if datediff(dd,@fromdate,@todate)>12*@RangeValue                
   begin                
    set @RangeValue=ceiling((datediff(dd,@fromdate,@todate))/12) +1                
   end               
   end              
   else if @Range = 'Month'                
  begin   
  if ceiling(datediff(mm,@fromdate,@todate))>12                
   begin                
   set @RangeValue=ceiling((datediff(mm,@fromdate,@todate))/12) +1       
  end   
  else  
 begin  
  set @RangeValue= ceiling(datediff(mm,@fromdate,@todate))  
 end  
  end        
set @RangeValue1 =  @RangeValue           
while @datecreated1 <= @todate              
 begin              
              
   If @Range='Day'              
  begin              
   if   dateadd(dd,(@Rangevalue-1),@datecreated1) >  @todate   
 BEGIN  
  set  @Rangevalue = ceiling(datediff(dd,@datecreated1,@todate))+1   
 END    
   insert into #userstats(dt,FromTo,tCount, user_id )              
   select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+          
  convert(varchar, dateadd(dd,(@Rangevalue-1),@datecreated1), 103),          
    SUM(Debits),User_ID             
  from Credit_Details (nolock) where Convert(date,DateCreated)           
 between @datecreated1 and dateadd(dd,(@Rangevalue-1),@datecreated1)              
    and m_id = @MID and FromUser_ID = User_ID          
      group by User_ID              
   set @datecreated1=dateadd(dd,@Rangevalue, @datecreated1)              
  end              
                
                 
                 
              
  else if @Range = 'Month'              
  begin              
               
  declare @monthend date              
  if (@Rangevalue > 12)  
 set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + @Rangevalue, 0))  
  else  
  set @monthend= DATEADD(d, -1, DATEADD(m, DATEDIFF(m, 0, @datecreated1) + 1, 0))  
   
  if   @monthend >  @todate   
 BEGIN  
 set @monthend =  @todate   
 END           
 insert into #userstats(dt,FromTo,tCount, user_id )              
   select @datecreated1, convert(varchar, @datecreated1, 103)+'-'+          
  convert(varchar, @monthend, 103),          
    SUM(Debits),User_ID             
  from Credit_Details (nolock)  where Convert(date,DateCreated)           
 between @datecreated1 and @monthend           
    and m_id = @MID and FromUser_ID = User_ID          
      group by User_ID             
                
   set @datecreated1=dateadd(dd,1,@monthend)               
  end              
              
            
              
            
end              
            
             
   insert into #UserStatsAll(dt,Fromto,db100 ,db1k ,            
    db10k ,db1L ,db10L , dbgr10L )              
    select dt,max(FromTo),            
    sum(case when tCOUNT <= 100 then tCOUNT else 0 end),             
     sum(case when tCOUNT > 100 and tCOUNT <= 1000 then tCOUNT else 0 end),          
    sum(case when tCOUNT > 1000 and tCOUNT <= 10000 then tCOUNT else 0 end),            
    sum(case when tCOUNT > 10000 and tCOUNT <= 100000 then tCOUNT else 0 end),           
    sum(case when tCOUNT > 100000 and tCOUNT <=1000000 then tCOUNT else 0 end),           
    sum(case when tCOUNT > 1000000 then tCOUNT else 0 end)           
    from #UserStats   group by dt order by dt                  
           
    select dt,max(FromTo) FromTo,           
    sum(case when tCOUNT <= 100 then 1 else 0 end) db100,             
     sum(case when tCOUNT > 100 and tCOUNT <= 1000 then 1 else 0 end) db1k,          
    sum(case when tCOUNT > 1000 and tCOUNT <= 10000 then 1 else 0 end) db10k,            
    sum(case when tCOUNT > 10000 and tCOUNT <= 100000 then 1 else 0 end) db1L,           
    sum(case when tCOUNT > 100000 and tCOUNT <=1000000 then 1 else 0 end) db10L,           
    sum(case when tCOUNT > 1000000 then tCOUNT else 0 end) dbgr10L          
    from #UserStats          
    group by  dt order by dt                 
          
   select dt,Fromto,db100 ,db1k ,            
    db10k ,db1L ,db10L , dbgr10L from #UserStatsAll          
   --select * from #UserStats    
   select @RangeValue1 Rangevalue            
     drop table #UserStatsAll          
     drop table #UserStats          
                    
 SET NOCOUNT ON;              
               
             
end


GO

