/* ============================================================
   Procedure: [dbo].[getcurrencyrate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[getcurrencyrate]    
as    
begin    
exec sp_configure 'show advanced options', 1;    
RECONFIGURE;    
exec sp_configure 'Ole Automation Procedures', 1;    
RECONFIGURE;    
    
DECLARE @URL NVARCHAR(MAX) = 'http://data.fixer.io/api/latest?access_key=6dc6fd04805f63d80606d3ee4387c402&base=USD&symbols=INR';    
Declare @Object as Int;    
Declare @ResponseText as Varchar(8000),@cid bigint;    
    
insert into currencyapirun(api)    
select @url    
select @cid=scope_identity()    
    
Exec sp_OACreate 'MSXML2.XMLHTTP', @Object OUT;    
Exec sp_OAMethod @Object, 'open', NULL, 'get',@URL,'False'    
Exec sp_OAMethod @Object, 'send'    
Exec sp_OAMethod @Object, 'responseText', @ResponseText OUTPUT    
    
IF((Select @ResponseText) <> '')    
BEGIN    
     DECLARE @json NVARCHAR(MAX) = (Select @ResponseText)    
  Select @ResponseText    
update currencyapirun set jsontext=@ResponseText,issuccess=case when     
JSON_VALUE(replace(replace(replace(@responsetext,char(39),char(146)),char(13),''),char(10),''),'$.success')='true'    
then 1 else 0 end,    
error=JSON_VALUE(replace(replace(replace(@responsetext,char(39),char(146)),char(13),''),char(10),''),'$.error.info')    
where id=@cid    
    
if JSON_VALUE(replace(replace(replace(@responsetext,char(39),char(146)),char(13),''),char(10),''),'$.success')='true'    
begin    
insert into currencyrates(basecurrency,currency,rate)    
select 'USD','INR',JSON_VALUE(replace(replace(replace(@responsetext,char(39),char(146)),char(13),''),char(10),''),'$.rates.INR')    
end    
END    
ELSE    
BEGIN    
     DECLARE @ErroMsg NVARCHAR(30) = 'No data found.';    
     Print @ErroMsg;    
END    
Exec sp_OADestroy @Object;    
    
--exec sp_configure 'show advanced options', 1;    
--RECONFIGURE;    
--exec sp_configure 'Ole Automation Procedures', 0;    
--RECONFIGURE;    
end 


GO

/* ============================================================
   Procedure: [dbo].[GetCustomButtonUserTypes]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.GetCustomButtonUserTypes  
    @ButtonId INT  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    DECLARE @UserTypes VARCHAR(MAX) = '';  
  
    -- Concatenate user types into a comma-separated string  
    SELECT @UserTypes = @UserTypes + ',' + CAST(UserType AS VARCHAR(10))  
    FROM tbl_CB_CustomButtons  
    WHERE ButtonId = @ButtonId;  
  
    -- Remove leading comma and return the concatenated string  
    IF LEN(@UserTypes) > 0  
        SET @UserTypes = STUFF(@UserTypes, 1, 1, '');  
  
    SELECT @UserTypes AS UserTypes;  
END 


