/* ============================================================
   Procedure: [dbo].[GetEntityId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE GetEntityId
    @identifier NVARCHAR(50),
    @mobileNo NVARCHAR(50) = NULL,
    @emailId NVARCHAR(50) = NULL,
    @entityNo NVARCHAR(50) = NULL,
    @EntityName NVARCHAR(50),
    @ParentId INT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @EntityId BIGINT;


    IF (@identifier = 'mobileno' AND ISNULL(@mobileNo, '') = '')  
    BEGIN  
        PRINT 'MobileNo not supplied';  
        RETURN;  
    END  

    IF (@identifier = 'emailid' AND ISNULL(@emailId, '') = '')  
    BEGIN  
        PRINT 'EmailId not supplied';  
        RETURN;  
    END  

    IF (@identifier = 'entityNo' AND ISNULL(@entityNo, '') = '')  
    BEGIN  
        PRINT 'EntityNo not supplied';  
        RETURN;  
    END  


    IF (@EntityName = 'lead')  
    BEGIN  
        PRINT CONCAT('lead, => @mobileNo => ', @mobileNo);  
        PRINT CONCAT('lead, => @identifier => ', @identifier);  
        PRINT CONCAT('lead, => @ParentId => ', @ParentId);  

        SELECT TOP 1 @EntityId = ulme_id 
        FROM Userleads_Mobile_Email WITH (NOLOCK) 
        WHERE Parentid = @ParentId 
          AND (
              (@identifier = 'mobileno' AND Mobile = @mobileNo) OR
              (@identifier = 'entityNo' AND leadno = @entityNo) OR
              (@identifier = 'emailid' AND email = @emailId)
          )
        ORDER BY ulme_id DESC;  
    END  
    ELSE IF (@EntityName = 'enquiry')  
    BEGIN  
        PRINT 'enquiry';  
        
        SELECT TOP 1 @EntityId = enquiryid 
        FROM Userenquiry_Mobile_Email WITH (NOLOCK) 
        WHERE Parentid = @ParentId 
          AND (
              (@identifier = 'mobileno' AND Mobile = @mobileNo) OR
              (@identifier = 'entityNo' AND enquiryid = @entityNo) OR
              (@identifier = 'emailid' AND email = @emailId)
          )
        ORDER BY enquiryid DESC;  
    END  
    ELSE IF (@EntityName = 'user')  
    BEGIN  
       SELECT TOP 1 @EntityId = User_Id
        FROM tbl_tp_UserLogin WITH (NOLOCK) 
        WHERE ParentId = @ParentId 
          AND (
              (@identifier = 'mobileno' AND Mobile = @mobileNo) OR
              (@identifier = 'entityNo' AND User_Id = @entityNo) OR
              (@identifier = 'emailid' AND email = @emailId)
          )
        ORDER BY TpUser_Id DESC;  
    END  

 SELECT @EntityId AS EntityId;
END





GO

/* ============================================================
   Procedure: [dbo].[getKeywordWiseReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--  exec getKeywordWiseReport @user_id=335,@gcampaignid=0,@gadwordgroupid=0,@fmdate='2019-07-01',@todate='2019-07-20'
CREATE   PROCEDURE [dbo].[getKeywordWiseReport]
(          
@user_id bigint,    
@gcampaignid bigint,    
@gadwordgroupid bigint,          
@fmdate date,          
@todate date    
)          
as          
begin       
   declare @ParentID  bigint = 0        
   select  @ParentID = ParentID from user_detail where USER_ID = @user_id        
    
       
if @user_id > 0          
    
select criteria as Keywordname,sum(Clicks) clicks,sum(cost) costs ,tc.CampaignName,tg./*Adword_Name */GroupName,sum(impressions) Impressions  
from Adword_DailyCampaignDt rpt  join tblCampaign tc on rpt.CampaignId=tc.CampAd_id  
join tblAdGroup tg on rpt.AdGroupId =tg.AdwordGroupId  
where rpt.CampaignId=case when @gcampaignid = 0 then rpt.CampaignId else @gcampaignid end     
and rpt.AdGroupId=case when @gadwordgroupid = 0 then rpt.AdGroupId else @gadwordgroupid end     
and rpt.user_id = @user_id and tc.IsDeleted=0
and CONVERT(date,rpt.Report_Date) between CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentID,@fmdate)) and        
 CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentID,@todate))    
group by criteria ,tc.CampaignName,tg./*Adword_Name*/GroupName    
    
else          
select criteria as Keywordname,sum(Clicks) clicks,sum(cost) costs ,tc.CampaignName,tg./*Adword_Name */GroupName,sum(impressions) Impressions  
from Adword_DailyCampaignDt rpt join tblCampaign tc on rpt.CampaignId=tc.CampaignId  
join tblAdGroup tg on rpt.AdGroupId =tg.AdwordGroupId   
where rpt.CampaignId=case when @gcampaignid = 0 then rpt.CampaignId else @gcampaignid end     
and rpt.AdGroupId=case when @gadwordgroupid = 0 then rpt.AdGroupId else @gadwordgroupid end     
and rpt.user_id = @user_id and tc.IsDeleted=0 
  and CONVERT(date,rpt.Report_Date) between CONVERT(date, dbo.[fn_getISTtimefromusertime](@ParentID,@fmdate)) and        
   CONVERT(date,dbo.[fn_getISTtimefromusertime](@ParentID,@todate))    
group by criteria ,tc.CampaignName,tg./*Adword_Name*/GroupName
end      



GO

