/* ============================================================
   Procedure: [dbo].[GetNewName]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE GetNewName --17626,'usercampaignmaster','campaignname','FollowUpLead'
    @parentid bigINT ,   --<-- I dont think you need BIT here, BIT can only 1 or 0
    @tbl sysname,
    @colname nvarchar(50),
    @Name varchar(250) OUTPUT
AS
BEGIN
 SET NOCOUNT ON;
DECLARE @SQL NVARCHAR(MAX);
SET @SQL =  N' declare @oName nvarchar(50)=@name;
declare @i int =0;
while exists (select '+ @colname +' from '+ QUOTENAME(@tbl)
            + ' where '+ @colname +'=@name and parentid=@parentid)
begin
if @name<>@oName
begin
set @name= LEFT(@name,len(@name)-len(@i)); 
end
set @i=@i+1;
declare @len int=len(@i);
set @name= @name + CAST(@i as nvarchar);
end
select @name;'
--N' while exists @name in (SELECT @Name = Name FROM ' + QUOTENAME(@tbl)
--            + N' WHERE Id = @id '
 EXECUTE sp_executesql @SQL 
                      ,N'@parentid bigINT , @Name varchar(32) OUTPUT'
                      ,@parentid
                      ,@Name OUTPUT
END 


GO

