/* ============================================================
   Procedure: [dbo].[GetnextTemplate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[GetnextTemplate]-- 1283981--'2648'  
(@jobid bigint)  
as  
begin  
--declare @jobid int =2648   
select distinct u.campaignid,m.templategroupid,0 as templateid,(TemplateGroupSequence-1) as orderno,isending into #TemplatesTorun  
from UserCampaignexecutionHistory u join usercampaignmaster m on m.id=u.campaignid left join  
(select campaignid,MAX(jobid) as Jobid,TemplateSequence from UserCampaignexecutionHistory u where u.IsExecuted=1 group by CampaignID,TemplateSequence) A  
on A.CampaignID =m.id   
where u.Jobid=@jobid  and TemplateGroupID<>0  


  
if exists(select '1' from #TemplatesTorun)  
begin  
update ttr set templateid= case when isending=1 then isnull(A.templateid,0) else isnull(isnull(A.templateid,B.templateid),0) end,orderno=isnull(ISNULL(A.OrderNo,B.OrderNo),0) from #TemplatesTorun ttr left join   
(select ttr.campaignid,ugtm.templateid,ugtm.OrderNo from UserGroupTemplateMix ugtm join #TemplatesTorun ttr on ugtm.groupid=ttr.TemplateGroupID join UserMailTemplate umt on   
umt.ID=ugtm.TemplateID where ugtm.OrderNo = ttr.orderno +1) A on A.CampaignID=ttr.CampaignID   
join   
(select ttr.campaignid,ugtm.templateid,ugtm.OrderNo from UserGroupTemplateMix ugtm join #TemplatesTorun ttr on ugtm.groupid=ttr.TemplateGroupID join UserMailTemplate umt on   
umt.ID=ugtm.TemplateID  where ugtm.OrderNo = 1) B on B.CampaignID=ttr.CampaignID  
end  
  
select * from #TemplatesTorun  
end  

--select * from UserMailTemplate where ID=1657
  
  


GO

/* ============================================================
   Procedure: [dbo].[GetNonPersonalisedUserTemplate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[GetNonPersonalisedUserTemplate] 
@id bigint =0 ,
@userid bigint 
AS 
BEGIN
	Declare @parentid bigint = (Select parentid from User_Detail where User_id = @userid) 
	IF @id = 0
	BEGIN
		Select ID, ParentID,Name,MailSubject from UserMailTemplate where parentid= @parentid and IsPersonalized=0 and ActiveStatus=1 and IsMail=1 
		Order by ID desc
	END
	Else 
	BEGIN
		Select ID, ParentID, Name, MailSubject, MailContent, MailContentEditable, body_disp from UserMailTemplate where ID= @id
	END
END


