 ud.User_ID as [OwnerId],  
 concat(ud.User_Login, '(', ud.FName, ' ', ud.LName, ')') as [OwnerName],  
 (  
  select  concat( ue.FName, ' ', ue.LName) as [FieldExcutiveName]   
   from TBL_ET_PhyAppointUserMapping(nolock) fe inner join User_Detail(nolock) ue on fe.UserId = ue.User_ID   
   where fe.PhysicalAppointmentId = p.PhysicalAppointmentId  
  for json path  
  
 ) as [FieldExecutives],  
  
 (  
  select  concat('(', ue.FName, ' ', ue.LName, ')') as [CollaboratorName]   
   from TBL_ET_PhyAppointCollaboratorUserMapping(nolock) fe inner join User_Detail(nolock) ue on fe.UserId = ue.User_ID   
   where fe.PhysicalAppointmentId = p.PhysicalAppointmentId  
  for json path  
  
 ) as [CollaboratorName]  
  
  
from  tbl_et_geoentitymaster(NOLOCK) as g  
 inner join TBL_ET_GeoEntitySiteMaster(nolock) s on g.GeoEntityId = s.GeoEntityId   
 INNER JOIN TBL_ET_PhysicalAppointment(NOLOCK) p on s.GeoEntitySiteId = p.GeoEntitySiteId  
 LEFT JOIN TBL_ET_GeoEntityCheckInOut(nolock) c on p.PhysicalAppointmentId = c.PhysicalAppointmentId  
 LEFT JOIN tbl_tsk_UserOutcomeMaster(Nolock) o on p.OutcomesId = o.Id  
    LEFT JOIN TBL_ET_PhyAppointCollaboratorUserMapping(NOLOCK) cp on p.PhysicalAppointmentId = cp.PhysicalAppointmentId  
 LEFT JOIN User_Detail(NOLOCK) ud on p.AssignedTo = ud.User_ID  
   
 where g.EntityId=@LeadId --and  g.GeoEntityType = 'lead'  
End  





GO

/* ============================================================
   Procedure: [dbo].[GetPhyAppListwidgetWithEntityName]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[GetPhyAppListwidgetWithEntityName] ---GetPhyAppListwidget '1630709'  
	@EntityName nvarchar(25),
	@EntityId BIGINT

as  
begin  
  
	select    distinct
	 p.TItle,  
	 p.Description,  
	 p.startDate,  
	 o.OutcomeName,  
	 c.CheckIn,  
	 c.CheckOut,  
	 p.Address,  
	 g.EntityId,  
	 ud.User_ID as [OwnerId],  
	 concat(ud.User_Login, '(', ud.FName, ' ', ud.LName, ')') as [OwnerName],  
	 (  
	  select  concat( ue.FName, ' ', ue.LName) as [FieldExcutiveName]   
	   from TBL_ET_PhyAppointUserMapping(nolock) fe inner join User_Detail(nolock) ue on fe.UserId = ue.User_ID   
	   where fe.PhysicalAppointmentId = p.PhysicalAppointmentId  
	  for json path  
  
	 ) as [FieldExecutives],  
  
	 (  
	  select  concat('(', ue.FName, ' ', ue.LName, ')') as [CollaboratorName]   
	   from TBL_ET_PhyAppointCollaboratorUserMapping(nolock) fe inner join User_Detail(nolock) ue on fe.UserId = ue.User_ID   
	   where fe.PhysicalAppointmentId = p.PhysicalAppointmentId  
	  for json path  
  
	 ) as [CollaboratorName]  
  
  
	from  tbl_et_geoentitymaster(NOLOCK) as g  
		inner join TBL_ET_GeoEntitySiteMaster(nolock) s on g.GeoEntityId = s.GeoEntityId   
		INNER JOIN TBL_ET_PhysicalAppointment(NOLOCK) p on s.GeoEntitySiteId = p.GeoEntitySiteId  
		LEFT JOIN TBL_ET_GeoEntityCheckInOut(nolock) c on p.PhysicalAppointmentId = c.PhysicalAppointmentId  
		LEFT JOIN tbl_tsk_UserOutcomeMaster(Nolock) o on p.OutcomesId = o.Id  
		LEFT JOIN TBL_ET_PhyAppointCollaboratorUserMapping(NOLOCK) cp on p.PhysicalAppointmentId = cp.PhysicalAppointmentId  
		LEFT JOIN User_Detail(NOLOCK) ud on p.AssignedTo = ud.User_ID  
   
	 where g.EntityId=@EntityId and g.EntityId <> 0 and  g.GeoEntityType = @EntityName
	end




GO

