/* ============================================================
   Procedure: [dbo].[GetRecordValueByDomainAndUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.GetRecordValueByDomainAndUser --'growmet.in',31899  
    @DomainName NVARCHAR(200),  
    @UserID BIGINT  
AS  
BEGIN  
    SET NOCOUNT ON;  
      
    BEGIN TRY  
        -- Check if any record exists for the given domain, user ID, and isverified = 0  
        IF EXISTS (  
            SELECT 1  
            FROM tbl_pt_DomainVerification with(nolock)  
            WHERE domain = dbo.fn_removewww(@DomainName) 
			--domain = @DomainName  
              AND userid = @UserID  
              AND isverified = 0  
        )  
        BEGIN  
            -- If a record exists, retrieve the record_value  
            SELECT record_value  
            FROM tbl_pt_DomainVerification with(nolock)  
            WHERE domain = dbo.fn_removewww(@DomainName) 
			--domain = @DomainName  
              AND userid = @UserID  
              AND isverified = 0;  
        END  
        ELSE  
        BEGIN  
            -- If no record exists, return a status message  
            SELECT 'No record found' AS StatusMessage;  
        END  
    END TRY  
    BEGIN CATCH  
       EXEC usp_InsertErrorInfo;  
    END CATCH  
END   


GO

