/* ============================================================
   Procedure: [dbo].[GetStatusofLinkedServer]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 

CREATE   PROCEDURE [dbo].[GetStatusofLinkedServer]
	@ServerName VARCHAR(50)
AS
BEGIN
	DECLARE @srvr NVARCHAR(128),
	        @retval INT;
	SET @srvr = @ServerName;
	BEGIN TRY
		EXEC @retval = sys.sp_testlinkedserver @srvr;
	END TRY
	BEGIN CATCH
		SET @retval = SIGN(@@error);
	END CATCH;
	IF @retval <> 0
	BEGIN
	    SELECT 'Server is currently Offline!!'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[GetStatusofLinkedServerwithoutput]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[GetStatusofLinkedServerwithoutput] -- 'CRM'
 @ServerName VARCHAR(50)  ,
 @result nvarchar(50) = '0' output 
 AS  
BEGIN  
 DECLARE @srvr NVARCHAR(128),  
         @retval INT;  
 SET @srvr = @ServerName;  
 BEGIN TRY  
  EXEC @retval = sys.sp_testlinkedserver @srvr;  
 END TRY  
 BEGIN CATCH  
  SET @retval = SIGN(@@error);  
 END CATCH;  
 IF @retval <> 0  
 BEGIN  
     SELECT @result='Server is currently Offline!!'  
 END  
END  


GO

