CREATE   PROC getsupport_url_link    
(    
@shorturl varchar(50),    
@ipaddress varchar(20),    
@domain varchar(50)    
)    
as    
begin    
    
if exists (select '*' from Serv_Ticket_url_link where ShortUrl = @domain+'/'+@shorturl )    
begin    
insert into serv_ticket_url_track (VisitDate,Mobile, Parentid, link_id, Long_Url, ipAddress)    
select getdate(),isnull(d.Mobile,0),isnull(m.ParentId, NULL),l.id, l.DomainUrl,@ipaddress     
from Serv_Ticket_url_link l(nolock)     
left outer join Serv_TicketMaster m(nolock)    
on l.TicketId = m.TicketID    
left outer join Serv_User_Detail d (nolock)    
on m.User_id = d.ser_user_id    
where l.ShortUrl = @domain+'/'+@shorturl-- and l.Status = 1    
end    
Select DomainUrl from Serv_Ticket_url_link where ShortUrl = @domain+'/'+@shorturl     
end    



