SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[getTrack_url_link]--'ZTHQD' ,'1.1.1.1','pel.im'                             
(                                
 @Final_url nvarchar(50),                                
 @ipAddress varchar(200),                              
 @domain varchar(50)                                
)                                
as                                 
begin  
if not exists(select 1 from dbo.Link_smsMobile(nolock) where Final_url=@Final_url and status=1 and shorturl = @domain)                                
and exists (select 1 from dbo.Link_smsMobilefromclone(nolock) where Final_url=@Final_url and status=1 and shorturl = @domain)                                
begin                     
 insert into Link_smsMobile(Mobile, batchid,shorturl, longurl,  ProcessUrl_id,Final_url,Parentid,MessageID,Page_nm,p_url)      
 select l.Mobile, l.batchid,l.shorturl, l.longurl,  l.ProcessUrl_id,l.Final_url,l.Parentid,l.MessageID,l.Page_nm,l.p_url      
 from Link_smsMobilefromclone(nolock) l where l.final_url=@Final_url  
end  
if exists(select 1 from dbo.Link_smsMobile(nolock) where Final_url=@Final_url and status=1                              
 and shorturl = @domain)                                
begin                                
 declare @trackid bigint,@mobile nvarchar(20),@longurl nvarchar(200),@parentid bigint,@batchid bigint ,@mobile_url_id bigint,      
 @smssource nvarchar(20)                         
 insert into dbo.Link_smsTrack (Mobile, Parentid, link_id, Long_Url, ipAddress)                                
 select Mobile, Parentid, mobile_url_id, ISNULL(p_url,LongUrl), @ipAddress from dbo.Link_smsMobile(nolock)                                 
 where Final_url=@Final_url and status=1 and shorturl = @domain                               
 select @trackid=SCOPE_IDENTITY()                
      
 --Start embedded                 
                          
  Declare @MobileForLead nvarchar(50) = ''                
  Declare @ParentIDForLead bigint = 0  ,@messageid bigint              
                   
 select top 1 @MobileForLead = isnull(Mobile,''), @ParentIDForLead = isnull(Parentid,0),@messageid=MessageID,  
 @batchid=batchid,@mobile_url_id=mobile_url_id  from dbo.Link_smsMobile(nolock)  where Final_url=@Final_url and status=1 and shorturl = @domain      
       
 select @smssource=sms_source from Batchinfo(nolock) where batchid=@BatchID      
      
 if @smssource='InternalCRM'      
 begin      
 declare @etime datetime=getdate()      
 exec usp_insertcrmenagagementactivity @batchid,@MobileForLead,'SMS','Clicked','Link_smsTrack',@trackid,@etime      
 end      
         
  if exists(select 1 from DLTdetails d where parentid=@parentidforlead and PE_ID='1701159108398939463')        
  begin        
  declare @bmessage nvarchar(3000)=(select bmessage from BatchInfo(nolock) where batchid=@batchid)        
   insert into UserEvent ([Event],[UserID],[CRMEntry],[Description],[CreatedOn],[RefTable],[RefID],Mapping,MappingValue )        
  values ('User  Clicked on SMS link',0,0,'User with mobile no '+ cast(@MobileForLead as nvarchar)+' clicked on an SMS that read as "'+      
  substring(isnull(@bmessage,''),1,50)+'..."',GETDATE(),'MessageDeliverystatus,Batchid',cast(@messageid as nvarchar)+'-'      
  +cast(@batchid as nvarchar),'Mobile',@MobileForLead )        
   end        
        
                   
  if(@MobileForLead <> '')                
  Begin        
    begin try                
        
 if(exists (select 1 from leadsettings where isnull(UserID,0) = @ParentIDForLead and isnull(Mode,'') = 'SMSTrackingLead' and isnull(Status,0) = 1) )        
  Begin        
      exec Usp_insertIntoLeadList 'SMSTrackingLead','Mobile','',@MobileForLead,'','','','',@ParentIDForLead                 
     end        
           
   end try        
   begin catch        
     exec usp_insertErrorInfo        
   end catch        
        
        
  End                
                
 --End                
                
  exec usp_smstrack_salessignal @mobile_url_id,@trackid      
 /*                          
 SELECT @mobile=MOBILE,@LONGURL=long_url,@parentid=Parentid from link_smstrack(nolock) where trackid=@trackid                          
                    
 if exists(select 1 from UserLeads(nolock) where parentid=@parentid and @mobile in (MobileNo,MobileNo1,MobileNo2))        
 --exists(select 1 from user_detail (nolock) where ParentID=@parentid and isdemoaccount=1)                  
 --and exists(select 1 from user_detail(nolock) where STR(mobile)=@mobile and M_ID=10043)                  
 begin                  
 declare @user_login nvarchar(50),@user_id bigint,@message nvarchar(2000),@assignedto nvarchar(100)                  
 declare @recipients nvarchar(max),@salesmessage nvarchar(2500),@leadid bigint,@leadno int,@leadname nvarchar(100)        
  select top 1 @Leadid=id,@leadno=leadno,@leadname=isnull(personname,''),@user_id=assignedto from userleads(nolock) where parentid=@parentid and @mobile in (MobileNo,MobileNo1,MobileNo2) order by id desc        
  select @user_login=user_login from user_detail(nolock) where user_id=@user_id        
  select @recipients= coalesce(@recipients+',','')+cast(str(mobile) as nvarchar(max)) from user_Detail(nolock) where user_id in (@user_id,@parentid)        
           
         
 select @batchid=batchid from dbo.Link_smsMobile  (nolock)                               
 where Final_url=@Final_url and status=1 and shorturl = @domain                               
select @message=bmessage from batchinfo(nolock) where batchid=@batchid                  
 --declare @description nvarchar(200)='User '+cast(@user_login as nvarchar)+' opened SMS with text "'+cast(@message as nvarchar)+'" and clicked on url "'+cast(@final_url as nvarchar)+'"'                  
 --exec Usp_InsertUserEventDetails 'User opened sms and clicked on a link',@user_ID,@Description,'Link_smsTrack',@trackID               
              
   --Script Start to be added for lead activity              
                        
   Begin try            
            
  Declare @Mobile_LDActivity nvarchar(50) = @mobile            
  Declare @UserID_LDActivity bigint = @user_id            
  Declare @Message_LDActivity nvarchar(max) = @message            
  Declare @MessageSentDate_LDActivity nvarchar(50)        
  Declare @LeadID_LDActivity   bigint = 0             
  Declare @LongURL_LD nvarchar(500) = @LONGURL            
  Declare @BatchID_LD bigint = @batchid            
  Declare @ParentID_LDActivity  bigint = @ParentID           
              
  --select @ParentID_LDActivity = isnull(ParentID,0) from User_detail(nolock)  where user_id = @user_id        
            
  select @Message_LDActivity= isnull(bmessage,''),@MessageSentDate_LDActivity = cast(isnull(nullif(scheduleddate,''),BatchInsertTime) as nvarchar(20))  from batchinfo(nolock) where batchid=@BatchID_LD              
        
  if @Message_LDActivity is null        
  select @Message_LDActivity='Message text unavailable',@MessageSentDate_LDActivity='More than 30 days back'        
          
  select @salesmessage= 'Lead number: '+ cast(@leadno as nvarchar)+ ', Name: '+@leadname+ ', Assigned to : '+@user_login + ' just clicked on a link on a SMS sent by you. The message read as "' + substring(@Message_LDActivity,1,50)        
  + '" was sent on '+ @MessageSentDate_LDActivity + '. Pl take apt action'        
        
  if 1=1-- @parentid=335        
  begin        
  exec usp_sendmessage 335,@salesmessage,@recipients,'KITAPP',0,1        
  end        
          
  select top 1 @LeadID_LDActivity = isnull(ID,0) from UserLeads(nolock) where MobileNo = @Mobile_LDActivity or MobileNo1 = @Mobile_LDActivity or MobileNo2 = @Mobile_LDActivity    order by id desc        
            
  create table #tblEventDescrb            
  (            
    EVNT_Description nvarchar(max)             
  )            
            
  if(isnull(@LeadID_LDActivity,0) > 0)            
    Begin            
                   
    insert into #tblEventDescrb            
       exec  Usp_EventTemplate_DynamicVarReplacement 'User clicked on link in sms',@UserID_LDActivity,@Message_LDActivity,            
    @Mobile_LDActivity,@LeadID_LDActivity,@LongURL_LD,@MessageSentDate_LDActivity,0,0,null,null,0,null,0,null,            
    null,null,null,null,0,null,null,null,null,null,null,null,null,null,null,null,0,0,0,null,null,null,0,null,null,            
    null,null,null,null            
             
    declare @evntMessage nvarchar(max) = ''             
            
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb            
               
   exec UspSaveLeadActivity @LeadID_LDActivity,@UserID_LDActivity,@ParentID_LDActivity,@evntMessage,'User clicked on link in sms'            
             
             
 End            
            
 End try            
            
 Begin Catch            
            
   exec usp_InsertErrorInfo             
            
 End Catch            
            
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence              
   Begin              
        DROP TABLE #tblEventDescrb              
   End             
               
              
   --Script End to be added for lead activity               
                    
 end         
 */                        
 if (select COUNT(1) from Link_smsTrack where Mobile=@mobile and long_url=@longurl and VisitDate>dateadd(mi,-5,getdate()))<2                          
 begin                          
 exec usp_sendtrackleadnotification @trackid                          
 end                          
                           
                           
end                                
select top 1 ISNULL(p_url,LongUrl) LongUrl  from dbo.Link_smsMobile(nolock) where Final_url=@Final_url and status=1 and shorturl = @domain  order by mobile_url_id desc                    
                                
end 


