/* ============================================================
   Procedure: [dbo].[getTrack_url_link_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[getTrack_url_link_New]                        
(                        
 @Final_url nvarchar(50),                        
 @ipAddress varchar(200),                      
 @domain varchar(50)                        
)                        
as                         
begin                        
if exists(select 1 from dbo.Link_smsMobile where Final_url=@Final_url and status=1                      
 and shorturl = @domain)                        
begin                        
 declare @trackid bigint,@mobile nvarchar(20),@longurl nvarchar(200),@parentid bigint,@batchid bigint                  
 insert into dbo.Link_smsTrack (Mobile, Parentid, link_id, Long_Url, ipAddress)                        
 select Mobile, Parentid, mobile_url_id, ISNULL(p_url,LongUrl), @ipAddress from dbo.Link_smsMobile                         
 where Final_url=@Final_url and status=1 and shorturl = @domain                       
 select @trackid=SCOPE_IDENTITY()        
         
 --Start embedded         
                  
  Declare @MobileForLead nvarchar(50) = ''        
  Declare @ParentIDForLead bigint = 0        
           
  select top 1 @MobileForLead = isnull(Mobile,''), @ParentIDForLead = isnull(Parentid,0)  from dbo.Link_smsMobile    where Final_url=@Final_url and status=1 and shorturl = @domain          
        
  if(@MobileForLead <> '')        
  Begin  
    
     if(exists(select 1 from leadsettings where  isnull(Mode,'') = 'SMSTrackingLead' and isnull(UserID,0) = @ParentIDForLead  and  ISNULL(Status,0) = 1 ))  
       Begin      
         exec Usp_insertIntoLeadList 'SMSTrackingLead','Mobile','',@MobileForLead,'','','','',@ParentIDForLead         
       End  
    
  End        
        
 --End        
        
        
                   
 SELECT @mobile=MOBILE,@LONGURL=long_url,@parentid=Parentid from link_smstrack where trackid=@trackid                  
            
 if exists(select 1 from user_detail (nolock) where ParentID=@parentid and isdemoaccount=1)          
 and exists(select 1 from user_detail(nolock) where STR(mobile)=@mobile and M_ID=10043)          
 begin          
 declare @user_login nvarchar(50),@user_id bigint,@message nvarchar(2000)          
 select @user_login=user_login,@user_id=user_id from user_detail(nolock) where STR(mobile)=@mobile and M_ID=10043          
 select @batchid=batchid from dbo.Link_smsMobile                         
 where Final_url=@Final_url and status=1 and shorturl = @domain                       
select @message=bmessage from batchinfo(nolock) where batchid=@batchid          
 declare @description nvarchar(200)='User '+cast(@user_login as nvarchar)+' opened SMS with text "'+cast(@message as nvarchar)+'" and clicked on url "'+cast(@final_url as nvarchar)+'"'          
 exec Usp_InsertUserEventDetails 'User opened sms and clicked on a link',@user_ID,@Description,'Link_smsTrack',@trackID,'mobile',@mobile       
      
   --Script Start to be added for lead activity      
                
   Begin try    
    
  Declare @Mobile_LDActivity nvarchar(50) = @mobile    
  Declare @UserID_LDActivity bigint = @user_id    
  Declare @Message_LDActivity nvarchar(max) = @message    
  Declare @MessageSentDate_LDActivity datetime = getdate()    
  Declare @LeadID_LDActivity   bigint = 0     
  Declare @LongURL_LD nvarchar(500) = @LONGURL    
  Declare @BatchID_LD bigint = @batchid    
  Declare @ParentID_LDActivity  bigint = 0    
      
  select @ParentID_LDActivity = isnull(ParentID,0) from User_detail  where user_id = @UserID_LDActivity    
    
    
    
  select @Message_LDActivity= isnull(bmessage,''),@MessageSentDate_LDActivity = BatchProcessComplete  from batchinfo(nolock) where batchid=@BatchID_LD      
    
  select top 1 @LeadID_LDActivity = isnull(ID,0) from UserLeads where MobileNo = @Mobile_LDActivity    
    
  create table #tblEventDescrb    
  (    
    EVNT_Description nvarchar(max)     
  )    
    
  if(isnull(@LeadID_LDActivity,0) > 0)    
    Begin    
           
    insert into #tblEventDescrb    
       exec  Usp_EventTemplate_DynamicVarReplacement 'User clicked on link in sms',@UserID_LDActivity,@Message_LDActivity,    
    @Mobile_LDActivity,@LeadID_LDActivity,@LongURL_LD,@MessageSentDate_LDActivity,0,0,null,null,0,null,0,null,    
    null,null,null,null,0,null,null,null,null,null,null,null,null,null,null,null,0,0,0,null,null,null,0,null,null,    
    null,null,null,null    
     
    declare @evntMessage nvarchar(max) = ''     
    
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb    
       
   exec UspSaveLeadActivity @LeadID_LDActivity,@UserID_LDActivity,@ParentID_LDActivity,@evntMessage,'User clicked on link in sms'    
     
     
 End    
    
 End try    
    
 Begin Catch    
    
   exec usp_InsertErrorInfo     
    
 End Catch    
    
  IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence      
   Begin      
        DROP TABLE #tblEventDescrb      
   End     
       
      
   --Script End to be added for lead activity       
            
 end                 
 --if (select COUNT(1) from Link_smsTrack where Mobile=@mobile and long_url=@longurl)<2                  
 --begin                  
 exec usp_sendtrackleadnotification @trackid                  
 --end                  
                   
                   
end                        
select top 1 ISNULL(p_url,LongUrl) LongUrl  from dbo.Link_smsMobile where Final_url=@Final_url and status=1 and shorturl = @domain  order by mobile_url_id desc            
                        
end 


GO

