/* ============================================================
   Procedure: [dbo].[GetUserDetailsByParentIdAndSearch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


------------------------------------------------------------------

CREATE   PROCEDURE [dbo].[GetUserDetailsByParentIdAndSearch]
    @parentid BIGINT,
    @searchTerm NVARCHAR(100) = ''
AS
BEGIN
    SET NOCOUNT ON;
    
    BEGIN TRY
        -- Use dynamic search term with wildcards
        SELECT 
            ud.FName + ' ' + ud.LName AS Name
        FROM 
            user_detail (NOLOCK) AS ud
        WHERE 
            ud.parentid = @parentid
            AND (ud.FName + ' ' + ud.LName LIKE '%' + @searchTerm + '%' OR @searchTerm = '')
    END TRY
    BEGIN CATCH
        -- Error handling
        SELECT 
            ERROR_MESSAGE() AS ErrorMessage;
    END CATCH
END




GO

