/* ============================================================
   Procedure: [dbo].[getvconbalance]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE getvconbalance
as  
begin  
exec sp_configure 'show advanced options', 1;  
RECONFIGURE;  
exec sp_configure 'Ole Automation Procedures', 1;  
RECONFIGURE;  

declare @t1 nvarchar(20)= 'a823824c00',@t2 nvarchar(20)= 'b74600fd83'
DECLARE @URL NVARCHAR(MAX) = 'http://blr.paragalaxy.com/api/balance_check.php?TokenID=a823824c00';
DECLARE @URL1 NVARCHAR(MAX) = 'http://blr.paragalaxy.com/api/balance_check.php?TokenID=b74600fd83';
Declare @Object as Int; DECLARE @ErroMsg NVARCHAR(30); 
Declare @ResponseText as Varchar(8000),@ResponseText1 as Varchar(8000);  
  
Exec sp_OACreate 'MSXML2.XMLHTTP', @Object OUT;  
Exec sp_OAMethod @Object, 'open', NULL, 'get',@URL,'False'  
Exec sp_OAMethod @Object, 'send'  
Exec sp_OAMethod @Object, 'responseText', @ResponseText OUTPUT  

Exec sp_OACreate 'MSXML2.XMLHTTP', @Object OUT;  
Exec sp_OAMethod @Object, 'open', NULL, 'get',@URL1,'False'  
Exec sp_OAMethod @Object, 'send'  
Exec sp_OAMethod @Object, 'responseText', @ResponseText1 OUTPUT  



Select @ResponseText,@ResponseText1
IF((Select @ResponseText) <> '')  
BEGIN  
insert into vconbalance(balance,token)
select JSON_VALUE(@responsetext,'$.balance'),@t1
end
ELSE  
BEGIN  
select @ErroMsg = 'No data found for token '+ @t1;  
     Print @ErroMsg;  
END  
IF((Select @ResponseText1) <> '')  
BEGIN  
insert into vconbalance(balance,token)
select JSON_VALUE(@responsetext1,'$.balance'),@t2
end
ELSE  
BEGIN  
select @ErroMsg = 'No data found for token '+ @t2;       
Print @ErroMsg;  
END 
