   Procedure: [dbo].[GetYahooLinkMailForwarding]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


     

CREATE   PROCEDURE [dbo].[GetYahooLinkMailForwarding]
	@VerifiyingEmail VARCHAR(500)
AS
BEGIN
	SELECT umv.ID,
	       umv.MailContent
	FROM   UserMailsVerification AS umv
	WHERE  umv.FromMail LIKE  '%no-reply@cc.yahoo-inc.com%'
	       AND umv.VerifiyingEmail = @VerifiyingEmail
	       AND umv.IsProcessed = 0
END




