/* ============================================================
   Procedure: [dbo].[ims_dlt_Validate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE ims_dlt_Validate(
	@UserId bigint,
	@Mode  nvarchar(255)
)
as
begin
	declare @ParentID bigint = 0 ,@DLT_TemplateID nvarchar(200) = '', @tempDLT_TemplateID nvarchar(200) = '' 
	select @ParentID = isnull(ParentID,0)  from User_Detail(nolock) where User_ID = @UserId    

	declare @isRegistered int =   dbo.fn_isdltregistered(@ParentId)


	if(@isRegistered = 1)
	begin

	declare @ContentToBeSearched nvarchar(max)  = '' 
	
	set @ContentToBeSearched =	case when @Mode = 'followup reminder'
										then 'Dear %, This is a Reminder message for % for Name-%,Mobile-%,Emailid-%,Remarks-% to be followed up on %'
									when @Mode = 'task creation'
										then 'Task Creation notification: Dear %, Task with title % with your role as Owner has been % on % by %'
									when @Mode = 'task reminder'
										then 'Reminder: Your Task titled % with % is scheduled for % at %'
									when @Mode = 'appointment creation'
										then 'Appointment Creation notification: Dear %, Task with title % with your role as Owner has been % on % by %'
									when @Mode = 'appointment reminder'
										then 'Reminder: Your Appointment titled % with % is scheduled for % at %'										 
									else '' end

	declare @defaultSenderId bigint

	select top 1 @defaultSenderId = Sender_ID from SenderID_Detail(nolock)    
		  where isnull(User_ID,0) = @UserID and isnull(Status,0) = 1  
			 and isnull(Sender_Name,'') in  
		   (  
			select Sender_Name from Default_SenderID(nolock) where User_ID = @UserID and ISNULL(Sender_Name ,'') <> ''  
		   )   
		   order by Sender_ID desc  


	select top 1 @tempDLT_TemplateID = isnull(TSM.DLT_TemplateID,'')   
       from DLT_TemplateSenderMapping(nolock) as TSM   join [UserMailTemplate](nolock) as UMT  
			on TSM.DLT_TemplateID = UMT.DLT_TemplateID  
		where TSM.SenderID = @defaultSenderId     
			 and TSM.CreatedBy = @UserID  and UMT.MailContent = @ContentToBeSearched   


		if(RTRIM(ltrim(@tempDLT_TemplateID)) <> '')    
		Begin    
			SELECT top 1 @DLT_TemplateID = [DLT_TemplateID] FROM [UserMailTemplate](nolock) 
						where ParentID = @ParentID and MailContent = @ContentToBeSearched and DLT_TemplateID = @tempDLT_TemplateID  
		end

	end

	declare @message nvarchar(max) = ''
	set @message =  case when  @isRegistered = 0
				then 'Only DLT registered entities can send SMS. To <a href="/user/DLT/DLT_Entity.aspx">know more</a>'
			when @DLT_TemplateID = ''
				then 'No template found for notification SMS. To send reminder SMS, you must get a template exactly like "' + @ContentToBeSearched + '" approved. For template creation <a href="/user/DLT/DLT_Entity.aspx">Click Here</a>'
				else '' end
	
	select @isRegistered as [IsRegistered], @DLT_TemplateID as [DLTTemplateId], @message as Message
end



GO

/* ============================================================
   Procedure: [dbo].[incallfunction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE incallfunction(@disposition nvarchar(20),@diallercallid int)
as
begin
declare @channelid int=(select k.channel_id from kit19channels k join kit19calls kc on k.channel_uniqueid=kc.uniqueid join DiallerCalls d on kc.id=d.kit19callsid )
update diallercalls set disposition=@disposition,call_answer_time=case when @disposition='ANSWER' then GETDATE() end
from diallercalls where ID=@diallercallid
UPDATE Kit19Channels SET channel_flowstep ='DialerCalls' WHERE id = @channelid
end



GO

/* ============================================================
   Procedure: [dbo].[insert_custm_Analytics]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext insert_custm_Analytics  
CREATE   PROCEDURE dbo.insert_custm_Analytics (
	@USER_ID AS BIGINT = NULL
	,@Usergraphdisp2 AS TINYINT = 0
	,@Usergraphdisp1 AS TINYINT = 0
	,@SMSGraphdisp AS TINYINT = 0
	,@MailGraphdisp AS TINYINT = 0
	,@PurchaseGraphdisp AS TINYINT = 0
	,@SourceGraphdisp AS TINYINT = 0
	,@MediumGraphdisp AS TINYINT = 0
	,@CampaignGraphdisp AS TINYINT = 0
	,@leadGraphdisp AS TINYINT = 0
	)
AS
BEGIN
	DECLARE @activity VARCHAR(MAX) = ''
		,@action VARCHAR(1) = ''

	IF EXISTS (
			SELECT *
			FROM custm_Analytics
			WHERE user_id = @USER_ID
			)
	BEGIN
		UPDATE custm_Analytics
		SET Usergraphdisp2 = @Usergraphdisp2
			,Usergraphdisp1 = @Usergraphdisp1
			,SMSGraphdisp = @SMSGraphdisp
			,MailGraphdisp = @MailGraphdisp
			,PurchaseGraphdisp = @PurchaseGraphdisp
			,SourceGraphdisp = @SourceGraphdisp
			,MediumGraphdisp = @MediumGraphdisp
			,CampaignGraphdisp = @CampaignGraphdisp
			,leadGraphdisp = @leadGraphdisp
		WHERE user_id = @USER_ID

		SET @action = 'U'
		SET @activity = 'Updt_CusAnys_dshbrd'
	END
	ELSE
	BEGIN
		INSERT INTO custm_Analytics (
			user_id
			,Usergraphdisp2
			,Usergraphdisp1
			,SMSGraphdisp
			,MailGraphdisp
			,PurchaseGraphdisp
			,SourceGraphdisp
			,MediumGraphdisp
			,CampaignGraphdisp
			,leadGraphdisp
			)
		VALUES (
			@user_id
			,@Usergraphdisp2
			,@Usergraphdisp1
			,@SMSGraphdisp
			,@MailGraphdisp
			,@PurchaseGraphdisp
			,@SourceGraphdisp
			,@MediumGraphdisp
			,@CampaignGraphdisp
			,@leadGraphdisp
			)

		SET @action = 'I'
		SET @activity = 'Inst_CusAnys_dshbrd'
	END

	SELECT 'Updated Successfully'

	DECLARE @rowJson VARCHAR(MAX) = (
			SELECT *
			FROM custm_Analytics(NOLOCK)
			WHERE user_id = @USER_ID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @USER_ID
			,@Activity_type = @activity
			,@ActionType = @action
			,@RowJson = @rowJson
			,@Table_name = 'custm_Analytics'
	END
END



GO

