/* ============================================================
   Procedure: [dbo].[Insert_Update_BlockSpamDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[Insert_Update_BlockSpamDetail]
(
@UserID int,
@ContactNo varchar(20),
@status char(1)

)
as
begin
	if exists(select * from ContactBlockSpam_Detail where UserID=@UserID and  ContactNo=@ContactNo)                                                            
		begin                                                            
		   if(@status='B')
			  begin
				  update ContactBlockSpam_Detail set IsBlock=1 where UserID=@UserID and  ContactNo=@ContactNo
				  select 'Blocked Successfully'
			  end 
			else
			  begin
				  update ContactBlockSpam_Detail set IsSpam=1 where UserID=@UserID and  ContactNo=@ContactNo
				  select 'Spam Successfully'
			  end                                                    
		end 
   else
          
		begin                                                            
		   if(@status='B')
			  begin
				 insert into ContactBlockSpam_Detail (UserID,ContactNo,IsSpam,IsBlock,BlockDateTime)
				                               values(@UserID,@ContactNo,0,1,GETDATE())
				 select 'Blocked Successfully'
			  end 
			else
			  begin
				 insert into ContactBlockSpam_Detail (UserID,ContactNo,IsSpam,IsBlock,SpamDateTime)
				                               values(@UserID,@ContactNo,1,0,GETDATE())
				select 'Spam Successfully'
			  end                                                    
		end 
End




