CREATE   PROC InsertInfoBeforeAlowNotAllow      
@sender varchar(20),      
@userid nvarchar(100),      
@DndAllow tinyint      
AS      
BEGIN     
DEclare @DND bigint,@TotalRecords bigint ,@Message nvarchar(2000)
Declare @batchID bigint,@ispriority tinyint, @u_id bigint 
select @Message=Message,@batchID=batchid from MessageMonitor where senderid=@sender
select @DND=Operator,@TotalRecords=TotalRecords,@ispriority=IsPrority,@u_id=userid from batchinfo where batchid=@batchID

insert into DNDAllowNotAllow (Senderid,Userid,Message,Dnd)      
select @sender,@userid,@Message,@DndAllow --from MessageMonitor where senderid=@sender --group by Message

insert into DNDRefund(UserID, Senderid,total,DND,[Message],Priority,[Action],batchid)
select @u_id,@sender,@TotalRecords,@DND,@Message,@ispriority,@DndAllow,@batchID
    
END    


