/* ============================================================
   Procedure: [dbo].[isp_GetSmsProviderByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Create stored procedure to get SMS Provider configuration by User ID and Provider ID  
-- This procedure returns provider name, API key, API URL, and other configuration details  
  
-- Stored Procedure: isp_GetSmsProviderByUserId  
-- Purpose: Get SMS provider configuration for a user based on country code and user preferences  
-- This procedure uses Price_Base_SMS_Rate table to get default provider by country code  
-- and tbl_SMS_Provider table to get actual provider configuration details  
  
CREATE   PROCEDURE [dbo].[isp_GetSmsProviderByUserId]  
    @UserId BIGINT,  
    @IntlSMSProviderId INT,  
    @CountryCode NVARCHAR(10)  
AS  
BEGIN  
    SET NOCOUNT ON;  
      
    BEGIN TRY  
        -- First try to get the default provider for the destination country  
        DECLARE @DefaultProviderName NVARCHAR(100)  
        DECLARE @ProviderName NVARCHAR(150)  
        DECLARE @ApiKey NVARCHAR(500)  
        DECLARE @ApiUrl NVARCHAR(500)  
        DECLARE @DefaultSender NVARCHAR(50)  
          
        -- Get default provider from Price_Base_SMS_Rate table based on country code  
        SELECT TOP 1 @DefaultProviderName = DefaultProvider  
        FROM Price_Base_SMS_Rate   
        WHERE --UserID = @UserId   
            
    DestinationCountryCode = @CountryCode  
          AND IsEligible = 1  
          AND DefaultProvider IS NOT NULL  
          
        -- If no specific provider found for country, use the IntlSMSProviderId mapping  
        IF @DefaultProviderName IS NULL  
        BEGIN  
            SELECT @DefaultProviderName = CASE @IntlSMSProviderId  
                WHEN 1 THEN 'Twilio'  
                WHEN 2 THEN 'Karix'  
                WHEN 3 THEN 'TextLocal'  
                WHEN 4 THEN 'Msg91'  
                WHEN 5 THEN 'Nexmo'  
                WHEN 6 THEN 'Plivo'  
                ELSE 'Twilio'  
            END  
        END  
          
        -- Now get the actual provider configuration from tbl_SMS_Provider  
        SELECT TOP 1   
            @ProviderName = ProviderName,  
            @ApiKey = AuthKey,  
            @ApiUrl = ApiUrl  
        FROM tbl_SMS_Provider   
        WHERE ProviderName = @DefaultProviderName   
          AND IsActive = 1  
          
        -- If provider not found in table, use default configuration  
        IF @ProviderName IS NULL  
        BEGIN  
            SET @ProviderName = @DefaultProviderName  
            -- Set default configurations based on provider name  
            SELECT   
                @ApiKey = CASE @DefaultProviderName  
                    WHEN 'Twilio' THEN ''  
                    WHEN 'Karix' THEN 'your-karix-api-key'  
                    WHEN 'TextLocal' THEN 'your-textlocal-api-key'  
                    WHEN 'Msg91' THEN 'your-msg91-api-key'  
                    WHEN 'Nexmo' THEN 'your-nexmo-api-key'  
                    WHEN 'Plivo' THEN 'your-plivo-api-key'  
                    ELSE ''  
                END,  
                @ApiUrl = CASE @DefaultProviderName  
                    WHEN 'Twilio' THEN ''  
                    WHEN 'Karix' THEN 'https://api.karix.io/message/'  
                    WHEN 'TextLocal' THEN 'https://api.textlocal.in/send/'  
                    WHEN 'Msg91' THEN 'https://api.msg91.com/api/v5/flow/'  
                    WHEN 'Nexmo' THEN 'https://rest.nexmo.com/sms/json'  
                    WHEN 'Plivo' THEN 'https://api.plivo.com/v1/Account/{auth_id}/Message/'  
                    ELSE ''  
                END  
        END  
          
        -- Set default sender based on provider  
        SET @DefaultSender = CASE @ProviderName  
            WHEN 'Twilio' THEN 'TWILIO'  
            WHEN 'Karix' THEN 'KARIX'  
            WHEN 'TextLocal' THEN 'TXTLCL'  
            WHEN 'Msg91' THEN 'MSG91'  
            WHEN 'Nexmo' THEN 'NEXMO'  
            WHEN 'Plivo' THEN 'PLIVO'  
            ELSE 'ALERT'  
        END  
          
        -- Return the provider configuration  
        SELECT   
            @ProviderName AS ProviderName,  
            @ApiKey AS ApiKey,  
  @ApiUrl AS ApiUrl,  
            @DefaultSender AS DefaultSender,  
            CAST(1 AS BIT) AS IsActive,  
            @IntlSMSProviderId AS IntlSMSProviderId,  
            @UserId AS UserId,  
            @CountryCode AS CountryCode  
          
    END TRY  
    BEGIN CATCH  
        -- Return default Twilio configuration in case of error  
        SELECT   
            'Twilio' AS ProviderName,  
            '' AS ApiKey,  
            '' AS ApiUrl,  
            'ALERT' AS DefaultSender,  
            CAST(1 AS BIT) AS IsActive,  
            @IntlSMSProviderId AS IntlSMSProviderId,  
            @UserId AS UserId,  
            @CountryCode AS CountryCode  
  
     EXEC usp_InsertErrorInfo; -- Log the error  
    END CATCH  
END  
  
-- Usage Example:  
-- EXEC isp_GetSmsProviderByUserId @UserId = 12345, @IntlSMSProviderId = 2, @CountryCode = 'IN'  
  
-- Note:   
-- 1. This procedure first checks Price_Base_SMS_Rate for country-specific default provider  
-- 2. Then gets actual configuration from tbl_SMS_Provider table  
-- 3. Falls back to hardcoded configurations if provider not found in table  
-- 4. Update the API keys in tbl_SMS_Provider table with actual values



GO

/* ============================================================
   Procedure: [dbo].[isp_IntlSmsManyToManyValidation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------

CREATE   PROCEDURE [dbo].[isp_IntlSmsManyToManyValidation]  
@UserId bigint,          
@MessagesJson nvarchar(max)='',
@MassOpBatchId bigint=0
  as        
BEGIN     -- Declare variables     
DECLARE @Result AS VARCHAR(100);     DECLARE @IsValid AS BIT=1;     DECLARE @SmsApiURI AS VARCHAR(200);     DECLARE @IntlSMSProviderId AS INT;     DECLARE @Balance AS DECIMAL;     DECLARE @CountryCode AS VARCHAR(200);   
  DECLARE @Key AS VARCHAR(200);     DECLARE @Send AS VARCHAR(200);
  -- Create a table to hold the parsed JSON data
  DECLARE @Messages TABLE (         dest NVARCHAR(MAX),         textMsg NVARCHAR(MAX)     );
  -- Insert JSON data into the table  
   INSERT INTO @Messages (dest, textMsg)     SELECT          JSON_VALUE(value, '$.dest') AS dest,         JSON_VALUE(value, '$.text') AS textMsg     FROM OPENJSON(@MessagesJson) AS value;
   -- Check if user exists
   IF EXISTS (SELECT 1 FROM user_detail WITH (NOLOCK) WHERE User_ID = @UserId)
   BEGIN
   -- Get user balance
   SELECT TOP 1 @Balance = Balance
   FROM IntCredit_Details WITH (NOLOCK)
   WHERE User_ID = @UserId
   GROUP BY Balance
   ORDER BY MAX(DateCreated) DESC;

   DECLARE @avilablebalance decimal(18, 4)
  SET @avilablebalance = dbo.GetAvailableBalanceForService(@UserId, 3)
   
   IF (@avilablebalance <= 0)
   BEGIN
   SET @Result = 'you have insufficient balance';
   SET @IsValid = 0;
   SET @SmsApiURI = '';
   SET @Key = '';
   SET @Send = '';
   SET @IntlSMSProviderId = 0;
   SET @CountryCode = '';
   END
   
   END
   ELSE
   BEGIN
   SET @Result = 'user not found';
   SET @IsValid = 0;
   SET @SmsApiURI = '';
   SET @IntlSMSProviderId = 0;
   SET @Key = '';       
   SET @Send = '';
   SET @CountryCode = '';
   END
   
   -- Return the result
   SELECT isnull(@Result,'') AS Result, isnull(@IsValid,0) AS IsValid, isnull(@SmsApiURI,'') AS SmsApiURI, isnull(@IntlSMSProviderId,0) AS IntlSMSProviderId, 
      isnull(@Key,'') AS Keys, isnull(@Send,'') AS Sends, isnull(@CountryCode,'') AS CountryCode;
   
END



GO

/* ============================================================
   Procedure: [dbo].[isp_intlSMSOneToManyDataHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[isp_intlSMSOneToManyDataHistory]  
(  
 @UserId BIGINT ,       
        @MobileNo NVARCHAR(MAX) ,    
        @SenderCountryCode VARCHAR(200),    
        @Msz NVARCHAR(MAX) ,  
