        @Campaignid BIGINT,  
        @EntityID BIGINT = 0,  
        @EntityName NVARCHAR(MAX) = '',  
        @ParentId BIGINT,  
        @m_id BIGINT,  
        @Placeholders NVARCHAR(MAX) = '',  
        @ispersonalised BIT,  
        @mszstatus NVARCHAR(MAX),  
        @MessageDeliveryStatusID BIGINT = 0,  
        @cost_in_inr DECIMAL,  
        @Price DECIMAL,  
        @IsUnicode BIT = 0,  
        @CurrentMobile NVARCHAR(20),
		@CountryCode NVARCHAR(20)
  
-- Get parent ID and m_id  
SELECT @m_id = m_id, @ParentId = parentid   
FROM user_detail WITH (NOLOCK)   
WHERE user_id = @UserId;  
  
-- Get balance  
SELECT @Balance = dbo.[fn_GetMoneyBalance](@ParentId);  
PRINT CONCAT('@Balance: ', @Balance);  
  
-- Begin transaction for batch ID  
BEGIN TRAN                     
    INSERT INTO Getbatchrecord (user_id, randnum)                                          
    VALUES (@UserId, @m_id);                    
    SET @Batchid = SCOPE_IDENTITY();                    
    DELETE FROM Getbatchrecord WHERE Batchid = @Batchid;                
COMMIT;                   
  
-- Split mobile numbers and process each one  
DECLARE @MobileNumbers TABLE (Mobile NVARCHAR(20));  
INSERT INTO @MobileNumbers (Mobile)  
SELECT value FROM STRING_SPLIT(@MobileNo, ',');  
  
DECLARE cur CURSOR FOR  
SELECT Mobile FROM @MobileNumbers;  
  
OPEN cur;  
FETCH NEXT FROM cur INTO @CurrentMobile;  
  
WHILE @@FETCH_STATUS = 0  
BEGIN  
	-- Process each mobile number  
	select @CountryCode= CountryCode,@Mobile=Mobile  
	FROM fn_separatecountrycodeandmobile(@CurrentMobile)  
  
    SET @Mobile = REPLACE(CAST(@CurrentMobile AS NVARCHAR(100)), REPLACE(trim(@CountryCode), '+', ''), '');  
  
    IF EXISTS (SELECT * FROM UserLeads WITH (NOLOCK) WHERE ParentID = @ParentId AND MobileNo = @Mobile AND CountryCode = @CountryCode)  
    BEGIN  
        SELECT @EntityID = ID, @EntityName = 'lead'   
        FROM UserLeads WITH (NOLOCK)   
        WHERE ParentID = @ParentId AND MobileNo = @Mobile AND CountryCode = @CountryCode;  
        SET @Placeholders = (SELECT dbo.ExtractPlaceholders('lead', @Msz));  
    END  
    ELSE IF EXISTS (SELECT * FROM UserEnquiry WITH (NOLOCK) WHERE ParentID = @ParentId AND MobileNo = @Mobile AND CountryCode = @CountryCode)  
    BEGIN  
        SELECT TOP 1 @EntityID = EnquiryID, @EntityName = 'Enquiry'   
        FROM UserEnquiry WITH (NOLOCK)   
        WHERE ParentID = @ParentId AND MobileNo = @Mobile AND CountryCode = @CountryCode   
        ORDER BY CreatedDate;  
        SET @Placeholders = (SELECT dbo.ExtractPlaceholders('Enquiry', @Msz));  
    END  
  
    IF (@Placeholders = '')  
    BEGIN  
        SET @ispersonalised = 0;  
    END  
    ELSE  
    BEGIN  
        SET @ispersonalised = 1;  
    END  
  
    -- Validation  
    SET @mszstatus = (SELECT CASE WHEN LEN(@Mobile) BETWEEN 5 AND 15 AND @Mobile NOT LIKE '%[^0-9+]%' THEN '' ELSE '6'  END);  
   
   
   
   
   
 if(@mszstatus ='')  
 begin  
 set @mszstatus =(select (case when (select count(*) from Price_base_sms_rate with(nolock) where DestinationCountryCode =@CountryCode and IsEligible=1) >0 then '' else '9' end))  
 end  
    -- Insert into Int_MessageDeliveryStatus  
    INSERT INTO Int_MessageDeliveryStatus (CountryCode, BatchID, Mobile, Message, MessageStatus, MessageInsertDate, MessageSubmitDate, U_ID, processed, SmsMode,MassOpBatchId,EntityId,EntityName)  
    VALUES (@CountryCode, ISNULL(@Batchid, 0), @Mobile, @Msz, @mszstatus, GETDATE(), GETDATE(), @UserId, 2, 'singleTomulti',@MassOpBatchId,@EntityID,@EntityName);  
  
    -- Clean up  
  
  
     
  
    -- Fetch next mobile number  
    FETCH NEXT FROM cur INTO @CurrentMobile;  
END  
  
CLOSE cur;  
DEALLOCATE cur;  
  
SELECT SCOPE_IDENTITY() AS Id, @EntityID AS EntityID, @EntityName AS EntityName, ISNULL(@Batchid, 0) AS Batchid, @Msz AS Msz, @Mobile AS Mobile;  
end



GO

