CREATE   PROCEDURE [dbo].[isp_intlSMSSendHistory](      
@IntlSMSProviderId int ,      
@RequestJson nvarchar(max) ,      
@ResponceJson nvarchar(max) ,      
@CountryCode nvarchar(200) ,      
@userId bigint ,
@Batchid bigint=0
)      
as      
begin      
      
DECLARE @M_ID AS bigint;      
declare @Balance as decimal;      
declare @cost_in_inr as decimal;      
      
--select * from user_detail where User_ID=335      
      
select @M_ID=M_ID from user_detail with(nolock) where User_ID=@userId       
      
select top 1 @Balance=Balance from mysms.dbo.IntCredit_Details with(nolock) where User_ID=@userId      
group by Balance      
order by max(DateCreated) desc      
      
   select batchid ,case when A.isunicode=0 and len(A.message)<=160  then 1 when A.isunicode=0 and LEN(A.message)>160 then ceiling(LEN  (A.message)/cast(153 as FLOat)) when A.IsUniCode=1 and len(A.message)<=70 then 1 else ceiling(LEN(A.message )
    /cast(67 as float)) end as Credits into #batchtobeprocessed from CloneIntMsgDeliveryStatus A with(nolock) where Batchid=@BatchID 
    declare @creditsreqd bigint= (select sum(Credits) from #batchtobeprocessed where batchid=@batchid)    
	
select @cost_in_inr=isnull(PTrnsScurb,0) from Price_base_sms_rate with(nolock)      where  DestinationCountryCode=trim(@CountryCode) 
and IsEligible=1
--and UserID=@userId
    
      
 insert into mysms.dbo.IntCredit_Details( FromUser_ID, M_ID, User_ID, Debits, Credits, Balance, Validity, typecredit, Remarks)                            
   select @userId, isnull(@M_ID,10043),@userId,@cost_in_inr*@creditsreqd,0,(@Balance-@cost_in_inr),99999,3,'Balance deducted for international SMS conversation'           
    
  declare @intCreditId bigint = scope_identity()
  exec usp_rf_UpdateReserveFundTransaction @CreditId = @intCreditId

     --select * from mysms.dbo.Price_Master_TypeCredit      
      
  insert into tbl_intlSMSSendHistory (tblintlSMSProviderId,RequestJson,ResponceJson,CreatedBy,CreatedDate,UpdatedBy,UpdatedDate,CountryCode)      
  values (@IntlSMSProviderId,@RequestJson,@ResponceJson,@userId,getdate(),@userId,GETDATE(),trim(@CountryCode))      
      
  
SELECT SCOPE_IDENTITY();        
end 



