CREATE   PROCEDURE [dbo].[isp_intlSMSSendHistory_oneToMany]
(
    @IntlSMSProviderId int ,          
    @RequestJson nvarchar(max) ,          
    @ResponceJson nvarchar(max) ,          
    @CountryCode nvarchar(200) ,          
    @userId bigint ,    
    @Batchid nvarchar(max)='',    
    @requestId nvarchar(max) ,    
    @MessageID nvarchar(max),    
    @statusCode nvarchar(max),
    @Mode varchar(10)='Single'    
)          
as          
begin          
          
--    declare @IntlSMSProviderId int=0 ,          
--@RequestJson nvarchar(max)='Twilio API' ,          
--@ResponceJson nvarchar(max)='{"sid":"SM299a840fc82364d61adc08eec9302e0e","status":"queued","to":"++27601234567","from":"+18653446319","body":"test intl msg 9"}' ,          
--@CountryCode nvarchar(200)='+27' ,          
--@userId bigint=34594 ,    
--@Batchid nvarchar(max)='156198643',    
--@requestId nvarchar(max) ='SM299a840fc82364d61adc08eec9302e0e',    
--@MessageID nvarchar(max)='22009',    
--@statusCode nvarchar(max)='queued'    


DECLARE @ParentId bigint,@M_ID bigint,@MessageDeliveryStatusID bigint=0,@Message_ID bigint=0;          
declare @Balance as numeric(18,4), @Batch_ID bigint=0, @MobileNo varchar(50)='',@SenderID nvarchar(40);          
