--select * from user_detail where User_ID=335          
          
select @ParentId=ParentId,@M_ID=M_ID from user_detail with(nolock) where User_ID=@userId
  
          
  
    drop table if exists #temp

     Select *,  ROW_NUMBER() OVER (ORDER BY MessageDeliveryStatusID) AS RowNum  
     into #temp 
     from Int_MessageDeliveryStatus(nolock) 
     Where MessageDeliveryStatusID=case when @Mode='Single' then @MessageID else MessageDeliveryStatusID end 
            and BatchID=case when @Mode='Bulk' then @Batchid else BatchID end


  update I set I.Processed=1,I.MessageStatus= @statusCode, I.MessageRefID=@requestId, MessageDeliveredDate=getdate()
  From Int_MessageDeliveryStatus I inner join #temp T
  on I.MessageDeliveryStatusID=T.MessageDeliveryStatusID
  where I.BatchID in (select value from dbo.fn_Split(@BatchID ,',') )    

    ---------------
  --return
  ------------------     

 If(@mode='Single')
 Begin
   insert into tbl_intlSMSSendHistory (tblintlSMSProviderId,RequestJson,ResponceJson,CreatedBy,CreatedDate,UpdatedBy,UpdatedDate,CountryCode,MessageDeliveryStatusID)  
   Select tblintlSMSProviderId=@IntlSMSProviderId,RequestJson=@RequestJson,ResponceJson=@ResponceJson,CreatedBy=@userId,CreatedDate=getdate(),UpdatedBy=@userId,UpdatedDate=GETDATE(),CountryCode=trim(@CountryCode), MessageDeliveryStatusID
   From #temp

    SELECT SCOPE_IDENTITY() as val;  
