       insert into tbl_intlSMSSendHistory (tblintlSMSProviderId,RequestJson,ResponceJson,CreatedBy,CreatedDate,UpdatedBy,UpdatedDate,CountryCode,MessageDeliveryStatusID)  
    Select tblintlSMSProviderId=@IntlSMSProviderId,RequestJson=@RequestJson,ResponceJson=@ResponceJson,CreatedBy=@userId,CreatedDate=getdate(),UpdatedBy=@userId,UpdatedDate=GETDATE(),CountryCode=trim(@CountryCode), 0 as MessageDeliveryStatusID

    SELECT SCOPE_IDENTITY() as val;  
  End
          
end   



