   Procedure: [dbo].[isp_IntlSmsValidation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[isp_IntlSmsValidation](          
@UserId bigint ,          
@MobileNo bigint )          
as          
begin          
        
DECLARE @Result AS VARCHAR(100);        
DECLARE @IsValid AS bit;        
DECLARE @SmsApiURI AS VARCHAR(200);        
DECLARE @IntlSMSProviderId AS int;        
declare @Balance as decimal;        
DECLARE @Country AS VARCHAR(200);        
DECLARE @Key AS VARCHAR(200);        
DECLARE @Send AS VARCHAR(200);      
DECLARE @CountryCode AS VARCHAR(200);        
      
        
        
if EXISTS (select 1 from user_detail with(nolock) where User_ID=@UserId  )        
begin        
   select top 1 @Balance=Balance from IntCredit_Details with(nolock) where User_ID=@UserId        
   group by Balance        
   order by max(DateCreated) desc        
   if(@Balance>0)        
   begin        
     if EXISTS ( select 1 from Price_base_sms_rate with(nolock) where DestinationCountryCode =    
    (select CountryCode from fn_separatecountrycodeandmobile(@MobileNo))    and IsEligible=1 )          
     begin        
       select @SmsApiURI=API,@IntlSMSProviderId=id,@Key=[Key] from tbl_intlSMSProvider with(nolock)    where IsActive=1    
      
  select @CountryCode=CountryCode from fn_separatecountrycodeandmobile(@MobileNo)      
       set @Result='Success';        
       set @IsValid=1      
       set @Send='Alert'        
             
     end        
     else        
     begin        
       set @Result='we do not serve sms to this country.';        
       set @IsValid=0        
       set @SmsApiURI=''        
       set @IntlSMSProviderId=''        
       set @Key=''        
       set @Send=''        
    set @CountryCode=''      
     end        
        
   end        
   else        
   begin        
    set @Result='you have insufficient balance';        
    set @IsValid=0        
    set @SmsApiURI=''        
    set @Key=''        
    set @Send=''        
 set @IntlSMSProviderId=''        
 set @CountryCode=''      
   end        
           
        
end        
else        
begin        
 set @Result='user not found';        
 set @IsValid=0        
 set @SmsApiURI=''        
 set @IntlSMSProviderId=''        
 set @Key=''        
 set @Send=''        
 set @CountryCode=''      
end        
        
--select * from tbl_intlSMSProvider        
        
          
          
select cast(@Result as nvarchar(200)) as Result,  cast(@IsValid as bit) as IsValid,cast(@SmsApiURI as nvarchar(200)) as SmsApiURI,          
cast(@IntlSMSProviderId as int) as IntlSMSProviderId,cast(@Key as nvarchar(200)) as Keys,cast(@Send as nvarchar(200)) as Sends,      
cast(@CountryCode as nvarchar(200)) as CountryCode      
          
end



