/* ============================================================
   Procedure: [dbo].[ispSingleToMany_IntlSmsValidation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec ispSingleToMany_IntlSmsValidation  @UserId=34594,@MobileNo='+27781336945',@SmsMsg='test intl sms smg', @MassOpBatchId=40136
CREATE   PROCEDURE [dbo].[ispSingleToMany_IntlSmsValidation]      
(    
 @UserId BIGINT ,      
    @MobileNo NVARCHAR(MAX) ,      
 @SmsMsg nvarchar(4000),    
 @MassOpBatchId bigint=0    
)     
As      
BEGIN      
    
   /* declare @MobileNo nvarchar(max) = '+919913943059,+619913943057,+619913943058',    
  @UserId BIGINT=34594,      
 @SmsMsg nvarchar(4000)=N'This is Sample TextThis is Sample TextThis is Sample TextThis is Sample Text आयोग',    
 @MassOpBatchId bigint=0  */  
    
 --   declare  @UserId BIGINT=34594 ,      
 --   @MobileNo NVARCHAR(MAX)=N'+27781336945' ,      
 --@SmsMsg nvarchar(4000)=N'This is a test sms from kit19',    
 --@MassOpBatchId bigint=40136    

    
    -- Declare variables      
    DECLARE @Result AS VARCHAR(100);      
    DECLARE @IsValid AS BIT;      
    DECLARE @SmsApiURI AS VARCHAR(200);      
    DECLARE @IntlSMSProviderId AS INT;      
    DECLARE @Balance AS DECIMAL;      
    DECLARE @Country AS VARCHAR(200);      
    DECLARE @Key AS VARCHAR(200);      
    DECLARE @Send AS VARCHAR(200);      
    DECLARE @CountryCode AS VARCHAR(200);      
    
 declare @TotalCost numeric(18,4)=0,@Cost numeric(18,4)=0, @IsUnicode bit =0, @NoOfUnit int=1    
    
 drop table if exists #MobileNumbers    
      
    -- Create a temporary table to store individual mobile numbers      
    CREATE TABLE #MobileNumbers (      
        CountryCode NVARCHAR(30),      
        MobileNo NVARCHAR(30),    
  Cost numeric(18,4)    
    );      
      
   select @IsUnicode=dbo.fn_isunicode(@SmsMsg)     
       
   select @NoOfUnit=(case when @IsUnicode=0 and len(@SmsMsg)<=160 then 1 when @IsUnicode=0 and LEN(@SmsMsg)>160 then ceiling(LEN(@SmsMsg)/cast(153 as float)) when @IsUnicode=1 and len(@SmsMsg)<=70 then 1 else ceiling(LEN(@SmsMsg)/cast(67 as float)) end)  
  
    
    
    -- Split the mobile numbers and insert into the temporary table      
 insert into #MobileNumbers(CountryCode,MobileNo)    
 select countrycode,MobileWithoutContryCode    
 From     
 (    
  select  row_number()over(partition by countrycode,MobileNo order by countrycode,MobileNo) as sno,countrycode, STUFF(replace(MobileNo,'+',''), CHARINDEX(replace(trim(countrycode),'+',''), replace(MobileNo,'+','')), LEN(replace(trim(countrycode),'+','')),
  
 '') MobileWithoutContryCode    
  from m_country1(nolock) inner join ( SELECT value as MobileNo FROM STRING_SPLIT(@MobileNo, ',')) M    
  on replace(ltrim(rtrim(countrycode)),'+','')=left(dbo.fn_trim0prefix(replace(replace(replace(MobileNo,'+',''),'-',''),' ','')),len(replace(ltrim(rtrim(countrycode)),'+','')))     
 ) T    
 Where T.sno=1    
    
    -- Check if the user exists      
    IF EXISTS (SELECT 1 FROM user_detail WITH (NOLOCK) WHERE User_ID = @UserId)      
    BEGIN      
        -- Get the user's balance   
    
  --select @Balance=dbo.fn_GetMoneyBalance(@UserId)    
    
    
  
  -- Reserve Fund =>   
  select @Balance = dbo.GetAvailableBalanceForService(@UserId, 3)    
    
  
  If exists (select * from Price_Base_SMS_Rate_Exception(nolock) Where ParentID=@UserId)    
  Begin    
   update MN set MN.Cost=cast(isnull(BR.PTrns,0.00)*@NoOfUnit as Numeric(18,4))    
   FROM Price_Base_SMS_Rate_Exception(NOLOCK) BR right Join  #MobileNumbers MN    
   ON BR.DestinationCountryCode=MN.CountryCode AND BR.ParentID = @UserId    
  End    
  Else    
  Begin    
   update MN set MN.Cost=cast(isnull(BR.PTrns,0.00)*@NoOfUnit as Numeric(18,4))    
   FROM Price_base_sms_rate(NOLOCK) BR right Join  #MobileNumbers MN    
   ON BR.DestinationCountryCode=MN.CountryCode AND BR.IsEligible = 1    
        End    
    
  Select @TotalCost=sum(Cost) From #MobileNumbers    
    
  print concat('@Balance: ',@Balance)    
  print concat('@TotalCost: ', @TotalCost)    
  print concat('@TotalCost*1.5: ',@TotalCost*1.5)    
  print concat('Balance After this batch: ',@Balance-(@TotalCost*1.5))    
      
        -- Check if the user has sufficient balance      
        IF ((@Balance-(@TotalCost*1.5)) > 0)      
        BEGIN      
      
            -- Check if the country is eligible for SMS service      
            IF @TotalCost > 0    
            BEGIN      
               -- Pick the country code from mobile numbers  
DECLARE @SelectedCountryCode NVARCHAR(30);  
SELECT TOP 1 @SelectedCountryCode = CountryCode FROM #MobileNumbers;  
  
-- Get SMS provider for that specific country  
SELECT TOP 1  
       @SmsApiURI = API,  
       @IntlSMSProviderId = Id,  
       @Key = [Key],  
       @CountryCode = CountryCode  
FROM tbl_intlSMSProvider WITH (NOLOCK)  
WHERE IsActive = 1  
      AND CountryCode = @SelectedCountryCode;    
      
      
  
                -- Set success result      
                SET @Result = 'Success';      
                SET @IsValid = 1;      
    SET @Send = 'Alert';      
            END      
            ELSE      
            BEGIN      
                -- Set failure result for ineligible country      
                SET @Result = 'We do not serve SMS to this country.';      
                SET @IsValid = 0;      
                SET @SmsApiURI = '';      
                SET @IntlSMSProviderId = '';      
                SET @Key = '';      
                SET @Send = '';      
                SET @CountryCode = '';      
            END      
        
        END      
        ELSE      
        BEGIN      
            -- Set failure result for insufficient balance      
            SET @Result = 'You have insufficient balance';      
            SET @IsValid = 0;      
            SET @SmsApiURI = '';      
            SET @IntlSMSProviderId = '';      
            SET @Key = '';      
            SET @Send = '';      
            SET @CountryCode = '';      
        END      
    END      
    ELSE      
    BEGIN      
        -- Set failure result for user not found      
        SET @Result = 'User not found';      
        SET @IsValid = 0;      
        SET @SmsApiURI = '';      
        SET @IntlSMSProviderId = '';      
        SET @Key = '';      
        SET @Send = '';      
        SET @CountryCode = '';      
    END      
      
    -- Select the result      
    SELECT CAST(@Result AS NVARCHAR(200)) AS Result,      
           CAST(@IsValid AS BIT) AS IsValid,      
           CAST(@SmsApiURI AS NVARCHAR(200)) AS SmsApiURI,      
           isnull(@IntlSMSProviderId,0) AS IntlSMSProviderId,      
           CAST(@Key AS NVARCHAR(200)) AS Keys,      
           CAST(@Send AS NVARCHAR(200)) AS Sends,      
           isnull(@CountryCode,@SelectedCountryCode) AS CountryCode;      
      
    -- Clean up temporary table      
    --DROP TABLE if exists #MobileNumbers;        
END     



