/* ============================================================
   Procedure: [dbo].[LongRunningProcedure]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.LongRunningProcedure
AS
BEGIN
    DECLARE @Counter INT = 0;

    -- Loop to simulate long-running process (runs for ~6 minutes)
    WHILE @Counter < 6
    BEGIN
        -- Wait for 60 seconds
        WAITFOR DELAY '00:01:00';
        
        -- Increment counter
        SET @Counter = @Counter + 1;
    END
END



