/* ============================================================
   Procedure: [dbo].[MoveFromTransToTrans1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE MoveFromTransToTrans1  
@records bigint =null  
as  
begin  
declare @r bigint=(select COUNT(1) from messagequeuenew (nolock))  
set @records=coalesce(@records,@r)  
   
select top (@records) * into #t2 from dbo.MessageQueueNew  
insert into MessageQueuemtix01(MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent)  
select MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,2,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent from #t2  
delete m from messagequeuenew m join #t2 t on t.messagequeueid=m.messagequeueid  
drop table #t2  
end  
  


GO

/* ============================================================
   Procedure: [dbo].[MoveFromTransToTrc]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE MoveFromTransToTrc  
@records bigint =null  
as  
begin  
declare @r bigint=(select COUNT(1) from messagequeuenew (nolock))  
set @records=coalesce(@records,@r)  
   
select top (@records) * into #t2 from dbo.MessageQueueNew  
insert into MessageQueuetrcroute(MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,Priority,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent)  
select MessageID,Mobile,Message,SenderID,SmppID,MessageInsertDate,2,U_ID,IsUniCode,IsDND,Operator,BatchID,Isallowdnd,issent from #t2  
delete m from messagequeuenew m join #t2 t on t.messagequeueid=m.messagequeueid  
drop table #t2  
end  
  


GO

/* ============================================================
   Procedure: [dbo].[newkit19search]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

       CREATE   PROC newkit19search --5
       (
       @searchid int 
       )
       as       
       --declare  @searchid int=5
       declare @UserName nvarchar(max)
      ,@Mobile nvarchar(20)
      ,@EmailID nvarchar(100)
      ,@UserType nvarchar(10)
      ,@LastLoginBeforeFrom int
      ,@LastLoginBeforeTo int
      ,@LastPurchaseDaysFrom int
      ,@LastPurchaseDaysTo int
      ,@LastPurchasePriceFrom decimal(18,2)
      ,@LastPurchasePriceTo decimal(18,2)
      ,@UserFilter nvarchar(20)
      ,@BalanceFrom bigint
      ,@BalanceTo bigint
      ,@TotalCreditPurchasedFrom bigint
      ,@TotalCreditPurchasedTo bigint
      ,@TotalCreditConsumedFrom bigint
      ,@TotalCreditConsumedTo bigint
      ,@CreatedBetweenFrom int
      ,@CreatedBetweenTo int
      ,@HasMicrosite int
      --,@isactive int
      
      select @username=[UserName]
      ,@Mobile=isnull(nullif([Mobile],0),'')
      ,@EmailID=isnull([EmailID],'')
      ,@UserType=isnull([UserType],'')
      ,@LastLoginBeforeFrom=[LastLoginBeforeFrom]
      ,@LastLoginBeforeTo=[LastLoginBeforeTo]
      ,@LastPurchaseDaysFrom=[LastPurchaseDaysFrom]
      ,@LastPurchaseDaysTo=[LastPurchaseDaysTo]
      ,@LastPurchasePriceFrom=[LastPurchasePriceFrom]
      ,@LastPurchasePriceTo=LastPurchasePriceTo
      ,@UserFilter=[UserFilter]
      ,@BalanceFrom=[BalanceFrom]
      ,@BalanceTo=[BalanceTo]
      ,@TotalCreditPurchasedFrom=[TotalCreditPurchasedFrom]
      ,@TotalCreditPurchasedTo=[TotalCreditPurchasedTo]
      ,@TotalCreditConsumedFrom=[TotalCreditConsumedFrom]
      ,@TotalCreditConsumedTo=[TotalCreditConsumedTo]
      ,@CreatedBetweenFrom=[CreatedBetweenFrom]
      ,@CreatedBetweenTo=[CreatedBetweenTo]
      ,@HasMicrosite=[HasMicrosite]
      --,@isactive=nullif(IsActive,0)
      from searchdetails where id=@searchid
      --select * from searchdetails where id=5 
      
      select * into #userid from user_detail where m_id=10043
            
      if ISNULL(@username,'')<>''
      begin
      delete from #userid where User_Login not in (select value from dbo.fn_Split(@username,'#'))
      select count(*),'@username' from #userid
      end
      if ISNULL(@userfilter,'')<>''
      begin
      delete from #userid where userfilter not in (select value from dbo.fn_Split(@userfilter,'#'))
      select count(*),'@userfilter' from #userid
      end
      if ISNULL(@usertype,'')<>''
      begin
      delete from #userid where UserType not in (select value from dbo.fn_Split(@usertype,'#'))
      select count(*),'@usertype' from #userid
      end
      if @Mobile<>''
      begin
      delete from #userid where mobile not in (select value from fn_split(@Mobile,'#'))
      select count(*),'@Mobile' from #userid
      end
      if @EmailID<>''
      begin
      delete from #userid where emailid not in (select value from fn_split(@EmailID,'#'))
      select count(*),'@EmailID' from #userid
      end
      --select @LastLoginBeforeFrom
      --select @LastLoginBeforeTo
      if @LastLoginBeforeFrom<>0 and @LastLoginBeforeTo <>0
      begin
      delete from #userid where user_id not in (select user_id from credit_details where datediff(d,max(datecreated),getdate()) between @LastLoginBeforeFrom and @LastLoginBeforeTo group by USER_ID)
      select count(*),'@LastLoginBeforeFrom' from #userid
      end
      if @LastPurchaseDaysFrom<>0 and @LastPurchaseDaysTo<>0
      begin
      delete from #userid where user_id not in (select user_id from AddCreditDetails where datediff(d,max(CreatedDate),getdate()) between @LastPurchaseDaysFrom and @LastPurchaseDaysTo group by USER_ID)
      select count(*),'@LastPurchaseDaysFrom' from #userid
      end
      if @LastPurchasePriceFrom<>0 and @lastpurchasepriceto<>0
      begin
      create table #Latestpricetable(userid bigint)
      insert into #Latestpricetable
      Select userid From AddCreditDetails a where createddate = (select max(createddate) from AddCreditDetails a1 where a.userid =a1.userid) and pricepersms between cast(@lastpurchasepricefrom as decimal) and cast(@lastpurchasepriceto as decimal) order by createddate desc
      delete from #userid where user_id not in (select userid from #Latestpricetable) 
      drop table #Latestpricetable 
      select count(*),'@LastPurchasePriceFrom' from #userid
      end
      if @BalanceFrom<>'' and @BalanceTo <>''
      begin
      delete from #userid where user_id not in (select user_id from credit_details where balance between @BalanceFrom and @BalanceTo group by user_id having DateCreated=max(datecreated))
      select count(*),'@BalanceFrom' from #userid
      end
      if @TotalCreditPurchasedFrom<>'' and @TotalCreditPurchasedto <>''
      begin
      delete from #userid where user_id not in (select user_id from credit_details where sum(credits) between @TotalCreditPurchasedFrom and @TotalCreditPurchasedTo)
      select count(*),'@TotalCreditPurchasedFrom' from #userid
      end
      if @TotalCreditConsumedFrom<>'' and @TotalCreditConsumedTo <>''
      begin
      delete from #userid where user_id not in (select user_id from credit_details where sum(debits) between @TotalCreditConsumedFrom and @TotalCreditConsumedTo)
      select count(*),'@TotalCreditConsumedFrom' from #userid
      end
      if @CreatedBetweenFrom<>'' and @CreatedBetweenTo<>''
      begin
      delete from #userid where datediff(d,DateCreated,getdate()) not between @CreatedBetweenFrom and @CreatedBetweenTo 
      select count(*),'@CreatedBetweenFrom' from #userid
      end
      if @HasMicrosite <>''
      begin
      delete u from #userid u join clientpagedetail c on u.user_id<>c.user_id 
      select count(*),'@HasMicrosite' from #userid
      end
      --if @Isactive <>''
      --begin
      --delete from #userid where status=0
      --select count(*),'@Isactive' from #userid
      --end
      
      select user_id,User_Login,Mobile,email from #userid
      drop table #userid
      
      
      


GO

/* ============================================================
   Procedure: [dbo].[prc_AdsReview]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec prc_AdsReview 15
-- exec prc_AdsReview 89
CREATE   PROC [dbo].[prc_AdsReview]   
@AdsId varchar(50)    
As    
Begin    
select  ads.AdsId,isnull(ads.BusinessName,rad.BusinessName) as BusinessName,isnull(ads.Description1,rad.ShortHeadline1) as Description1,isnull(ads.Description2,rad.Description1) as Description2, isnull(ads.DisplayUrl,rad.FinalUrl) as DisplayUrl    
,adgrp.GroupName,adgrp.Keyword,adgrp.AdwordGroupId, cam.CampaignName,cam.Location,cam.Budget,(cam.Budget * 30) as monthly  -- select * 
from tblAds ads inner join tblAdGroup adgrp 
on ads.CampaignId=adgrp.CampAd_id inner join tblCampaign cam 
on cam.CampAd_id=adgrp.CampAd_id left join tblAds_ResponsiveAdForDisplay rad
on ads.AdsId = rad.Ref_AdsId
where ads.AdsId=@AdsId and cam.IsDeleted=0  and adgrp.IsDeleted=0 and ads.IsDeleted=0
/*cam.CampaignId=@AdsId*/  
select 'success' as result from tblAds where AdsId=@AdsId   
--select 'success' as result from tblAds where CampaignId=@AdsId   
End  



GO

