/* ============================================================
   Procedure: [dbo].[prc_AdwordsTransactions]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[prc_AdwordsTransactions] --335,'10/16/2018','10/16/2018'  
(    
@User_ID varchar(50),  
@fmdate datetime ,  
@todate datetime   
)  
As    
Begin   
  
  Declare @ParentID  bigint = 0  
  select  @ParentID = ParentID from user_detail where USER_ID = @user_id  
  
select 
       gp.AdGroupId,
       rpt.[user_id]
      ,rpt.[CampaignId]
      ,dbo.[fn_getusertimefromindiantime](@ParentID,rpt.Report_Date)  as Report_Date
      ,rpt.[AdGroupId]
      ,rpt.[KeyWordID]
      ,rpt.[CriteriaType]
      ,rpt.[Criteria]
      ,rpt.[FinalUrls]
      ,rpt.[Clicks]
      ,rpt.[Impressions]
      ,rpt.[Cost]

,

cp.CampaignName,
gp.GroupName 
from Adword_DailyCampaignDt rpt   
inner join tblCampaign cp on cp.CampAd_id = rpt.CampaignId  
inner join tblAdGroup gp on gp.AdwordGroupId = rpt.AdGroupId  
where rpt.User_ID=@User_ID and  
Convert(Date,Report_Date) 
between

 Convert(Date,dbo.[fn_getISTtimefromusertime](@ParentID,@fmdate))

  and 

 Convert(Date,dbo.[fn_getISTtimefromusertime](@ParentID,@todate))  

order by Convert(Date,Report_Date) desc, CampaignId  

End  



GO

