--prc_GetAdgrp_adsbyId'adgroup','335','','48'  
CREATE   PROCEDURE [dbo].[prc_GetAdgrp_adsbyId]  
 @Type varchar(50)  
,@User_ID varchar(50)  
,@CampAd_id varchar(50)  
,@AdwordGroupId varchar(50)  
As  
Begin  
Declare @ParentID bigint = 0
select @ParentID = isnull(ParentID,0) from user_detail where user_id = @User_ID

if(@Type='adgroup')  
begin  
Select
       [AdGroupId]
      ,[AdwordGroupId]
      ,[CampAd_id]
      ,[User_Id]
      ,[GroupName]
      ,[Adword_Name]
      ,[Keyword]
      ,[Status]
      ,[IsPublished]
      ,[IsActive]
     
      ,dbo.[fn_getusertimefromindiantime](@ParentID,CreatedDate) as CreatedDate
      
      ,dbo.[fn_getusertimefromindiantime](@ParentID,ModifiedDate) as ModifiedDate
      
      ,[KeywordId]
      ,[match_type]
      
 from tblAdGroup where CampAd_id=@CampAd_id  
print'a'  
end  
if(@Type='ads')  
begin  
Select 
      [AdsId]
      ,[AdwordAdsId]
      ,[User_Id]
      ,[CampaignId]
      ,[AdwordGroupId]
      ,[BusinessName]
      ,[Description1]
      ,[Description2]
      ,[DisplayUrl]
      ,[DestinationUrl]
      ,[Status]
      ,[IsPublished]
      ,[IsActive]
      
      ,dbo.[fn_getusertimefromindiantime](@ParentID,CreatedDate) as CreatedDate
      
      ,dbo.[fn_getusertimefromindiantime](@ParentID,ModifiedDate) as ModifiedDate
       
       
from tblAds where AdwordGroupId=@AdwordGroupId  
print'b'  
end  

End  



