SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--prc_GetAdgrp_adsbyId'adgroup','335','','48'  
CREATE   PROC [dbo].[prc_GetAdgrp_adsbyId_INTDateTime]  
 @Type varchar(50)  
,@User_ID varchar(50)  
,@CampAd_id varchar(50)  
,@AdwordGroupId varchar(50)  
As  
Begin  
Declare @ParentID bigint = 0
select @ParentID = isnull(ParentID,0) from user_detail where user_id = @User_ID

if(@Type='adgroup')  
begin  
Select
       [AdGroupId]
      ,[AdwordGroupId]
      ,[CampAd_id]
      ,[User_Id]
      ,[GroupName]
      ,[Adword_Name]
      ,[Keyword]
      ,[Status]
      ,[IsPublished]
      ,[IsActive]
     
      ,dbo.[fn_getusertimefromindiantime](@ParentID,CreatedDate) as CreatedDate
      
      ,dbo.[fn_getusertimefromindiantime](@ParentID,ModifiedDate) as ModifiedDate
      
      ,[KeywordId]
      ,[match_type]
      
 from tblAdGroup where CampAd_id=@CampAd_id  
print'a'  
end  
if(@Type='ads')  
begin  
Select 
      [AdsId]
      ,[AdwordAdsId]
      ,[User_Id]
      ,[CampaignId]
      ,[AdwordGroupId]
      ,[BusinessName]
      ,[Description1]
      ,[Description2]
      ,[DisplayUrl]
      ,[DestinationUrl]
      ,[Status]
      ,[IsPublished]
      ,[IsActive]
      
      ,dbo.[fn_getusertimefromindiantime](@ParentID,CreatedDate) as CreatedDate
      
      ,dbo.[fn_getusertimefromindiantime](@ParentID,ModifiedDate) as ModifiedDate
       
       
from tblAds where AdwordGroupId=@AdwordGroupId  
print'b'  
end  

End  


GO

/* ============================================================
   Procedure: [dbo].[prc_GetCampaignDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- exec dbo.prc_GetCampaignDetails 6451965347, 'camp'
CREATE   PROCEDURE [dbo].[prc_GetCampaignDetails]    
 @Id varchar(50)      
,@Type varchar(50)      
As      
Begin      
if(@Type='camp')      
begin      
Select  top 1  
       tbc.[CampaignId]  
      ,tbc.[CampAd_id]  
      ,tbc.[User_ID]  
      ,tbc.[CampaignName]  
      ,tbc.[Location]  
      ,tbc.[BidStrategyType]  
      ,tbc.[CampaignType]  
      ,tbc.[Budget]  
      ,tbc.[BudgetId]  
      ,tbc.[BiddingClick]  
      ,tbc.[Bidding]  
      ,tbc.[Status]  
      ,tbc.[SortId]  
      ,tbc.[Source]  
      ,tbc.[IPAddress]  
      ,tbc.[IsActive]  
      ,tbc.[IsPublished]  
        
     ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = tbc.User_ID),tbc.CreatedDate) as CreatedDate  
        
      ,  
      dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = tbc.User_ID),tbc.[ModifiedDate]) as ModifiedDate  
        
      ,tbc.CreatedBy  
      ,tbc.[ModifiedBy]  
            
      ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = tbc.User_ID),tbc.[CmpStartDate]) as CmpStartDate  
        
,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = tbc.User_ID),tbc.[CmpEndDate]) as CmpEndDate  
        
   ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = tbc.User_ID),tbc.[Starton]) as Starton  
        
      ,tbc.[GCampaignName]  
      ,tbc.[minbal]  
      ,tbc.[locid]   
      ,tbc.CampaignType
	 ,tbc.CampaignSubType  
from tblCampaign tbc where tbc.CampaignId=@Id  or tbc.CampAd_id=@Id
end      
else if(@Type='group')      
begin      
Select   
       TAG.[AdGroupId]  
      ,TAG.[AdwordGroupId]  
      ,TAG.[CampAd_id]  
      ,TAG.[User_Id]  
      ,TAG.[GroupName]  
      ,TAG.[Adword_Name]  
      ,TAG.[Keyword]  
      ,TAG.[Status]  
      ,TAG.[IsPublished]  
      ,TAG.[IsActive]  
       
      ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = TAG.User_ID),TAG.[CreatedDate]) as CreatedDate  
            
      ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = TAG.User_ID),TAG.[ModifiedDate]) as ModifiedDate  
        
        
      ,TAG.[KeywordId]  
      ,TAG.[match_type]  
        
from tblAdGroup TAG where TAG.AdGroupId=@Id      
end      
else if(@Type='ads')      
begin      
Select   
       TBA.[AdsId]  
      ,TBA.[AdwordAdsId]  
      ,TBA.[User_Id]  
      ,TBA.[CampaignId]  
      ,TBA.[AdwordGroupId]  
      ,TBA.[BusinessName]  
      ,TBA.[Description1]  
      ,TBA.[Description2]  
      ,TBA.[DisplayUrl]  
      ,TBA.[DestinationUrl]  
      ,TBA.[Status]  
      ,TBA.[IsPublished]  
      ,TBA.[IsActive]  
      ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = TBA.User_ID),TBA.[CreatedDate]) as CreatedDate  
     
     ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = TBA.User_ID),TBA.[ModifiedDate]) as ModifiedDate  
  
              
from tblAds TBA where TBA.AdsId=@Id      
end      
End    



GO

/* ============================================================
   Procedure: [dbo].[prc_GetCampaignDetails_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[prc_GetCampaignDetails_INTDateTime]  
 @Id varchar(50)    
,@Type varchar(50)    
As    
Begin    
if(@Type='camp')    
begin    
Select 
       tbc.[CampaignId]
      ,tbc.[CampAd_id]
      ,tbc.[User_ID]
      ,tbc.[CampaignName]
      ,tbc.[Location]
      ,tbc.[BidStrategyType]
      ,tbc.[CampaignType]
      ,tbc.[Budget]
      ,tbc.[BudgetId]
      ,tbc.[BiddingClick]
      ,tbc.[Bidding]
      ,tbc.[Status]
      ,tbc.[SortId]
      ,tbc.[Source]
      ,tbc.[IPAddress]
      ,tbc.[IsActive]
      ,tbc.[IsPublished]
      
     ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = tbc.User_ID),tbc.CreatedDate) as CreatedDate
      
      ,
      dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = tbc.User_ID),tbc.[ModifiedDate]) as ModifiedDate
      
      ,tbc.CreatedBy
      ,tbc.[ModifiedBy]
          
      ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = tbc.User_ID),tbc.[CmpStartDate]) as CmpStartDate
      
,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = tbc.User_ID),tbc.[CmpEndDate]) as CmpEndDate
      
   ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = tbc.User_ID),tbc.[Starton]) as Starton
      
      ,tbc.[GCampaignName]
      ,tbc.[minbal]
      ,tbc.[locid] 
      
from tblCampaign tbc where tbc.CampaignId=@Id    
end    
else if(@Type='group')    
begin    
Select 
       TAG.[AdGroupId]
      ,TAG.[AdwordGroupId]
      ,TAG.[CampAd_id]
      ,TAG.[User_Id]
      ,TAG.[GroupName]
      ,TAG.[Adword_Name]
      ,TAG.[Keyword]
      ,TAG.[Status]
      ,TAG.[IsPublished]
      ,TAG.[IsActive]
     
      ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = TAG.User_ID),TAG.[CreatedDate]) as CreatedDate
          
      ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = TAG.User_ID),TAG.[ModifiedDate]) as ModifiedDate
      
      
      ,TAG.[KeywordId]
      ,TAG.[match_type]
      
from tblAdGroup TAG where TAG.AdGroupId=@Id    
end    
else if(@Type='ads')    
begin    
Select 
       TBA.[AdsId]
      ,TBA.[AdwordAdsId]
      ,TBA.[User_Id]
      ,TBA.[CampaignId]
      ,TBA.[AdwordGroupId]
      ,TBA.[BusinessName]
      ,TBA.[Description1]
      ,TBA.[Description2]
      ,TBA.[DisplayUrl]
      ,TBA.[DestinationUrl]
      ,TBA.[Status]
      ,TBA.[IsPublished]
      ,TBA.[IsActive]
      ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = TBA.User_ID),TBA.[CreatedDate]) as CreatedDate
   
     ,dbo.[fn_getusertimefromindiantime]((select isnull(ParentID,0) from user_detail ud where ud.User_ID = TBA.User_ID),TBA.[ModifiedDate]) as ModifiedDate

            
from tblAds TBA where TBA.AdsId=@Id    
end    
End  


GO


